    public static MasterListOptions Load() {
        ConfigValues config = ReadConfigFile();
        string bindUrls = FirstNonEmpty(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_BIND_URLS"),
            config.Urls,
            "http://0.0.0.0:8494");
        string websiteBindUrls = FirstNonEmpty(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_BIND_URLS"),
            config.WebsiteUrls,
            "http://0.0.0.0:80");
        string websiteSslBindUrls = FirstNonEmpty(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_BIND_URLS"),
            config.WebsiteSslUrls,
            "https://0.0.0.0:443");

        int port = ReadInt(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_PORT"),
            null,
            ReadPort(bindUrls, 8494),
            1,
            65535);
        int websitePort = ReadInt(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_PORT"),
            null,
            ReadPort(websiteBindUrls, 80),
            1,
            65535);
        int websiteSslPort = ReadInt(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_PORT"),
            null,
            ReadPort(websiteSslBindUrls, 443),
            1,
            65535);
        string bindHost = FirstNonEmpty(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_BIND_HOST"),
            config.BindHost,
            ReadBindableHost(bindUrls),
            ReadBindableHost(websiteBindUrls),
            ReadBindableHost(websiteSslBindUrls),
            DefaultBindHost);
        string sqlLoopbackBindHost = FirstNonEmpty(
            Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_SQL_LOOPBACK_BIND_HOST"),
            config.SqlLoopbackBindHost,
            DefaultSqlLoopbackBindHost);

        var options = new MasterListOptions {
            Port = port,
            WebsitePort = websitePort,
            WebsiteSslPort = websiteSslPort,
            BindHost = bindHost,
            BindAddress = ResolveBindAddress(bindHost),
            JackcastEnabled = ReadBool(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_ENABLED"),
                config.JackcastEnabled,
                false),
            JackcastDedicatedListenersEnabled = ReadBool(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_DEDICATED_LISTENERS"),
                config.JackcastDedicatedListenersEnabled,
                false),
            JackcastHostName = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_HOST"),
                config.JackcastHostName,
                DefaultJackcastHostName),
            JackcastHostAliases = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_HOST_ALIASES"),
                config.JackcastHostAliases,
                ""),
            JackcastBindAddress = ResolveBindAddress(FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_BIND_ADDRESS"),
                config.JackcastBindAddress,
                DefaultJackcastBindAddress)),
            JackcastTargetUrl = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_TARGET_URL"),
                config.JackcastTargetUrl,
                DefaultJackcastTargetUrl),
            SecureAuthorityTargetUrl = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_SECURE_AUTHORITY_TARGET_URL"),
                config.SecureAuthorityTargetUrl,
                DefaultSecureAuthorityTargetUrl),
            JackcastSslEnabled = ReadBool(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_SSL_ENABLED"),
                config.JackcastSslEnabled,
                false),
            JackcastSslCertificatePath = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_SSL_CERTIFICATE"),
                config.JackcastSslCertificatePath,
                @"C:\jackcast_live.pfx"),
            JackcastSslCertificateKeyPath = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_SSL_KEY"),
                config.JackcastSslCertificateKeyPath,
                @"C:\pw.txt"),
            JackcastSslCertificatePassword = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_SSL_PASSWORD"),
                config.JackcastSslCertificatePassword,
                ""),
            JackcastSslCertificateSubject = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_JACKCAST_SSL_SUBJECT"),
                config.JackcastSslCertificateSubject,
                DefaultJackcastHostName),
            WebsiteSslEnabled = ReadBool(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_ENABLED"),
                config.WebsiteSslEnabled,
                true),
            WebsiteSslCertificatePath = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_CERTIFICATE"),
                config.WebsiteSslCertificatePath,
                @"C:\socketjack_com.pfx"),
            WebsiteSslCertificateKeyPath = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_KEY"),
                config.WebsiteSslCertificateKeyPath,
                @"C:\pw.txt"),
            WebsiteSslCertificatePassword = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_PASSWORD"),
                config.WebsiteSslCertificatePassword,
                ""),
            WebsiteSslCertificateSubject = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_SSL_SUBJECT"),
                config.WebsiteSslCertificateSubject,
                "socketjack.com"),
            JackLLMUpdateDirectory = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_GUI_UPDATE_DIRECTORY"),
                config.JackLLMUpdateDirectory,
                @"C:\JackLLM\Update"),
            PublicUrl = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_PUBLIC_URL"),
                config.PublicUrl,
                "https://socketjack.com/"),
            WebsitePublicUrl = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_WEBSITE_PUBLIC_URL"),
                config.WebsitePublicUrl,
                "https://socketjack.com/"),
            DataFile = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_DATA_FILE"),
                config.DataFile,
                "data/socketjack-master-list-db"),
            RegistrationTtlMinutes = ReadInt(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_TTL_MINUTES"),
                config.RegistrationTtlMinutes,
                360,
                1,
                43200),
            MaxServers = ReadInt(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_MAX_SERVERS"),
                config.MaxServers,
                1000,
                1,
                100000),
            DatabaseName = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_DATABASE"),
                config.DatabaseName,
                "SocketJack"),
            TableName = FirstNonEmpty(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_TABLE"),
                config.TableName,
                "JackLLMServers"),
            AllowedSqlLoginIpAddresses = ReadStringList(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_SQL_LOGIN_ALLOWED_IPS"),
                config.AllowedSqlLoginIpAddresses,
                DefaultAllowedSqlLoginIpAddresses),
            SqlLoopbackEnabled = ReadBool(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_SQL_LOOPBACK_ENABLED"),
                config.SqlLoopbackEnabled,
                true),
            SqlLoopbackPort = ReadInt(
                Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_SQL_LOOPBACK_PORT"),
                config.SqlLoopbackPort,
                websitePort,
                1,
                65535),
            SqlLoopbackBindHost = sqlLoopbackBindHost,
            SqlLoopbackBindAddress = ResolveBindAddress(sqlLoopbackBindHost),
            AdminKey = Environment.GetEnvironmentVariable("SOCKETJACK_MAGIC_MASTER_LIST_ADMIN_KEY") ?? ""
        };

        // SocketJack.com is the only public TLS hostname this process owns.
        // Keep SNI disabled here so the HTTPS listener uses one certificate.
        options.JackcastEnabled = false;
        options.JackcastSslEnabled = false;
        options.JackcastDedicatedListenersEnabled = false;

        return options;
    }

    public string ResolveDataFilePath() {
        return Path.IsPathRooted(DataFile)
            ? DataFile
            : Path.Combine(AppContext.BaseDirectory, DataFile);
    }

    private static ConfigValues ReadConfigFile() {
        var values = new ConfigValues();
        string path = Path.Combine(AppContext.BaseDirectory, "appsettings.json");
        if (!File.Exists(path))
            path = Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "appsettings.json");
        if (!File.Exists(path))
            return values;

        try {
            using JsonDocument document = JsonDocument.Parse(File.ReadAllText(path));
            JsonElement root = document.RootElement;
            values.Urls = GetString(root, "Urls");
            values.WebsiteUrls = GetString(root, "WebsiteUrls");
            values.WebsiteSslUrls = GetString(root, "WebsiteSslUrls");
            values.BindHost = FirstNonEmpty(GetString(root, "BindHost"), GetString(root, "BindAddress"));
            if (TryGetProperty(root, "SocketJackMagicMasterList", out JsonElement section) &&
                section.ValueKind == JsonValueKind.Object) {
                values.BindHost = FirstNonEmpty(GetString(section, "BindHost"), GetString(section, "BindAddress"), values.BindHost);
                values.JackcastEnabled = GetString(section, "JackcastEnabled");
                values.JackcastDedicatedListenersEnabled = GetString(section, "JackcastDedicatedListenersEnabled");
                values.JackcastHostName = GetString(section, "JackcastHostName");
                values.JackcastHostAliases = GetString(section, "JackcastHostAliases");
                values.JackcastBindAddress = GetString(section, "JackcastBindAddress");
                values.JackcastTargetUrl = GetString(section, "JackcastTargetUrl");
                values.SecureAuthorityTargetUrl = GetString(section, "SecureAuthorityTargetUrl");
                values.JackcastSslEnabled = GetString(section, "JackcastSslEnabled");
                values.JackcastSslCertificatePath = GetString(section, "JackcastSslCertificatePath");
                values.JackcastSslCertificateKeyPath = GetString(section, "JackcastSslCertificateKeyPath");
                values.JackcastSslCertificatePassword = GetString(section, "JackcastSslCertificatePassword");
                values.JackcastSslCertificateSubject = GetString(section, "JackcastSslCertificateSubject");
                values.PublicUrl = GetString(section, "PublicUrl");
                values.WebsitePublicUrl = GetString(section, "WebsitePublicUrl");
                values.WebsiteSslEnabled = GetString(section, "WebsiteSslEnabled");
                values.WebsiteSslCertificatePath = GetString(section, "WebsiteSslCertificatePath");
                values.WebsiteSslCertificateKeyPath = GetString(section, "WebsiteSslCertificateKeyPath");
                values.WebsiteSslCertificatePassword = GetString(section, "WebsiteSslCertificatePassword");
                values.WebsiteSslCertificateSubject = GetString(section, "WebsiteSslCertificateSubject");
                values.JackLLMUpdateDirectory = FirstNonEmpty(GetString(section, "JackLLMUpdateDirectory"), GetString(section, "GuiUpdateDirectory"), GetString(section, "UpdateDirectory"));
                values.DataFile = FirstNonEmpty(GetString(section, "DatabaseFile"), GetString(section, "DataFile"));
                values.RegistrationTtlMinutes = GetString(section, "RegistrationTtlMinutes");
                values.MaxServers = GetString(section, "MaxServers");
                values.DatabaseName = GetString(section, "DatabaseName");
                values.TableName = GetString(section, "TableName");
                values.AllowedSqlLoginIpAddresses = FirstNonEmpty(
                    GetString(section, "AllowedSqlLoginIpAddresses"),
                    GetString(section, "SqlLoginAllowedIpAddresses"),
                    GetString(section, "SqlAdminAllowedIpAddresses"));
                values.SqlLoopbackEnabled = FirstNonEmpty(GetString(section, "SqlLoopbackEnabled"), GetString(section, "SqlServerLoopbackEnabled"));
                values.SqlLoopbackPort = FirstNonEmpty(GetString(section, "SqlLoopbackPort"), GetString(section, "SqlServerLoopbackPort"));
                values.SqlLoopbackBindHost = FirstNonEmpty(
                    GetString(section, "SqlLoopbackBindHost"),
                    GetString(section, "SqlLoopbackBindAddress"),
                    GetString(section, "SqlServerBindHost"),
                    GetString(section, "SqlServerBindAddress"));
            }
        } catch {
            return values;
        }

        return values;
    }

    private static int ReadPort(string text, int fallback) {
        if (int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed))
            return Math.Clamp(parsed, 1, 65535);

        foreach (string part in (text ?? "").Split(new[] { ';', ',' }, StringSplitOptions.RemoveEmptyEntries)) {
            if (Uri.TryCreate(part.Trim(), UriKind.Absolute, out Uri? uri) && uri.Port > 0)
                return uri.Port;
        }

        return fallback;
    }

    private static string ReadBindableHost(string text) {
        foreach (string part in (text ?? "").Split(new[] { ';', ',' }, StringSplitOptions.RemoveEmptyEntries)) {
            if (!Uri.TryCreate(part.Trim(), UriKind.Absolute, out Uri? uri))
                continue;
            string host = uri.Host.Trim();
            if (string.IsNullOrWhiteSpace(host) ||
                host == "*" ||
                host == "+" ||
                host == "0.0.0.0" ||
                host == "::" ||
                host.Equals("localhost", StringComparison.OrdinalIgnoreCase))
                continue;
            return host;
        }

        return "";
    }

    private static IPAddress ResolveBindAddress(string host) {
        host = string.IsNullOrWhiteSpace(host) ? DefaultBindHost : host.Trim();
        if (IPAddress.TryParse(host, out IPAddress? address))
            return address;

        IPAddress? ipv4 = Dns.GetHostAddresses(host)
            .FirstOrDefault(candidate => candidate.AddressFamily == AddressFamily.InterNetwork);
        if (ipv4 == null)
            throw new InvalidOperationException("Unable to resolve an IPv4 bind address for " + host + ".");

        return ipv4;
    }

    private static int ReadInt(string? first, string? second, int fallback, int min, int max) {
        string text = !string.IsNullOrWhiteSpace(first) ? first : second ?? "";
        if (!int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value))
            value = fallback;
        return Math.Clamp(value, min, max);
    }

    private static bool ReadBool(string? first, string? second, bool fallback) {
        string text = !string.IsNullOrWhiteSpace(first) ? first : second ?? "";
        return bool.TryParse(text, out bool value) ? value : fallback;
    }

    private static string[] ReadStringList(string? first, string? second, string[] fallback) {
        string text = !string.IsNullOrWhiteSpace(first) ? first : second ?? "";
        if (string.IsNullOrWhiteSpace(text))
            return fallback.ToArray();

        string[] values = text
            .Split(new[] { ',', ';', '\r', '\n', '\t', '|' }, StringSplitOptions.RemoveEmptyEntries)
            .Select(value => value.Trim())
            .Where(value => !string.IsNullOrWhiteSpace(value))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToArray();
        return values.Length == 0 ? fallback.ToArray() : values;
    }

    private static string GetString(JsonElement element, string name) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return "";
        return RegisteredServer.JsonValueToText(value);
    }

    private static bool TryGetProperty(JsonElement element, string name, out JsonElement value) {
        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase)) {
                    value = property.Value;
                    return true;
                }
            }
        }

        value = default;
        return false;
    }

    private static string FirstNonEmpty(params string?[] values) {
        foreach (string? value in values) {
            if (!string.IsNullOrWhiteSpace(value))
                return value.Trim();
        }

        return "";
    }

