        public string JackcastHostName { get; set; } = "";
        public string JackcastHostAliases { get; set; } = "";
        public string JackcastBindAddress { get; set; } = "";
        public string JackcastTargetUrl { get; set; } = "";
        public string SecureAuthorityTargetUrl { get; set; } = "";
        public string JackcastSslEnabled { get; set; } = "";
        public string JackcastSslCertificatePath { get; set; } = "";
        public string JackcastSslCertificateKeyPath { get; set; } = "";
        public string JackcastSslCertificatePassword { get; set; } = "";
        public string JackcastSslCertificateSubject { get; set; } = "";
        public string WebsiteSslEnabled { get; set; } = "";
        public string WebsiteSslCertificatePath { get; set; } = "";
        public string WebsiteSslCertificateKeyPath { get; set; } = "";
        public string WebsiteSslCertificatePassword { get; set; } = "";
        public string WebsiteSslCertificateSubject { get; set; } = "";
        public string JackLLMUpdateDirectory { get; set; } = "";
        public string PublicUrl { get; set; } = "";
        public string WebsitePublicUrl { get; set; } = "";
        public string DataFile { get; set; } = "";
        public string RegistrationTtlMinutes { get; set; } = "";
        public string MaxServers { get; set; } = "";
        public string DatabaseName { get; set; } = "";
        public string TableName { get; set; } = "";
        public string AllowedSqlLoginIpAddresses { get; set; } = "";
        public string SqlLoopbackEnabled { get; set; } = "";
        public string SqlLoopbackPort { get; set; } = "";
        public string SqlLoopbackBindHost { get; set; } = "";
    }
}

