    public MasterListServerHost(MasterListOptions options) {
        _options = options;
        _shellProxyWebSocketTunnels = new ShellProxyWebSocketTunnelManager(this);
        _masterListHtml = new Lazy<string>(BuildIndexHtml, LazyThreadSafetyMode.ExecutionAndPublication);
        _server = CreateServer(options.Port, "SocketJack-MagicMasterList");
        _server.Options.Logging = false;
        _server.CacheControl = "no-store";
        _server.OnError += Server_OnError;
        _server.OnHttpRequest += ShellProxy_OnHttpRequest;
        RegisterShellProxyWebSockets(_server);

        _websiteServer = CreateWebsiteServer(options.WebsitePort, "SocketJackMagicMasterListWebsite");
        if (options.WebsiteSslEnabled) {
            try {
                X509Certificate2 certificate = LoadWebsiteSslCertificate(options);
                _websiteSslServer = CreateWebsiteServer(options.WebsiteSslPort, "SocketJackMagicMasterListWebsiteSsl");
                _websiteSslServer.Options.UseSsl = true;
                _websiteSslServer.SslCertificate = certificate;
                _websiteSslServer.SslTargetHost = options.WebsiteSslCertificateSubject;
                ConfigureSharedJackcastSslCertificate(_websiteSslServer);
            } catch (Exception ex) {
                _websiteSslError = "HTTPS unavailable: " + ex.Message;
            }
        }
        _websiteServer.EnablePort80HttpsRedirect = _websiteSslServer != null;
        if (options.SqlLoopbackEnabled)
            _sqlLoopbackServer = CreateSqlLoopbackServer(options.SqlLoopbackPort, "SocketJackMagicMasterListSqlLoopback", options.SqlLoopbackBindAddress);
        if (options.JackcastEnabled && options.JackcastDedicatedListenersEnabled) {
            _jackcastServer = CreateWebsiteServer(options.WebsitePort, "JackcastLiveProxy", options.JackcastBindAddress);
            if (options.JackcastSslEnabled) {
                try {
                    X509Certificate2 certificate = LoadJackcastSslCertificate(options);
                    _jackcastSslServer = CreateWebsiteServer(options.WebsiteSslPort, "JackcastLiveProxySsl", options.JackcastBindAddress);
                    _jackcastSslServer.Options.UseSsl = true;
                    _jackcastSslServer.SslCertificate = certificate;
                    _jackcastSslServer.SslTargetHost = options.JackcastSslCertificateSubject;
                } catch (Exception ex) {
                    _jackcastSslError = "Jackcast HTTPS unavailable: " + ex.Message;
                }
            }
            _jackcastServer.EnablePort80HttpsRedirect = _jackcastSslServer != null;
        }

        _tds = new TdsProtocolHandler();
        _dataServer = _tds.Server;
        _dataServer.DataPath = options.ResolveDataFilePath();
        _dataServer.DefaultDatabase = options.DatabaseName;
        _dataServer.ServerName = "SocketJack";
        _dataServer.AutoSave = true;
        _dataServer.AutoSaveDebounceMs = 250;
    }

    public async Task InitializeAsync() {
        await _initSemaphore.WaitAsync().ConfigureAwait(false);
        try {
            if (_initialized)
                return;

            await _dataServer.LoadAsync().ConfigureAwait(false);
            ConfigureSqlLoginIpAllowList();
            _server.RegisterProtocol(_tds);
            RegisterSqlAdminDataServer(_websiteServer);
            if (_websiteSslServer != null)
                RegisterSqlAdminDataServer(_websiteSslServer);
            RegisterSqlAdminDataServer(_sqlLoopbackServer);
            SetSqlAdminPanelEnabled(true);

            _table = EnsureServerTable();
            _usersTable = EnsureTable(UsersTableName, AccountColumns);
            _registrationRequestsTable = EnsureTable(RegistrationRequestsTableName, RegistrationRequestColumns);
            _shellProxyTable = EnsureTable(ShellProxyTableName, ShellProxyColumns);
            _runtimeReportsTable = EnsureTable(RuntimeReportsTableName, RuntimeReportColumns);
            _masterLogsTable = EnsureTable(MasterLogsTableName, MasterLogColumns);
            _autoSessionsTable = EnsureTable(AutoSessionsTableName, AutoSessionColumns);
            _issueReportsTable = EnsureTable(IssueReportsTableName, IssueReportColumns);
            _issueSessionsTable = EnsureTable(IssueSessionsTableName, IssueSessionColumns);
            EnsureAgentBuilderStorage();
            AppendMasterLog("info", "startup", "SocketJack master-list storage initialized.", "");
            LoadShellRelaysFromTable();
            MapRoutes();
            MapWebsiteRoutes(_websiteServer);
            if (_websiteSslServer != null)
                MapWebsiteRoutes(_websiteSslServer);
            if (_options.JackcastEnabled && !_options.JackcastDedicatedListenersEnabled) {
                MapJackcastRoutes(_websiteServer);
                if (_websiteSslServer != null)
                    MapJackcastRoutes(_websiteSslServer);
            }
            if (_jackcastServer != null)
                MapJackcastRoutes(_jackcastServer);
            if (_jackcastSslServer != null)
                MapJackcastRoutes(_jackcastSslServer);

            _initialized = true;
        } finally {
            _initSemaphore.Release();
        }
    }

    private void ConfigureSqlLoginIpAllowList() {
        _dataServer.EnforceSqlLoginIpAllowList = true;
        _dataServer.AllowLoopbackSqlLogin = true;
        _dataServer.AllowSqlLoginIpAddress(_options.AllowedSqlLoginIpAddresses);
    }

    private void ConfigureSharedJackcastSslCertificate(MutableTcpServer websiteSslServer) {
        if (!_options.JackcastEnabled ||
            !_options.JackcastSslEnabled ||
            _options.JackcastDedicatedListenersEnabled)
            return;

        try {
            X509Certificate2 jackcastCertificate = LoadJackcastSslCertificate(_options);
            websiteSslServer.SslCertificateSelector = hostName => IsJackcastProxyHost(hostName)
                ? jackcastCertificate
                : websiteSslServer.SslCertificate;
        } catch (Exception ex) {
            _jackcastSslError = "Jackcast HTTPS uses SocketJack listener, but the Jackcast certificate is unavailable: " + ex.Message;
        }
    }

    private void RegisterSqlAdminDataServer(MutableTcpServer? server) {
        if (server == null)
            return;
        server.RegisterProtocol(_tds);
    }

    private IEnumerable<MutableTcpServer> GetSqlAdminPanelServers() {
        yield return _server;
        yield return _websiteServer;
        if (_websiteSslServer != null)
            yield return _websiteSslServer;
        if (_sqlLoopbackServer != null)
            yield return _sqlLoopbackServer;
    }

    private void SetSqlAdminPanelEnabled(bool enabled) {
        foreach (MutableTcpServer server in GetSqlAdminPanelServers())
            server.SqlAdminPanelEnabled = enabled;
    }

    private bool IsSqlAdminPanelEnabled() {
        foreach (MutableTcpServer server in GetSqlAdminPanelServers()) {
            if (server.SqlAdminPanelEnabled)
                return true;
        }
        return false;
    }

    private bool IsPublicSqlAdminPanelListening() {
        return _websiteServer.IsListening || (_websiteSslServer?.IsListening ?? false);
    }

    private bool IsSqlLoopbackPanelListening() {
        return _sqlLoopbackServer?.IsListening == true;
    }

    private string GetSqlAdminPanelListenerStatus() {
        if (!IsSqlAdminPanelEnabled())
            return "disabled";
        var listeners = new List<string>();
        if (IsSqlLoopbackPanelListening())
            listeners.Add("SQL loopback " + GetLocalSqlAdminUrl());
        if (_websiteSslServer?.IsListening == true)
            listeners.Add("website HTTPS listening");
        if (_websiteServer.IsListening)
            listeners.Add("website HTTP listening");
        if (_server.IsListening)
            listeners.Add("API listener");
        return listeners.Count == 0 ? "stopped" : string.Join(", ", listeners);
    }

    private MutableTcpServer CreateWebsiteServer(int port, string name) {
        var server = CreateServer(port, name);
        server.Options.Logging = false;
        server.CacheControl = "no-store";
        server.OnError += Server_OnError;
        server.OnHttpRequest += ShellProxy_OnHttpRequest;
        RegisterShellProxyWebSockets(server);
        return server;
    }

    private MutableTcpServer CreateWebsiteServer(int port, string name, IPAddress bindAddress) {
        var server = CreateServer(port, name, bindAddress);
        server.Options.Logging = false;
        server.CacheControl = "no-store";
        server.OnError += Server_OnError;
        server.OnHttpRequest += ShellProxy_OnHttpRequest;
        RegisterShellProxyWebSockets(server);
        return server;
    }

    private MutableTcpServer CreateSqlLoopbackServer(int port, string name, IPAddress bindAddress) {
        var server = CreateServer(port, name, bindAddress);
        server.Options.Logging = false;
        server.CacheControl = "no-store";
        server.OnError += Server_OnError;
        return server;
    }

    private void RegisterShellProxyWebSockets(MutableTcpServer server) {
        server.RegisterProtocol(new ShellProxyWebSocketTunnelHandler(this, _shellProxyWebSocketTunnels));
        server.RegisterProtocol(new ShellProxyWebChatWebSocketHandler(this, _shellProxyWebSocketTunnels));
        server.RegisterProtocol(new ShellProxyJsonWebSocketHandler(this));
        server.RegisterProtocol(new MasterListLiveWebSocketHandler(this));
    }

    private MutableTcpServer CreateServer(int port, string name) {
        return CreateServer(port, name, _options.BindAddress);
    }

    private MutableTcpServer CreateServer(int port, string name, IPAddress bindAddress) {
        NetworkOptions networkOptions = NetworkOptions.NewDefault();
        networkOptions.BindAddress = bindAddress;
        DisableDefaultSocketJackSecurity(networkOptions);
        return new MutableTcpServer(networkOptions, port, name);
    }

    private static void DisableDefaultSocketJackSecurity(NetworkOptions networkOptions) {
        networkOptions.EndpointSecurity.Enabled = false;
        networkOptions.EndpointSecurity.BlockKnownBadPaths = false;
        networkOptions.EndpointSecurity.TreatSuspiciousUserAgentsAsBad = false;
    }

    private static X509Certificate2 LoadWebsiteSslCertificate(MasterListOptions options) {
        return LoadSslCertificate(
            options.WebsiteSslCertificatePath,
            options.WebsiteSslCertificateKeyPath,
            options.WebsiteSslCertificatePassword,
            options.WebsiteSslCertificateSubject,
            "SocketJack HTTPS");
    }

    private static X509Certificate2 LoadJackcastSslCertificate(MasterListOptions options) {
        return LoadSslCertificate(
            options.JackcastSslCertificatePath,
            options.JackcastSslCertificateKeyPath,
            options.JackcastSslCertificatePassword,
            options.JackcastSslCertificateSubject,
            "Jackcast HTTPS");
    }

    private static X509Certificate2 LoadSslCertificate(string certificatePath, string keyPath, string configuredPassword, string subject, string description) {
        certificatePath = certificatePath ?? "";
        keyPath = keyPath ?? "";
        string password = ResolveSslPassword(certificatePath, keyPath, configuredPassword);
        var flags = X509KeyStorageFlags.MachineKeySet |
                    X509KeyStorageFlags.PersistKeySet |
                    X509KeyStorageFlags.Exportable;

        foreach (string pfxPath in GetPfxCandidates(certificatePath, subject)) {
            if (!File.Exists(pfxPath))
                continue;

            var certificate = string.IsNullOrEmpty(password)
                ? new X509Certificate2(pfxPath, (string?)null, flags)
                : new X509Certificate2(pfxPath, password, flags);
            if (IsCertificateUsable(certificate, subject, description))
                return certificate;
            certificate.Dispose();
        }

        if (File.Exists(certificatePath)) {
            if (File.Exists(keyPath)) {
                X509Certificate2 certificate = string.IsNullOrEmpty(password)
                    ? X509Certificate2.CreateFromPemFile(certificatePath, keyPath)
                    : X509Certificate2.CreateFromEncryptedPemFile(certificatePath, password, keyPath);
                X509Certificate2 imported = ReimportCertificate(certificate, password, flags, subject, description);
                return imported;
            }

            var publicCertificate = new X509Certificate2(certificatePath);
            if (publicCertificate.HasPrivateKey)
                return ReimportCertificate(publicCertificate, password, flags, subject, description);

            X509Certificate2? storeMatch = FindStoreCertificateWithPrivateKey(publicCertificate, subject, description);
            if (storeMatch != null)
                return storeMatch;
        }

        X509Certificate2? subjectMatch = FindStoreCertificateWithPrivateKey(null, subject, description);
        if (subjectMatch != null)
            return subjectMatch;

        throw new InvalidOperationException(
            "Unable to load a " + description + " certificate with a private key. " +
            "Configure a PFX, configure a PEM certificate/key pair, " +
            "or install a matching certificate with its private key in the Windows LocalMachine or CurrentUser Personal certificate store.");
    }

    private static string ResolveWebsiteSslPassword(MasterListOptions options) {
        return ResolveSslPassword(options.WebsiteSslCertificatePath, options.WebsiteSslCertificateKeyPath, options.WebsiteSslCertificatePassword);
    }

    private static string ResolveSslPassword(string certificatePath, string keyPath, string configuredPassword) {
        string password = configuredPassword ?? "";
        if (!string.IsNullOrEmpty(password))
            return password;

        keyPath = keyPath ?? "";
        string certificateExtension = Path.GetExtension(certificatePath ?? "");
        bool certificateIsPfx =
            string.Equals(certificateExtension, ".pfx", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(certificateExtension, ".p12", StringComparison.OrdinalIgnoreCase);

        if (certificateIsPfx && File.Exists(keyPath))
            return File.ReadAllText(keyPath).Trim();

        return "";
    }

    private static IEnumerable<string> GetPfxCandidates(string certificatePath, string subject) {
        if (!string.IsNullOrWhiteSpace(certificatePath)) {
            string extension = Path.GetExtension(certificatePath);
            if (string.Equals(extension, ".pfx", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(extension, ".p12", StringComparison.OrdinalIgnoreCase))
                yield return certificatePath;

            string? directory = Path.GetDirectoryName(certificatePath);
            string name = Path.GetFileNameWithoutExtension(certificatePath);
            if (!string.IsNullOrWhiteSpace(directory) && !string.IsNullOrWhiteSpace(name)) {
                yield return Path.Combine(directory, name + ".pfx");
                yield return Path.Combine(directory, name + ".p12");
            }
        }

        string normalizedSubject = Regex.Replace(subject ?? "", "[^A-Za-z0-9]+", "_").Trim('_').ToLowerInvariant();
        if (!string.IsNullOrWhiteSpace(normalizedSubject)) {
            yield return @"C:\" + normalizedSubject + ".pfx";
            yield return @"C:\" + normalizedSubject + ".p12";
        }
    }

    private static X509Certificate2 ReimportCertificate(X509Certificate2 certificate, string password, X509KeyStorageFlags flags, string subject, string description) {
        if (!certificate.HasPrivateKey)
            throw new InvalidOperationException("The configured " + description + " certificate does not include a private key.");

        byte[] pfx = certificate.Export(X509ContentType.Pfx, password);
        certificate.Dispose();
        var imported = new X509Certificate2(pfx, password, flags);
        if (!IsCertificateUsable(imported, subject, description)) {
            imported.Dispose();
            throw new InvalidOperationException("The configured " + description + " certificate is not usable for " + subject + ".");
        }
        return imported;
    }

    private static bool IsCertificateUsable(X509Certificate2 certificate, string subject, string description) {
        if (certificate == null || !certificate.HasPrivateKey)
            return false;
        if (certificate.NotAfter <= DateTime.Now)
            return false;
        if (!string.IsNullOrWhiteSpace(subject) && !IsCertificateMatch(certificate, null, subject))
            return false;

        try {
            using RSA? rsa = certificate.GetRSAPrivateKey();
            using ECDsa? ecdsa = certificate.GetECDsaPrivateKey();
            if (rsa == null && ecdsa == null)
                throw new InvalidOperationException("The certificate private key is neither RSA nor ECDSA.");
        } catch (Exception ex) {
            throw new InvalidOperationException(
                "The " + description + " certificate private key could not be opened by this process. " +
                "Check the PFX password and private-key permissions.", ex);
        }

        return true;
    }

    private static X509Certificate2? FindStoreCertificateWithPrivateKey(X509Certificate2? publicCertificate, string subject, string description) {
        foreach (StoreLocation location in new[] { StoreLocation.LocalMachine, StoreLocation.CurrentUser }) {
            using var store = new X509Store(StoreName.My, location);
            try {
                store.Open(OpenFlags.ReadOnly);
            } catch {
                continue;
            }

            X509Certificate2? certificate = store.Certificates
                .OfType<X509Certificate2>()
                .Where(candidate => candidate.HasPrivateKey && IsCertificateMatch(candidate, publicCertificate, subject))
                .Where(candidate => candidate.NotAfter > DateTime.Now)
                .OrderByDescending(candidate => candidate.NotAfter)
                .FirstOrDefault();
            if (certificate != null && IsCertificateUsable(certificate, subject, description))
                return new X509Certificate2(certificate);
        }

        return null;
    }

    private static bool IsCertificateMatch(X509Certificate2 candidate, X509Certificate2? publicCertificate, string subject) {
        if (publicCertificate != null &&
            string.Equals(candidate.Thumbprint, publicCertificate.Thumbprint, StringComparison.OrdinalIgnoreCase))
            return true;

        subject = NormalizeCertificateHostName(subject);
        if (subject.Length == 0)
            return false;

        string dnsName = candidate.GetNameInfo(X509NameType.DnsName, false);
        if (CertificateNameMatches(dnsName, subject))
            return true;

        foreach (string sanName in GetCertificateDnsSubjectAlternativeNames(candidate)) {
            if (CertificateNameMatches(sanName, subject))
                return true;
        }

        return candidate.Subject.IndexOf(subject, StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static string NormalizeCertificateHostName(string hostName) {
        hostName = (hostName ?? "").Trim().TrimEnd('.');
        if (hostName.StartsWith("http://", StringComparison.OrdinalIgnoreCase) ||
            hostName.StartsWith("https://", StringComparison.OrdinalIgnoreCase)) {
            if (Uri.TryCreate(hostName, UriKind.Absolute, out Uri? uri))
                hostName = uri.Host;
        }

        return hostName.Trim().TrimEnd('.').ToLowerInvariant();
    }

    private static bool CertificateNameMatches(string certificateName, string requestedHost) {
        certificateName = NormalizeCertificateHostName(certificateName);
        requestedHost = NormalizeCertificateHostName(requestedHost);
        if (certificateName.Length == 0 || requestedHost.Length == 0)
            return false;

        if (string.Equals(certificateName, requestedHost, StringComparison.OrdinalIgnoreCase))
            return true;

        if (!certificateName.StartsWith("*.", StringComparison.Ordinal))
            return false;

        string suffix = certificateName.Substring(1);
        return requestedHost.EndsWith(suffix, StringComparison.OrdinalIgnoreCase) &&
               requestedHost.Count(ch => ch == '.') == suffix.Count(ch => ch == '.');
    }

    private static IEnumerable<string> GetCertificateDnsSubjectAlternativeNames(X509Certificate2 certificate) {
        foreach (X509Extension extension in certificate.Extensions) {
            if (!string.Equals(extension.Oid?.Value, "2.5.29.17", StringComparison.Ordinal))
                continue;

            string formatted = extension.Format(multiLine: true);
            foreach (string rawLine in formatted.Split(new[] { '\r', '\n', ',' }, StringSplitOptions.RemoveEmptyEntries)) {
                string line = rawLine.Trim();
                const string dnsPrefix = "DNS Name=";
                if (line.StartsWith(dnsPrefix, StringComparison.OrdinalIgnoreCase))
                    yield return line.Substring(dnsPrefix.Length).Trim();
            }
        }
    }

    public bool IsListening => _server.IsListening || _websiteServer.IsListening || (_websiteSslServer?.IsListening ?? false) || (_sqlLoopbackServer?.IsListening ?? false) || (_jackcastServer?.IsListening ?? false) || (_jackcastSslServer?.IsListening ?? false);
    public bool IsApiListening => _server.IsListening;
    public bool IsWebsiteListening => _websiteServer.IsListening || (_websiteSslServer?.IsListening ?? false) || (_jackcastServer?.IsListening ?? false) || (_jackcastSslServer?.IsListening ?? false);
    public int Port => _options.Port;
    public int WebsitePort => _options.WebsitePort;
    public int WebsiteSslPort => _options.WebsiteSslPort;
    public string WebsitePortsText => _options.WebsiteSslEnabled
        ? _options.WebsitePort.ToString(CultureInfo.InvariantCulture) + " HTTP, " + _options.WebsiteSslPort.ToString(CultureInfo.InvariantCulture) + " HTTPS" + (_websiteSslServer == null ? " unavailable" : "")
        : _options.WebsitePort.ToString(CultureInfo.InvariantCulture) + " HTTP";
