    public string LocalSqlAdminUrl => GetLocalSqlAdminUrl();
    public string SecureAuthorityTargetUrl => _options.SecureAuthorityTargetUrl;
    public string JackcastHostName => _options.JackcastHostName;
    public string JackcastTargetUrl => _options.JackcastTargetUrl;
    public string JackcastBindAddressText => _options.JackcastBindAddress.ToString();
    public bool JackcastEnabled => _options.JackcastEnabled;
    public bool JackcastSslEnabled => _options.JackcastSslEnabled;
    public bool WebsiteSslEnabled => _options.WebsiteSslEnabled;
