    internal long ServerListVersion => Interlocked.Read(ref _serverListVersion);
    internal long AutoLiveVersion => Interlocked.Read(ref _autoLiveVersion);

    private void MarkServerListChanged() {
        Interlocked.Increment(ref _serverListVersion);
        lock (_masterListLiveSnapshotLock)
            _cachedMasterListLivePayload = null;
    }

    private void NotifyServersChanged() {
        MarkServerListChanged();
        ServerListChanged?.Invoke(this, EventArgs.Empty);
        ServersChanged?.Invoke(this, EventArgs.Empty);
    }

    private void NotifyShellRelaysChanged(bool affectsServerList = true) {
        if (affectsServerList) {
            MarkServerListChanged();
            ServerListChanged?.Invoke(this, EventArgs.Empty);
        }
        ShellRelaysChanged?.Invoke(this, EventArgs.Empty);
    }

    private void NotifyAutoLiveDataChanged() {
        Interlocked.Increment(ref _autoLiveVersion);
        AutoLiveDataChanged?.Invoke(this, EventArgs.Empty);
    }

    public bool Start() {
        if (_server.IsListening &&
            _websiteServer.IsListening &&
            (_websiteSslServer == null || _websiteSslServer.IsListening) &&
            (_sqlLoopbackServer == null || _sqlLoopbackServer.IsListening) &&
            (!_options.JackcastDedicatedListenersEnabled || _jackcastServer == null || _jackcastServer.IsListening) &&
            (!_options.JackcastDedicatedListenersEnabled || _jackcastSslServer == null || _jackcastSslServer.IsListening))
            return true;

        bool apiStarted = _server.IsListening || _server.Listen();
        bool websiteStarted = _websiteServer.IsListening || _websiteServer.Listen();
        bool websiteSslStarted = !_options.WebsiteSslEnabled || (_websiteSslServer != null && (_websiteSslServer.IsListening || _websiteSslServer.Listen()));
        bool jackcastStarted = !_options.JackcastEnabled ||
                               (!_options.JackcastDedicatedListenersEnabled && websiteStarted) ||
                               (_jackcastServer != null && (_jackcastServer.IsListening || _jackcastServer.Listen()));
        bool jackcastSslStarted = !_options.JackcastEnabled ||
                                  !_options.JackcastSslEnabled ||
                                  (!_options.JackcastDedicatedListenersEnabled && websiteSslStarted) ||
                                  (_jackcastSslServer != null && (_jackcastSslServer.IsListening || _jackcastSslServer.Listen()));
        bool sqlLoopbackStarted = _sqlLoopbackServer == null || _sqlLoopbackServer.IsListening || _sqlLoopbackServer.Listen();
        _sqlLoopbackError = sqlLoopbackStarted || _sqlLoopbackServer == null
            ? ""
            : "SQL loopback unavailable at " + GetLocalSqlAdminUrl();
        if (_jackcastServer != null)
            _jackcastServer.EnablePort80HttpsRedirect = jackcastSslStarted;
        StartEnabledShellRelays();
        string sqlLoopbackStatus = _sqlLoopbackServer == null
            ? ""
            : sqlLoopbackStarted
                ? "; SQL loopback " + GetLocalSqlAdminUrl()
                : "; " + _sqlLoopbackError;
        LastStatus = apiStarted && websiteStarted && websiteSslStarted && jackcastStarted && jackcastSslStarted
            ? "Listening: website " + WebsitePortsText + ", API " + _options.Port.ToString(CultureInfo.InvariantCulture)
            : apiStarted
                ? websiteStarted
                    ? !websiteSslStarted
                        ? FirstNonEmpty(_websiteSslError, "API and HTTP website listening; HTTPS website unavailable")
                        : !jackcastSslStarted
                            ? FirstNonEmpty(_jackcastSslError, "API and SocketJack website listening; Jackcast HTTPS unavailable")
                            : "API and SocketJack website listening; Jackcast unavailable"
                    : "API listening; website ports unavailable"
                : websiteStarted
                    ? "Website listening; API port unavailable"
                    : "Ports unavailable";
        LastStatus += sqlLoopbackStatus;
        AppendMasterLog(apiStarted && websiteStarted ? "info" : "warning", "service", LastStatus);
        StatusChanged?.Invoke(this, EventArgs.Empty);
        return apiStarted && websiteStarted && websiteSslStarted && jackcastStarted && jackcastSslStarted;
    }

    public void Stop() {
        if (_server.IsListening)
            _server.StopListening();
        if (_websiteServer.IsListening)
            _websiteServer.StopListening();
        if (_websiteSslServer?.IsListening == true)
            _websiteSslServer.StopListening();
        if (_sqlLoopbackServer?.IsListening == true)
            _sqlLoopbackServer.StopListening();
        if (_jackcastServer?.IsListening == true)
            _jackcastServer.StopListening();
        if (_jackcastSslServer?.IsListening == true)
            _jackcastSslServer.StopListening();
        StopAllShellRelays();
        LastStatus = "Stopped";
        AppendMasterLog("info", "service", LastStatus);
        StatusChanged?.Invoke(this, EventArgs.Empty);
    }

    public List<MasterShellRelay> GetShellRelays() {
        lock (_sync) {
            return _shellRelays.Values
                .OrderBy(relay => relay.PublicPort)
                .Select(UpdateShellRelayRuntime)
                .Select(relay => relay.Clone())
                .ToList();
        }
    }

    public MasterShellRelay UpsertShellRelay(MasterShellRelay relay) {
        if (relay == null)
            throw new InvalidOperationException("Shell relay payload is required.");
        relay.Normalize();
        if (IsReservedPort(relay.PublicPort) || IsReservedPort(relay.AgentPort))
            throw new InvalidOperationException("Shell ports cannot match the master API or website ports.");
        if (relay.PublicPort == relay.AgentPort)
            throw new InvalidOperationException("Public and agent ports must be different.");

        lock (_sync) {
            PrepareShellRelayProxyFieldsLocked(relay);
            if (_shellRelays.Values.Any(existing =>
                    !string.Equals(existing.Id, relay.Id, StringComparison.OrdinalIgnoreCase) &&
                    (existing.PublicPort == relay.PublicPort || existing.AgentPort == relay.AgentPort ||
                     existing.PublicPort == relay.AgentPort || existing.AgentPort == relay.PublicPort)))
                throw new InvalidOperationException("A shell relay already uses one of those ports.");

            bool wasRunning = _shellRelayServers.ContainsKey(relay.Id);
            if (wasRunning)
                StopShellRelayLocked(relay.Id);

            _shellRelays[relay.Id] = relay.Clone();
            SaveShellRelayLocked(_shellRelays[relay.Id]);
            if (relay.Enabled && IsListening)
                StartShellRelayLocked(relay.Id);

            NotifyShellRelaysChanged();
            return UpdateShellRelayRuntime(_shellRelays[relay.Id]).Clone();
        }
    }

    private bool IsReservedPort(int port) {
        return port == _options.Port || port == _options.WebsitePort || (_options.WebsiteSslEnabled && port == _options.WebsiteSslPort);
    }

    public void SetShellRelayEnabled(string id, bool enabled) {
        if (string.IsNullOrWhiteSpace(id))
            return;

        lock (_sync) {
            if (!_shellRelays.TryGetValue(id, out MasterShellRelay? relay))
                return;

            relay.Enabled = enabled;
            if (enabled && IsListening)
                StartShellRelayLocked(id);
            else
                StopShellRelayLocked(id);
            SaveShellRelayLocked(relay);

            NotifyShellRelaysChanged();
        }
    }

    public void RemoveShellRelay(string id) {
        if (string.IsNullOrWhiteSpace(id))
            return;

        bool removedServer = false;
        lock (_sync) {
            _shellRelays.TryGetValue(id, out MasterShellRelay? relay);
            StopShellRelayLocked(id);
            _shellRelays.Remove(id);
            RemoveShellRelayRowLocked(id);
            if (!string.IsNullOrWhiteSpace(relay?.ServerId)) {
                int serverIndex = FindRowIndexLocked(relay.ServerId);
                if (serverIndex >= 0) {
                    _table.Rows.RemoveAt(serverIndex);
                    removedServer = true;
                }
            }
            _dataServer.Save();
            NotifyShellRelaysChanged();
        }

        if (removedServer)
            NotifyServersChanged();
    }

    public MasterListResponse BuildResponse(bool refreshAvailability = false) {
        List<RegisteredServer> servers = GetServers(refreshAvailability: refreshAvailability)
            .Where(server => !server.WebsiteHidden)
            .Select(BuildPublicServerListEntry)
            .ToList();
        return new MasterListResponse {
            PublicUrl = _options.PublicUrl,
            UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture),
            Count = servers.Count,
            Servers = servers
        };
    }

    private MasterListResponse BuildResponse(HttpRequest request) =>
        BuildResponse(ShouldRefreshMasterListResponse(request));

    private static bool ShouldRefreshMasterListResponse(HttpRequest request) =>
        IsTruthyText(FirstNonEmpty(
            GetQuery(request, "fresh"),
            GetQuery(request, "refresh"),
            GetQuery(request, "refreshAvailability"),
            GetQuery(request, "refresh_availability")));

    private RegisteredServer BuildPublicServerListEntry(RegisteredServer server) {
        RegisteredServer publicServer = server.Clone();
        publicServer.HydrateFromStoredRegistration();
        string proxyEndpoint = ResolvePublicProxyEndpoint(server);
        string publicHost = NormalizePublicHost(_options.WebsitePublicUrl);
        int publicPort = ResolvePublicPort(proxyEndpoint);

        publicServer.Endpoint = proxyEndpoint;
        publicServer.LaunchUrl = proxyEndpoint;
        publicServer.BackgroundImageUrl = BuildServerBackgroundImageUrl(publicServer);
        publicServer.ConnectHost = string.IsNullOrWhiteSpace(proxyEndpoint) ? "" : publicHost;
        publicServer.IpAddress = "";
        publicServer.RegisteredByIp = "";
        publicServer.ProxyPort = publicPort;
        publicServer.ChatPort = publicPort;
        publicServer.LmStudioPort = publicPort;
        publicServer.FtpPort = 0;
        publicServer.ExtraJson = "";
        publicServer.SearchText = string.Join(" ", new[] {
            publicServer.Id,
            publicServer.Title,
            publicServer.DisplayName,
            publicServer.Description,
            publicServer.AvailableModels,
            publicServer.ModelCapabilitiesJson,
            publicServer.ModelBenchmarksJson,
            publicServer.ToolsAllowed,
            publicServer.AvailableRam,
            publicServer.AvailableVram,
            publicServer.AvailableResources,
            publicServer.StorageAvailable,
            publicServer.GpuModel,
            publicServer.GpuAvailable,
            publicServer.CpuModel,
            publicServer.CpuAvailable,
            publicServer.OwnerUserName,
            publicServer.ModelRuntimeProvider,
            publicServer.ModelRuntimeStatus,
            publicServer.LlmRuntimeStatus
        });
        return publicServer;
    }

    private string ResolvePublicProxyEndpoint(RegisteredServer server) {
        string endpoint = FirstPublicProxyUrl(server.Endpoint, server.LaunchUrl);
        if (!string.IsNullOrWhiteSpace(endpoint))
            return endpoint;

        lock (_sync) {
            MasterShellRelay? relay = _shellRelays.Values.FirstOrDefault(candidate =>
                string.Equals(candidate.ServerId, server.Id, StringComparison.OrdinalIgnoreCase));
            if (relay != null)
                return BuildShellProxyEndpoint(relay.RouteName);
        }

        return "";
    }

    private static string FirstPublicProxyUrl(params string[] values) {
        foreach (string value in values) {
            if (IsPublicProxyUrl(value))
                return value.Trim();
        }
        return "";
    }

    private static bool IsPublicProxyUrl(string value) {
        if (string.IsNullOrWhiteSpace(value) || !Uri.TryCreate(value.Trim(), UriKind.Absolute, out Uri? uri))
            return false;
        if (!uri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
            return false;
        return !IPAddress.TryParse(uri.Host, out _);
    }

    private int ResolvePublicPort(string proxyEndpoint) {
        if (Uri.TryCreate(proxyEndpoint, UriKind.Absolute, out Uri? uri) && !uri.IsDefaultPort)
            return uri.Port;
        if (_options.WebsiteSslEnabled)
            return _options.WebsiteSslPort;
        return _options.WebsitePort;
    }

    private static string BuildServerBackgroundImageUrl(RegisteredServer server) {
        string key = NormalizeServerBackgroundKey(server?.BackgroundImageKey ?? "");
        return string.IsNullOrWhiteSpace(key)
            ? ""
            : "/api/lmvsproxy/server-background/" + Uri.EscapeDataString(key) + ".jpg";
    }

    public object BuildPricingResponse(HttpRequest request) {
        PricingConfig config = ReadPricingConfigFromSettings();
        return new {
            tokenUsdPerToken = config.TokenUsdPerToken,
            tokenUsdPerMillion = config.TokenUsdPerToken * 1_000_000d,
            serviceFeePercent = config.ServiceFeePercent,
            serviceFeeRate = config.ServiceFeePercent / 100d,
            currency = "usd",
            products = BuildStripeTokenProductPayloads(includeDisabled: false),
            source = "master-list-database",
            updatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
        };
    }

    private object BuildTokenProductsResponse(bool includeDisabled) {
        return new {
            ok = true,
            currency = "usd",
            products = BuildStripeTokenProductPayloads(includeDisabled),
            updatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
        };
    }

    private static PricingConfig ReadPricingConfigFromSettings() {
        JsonObject root = LoadAppSettingsRoot();
        JsonObject? section = root["SocketJackMagicMasterList"] as JsonObject;
        double tokenUsdPerToken = ParseConfigDouble(
            RegisteredServer.FirstNonEmpty(GetJsonText(section, "StripeTokenUsdPerToken"), Environment.GetEnvironmentVariable("SOCKETJACK_TOKEN_USD_PER_TOKEN")),
            0.00005,
            0);
        double serviceFeePercent = ParseConfigDouble(
            RegisteredServer.FirstNonEmpty(GetJsonText(section, "StripeServiceFeePercent"), Environment.GetEnvironmentVariable("SOCKETJACK_STRIPE_SERVICE_FEE_PERCENT")),
            1.5,
            0);
        return new PricingConfig(tokenUsdPerToken, serviceFeePercent);
    }

    private static List<object> BuildStripeTokenProductPayloads(bool includeDisabled) {
        return ReadStripeTokenProductsFromSettings()
            .Where(product => includeDisabled || product.Enabled)
            .Select(product => {
                long amountCents = ResolveStripeTokenProductUnitAmountCents(product);
                bool configured = !string.IsNullOrWhiteSpace(product.PriceId) ||
                                  (!string.IsNullOrWhiteSpace(product.ProductId) && amountCents >= 50);
                return (object)new {
                    productId = product.ProductId,
                    name = product.Name,
                    description = product.Description,
                    tokenAmount = product.TokenAmount,
                    unitAmountCents = amountCents,
                    currency = string.IsNullOrWhiteSpace(product.Currency) ? "usd" : product.Currency,
                    enabled = product.Enabled,
                    configured,
                    priceIdConfigured = !string.IsNullOrWhiteSpace(product.PriceId)
                };
            })
            .ToList();
    }

    private static List<StripeTokenProductConfig> ReadStripeTokenProductsFromSettings() {
        JsonObject root = LoadAppSettingsRoot();
        JsonObject? section = root["SocketJackMagicMasterList"] as JsonObject;
        if (section == null ||
            !section.TryGetPropertyValue("StripeTokenProducts", out JsonNode? node) ||
            node == null)
            return StripeTokenProductCatalog.CreateDefaultProducts().Select(product => product.Clone()).ToList();

        try {
            return StripeTokenProductCatalog.Normalize(
                JsonSerializer.Deserialize<List<StripeTokenProductConfig>>(
                    node.ToJsonString(),
                    new JsonSerializerOptions { PropertyNameCaseInsensitive = true }) ?? []);
        } catch {
            return StripeTokenProductCatalog.CreateDefaultProducts().Select(product => product.Clone()).ToList();
        }
    }

    private static long ResolveStripeTokenProductUnitAmountCents(StripeTokenProductConfig product) {
        if (product == null)
            return 0;
        if (product.UnitAmountCents > 0)
            return product.UnitAmountCents;

        PricingConfig pricing = ReadPricingConfigFromSettings();
        decimal amount = (decimal)Math.Max(0, product.TokenAmount) * (decimal)Math.Max(0, pricing.TokenUsdPerToken) * 100m;
        if (amount <= 0)
            return 0;
        if (amount > long.MaxValue)
            return long.MaxValue;
        return (long)decimal.Round(amount, 0, MidpointRounding.AwayFromZero);
    }

    private static JsonObject LoadAppSettingsRoot() {
        string path = Path.Combine(AppContext.BaseDirectory, "appsettings.json");
        if (!File.Exists(path))
            path = Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "appsettings.json");
        if (!File.Exists(path))
            return new JsonObject();

        try {
            JsonNode? node = JsonNode.Parse(File.ReadAllText(path));
            return node as JsonObject ?? new JsonObject();
        } catch {
            return new JsonObject();
        }
    }

    private static string GetJsonText(JsonObject? section, string name) {
        if (section == null || !section.TryGetPropertyValue(name, out JsonNode? node) || node == null)
            return "";
        return node.GetValueKind() == JsonValueKind.String
            ? node.GetValue<string>() ?? ""
            : node.ToJsonString().Trim('"');
    }

    private static double ParseConfigDouble(string value, double fallback, double minimum) {
        if (!double.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed))
            parsed = fallback;
        if (double.IsNaN(parsed) || double.IsInfinity(parsed))
            parsed = fallback;
        return Math.Max(minimum, parsed);
    }

    public int Count() {
        return GetServers(refreshAvailability: false).Count;
    }

    public List<RegisteredServer> GetServers() {
        return GetServers(refreshAvailability: false);
    }

    private List<RegisteredServer> GetServers(bool refreshAvailability) {
        lock (_sync) {
            DateTimeOffset now = DateTimeOffset.UtcNow;
            bool shellRowsChanged = EnsureShellRelayServerRowsLocked(now);
            bool statusChanged = refreshAvailability && UpdateServerAvailabilityLocked(now, allowLiveChecks: true);
            if (shellRowsChanged || statusChanged) {
                _dataServer.Save();
                MarkServerListChanged();
            }

            List<RegisteredServer> servers = _table.Rows
                .Select(RowToServer)
                .Where(server => !string.IsNullOrWhiteSpace(server.Id))
                .Select(server => ApplyAvailability(server, now, refreshAvailability))
                .OrderByDescending(server => server.LastSeenSort)
                .ThenBy(server => server.TitleText, StringComparer.OrdinalIgnoreCase)
                .ToList();

            return CollapseDuplicateWebsiteListings(servers)
                .Select(server => server.Clone())
                .ToList();
        }
    }

    private bool EnsureShellRelayServerRowsLocked(DateTimeOffset now) {
        bool changed = false;
        string publicHost = NormalizePublicHost(_options.WebsitePublicUrl);
        foreach (MasterShellRelay relay in _shellRelays.Values) {
            if (relay == null || !relay.Enabled || string.IsNullOrWhiteSpace(relay.ServerId))
                continue;

            int existingIndex = FindRowIndexLocked(relay.ServerId);
            RegisteredServer? existing = existingIndex >= 0 ? RowToServer(_table.Rows[existingIndex]) : null;
            string existingEndpoint = existing == null ? "" : FirstPublicProxyUrl(existing.Endpoint, existing.LaunchUrl);
            if (existing != null && !existing.WebsiteHidden && !string.IsNullOrWhiteSpace(existingEndpoint))
                continue;

            string endpoint = FirstNonEmpty(existingEndpoint, relay.Endpoint, BuildShellProxyEndpoint(relay.RouteName));
            int publicPort = ResolvePublicPort(endpoint);
            bool online = relay.IsRunning && (relay.WebSocketTunnelConnected || relay.WaitingAgents > 0 || relay.ActiveSessions > 0);
            string status = online
                ? (relay.WebSocketTunnelConnected ? "Shell proxy online - JackLLM WebSocket tunnel connected" : "Shell proxy online")
                : FirstNonEmpty(relay.Status, "Shell proxy route ready");
            string timestamp = now.ToString("O", CultureInfo.InvariantCulture);
            RegisteredServer server = existing?.Clone() ?? new RegisteredServer();
            server.Id = relay.ServerId;
            server.Title = FirstNonEmpty(server.Title, relay.Name);
            server.DisplayName = FirstNonEmpty(server.DisplayName, relay.Name);
            server.Endpoint = endpoint;
            server.LaunchUrl = endpoint;
            server.ConnectHost = publicHost;
            server.IpAddress = publicHost;
            server.ProxyPort = publicPort;
            server.ChatPort = publicPort;
            server.LmStudioPort = publicPort;
            server.FtpPort = 0;
            server.WebsiteHidden = false;
            server.FirstSeenUtc = FirstNonEmpty(server.FirstSeenUtc, relay.CreatedUtc, timestamp);
            server.LastSeenUtc = timestamp;
            server.StartedUtc = FirstNonEmpty(server.StartedUtc, relay.CreatedUtc, timestamp);
            server.UpdatedUtc = timestamp;
            server.LastStatus = status;
            server.StatusText = status;
            server.IsOnline = online;
            server.HostResponding = online;
            server.LmStudioConnected = online;
            server.ModelRuntimeProvider = FirstNonEmpty(server.ModelRuntimeProvider, "LlmRuntime");
            server.ModelRuntimeConnected = online;
            server.ModelRuntimeStatus = online ? "Connected" : FirstNonEmpty(server.ModelRuntimeStatus, "Unknown");
            server.LlmRuntimeConnected = online;
            server.LlmRuntimeStatus = online ? "Connected" : FirstNonEmpty(server.LlmRuntimeStatus, "Unknown");
            server.OwnerKey = FirstNonEmpty(server.OwnerKey, relay.OwnerKey);
            server.OwnerTokenHash = FirstNonEmpty(server.OwnerTokenHash, relay.OwnerTokenHash);
            server.SearchText = string.Join(" ", new[] {
                server.Id,
                server.Title,
                server.DisplayName,
                server.Endpoint,
                relay.RouteName,
                relay.ProxyPath,
                relay.PublicPort.ToString(CultureInfo.InvariantCulture),
                relay.AgentPort.ToString(CultureInfo.InvariantCulture),
                relay.TransportMode
            });
            server.Normalize();
            object[] nextRow = ServerToRow(server);
            if (existingIndex >= 0) {
                if (!ShellRelayPublishedServerRowsEquivalent(_table.Rows[existingIndex], nextRow)) {
                    _table.Rows[existingIndex] = nextRow;
                    _healthCache.Remove(server.Id);
                    changed = true;
                }
            } else {
                _table.Rows.Insert(0, nextRow);
                _healthCache.Remove(server.Id);
                changed = true;
            }
        }

        return changed;
    }

    private static bool ShellRelayPublishedServerRowsEquivalent(object[] existingRow, object[] nextRow) {
        if (existingRow == null || nextRow == null)
            return false;

        for (int i = 0; i < ServerColumns.Length; i++) {
            string column = ServerColumns[i];
            if (column.Equals(nameof(RegisteredServer.LastSeenUtc), StringComparison.OrdinalIgnoreCase) ||
                column.Equals(nameof(RegisteredServer.UpdatedUtc), StringComparison.OrdinalIgnoreCase))
                continue;

            string existing = i < existingRow.Length ? Convert.ToString(existingRow[i], CultureInfo.InvariantCulture) ?? "" : "";
            string next = i < nextRow.Length ? Convert.ToString(nextRow[i], CultureInfo.InvariantCulture) ?? "" : "";
            if (!string.Equals(existing, next, StringComparison.Ordinal))
                return false;
        }

        return true;
    }

    public RegisteredServer Register(JsonElement root, string remoteIp, HttpRequest request) {
        RegisteredServer incoming = RegisteredServer.FromRegistration(root, remoteIp);
        string action = RegisteredServer.FirstNonEmpty(RegisteredServer.GetString(root, "action"), "online").Trim();
        bool deleteRequested = action.Equals("delete", StringComparison.OrdinalIgnoreCase) ||
                               action.Equals("remove", StringComparison.OrdinalIgnoreCase);
        bool hideFromWebsite = deleteRequested ||
                               action.Equals("unpublish", StringComparison.OrdinalIgnoreCase) ||
                               action.Equals("hide", StringComparison.OrdinalIgnoreCase) ||
                               action.Equals("hidden", StringComparison.OrdinalIgnoreCase) ||
                               !RegisteredServer.GetBool(root, "visibleOnWebsite", RegisteredServer.GetBool(root, "publishEnabled", !RegisteredServer.GetBool(root, "offline", false)));
        if (!deleteRequested && !hideFromWebsite)
            ValidatePublishableHost(incoming, remoteIp);

        AccountRecord? account = AuthenticateRequest(request, out _);
        if (account == null)
            throw new InvalidOperationException("SocketJack.com login is required to publish JackLLM servers.");
        string ownerKey = BuildOwnerKey(account.UserName);
        string ownerTokenHash = HashOwnerToken(ExtractOwnerTokenFromRequest(request));
        incoming.OwnerUserName = RegisteredServer.FirstNonEmpty(incoming.OwnerUserName, account.UserName);

        lock (_sync) {
            UpdateServerAvailabilityLocked(DateTimeOffset.UtcNow, allowLiveChecks: false);
            int existingIndex = FindPublishedServerRowIndexLocked(incoming, remoteIp, ownerKey, ownerTokenHash);
            RegisteredServer? existing = existingIndex >= 0 ? RowToServer(_table.Rows[existingIndex]) : null;
            if (existing != null && !IsServerOwnerAuthorized(existing, request, remoteIp, ownerKey, ownerTokenHash))
                throw new InvalidOperationException("Only the owner of this server can change or delete it.");

            if (deleteRequested) {
                if (existingIndex < 0)
                    throw new InvalidOperationException("Server not found.");
                _table.Rows.RemoveAt(existingIndex);
                _dataServer.Save();
                LastStatus = "Deleted " + incoming.Id;
                AppendMasterLog("info", "server", LastStatus, "", account.UserName, remoteIp, request.Path);
                NotifyServersChanged();
                StatusChanged?.Invoke(this, EventArgs.Empty);
                return existing?.Clone() ?? incoming.Clone();
            }

            incoming.WebsiteHidden = hideFromWebsite;
            if (hideFromWebsite) {
                incoming.LastSeenUtc = existing?.LastSeenUtc ?? incoming.LastSeenUtc;
                incoming.LastStatus = "Hidden from website";
            }
            incoming.OwnerKey = RegisteredServer.FirstNonEmpty(existing?.OwnerKey, ownerKey);
            incoming.OwnerTokenHash = RegisteredServer.FirstNonEmpty(existing?.OwnerTokenHash, ownerTokenHash);
            PreserveServerBackground(existing, incoming);

            if (existingIndex >= 0) {
                incoming.FirstSeenUtc = existing?.FirstSeenUtc ?? incoming.FirstSeenUtc;
                _table.Rows[existingIndex] = ServerToRow(incoming);
            } else {
                _table.Rows.Insert(0, ServerToRow(incoming));
                existingIndex = 0;
            }

            RemoveDuplicatePublishedServerRowsLocked(incoming, existingIndex, remoteIp, ownerKey, ownerTokenHash);

            while (_table.Rows.Count > _options.MaxServers)
                _table.Rows.RemoveAt(_table.Rows.Count - 1);

            _dataServer.Save();
            LastStatus = hideFromWebsite ? "Hid " + incoming.TitleText + " from website" : "Registered " + incoming.TitleText;
            AppendMasterLog("info", "server", LastStatus, "", account.UserName, remoteIp, request.Path);
        }

        NotifyServersChanged();
        StatusChanged?.Invoke(this, EventArgs.Empty);
        return incoming.Clone();
    }

    public bool Remove(string id) {
        bool removed = false;
        lock (_sync) {
            int index = FindRowIndexLocked(id);
            if (index >= 0) {
                _table.Rows.RemoveAt(index);
                _dataServer.Save();
                removed = true;
                LastStatus = "Removed " + id;
            }
        }

        if (removed) {
            NotifyServersChanged();
            StatusChanged?.Invoke(this, EventArgs.Empty);
        }

        return removed;
    }

    public bool Remove(string id, HttpRequest request, string remoteIp, out string error) {
        error = "";
        bool removed = false;
        lock (_sync) {
            int index = FindRowIndexLocked(id);
            if (index < 0) {
                error = "Server not found.";
                return false;
            }

            RegisteredServer existing = RowToServer(_table.Rows[index]);
            AccountRecord? account = AuthenticateRequest(request, out _);
            string ownerKey = account == null ? "" : BuildOwnerKey(account.UserName);
            string ownerTokenHash = HashOwnerToken(ExtractOwnerTokenFromRequest(request));
            if (!IsServerOwnerAuthorized(existing, request, remoteIp, ownerKey, ownerTokenHash)) {
                error = "Only the owner of this server can delete it.";
                return false;
            }

            _table.Rows.RemoveAt(index);
            _dataServer.Save();
            removed = true;
            LastStatus = "Removed " + id;
        }

        if (removed) {
            NotifyServersChanged();
            StatusChanged?.Invoke(this, EventArgs.Empty);
        }

        return removed;
    }

    public bool MarkOffline(string id) {
        bool changed = false;
        lock (_sync) {
            int index = FindRowIndexLocked(id);
            if (index >= 0) {
                DateTimeOffset now = DateTimeOffset.UtcNow;
                object[] row = _table.Rows[index];
                SetCell(row, nameof(RegisteredServer.LastSeenUtc), now.AddMinutes(-_options.RegistrationTtlMinutes - 1).ToString("O", CultureInfo.InvariantCulture));
                SetCell(row, nameof(RegisteredServer.UpdatedUtc), now.ToString("O", CultureInfo.InvariantCulture));
                SetCell(row, nameof(RegisteredServer.LastStatus), "Offline - manually marked offline");
                SetCell(row, nameof(RegisteredServer.IsOnline), "false");
                SetCell(row, nameof(RegisteredServer.HostResponding), "false");
                SetCell(row, nameof(RegisteredServer.LmStudioConnected), "false");
                SetCell(row, nameof(RegisteredServer.ModelRuntimeConnected), "false");
                SetCell(row, nameof(RegisteredServer.ModelRuntimeStatus), "Offline - manually marked offline");
                SetCell(row, nameof(RegisteredServer.LlmRuntimeConnected), "false");
                SetCell(row, nameof(RegisteredServer.LlmRuntimeStatus), "Offline - manually marked offline");
                SetCell(row, nameof(RegisteredServer.StatusText), "Offline - manually marked offline");
                _dataServer.Save();
                changed = true;
                LastStatus = "Marked offline " + id;
            }
        }

        if (changed) {
            NotifyServersChanged();
            StatusChanged?.Invoke(this, EventArgs.Empty);
        }

        return changed;
    }

    private void Server_OnError(SocketJack.Net.ErrorEventArgs e) {
        LastStatus = e.Exception.Message;
        AppendMasterLog("error", "server", e.Exception.Message, e.Exception.ToString());
        StatusChanged?.Invoke(this, EventArgs.Empty);
    }

    private void LoadShellRelaysFromTable() {
        lock (_sync) {
            _shellRelays.Clear();
            foreach (object[] row in _shellProxyTable.Rows.ToList()) {
                MasterShellRelay relay = ShellRelayFromRow(row);
                if (string.IsNullOrWhiteSpace(relay.Id))
                    continue;

                PrepareShellRelayProxyFieldsLocked(relay);
                _shellRelays[relay.Id] = relay;
            }
        }
    }

    private string HandleShellProxyRequest(NetworkConnection connection, HttpRequest request) {
        try {
            if (string.IsNullOrWhiteSpace(request.Body))
                return Json(request, new { ok = false, error = "Request body is required." }, 400, "Bad Request");

            using JsonDocument document = JsonDocument.Parse(request.Body);
            string remoteIp = connection?.EndPoint?.Address?.ToString() ?? "";
            ShellProxyRegistration registration = RequestShellProxy(document.RootElement, remoteIp, request);
            return Json(request, new {
                ok = true,
                proxyPath = registration.ProxyPath,
                endpoint = registration.Endpoint,
                supportsWebSocketTunnel = true,
                transportMode = registration.Relay.TransportMode,
                webSocketTunnelUrl = registration.Relay.WebSocketTunnelUrl,
                instance = registration.Relay,
                registered = registration.Server,
                instances = GetShellRelays()
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (InvalidOperationException ex) {
            return Json(request, new { ok = false, error = "Shell proxy rejected.", detail = ex.Message }, 400, "Bad Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Shell proxy request failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private ShellProxyRegistration RequestShellProxy(JsonElement root, string remoteIp, HttpRequest request) {
        JsonElement profile = TryGetJsonProperty(root, "profile", out JsonElement profileElement) && profileElement.ValueKind == JsonValueKind.Object
            ? profileElement
            : root;
        string displayName = FirstNonEmpty(
            GetJsonString(root, "serverName"),
            GetJsonString(root, "displayName"),
            GetJsonString(root, "name"),
            GetJsonString(profile, "serverName"),
            GetJsonString(profile, "ServerName"),
            remoteIp,
            "JackLLM Host");

        AccountRecord? account = AuthenticateRequest(request, out _);
        if (account == null)
            throw new InvalidOperationException("SocketJack.com login is required to request a JackLLM shell proxy.");
        string ownerKey = BuildOwnerKey(account.UserName);
        string ownerTokenHash = HashOwnerToken(ExtractOwnerTokenFromRequest(request));
        string ownerFingerprint = FirstNonEmpty(ownerKey, ownerTokenHash, remoteIp, displayName);
        string serverId = BuildShellServerId(root, profile, displayName, ownerFingerprint);
        RegisteredServer incoming = RegisteredServer.FromRegistration(root, remoteIp);
        incoming.Id = serverId;
        if (account != null)
            incoming.OwnerUserName = RegisteredServer.FirstNonEmpty(incoming.OwnerUserName, account.UserName);

        MasterShellRelay savedRelay;
        RegisteredServer savedServer;
        lock (_sync) {
            UpdateServerAvailabilityLocked(DateTimeOffset.UtcNow, allowLiveChecks: false);
            RegisteredServer? duplicateExisting = RemoveDuplicateShellServerRowsLocked(serverId, incoming, displayName, remoteIp, ownerKey, ownerTokenHash);
            int existingIndex = FindRowIndexLocked(serverId);
            RegisteredServer? existing = existingIndex >= 0 ? RowToServer(_table.Rows[existingIndex]) : duplicateExisting;
            if (existing != null && !IsServerOwnerAuthorized(existing, request, remoteIp, ownerKey, ownerTokenHash))
                throw new InvalidOperationException("Only the owner of this server can request or update its shell proxy.");

            MasterShellRelay? existingRelay = _shellRelays.Values.FirstOrDefault(relay =>
                string.Equals(relay.ServerId, serverId, StringComparison.OrdinalIgnoreCase));
            if (existingRelay != null && IsShellRelayOwnerAuthorized(existingRelay, ownerKey, ownerTokenHash, remoteIp)) {
                existingRelay.Name = displayName;
                existingRelay.ServerId = serverId;
                existingRelay.OwnerKey = FirstNonEmpty(existingRelay.OwnerKey, ownerKey);
                existingRelay.OwnerTokenHash = FirstNonEmpty(ownerTokenHash, existingRelay.OwnerTokenHash);
                existingRelay.TargetHost = "127.0.0.1";
                existingRelay.TargetPort = ShellProxyTargetPort;
                existingRelay.Enabled = true;
                existingRelay.TransportMode = NormalizeShellProxyTransportMode(FirstNonEmpty(GetJsonString(root, "transportMode"), GetJsonString(profile, "transportMode"), existingRelay.TransportMode));
                existingRelay.FallbackTcpEnabled = GetJsonBool(root, "fallbackTcpEnabled", GetJsonBool(profile, "fallbackTcpEnabled", true));
                existingRelay.SupportsWebSocketTunnel = true;
                existingRelay.Status = string.IsNullOrWhiteSpace(existingRelay.Status) ? "Ready" : existingRelay.Status;
                existingRelay.LastUpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                PrepareShellRelayProxyFieldsLocked(existingRelay, displayName);
                if (IsListening)
                    StartShellRelayLocked(existingRelay.Id);
                savedRelay = UpdateShellRelayRuntime(existingRelay).Clone();
                savedServer = UpsertShellProxyServerLocked(incoming, savedRelay, root, remoteIp, ownerKey, ownerTokenHash, existing, existingIndex);
                _dataServer.Save();
                LastStatus = "Shell proxy ready: " + savedRelay.Endpoint;
            } else {

                var relay = existingRelay?.Clone() ?? new MasterShellRelay {
                    Id = MakeHashId("shell-", serverId + "|" + ownerFingerprint, 8),
                    CreatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                };

                relay.Name = displayName;
                relay.ServerId = serverId;
                relay.OwnerKey = FirstNonEmpty(relay.OwnerKey, ownerKey);
                relay.OwnerTokenHash = FirstNonEmpty(ownerTokenHash, relay.OwnerTokenHash);
                relay.TargetHost = "127.0.0.1";
                relay.TargetPort = ShellProxyTargetPort;
                relay.Enabled = true;
                relay.TransportMode = NormalizeShellProxyTransportMode(FirstNonEmpty(GetJsonString(root, "transportMode"), GetJsonString(profile, "transportMode"), relay.TransportMode));
                relay.FallbackTcpEnabled = GetJsonBool(root, "fallbackTcpEnabled", GetJsonBool(profile, "fallbackTcpEnabled", true));
                relay.SupportsWebSocketTunnel = true;
                relay.Status = "Ready";
                relay.LastUpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                if (relay.PublicPort <= 0)
                    relay.PublicPort = AllocateShellPortLocked(ShellPublicPortStart);
                if (relay.AgentPort <= 0)
                    relay.AgentPort = AllocateShellPortLocked(ShellAgentPortStart, relay.PublicPort);

                PrepareShellRelayProxyFieldsLocked(relay, displayName);
                _shellRelays[relay.Id] = relay.Clone();
                SaveShellRelayLocked(_shellRelays[relay.Id]);

                if (IsListening)
                    StartShellRelayLocked(relay.Id);

                savedRelay = UpdateShellRelayRuntime(_shellRelays[relay.Id]).Clone();
                savedServer = UpsertShellProxyServerLocked(incoming, savedRelay, root, remoteIp, ownerKey, ownerTokenHash, existing, existingIndex);
                _dataServer.Save();
                LastStatus = "Shell proxy ready: " + savedRelay.Endpoint;
            }
        }

        NotifyServersChanged();
        NotifyShellRelaysChanged();
        StatusChanged?.Invoke(this, EventArgs.Empty);
        return new ShellProxyRegistration(savedRelay, savedServer, savedRelay.ProxyPath, savedRelay.Endpoint);
    }

    private static bool IsShellRelayOwnerAuthorized(MasterShellRelay relay, string ownerKey, string ownerTokenHash, string remoteIp) {
        if (relay == null)
            return false;
        if (!string.IsNullOrWhiteSpace(relay.OwnerKey) &&
            !string.IsNullOrWhiteSpace(ownerKey) &&
            string.Equals(relay.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
            return true;
        if (!string.IsNullOrWhiteSpace(relay.OwnerTokenHash) &&
            !string.IsNullOrWhiteSpace(ownerTokenHash) &&
            FixedTimeEqualsText(relay.OwnerTokenHash, ownerTokenHash))
            return true;
        return string.IsNullOrWhiteSpace(relay.OwnerKey) &&
               string.IsNullOrWhiteSpace(relay.OwnerTokenHash) &&
               !string.IsNullOrWhiteSpace(remoteIp);
    }

    private RegisteredServer UpsertShellProxyServerLocked(
        RegisteredServer server,
        MasterShellRelay relay,
        JsonElement root,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash,
        RegisteredServer? existing,
        int existingIndex) {
        DateTimeOffset now = DateTimeOffset.UtcNow;
        Uri? endpointUri = Uri.TryCreate(relay.Endpoint, UriKind.Absolute, out Uri? parsedEndpoint) ? parsedEndpoint : null;
        string publicHost = endpointUri?.Host ?? NormalizePublicHost(_options.WebsitePublicUrl);
        int publicPort = endpointUri == null ? _options.WebsitePort : endpointUri.Port;
        bool visibleOnWebsite = RegisteredServer.GetBool(root, "visibleOnWebsite", RegisteredServer.GetBool(root, "publishEnabled", true));

        server.Id = relay.ServerId;
        server.Title = relay.Name;
        server.DisplayName = relay.Name;
        server.Endpoint = relay.Endpoint;
        server.ConnectHost = publicHost;
        server.IpAddress = FirstNonEmpty(remoteIp, publicHost);
        server.ProxyPort = publicPort;
        server.ChatPort = publicPort;
        server.LmStudioPort = publicPort;
        server.FtpPort = 2121;
        server.WebsiteHidden = !visibleOnWebsite;
        server.RegisteredByIp = remoteIp;
        server.FirstSeenUtc = existing?.FirstSeenUtc ?? now.ToString("O", CultureInfo.InvariantCulture);
        server.LastSeenUtc = now.ToString("O", CultureInfo.InvariantCulture);
        server.StartedUtc = FirstNonEmpty(server.StartedUtc, existing?.StartedUtc, now.ToString("O", CultureInfo.InvariantCulture));
        server.UptimeSeconds = Math.Max(server.UptimeSeconds, existing?.UptimeSeconds ?? 0);
        server.UpdatedUtc = now.ToString("O", CultureInfo.InvariantCulture);
        server.LastStatus = visibleOnWebsite ? "Shell proxy online" : "Hidden from website";
        bool shellOnline = visibleOnWebsite && relay.Enabled && relay.IsRunning;
        server.IsOnline = shellOnline;
        server.HostResponding = shellOnline;
        server.StatusText = server.LastStatus;
        server.OwnerUserName = FirstNonEmpty(server.OwnerUserName, existing?.OwnerUserName);
        server.OwnerKey = FirstNonEmpty(existing?.OwnerKey, ownerKey);
        server.OwnerTokenHash = FirstNonEmpty(existing?.OwnerTokenHash, ownerTokenHash);
        PreserveServerBackground(existing, server);
        server.ExtraJson = root.GetRawText();
        server.SearchText = string.Join(" ", new[] {
            server.Title,
            server.DisplayName,
            server.Endpoint,
            relay.RouteName,
            relay.ProxyPath,
            relay.PublicPort.ToString(CultureInfo.InvariantCulture),
            relay.AgentPort.ToString(CultureInfo.InvariantCulture),
            root.GetRawText()
        });
        server.Normalize();

        if (existingIndex >= 0)
            _table.Rows[existingIndex] = ServerToRow(server);
        else {
            _table.Rows.Insert(0, ServerToRow(server));
            existingIndex = 0;
        }

        RemoveDuplicatePublishedServerRowsLocked(server, existingIndex, remoteIp, ownerKey, ownerTokenHash);

        while (_table.Rows.Count > _options.MaxServers)
            _table.Rows.RemoveAt(_table.Rows.Count - 1);

        _healthCache.Remove(server.Id);
        return server.Clone();
    }

    private RegisteredServer? RemoveDuplicateShellServerRowsLocked(
        string serverId,
        RegisteredServer incoming,
        string displayName,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash) {
        RegisteredServer? firstRemoved = null;
        for (int i = _table.Rows.Count - 1; i >= 0; i--) {
            RegisteredServer existing = RowToServer(_table.Rows[i]);
            if (string.IsNullOrWhiteSpace(existing.Id) ||
                string.Equals(existing.Id, serverId, StringComparison.OrdinalIgnoreCase))
                continue;
            if (!IsSamePublishedServerOwner(existing, remoteIp, ownerKey, ownerTokenHash))
                continue;
            if (!IsDuplicatePublishedListing(existing, incoming) &&
                !IsSamePublishedServerEndpoint(existing, incoming) &&
                !(!HasStrongPublishedServerOwnerEvidence(ownerKey, ownerTokenHash) && IsSameServerTitle(existing, displayName)))
                continue;

            firstRemoved ??= existing.Clone();
            _healthCache.Remove(existing.Id);
            _table.Rows.RemoveAt(i);
        }

        return firstRemoved;
    }

    private static bool IsSameServerTitle(RegisteredServer server, string displayName) {
        string left = RegisteredServer.FirstNonEmpty(server.Title, server.DisplayName).Trim();
        string right = (displayName ?? "").Trim();
        return !string.IsNullOrWhiteSpace(left) &&
               !string.IsNullOrWhiteSpace(right) &&
               string.Equals(left, right, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsSamePublishedServerOwner(
        RegisteredServer server,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash) {
        if (!string.IsNullOrWhiteSpace(server.OwnerKey) &&
            !string.IsNullOrWhiteSpace(ownerKey) &&
            string.Equals(server.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
            return true;
        if (!string.IsNullOrWhiteSpace(server.OwnerTokenHash) &&
            !string.IsNullOrWhiteSpace(ownerTokenHash) &&
            FixedTimeEqualsText(server.OwnerTokenHash, ownerTokenHash))
            return true;
        return string.IsNullOrWhiteSpace(server.OwnerKey) &&
               string.IsNullOrWhiteSpace(server.OwnerTokenHash) &&
               !string.IsNullOrWhiteSpace(remoteIp) &&
               string.Equals(server.RegisteredByIp, remoteIp, StringComparison.OrdinalIgnoreCase);
    }

    private int FindPublishedServerRowIndexLocked(
        RegisteredServer incoming,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash) {
        int exactIndex = FindRowIndexLocked(incoming.Id);
        if (exactIndex >= 0)
            return exactIndex;

        return FindMatchingPublishedServerRowIndexLocked(incoming, remoteIp, ownerKey, ownerTokenHash, -1);
    }

    private int FindSamePublishedServerOwnerRowIndexLocked(
        string remoteIp,
        string ownerKey,
        string ownerTokenHash,
        int skipIndex) {
        if (!HasStrongPublishedServerOwnerEvidence(ownerKey, ownerTokenHash))
            return -1;

        for (int i = 0; i < _table.Rows.Count; i++) {
            if (i == skipIndex)
                continue;

            RegisteredServer existing = RowToServer(_table.Rows[i]);
            if (IsSamePublishedServerOwner(existing, remoteIp, ownerKey, ownerTokenHash))
                return i;
        }

        return -1;
    }

    private int FindMatchingPublishedServerRowIndexLocked(
        RegisteredServer incoming,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash,
        int skipIndex) {
        string incomingSignatureKey = BuildPublishedListingSignatureKey(incoming);
        string incomingEndpointKey = BuildPublishedServerEndpointKey(incoming);
        string incomingHostPortKey = BuildPublishedServerHostPortKey(incoming);
        if (string.IsNullOrWhiteSpace(incomingSignatureKey) &&
            string.IsNullOrWhiteSpace(incomingEndpointKey) &&
            string.IsNullOrWhiteSpace(incomingHostPortKey))
            return -1;

        for (int i = 0; i < _table.Rows.Count; i++) {
            if (i == skipIndex)
                continue;

            RegisteredServer existing = RowToServer(_table.Rows[i]);
            if (!IsSamePublishedServerOwner(existing, remoteIp, ownerKey, ownerTokenHash))
                continue;
            if (!string.IsNullOrWhiteSpace(incomingSignatureKey) &&
                string.Equals(BuildPublishedListingSignatureKey(existing), incomingSignatureKey, StringComparison.OrdinalIgnoreCase))
                return i;
            if (!string.IsNullOrWhiteSpace(incomingEndpointKey) &&
                string.Equals(BuildPublishedServerEndpointKey(existing), incomingEndpointKey, StringComparison.OrdinalIgnoreCase))
                return i;
            if (!string.IsNullOrWhiteSpace(incomingHostPortKey) &&
                string.Equals(BuildPublishedServerHostPortKey(existing), incomingHostPortKey, StringComparison.OrdinalIgnoreCase))
                return i;
        }

        return -1;
    }

    private void RemoveDuplicatePublishedServerRowsLocked(
        RegisteredServer incoming,
        int keepIndex,
        string remoteIp,
        string ownerKey,
        string ownerTokenHash) {
        for (int i = _table.Rows.Count - 1; i >= 0; i--) {
            if (i == keepIndex)
                continue;

            RegisteredServer existing = RowToServer(_table.Rows[i]);
            if (!IsSamePublishedServerOwner(existing, remoteIp, ownerKey, ownerTokenHash))
                continue;
            if (!IsDuplicatePublishedListing(existing, incoming) &&
                !IsSamePublishedServerEndpoint(existing, incoming))
                continue;

            _healthCache.Remove(existing.Id);
            _table.Rows.RemoveAt(i);
        }
    }

    private static void PreserveServerBackground(RegisteredServer? existing, RegisteredServer incoming) {
        if (existing == null || incoming == null)
            return;
        if (string.IsNullOrWhiteSpace(incoming.BackgroundImageKey) &&
            !string.IsNullOrWhiteSpace(existing.BackgroundImageKey)) {
            incoming.BackgroundImageKey = existing.BackgroundImageKey;
            incoming.BackgroundOffsetX = existing.BackgroundOffsetX;
            incoming.BackgroundOffsetY = existing.BackgroundOffsetY;
            incoming.BackgroundScale = existing.BackgroundScale <= 0 ? 1 : existing.BackgroundScale;
        }
    }

    private static bool IsDuplicatePublishedListing(RegisteredServer left, RegisteredServer right) {
        string leftKey = BuildPublishedListingSignatureKey(left);
        string rightKey = BuildPublishedListingSignatureKey(right);
        return !string.IsNullOrWhiteSpace(leftKey) &&
               string.Equals(leftKey, rightKey, StringComparison.OrdinalIgnoreCase);
    }

    private static string BuildPublishedListingSignatureKey(RegisteredServer server) {
        if (server == null)
            return "";

        string owner = NormalizeWebsiteDuplicateToken(RegisteredServer.FirstNonEmpty(server.OwnerUserName, server.OwnerKey));
        string host = BuildWebsiteDuplicateHostKey(server);
        string title = NormalizeWebsiteDuplicateToken(RegisteredServer.FirstNonEmpty(server.Title, server.DisplayName));
        string models = BuildWebsiteDuplicateModelsKey(server);
        string cost = BuildWebsiteDuplicateCostKey(server);
        string hardware = BuildPublishedHardwareSignatureKey(server);
        if (string.IsNullOrWhiteSpace(owner) ||
            string.IsNullOrWhiteSpace(host) ||
            string.IsNullOrWhiteSpace(title) ||
            string.IsNullOrWhiteSpace(models) ||
            string.IsNullOrWhiteSpace(cost))
            return "";

        int modelCount = models.Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries).Length;
        return "owner:" + owner +
               "|host:" + host +
               "|title:" + title +
               "|hardware:" + hardware +
               "|models:" + modelCount.ToString(CultureInfo.InvariantCulture) + ":" + models +
               "|cost:" + cost;
    }

    private static string BuildPublishedHardwareSignatureKey(RegisteredServer server) {
        string gpu = NormalizeWebsiteDuplicateToken(server.GpuModel);
        string cpu = NormalizeWebsiteDuplicateToken(server.CpuModel);
        return "gpu:" + gpu + "|cpu:" + cpu;
    }

    private static bool IsSamePublishedServerEndpoint(RegisteredServer left, RegisteredServer right) {
        string leftEndpointKey = BuildPublishedServerEndpointKey(left);
        string rightEndpointKey = BuildPublishedServerEndpointKey(right);
        if (!string.IsNullOrWhiteSpace(leftEndpointKey) &&
            string.Equals(leftEndpointKey, rightEndpointKey, StringComparison.OrdinalIgnoreCase))
            return true;

        string leftHostPortKey = BuildPublishedServerHostPortKey(left);
        string rightHostPortKey = BuildPublishedServerHostPortKey(right);
        return !string.IsNullOrWhiteSpace(leftHostPortKey) &&
               string.Equals(leftHostPortKey, rightHostPortKey, StringComparison.OrdinalIgnoreCase);
    }

    private static List<RegisteredServer> CollapseDuplicateWebsiteListings(IEnumerable<RegisteredServer> servers) {
        var visible = new List<RegisteredServer>();
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach (RegisteredServer server in servers) {
            string duplicateKey = BuildWebsiteDuplicateListingKey(server);
            if (!string.IsNullOrWhiteSpace(duplicateKey) && !seen.Add(duplicateKey))
                continue;

            visible.Add(server);
        }

        return visible;
    }

    private static string BuildWebsiteDuplicateListingKey(RegisteredServer server) {
        string signatureKey = BuildPublishedListingSignatureKey(server);
        if (!string.IsNullOrWhiteSpace(signatureKey))
            return signatureKey;

        string hostKey = BuildWebsiteDuplicateHostKey(server);
        string modelsKey = BuildWebsiteDuplicateModelsKey(server);
        string costKey = BuildWebsiteDuplicateCostKey(server);
        if (string.IsNullOrWhiteSpace(hostKey) ||
            string.IsNullOrWhiteSpace(modelsKey) ||
            string.IsNullOrWhiteSpace(costKey))
            return "";

        return hostKey + "|models:" + modelsKey + "|cost:" + costKey;
    }

    private static string BuildWebsiteDuplicateHostKey(RegisteredServer server) {
        foreach (string value in new[] {
                     server.ConnectHost,
                     server.Endpoint,
                     server.LaunchUrl,
                     server.IpAddress,
                     server.RegisteredByIp
                 }) {
            string host = ExtractWebsiteDuplicateHost(value);
            if (!string.IsNullOrWhiteSpace(host))
                return host;
        }

        return "";
    }

    private static string ExtractWebsiteDuplicateHost(string value) {
        if (string.IsNullOrWhiteSpace(value))
            return "";

        if (Uri.TryCreate(value.Trim(), UriKind.Absolute, out Uri? uri))
            return RegisteredServer.NormalizeExternalHost(uri.Host).ToLowerInvariant();

        return RegisteredServer.NormalizeExternalHost(value).ToLowerInvariant();
    }

    private static string BuildWebsiteDuplicateModelsKey(RegisteredServer server) {
        var models = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
        AddWebsiteDuplicateModelNames(models, server.AvailableModels);
        AddWebsiteDuplicateCapabilityModelNames(models, server.ModelCapabilitiesJson);
        AddWebsiteDuplicateBenchmarkModelNames(models, server.ModelBenchmarksJson);
        models.RemoveWhere(model => string.IsNullOrWhiteSpace(model) ||
                                    model.Equals("unknown", StringComparison.OrdinalIgnoreCase));
        return models.Count == 0 ? "" : string.Join(",", models.Select(NormalizeWebsiteDuplicateToken));
    }

    private static void AddWebsiteDuplicateModelNames(ISet<string> models, string value) {
        if (string.IsNullOrWhiteSpace(value))
            return;

        foreach (string part in value.Split(new[] { ',', ';', '\n', '\r', '\t' }, StringSplitOptions.RemoveEmptyEntries)) {
            string model = part.Trim();
            if (!string.IsNullOrWhiteSpace(model))
                models.Add(model);
        }
    }

    private static void AddWebsiteDuplicateBenchmarkModelNames(ISet<string> models, string value) {
        if (string.IsNullOrWhiteSpace(value))
            return;

        try {
            using JsonDocument document = JsonDocument.Parse(value);
            if (document.RootElement.ValueKind != JsonValueKind.Array)
                return;

            foreach (JsonElement item in document.RootElement.EnumerateArray()) {
                string model = RegisteredServer.FirstNonEmpty(
                    RegisteredServer.GetString(item, "modelId"),
                    RegisteredServer.GetString(item, "ModelId"),
                    RegisteredServer.GetString(item, "model"),
                    RegisteredServer.GetString(item, "Model"));
                if (!string.IsNullOrWhiteSpace(model))
                    models.Add(model);
            }
        } catch {
        }
    }

    private static void AddWebsiteDuplicateCapabilityModelNames(ISet<string> models, string value) {
        if (string.IsNullOrWhiteSpace(value))
            return;

        try {
            using JsonDocument document = JsonDocument.Parse(value);
            if (document.RootElement.ValueKind != JsonValueKind.Array)
                return;

            foreach (JsonElement item in document.RootElement.EnumerateArray()) {
                string model = RegisteredServer.FirstNonEmpty(
                    RegisteredServer.GetString(item, "modelId"),
                    RegisteredServer.GetString(item, "ModelId"),
                    RegisteredServer.GetString(item, "id"),
                    RegisteredServer.GetString(item, "model"),
                    RegisteredServer.GetString(item, "Model"));
                if (!string.IsNullOrWhiteSpace(model))
                    models.Add(model);
            }
        } catch {
        }
    }

    private static string BuildWebsiteDuplicateCostKey(RegisteredServer server) {
        double cost = Math.Max(0, server.Cost);
        long cents = Math.Max(0, server.StripeUnitAmountCents);
        double factor = ClampWebsiteDuplicateCostFactor(server.CostFactor);
        string currency = string.IsNullOrWhiteSpace(server.StripeCurrency) ? "usd" : server.StripeCurrency.Trim().ToLowerInvariant();
        string baseCost = cost > 0
            ? "cost:" + cost.ToString("0.####", CultureInfo.InvariantCulture)
            : cents > 0
                ? "stripe:" + cents.ToString(CultureInfo.InvariantCulture) + ":" + currency
                : server.RequiresPayment ? "payment" : "free";

        return baseCost + "|factor:" + factor.ToString("0.####", CultureInfo.InvariantCulture);
    }

    private static string NormalizeWebsiteDuplicateToken(string value) {
        return Regex.Replace(value.Trim().ToLowerInvariant(), @"\s+", " ");
    }

    private static double ClampWebsiteDuplicateCostFactor(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 1;
        return Math.Max(1, Math.Min(5, value));
    }

    private static string BuildPublishedServerEndpointKey(RegisteredServer server) {
        string endpoint = RegisteredServer.FirstNonEmpty(server.Endpoint, server.LaunchUrl);
        if (string.IsNullOrWhiteSpace(endpoint))
            return "";

        if (Uri.TryCreate(endpoint, UriKind.Absolute, out Uri? uri)) {
            string uriHost = RegisteredServer.NormalizeExternalHost(uri.Host).ToLowerInvariant();
            int port = uri.IsDefaultPort ? server.ChatPort : uri.Port;
            return uriHost + ":" + port.ToString(CultureInfo.InvariantCulture) + uri.AbsolutePath.TrimEnd('/').ToLowerInvariant();
        }

        string fallbackHost = RegisteredServer.NormalizeExternalHost(endpoint).ToLowerInvariant();
        return string.IsNullOrWhiteSpace(fallbackHost) ? "" : fallbackHost + ":" + Math.Clamp(server.ChatPort, 1, 65535).ToString(CultureInfo.InvariantCulture);
    }

    private static string BuildPublishedServerHostPortKey(RegisteredServer server) {
        if (IsSocketJackProxyEndpoint(server))
            return "";

        string host = RegisteredServer.NormalizeExternalHost(RegisteredServer.FirstNonEmpty(server.ConnectHost, server.IpAddress, server.RegisteredByIp)).ToLowerInvariant();
        if (string.IsNullOrWhiteSpace(host))
            return "";

        int port = Math.Clamp(server.ChatPort, 1, 65535);
        return host + ":" + port.ToString(CultureInfo.InvariantCulture);
    }

    private static bool HasStrongPublishedServerOwnerEvidence(string ownerKey, string ownerTokenHash) {
        return !string.IsNullOrWhiteSpace(ownerKey) || !string.IsNullOrWhiteSpace(ownerTokenHash);
    }

    private static bool IsSocketJackProxyEndpoint(RegisteredServer server) {
        return IsSocketJackProxyUrl(server.Endpoint) || IsSocketJackProxyUrl(server.LaunchUrl);
    }

    private static bool IsSocketJackProxyUrl(string value) {
        if (string.IsNullOrWhiteSpace(value) || !Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            return false;

        return uri.Host.Contains("socketjack", StringComparison.OrdinalIgnoreCase) &&
               uri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase);
    }

    private void PrepareShellRelayProxyFieldsLocked(MasterShellRelay relay, string requestedRouteName = "") {
        relay.Normalize();
        relay.TargetHost = "127.0.0.1";
        relay.TargetPort = ShellProxyTargetPort;
        relay.RouteName = MakeUniqueShellRouteNameLocked(FirstNonEmpty(requestedRouteName, relay.RouteName, relay.Name, relay.Id), relay.ServerId, relay.Id);
        relay.ProxyPath = BuildShellProxyPath(relay.RouteName);
        relay.Endpoint = BuildShellProxyEndpoint(relay.RouteName);
        relay.SupportsWebSocketTunnel = true;
        relay.TransportMode = NormalizeShellProxyTransportMode(relay.TransportMode);
        relay.WebSocketTunnelUrl = BuildShellProxyTunnelEndpoint(relay.Id);
        if (string.IsNullOrWhiteSpace(relay.CreatedUtc))
            relay.CreatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        relay.LastUpdatedUtc = string.IsNullOrWhiteSpace(relay.LastUpdatedUtc)
            ? DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            : relay.LastUpdatedUtc;
    }

    private string MakeUniqueShellRouteNameLocked(string desiredName, string serverId, string relayId) {
        string baseName = NormalizeShellRouteName(desiredName);
        string candidate = baseName;
        int suffix = 2;
        while (_shellRelays.Values.Any(existing =>
                   !string.Equals(existing.Id, relayId, StringComparison.OrdinalIgnoreCase) &&
                   !(string.IsNullOrWhiteSpace(serverId) == false && string.Equals(existing.ServerId, serverId, StringComparison.OrdinalIgnoreCase)) &&
                   string.Equals(existing.RouteName, candidate, StringComparison.OrdinalIgnoreCase))) {
            candidate = baseName + "-" + suffix.ToString(CultureInfo.InvariantCulture);
            suffix++;
        }

        return candidate;
    }

    private static string NormalizeShellRouteName(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "JackLLM";

        var builder = new StringBuilder(value.Length);
        bool lastWasSpace = false;
        foreach (char c in value) {
            if (char.IsLetterOrDigit(c) || c == '-' || c == '_' || c == '.') {
                builder.Append(c);
                lastWasSpace = false;
            } else if (char.IsWhiteSpace(c)) {
                if (!lastWasSpace && builder.Length > 0)
                    builder.Append(' ');
                lastWasSpace = true;
            }
        }

        string result = builder.ToString().Trim();
        return string.IsNullOrWhiteSpace(result) ? "JackLLM" : result;
    }

    private string BuildShellProxyPath(string routeName) {
        return "/proxy/" + Uri.EscapeDataString(NormalizeShellRouteName(routeName));
    }

    private string BuildShellProxyEndpoint(string routeName) {
        return _options.WebsitePublicUrl.TrimEnd('/') + BuildShellProxyPath(routeName);
    }

    private string BuildShellProxyTunnelEndpoint(string relayId) {
        string baseUrl = _options.WebsitePublicUrl.TrimEnd('/');
        if (!Uri.TryCreate(baseUrl, UriKind.Absolute, out Uri? uri))
            return "/api/shell/proxies/" + Uri.EscapeDataString(relayId ?? "") + "/tunnel";

        string scheme = uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase) ? "wss" : "ws";
        return scheme + "://" + uri.Authority.TrimEnd('/') + "/api/shell/proxies/" + Uri.EscapeDataString(relayId ?? "") + "/tunnel";
    }

    private static string NormalizeShellProxyTransportMode(string value) {
        value = (value ?? "").Trim();
        if (value.Equals("websocket", StringComparison.OrdinalIgnoreCase) ||
            value.Equals("websocketPreferred", StringComparison.OrdinalIgnoreCase) ||
            value.Equals("ws", StringComparison.OrdinalIgnoreCase))
            return "websocketPreferred";
        if (value.Equals("tcp", StringComparison.OrdinalIgnoreCase) ||
            value.Equals("reverseTcp", StringComparison.OrdinalIgnoreCase))
            return "tcp";
        return "websocketPreferred";
    }

    private static string BuildSocketJackLoginPath(string returnUrl) {
        string normalizedReturnUrl = NormalizeSocketJackLoginReturnUrl(returnUrl);
        return "/Login?returnUrl=" + Uri.EscapeDataString(normalizedReturnUrl);
    }

    private static string NormalizeSocketJackLoginReturnUrl(string returnUrl) {
        returnUrl = (returnUrl ?? "").Trim();
        if (string.IsNullOrWhiteSpace(returnUrl))
            return "/";

        if (returnUrl.StartsWith("/", StringComparison.Ordinal) && !returnUrl.StartsWith("//", StringComparison.Ordinal))
            return returnUrl;

        if (Uri.TryCreate(returnUrl, UriKind.Absolute, out Uri? uri) &&
            (uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) ||
             uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)) &&
            uri.Host.EndsWith("socketjack.com", StringComparison.OrdinalIgnoreCase)) {
            return uri.PathAndQuery + uri.Fragment;
        }

        if (Uri.TryCreate(returnUrl, UriKind.Absolute, out uri) &&
            IsAllowedSocketJackLoginReturnUri(uri)) {
            return uri.ToString();
        }

        return "/";
    }

    private static bool IsAllowedSocketJackLoginReturnUri(Uri uri) {
        if (uri == null)
            return false;

        if (uri.IsFile)
            return IsJackLlmWebChatReturnPath(uri.LocalPath);

        if (uri.Scheme.Equals("socketjack", StringComparison.OrdinalIgnoreCase))
            return uri.Host.Equals("visualstudio-auth", StringComparison.OrdinalIgnoreCase);

        if (!uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) &&
            !uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase))
            return false;

        return IsLoopbackHost(uri.Host) && IsJackLlmWebChatReturnPath(uri.AbsolutePath);
    }

    private static bool IsJackLlmWebChatReturnPath(string path) {
        string normalized = (path ?? "").Replace('\\', '/').Trim();
        return normalized.EndsWith("/JackLLMWebChat.html", StringComparison.OrdinalIgnoreCase) ||
            normalized.EndsWith("JackLLMWebChat.html", StringComparison.OrdinalIgnoreCase);
    }

    private static string BuildShellServerId(JsonElement root, JsonElement profile, string displayName, string ownerFingerprint) {
        string supplied = FirstNonEmpty(
            GetJsonString(root, "serverId"),
            GetJsonString(root, "id"),
            GetJsonString(profile, "serverId"),
            GetJsonString(profile, "id"));
        if (!string.IsNullOrWhiteSpace(supplied))
            return NormalizeIdentifierText(supplied, "lmvs-shell-server");

        return MakeHashId("lmvs-shell-server-", displayName + "|" + ownerFingerprint, 8);
    }

    private int AllocateShellPortLocked(int startPort, params int[] reserved) {
        int start = Math.Clamp(startPort, 1, 65535);
        for (int port = start; port <= 65535; port++) {
            if (IsShellPortAvailableLocked(port, reserved))
                return port;
        }

        throw new InvalidOperationException("No available shell proxy ports were found.");
    }

    private bool IsShellPortAvailableLocked(int port, IEnumerable<int> reserved) {
        if (port <= 0 || port > 65535 || IsReservedPort(port) || reserved.Contains(port))
            return false;
        if (_shellRelays.Values.Any(relay => relay.PublicPort == port || relay.AgentPort == port))
            return false;

        try {
            TcpListener listener = new(IPAddress.Any, port);
            listener.Start();
            listener.Stop();
            return true;
        } catch {
            return false;
        }
    }

    private void SaveShellRelayLocked(MasterShellRelay relay) {
        int index = FindShellRelayRowIndexLocked(relay.Id);
        object[] row = ShellRelayToRow(relay);
        if (index >= 0)
            _shellProxyTable.Rows[index] = row;
        else
            _shellProxyTable.Rows.Add(row);
        _dataServer.Save();
    }

    private void RemoveShellRelayRowLocked(string id) {
        int index = FindShellRelayRowIndexLocked(id);
        if (index >= 0)
            _shellProxyTable.Rows.RemoveAt(index);
    }

    private int FindShellRelayRowIndexLocked(string id) {
        for (int i = 0; i < _shellProxyTable.Rows.Count; i++) {
            if (string.Equals(GetShellCell(_shellProxyTable.Rows[i], nameof(MasterShellRelay.Id)), id, StringComparison.OrdinalIgnoreCase))
                return i;
        }

        return -1;
    }

    private object[] ShellRelayToRow(MasterShellRelay relay) {
        var row = new object[_shellProxyTable.Columns.Count];
        for (int i = 0; i < _shellProxyTable.Columns.Count; i++) {
            string columnName = _shellProxyTable.Columns[i].Name;
            row[i] = ShellRelayProperties.TryGetValue(columnName, out PropertyInfo? property)
                ? GetShellRelayPropertyText(relay, property)
                : "";
        }

        return row;
    }

    private MasterShellRelay ShellRelayFromRow(object[] row) {
        var relay = new MasterShellRelay();
        for (int i = 0; i < _shellProxyTable.Columns.Count && i < row.Length; i++) {
            string columnName = _shellProxyTable.Columns[i].Name;
            if (!ShellRelayProperties.TryGetValue(columnName, out PropertyInfo? property))
                continue;

            SetShellRelayPropertyValue(relay, property, row[i]?.ToString() ?? "");
        }

        relay.DebugLines = new List<string>();
        relay.Normalize();
        return relay;
    }

    private string GetShellCell(object[] row, string columnName) {
        for (int i = 0; i < _shellProxyTable.Columns.Count && i < row.Length; i++) {
            if (string.Equals(_shellProxyTable.Columns[i].Name, columnName, StringComparison.OrdinalIgnoreCase))
                return row[i]?.ToString() ?? "";
        }

        return "";
    }

    private static string GetShellRelayPropertyText(MasterShellRelay relay, PropertyInfo property) {
        object? value = property.GetValue(relay);
        return value switch {
            null => "",
            bool boolean => boolean ? "true" : "false",
            IFormattable formattable => formattable.ToString(null, CultureInfo.InvariantCulture),
            _ => value.ToString() ?? ""
        };
    }

    private static void SetShellRelayPropertyValue(MasterShellRelay relay, PropertyInfo property, string text) {
        Type type = Nullable.GetUnderlyingType(property.PropertyType) ?? property.PropertyType;
        object? value = text;
        if (type == typeof(int)) {
            value = int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed) ? parsed : 0;
        } else if (type == typeof(long)) {
            value = long.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out long parsed) ? parsed : 0L;
        } else if (type == typeof(double)) {
            value = double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed) ? parsed : 0d;
        } else if (type == typeof(bool)) {
            value = bool.TryParse(text, out bool parsed) && parsed;
        }

        property.SetValue(relay, value);
    }

    private void ShellProxy_OnHttpRequest(NetworkConnection connection, ref HttpContext context, CancellationToken cancellationToken) {
        HttpRequest request = context.Request;
        if (!TryParseShellProxyPath(request.Path, out string routeName, out string forwardedPath))
            return;

        if (request.Method.Equals("OPTIONS", StringComparison.OrdinalIgnoreCase)) {
            context.StatusCodeNumber = 204;
            context.ReasonPhrase = "No Content";
            context.Response.BodyBytes = Array.Empty<byte>();
            AddCors(request);
            return;
        }

        if (ShouldRedirectShellProxyNavigationToLogin(connection, request, forwardedPath)) {
            SetShellProxyLoginRedirect(request);
            return;
        }

        MasterShellRelay? relay = ResolveShellRelayForProxy(routeName);
        if (relay == null) {
            SetShellProxyError(request, 404, "Not Found", "Shell proxy route was not found.");
            return;
        }

        if (!relay.Enabled) {
            SetShellProxyError(request, 503, "Service Unavailable", "Shell proxy route is disabled.");
            return;
        }

        if (!relay.IsRunning) {
            SetShellProxyError(request, 503, "Service Unavailable", "Shell proxy route is not listening: " + relay.Status);
            return;
        }

        bool webSocketTunnelAvailable = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id);
        if (!webSocketTunnelAvailable && relay.WaitingAgents == 0) {
            relay = WaitForShellRelayAgent(routeName, relay);
            webSocketTunnelAvailable = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id);
        }

        if (!webSocketTunnelAvailable && !ShouldAttemptShellProxyForward(relay, DateTimeOffset.UtcNow)) {
            SetShellProxyWaitingResponse(request, relay, "Server is not responding through the shell yet. The shell route is online, but JackLLM has not connected its reverse agent.");
            return;
        }

        if (TryRedirectShellProxyNavigationWithAuthToken(connection, request, forwardedPath))
            return;

        if (webSocketTunnelAvailable) {
            try {
                _shellProxyWebSocketTunnels.Forward(request, relay, forwardedPath, cancellationToken);
                return;
            } catch (TaskCanceledException) {
                if (!relay.FallbackTcpEnabled) {
                    SetShellProxyWaitingResponse(request, relay, "Server is not responding through the WebSocket tunnel. The JackLLM session timed out.");
                    return;
                }
            } catch (Exception ex) {
                AppendShellRelayRuntimeLog(relay.Id, "WebSocket tunnel forward failed: " + ex.Message);
                if (!relay.FallbackTcpEnabled || !ShouldAttemptShellProxyForward(relay, DateTimeOffset.UtcNow)) {
                    SetShellProxyWaitingResponse(request, relay, "Server is not responding through the WebSocket tunnel: " + ex.Message);
                    return;
                }
            }
        }

        try {
            ForwardShellProxyRequest(request, relay, forwardedPath, cancellationToken);
        } catch (TaskCanceledException) {
            SetShellProxyWaitingResponse(request, relay, "Server is not responding through the shell. The shell route is online, but the JackLLM session timed out.");
        } catch (Exception ex) {
            SetShellProxyWaitingResponse(request, relay, "Server is not responding through the shell: " + ex.Message);
        }
    }

    private void HandleAutoProxyRequest(NetworkConnection connection, HttpRequest request, string forwardedPath, CancellationToken cancellationToken) {
        if (request.Method.Equals("OPTIONS", StringComparison.OrdinalIgnoreCase)) {
            request.Context.StatusCodeNumber = 204;
            request.Context.ReasonPhrase = "No Content";
            request.Context.Response.BodyBytes = Array.Empty<byte>();
            AddCors(request);
            return;
        }

        if (ShouldRedirectShellProxyNavigationToLogin(connection, request, forwardedPath)) {
            SetShellProxyLoginRedirect(request);
            return;
        }

        string model = ExtractAutoModel(request);
        string mode = NormalizeAutoMode(ExtractAutoMode(request, forwardedPath));
        if (!TryResolveAutoShellRelay(request, model, mode, out MasterShellRelay? relay, out RegisteredServer? selectedServer, out int eligibleCount, out string reason)) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, reason);
            return;
        }

        if (relay == null) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected a server, but its shell relay is unavailable.");
            return;
        }

        if (!relay.Enabled) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected a server, but its shell route is disabled.");
            return;
        }

        if (!relay.IsRunning) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected a server, but its shell route is not listening: " + relay.Status);
            return;
        }

        bool webSocketTunnelAvailable = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id);
        if (!webSocketTunnelAvailable && relay.WaitingAgents == 0) {
            relay = WaitForShellRelayAgent(relay.RouteName, relay);
            webSocketTunnelAvailable = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id);
        }

        if (!webSocketTunnelAvailable && !ShouldAttemptShellProxyForward(relay, DateTimeOffset.UtcNow)) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected " + AutoServerDisplayName(selectedServer) + ", but JackLLM has not connected its reverse agent yet.");
            return;
        }

        if (TryRedirectShellProxyNavigationWithAuthToken(connection, request, forwardedPath))
            return;

        if (webSocketTunnelAvailable) {
            try {
                _shellProxyWebSocketTunnels.Forward(request, relay, forwardedPath, cancellationToken, "/Auto");
                AddAutoRoutingHeaders(request, selectedServer, eligibleCount, mode);
                return;
            } catch (TaskCanceledException) {
                if (!relay.FallbackTcpEnabled) {
                    SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected " + AutoServerDisplayName(selectedServer) + ", but the JackLLM session timed out.");
                    return;
                }
            } catch (Exception ex) {
                AppendShellRelayRuntimeLog(relay.Id, "Auto WebSocket tunnel forward failed: " + ex.Message);
                if (!relay.FallbackTcpEnabled || !ShouldAttemptShellProxyForward(relay, DateTimeOffset.UtcNow)) {
                    SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected " + AutoServerDisplayName(selectedServer) + ", but the WebSocket tunnel failed: " + ex.Message);
                    return;
                }
            }
        }

        try {
            ForwardShellProxyRequest(request, relay, forwardedPath, cancellationToken, "/Auto");
            AddAutoRoutingHeaders(request, selectedServer, eligibleCount, mode);
        } catch (TaskCanceledException) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected " + AutoServerDisplayName(selectedServer) + ", but the JackLLM session timed out.");
        } catch (Exception ex) {
            SetAutoProxyNoMatchResponse(request, model, mode, eligibleCount, "Auto selected " + AutoServerDisplayName(selectedServer) + ", but the shell route failed: " + ex.Message);
        }
    }

    private bool TryResolveAutoShellRelay(
        HttpRequest request,
        string model,
        string mode,
        out MasterShellRelay? relay,
        out RegisteredServer? selectedServer,
        out int eligibleCount,
        out string reason) {
        relay = null;
        selectedServer = null;
        eligibleCount = 0;
        reason = "";
        bool premiumModelsEnabled = ExtractAutoPremiumModelsEnabled(request);
        AccountRecord? account = premiumModelsEnabled ? AuthenticateRequest(request, out _) : null;
        bool canUsePremium = premiumModelsEnabled && AccountHasAutoPremiumTokens(account);
        int premiumBlockedCount = 0;

        List<(RegisteredServer Server, string RouteName, MasterShellRelay Relay)> eligible = new();
        foreach (RegisteredServer server in BuildResponse(refreshAvailability: true).Servers) {
            if (!ServerIsAutoOnline(server, mode))
                continue;
            if (!ServerSupportsAutoModel(server, model))
                continue;
            if (!ServerSupportsAutoMode(server, model, mode))
                continue;
            if (!ServerHasUsableAutoBenchmarkModel(server, model, mode))
                continue;
            if (ServerRequiresAutoPremium(server) && !canUsePremium) {
                premiumBlockedCount++;
                continue;
            }
            if (!TryResolveAutoRouteName(server, out string routeName))
                continue;

            MasterShellRelay? candidateRelay = ResolveShellRelayForProxy(routeName);
            if (candidateRelay == null || !candidateRelay.Enabled || !candidateRelay.IsRunning)
                continue;
            eligible.Add((server, routeName, candidateRelay));
        }

        eligibleCount = eligible.Count;
        var selected = eligible
            .OrderBy(item => AutoResourceLoadScore(item.Server))
            .ThenByDescending(item => AutoHardwareScore(item.Server))
            .ThenBy(item => AutoLatencyScore(item.Server))
            .ThenBy(item => AutoCostScore(item.Server))
            .ThenBy(item => item.Server.TitleText, StringComparer.OrdinalIgnoreCase)
            .FirstOrDefault();
        if (selected.Server == null) {
            if (premiumBlockedCount > 0 && !premiumModelsEnabled) {
                reason = "Premium Auto servers are available for " + mode + ", but Premium Models are disabled on this page.";
            } else if (premiumBlockedCount > 0 && account == null) {
                reason = "Premium Auto servers are available for " + mode + ", but SocketJack.com login with tokens is required.";
            } else if (premiumBlockedCount > 0) {
                reason = "Premium Auto servers are available for " + mode + ", but this account has no tokens remaining.";
            } else {
                reason = string.IsNullOrWhiteSpace(model)
                ? "No healthy Auto servers with a compatible model are available for " + mode + "."
                : "No healthy Auto servers with model '" + model + "' are available for " + mode + ".";
            }
            return false;
        }

        selectedServer = selected.Server;
        relay = selected.Relay;
        return true;
    }

    private static bool TryResolveAutoRouteName(RegisteredServer server, out string routeName) {
        routeName = "";
        foreach (string value in new[] { server.LaunchUrl, server.Endpoint }) {
            if (string.IsNullOrWhiteSpace(value))
                continue;
            try {
                Uri uri = new(value, UriKind.RelativeOrAbsolute);
                string path = uri.IsAbsoluteUri ? uri.AbsolutePath : value;
                if (TryParseShellProxyPath(path, out routeName, out _))
                    return true;
            } catch {
            }
        }

        return false;
    }

    private static bool ServerIsAutoOnline(RegisteredServer server, string mode) {
        if (server == null || !server.IsOnline || !server.HostResponding)
            return false;

        bool hasStructuredModelInventory = server.ModelCount > 0;
        bool hasLegacyModelHints = !string.IsNullOrWhiteSpace(server.AvailableModels);
        bool runtimeReady =
            server.ModelRuntimeConnected ||
            server.LmStudioConnected ||
            server.LlmRuntimeConnected ||
            hasStructuredModelInventory ||
            hasLegacyModelHints && !AutoServerRuntimeLooksDisconnected(server);
        string normalizedMode = NormalizeAutoMode(mode);
        if (normalizedMode is "image" or "audio" or "video")
            return runtimeReady || server.SupportsMediaGeneration && hasStructuredModelInventory;
        if (normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            return server.SupportsTools && (runtimeReady || TryResolveAutoRouteName(server, out _));

        return runtimeReady;
    }

    private static bool AutoServerRuntimeLooksDisconnected(RegisteredServer server) {
        if (server == null)
            return true;
        string text = string.Join(" ", server.ModelRuntimeStatus, server.StatusText, server.LastStatus);
        return Regex.IsMatch(text ?? "", @"\b(disconnected|offline|unavailable|connection\s+refused|not\s+connected|stopped|disabled)\b", RegexOptions.IgnoreCase);
    }

    private static bool ServerSupportsAutoModel(RegisteredServer server, string model) {
        if (string.IsNullOrWhiteSpace(model))
            return true;

        if (server.SupportsTools &&
            server.Models.Count == 0 &&
            string.IsNullOrWhiteSpace(server.AvailableModels) &&
            TryResolveAutoRouteName(server, out _))
            return true;

        List<string> requestedAliases = AutoModelAliases(model).ToList();
        foreach (RegisteredServerModelInfo item in server.Models) {
            if (AutoModelAliases(item.Id).Any(candidate => AutoModelAliasMatches(candidate, requestedAliases)))
                return true;
        }

        foreach (string candidate in AutoSplitModelHints(server.AvailableModels)) {
            if (AutoModelAliases(candidate).Any(alias => AutoModelAliasMatches(alias, requestedAliases)))
                return true;
        }

        return false;
    }

    private static bool ServerSupportsAutoMode(RegisteredServer server, string model, string mode) {
        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase))
            return string.IsNullOrWhiteSpace(model)
                ? ServerHasSelectableAutoModeModel(server, mode)
                : ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, mode) && item.SupportsImageGeneration);
        if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            return string.IsNullOrWhiteSpace(model)
                ? ServerHasSelectableAutoModeModel(server, mode)
                : ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, mode) && item.SupportsAudioGeneration);
        if (mode.Equals("video", StringComparison.OrdinalIgnoreCase))
            return string.IsNullOrWhiteSpace(model)
                ? ServerHasSelectableAutoModeModel(server, mode)
                : ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, mode) && item.SupportsVideoGeneration);
        if (mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase))
            return string.IsNullOrWhiteSpace(model)
                ? server.Models.Any(item => AutoModelIsSelectableForMode(item, mode))
                : ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, mode) && item.SupportsVision);
        if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            return string.IsNullOrWhiteSpace(model)
                ? server.Models.Any(item => AutoModelIsSelectableForMode(item, mode)) || server.SupportsTools && TryResolveAutoRouteName(server, out _)
                : ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, mode)) ||
                  server.SupportsTools && server.Models.Count == 0 && string.IsNullOrWhiteSpace(server.AvailableModels) && TryResolveAutoRouteName(server, out _);
        if (mode.Equals("embedding", StringComparison.OrdinalIgnoreCase))
            return ServerHasEmbeddingModel(server, model);
        if (!string.IsNullOrWhiteSpace(model))
            return ServerModelSupports(server, model, item => AutoModelIsSelectableForMode(item, "text"));

        return server.Models.Any(item => AutoModelIsSelectableForMode(item, "text"));
    }

    private static bool ServerHasSelectableAutoModeModel(RegisteredServer server, string mode) =>
        server.Models.Any(item => AutoModelIsSelectableForMode(item, mode));

    private static bool ServerHasEmbeddingModel(RegisteredServer server, string model) {
        static bool LooksEmbedding(string value) {
            string text = NormalizeAutoModelId(value);
            return text.Contains("embed", StringComparison.OrdinalIgnoreCase) ||
                   text.Contains("bge-", StringComparison.OrdinalIgnoreCase) ||
                   text.Contains("e5-", StringComparison.OrdinalIgnoreCase) ||
                   text.Contains("gte-", StringComparison.OrdinalIgnoreCase) ||
                   text.Contains("nomic-embed", StringComparison.OrdinalIgnoreCase);
        }

        if (!string.IsNullOrWhiteSpace(model))
            return LooksEmbedding(model) && ServerSupportsAutoModel(server, model);

        return server.Models.Any(item => AutoModelIsSelectableForMode(item, "embedding") && LooksEmbedding(item.Id));
    }

    private static bool ServerModelSupports(RegisteredServer server, string model, Func<RegisteredServerModelInfo, bool> predicate) {
        if (string.IsNullOrWhiteSpace(model))
            return server.Models.Any(predicate);

        List<string> requestedAliases = AutoModelAliases(model).ToList();
        return server.Models.Any(item =>
            AutoModelAliases(item.Id).Any(candidate => AutoModelAliasMatches(candidate, requestedAliases)) &&
            predicate(item));
    }

    private static IEnumerable<string> AutoSplitModelHints(string value) {
        if (string.IsNullOrWhiteSpace(value))
            yield break;

        foreach (string part in value.Replace("\r\n", "\n").Split(new[] { '\n', ',', ';', '\t' }, StringSplitOptions.RemoveEmptyEntries)) {
            string text = part.Trim();
            if (!string.IsNullOrWhiteSpace(text))
                yield return text;
        }
    }

    private static string NormalizeAutoModelId(string value) =>
        (value ?? "").Trim().Trim('"', '\'').Replace('\\', '/').Trim('/').ToLowerInvariant();

    private static IEnumerable<string> AutoModelAliases(string value) {
        foreach (string candidate in new[] {
            value,
            CleanAutoModelDisplayName(value)
        }) {
            string normalized = NormalizeAutoModelId(candidate);
            if (!string.IsNullOrWhiteSpace(normalized))
                yield return normalized;
        }
    }

    private static bool AutoModelIsSelectableForMode(RegisteredServerModelInfo item, string mode) {
        if (item == null || string.IsNullOrWhiteSpace(item.Id) || item.Disabled)
            return false;
        if (!AutoModelIsRuntimeLoadable(item))
            return false;

        string normalizedMode = NormalizeAutoMode(mode);
        if (normalizedMode.Equals("image", StringComparison.OrdinalIgnoreCase))
            return item.SupportsImageGeneration;
        if (normalizedMode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            return item.SupportsAudioGeneration;
        if (normalizedMode.Equals("video", StringComparison.OrdinalIgnoreCase))
            return item.SupportsVideoGeneration;
        if (normalizedMode.Equals("multimodal", StringComparison.OrdinalIgnoreCase))
            return item.SupportsVision || AutoModelNameLooksSelectableForMode(item.Id, "multimodal");
        if (normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            return AutoModelIsToolRouteSelectable(item);
        if (normalizedMode.Equals("embedding", StringComparison.OrdinalIgnoreCase))
            return NormalizeAutoModelId(item.Id).Contains("embed", StringComparison.OrdinalIgnoreCase);
        return AutoModelIsTextSelectable(item);
    }

    private static bool AutoModelHasBenchmarkNumber(RegisteredServerModelInfo item) =>
        item != null &&
        (item.BenchmarkRating > 0 ||
         item.TokensPerSecond > 0 ||
         item.TokensPerHour > 0 ||
         item.OutputTokens > 0 ||
         item.BenchmarkDurationMs > 0);

    private static bool AutoModelIsRuntimeLoadable(RegisteredServerModelInfo item) =>
        item.Loaded ||
        item.RuntimeLoadEnabled ||
        item.DynamicLoadEnabled && item.ServerDynamicLoadingEnabled ||
        item.Enabled && (item.ServerDynamicLoadingEnabled || item.DynamicLoadEnabled);

    private static bool AutoModelIsTextSelectable(RegisteredServerModelInfo item) {
        if (item == null)
            return false;
        string text = NormalizeAutoModelId(item.Id);
        if (string.IsNullOrWhiteSpace(text))
            return false;
        if (AutoModelLooksEmbedding(text))
            return false;
        if (item.SupportsImageGeneration || item.SupportsAudioGeneration || item.SupportsVideoGeneration || AutoModelLooksGenerationOnly(text))
            return false;
        if (item.SupportsTools || item.SupportsVision || AutoModelLooksChatCapable(text))
            return true;
        return true;
    }

    private static bool AutoModelIsToolRouteSelectable(RegisteredServerModelInfo item) {
        if (item == null)
            return false;
        return item.SupportsTools || AutoModelIsTextSelectable(item);
    }

    private static bool AutoModelLooksEmbedding(string text) =>
        Regex.IsMatch(text ?? "", @"(?:^|[\/\s._-])(?:embed|embedding|bge|e5|gte)(?:[\/\s._-]|$)|nomic-embed", RegexOptions.IgnoreCase);

    private static bool AutoModelLooksChatCapable(string text) =>
        Regex.IsMatch(text ?? "", @"(?:qwen|llama|mistral|gemma|phi|claude|opus|instruct|chat|llm|gguf|unsloth|gpt|q[0-9]|q[0-9]_[a-z])", RegexOptions.IgnoreCase);

    private static bool AutoModelLooksGenerationOnly(string text) =>
        Regex.IsMatch(text ?? "", @"(?:stable|diffusion|sdxl|flux|image|video|zeroscope|cerspense|svd|animated|motion|wan2?|ltx|hunyuan|audio|speech|tts|whisper|music|voice)", RegexOptions.IgnoreCase);

    private static bool AutoModelNameLooksSelectableForMode(string model, string mode) {
        string text = NormalizeAutoModelId(model);
        if (string.IsNullOrWhiteSpace(text))
            return false;

        string normalizedMode = NormalizeAutoMode(mode);
        if (normalizedMode.Equals("image", StringComparison.OrdinalIgnoreCase))
            return Regex.IsMatch(text, @"(?:stable|diffusion|sdxl|flux|image[_\s/-]?generation|text[_\s/-]?to[_\s/-]?image|t2i|qwen[_\s/-]?image|imagegen)", RegexOptions.IgnoreCase);
        if (normalizedMode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            return Regex.IsMatch(text, @"(?:audio|speech|tts|whisper|music|voice)", RegexOptions.IgnoreCase);
        if (normalizedMode.Equals("video", StringComparison.OrdinalIgnoreCase))
            return Regex.IsMatch(text, @"(?:video|zeroscope|cerspense|svd|animated|motion|wan2?|ltx|hunyuan|text[_\s/-]?to[_\s/-]?video|t2v|i2v|v2v)", RegexOptions.IgnoreCase);
        if (normalizedMode.Equals("embedding", StringComparison.OrdinalIgnoreCase))
            return AutoModelLooksEmbedding(text);
        if (normalizedMode.Equals("multimodal", StringComparison.OrdinalIgnoreCase))
            return Regex.IsMatch(text, @"(?:vision|vl|omni|multi|llava)", RegexOptions.IgnoreCase) && !AutoModelLooksGenerationOnly(text);
        if (normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            return Regex.IsMatch(text, @"(?:tool|function|qwen|llama|mistral|gemma|phi|claude|opus|instruct|chat|llm|gguf|unsloth|gpt)", RegexOptions.IgnoreCase) && !AutoModelLooksGenerationOnly(text);

        return !AutoModelLooksEmbedding(text) &&
               !AutoModelLooksGenerationOnly(text) &&
               AutoModelLooksChatCapable(text);
    }

    private static bool AutoModelAliasMatches(string candidate, IEnumerable<string> requestedAliases) {
        if (string.IsNullOrWhiteSpace(candidate))
            return false;

        foreach (string requested in requestedAliases) {
            if (string.IsNullOrWhiteSpace(requested))
                continue;
            if (candidate.Equals(requested, StringComparison.OrdinalIgnoreCase))
                return true;
            if (candidate.Contains(requested, StringComparison.OrdinalIgnoreCase) || requested.Contains(candidate, StringComparison.OrdinalIgnoreCase))
                return true;
        }

        return false;
    }

    private static string CleanAutoModelDisplayName(string value) {
        string text = (value ?? "").Trim().Trim('"', '\'').Replace('\\', '/');
        if (string.IsNullOrWhiteSpace(text))
            return "";

        int queryIndex = text.IndexOfAny(new[] { '?', '#' });
        if (queryIndex >= 0)
            text = text[..queryIndex];

        bool lookedLikePath = text.Contains('/', StringComparison.Ordinal) || text.Contains(':', StringComparison.Ordinal);
        List<string> parts = text.Split('/', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(part => !Regex.IsMatch(part, @"^[a-z]:$", RegexOptions.IgnoreCase))
            .Select(SanitizeAutoModelDisplayName)
            .Where(part => !IsAutoModelArtifactPart(part))
            .ToList();

        if (parts.Count > 0 && lookedLikePath) {
            text = parts.LastOrDefault(AutoModelNameLooksSpecific) ??
                   parts.OrderByDescending(part => part.Length).FirstOrDefault() ??
                   "";
        }

        text = SanitizeAutoModelDisplayName(text);
        return IsAutoModelArtifactPart(text) ? "" : text;
    }

    private static string SanitizeAutoModelDisplayName(string value) {
        string text = (value ?? "").Trim().Trim('"', '\'').Replace('\\', '/');
        if (string.IsNullOrWhiteSpace(text))
            return "";

        text = Regex.Replace(text, @"[?#].*$", "", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"\.(?:gguf|safetensors|bin|onnx|json|yaml|yml|txt|md)$", "", RegexOptions.IgnoreCase).Trim();
        text = Regex.Replace(text, @"^(?:huggingface|hf|models?|complete[-_ ]?models?|storage|stor2?)[\s._/-]+", "", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"^(?:lightricks|fastvideo)[\s._-]+(?=.+(?:\d|ltx|wan|video|image))", "", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"[\s._-]+(?:pytorch|diffusers|onnx|cuda|cpu|safetensors|checkpoint|weights)$", "", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"[\s._-]+q[0-9]+(?:_[a-z0-9]+)+$", "", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"\s{2,}", " ").Trim();
        text = text.Trim('.', '/', '\\', '-', '_', ' ');
        return text;
    }

    private static bool IsAutoModelArtifactPart(string value) {
        string text = (value ?? "").Trim().Trim('.', '/', '\\', '-', '_', ' ');
        if (string.IsNullOrWhiteSpace(text))
            return true;

        string normalized = text.ToLowerInvariant();
        if (normalized is "auth" or "chat" or "main" or "model" or "models" or "local" or "pytorch" or "diffusers" or "onnx" or "cuda" or "cpu" or "video" or "image" or "audio" or "text" or "vision" or "video_generation" or "image_generation" or "audio_generation" or "text_generation" or "complete-model" or "completemodel" or "complete-models" or "completemodels" or "gguf" or "stor" or "stor2" or "storage" or "manifest" or "manifest.json" or "config" or "config.json" or "model_index" or "model_index.json")
            return true;
        if (normalized.Contains("completemodel", StringComparison.Ordinal) ||
            normalized.Contains("complete-model", StringComparison.Ordinal) ||
            normalized.Contains(" stay in models", StringComparison.Ordinal) ||
            normalized.StartsWith("standard ", StringComparison.Ordinal))
            return true;
        if (Regex.IsMatch(normalized, @"^q[0-9]+(?:_[a-z0-9]+)+$", RegexOptions.IgnoreCase))
            return true;
        if (!normalized.Any(char.IsDigit) && !normalized.Contains('-', StringComparison.Ordinal) && !normalized.Contains('/', StringComparison.Ordinal) && normalized.Length < 12)
            return true;
        if (Regex.IsMatch(normalized, @"^(?:tokenizer|preprocessor|scheduler|vae|unet|text_encoder|generation_config)(?:\..*)?$", RegexOptions.IgnoreCase))
            return true;
        if (Regex.IsMatch(normalized, @"\.(?:json|txt|md|yaml|yml|lock)$", RegexOptions.IgnoreCase))
            return true;

        return false;
    }

    private static bool AutoModelNameLooksSpecific(string value) {
        string text = (value ?? "").Trim().ToLowerInvariant();
        if (string.IsNullOrWhiteSpace(text))
            return false;
        bool hasModelKeyword = Regex.IsMatch(text, @"(?:flux|stable|diffusion|sdxl|qwen|llama|mistral|gemma|phi|wan|ltx|hunyuan|whisper|embedding|instruct|claude)", RegexOptions.IgnoreCase);
        if (hasModelKeyword)
            return true;
        if (text.Any(char.IsDigit) && (text.Contains('-', StringComparison.Ordinal) || text.Contains('.', StringComparison.Ordinal)))
            return true;
        return
               (text.Contains('-', StringComparison.Ordinal) && text.Length >= 12);
    }


    private string BuildAutoDisplayModelList(RegisteredServer server, string mode = "", double minParameterBillions = 0, double maxParameterBillions = 0, ISet<string>? userDisabledModels = null) {
        var models = new LinkedList<string>();
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        void Add(string value) {
            string cleaned = CleanAutoModelDisplayName(value);
            if (string.IsNullOrWhiteSpace(cleaned))
                return;
            if (seen.Add(NormalizeAutoModelId(cleaned)))
                models.AddLast(cleaned);
        }

        foreach (RegisteredServerModelInfo item in server.Models
            .Where(item => string.IsNullOrWhiteSpace(mode) || AutoModelIsSelectableForMode(item, mode))
            .Where(item => AutoModelMatchesParameterLimit(item.Id, string.IsNullOrWhiteSpace(mode) ? "text" : mode, minParameterBillions, maxParameterBillions))
            .Where(item => !AutoModelRequiresFreshBenchmark(server, item))
            .OrderByDescending(item => AutoModelModeScore(item, string.IsNullOrWhiteSpace(mode) ? "text" : mode))
            .ThenBy(item => CleanAutoModelDisplayName(item.Id), StringComparer.OrdinalIgnoreCase))
            Add(item.Id);
        if (models.Count == 0 && string.IsNullOrWhiteSpace(mode)) {
            foreach (string item in AutoSplitModelHints(server.AvailableModels).Where(item => AutoModelMatchesParameterLimit(item, string.IsNullOrWhiteSpace(mode) ? "text" : mode, minParameterBillions, maxParameterBillions)))
                Add(item);
        }

        return string.Join(", ", models);
    }

    private static int AutoLatencyScore(RegisteredServer server) {
        int proxy = server.ProxyLatencyMs > 0 ? server.ProxyLatencyMs : int.MaxValue / 4;
        int internet = server.InternetLatencyMs > 0 ? server.InternetLatencyMs : int.MaxValue / 4;
        return Math.Min(proxy, internet);
    }

    private static double AutoResourceLoadScore(RegisteredServer server) {
        string text = string.Join(" ", server.ModelRuntimeStatus, server.LastStatus, server.AvailableResources, server.GpuAvailable, server.CpuAvailable);
        double active = ExtractAutoResourceMetric(text, "active", "running", "busy");
        double queue = ExtractAutoResourceMetric(text, "queue", "queued", "pending", "waiting");
        double jobs = ExtractAutoResourceMetric(text, "jobs", "job");
        return active * 1000d + queue * 500d + jobs * 100d;
    }

    private static double AutoHardwareScore(RegisteredServer server) {
        double vramGb = ExtractAutoGb(server.AvailableVram + " " + server.GpuAvailable);
        double ramGb = ExtractAutoGb(server.AvailableRam + " " + server.AvailableResources);
        string gpu = (server.GpuModel ?? "").ToLowerInvariant();
        double gpuBonus = 0;
        if (gpu.Contains("h100", StringComparison.Ordinal)) gpuBonus += 1200;
        else if (gpu.Contains("a100", StringComparison.Ordinal)) gpuBonus += 900;
        else if (gpu.Contains("6000", StringComparison.Ordinal) || gpu.Contains("4090", StringComparison.Ordinal)) gpuBonus += 650;
        else if (gpu.Contains("4080", StringComparison.Ordinal) || gpu.Contains("3090", StringComparison.Ordinal)) gpuBonus += 450;
        else if (gpu.Contains("4070", StringComparison.Ordinal) || gpu.Contains("3080", StringComparison.Ordinal)) gpuBonus += 280;
        else if (gpu.Contains("cuda", StringComparison.Ordinal) || gpu.Contains("rtx", StringComparison.Ordinal)) gpuBonus += 120;

        return gpuBonus + vramGb * 100d + ramGb * 8d;
    }

    private static double ExtractAutoResourceMetric(string text, params string[] names) {
        if (string.IsNullOrWhiteSpace(text))
            return 0;

        foreach (string name in names) {
            Match after = Regex.Match(text, @"\b" + Regex.Escape(name) + @"\b\s*[:=]?\s*(\d+(?:\.\d+)?)", RegexOptions.IgnoreCase);
            if (after.Success && double.TryParse(after.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double afterValue))
                return Math.Max(0, afterValue);

            Match before = Regex.Match(text, @"(\d+(?:\.\d+)?)\s*\b" + Regex.Escape(name) + @"\b", RegexOptions.IgnoreCase);
            if (before.Success && double.TryParse(before.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double beforeValue))
                return Math.Max(0, beforeValue);
        }

        return 0;
    }

    private static double ExtractAutoGb(string text) {
        if (string.IsNullOrWhiteSpace(text))
            return 0;

        double best = 0;
        foreach (Match match in Regex.Matches(text, @"(\d+(?:\.\d+)?)\s*(tib|tb|gib|gb|mib|mb)?", RegexOptions.IgnoreCase)) {
            if (!double.TryParse(match.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double value))
                continue;
            string unit = match.Groups[2].Value.ToLowerInvariant();
            if (unit is "tb" or "tib")
                value *= 1024d;
            else if (unit is "mb" or "mib")
                value /= 1024d;
            best = Math.Max(best, value);
        }

        return best;
    }

    private static double AutoCostScore(RegisteredServer server) =>
        server.CostFactor > 0 ? server.CostFactor : 1d;

    private static bool ServerRequiresAutoPremium(RegisteredServer? server) {
        if (server == null)
            return false;

        return server.RequiresPayment ||
               server.Cost > 0 ||
               !string.IsNullOrWhiteSpace(server.StripePriceId) ||
               server.StripeUnitAmountCents > 0;
    }

    private static long EstimateAutoPromptTokenCost(RegisteredServer? server, string mode) {
        if (!ServerRequiresAutoPremium(server))
            return 0;

        double factor = server != null && server.CostFactor > 0 ? server.CostFactor : 1d;
        long baseTokens = mode.Equals("video", StringComparison.OrdinalIgnoreCase) ? 1L : 1L;
        return Math.Max(1L, (long)Math.Ceiling(baseTokens * factor));
    }

    private static bool AccountHasAutoPremiumTokens(AccountRecord? account) {
        if (account == null)
            return false;

        long tokenLimit = Math.Max(0, account.TokenLimit);
        if (tokenLimit <= 0)
            return true;

        long tokensUsed = Math.Max(0, account.TokensUsed);
        return Math.Max(0, tokenLimit - tokensUsed) > 0;
    }

    private static string ExtractAutoModel(HttpRequest request) =>
        FirstNonEmpty(
            GetQuery(request, "model"),
            GetQuery(request, "model_id"),
            GetQuery(request, "modelId"),
            GetJsonBodyText(request, "model"),
            GetJsonBodyText(request, "model_id"),
            GetJsonBodyText(request, "modelId"));

    private static string ExtractAutoServerId(HttpRequest request) =>
        FirstNonEmpty(
            GetQuery(request, "server"),
            GetQuery(request, "server_id"),
            GetQuery(request, "serverId"),
            GetJsonBodyText(request, "server"),
            GetJsonBodyText(request, "server_id"),
            GetJsonBodyText(request, "serverId"));

    private static bool ExtractAutoStrictServerEnabled(HttpRequest request) =>
