    private static string ExtractAutoOriginMode(HttpRequest request) =>
        FirstNonEmpty(
            GetQuery(request, "origin"),
            GetQuery(request, "origin_mode"),
            GetQuery(request, "originMode"),
            GetQuery(request, "routing_strategy"),
            GetQuery(request, "routingStrategy"),
            GetJsonBodyText(request, "origin"),
            GetJsonBodyText(request, "origin_mode"),
            GetJsonBodyText(request, "originMode"),
            GetJsonBodyText(request, "routing_strategy"),
            GetJsonBodyText(request, "routingStrategy"));

    private static bool ExtractAutoPoolEnabled(HttpRequest request) {
        string explicitValue = FirstNonEmpty(
            GetQuery(request, "pool"),
            GetQuery(request, "pool_enabled"),
            GetQuery(request, "poolEnabled"),
            GetQuery(request, "multiGpu"),
            GetQuery(request, "multi_gpu"),
            GetQuery(request, "multiGpuPool"),
            GetQuery(request, "multi_gpu_pool"),
            GetQuery(request, "parallelPool"),
            GetQuery(request, "parallel_pool"),
            GetJsonBodyText(request, "pool"),
            GetJsonBodyText(request, "pool_enabled"),
            GetJsonBodyText(request, "poolEnabled"),
            GetJsonBodyText(request, "multiGpu"),
            GetJsonBodyText(request, "multi_gpu"),
            GetJsonBodyText(request, "multiGpuPool"),
            GetJsonBodyText(request, "multi_gpu_pool"),
            GetJsonBodyText(request, "parallelPool"),
            GetJsonBodyText(request, "parallel_pool"));
        if (!string.IsNullOrWhiteSpace(explicitValue))
            return IsTruthyText(explicitValue);

        string legacyOrigin = (ExtractAutoOriginMode(request) ?? "").Trim().Replace('_', '-').ToLowerInvariant();
        return legacyOrigin.Contains("pool", StringComparison.Ordinal) ||
               legacyOrigin.Contains("parallel", StringComparison.Ordinal) ||
               legacyOrigin.Contains("multi-gpu", StringComparison.Ordinal) ||
               legacyOrigin.Contains("multi gpu", StringComparison.Ordinal) ||
               legacyOrigin.Contains("multigpu", StringComparison.Ordinal);
    }

    private static double ExtractAutoMaxParameterBillions(HttpRequest request) {
        string value = FirstNonEmpty(
            GetQuery(request, "maxParamsB"),
            GetQuery(request, "paramsB"),
            GetQuery(request, "max_parameters_b"),
            GetQuery(request, "maxParametersB"),
            GetQuery(request, "parameterLimitB"),
            GetQuery(request, "parameter_limit_b"),
            GetJsonBodyText(request, "maxParamsB"),
            GetJsonBodyText(request, "paramsB"),
            GetJsonBodyText(request, "max_parameters_b"),
            GetJsonBodyText(request, "maxParametersB"),
            GetJsonBodyText(request, "parameterLimitB"),
            GetJsonBodyText(request, "parameter_limit_b"));
        if (string.IsNullOrWhiteSpace(value))
            return 0;
        value = Regex.Replace(value.Trim(), @"[^0-9.]", "");
        return double.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed)
            ? Math.Clamp(parsed, 0d, 1000d)
            : 0d;
    }

    private static double ExtractAutoMinParameterBillions(HttpRequest request) {
        string value = FirstNonEmpty(
            GetQuery(request, "minParamsB"),
            GetQuery(request, "min_parameters_b"),
            GetQuery(request, "minParametersB"),
            GetQuery(request, "parameterMinimumB"),
            GetQuery(request, "parameter_minimum_b"),
            GetJsonBodyText(request, "minParamsB"),
            GetJsonBodyText(request, "min_parameters_b"),
            GetJsonBodyText(request, "minParametersB"),
            GetJsonBodyText(request, "parameterMinimumB"),
            GetJsonBodyText(request, "parameter_minimum_b"));
        if (string.IsNullOrWhiteSpace(value))
            return 0;
        value = Regex.Replace(value.Trim(), @"[^0-9.]", "");
        return double.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed)
            ? Math.Clamp(parsed, 0d, 1000d)
            : 0d;
    }

    private static ISet<string> ExtractAutoDisabledModels(HttpRequest request) {
        var disabled = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        void AddOne(string value) {
            string clean = CleanAutoModelDisplayName(value);
            foreach (string candidate in new[] { value, clean }) {
                string normalized = NormalizeAutoModelId(candidate);
                if (!string.IsNullOrWhiteSpace(normalized))
                    disabled.Add(normalized);
            }
        }

        void AddMany(string value) {
            if (string.IsNullOrWhiteSpace(value))
                return;
            string text = value.Trim();
            if (text.StartsWith("[", StringComparison.Ordinal)) {
                try {
                    using JsonDocument document = JsonDocument.Parse(text);
                    if (document.RootElement.ValueKind == JsonValueKind.Array) {
                        foreach (JsonElement item in document.RootElement.EnumerateArray())
                            AddOne(item.ValueKind == JsonValueKind.String ? item.GetString() ?? "" : item.ToString());
                        return;
                    }
                } catch {
                }
            }

            foreach (string item in AutoSplitModelHints(text))
                AddOne(item);
        }

        AddMany(GetQuery(request, "disabledModels"));
        AddMany(GetQuery(request, "disabled_models"));
        AddMany(GetQuery(request, "excludedModels"));
        AddMany(GetQuery(request, "excluded_models"));
        AddMany(GetQuery(request, "excludeModels"));
        AddMany(GetQuery(request, "exclude_models"));

        if (!string.IsNullOrWhiteSpace(request?.Body)) {
            try {
                using JsonDocument document = JsonDocument.Parse(request.Body);
                if (document.RootElement.ValueKind == JsonValueKind.Object) {
                    foreach (string name in new[] { "disabledModels", "disabled_models", "excludedModels", "excluded_models", "excludeModels", "exclude_models" }) {
                        if (!document.RootElement.TryGetProperty(name, out JsonElement value))
                            continue;
                        if (value.ValueKind == JsonValueKind.Array) {
                            foreach (JsonElement item in value.EnumerateArray())
                                AddOne(item.ValueKind == JsonValueKind.String ? item.GetString() ?? "" : item.ToString());
                        } else {
                            AddMany(value.ValueKind == JsonValueKind.String ? value.GetString() ?? "" : value.ToString());
                        }
                    }
                }
            } catch {
            }
        }

        return disabled;
    }

    private static bool ExtractAutoPremiumModelsEnabled(HttpRequest request) =>
        IsTruthyText(FirstNonEmpty(
            GetQuery(request, "premium"),
            GetQuery(request, "premiumModels"),
            GetQuery(request, "premium_models"),
            GetQuery(request, "premiumModelsEnabled"),
            GetQuery(request, "allowPremium"),
            GetJsonBodyText(request, "premium"),
            GetJsonBodyText(request, "premiumModels"),
            GetJsonBodyText(request, "premium_models"),
            GetJsonBodyText(request, "premiumModelsEnabled"),
            GetJsonBodyText(request, "allowPremium")));

    private static bool IsTruthyText(string value) {
        string normalized = (value ?? "").Trim().ToLowerInvariant();
        return normalized.Equals("1", StringComparison.Ordinal) ||
               normalized.Equals("true", StringComparison.Ordinal) ||
               normalized.Equals("yes", StringComparison.Ordinal) ||
               normalized.Equals("on", StringComparison.Ordinal) ||
               normalized.Equals("enabled", StringComparison.Ordinal);
    }

    private static string ExtractAutoMode(HttpRequest request, string forwardedPath) {
        string mode = FirstNonEmpty(
            GetQuery(request, "mode"),
            GetQuery(request, "type"),
            GetQuery(request, "modality"),
            GetJsonBodyText(request, "mode"),
            GetJsonBodyText(request, "type"),
            GetJsonBodyText(request, "modality"));
        if (!string.IsNullOrWhiteSpace(mode))
            return mode;
        if (forwardedPath.Contains("image", StringComparison.OrdinalIgnoreCase))
            return "image";
        if (forwardedPath.Contains("audio", StringComparison.OrdinalIgnoreCase))
            return "audio";
        if (forwardedPath.Contains("video", StringComparison.OrdinalIgnoreCase))
            return "video";
        return "text";
    }

    private static string NormalizeAutoMode(string mode) {
        string normalized = (mode ?? "").Trim().ToLowerInvariant();
        if (normalized.Contains("multi", StringComparison.Ordinal) ||
            normalized.Contains("vision", StringComparison.Ordinal) ||
            normalized.Contains("vlm", StringComparison.Ordinal) ||
            normalized.Contains("omni", StringComparison.Ordinal))
            return "multimodal";
        if (normalized.Contains("tool", StringComparison.Ordinal) ||
            normalized.Contains("agent", StringComparison.Ordinal) ||
            normalized.Contains("function", StringComparison.Ordinal))
            return "tools";
        if (normalized.Contains("embed", StringComparison.Ordinal) ||
            normalized.Contains("vector", StringComparison.Ordinal))
            return "embedding";
        if (normalized.Contains("image", StringComparison.Ordinal))
            return "image";
        if (normalized.Contains("audio", StringComparison.Ordinal) || normalized.Contains("speech", StringComparison.Ordinal))
            return "audio";
        if (normalized.Contains("video", StringComparison.Ordinal))
            return "video";
        if (normalized.Contains("chat", StringComparison.Ordinal) ||
            normalized.Contains("text", StringComparison.Ordinal) ||
            normalized.Contains("llm", StringComparison.Ordinal))
            return "text";
        return "text";
    }

    private static string NormalizeAutoOriginMode(string mode) {
        string normalized = (mode ?? "").Trim().Replace('_', '-').ToLowerInvariant();
        if (normalized.Contains("same", StringComparison.Ordinal) ||
            normalized.Contains("relay", StringComparison.Ordinal) ||
            normalized.Contains("master", StringComparison.Ordinal))
            return "same-origin";
        return "hybrid";
    }

    private static bool AutoApiRequiresAuthenticatedUser(HttpRequest request, string mode) {
        if (IsAutoPublicTextMode(mode)) {
            string service = FirstNonEmpty(
                GetQuery(request, "service"),
                GetQuery(request, "serviceId"),
                GetJsonBodyText(request, "service"),
                GetJsonBodyText(request, "serviceId"),
                GetJsonBodyText(request, "chat_service"),
                GetJsonBodyText(request, "chatService"));
            return IsAutoProtectedService(service);
        }

        return true;
    }

    private static bool IsAutoPublicTextMode(string mode) =>
        mode.Equals("text", StringComparison.OrdinalIgnoreCase);

    private static bool IsAutoProtectedService(string service) {
        string normalized = (service ?? "").Trim().Replace('-', '_').ToLowerInvariant();
        return normalized.Equals("image_generation", StringComparison.Ordinal) ||
               normalized.Equals("audio_generation", StringComparison.Ordinal) ||
               normalized.Equals("video_generation", StringComparison.Ordinal) ||
               normalized.Equals("agent", StringComparison.Ordinal) ||
               normalized.Equals("tool", StringComparison.Ordinal) ||
               normalized.Equals("tools", StringComparison.Ordinal) ||
               normalized.Equals("tool_use", StringComparison.Ordinal) ||
               normalized.Equals("embedding", StringComparison.Ordinal) ||
               normalized.Equals("embeddings", StringComparison.Ordinal) ||
               normalized.Equals("vector", StringComparison.Ordinal);
    }

    private static string GetQuery(HttpRequest request, string name) =>
        request.QueryParameters != null && request.QueryParameters.TryGetValue(name, out string? value)
            ? value ?? ""
            : "";

    private static string GetJsonBodyText(HttpRequest request, string name) {
        if (string.IsNullOrWhiteSpace(request?.Body))
            return "";
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty(name, out JsonElement value))
                return value.ValueKind == JsonValueKind.String ? value.GetString() ?? "" : value.ToString();
        } catch {
        }

        return "";
    }

    private static string AutoServerDisplayName(RegisteredServer? server) =>
        server == null ? "a server" : FirstNonEmpty(server.TitleText, server.DisplayName, server.Id, "a server");

    private static void AddAutoRoutingHeaders(HttpRequest request, RegisteredServer? selectedServer, int eligibleCount, string mode, string model = "", MasterShellRelay? relay = null) {
        if (request?.Context?.Response?.Headers == null)
            return;
        foreach (KeyValuePair<string, string> header in BuildAutoRoutingHeaderMap(selectedServer, relay, eligibleCount, mode, model))
            request.Context.Response.Headers[header.Key] = header.Value;
    }

    private static Dictionary<string, string> BuildAutoRoutingHeaderMap(RegisteredServer? selectedServer, int eligibleCount, string mode, string model = "") {
        return BuildAutoRoutingHeaderMap(selectedServer, null, eligibleCount, mode, model);
    }

    private static Dictionary<string, string> BuildAutoRoutingHeaderMap(RegisteredServer? selectedServer, MasterShellRelay? relay, int eligibleCount, string mode, string model = "") {
        var headers = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase) {
            ["X-SocketJack-Auto"] = "true",
            ["X-SocketJack-Auto-Eligible"] = eligibleCount.ToString(CultureInfo.InvariantCulture),
            ["X-SocketJack-Auto-Mode"] = mode
        };
        string displayModel = CleanAutoModelDisplayName(model);
        if (!string.IsNullOrWhiteSpace(model))
            headers["X-SocketJack-Auto-Model-Id"] = SanitizeForwardedHeaderValue(model.Trim());
        if (!string.IsNullOrWhiteSpace(displayModel))
            headers["X-SocketJack-Auto-Model"] = displayModel;
        if (selectedServer != null) {
            headers["X-SocketJack-Auto-Server"] = FirstNonEmpty(selectedServer.Id, selectedServer.TitleText);
            headers["X-SocketJack-Auto-Server-Title"] = SanitizeForwardedHeaderValue(FirstNonEmpty(selectedServer.TitleText, selectedServer.DisplayName, selectedServer.Id));
            headers["X-SocketJack-Auto-Server-Hardware"] = SanitizeForwardedHeaderValue(BuildAutoServerHardwareSummary(selectedServer));
            headers["X-SocketJack-Auto-Continue-Url"] = SanitizeForwardedHeaderValue(BuildAutoServerContinueUrl(selectedServer, relay));
            headers["X-SocketJack-Auto-Premium"] = ServerRequiresAutoPremium(selectedServer) ? "true" : "false";
            headers["X-SocketJack-Auto-Estimated-Tokens"] = EstimateAutoPromptTokenCost(selectedServer, mode).ToString(CultureInfo.InvariantCulture);
        }
        return headers;
    }

    private static void SetAutoProxyNoMatchResponse(HttpRequest request, string model, string mode, int eligibleCount, string message) {
        if (!IsShellProxyBrowserNavigation(request)) {
            request.Context.StatusCodeNumber = 503;
            request.Context.ReasonPhrase = "Service Unavailable";
            request.Context.Response.ContentType = "application/json";
            request.Context.Response.Body = JsonSerializer.Serialize(new {
                ok = false,
                error = message,
                code = "auto_no_eligible_server",
                model,
                mode,
                eligible_servers = eligibleCount
            }, MasterListJson.Options);
            AddCors(request);
            return;
        }

        request.Context.StatusCodeNumber = 503;
        request.Context.ReasonPhrase = "Service Unavailable";
        request.Context.Response.ContentType = "text/html; charset=utf-8";
        request.Context.Response.Headers["Cache-Control"] = "no-store, no-cache, must-revalidate";
        request.Context.Response.Headers["Pragma"] = "no-cache";
        request.Context.Response.Headers["Retry-After"] = "4";
        request.Context.Response.Body = request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase)
            ? ""
            : BuildAutoProxyNoMatchHtml(model, mode, message);
        AddCors(request);
    }

