</head>
<body><main class="card"><div class="kicker">SocketJack Auto</div><h1>No healthy server is ready yet.</h1><div class="meta">__MESSAGE__</div><div class="route">model: __MODEL__<br>mode: __MODE__</div></main></body>
</html>
"""
            .Replace("__MODEL__", title)
            .Replace("__MODE__", encodedMode)
            .Replace("__MESSAGE__", encodedMessage);
    }

    private static bool ShouldAttemptShellProxyForward(MasterShellRelay relay, DateTimeOffset now) {
        if (!IsShellRelayRouteListening(relay))
            return false;
        return relay.WebSocketTunnelConnected || relay.WaitingAgents > 0;
    }

    private bool ShouldRedirectShellProxyNavigationToLogin(NetworkConnection connection, HttpRequest request, string forwardedPath) {
        if (!IsShellProxyBrowserNavigation(request))
            return false;
        if (!string.IsNullOrWhiteSpace(forwardedPath) &&
            forwardedPath.StartsWith("/api/", StringComparison.OrdinalIgnoreCase))
            return false;
        if (AuthenticateRequest(request, out _) != null)
            return false;
        return !TryAutoAuthenticateKnownIp(connection, request, out AccountRecord? record, out _) || record == null;
    }

    private bool TryRedirectShellProxyNavigationWithAuthToken(NetworkConnection connection, HttpRequest request, string forwardedPath) {
        if (!IsShellProxyBrowserNavigation(request))
            return false;
        if (!string.IsNullOrWhiteSpace(forwardedPath) &&
            forwardedPath.StartsWith("/api/", StringComparison.OrdinalIgnoreCase))
            return false;
        if (HasShellProxyUrlAuthToken(request))
            return false;
        if (!TryResolveShellProxyUrlAuthToken(connection, request, out string token))
            return false;

        string currentPath = request.Path ?? "/";
        if (!string.IsNullOrWhiteSpace(request.QueryString))
            currentPath += "?" + request.QueryString;
        string redirectUrl = AppendQuery(currentPath, new Dictionary<string, string> {
            ["socketjack_auth"] = token
        });

        request.Context.StatusCodeNumber = 302;
        request.Context.ReasonPhrase = "Found";
        request.Context.Response.Headers["Location"] = redirectUrl;
        request.Context.Response.Headers["Cache-Control"] = "no-store, no-cache, must-revalidate";
        request.Context.Response.Headers["Pragma"] = "no-cache";
        request.Context.Response.ContentType = "text/plain; charset=utf-8";
        request.Context.Response.Body = "Forwarding SocketJack auth to proxy.";
        AddCors(request);
        return true;
    }

    private bool TryResolveShellProxyUrlAuthToken(NetworkConnection connection, HttpRequest request, out string token) {
        token = "";
        AccountRecord? record = AuthenticateRequest(request, out _);
        if (record != null) {
            token = ExtractTokenFromRequest(request);
            if (string.IsNullOrWhiteSpace(token) || ShouldRefreshAuthToken(record))
                token = IssueToken(record, request, remember: true);
            return !string.IsNullOrWhiteSpace(token);
        }

        return TryAutoAuthenticateKnownIp(connection, request, out record, out token) &&
               record != null &&
               !string.IsNullOrWhiteSpace(token);
    }

    private static bool HasShellProxyUrlAuthToken(HttpRequest request) {
        if (request?.QueryParameters == null)
            return false;

        foreach (string name in ShellProxyUrlAuthTokenNames) {
            if (request.QueryParameters.TryGetValue(name, out string? value) &&
                !string.IsNullOrWhiteSpace(value))
                return true;
        }

        return false;
    }

    private static readonly string[] ShellProxyUrlAuthTokenNames = {
        "socketjack_auth",
        "socketjack_token",
        "socketjackAccessToken",
        "sj_auth",
        "authToken",
        "access_token"
    };

    private static void SetShellProxyLoginRedirect(HttpRequest request) {
        string returnPath = request.Path ?? "/";
        if (!string.IsNullOrWhiteSpace(request.QueryString))
            returnPath += "?" + request.QueryString;
        string loginUrl = BuildSocketJackLoginPath(returnPath);

        request.Context.StatusCodeNumber = 302;
        request.Context.ReasonPhrase = "Found";
        request.Context.Response.Headers["Location"] = loginUrl;
        request.Context.Response.ContentType = "text/plain; charset=utf-8";
        request.Context.Response.Body = "Redirecting to " + loginUrl;
        AddCors(request);
    }

    private MasterShellRelay? ResolveShellRelayForProxy(string routeName) {
        lock (_sync) {
            MasterShellRelay? relay = _shellRelays.Values.FirstOrDefault(candidate =>
                string.Equals(candidate.RouteName, routeName, StringComparison.OrdinalIgnoreCase));
            if (relay == null)
                return null;
            if (relay.Enabled && IsListening && !_shellRelayServers.ContainsKey(relay.Id))
                StartShellRelayLocked(relay.Id);
            return UpdateShellRelayRuntime(relay).Clone();
        }
    }

    private MasterShellRelay WaitForShellRelayAgent(string routeName, MasterShellRelay relay) {
        if (!relay.Enabled || !relay.IsRunning)
            return relay;

        int attempts = Math.Max(1, (int)Math.Ceiling(ShellProxyAgentCapacityWait.TotalMilliseconds / 250d));
        for (int attempt = 0; attempt < attempts; attempt++) {
            Thread.Sleep(250);
            MasterShellRelay? current = ResolveShellRelayForProxy(routeName);
            if (current == null)
                return relay;
            relay = current;
            if (relay.WaitingAgents > 0)
                break;
        }

        return relay;
    }

    private void ForwardShellProxyRequest(HttpRequest request, MasterShellRelay relay, string forwardedPath, CancellationToken cancellationToken, string? proxyPathOverride = null) {
        string query = string.IsNullOrWhiteSpace(request.QueryString) ? "" : "?" + request.QueryString;
        Uri upstreamUri = new("http://127.0.0.1:" + relay.PublicPort.ToString(CultureInfo.InvariantCulture) + forwardedPath + query);
        bool streamingRequest = IsShellProxyStreamingRequest(request, forwardedPath);
        using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, streamingRequest);
        CancellationToken proxyCancellationToken = timeoutCts?.Token ?? cancellationToken;
        using var upstreamRequest = new System.Net.Http.HttpRequestMessage(new System.Net.Http.HttpMethod(request.Method), upstreamUri);
        upstreamRequest.Headers.ConnectionClose = true;
        string proxyPath = string.IsNullOrWhiteSpace(proxyPathOverride)
            ? BuildShellProxyPath(relay.RouteName).TrimEnd('/')
            : proxyPathOverride.TrimEnd('/');

        if (request.BodyBytes != null && request.BodyBytes.Length > 0) {
            upstreamRequest.Content = new System.Net.Http.ByteArrayContent(request.BodyBytes);
            if (request.Headers.TryGetValue("Content-Type", out string? requestContentType) && !string.IsNullOrWhiteSpace(requestContentType))
                upstreamRequest.Content.Headers.TryAddWithoutValidation("Content-Type", requestContentType);
        }

        foreach (KeyValuePair<string, string> header in request.Headers) {
            if (ShouldSkipProxyRequestHeader(header.Key))
                continue;
            if (!upstreamRequest.Headers.TryAddWithoutValidation(header.Key, header.Value) && upstreamRequest.Content != null)
                upstreamRequest.Content.Headers.TryAddWithoutValidation(header.Key, header.Value);
        }

        string originalHost = request.Headers != null && request.Headers.TryGetValue("Host", out string? hostHeader)
            ? hostHeader
            : request.Host;
        upstreamRequest.Headers.Remove("X-Forwarded-Host");
        upstreamRequest.Headers.Remove("X-Forwarded-Proto");
        upstreamRequest.Headers.Remove("X-Forwarded-Prefix");
        if (!string.IsNullOrWhiteSpace(originalHost))
            upstreamRequest.Headers.TryAddWithoutValidation("X-Forwarded-Host", SanitizeForwardedHeaderValue(originalHost));
        upstreamRequest.Headers.TryAddWithoutValidation("X-Forwarded-Proto", request.Context?.Connection?.Parent?.Options?.UseSsl == true ? "https" : "http");
        upstreamRequest.Headers.TryAddWithoutValidation("X-Forwarded-Prefix", proxyPath);

        using System.Net.Http.HttpResponseMessage upstreamResponse = ShellProxyHttpClient.Send(
            upstreamRequest,
            streamingRequest ? HttpCompletionOption.ResponseHeadersRead : HttpCompletionOption.ResponseContentRead,
            proxyCancellationToken);
        string contentType = upstreamResponse.Content.Headers.ContentType?.ToString() ?? "application/octet-stream";
        if (streamingRequest || IsShellProxyStreamingResponse(contentType, forwardedPath)) {
            StreamShellProxyResponse(request, upstreamResponse, contentType, proxyCancellationToken);
            return;
        }

        byte[] body = upstreamResponse.Content.ReadAsByteArrayAsync(proxyCancellationToken).GetAwaiter().GetResult();
        bool rewritten = false;
        if (IsShellProxyModelsApiPath(forwardedPath)) {
            body = RewriteShellProxyModelsApiResponse(body);
            rewritten = true;
        } else if (IsHtmlContentType(contentType) && !IsShellProxyBrowserProxyPath(forwardedPath)) {
            body = RewriteShellProxyHtml(body, proxyPath);
            rewritten = true;
        }

        HttpResponse response = request.Context.Response;
        request.Context.StatusCodeNumber = (int)upstreamResponse.StatusCode;
        request.Context.ReasonPhrase = string.IsNullOrWhiteSpace(upstreamResponse.ReasonPhrase)
            ? GetReasonPhrase((int)upstreamResponse.StatusCode)
            : upstreamResponse.ReasonPhrase!;
        response.ContentType = contentType;
        response.BodyBytes = request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase) ? Array.Empty<byte>() : body;
        CopyProxyHeaders(response.Headers, upstreamResponse.Headers, rewritten, proxyPath);
        CopyProxyHeaders(response.Headers, upstreamResponse.Content.Headers, rewritten, proxyPath);
        AddCors(request);
    }

    private JsonObject BuildShellProxyJsonWebSocketSnapshot(ShellProxyJsonWebSocketState state, JsonObject? clientRequest) {
        DateTimeOffset receivedUtc = DateTimeOffset.UtcNow;
        string requestId = JsonText(clientRequest, "id", JsonText(clientRequest, "requestId", ""));
        string clientSentAt = JsonText(clientRequest, "clientSentAt", "");
        MasterShellRelay? relay = ResolveShellRelayForProxy(state.RouteName);
        if (relay == null)
            return BuildShellProxyJsonWebSocketError(state, requestId, 404, "Shell proxy route was not found.", receivedUtc, null);
        RegisteredServer? registeredServer = FindRegisteredServerForShellRelay(relay);

        if (!relay.Enabled)
            return BuildShellProxyJsonWebSocketError(state, requestId, 503, "Shell proxy route is disabled.", receivedUtc, registeredServer);
        if (!relay.IsRunning)
            return BuildShellProxyJsonWebSocketError(state, requestId, 503, "Shell proxy route is not listening: " + relay.Status, receivedUtc, registeredServer);
        if (!ShouldAttemptShellProxyForward(relay, receivedUtc))
            return BuildShellProxyJsonWebSocketError(state, requestId, 503, "JackLLM has not connected its reverse shell agent yet.", receivedUtc, registeredServer);

        ShellProxyJsonFetchResult result = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)
            ? _shellProxyWebSocketTunnels.FetchJson(relay, state.ForwardedPath, state.QueryString, CancellationToken.None)
            : FetchShellProxyJsonForWebSocket(relay, state.ForwardedPath, state.QueryString, CancellationToken.None);
        JsonObject output = ParseShellProxyJsonObject(result.Body);
        if (!output.ContainsKey("ok"))
            output["ok"] = result.StatusCode >= 200 && result.StatusCode < 300;
        output["type"] = "snapshot";
        output["requestId"] = requestId;
        if (!string.IsNullOrWhiteSpace(clientSentAt))
            output["clientSentAt"] = clientSentAt;
        output["socketJackTransport"] = "websocket";
        output["socketJackProxyRoute"] = state.RouteName;
        output["socketJackProxyPath"] = BuildShellProxyPath(state.RouteName);
        output["socketJackForwardedPath"] = state.ForwardedPath;
        output["socketJackReceivedUtc"] = receivedUtc.ToString("O", CultureInfo.InvariantCulture);
        output["socketJackSentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        output["socketJackToWorkstationMs"] = result.DurationMs;
        output["statusCode"] = result.StatusCode;
        if (!string.IsNullOrWhiteSpace(result.ReasonPhrase))
            output["reasonPhrase"] = result.ReasonPhrase;
        TryMergeShellProxyModelInventory(relay, state, output, registeredServer);
        ApplyRegisteredLatencyFields(output, registeredServer);
        UpdateRegisteredServerFromShellProxyJson(relay, registeredServer, output, result.StatusCode, result.DurationMs, receivedUtc);
        return output;
    }

    private void TryMergeShellProxyModelInventory(MasterShellRelay relay, ShellProxyJsonWebSocketState state, JsonObject output, RegisteredServer? registeredServer) {
        if (relay == null || state == null || output == null || !IsMasterListPingPath(state.ForwardedPath))
            return;
        try {
            ShellProxyJsonFetchResult modelsResult = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)
                ? _shellProxyWebSocketTunnels.FetchJson(relay, "/api/models", "", CancellationToken.None)
                : FetchShellProxyJsonForWebSocket(relay, "/api/models", "", CancellationToken.None);
            if (modelsResult.StatusCode < 200 || modelsResult.StatusCode >= 300 || string.IsNullOrWhiteSpace(modelsResult.Body))
                return;

            string enriched = EnrichShellProxyModelsApiJson(modelsResult.Body);
            JsonObject inventory = ParseShellProxyJsonObject(enriched);
            string modelBenchmarksJson = FirstUsefulModelBenchmarksJson(
                FindUsefulModelBenchmarksJson(output),
                FindUsefulModelBenchmarksJson(inventory),
                registeredServer?.ModelBenchmarksJson ?? "",
                FetchShellProxyHardwareBenchmarkJson(relay));
            if (!string.IsNullOrWhiteSpace(modelBenchmarksJson)) {
                inventory["modelBenchmarksJson"] = modelBenchmarksJson;
                inventory["benchmarkedModelCount"] = CountBenchmarkItems(modelBenchmarksJson);
                output["modelBenchmarksJson"] = modelBenchmarksJson;
                output["benchmarkedModelCount"] = CountBenchmarkItems(modelBenchmarksJson);
            }
            output["modelInventory"] = inventory.DeepClone();
            CopyModelInventoryField(output, inventory, "models");
            CopyModelInventoryField(output, inventory, "modelBenchmarksJson");
            CopyModelInventoryField(output, inventory, "benchmarkedModelCount");
            CopyModelInventoryField(output, inventory, "modelCount");
            CopyModelInventoryField(output, inventory, "availableModelCount");
            CopyModelInventoryField(output, inventory, "loadedModelCount");
            CopyModelInventoryField(output, inventory, "enabledModelCount");
            CopyModelInventoryField(output, inventory, "disabledModelCount");
            CopyModelInventoryField(output, inventory, "availableModels");
            CopyModelInventoryField(output, inventory, "loadedModels");
            CopyModelInventoryField(output, inventory, "enabledModels");
            CopyModelInventoryField(output, inventory, "disabledModels");
            CopyModelInventoryField(output, inventory, "dynamicLoadingEnabled");
            CopyModelInventoryField(output, inventory, "serverDynamicLoadingEnabled");
        } catch {
        }
    }

    private string FetchShellProxyHardwareBenchmarkJson(MasterShellRelay relay) {
        if (relay == null)
            return "";
        try {
            ShellProxyJsonFetchResult attestationResult = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)
                ? _shellProxyWebSocketTunnels.FetchJson(relay, "/api/hardware-attestation", "", CancellationToken.None)
                : FetchShellProxyJsonForWebSocket(relay, "/api/hardware-attestation", "", CancellationToken.None);
            if (attestationResult.StatusCode < 200 || attestationResult.StatusCode >= 300 || string.IsNullOrWhiteSpace(attestationResult.Body))
                return "";

            JsonObject attestation = ParseShellProxyJsonObject(attestationResult.Body);
            return FindUsefulModelBenchmarksJson(attestation);
        } catch {
            return "";
        }
    }

    private static void CopyModelInventoryField(JsonObject output, JsonObject inventory, string name) {
        if (output == null || inventory == null || !inventory.TryGetPropertyValue(name, out JsonNode? value) || value == null)
            return;
        output[name] = value.DeepClone();
    }

    private static string FirstUsefulModelBenchmarksJson(params string[] values) {
        foreach (string value in values ?? Array.Empty<string>()) {
            string normalized = NormalizeModelBenchmarksJsonText(value);
            if (!string.IsNullOrWhiteSpace(normalized))
                return normalized;
        }

        return "";
    }

    private static string FindUsefulModelBenchmarksJson(JsonNode? node, int depth = 0) {
        if (node == null || depth > 8)
            return "";
        if (node is JsonValue value) {
            if (value.TryGetValue(out string? text))
                return NormalizeModelBenchmarksJsonText(text);
            return "";
        }

        string direct = NormalizeModelBenchmarksNode(node);
        if (!string.IsNullOrWhiteSpace(direct))
            return direct;

        if (node is not JsonObject obj)
            return "";

        foreach (string name in new[] { "modelBenchmarksJson", "modelBenchmarks", "benchmarks" }) {
            if (TryGetJsonNodeProperty(obj, name, out JsonNode? child)) {
                string childBenchmarks = FindUsefulModelBenchmarksJson(child, depth + 1);
                if (!string.IsNullOrWhiteSpace(childBenchmarks))
                    return childBenchmarks;
            }
        }

        foreach (string name in new[] { "claims", "profile", "modelInventory", "payload", "server" }) {
            if (TryGetJsonNodeProperty(obj, name, out JsonNode? child)) {
                string childBenchmarks = FindUsefulModelBenchmarksJson(child, depth + 1);
                if (!string.IsNullOrWhiteSpace(childBenchmarks))
                    return childBenchmarks;
            }
        }

        foreach (KeyValuePair<string, JsonNode?> property in obj) {
            string childBenchmarks = FindUsefulModelBenchmarksJson(property.Value, depth + 1);
            if (!string.IsNullOrWhiteSpace(childBenchmarks))
                return childBenchmarks;
        }

        return "";
    }

    private static string NormalizeModelBenchmarksJsonText(string value) {
        value = (value ?? "").Trim();
        if (value.Length == 0 ||
            value.Equals("null", StringComparison.OrdinalIgnoreCase) ||
            value.Equals("\"\"", StringComparison.Ordinal) ||
            value.Equals("[]", StringComparison.Ordinal) ||
            value.Equals("{}", StringComparison.Ordinal))
            return "";

        try {
            JsonNode? node = JsonNode.Parse(value);
            return NormalizeModelBenchmarksNode(node);
        } catch {
            return "";
        }
    }

    private static string NormalizeModelBenchmarksNode(JsonNode? node) {
        if (node == null)
            return "";
        if (node is JsonValue value) {
            if (value.TryGetValue(out string? text))
                return NormalizeModelBenchmarksJsonText(text);
            return "";
        }
        if (node is JsonArray array)
            return array.Count == 0 || !JsonArrayLooksLikeBenchmarkArray(array) ? "" : array.ToJsonString(MasterListJson.Options);
        if (node is not JsonObject obj)
            return "";

        foreach (string name in new[] { "modelBenchmarksJson", "modelBenchmarks", "benchmarks" }) {
            if (TryGetJsonNodeProperty(obj, name, out JsonNode? child)) {
                string nested = NormalizeModelBenchmarksNode(child);
                if (!string.IsNullOrWhiteSpace(nested))
                    return nested;
            }
        }

        if (LooksLikeBenchmarkObject(obj)) {
            var single = new JsonArray(obj.DeepClone());
            return single.ToJsonString(MasterListJson.Options);
        }

        var keyed = new JsonArray();
        foreach (KeyValuePair<string, JsonNode?> property in obj) {
            if (property.Value is not JsonObject item || !LooksLikeBenchmarkObject(item, requireId: false))
                continue;
            JsonObject clone = (JsonObject)item.DeepClone();
            if (!TryGetJsonNodeProperty(clone, "modelId", out _) &&
                !TryGetJsonNodeProperty(clone, "ModelId", out _) &&
                !TryGetJsonNodeProperty(clone, "id", out _))
                clone["modelId"] = property.Key;
            keyed.Add(clone);
        }

        return keyed.Count == 0 ? "" : keyed.ToJsonString(MasterListJson.Options);
    }

    private static bool LooksLikeBenchmarkObject(JsonObject obj, bool requireId = true) {
        if (obj == null)
            return false;
        bool hasId = TryGetJsonNodeProperty(obj, "modelId", out _) ||
                     TryGetJsonNodeProperty(obj, "ModelId", out _) ||
                     TryGetJsonNodeProperty(obj, "id", out _) ||
                     TryGetJsonNodeProperty(obj, "model", out _) ||
                     TryGetJsonNodeProperty(obj, "name", out _);
        bool hasBenchmarkSignal =
            JsonNodeDouble(GetJsonNodeProperty(obj, "tokensPerSecond") ?? GetJsonNodeProperty(obj, "TokensPerSecond"), 0) > 0 ||
            JsonNodeDouble(GetJsonNodeProperty(obj, "tokensPerHour") ?? GetJsonNodeProperty(obj, "TokensPerHour"), 0) > 0 ||
            JsonNodeInt(GetJsonNodeProperty(obj, "outputTokens") ?? GetJsonNodeProperty(obj, "OutputTokens"), 0) > 0 ||
            JsonNodeDouble(GetJsonNodeProperty(obj, "durationMs") ?? GetJsonNodeProperty(obj, "DurationMs") ?? GetJsonNodeProperty(obj, "benchmarkDurationMs"), 0) > 0 ||
            JsonNodeInt(GetJsonNodeProperty(obj, "rating") ?? GetJsonNodeProperty(obj, "Rating") ?? GetJsonNodeProperty(obj, "benchmarkRating") ?? GetJsonNodeProperty(obj, "BenchmarkRating") ?? GetJsonNodeProperty(obj, "score") ?? GetJsonNodeProperty(obj, "Score"), 0) > 0 ||
            !string.IsNullOrWhiteSpace(JsonNodeText(GetJsonNodeProperty(obj, "benchmarkedUtc") ?? GetJsonNodeProperty(obj, "BenchmarkedUtc")));
        return hasBenchmarkSignal && (!requireId || hasId);
    }

    private static bool JsonArrayLooksLikeBenchmarkArray(JsonArray array) {
        foreach (JsonNode? item in array) {
            if (item is JsonObject obj && LooksLikeBenchmarkObject(obj))
                return true;
        }

        return false;
    }

    private static bool TryGetJsonNodeProperty(JsonObject obj, string name, out JsonNode? value) {
        if (obj != null) {
            foreach (KeyValuePair<string, JsonNode?> property in obj) {
                if (string.Equals(property.Key, name, StringComparison.OrdinalIgnoreCase)) {
                    value = property.Value;
                    return true;
                }
            }
        }

        value = null;
        return false;
    }

    private static int CountBenchmarkItems(string modelBenchmarksJson) {
        modelBenchmarksJson = NormalizeModelBenchmarksJsonText(modelBenchmarksJson);
        if (string.IsNullOrWhiteSpace(modelBenchmarksJson))
            return 0;
        try {
            JsonNode? node = JsonNode.Parse(modelBenchmarksJson);
            return node is JsonArray array ? array.Count : 0;
        } catch {
            return 0;
        }
    }

    private JsonObject BuildShellProxyJsonWebSocketError(
        ShellProxyJsonWebSocketState state,
        string requestId,
        int statusCode,
        string message,
        DateTimeOffset receivedUtc,
        RegisteredServer? registeredServer) {
        var output = new JsonObject {
            ["type"] = "snapshot",
            ["ok"] = false,
            ["requestId"] = requestId,
            ["socketJackTransport"] = "websocket",
            ["socketJackProxyRoute"] = state.RouteName,
            ["socketJackProxyPath"] = BuildShellProxyPath(state.RouteName),
            ["socketJackForwardedPath"] = state.ForwardedPath,
            ["socketJackReceivedUtc"] = receivedUtc.ToString("O", CultureInfo.InvariantCulture),
            ["socketJackSentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture),
            ["statusCode"] = statusCode,
            ["error"] = message
        };
        ApplyRegisteredLatencyFields(output, registeredServer);
        return output;
    }

    private RegisteredServer? FindRegisteredServerForShellRelay(MasterShellRelay relay) {
        if (relay == null || string.IsNullOrWhiteSpace(relay.ServerId))
            return null;
        lock (_sync) {
            int index = FindRowIndexLocked(relay.ServerId);
            return index >= 0 ? RowToServer(_table.Rows[index]).Clone() : null;
        }
    }

    private ShellProxyJsonFetchResult FetchShellProxyJsonForWebSocket(MasterShellRelay relay, string forwardedPath, string queryString, CancellationToken cancellationToken) {
        string query = string.IsNullOrWhiteSpace(queryString) ? "" : queryString.StartsWith("?", StringComparison.Ordinal) ? queryString : "?" + queryString;
        Uri upstreamUri = new("http://127.0.0.1:" + relay.PublicPort.ToString(CultureInfo.InvariantCulture) + forwardedPath + query);
        using var timeoutCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
        timeoutCts.CancelAfter(TimeSpan.FromMilliseconds(2500));
        using var upstreamRequest = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, upstreamUri);
        upstreamRequest.Headers.TryAddWithoutValidation("Accept", "application/json");
        upstreamRequest.Headers.ConnectionClose = true;
        Stopwatch stopwatch = Stopwatch.StartNew();
        using System.Net.Http.HttpResponseMessage upstreamResponse = ShellProxyHttpClient.Send(upstreamRequest, HttpCompletionOption.ResponseContentRead, timeoutCts.Token);
        string body = upstreamResponse.Content.ReadAsStringAsync(timeoutCts.Token).GetAwaiter().GetResult();
        stopwatch.Stop();
        string contentType = upstreamResponse.Content.Headers.ContentType?.ToString() ?? "application/json";
        string reason = string.IsNullOrWhiteSpace(upstreamResponse.ReasonPhrase)
            ? GetReasonPhrase((int)upstreamResponse.StatusCode)
            : upstreamResponse.ReasonPhrase!;
        return new ShellProxyJsonFetchResult((int)upstreamResponse.StatusCode, reason, contentType, body, ClampLatencyMilliseconds(stopwatch.Elapsed));
    }

    private static JsonObject ParseShellProxyJsonObject(string body) {
        if (string.IsNullOrWhiteSpace(body))
            return new JsonObject();
        try {
            JsonNode? node = JsonNode.Parse(body);
            if (node is JsonObject obj)
                return obj;
            return new JsonObject {
                ["ok"] = true,
                ["value"] = node
            };
        } catch {
            return new JsonObject {
                ["ok"] = false,
                ["detail"] = LimitWebSocketPreview(body, 500)
            };
        }
    }

    private static void ApplyRegisteredLatencyFields(JsonObject output, RegisteredServer? registeredServer) {
        if (registeredServer == null)
            return;
        if (registeredServer.InternetLatencyMs > 0)
            output["internetLatencyMs"] = registeredServer.InternetLatencyMs;
        if (registeredServer.ProxyLatencyMs > 0)
            output["registeredProxyLatencyMs"] = registeredServer.ProxyLatencyMs;
    }

    private void UpdateRegisteredServerFromShellProxyJson(
        MasterShellRelay relay,
        RegisteredServer? registeredServer,
        JsonObject output,
        int statusCode,
        int durationMs,
        DateTimeOffset checkedUtc) {
        if (relay == null || string.IsNullOrWhiteSpace(relay.ServerId) || output == null)
            return;

        bool ok = statusCode >= 200 && statusCode < 300 && JsonNodeIsTruthy(output["ok"], true);
        string json = output.ToJsonString(MasterListJson.Options);
        ModelRuntimeHealthInfo runtime = ReadModelRuntimeHealth(json, registeredServer ?? new RegisteredServer());
        bool pong = TryReadMasterListPong(json);
        bool hostResponding = ok && (pong || statusCode < 500);
        int latencyMs = Math.Max(1, durationMs);
        string status = hostResponding
            ? runtime.HasValue && runtime.Connected
                ? "Online - " + runtime.Provider + " connected"
                : runtime.HasValue
                    ? "Online - " + RegisteredServer.FirstNonEmpty(runtime.Provider, "model runtime") + " " + RegisteredServer.FirstNonEmpty(runtime.Status, "reachable").ToLowerInvariant()
                    : "Online - JackLLM reachable"
            : "Offline - browser health returned HTTP " + statusCode.ToString(CultureInfo.InvariantCulture);

        lock (_sync) {
            int index = FindRowIndexLocked(relay.ServerId);
            if (index < 0)
                return;

            object[] row = _table.Rows[index];
            RegisteredServer server = RowToServer(row);
            bool visible = !server.WebsiteHidden;
            SetCellIfChanged(row, nameof(RegisteredServer.IsOnline), visible && hostResponding ? "true" : "false");
            SetCellIfChanged(row, nameof(RegisteredServer.HostResponding), visible && hostResponding ? "true" : "false");
            SetCellIfChanged(row, nameof(RegisteredServer.LmStudioConnected), visible && runtime.HasValue && runtime.LmStudioConnected ? "true" : "false");
            SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeProvider), runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.Provider, server.ModelRuntimeProvider, "Model runtime") : RegisteredServer.FirstNonEmpty(server.ModelRuntimeProvider, "Model runtime"));
            SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeConnected), visible && runtime.HasValue && runtime.Connected ? "true" : "false");
            SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeStatus), visible ? (runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.Status, status) : status) : "Hidden from website");
            SetCellIfChanged(row, nameof(RegisteredServer.LlmRuntimeConnected), visible && runtime.HasValue && runtime.LlmRuntimeConnected ? "true" : "false");
            SetCellIfChanged(row, nameof(RegisteredServer.LlmRuntimeStatus), visible ? (runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.LlmRuntimeStatus, runtime.LlmRuntimeConnected ? "Connected" : "Not selected") : server.LlmRuntimeStatus) : "Hidden from website");
            if (visible && runtime.HasValue) {
                string availableModels = RegisteredServer.FirstNonEmpty(runtime.AvailableModels, runtime.ActiveModel);
                if (!string.IsNullOrWhiteSpace(availableModels))
                    SetCellIfChanged(row, nameof(RegisteredServer.AvailableModels), availableModels);
                if (!string.IsNullOrWhiteSpace(runtime.ModelInventoryJson))
                    SetCellIfChanged(row, nameof(RegisteredServer.ModelCapabilitiesJson), runtime.ModelInventoryJson);
                if (!string.IsNullOrWhiteSpace(runtime.ModelBenchmarksJson))
                    SetCellIfChanged(row, nameof(RegisteredServer.ModelBenchmarksJson), runtime.ModelBenchmarksJson);
            }
            SetCellIfChanged(row, nameof(RegisteredServer.InternetLatencyMs), visible && latencyMs > 0 ? latencyMs.ToString(CultureInfo.InvariantCulture) : "");
            SetCellIfChanged(row, nameof(RegisteredServer.ProxyLatencyMs), "");
            SetCellIfChanged(row, nameof(RegisteredServer.StatusText), visible ? status : "Hidden from website");
            SetCellIfChanged(row, nameof(RegisteredServer.LastStatus), visible ? status : "Hidden from website");
            SetCellIfChanged(row, nameof(RegisteredServer.UpdatedUtc), checkedUtc.ToString("O", CultureInfo.InvariantCulture));
            if (visible && hostResponding)
                SetCellIfChanged(row, nameof(RegisteredServer.LastSeenUtc), checkedUtc.ToString("O", CultureInfo.InvariantCulture));

            var snapshot = new ServerHealthSnapshot(visible && hostResponding, visible && hostResponding, visible && runtime.HasValue && runtime.LmStudioConnected, visible ? status : "Hidden from website", checkedUtc) {
                ModelRuntimeProvider = runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.Provider, server.ModelRuntimeProvider, "Model runtime") : RegisteredServer.FirstNonEmpty(server.ModelRuntimeProvider, "Model runtime"),
                ModelRuntimeConnected = visible && runtime.HasValue && runtime.Connected,
                ModelRuntimeStatus = visible ? (runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.Status, status) : status) : "Hidden from website",
                LlmRuntimeConnected = visible && runtime.HasValue && runtime.LlmRuntimeConnected,
                LlmRuntimeStatus = visible ? (runtime.HasValue ? RegisteredServer.FirstNonEmpty(runtime.LlmRuntimeStatus, runtime.LlmRuntimeConnected ? "Connected" : "Not selected") : server.LlmRuntimeStatus) : "Hidden from website",
                InternetLatencyMs = visible ? latencyMs : 0,
                ProxyLatencyMs = 0
            };
            _healthCache[relay.ServerId] = snapshot;
        }
    }

    private static bool JsonNodeIsTruthy(JsonNode? node, bool fallback) {
        if (node == null)
            return fallback;
        if (node is JsonValue value) {
            if (value.TryGetValue(out bool boolean))
                return boolean;
            if (value.TryGetValue(out int integer))
                return integer > 0;
            if (value.TryGetValue(out double number))
                return number > 0;
            if (value.TryGetValue(out string? text))
                return !string.IsNullOrWhiteSpace(text) &&
                       !text.Equals("false", StringComparison.OrdinalIgnoreCase) &&
                       !text.Equals("0", StringComparison.OrdinalIgnoreCase) &&
                       !text.Equals("no", StringComparison.OrdinalIgnoreCase) &&
                       !text.Equals("none", StringComparison.OrdinalIgnoreCase);
        }

        return fallback;
    }

    private static string JsonText(JsonObject? obj, string name, string fallback) {
        if (obj == null || !obj.TryGetPropertyValue(name, out JsonNode? value) || value == null)
            return fallback;
        return value.ToString();
    }

    private static string LimitWebSocketPreview(string value, int maxLength) {
        value = value ?? "";
        if (value.Length <= maxLength)
            return value;
        return value.Substring(0, Math.Max(0, maxLength)) + "...";
    }

