    private sealed class ShellProxyWebSocketTunnelManager {
        private static readonly TimeSpan ResponseStartTimeout = TimeSpan.FromSeconds(20);
        private static readonly TimeSpan ResponseCompleteTimeout = TimeSpan.FromSeconds(70);
        private static readonly TimeSpan TunnelFreshnessWindow = TimeSpan.FromSeconds(60);
        private readonly MasterListServerHost _host;
        private readonly ConcurrentDictionary<Guid, ShellProxyTunnelConnection> _connections = new();
        private readonly ConcurrentDictionary<string, ConcurrentDictionary<Guid, ShellProxyTunnelConnection>> _connectionsByRelay = new(StringComparer.OrdinalIgnoreCase);
        private readonly ConcurrentDictionary<string, string> _lastSeenUtcByRelay = new(StringComparer.OrdinalIgnoreCase);

        public ShellProxyWebSocketTunnelManager(MasterListServerHost host) {
            _host = host;
        }

        public bool HasConnectedTunnel(string relayId) {
            return GetConnectedCount(relayId) > 0;
        }

        public int GetConnectedCount(string relayId) {
            if (string.IsNullOrWhiteSpace(relayId) || !_connectionsByRelay.TryGetValue(relayId, out ConcurrentDictionary<Guid, ShellProxyTunnelConnection>? map))
                return 0;
            int count = 0;
            foreach (ShellProxyTunnelConnection tunnel in map.Values) {
                if (IsFreshTunnel(tunnel))
                    count++;
            }
            return count;
        }

        public string GetLastSeenUtc(string relayId) {
            return !string.IsNullOrWhiteSpace(relayId) && _lastSeenUtcByRelay.TryGetValue(relayId, out string? value) ? value : "";
        }

        public void RegisterHello(NetworkConnection connection, string relayId, JsonObject hello) {
            string ownerToken = JsonText(hello, "ownerToken", JsonText(hello, "serverOwnerToken", ""));
            if (!TryAuthorizeTunnel(relayId, ownerToken, out MasterShellRelay? relay, out string error)) {
                SendJson(connection, new JsonObject {
                    ["type"] = "ready",
                    ["ok"] = false,
                    ["error"] = error
                });
                return;
            }
            if (relay == null)
                return;

            var tunnel = new ShellProxyTunnelConnection(relay.Id, connection);
            tunnel.IsReady = true;
            tunnel.LastSeenUtc = DateTimeOffset.UtcNow;
            _connections[connection.ID] = tunnel;
            var relayMap = _connectionsByRelay.GetOrAdd(relay.Id, _ => new ConcurrentDictionary<Guid, ShellProxyTunnelConnection>());
            relayMap[connection.ID] = tunnel;
            NoteTunnelSeen(relay.Id, tunnel.LastSeenUtc);
            _host.AppendShellRelayRuntimeLog(relay.Id, "WebSocket tunnel connected.");
            SendJson(connection, new JsonObject {
                ["type"] = "ready",
                ["ok"] = true,
                ["relayId"] = relay.Id,
                ["transportMode"] = "websocket",
                ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });
        }

        public void Unregister(Guid connectionId) {
            if (!_connections.TryRemove(connectionId, out ShellProxyTunnelConnection? tunnel))
                return;
            tunnel.IsReady = false;
            foreach (PendingTunnelRequest pending in tunnel.Pending.Values.ToList())
                pending.Fail(new IOException("WebSocket tunnel disconnected."));
            if (_connectionsByRelay.TryGetValue(tunnel.RelayId, out ConcurrentDictionary<Guid, ShellProxyTunnelConnection>? map)) {
                map.TryRemove(connectionId, out _);
                if (map.IsEmpty)
                    _connectionsByRelay.TryRemove(tunnel.RelayId, out _);
            }
            NoteTunnelSeen(tunnel.RelayId, DateTimeOffset.UtcNow);
            _host.AppendShellRelayRuntimeLog(tunnel.RelayId, "WebSocket tunnel disconnected.");
        }

        public void HandleText(Guid connectionId, JsonObject message) {
            string type = JsonText(message, "type", "");
            if (type.Equals("hello", StringComparison.OrdinalIgnoreCase))
                return;

            if (!_connections.TryGetValue(connectionId, out ShellProxyTunnelConnection? tunnel))
                return;
            tunnel.LastSeenUtc = DateTimeOffset.UtcNow;
            NoteTunnelSeen(tunnel.RelayId, tunnel.LastSeenUtc);

            if (type.Equals("heartbeat", StringComparison.OrdinalIgnoreCase)) {
                SendJson(tunnel.Connection, new JsonObject {
                    ["type"] = "heartbeat",
                    ["ok"] = true,
                    ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                }, tunnel.SendLock);
                return;
            }

            string requestId = JsonText(message, "id", JsonText(message, "requestId", ""));
            if (string.IsNullOrWhiteSpace(requestId) || !tunnel.Pending.TryGetValue(requestId, out PendingTunnelRequest? pending))
                return;

            if (type.Equals("response-start", StringComparison.OrdinalIgnoreCase)) {
                pending.SetResponseStart(TunnelResponseStart.FromJson(message));
            } else if (type.Equals("response-end", StringComparison.OrdinalIgnoreCase)) {
                pending.SetLocalDuration(JsonInt(message, "durationMs", 0));
                pending.Complete();
                tunnel.Pending.TryRemove(requestId, out _);
            } else if (type.Equals("error", StringComparison.OrdinalIgnoreCase)) {
                pending.Fail(new IOException(JsonText(message, "error", "WebSocket tunnel returned an error.")));
                tunnel.Pending.TryRemove(requestId, out _);
            }
        }

        public void HandleText(NetworkConnection connection, JsonObject message) {
            string type = JsonText(message, "type", "");
            if (type.Equals("hello", StringComparison.OrdinalIgnoreCase)) {
                RegisterHello(connection, JsonText(message, "relayId", ""), message);
                return;
            }
            HandleText(connection.ID, message);
        }

        public void HandleBinary(Guid connectionId, byte[] payload) {
            if (payload == null || payload.Length <= 32 || !_connections.TryGetValue(connectionId, out ShellProxyTunnelConnection? tunnel))
                return;
            string requestId = Encoding.ASCII.GetString(payload, 0, 32);
            if (!tunnel.Pending.TryGetValue(requestId, out PendingTunnelRequest? pending))
                return;
            tunnel.LastSeenUtc = DateTimeOffset.UtcNow;
            NoteTunnelSeen(tunnel.RelayId, tunnel.LastSeenUtc);
            byte[] chunk = new byte[payload.Length - 32];
            Buffer.BlockCopy(payload, 32, chunk, 0, chunk.Length);
            pending.AddBodyChunk(chunk);
        }

        public void Forward(HttpRequest request, MasterShellRelay relay, string forwardedPath, CancellationToken cancellationToken, string? proxyPathOverride = null) {
            if (!TryGetTunnel(relay.Id, out ShellProxyTunnelConnection? tunnel))
                throw new InvalidOperationException("No WebSocket tunnel is connected.");
            if (tunnel == null)
                throw new InvalidOperationException("No WebSocket tunnel is connected.");

            bool requestStreaming = IsShellProxyStreamingRequest(request, forwardedPath);
            using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, requestStreaming);
            CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
            string requestId = Guid.NewGuid().ToString("N");
            var pending = new PendingTunnelRequest(requestId, requestStreaming, forwardedPath);
            if (!tunnel.Pending.TryAdd(requestId, pending))
                throw new InvalidOperationException("WebSocket tunnel request id collision.");

            Stopwatch total = Stopwatch.StartNew();
            try {
                JsonObject envelope = BuildRequestEnvelope(requestId, request, forwardedPath, requestStreaming);
                Stopwatch sendWatch = Stopwatch.StartNew();
                SendJson(tunnel.Connection, envelope, tunnel.SendLock);
                sendWatch.Stop();
                pending.WebSocketSendMs = ClampLatencyMilliseconds(sendWatch.Elapsed);

                TunnelResponseStart start = pending.WaitForStart(ResponseStartTimeout, effectiveCancellation);
                string contentType = FirstNonEmpty(start.ContentType, HeaderValue(start.Headers, "Content-Type"), "application/octet-stream");
                if (requestStreaming || IsShellProxyStreamingResponse(contentType, forwardedPath)) {
                    StreamTunnelResponse(request, relay, pending, start, contentType, effectiveCancellation, total);
                    return;
                }

                pending.WaitForCompletion(ResponseCompleteTimeout, effectiveCancellation);
                byte[] body = pending.GetBufferedBody();
                string proxyPath = string.IsNullOrWhiteSpace(proxyPathOverride)
                    ? _host.BuildShellProxyPath(relay.RouteName).TrimEnd('/')
                    : proxyPathOverride.TrimEnd('/');
                bool rewritten = false;
                if (IsShellProxyModelsApiPath(forwardedPath)) {
                    body = RewriteShellProxyModelsApiResponse(body);
                    rewritten = true;
                } else if (IsHtmlContentType(contentType) && !IsShellProxyBrowserProxyPath(forwardedPath)) {
                    body = RewriteShellProxyHtml(body, proxyPath);
                    rewritten = true;
                }

                HttpResponse response = request.Context.Response;
                request.Context.StatusCodeNumber = start.StatusCode;
                request.Context.ReasonPhrase = FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode));
                response.ContentType = contentType;
                response.BodyBytes = request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase) ? Array.Empty<byte>() : body;
                CopyTunnelHeaders(response.Headers, start.Headers, rewritten, proxyPath);
                ApplyTunnelTimingHeaders(response.Headers, pending, total);
                AddCors(request);
            } finally {
                tunnel.Pending.TryRemove(requestId, out _);
                if (effectiveCancellation.IsCancellationRequested)
                    TrySendCancel(tunnel, requestId);
            }
        }

        public ShellProxyJsonFetchResult FetchJson(MasterShellRelay relay, string forwardedPath, string queryString, CancellationToken cancellationToken) {
            if (relay == null)
                throw new ArgumentNullException(nameof(relay));
            if (!TryGetTunnel(relay.Id, out ShellProxyTunnelConnection? tunnel))
                throw new InvalidOperationException("No WebSocket tunnel is connected.");
            if (tunnel == null)
                throw new InvalidOperationException("No WebSocket tunnel is connected.");

            using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, false);
            CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
            string requestId = Guid.NewGuid().ToString("N");
            var pending = new PendingTunnelRequest(requestId, requestStreaming: false, forwardedPath);
            if (!tunnel.Pending.TryAdd(requestId, pending))
                throw new InvalidOperationException("WebSocket tunnel request id collision.");

            Stopwatch total = Stopwatch.StartNew();
            try {
                JsonObject envelope = BuildJsonFetchEnvelope(requestId, forwardedPath, queryString);
                Stopwatch sendWatch = Stopwatch.StartNew();
                SendJson(tunnel.Connection, envelope, tunnel.SendLock);
                sendWatch.Stop();
                pending.WebSocketSendMs = ClampLatencyMilliseconds(sendWatch.Elapsed);

                TunnelResponseStart start = pending.WaitForStart(ResponseStartTimeout, effectiveCancellation);
                pending.WaitForCompletion(ResponseCompleteTimeout, effectiveCancellation);
                byte[] bodyBytes = pending.GetBufferedBody();
                total.Stop();

                string body = bodyBytes.Length == 0 ? "" : Encoding.UTF8.GetString(bodyBytes);
                string contentType = FirstNonEmpty(start.ContentType, HeaderValue(start.Headers, "Content-Type"), "application/json");
                string reason = FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode));
                return new ShellProxyJsonFetchResult(start.StatusCode, reason, contentType, body, ClampLatencyMilliseconds(total.Elapsed));
            } finally {
                tunnel.Pending.TryRemove(requestId, out _);
                if (effectiveCancellation.IsCancellationRequested)
                    TrySendCancel(tunnel, requestId);
            }
        }

        public ShellProxyFetchResult FetchRequest(
            MasterShellRelay relay,
            string method,
            string forwardedPath,
            string queryString,
            IReadOnlyDictionary<string, string>? requestHeaders,
            byte[] bodyBytes,
            CancellationToken cancellationToken) {
            if (relay == null)
                throw new ArgumentNullException(nameof(relay));
            if (!TryGetTunnel(relay.Id, out ShellProxyTunnelConnection? tunnel))
                throw new InvalidOperationException("No WebSocket tunnel is connected.");
            if (tunnel == null)
                throw new InvalidOperationException("No WebSocket tunnel is connected.");

            bool requestStreaming = forwardedPath.Equals("/api/chat-stream", StringComparison.OrdinalIgnoreCase);
            using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, requestStreaming);
            CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
            string requestId = Guid.NewGuid().ToString("N");
            var pending = new PendingTunnelRequest(requestId, requestStreaming, forwardedPath);
            if (!tunnel.Pending.TryAdd(requestId, pending))
                throw new InvalidOperationException("WebSocket tunnel request id collision.");

            Stopwatch total = Stopwatch.StartNew();
            try {
                JsonObject envelope = BuildFetchRequestEnvelope(requestId, method, forwardedPath, queryString, requestHeaders, bodyBytes, requestStreaming);
                Stopwatch sendWatch = Stopwatch.StartNew();
                SendJson(tunnel.Connection, envelope, tunnel.SendLock);
                sendWatch.Stop();
                pending.WebSocketSendMs = ClampLatencyMilliseconds(sendWatch.Elapsed);

                TunnelResponseStart start = pending.WaitForStart(ResponseStartTimeout, effectiveCancellation);
                string contentType = FirstNonEmpty(start.ContentType, HeaderValue(start.Headers, "Content-Type"), "application/octet-stream");
                byte[] body;
                if (pending.Streaming || IsShellProxyStreamingResponse(contentType, forwardedPath)) {
                    using var stream = new MemoryStream();
                    foreach (byte[] chunk in pending.GetStreamingChunks(effectiveCancellation)) {
                        if (chunk.Length > 0)
                            stream.Write(chunk, 0, chunk.Length);
                    }
                    body = stream.ToArray();
                } else {
                    pending.WaitForCompletion(ResponseCompleteTimeout, effectiveCancellation);
                    body = pending.GetBufferedBody();
                }

                total.Stop();
                string reason = FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode));
                return new ShellProxyFetchResult(start.StatusCode, reason, contentType, body, start.Headers, ClampLatencyMilliseconds(total.Elapsed));
            } finally {
                tunnel.Pending.TryRemove(requestId, out _);
                if (effectiveCancellation.IsCancellationRequested)
                    TrySendCancel(tunnel, requestId);
            }
        }

        public void StreamRequest(
            HttpRequest request,
            MasterShellRelay relay,
            string method,
            string forwardedPath,
            string queryString,
            IReadOnlyDictionary<string, string>? requestHeaders,
            byte[] bodyBytes,
            IReadOnlyDictionary<string, string>? extraResponseHeaders,
            CancellationToken cancellationToken) {
            if (relay == null)
                throw new ArgumentNullException(nameof(relay));
            if (!TryGetTunnel(relay.Id, out ShellProxyTunnelConnection? tunnel))
                throw new InvalidOperationException("No WebSocket tunnel is connected.");
            if (tunnel == null)
                throw new InvalidOperationException("No WebSocket tunnel is connected.");

            using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, true);
            CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
            string requestId = Guid.NewGuid().ToString("N");
            var pending = new PendingTunnelRequest(requestId, requestStreaming: true, forwardedPath);
            if (!tunnel.Pending.TryAdd(requestId, pending))
                throw new InvalidOperationException("WebSocket tunnel request id collision.");

            Stopwatch total = Stopwatch.StartNew();
            try {
                JsonObject envelope = BuildFetchRequestEnvelope(requestId, method, forwardedPath, queryString, requestHeaders, bodyBytes, requestStreaming: true);
                Stopwatch sendWatch = Stopwatch.StartNew();
                SendJson(tunnel.Connection, envelope, tunnel.SendLock);
                sendWatch.Stop();
                pending.WebSocketSendMs = ClampLatencyMilliseconds(sendWatch.Elapsed);

                TunnelResponseStart start = pending.WaitForStart(ResponseStartTimeout, effectiveCancellation);
                string contentType = FirstNonEmpty(start.ContentType, HeaderValue(start.Headers, "Content-Type"), "application/octet-stream");
                StreamTunnelResponse(request, relay, pending, start, contentType, effectiveCancellation, total, extraResponseHeaders);
            } finally {
                tunnel.Pending.TryRemove(requestId, out _);
                if (effectiveCancellation.IsCancellationRequested)
                    TrySendCancel(tunnel, requestId);
            }
        }

        private static JsonObject BuildFetchRequestEnvelope(
            string requestId,
            string method,
            string forwardedPath,
            string queryString,
            IReadOnlyDictionary<string, string>? requestHeaders,
            byte[] bodyBytes,
            bool requestStreaming) {
            var headers = new JsonObject();
            if (requestHeaders != null) {
                foreach (KeyValuePair<string, string> header in requestHeaders) {
                    if (!ShouldSkipProxyRequestHeader(header.Key))
                        headers[header.Key] = header.Value;
                }
            }
            if ((bodyBytes?.Length ?? 0) > 0 && !headers.ContainsKey("Content-Type"))
                headers["Content-Type"] = "application/json";

            return new JsonObject {
                ["type"] = "request",
                ["id"] = requestId,
                ["method"] = string.IsNullOrWhiteSpace(method) ? "GET" : method,
                ["path"] = string.IsNullOrWhiteSpace(forwardedPath) ? "/" : forwardedPath,
                ["queryString"] = queryString ?? "",
                ["headers"] = headers,
                ["bodyBase64"] = bodyBytes == null || bodyBytes.Length == 0 ? "" : Convert.ToBase64String(bodyBytes),
                ["streaming"] = requestStreaming,
                ["requestedUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        }

        public void ForwardWebChatRequest(MasterShellRelay relay, JsonObject browserMessage, Action<JsonObject> sendText, Action<byte[]> sendBinary, CancellationToken cancellationToken) {
            if (relay == null)
                throw new ArgumentNullException(nameof(relay));
            if (browserMessage == null)
                throw new ArgumentNullException(nameof(browserMessage));
            if (!TryGetTunnel(relay.Id, out ShellProxyTunnelConnection? tunnel))
                throw new InvalidOperationException("No WebSocket tunnel is connected.");
            if (tunnel == null)
                throw new InvalidOperationException("No WebSocket tunnel is connected.");

            string browserRequestId = JsonText(browserMessage, "id", JsonText(browserMessage, "requestId", ""));
            if (string.IsNullOrWhiteSpace(browserRequestId))
                throw new InvalidOperationException("Browser WebSocket request id is required.");

            string forwardedPath = NormalizeForwardedWebChatPath(JsonText(browserMessage, "path", "/"));
            bool requestStreaming = JsonBool(browserMessage, "streaming", false) || IsShellProxyStreamingResponse("", forwardedPath);
            using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, requestStreaming);
            CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
            string tunnelRequestId = Guid.NewGuid().ToString("N");
            var pending = new PendingTunnelRequest(tunnelRequestId, requestStreaming, forwardedPath);
            if (!tunnel.Pending.TryAdd(tunnelRequestId, pending))
                throw new InvalidOperationException("WebSocket tunnel request id collision.");

            Stopwatch total = Stopwatch.StartNew();
            try {
                JsonObject envelope = BuildWebChatTunnelEnvelope(tunnelRequestId, browserMessage, forwardedPath, requestStreaming);
                Stopwatch sendWatch = Stopwatch.StartNew();
                SendJson(tunnel.Connection, envelope, tunnel.SendLock);
                sendWatch.Stop();
                pending.WebSocketSendMs = ClampLatencyMilliseconds(sendWatch.Elapsed);

                TunnelResponseStart start = pending.WaitForStart(ResponseStartTimeout, effectiveCancellation);
                string contentType = FirstNonEmpty(start.ContentType, HeaderValue(start.Headers, "Content-Type"), "application/octet-stream");
                SendWebChatResponseStart(sendText, browserRequestId, start, contentType);

                if (requestStreaming || IsShellProxyStreamingResponse(contentType, forwardedPath)) {
                    foreach (byte[] chunk in pending.GetStreamingChunks(effectiveCancellation)) {
                        if (chunk.Length > 0)
                            sendBinary(PrefixWebChatBinaryChunk(browserRequestId, chunk));
                    }
                } else {
                    pending.WaitForCompletion(ResponseCompleteTimeout, effectiveCancellation);
                    byte[] body = pending.GetBufferedBody();
                    if (body.Length > 0)
                        sendBinary(PrefixWebChatBinaryChunk(browserRequestId, body));
                }

                sendText(new JsonObject {
                    ["type"] = "response-end",
                    ["id"] = browserRequestId,
                    ["statusCode"] = start.StatusCode,
                    ["durationMs"] = ClampLatencyMilliseconds(total.Elapsed),
                    ["serverTiming"] = BuildServerTimingHeader(pending, total)
                });
            } finally {
                tunnel.Pending.TryRemove(tunnelRequestId, out _);
                if (effectiveCancellation.IsCancellationRequested)
                    TrySendCancel(tunnel, tunnelRequestId);
            }
        }

        private static JsonObject BuildWebChatTunnelEnvelope(string tunnelRequestId, JsonObject browserMessage, string forwardedPath, bool requestStreaming) {
            var headers = new JsonObject();
            if (browserMessage.TryGetPropertyValue("headers", out JsonNode? headersNode) && headersNode is JsonObject browserHeaders) {
                foreach (KeyValuePair<string, JsonNode?> header in browserHeaders) {
                    if (!ShouldSkipProxyRequestHeader(header.Key))
                        headers[header.Key] = header.Value?.ToString() ?? "";
                }
            }

            return new JsonObject {
                ["type"] = "request",
                ["id"] = tunnelRequestId,
                ["method"] = JsonText(browserMessage, "method", "GET"),
                ["path"] = forwardedPath,
                ["queryString"] = JsonText(browserMessage, "queryString", ""),
                ["headers"] = headers,
                ["bodyBase64"] = JsonText(browserMessage, "bodyBase64", ""),
                ["streaming"] = requestStreaming,
                ["requestedUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        }

        private static void SendWebChatResponseStart(Action<JsonObject> sendText, string browserRequestId, TunnelResponseStart start, string contentType) {
            var headers = new JsonObject();
            foreach (KeyValuePair<string, string> header in start.Headers) {
                if (!ShouldSkipProxyResponseHeader(header.Key, rewritten: false))
                    headers[header.Key] = header.Value;
            }
            if (!headers.ContainsKey("Content-Type"))
                headers["Content-Type"] = contentType;

            sendText(new JsonObject {
                ["type"] = "response-start",
                ["id"] = browserRequestId,
                ["statusCode"] = start.StatusCode,
                ["reasonPhrase"] = FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode)),
                ["contentType"] = contentType,
                ["headers"] = headers
            });
        }

        private static byte[] PrefixWebChatBinaryChunk(string browserRequestId, byte[] chunk) {
            byte[] idBytes = Encoding.ASCII.GetBytes(FixedWebChatRequestId(browserRequestId));
            byte[] payload = new byte[32 + (chunk?.Length ?? 0)];
            Buffer.BlockCopy(idBytes, 0, payload, 0, 32);
            if (chunk != null && chunk.Length > 0)
                Buffer.BlockCopy(chunk, 0, payload, 32, chunk.Length);
            return payload;
        }

        private static string FixedWebChatRequestId(string requestId) {
            requestId = (requestId ?? "").Trim();
            if (requestId.Length > 32)
                return requestId.Substring(0, 32);
            return requestId.PadRight(32, ' ');
        }

        private static string NormalizeForwardedWebChatPath(string path) {
            if (string.IsNullOrWhiteSpace(path))
                return "/";
            path = path.Trim();
            return path.StartsWith("/", StringComparison.Ordinal) ? path : "/" + path;
        }

        private JsonObject BuildRequestEnvelope(string requestId, HttpRequest request, string forwardedPath, bool requestStreaming) {
            var headers = new JsonObject();
            foreach (KeyValuePair<string, string> header in request.Headers) {
                if (!ShouldSkipProxyRequestHeader(header.Key))
                    headers[header.Key] = header.Value;
            }

            return new JsonObject {
                ["type"] = "request",
                ["id"] = requestId,
                ["method"] = request.Method ?? "GET",
                ["path"] = string.IsNullOrWhiteSpace(forwardedPath) ? "/" : forwardedPath,
                ["queryString"] = request.QueryString ?? "",
                ["headers"] = headers,
                ["bodyBase64"] = request.BodyBytes == null || request.BodyBytes.Length == 0 ? "" : Convert.ToBase64String(request.BodyBytes),
                ["streaming"] = requestStreaming,
                ["requestedUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        }

        private static JsonObject BuildJsonFetchEnvelope(string requestId, string forwardedPath, string queryString) {
            return new JsonObject {
                ["type"] = "request",
                ["id"] = requestId,
                ["method"] = "GET",
                ["path"] = string.IsNullOrWhiteSpace(forwardedPath) ? "/" : forwardedPath,
                ["queryString"] = queryString ?? "",
                ["headers"] = new JsonObject {
                    ["Accept"] = "application/json"
                },
                ["bodyBase64"] = "",
                ["streaming"] = false,
                ["requestedUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        }

        private void StreamTunnelResponse(HttpRequest request, MasterShellRelay relay, PendingTunnelRequest pending, TunnelResponseStart start, string contentType, CancellationToken cancellationToken, Stopwatch total, IReadOnlyDictionary<string, string>? extraHeaders = null) {
            HttpResponse response = request.Context.Response;
            request.Context.StatusCodeNumber = start.StatusCode;
            request.Context.ReasonPhrase = FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode));
            response.ContentType = contentType;
            response.RawResponseWritten = true;

            Stream? output = request.Context.Connection?.Stream;
            if (output == null)
                return;

            WriteTunnelStreamingHeaders(output, request, start, contentType, pending, total, extraHeaders);
            if (!request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase)) {
                foreach (byte[] chunk in pending.GetStreamingChunks(cancellationToken)) {
                    if (chunk.Length > 0)
                        WriteHttpChunk(output, chunk, chunk.Length);
                }
            }

            byte[] trailer = Encoding.ASCII.GetBytes("0\r\n\r\n");
            output.Write(trailer, 0, trailer.Length);
            output.Flush();
        }

        private static void WriteTunnelStreamingHeaders(Stream output, HttpRequest request, TunnelResponseStart start, string contentType, PendingTunnelRequest pending, Stopwatch total, IReadOnlyDictionary<string, string>? extraHeaders = null) {
            var headerBuilder = new StringBuilder();
            headerBuilder.Append(request.Version).Append(' ')
                .Append(start.StatusCode.ToString(CultureInfo.InvariantCulture))
                .Append(' ')
                .Append(FirstNonEmpty(start.ReasonPhrase, GetReasonPhrase(start.StatusCode)))
                .Append("\r\n");

            bool wroteContentType = false;
            foreach (KeyValuePair<string, string> header in start.Headers) {
                if (ShouldSkipStreamingProxyHeader(header.Key))
                    continue;
                if (header.Key.Equals("Content-Type", StringComparison.OrdinalIgnoreCase))
                    wroteContentType = true;
                headerBuilder.Append(header.Key).Append(": ").Append(header.Value).Append("\r\n");
            }
            if (!wroteContentType)
                headerBuilder.Append("Content-Type: ").Append(string.IsNullOrWhiteSpace(contentType) ? "application/octet-stream" : contentType).Append("\r\n");
            AppendExtraStreamingHeaders(headerBuilder, extraHeaders);
            headerBuilder.Append("Transfer-Encoding: chunked\r\n");
            headerBuilder.Append("Connection: close\r\n");
            headerBuilder.Append("Cache-Control: no-cache, no-store\r\n");
            headerBuilder.Append("Access-Control-Allow-Origin: *\r\n");
            headerBuilder.Append("Server-Timing: ").Append(BuildServerTimingHeader(pending, total)).Append("\r\n");
            headerBuilder.Append("\r\n");

            byte[] headerBytes = Encoding.UTF8.GetBytes(headerBuilder.ToString());
            output.Write(headerBytes, 0, headerBytes.Length);
            output.Flush();
        }

        private static void AppendExtraStreamingHeaders(StringBuilder target, IReadOnlyDictionary<string, string>? headers) {
            if (headers == null)
                return;
            foreach (KeyValuePair<string, string> header in headers) {
                if (string.IsNullOrWhiteSpace(header.Key) || ShouldSkipStreamingProxyHeader(header.Key))
                    continue;
                target.Append(header.Key).Append(": ").Append(header.Value ?? "").Append("\r\n");
            }
        }

        private static void CopyTunnelHeaders(Dictionary<string, string> target, Dictionary<string, string> headers, bool rewritten, string proxyPath) {
            foreach (KeyValuePair<string, string> header in headers) {
                if (ShouldSkipProxyResponseHeader(header.Key, rewritten))
                    continue;
                string value = header.Value ?? "";
                if (header.Key.Equals("Location", StringComparison.OrdinalIgnoreCase) && value.StartsWith("/", StringComparison.Ordinal))
                    value = proxyPath + value;
                target[header.Key] = value;
            }
        }

        private static void ApplyTunnelTimingHeaders(Dictionary<string, string> headers, PendingTunnelRequest pending, Stopwatch total) {
            headers["Server-Timing"] = BuildServerTimingHeader(pending, total);
        }

        private static string BuildServerTimingHeader(PendingTunnelRequest pending, Stopwatch total) {
            int totalMs = ClampLatencyMilliseconds(total.Elapsed);
            return "sj-tunnel-wait;dur=" + pending.ResponseStartWaitMs.ToString(CultureInfo.InvariantCulture) +
                   ", sj-ws-send;dur=" + pending.WebSocketSendMs.ToString(CultureInfo.InvariantCulture) +
                   ", sj-local;dur=" + pending.LocalDurationMs.ToString(CultureInfo.InvariantCulture) +
                   ", sj-first-byte;dur=" + pending.FirstByteMs.ToString(CultureInfo.InvariantCulture) +
                   ", sj-total;dur=" + totalMs.ToString(CultureInfo.InvariantCulture);
        }

        private bool TryGetTunnel(string relayId, out ShellProxyTunnelConnection? tunnel) {
            tunnel = null;
            if (string.IsNullOrWhiteSpace(relayId) || !_connectionsByRelay.TryGetValue(relayId, out ConcurrentDictionary<Guid, ShellProxyTunnelConnection>? map))
                return false;
            tunnel = map.Values
                .Where(IsFreshTunnel)
                .OrderByDescending(candidate => candidate.LastSeenUtc)
                .FirstOrDefault();
            return tunnel != null;
        }

        private static bool IsFreshTunnel(ShellProxyTunnelConnection tunnel) {
            return tunnel != null &&
                   tunnel.IsReady &&
                   tunnel.LastSeenUtc > DateTimeOffset.UtcNow.Subtract(TunnelFreshnessWindow);
        }

        private bool TryAuthorizeTunnel(string relayId, string ownerToken, out MasterShellRelay? relay, out string error) {
            relay = null;
            error = "";
            lock (_host._sync) {
                if (!_host._shellRelays.TryGetValue(relayId ?? "", out MasterShellRelay? candidate)) {
                    error = "Shell proxy relay was not found.";
                    return false;
                }
                candidate = _host.UpdateShellRelayRuntime(candidate);
                if (!candidate.Enabled) {
                    error = "Shell proxy relay is disabled.";
                    return false;
                }
                if (!string.IsNullOrWhiteSpace(candidate.OwnerTokenHash)) {
                    string providedHash = HashOwnerToken(ownerToken);
                    if (!FixedTimeEqualsText(candidate.OwnerTokenHash, providedHash)) {
                        error = "Shell proxy tunnel owner token was rejected.";
                        return false;
                    }
                }
                candidate.TransportMode = "websocketPreferred";
                candidate.SupportsWebSocketTunnel = true;
                candidate.FallbackTcpEnabled = true;
                candidate.LastTunnelSeenUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                relay = candidate.Clone();
                return true;
            }
        }

        private void NoteTunnelSeen(string relayId, DateTimeOffset seenUtc) {
            if (string.IsNullOrWhiteSpace(relayId))
                return;
            string text = seenUtc.ToUniversalTime().ToString("O", CultureInfo.InvariantCulture);
            _lastSeenUtcByRelay[relayId] = text;
            lock (_host._sync) {
                if (_host._shellRelays.TryGetValue(relayId, out MasterShellRelay? relay)) {
                    relay.LastTunnelSeenUtc = text;
                    relay.WebSocketTunnelCount = GetConnectedCount(relayId);
                    relay.WebSocketTunnelConnected = relay.WebSocketTunnelCount > 0;
                    relay.SupportsWebSocketTunnel = true;
                    relay.TransportMode = "websocketPreferred";
                }
            }
        }

        private static void TrySendCancel(ShellProxyTunnelConnection tunnel, string requestId) {
            try {
                SendJson(tunnel.Connection, new JsonObject {
                    ["type"] = "cancel",
                    ["id"] = requestId
                }, tunnel.SendLock);
            } catch {
            }
        }

        private static string HeaderValue(Dictionary<string, string> headers, string name) {
            return headers != null && headers.TryGetValue(name, out string? value) ? value ?? "" : "";
        }

        private static string JsonText(JsonObject? obj, string name, string fallback) {
            if (obj == null || !obj.TryGetPropertyValue(name, out JsonNode? value) || value == null)
                return fallback;
            return value.ToString();
        }

        private static int JsonInt(JsonObject? obj, string name, int fallback) {
            string text = JsonText(obj, name, "");
            return int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value) ? value : fallback;
        }

        private static bool JsonBool(JsonObject? obj, string name, bool fallback) {
            string text = JsonText(obj, name, "");
            return bool.TryParse(text, out bool value) ? value : fallback;
        }

        private static void SendJson(NetworkConnection connection, JsonObject payload, object? sendLock = null) {
            SendFrame(connection, Encoding.UTF8.GetBytes(payload.ToJsonString()), 0x81, sendLock);
        }

        private static void SendFrame(NetworkConnection connection, byte[] payload, byte opcode, object? sendLock = null) {
            byte[] frame = BuildWebSocketFrame(payload ?? Array.Empty<byte>(), opcode);
            object gate = sendLock ?? connection;
            lock (gate) {
                Stream? stream = connection.Stream;
                if (stream == null)
                    return;
                stream.Write(frame, 0, frame.Length);
                stream.Flush();
            }
        }

        private static byte[] BuildWebSocketFrame(byte[] payload, byte opcode) {
            if (payload.Length <= 125) {
                byte[] frame = new byte[2 + payload.Length];
                frame[0] = opcode;
                frame[1] = (byte)payload.Length;
                Buffer.BlockCopy(payload, 0, frame, 2, payload.Length);
                return frame;
            }
            if (payload.Length <= 65535) {
                byte[] frame = new byte[4 + payload.Length];
                frame[0] = opcode;
                frame[1] = 126;
                frame[2] = (byte)((payload.Length >> 8) & 0xFF);
                frame[3] = (byte)(payload.Length & 0xFF);
                Buffer.BlockCopy(payload, 0, frame, 4, payload.Length);
                return frame;
            }
            byte[] longFrame = new byte[10 + payload.Length];
            longFrame[0] = opcode;
            longFrame[1] = 127;
            ulong length = (ulong)payload.Length;
            for (int i = 0; i < 8; i++)
                longFrame[2 + i] = (byte)((length >> (56 - i * 8)) & 0xFF);
            Buffer.BlockCopy(payload, 0, longFrame, 10, payload.Length);
            return longFrame;
        }
    }

    private sealed class ShellProxyTunnelConnection {
        public ShellProxyTunnelConnection(string relayId, NetworkConnection connection) {
            RelayId = relayId ?? "";
            Connection = connection;
        }

        public string RelayId { get; }
        public NetworkConnection Connection { get; }
        public object SendLock { get; } = new();
        public bool IsReady { get; set; }
        public DateTimeOffset LastSeenUtc { get; set; }
        public ConcurrentDictionary<string, PendingTunnelRequest> Pending { get; } = new(StringComparer.OrdinalIgnoreCase);
    }

    private sealed class PendingTunnelRequest {
        private readonly TaskCompletionSource<TunnelResponseStart> _start = new(TaskCreationOptions.RunContinuationsAsynchronously);
        private readonly TaskCompletionSource<bool> _complete = new(TaskCreationOptions.RunContinuationsAsynchronously);
        private readonly MemoryStream _body = new();
        private readonly BlockingCollection<byte[]> _streamingChunks = new();
        private readonly Stopwatch _watch = Stopwatch.StartNew();
        private Exception? _error;

        public PendingTunnelRequest(string id, bool requestStreaming, string forwardedPath) {
            Id = id;
            RequestStreaming = requestStreaming;
            ForwardedPath = forwardedPath ?? "/";
        }

        public string Id { get; }
        public bool RequestStreaming { get; }
        public string ForwardedPath { get; }
        public bool Streaming { get; private set; }
        public int WebSocketSendMs { get; set; }
        public int ResponseStartWaitMs { get; private set; }
        public int FirstByteMs { get; private set; }
        public int LocalDurationMs { get; private set; }

        public void SetResponseStart(TunnelResponseStart start) {
            Streaming = RequestStreaming || IsShellProxyStreamingResponse(start.ContentType, ForwardedPath);
            ResponseStartWaitMs = ClampLatencyMilliseconds(_watch.Elapsed);
            _start.TrySetResult(start);
        }

        public TunnelResponseStart WaitForStart(TimeSpan timeout, CancellationToken cancellationToken) {
            if (!_start.Task.Wait(timeout, cancellationToken))
                throw new TimeoutException("Timed out waiting for WebSocket tunnel response headers.");
            if (_error != null)
                throw _error;
            return _start.Task.GetAwaiter().GetResult();
        }

        public void AddBodyChunk(byte[] chunk) {
            chunk ??= Array.Empty<byte>();
            if (FirstByteMs <= 0)
                FirstByteMs = ClampLatencyMilliseconds(_watch.Elapsed);
            if (Streaming) {
                if (!_streamingChunks.IsAddingCompleted)
                    _streamingChunks.Add(chunk);
                return;
            }
            lock (_body) {
                _body.Write(chunk, 0, chunk.Length);
            }
        }

        public IEnumerable<byte[]> GetStreamingChunks(CancellationToken cancellationToken) {
            foreach (byte[] chunk in _streamingChunks.GetConsumingEnumerable(cancellationToken))
                yield return chunk;
            if (_error != null)
                throw _error;
        }

        public void WaitForCompletion(TimeSpan timeout, CancellationToken cancellationToken) {
            if (!_complete.Task.Wait(timeout, cancellationToken))
                throw new TimeoutException("Timed out waiting for WebSocket tunnel response body.");
            if (_error != null)
                throw _error;
        }

        public byte[] GetBufferedBody() {
            lock (_body) {
                return _body.ToArray();
            }
        }

        public void SetLocalDuration(int durationMs) {
            LocalDurationMs = Math.Max(0, durationMs);
        }

        public void Complete() {
            _streamingChunks.CompleteAdding();
            _complete.TrySetResult(true);
        }

        public void Fail(Exception error) {
            _error = error;
            _streamingChunks.CompleteAdding();
            _start.TrySetException(error);
            _complete.TrySetException(error);
        }
    }

    private readonly record struct TunnelResponseStart(int StatusCode, string ReasonPhrase, string ContentType, Dictionary<string, string> Headers) {
        public static TunnelResponseStart FromJson(JsonObject obj) {
            var headers = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (obj.TryGetPropertyValue("headers", out JsonNode? headerNode) && headerNode is JsonObject headerObj) {
                foreach (KeyValuePair<string, JsonNode?> header in headerObj)
                    headers[header.Key] = header.Value?.ToString() ?? "";
            }
            int statusCode = 200;
            if (obj.TryGetPropertyValue("statusCode", out JsonNode? statusNode))
                int.TryParse(statusNode?.ToString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out statusCode);
            if (statusCode <= 0)
                statusCode = 200;
            string contentType = headers.TryGetValue("Content-Type", out string? headerContentType) ? headerContentType : "";
            if (obj.TryGetPropertyValue("contentType", out JsonNode? contentTypeNode) && !string.IsNullOrWhiteSpace(contentTypeNode?.ToString()))
                contentType = contentTypeNode!.ToString();
            string reason = obj.TryGetPropertyValue("reasonPhrase", out JsonNode? reasonNode) ? reasonNode?.ToString() ?? "" : "";
            return new TunnelResponseStart(statusCode, reason, contentType, headers);
        }
    }

    private sealed class ShellProxyWebSocketTunnelState {
        public bool HandshakeComplete { get; set; }
        public List<byte> Buffer { get; } = new();
        public string RelayId { get; set; } = "";
    }

    private sealed class ShellProxyWebSocketTunnelHandler : IProtocolHandler {
        private const string WebSocketMagicGuid = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";
        private const int OpcodeText = 0x1;
        private const int OpcodeBinary = 0x2;
        private const int OpcodeClose = 0x8;
        private const int OpcodePing = 0x9;
        private readonly MasterListServerHost _host;
        private readonly ShellProxyWebSocketTunnelManager _manager;
        private readonly ConcurrentDictionary<Guid, ShellProxyWebSocketTunnelState> _states = new();

        public ShellProxyWebSocketTunnelHandler(MasterListServerHost host, ShellProxyWebSocketTunnelManager manager) {
            _host = host;
            _manager = manager;
        }

        public string Name => "ShellProxyWebSocketTunnel";

        public bool CanHandle(byte[] data) {
            if (data == null || data.Length < 20 ||
                data[0] != (byte)'G' || data[1] != (byte)'E' || data[2] != (byte)'T' || data[3] != (byte)' ')
                return false;

            string header = Encoding.UTF8.GetString(data, 0, Math.Min(data.Length, 4096));
            if (header.IndexOf("Upgrade:", StringComparison.OrdinalIgnoreCase) < 0 ||
                header.IndexOf("websocket", StringComparison.OrdinalIgnoreCase) < 0)
                return false;

            return TryParseRequestTarget(header, out string path, out _) &&
                   TryParseShellProxyTunnelPath(path, out _);
        }

        public void ProcessReceive(MutableTcpServer server, NetworkConnection connection, ref IReceivedEventArgs e) {
            byte[]? incoming = MutableTcpServer.TryGetRawBytes(e.Obj);
            if (incoming == null || incoming.Length == 0)
                return;

            ShellProxyWebSocketTunnelState state = _states.GetOrAdd(connection.ID, _ => new ShellProxyWebSocketTunnelState());
            lock (state) {
                state.Buffer.AddRange(incoming);
                if (!state.HandshakeComplete)
                    TryCompleteHandshake(server, connection, state);
                else
                    ProcessFrames(server, connection, state);
            }
        }

        public void OnDisconnected(MutableTcpServer server, NetworkConnection connection) {
            _states.TryRemove(connection.ID, out _);
            _manager.Unregister(connection.ID);
        }

        private void TryCompleteHandshake(MutableTcpServer server, NetworkConnection connection, ShellProxyWebSocketTunnelState state) {
            int headerEnd = FindHeaderEnd(state.Buffer);
            if (headerEnd < 0)
                return;

            string request = Encoding.UTF8.GetString(state.Buffer.ToArray(), 0, headerEnd);
            if (!TryParseRequestTarget(request, out string path, out _) ||
                !TryParseShellProxyTunnelPath(path, out string relayId)) {
                SendHttpError(connection, 404, "Not Found", "Shell proxy WebSocket tunnel route was not found.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string secKey = HeaderValue(request, "Sec-WebSocket-Key");
            if (string.IsNullOrWhiteSpace(secKey)) {
                SendHttpError(connection, 400, "Bad Request", "Missing Sec-WebSocket-Key.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string acceptKey;
            using (SHA1 sha1 = SHA1.Create()) {
                acceptKey = Convert.ToBase64String(sha1.ComputeHash(Encoding.UTF8.GetBytes(secKey + WebSocketMagicGuid)));
            }

            string response =
                "HTTP/1.1 101 Switching Protocols\r\n" +
                "Upgrade: websocket\r\n" +
                "Connection: Upgrade\r\n" +
                "Sec-WebSocket-Accept: " + acceptKey + "\r\n" +
                "Cache-Control: no-store\r\n" +
                "\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(response));

            state.HandshakeComplete = true;
            state.RelayId = relayId;
            state.Buffer.RemoveRange(0, headerEnd);

            if (state.Buffer.Count > 0)
                ProcessFrames(server, connection, state);
        }

        private void ProcessFrames(MutableTcpServer server, NetworkConnection connection, ShellProxyWebSocketTunnelState state) {
            while (state.Buffer.Count >= 2) {
                int offset = 0;
                byte b0 = state.Buffer[offset++];
                byte b1 = state.Buffer[offset++];
                int opcode = b0 & 0x0F;
                bool masked = (b1 & 0x80) != 0;
                long payloadLength = b1 & 0x7F;

                if (payloadLength == 126) {
                    if (state.Buffer.Count < offset + 2)
                        return;
                    payloadLength = (state.Buffer[offset] << 8) | state.Buffer[offset + 1];
                    offset += 2;
                } else if (payloadLength == 127) {
                    if (state.Buffer.Count < offset + 8)
                        return;
                    payloadLength = 0;
                    for (int i = 0; i < 8; i++)
                        payloadLength = (payloadLength << 8) | state.Buffer[offset + i];
                    offset += 8;
                }

                if (payloadLength > 16L * 1024L * 1024L) {
                    SendClose(connection);
                    Close(server, connection, DisconnectionReason.LocalSocketClosed);
                    return;
                }

                byte[]? mask = null;
                if (masked) {
                    if (state.Buffer.Count < offset + 4)
                        return;
                    mask = state.Buffer.Skip(offset).Take(4).ToArray();
                    offset += 4;
                }

                if (state.Buffer.Count < offset + payloadLength)
                    return;

                int intPayloadLength = (int)payloadLength;
                byte[] payload = new byte[intPayloadLength];
                state.Buffer.CopyTo(offset, payload, 0, intPayloadLength);
                state.Buffer.RemoveRange(0, offset + intPayloadLength);

                if (masked && mask != null) {
                    for (int i = 0; i < payload.Length; i++)
                        payload[i] ^= mask[i % 4];
                }

                if (opcode == OpcodeClose) {
                    SendClose(connection);
                    Close(server, connection, DisconnectionReason.RemoteSocketClosed);
                    return;
                }

                if (opcode == OpcodePing) {
                    SendFrame(connection, payload, 0x8A);
                    continue;
                }

                if (opcode == OpcodeText) {
                    JsonObject? message = ParseJsonObject(payload);
                    if (message != null) {
                        if (!message.ContainsKey("relayId") && !string.IsNullOrWhiteSpace(state.RelayId))
                            message["relayId"] = state.RelayId;
                        _manager.HandleText(connection, message);
                    }
                } else if (opcode == OpcodeBinary) {
                    _manager.HandleBinary(connection.ID, payload);
                }
            }
        }

        private static bool TryParseRequestTarget(string requestHeader, out string path, out string queryString) {
            path = "";
            queryString = "";
            string firstLine = requestHeader.Split(new[] { "\r\n", "\n" }, StringSplitOptions.None).FirstOrDefault() ?? "";
            string[] parts = firstLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length < 2)
                return false;
            string target = parts[1].Trim();
            if (Uri.TryCreate(target, UriKind.Absolute, out Uri? absolute)) {
                path = absolute.AbsolutePath;
                queryString = absolute.Query.TrimStart('?');
                return !string.IsNullOrWhiteSpace(path);
            }

            int queryIndex = target.IndexOf('?');
            path = queryIndex >= 0 ? target.Substring(0, queryIndex) : target;
            queryString = queryIndex >= 0 ? target.Substring(queryIndex + 1) : "";
            return !string.IsNullOrWhiteSpace(path);
        }

        private static bool TryParseShellProxyTunnelPath(string path, out string relayId) {
            relayId = "";
            if (string.IsNullOrWhiteSpace(path))
                return false;

            string normalized = path.TrimEnd('/');
            const string prefix = "/api/shell/proxies/";
            const string suffix = "/tunnel";
            if (!normalized.StartsWith(prefix, StringComparison.OrdinalIgnoreCase) ||
                !normalized.EndsWith(suffix, StringComparison.OrdinalIgnoreCase))
                return false;

            relayId = normalized.Substring(prefix.Length, normalized.Length - prefix.Length - suffix.Length);
            relayId = Uri.UnescapeDataString(relayId);
            return !string.IsNullOrWhiteSpace(relayId);
        }

        private static JsonObject? ParseJsonObject(byte[] payload) {
            try {
                return JsonNode.Parse(Encoding.UTF8.GetString(payload)) as JsonObject;
            } catch {
                return null;
            }
        }

        private static int FindHeaderEnd(List<byte> buffer) {
            for (int i = 0; i <= buffer.Count - 4; i++) {
                if (buffer[i] == '\r' && buffer[i + 1] == '\n' && buffer[i + 2] == '\r' && buffer[i + 3] == '\n')
                    return i + 4;
            }
            return -1;
        }

        private static string HeaderValue(string request, string name) {
            foreach (string line in request.Split(new[] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)) {
                int colon = line.IndexOf(':');
                if (colon > 0 && line.Substring(0, colon).Trim().Equals(name, StringComparison.OrdinalIgnoreCase))
                    return line.Substring(colon + 1).Trim();
            }
            return "";
        }

        private static void SendHttpError(NetworkConnection connection, int statusCode, string reason, string body) {
            byte[] bodyBytes = Encoding.UTF8.GetBytes(body ?? "");
            string header = "HTTP/1.1 " + statusCode.ToString(CultureInfo.InvariantCulture) + " " + reason + "\r\n" +
                            "Content-Type: text/plain; charset=utf-8\r\n" +
                            "Content-Length: " + bodyBytes.Length.ToString(CultureInfo.InvariantCulture) + "\r\n" +
                            "Connection: close\r\n" +
                            "Cache-Control: no-store\r\n\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(header));
            if (bodyBytes.Length > 0)
                WriteRaw(connection, bodyBytes);
        }

        private static void SendClose(NetworkConnection connection) {
            SendFrame(connection, Array.Empty<byte>(), 0x88);
        }

        private static void SendFrame(NetworkConnection connection, byte[] payload, byte opcode) {
            byte[] frame = BuildWebSocketFrame(payload ?? Array.Empty<byte>(), opcode);
            WriteRaw(connection, frame);
        }

        private static byte[] BuildWebSocketFrame(byte[] payload, byte opcode) {
            if (payload.Length <= 125) {
                byte[] frame = new byte[2 + payload.Length];
                frame[0] = opcode;
                frame[1] = (byte)payload.Length;
                Buffer.BlockCopy(payload, 0, frame, 2, payload.Length);
                return frame;
            }
            if (payload.Length <= 65535) {
                byte[] frame = new byte[4 + payload.Length];
                frame[0] = opcode;
                frame[1] = 126;
                frame[2] = (byte)((payload.Length >> 8) & 0xFF);
                frame[3] = (byte)(payload.Length & 0xFF);
                Buffer.BlockCopy(payload, 0, frame, 4, payload.Length);
                return frame;
            }
            byte[] longFrame = new byte[10 + payload.Length];
            longFrame[0] = opcode;
            longFrame[1] = 127;
            ulong length = (ulong)payload.Length;
            for (int i = 0; i < 8; i++)
                longFrame[2 + i] = (byte)((length >> (56 - i * 8)) & 0xFF);
            Buffer.BlockCopy(payload, 0, longFrame, 10, payload.Length);
            return longFrame;
        }

        private static void WriteRaw(NetworkConnection connection, byte[] data) {
            try {
                Stream? stream = connection.Stream;
                if (stream == null || data == null || data.Length == 0)
                    return;
                lock (connection) {
                    stream.Write(data, 0, data.Length);
                    stream.Flush();
                }
            } catch {
            }
        }

        private static void Close(MutableTcpServer server, NetworkConnection connection, DisconnectionReason reason) {
            try {
                connection.Close(server, reason);
            } catch {
            }
        }
    }

    internal sealed class MasterListLivePayload {
        public MasterListLivePayload(long version, string signature, byte[] bytes) {
            Version = version;
            Signature = signature ?? "";
            Bytes = bytes ?? Array.Empty<byte>();
        }

        public long Version { get; }
        public string Signature { get; }
        public byte[] Bytes { get; }
    }

    private sealed class MasterListLiveWebSocketState {
        public NetworkConnection? Connection { get; set; }
        public bool HandshakeComplete { get; set; }
        public List<byte> Buffer { get; } = new();
        public string Page { get; set; } = "auto";
        public string QueryString { get; set; } = "";
        public Dictionary<string, string> RequestHeaders { get; set; } = new(StringComparer.OrdinalIgnoreCase);
        public JsonObject? LastClientRequest { get; set; }
        public long LastSnapshotVersion { get; set; } = -1;
        public string LastSnapshotSignature { get; set; } = "";
        public object SendLock { get; } = new();
    }

    private sealed class MasterListLiveWebSocketHandler : IProtocolHandler {
        private const string WebSocketMagicGuid = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";
        private const int OpcodeText = 0x1;
        private const int OpcodeClose = 0x8;
        private const int OpcodePing = 0x9;
        private readonly MasterListServerHost _host;
        private readonly ConcurrentDictionary<Guid, MasterListLiveWebSocketState> _states = new();
        private int _masterListBroadcastQueued;
        private int _autoLiveBroadcastQueued;

        public MasterListLiveWebSocketHandler(MasterListServerHost host) {
            _host = host;
            _host.ServerListChanged += Host_MasterListChanged;
            _host.AutoLiveDataChanged += Host_AutoLiveDataChanged;
        }

        public string Name => "MasterListLiveWebSocket";

        private void Host_MasterListChanged(object? sender, EventArgs e) {
            QueueMasterListBroadcast();
            QueueAutoLiveBroadcast();
        }

        private void Host_AutoLiveDataChanged(object? sender, EventArgs e) {
            QueueAutoLiveBroadcast();
        }

        private void QueueMasterListBroadcast() {
            if (Interlocked.Exchange(ref _masterListBroadcastQueued, 1) == 1)
                return;

            _ = Task.Run(() => {
                long broadcastVersion = -1;
                try {
                    broadcastVersion = BroadcastMasterListSnapshot();
                } finally {
                    Volatile.Write(ref _masterListBroadcastQueued, 0);
                    if (broadcastVersion >= 0 && _host.ServerListVersion > broadcastVersion)
                        QueueMasterListBroadcast();
                }
            });
        }

        private void QueueAutoLiveBroadcast() {
            if (Interlocked.Exchange(ref _autoLiveBroadcastQueued, 1) == 1)
                return;

            _ = Task.Run(() => {
                long broadcastVersion = -1;
                try {
                    broadcastVersion = BroadcastAutoLiveSnapshots();
                } finally {
                    Volatile.Write(ref _autoLiveBroadcastQueued, 0);
                    if (broadcastVersion >= 0 && _host.AutoLiveVersion > broadcastVersion)
                        QueueAutoLiveBroadcast();
                }
            });
        }

        private long BroadcastMasterListSnapshot() {
            MasterListLivePayload payload = _host.GetCachedMasterListLivePayload();
            foreach (KeyValuePair<Guid, MasterListLiveWebSocketState> item in _states.ToArray()) {
                MasterListLiveWebSocketState state = item.Value;
                NetworkConnection? connection = state.Connection;
                if (connection == null ||
                    !state.HandshakeComplete ||
                    !state.Page.Equals("masterlist", StringComparison.OrdinalIgnoreCase))
                    continue;

                SendMasterListPayload(connection, state, payload, force: false);
            }

            return payload.Version;
        }

        private long BroadcastAutoLiveSnapshots() {
            long version = _host.AutoLiveVersion;
            foreach (KeyValuePair<Guid, MasterListLiveWebSocketState> item in _states.ToArray()) {
                MasterListLiveWebSocketState state = item.Value;
                NetworkConnection? connection = state.Connection;
                if (connection == null ||
                    !state.HandshakeComplete ||
                    !state.Page.Equals("auto", StringComparison.OrdinalIgnoreCase))
                    continue;

                SendSnapshot(connection, state, state.LastClientRequest, force: false);
            }

            return version;
        }

        public bool CanHandle(byte[] data) {
            if (data == null || data.Length < 20 ||
                data[0] != (byte)'G' || data[1] != (byte)'E' || data[2] != (byte)'T' || data[3] != (byte)' ')
                return false;

            string header = Encoding.UTF8.GetString(data, 0, Math.Min(data.Length, 4096));
            if (header.IndexOf("Upgrade:", StringComparison.OrdinalIgnoreCase) < 0 ||
                header.IndexOf("websocket", StringComparison.OrdinalIgnoreCase) < 0)
                return false;

            return TryParseRequestTarget(header, out string path, out _) &&
                   TryParseLivePath(path, out _);
        }

        public void ProcessReceive(MutableTcpServer server, NetworkConnection connection, ref IReceivedEventArgs e) {
            byte[]? incoming = MutableTcpServer.TryGetRawBytes(e.Obj);
            if (incoming == null || incoming.Length == 0)
                return;

            MasterListLiveWebSocketState state = _states.GetOrAdd(connection.ID, _ => new MasterListLiveWebSocketState());
            state.Connection = connection;
            lock (state) {
                state.Buffer.AddRange(incoming);
                if (!state.HandshakeComplete)
                    TryCompleteHandshake(server, connection, state);
                else
                    ProcessFrames(server, connection, state);
            }
        }

        public void OnDisconnected(MutableTcpServer server, NetworkConnection connection) {
            _states.TryRemove(connection.ID, out _);
        }

        private void TryCompleteHandshake(MutableTcpServer server, NetworkConnection connection, MasterListLiveWebSocketState state) {
            int headerEnd = FindHeaderEnd(state.Buffer);
            if (headerEnd < 0)
                return;

            string request = Encoding.UTF8.GetString(state.Buffer.ToArray(), 0, headerEnd);
            if (!TryParseRequestTarget(request, out string path, out string queryString) ||
                !TryParseLivePath(path, out string page)) {
                SendHttpError(connection, 404, "Not Found", "SocketJack live WebSocket route was not found.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string secKey = HeaderValue(request, "Sec-WebSocket-Key");
            if (string.IsNullOrWhiteSpace(secKey)) {
                SendHttpError(connection, 400, "Bad Request", "Missing Sec-WebSocket-Key.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string acceptKey;
            using (SHA1 sha1 = SHA1.Create()) {
                acceptKey = Convert.ToBase64String(sha1.ComputeHash(Encoding.UTF8.GetBytes(secKey + WebSocketMagicGuid)));
            }

            string response =
                "HTTP/1.1 101 Switching Protocols\r\n" +
                "Upgrade: websocket\r\n" +
                "Connection: Upgrade\r\n" +
                "Sec-WebSocket-Accept: " + acceptKey + "\r\n" +
                "Cache-Control: no-store\r\n" +
                "\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(response), state.SendLock);

            state.HandshakeComplete = true;
            state.Page = page;
            state.QueryString = queryString;
            state.RequestHeaders = ParseHeaders(request);
            state.Buffer.RemoveRange(0, headerEnd);

            JsonArray topics = new();
            if (page.Equals("auto", StringComparison.OrdinalIgnoreCase))
                topics.Add("auto-sessions");
            else
                topics.Add("servers");
            SendJson(connection, state, new JsonObject {
                ["ok"] = true,
                ["type"] = "ready",
                ["page"] = page,
                ["topics"] = topics,
                ["protocol"] = "socketjack.live.v1",
                ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });
            if (page.Equals("masterlist", StringComparison.OrdinalIgnoreCase))
                SendMasterListPayload(connection, state, _host.GetCachedMasterListLivePayload(), force: true);

            if (state.Buffer.Count > 0)
                ProcessFrames(server, connection, state);
        }

        private void ProcessFrames(MutableTcpServer server, NetworkConnection connection, MasterListLiveWebSocketState state) {
            while (state.Buffer.Count >= 2) {
                int offset = 0;
                byte b0 = state.Buffer[offset++];
                byte b1 = state.Buffer[offset++];
                int opcode = b0 & 0x0F;
                bool masked = (b1 & 0x80) != 0;
                long payloadLength = b1 & 0x7F;

                if (payloadLength == 126) {
                    if (state.Buffer.Count < offset + 2)
                        return;
                    payloadLength = (state.Buffer[offset] << 8) | state.Buffer[offset + 1];
                    offset += 2;
                } else if (payloadLength == 127) {
                    if (state.Buffer.Count < offset + 8)
                        return;
                    payloadLength = 0;
                    for (int i = 0; i < 8; i++)
                        payloadLength = (payloadLength << 8) | state.Buffer[offset + i];
                    offset += 8;
                }

                if (payloadLength > 2L * 1024L * 1024L) {
                    SendClose(connection, state);
                    Close(server, connection, DisconnectionReason.LocalSocketClosed);
                    return;
                }

                byte[]? mask = null;
                if (masked) {
                    if (state.Buffer.Count < offset + 4)
                        return;
                    mask = state.Buffer.Skip(offset).Take(4).ToArray();
                    offset += 4;
                }

                if (state.Buffer.Count < offset + payloadLength)
                    return;

                int intPayloadLength = (int)payloadLength;
                byte[] payload = new byte[intPayloadLength];
                state.Buffer.CopyTo(offset, payload, 0, intPayloadLength);
                state.Buffer.RemoveRange(0, offset + intPayloadLength);

                if (masked && mask != null) {
                    for (int i = 0; i < payload.Length; i++)
                        payload[i] ^= mask[i % 4];
                }

                if (opcode == OpcodeClose) {
                    SendClose(connection, state);
                    Close(server, connection, DisconnectionReason.RemoteSocketClosed);
                    return;
                }

                if (opcode == OpcodePing) {
                    SendFrame(connection, state, payload, 0x8A);
                    continue;
                }

                if (opcode == OpcodeText)
                    HandleTextMessage(connection, state, payload);
            }
        }

        private void HandleTextMessage(NetworkConnection connection, MasterListLiveWebSocketState state, byte[] payload) {
            JsonObject? message = ParseJsonObject(payload);
            if (message == null)
                return;

            string type = JsonText(message, "type", "");
            if (type.Equals("ping", StringComparison.OrdinalIgnoreCase)) {
                SendJson(connection, state, new JsonObject {
                    ["ok"] = true,
                    ["type"] = "pong",
                    ["requestId"] = JsonText(message, "id", JsonText(message, "requestId", "")),
                    ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                });
                return;
            }
            if (type.Equals("session-import", StringComparison.OrdinalIgnoreCase)) {
                JsonObject result = _host.HandleAutoLiveSessionImport(connection, state.RequestHeaders, message);
                SendJson(connection, state, result);
                if (JsonNodeIsTruthy(result["ok"], false)) {
                    state.LastClientRequest = message.DeepClone() as JsonObject;
                    SendSnapshot(connection, state, state.LastClientRequest, force: true);
                }
                return;
            }

            state.LastClientRequest = message.DeepClone() as JsonObject;
            SendSnapshot(connection, state, state.LastClientRequest, force: true);
        }

        private void SendSnapshot(NetworkConnection connection, MasterListLiveWebSocketState state, JsonObject? clientRequest, bool force) {
            try {
                if (state.Page.Equals("masterlist", StringComparison.OrdinalIgnoreCase)) {
                    SendMasterListPayload(connection, state, _host.GetCachedMasterListLivePayload(), force);
                    return;
                }

                JsonObject snapshot = _host.BuildLiveWebSocketSnapshot(connection, state.RequestHeaders, state.Page, state.QueryString, clientRequest);
                string json = snapshot.ToJsonString(MasterListJson.Options);
                string signature = Convert.ToBase64String(SHA256.HashData(Encoding.UTF8.GetBytes(json)));
                if (!force && string.Equals(signature, state.LastSnapshotSignature, StringComparison.Ordinal))
                    return;
                state.LastSnapshotSignature = signature;
                SendFrame(connection, state, Encoding.UTF8.GetBytes(json), 0x81);
            } catch (Exception ex) {
                SendJson(connection, state, new JsonObject {
                    ["ok"] = false,
                    ["type"] = "error",
                    ["error"] = ex.Message,
                    ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                });
            }
        }

        private static void SendMasterListPayload(NetworkConnection connection, MasterListLiveWebSocketState state, MasterListLivePayload payload, bool force) {
            if (payload == null)
                return;
            if (!force && state.LastSnapshotVersion == payload.Version)
                return;
            if (!force && string.Equals(state.LastSnapshotSignature, payload.Signature, StringComparison.Ordinal))
                return;
            state.LastSnapshotVersion = payload.Version;
            state.LastSnapshotSignature = payload.Signature;
            SendFrame(connection, state, payload.Bytes, 0x81);
        }

        private static bool TryParseRequestTarget(string requestHeader, out string path, out string queryString) {
            path = "";
            queryString = "";
            string firstLine = requestHeader.Split(new[] { "\r\n", "\n" }, StringSplitOptions.None).FirstOrDefault() ?? "";
            string[] parts = firstLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length < 2)
                return false;
            string target = parts[1].Trim();
            if (Uri.TryCreate(target, UriKind.Absolute, out Uri? absolute)) {
                path = absolute.AbsolutePath;
                queryString = absolute.Query.TrimStart('?');
                return !string.IsNullOrWhiteSpace(path);
            }

            int queryIndex = target.IndexOf('?');
            path = queryIndex >= 0 ? target.Substring(0, queryIndex) : target;
            queryString = queryIndex >= 0 ? target.Substring(queryIndex + 1) : "";
            return !string.IsNullOrWhiteSpace(path);
        }

        private static bool TryParseLivePath(string path, out string page) {
            page = "";
            string normalized = (path ?? "").TrimEnd('/');
            if (normalized.Equals("/auto/ws", StringComparison.OrdinalIgnoreCase)) {
                page = "auto";
                return true;
            }
            if (normalized.Equals("/masterlist/ws", StringComparison.OrdinalIgnoreCase)) {
                page = "masterlist";
                return true;
            }
            if (normalized.Equals("/master-list/ws", StringComparison.OrdinalIgnoreCase)) {
                page = "masterlist";
                return true;
            }
            return false;
        }

        private static JsonObject? ParseJsonObject(byte[] payload) {
            try {
                return JsonNode.Parse(Encoding.UTF8.GetString(payload)) as JsonObject;
            } catch {
                return null;
            }
        }

        private static Dictionary<string, string> ParseHeaders(string request) {
            var headers = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (string line in request.Split(new[] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)) {
                int colon = line.IndexOf(':');
                if (colon <= 0)
                    continue;
                string name = line.Substring(0, colon).Trim();
                string value = line.Substring(colon + 1).Trim();
                if (!string.IsNullOrWhiteSpace(name))
                    headers[name] = value;
            }
            return headers;
        }

        private static int FindHeaderEnd(List<byte> buffer) {
            for (int i = 0; i <= buffer.Count - 4; i++) {
                if (buffer[i] == '\r' && buffer[i + 1] == '\n' && buffer[i + 2] == '\r' && buffer[i + 3] == '\n')
                    return i + 4;
            }
            return -1;
        }

        private static string HeaderValue(string request, string name) {
            foreach (string line in request.Split(new[] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)) {
                int colon = line.IndexOf(':');
                if (colon > 0 && line.Substring(0, colon).Trim().Equals(name, StringComparison.OrdinalIgnoreCase))
                    return line.Substring(colon + 1).Trim();
            }
            return "";
        }

        private static void SendHttpError(NetworkConnection connection, int statusCode, string reason, string body) {
            byte[] bodyBytes = Encoding.UTF8.GetBytes(body ?? "");
            string header = "HTTP/1.1 " + statusCode.ToString(CultureInfo.InvariantCulture) + " " + reason + "\r\n" +
                            "Content-Type: text/plain; charset=utf-8\r\n" +
                            "Content-Length: " + bodyBytes.Length.ToString(CultureInfo.InvariantCulture) + "\r\n" +
                            "Connection: close\r\n" +
                            "Cache-Control: no-store\r\n\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(header), connection);
            if (bodyBytes.Length > 0)
                WriteRaw(connection, bodyBytes, connection);
        }

        private static void SendJson(NetworkConnection connection, MasterListLiveWebSocketState state, JsonObject payload) {
            SendFrame(connection, state, Encoding.UTF8.GetBytes(payload.ToJsonString(MasterListJson.Options)), 0x81);
        }

        private static void SendClose(NetworkConnection connection, MasterListLiveWebSocketState state) {
            SendFrame(connection, state, Array.Empty<byte>(), 0x88);
        }

        private static void SendFrame(NetworkConnection connection, MasterListLiveWebSocketState state, byte[] payload, byte opcode) {
            byte[] frame = BuildWebSocketFrame(payload ?? Array.Empty<byte>(), opcode);
            WriteRaw(connection, frame, state.SendLock);
        }

        private static byte[] BuildWebSocketFrame(byte[] payload, byte opcode) {
            if (payload.Length <= 125) {
                byte[] frame = new byte[2 + payload.Length];
                frame[0] = opcode;
                frame[1] = (byte)payload.Length;
                Buffer.BlockCopy(payload, 0, frame, 2, payload.Length);
                return frame;
            }
            if (payload.Length <= 65535) {
                byte[] frame = new byte[4 + payload.Length];
                frame[0] = opcode;
                frame[1] = 126;
                frame[2] = (byte)((payload.Length >> 8) & 0xFF);
                frame[3] = (byte)(payload.Length & 0xFF);
                Buffer.BlockCopy(payload, 0, frame, 4, payload.Length);
                return frame;
            }
            byte[] longFrame = new byte[10 + payload.Length];
            longFrame[0] = opcode;
            longFrame[1] = 127;
            ulong length = (ulong)payload.Length;
            for (int i = 0; i < 8; i++)
                longFrame[2 + i] = (byte)((length >> (56 - i * 8)) & 0xFF);
            Buffer.BlockCopy(payload, 0, longFrame, 10, payload.Length);
            return longFrame;
        }

        private static void WriteRaw(NetworkConnection connection, byte[] data, object sendLock) {
            try {
                Stream? stream = connection.Stream;
                if (stream == null || data == null || data.Length == 0)
                    return;
                lock (sendLock) {
                    stream.Write(data, 0, data.Length);
                    stream.Flush();
                }
            } catch {
            }
        }

        private static void Close(MutableTcpServer server, NetworkConnection connection, DisconnectionReason reason) {
            try {
                connection.Close(server, reason);
            } catch {
            }
        }
    }

    private sealed class ShellProxyJsonWebSocketState {
        public bool HandshakeComplete { get; set; }
        public List<byte> Buffer { get; } = new();
        public string RouteName { get; set; } = "";
        public string ForwardedPath { get; set; } = "/";
        public string QueryString { get; set; } = "";
    }

    private sealed class ShellProxyWebChatWebSocketState {
        public bool HandshakeComplete { get; set; }
        public List<byte> Buffer { get; } = new();
        public string RouteName { get; set; } = "";
        public MasterShellRelay? Relay { get; set; }
        public object SendLock { get; } = new();
        public ConcurrentDictionary<string, CancellationTokenSource> Requests { get; } = new(StringComparer.OrdinalIgnoreCase);
    }

    private sealed class ShellProxyWebChatWebSocketHandler : IProtocolHandler {
        private const string WebSocketMagicGuid = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";
        private const int OpcodeText = 0x1;
        private const int OpcodeClose = 0x8;
        private const int OpcodePing = 0x9;
        private readonly MasterListServerHost _host;
        private readonly ShellProxyWebSocketTunnelManager _manager;
        private readonly ConcurrentDictionary<Guid, ShellProxyWebChatWebSocketState> _states = new();

        public ShellProxyWebChatWebSocketHandler(MasterListServerHost host, ShellProxyWebSocketTunnelManager manager) {
            _host = host;
            _manager = manager;
        }

        public string Name => "ShellProxyWebChatWebSocket";

        public bool CanHandle(byte[] data) {
            if (data == null || data.Length < 20 ||
                data[0] != (byte)'G' || data[1] != (byte)'E' || data[2] != (byte)'T' || data[3] != (byte)' ')
                return false;

            string header = Encoding.UTF8.GetString(data, 0, Math.Min(data.Length, 4096));
            if (header.IndexOf("Upgrade:", StringComparison.OrdinalIgnoreCase) < 0 ||
                header.IndexOf("websocket", StringComparison.OrdinalIgnoreCase) < 0)
                return false;

            return TryParseRequestTarget(header, out string path, out _) &&
                   TryParseShellProxyPath(path, out _, out string forwardedPath) &&
                   forwardedPath.Equals("/api/web-chat/ws", StringComparison.OrdinalIgnoreCase);
        }

        public void ProcessReceive(MutableTcpServer server, NetworkConnection connection, ref IReceivedEventArgs e) {
            byte[]? incoming = MutableTcpServer.TryGetRawBytes(e.Obj);
            if (incoming == null || incoming.Length == 0)
                return;

            ShellProxyWebChatWebSocketState state = _states.GetOrAdd(connection.ID, _ => new ShellProxyWebChatWebSocketState());
            lock (state) {
                state.Buffer.AddRange(incoming);
                if (!state.HandshakeComplete)
                    TryCompleteHandshake(server, connection, state);
                else
                    ProcessFrames(server, connection, state);
            }
        }

        public void OnDisconnected(MutableTcpServer server, NetworkConnection connection) {
            if (_states.TryRemove(connection.ID, out ShellProxyWebChatWebSocketState? state)) {
                foreach (CancellationTokenSource cts in state.Requests.Values) {
                    try { cts.Cancel(); } catch { }
                    try { cts.Dispose(); } catch { }
                }
            }
        }

        private void TryCompleteHandshake(MutableTcpServer server, NetworkConnection connection, ShellProxyWebChatWebSocketState state) {
            int headerEnd = FindHeaderEnd(state.Buffer);
            if (headerEnd < 0)
                return;

            string request = Encoding.UTF8.GetString(state.Buffer.ToArray(), 0, headerEnd);
            if (!TryParseRequestTarget(request, out string path, out _) ||
                !TryParseShellProxyPath(path, out string routeName, out string forwardedPath) ||
                !forwardedPath.Equals("/api/web-chat/ws", StringComparison.OrdinalIgnoreCase)) {
                SendHttpError(connection, 404, "Not Found", "Shell proxy Web Chat WebSocket route was not found.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            MasterShellRelay? relay = _host.ResolveShellRelayForProxy(routeName);
            if (relay == null) {
                SendHttpError(connection, 404, "Not Found", "Shell proxy route was not found.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }
            if (!relay.Enabled || !relay.IsRunning) {
                SendHttpError(connection, 503, "Service Unavailable", "Shell proxy route is not listening.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }
            if (!_manager.HasConnectedTunnel(relay.Id)) {
                SendHttpError(connection, 503, "Service Unavailable", "WebSocket tunnel is not connected.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string secKey = HeaderValue(request, "Sec-WebSocket-Key");
            if (string.IsNullOrWhiteSpace(secKey)) {
                SendHttpError(connection, 400, "Bad Request", "Missing Sec-WebSocket-Key.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string acceptKey;
            using (SHA1 sha1 = SHA1.Create()) {
                acceptKey = Convert.ToBase64String(sha1.ComputeHash(Encoding.UTF8.GetBytes(secKey + WebSocketMagicGuid)));
            }

            string response =
                "HTTP/1.1 101 Switching Protocols\r\n" +
                "Upgrade: websocket\r\n" +
                "Connection: Upgrade\r\n" +
                "Sec-WebSocket-Accept: " + acceptKey + "\r\n" +
                "Cache-Control: no-store\r\n" +
                "\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(response), state.SendLock);

            state.HandshakeComplete = true;
            state.RouteName = routeName;
            state.Relay = relay;
            state.Buffer.RemoveRange(0, headerEnd);

            SendJson(connection, state, new JsonObject {
                ["type"] = "ready",
                ["ok"] = true,
                ["transport"] = "websocket",
                ["proxyRoute"] = routeName,
                ["secure"] = connection.SSL,
                ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });

            if (state.Buffer.Count > 0)
                ProcessFrames(server, connection, state);
        }

        private void ProcessFrames(MutableTcpServer server, NetworkConnection connection, ShellProxyWebChatWebSocketState state) {
            while (state.Buffer.Count >= 2) {
                int offset = 0;
                byte b0 = state.Buffer[offset++];
                byte b1 = state.Buffer[offset++];
                int opcode = b0 & 0x0F;
                bool masked = (b1 & 0x80) != 0;
                long payloadLength = b1 & 0x7F;

                if (payloadLength == 126) {
                    if (state.Buffer.Count < offset + 2)
                        return;
                    payloadLength = (state.Buffer[offset] << 8) | state.Buffer[offset + 1];
                    offset += 2;
                } else if (payloadLength == 127) {
                    if (state.Buffer.Count < offset + 8)
                        return;
                    payloadLength = 0;
                    for (int i = 0; i < 8; i++)
                        payloadLength = (payloadLength << 8) | state.Buffer[offset + i];
                    offset += 8;
                }

                if (payloadLength > 16L * 1024L * 1024L) {
                    SendClose(connection, state);
                    Close(server, connection, DisconnectionReason.LocalSocketClosed);
                    return;
                }

                byte[]? mask = null;
                if (masked) {
                    if (state.Buffer.Count < offset + 4)
                        return;
                    mask = state.Buffer.Skip(offset).Take(4).ToArray();
                    offset += 4;
                }

                if (state.Buffer.Count < offset + payloadLength)
                    return;

                int intPayloadLength = (int)payloadLength;
                byte[] payload = new byte[intPayloadLength];
                state.Buffer.CopyTo(offset, payload, 0, intPayloadLength);
                state.Buffer.RemoveRange(0, offset + intPayloadLength);

                if (masked && mask != null) {
                    for (int i = 0; i < payload.Length; i++)
                        payload[i] ^= mask[i % 4];
                }

                if (opcode == OpcodeClose) {
                    SendClose(connection, state);
                    Close(server, connection, DisconnectionReason.RemoteSocketClosed);
                    return;
                }
                if (opcode == OpcodePing) {
                    SendFrame(connection, state, payload, 0x8A);
                    continue;
                }
                if (opcode == OpcodeText) {
                    JsonObject? message = ParseJsonObject(payload);
                    if (message != null)
                        HandleBrowserMessage(connection, state, message);
                }
            }
        }

        private void HandleBrowserMessage(NetworkConnection connection, ShellProxyWebChatWebSocketState state, JsonObject message) {
            string type = JsonText(message, "type", "");
            if (type.Equals("ping", StringComparison.OrdinalIgnoreCase)) {
                SendJson(connection, state, new JsonObject {
                    ["type"] = "pong",
                    ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                });
                return;
            }

            string id = JsonText(message, "id", JsonText(message, "requestId", ""));
            if (type.Equals("cancel", StringComparison.OrdinalIgnoreCase)) {
                if (!string.IsNullOrWhiteSpace(id) && state.Requests.TryRemove(id, out CancellationTokenSource? cts)) {
                    try { cts.Cancel(); } catch { }
                    try { cts.Dispose(); } catch { }
                }
                return;
            }

            if (!type.Equals("request", StringComparison.OrdinalIgnoreCase) || state.Relay == null || string.IsNullOrWhiteSpace(id))
                return;

            var requestCts = new CancellationTokenSource();
            state.Requests[id] = requestCts;
            Task.Run(() => {
                try {
                    _manager.ForwardWebChatRequest(
                        state.Relay,
                        message,
                        payload => SendJson(connection, state, payload),
                        payload => SendFrame(connection, state, payload, 0x82),
                        requestCts.Token);
                } catch (OperationCanceledException) {
                    SendJson(connection, state, new JsonObject {
                        ["type"] = "error",
                        ["id"] = id,
                        ["error"] = "Request canceled."
                    });
                } catch (Exception ex) {
                    SendJson(connection, state, new JsonObject {
                        ["type"] = "error",
                        ["id"] = id,
                        ["error"] = ex.Message
                    });
                } finally {
                    state.Requests.TryRemove(id, out _);
                    requestCts.Dispose();
                }
            });
        }

        private static JsonObject? ParseJsonObject(byte[] payload) {
            try {
                return JsonNode.Parse(Encoding.UTF8.GetString(payload)) as JsonObject;
            } catch {
                return null;
            }
        }

        private static string JsonText(JsonObject? obj, string name, string fallback) {
            if (obj == null || !obj.TryGetPropertyValue(name, out JsonNode? value) || value == null)
                return fallback;
            return value.ToString();
        }

        private static bool TryParseRequestTarget(string requestHeader, out string path, out string queryString) {
            path = "";
            queryString = "";
            string firstLine = requestHeader.Split(new[] { "\r\n", "\n" }, StringSplitOptions.None).FirstOrDefault() ?? "";
            string[] parts = firstLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length < 2)
                return false;
            string target = parts[1].Trim();
            int queryIndex = target.IndexOf('?');
            path = queryIndex >= 0 ? target.Substring(0, queryIndex) : target;
            queryString = queryIndex >= 0 ? target.Substring(queryIndex + 1) : "";
            return !string.IsNullOrWhiteSpace(path);
        }

        private static int FindHeaderEnd(List<byte> buffer) {
            for (int i = 0; i <= buffer.Count - 4; i++) {
                if (buffer[i] == '\r' && buffer[i + 1] == '\n' && buffer[i + 2] == '\r' && buffer[i + 3] == '\n')
                    return i + 4;
            }
            return -1;
        }

        private static string HeaderValue(string request, string name) {
            foreach (string line in request.Split(new[] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)) {
                int colon = line.IndexOf(':');
                if (colon > 0 && line.Substring(0, colon).Trim().Equals(name, StringComparison.OrdinalIgnoreCase))
                    return line.Substring(colon + 1).Trim();
            }
            return "";
        }

        private static void SendHttpError(NetworkConnection connection, int statusCode, string reason, string body) {
            byte[] bodyBytes = Encoding.UTF8.GetBytes(body ?? "");
            string header = "HTTP/1.1 " + statusCode.ToString(CultureInfo.InvariantCulture) + " " + reason + "\r\n" +
                            "Content-Type: text/plain; charset=utf-8\r\n" +
                            "Content-Length: " + bodyBytes.Length.ToString(CultureInfo.InvariantCulture) + "\r\n" +
                            "Connection: close\r\n" +
                            "Cache-Control: no-store\r\n\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(header), connection);
            if (bodyBytes.Length > 0)
                WriteRaw(connection, bodyBytes, connection);
        }

        private static void SendJson(NetworkConnection connection, ShellProxyWebChatWebSocketState state, JsonObject payload) {
            SendFrame(connection, state, Encoding.UTF8.GetBytes(payload.ToJsonString()), 0x81);
        }

        private static void SendClose(NetworkConnection connection, ShellProxyWebChatWebSocketState state) {
            SendFrame(connection, state, Array.Empty<byte>(), 0x88);
        }

        private static void SendFrame(NetworkConnection connection, ShellProxyWebChatWebSocketState state, byte[] payload, byte opcode) {
            byte[] frame = BuildWebSocketFrame(payload ?? Array.Empty<byte>(), opcode);
            WriteRaw(connection, frame, state.SendLock);
        }

        private static byte[] BuildWebSocketFrame(byte[] payload, byte opcode) {
            if (payload.Length <= 125) {
                byte[] frame = new byte[2 + payload.Length];
                frame[0] = opcode;
                frame[1] = (byte)payload.Length;
                Buffer.BlockCopy(payload, 0, frame, 2, payload.Length);
                return frame;
            }
            if (payload.Length <= 65535) {
                byte[] frame = new byte[4 + payload.Length];
                frame[0] = opcode;
                frame[1] = 126;
                frame[2] = (byte)((payload.Length >> 8) & 0xFF);
                frame[3] = (byte)(payload.Length & 0xFF);
                Buffer.BlockCopy(payload, 0, frame, 4, payload.Length);
                return frame;
            }
            byte[] longFrame = new byte[10 + payload.Length];
            longFrame[0] = opcode;
            longFrame[1] = 127;
            ulong length = (ulong)payload.Length;
            for (int i = 0; i < 8; i++)
                longFrame[2 + i] = (byte)((length >> (56 - i * 8)) & 0xFF);
            Buffer.BlockCopy(payload, 0, longFrame, 10, payload.Length);
            return longFrame;
        }

        private static void WriteRaw(NetworkConnection connection, byte[] data, object sendLock) {
            try {
                Stream? stream = connection.Stream;
                if (stream == null || data == null || data.Length == 0)
                    return;
                lock (sendLock) {
                    stream.Write(data, 0, data.Length);
                    stream.Flush();
                }
            } catch {
            }
        }

        private static void Close(MutableTcpServer server, NetworkConnection connection, DisconnectionReason reason) {
            try {
                connection.Close(server, reason);
            } catch {
            }
        }
    }

    private sealed class ShellProxyJsonWebSocketHandler : IProtocolHandler {
        private const string WebSocketMagicGuid = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";
        private const int OpcodeText = 0x1;
        private const int OpcodeBinary = 0x2;
        private const int OpcodeClose = 0x8;
        private const int OpcodePing = 0x9;
        private readonly MasterListServerHost _host;
        private readonly ConcurrentDictionary<Guid, ShellProxyJsonWebSocketState> _states = new();

        public ShellProxyJsonWebSocketHandler(MasterListServerHost host) {
            _host = host;
        }

        public string Name => "ShellProxyJsonWebSocket";

        public bool CanHandle(byte[] data) {
            if (data == null || data.Length < 20 ||
                data[0] != (byte)'G' || data[1] != (byte)'E' || data[2] != (byte)'T' || data[3] != (byte)' ')
                return false;

            string header = Encoding.UTF8.GetString(data, 0, Math.Min(data.Length, 4096));
            if (header.IndexOf("Upgrade:", StringComparison.OrdinalIgnoreCase) < 0 ||
                header.IndexOf("websocket", StringComparison.OrdinalIgnoreCase) < 0)
                return false;

            return TryParseRequestTarget(header, out string path, out _) &&
                   TryParseShellProxyPath(path, out _, out string forwardedPath) &&
                   IsShellProxyJsonWebSocketPath(forwardedPath);
        }

        public void ProcessReceive(MutableTcpServer server, NetworkConnection connection, ref IReceivedEventArgs e) {
            byte[]? incoming = MutableTcpServer.TryGetRawBytes(e.Obj);
            if (incoming == null || incoming.Length == 0)
                return;

            ShellProxyJsonWebSocketState state = _states.GetOrAdd(connection.ID, _ => new ShellProxyJsonWebSocketState());
            lock (state) {
                state.Buffer.AddRange(incoming);
                if (!state.HandshakeComplete)
                    TryCompleteHandshake(server, connection, state);
                else
                    ProcessFrames(server, connection, state);
            }
        }

        public void OnDisconnected(MutableTcpServer server, NetworkConnection connection) {
            _states.TryRemove(connection.ID, out _);
        }

        private void TryCompleteHandshake(MutableTcpServer server, NetworkConnection connection, ShellProxyJsonWebSocketState state) {
            int headerEnd = FindHeaderEnd(state.Buffer);
            if (headerEnd < 0)
                return;

            string request = Encoding.UTF8.GetString(state.Buffer.ToArray(), 0, headerEnd);
            if (!TryParseRequestTarget(request, out string path, out string queryString) ||
                !TryParseShellProxyPath(path, out string routeName, out string forwardedPath) ||
                !IsShellProxyJsonWebSocketPath(forwardedPath)) {
                SendHttpError(connection, 404, "Not Found", "Shell proxy WebSocket route was not found.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string secKey = HeaderValue(request, "Sec-WebSocket-Key");
            if (string.IsNullOrWhiteSpace(secKey)) {
                SendHttpError(connection, 400, "Bad Request", "Missing Sec-WebSocket-Key.");
                Close(server, connection, DisconnectionReason.LocalSocketClosed);
                return;
            }

            string acceptKey;
            using (SHA1 sha1 = SHA1.Create()) {
                acceptKey = Convert.ToBase64String(sha1.ComputeHash(Encoding.UTF8.GetBytes(secKey + WebSocketMagicGuid)));
            }

            string response =
                "HTTP/1.1 101 Switching Protocols\r\n" +
                "Upgrade: websocket\r\n" +
                "Connection: Upgrade\r\n" +
                "Sec-WebSocket-Accept: " + acceptKey + "\r\n" +
                "Cache-Control: no-store\r\n" +
                "\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(response));

            state.HandshakeComplete = true;
            state.RouteName = routeName;
            state.ForwardedPath = forwardedPath.Equals("/health", StringComparison.OrdinalIgnoreCase) ? "/api/health" : forwardedPath;
            state.QueryString = queryString;
            state.Buffer.RemoveRange(0, headerEnd);

            SendJson(connection, new JsonObject {
                ["type"] = "hello",
                ["ok"] = true,
                ["socketJackTransport"] = "websocket",
                ["socketJackProxyRoute"] = routeName,
                ["socketJackProxyPath"] = _host.BuildShellProxyPath(routeName),
                ["socketJackForwardedPath"] = state.ForwardedPath,
                ["socketJackSentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });

            if (state.Buffer.Count > 0)
                ProcessFrames(server, connection, state);
        }

        private void ProcessFrames(MutableTcpServer server, NetworkConnection connection, ShellProxyJsonWebSocketState state) {
            while (state.Buffer.Count >= 2) {
                int offset = 0;
                byte b0 = state.Buffer[offset++];
                byte b1 = state.Buffer[offset++];
                int opcode = b0 & 0x0F;
                bool masked = (b1 & 0x80) != 0;
                long payloadLength = b1 & 0x7F;

                if (payloadLength == 126) {
                    if (state.Buffer.Count < offset + 2)
                        return;
                    payloadLength = (state.Buffer[offset] << 8) | state.Buffer[offset + 1];
                    offset += 2;
                } else if (payloadLength == 127) {
                    if (state.Buffer.Count < offset + 8)
                        return;
                    payloadLength = 0;
                    for (int i = 0; i < 8; i++)
                        payloadLength = (payloadLength << 8) | state.Buffer[offset + i];
                    offset += 8;
                }

                if (payloadLength > 1_048_576) {
                    SendClose(connection);
                    Close(server, connection, DisconnectionReason.LocalSocketClosed);
                    return;
                }

                byte[]? mask = null;
                if (masked) {
                    if (state.Buffer.Count < offset + 4)
                        return;
                    mask = state.Buffer.Skip(offset).Take(4).ToArray();
                    offset += 4;
                }

                if (state.Buffer.Count < offset + payloadLength)
                    return;

                int intPayloadLength = (int)payloadLength;
                byte[] payload = new byte[intPayloadLength];
                state.Buffer.CopyTo(offset, payload, 0, intPayloadLength);
                state.Buffer.RemoveRange(0, offset + intPayloadLength);

                if (masked && mask != null) {
                    for (int i = 0; i < payload.Length; i++)
                        payload[i] ^= mask[i % 4];
                }

                if (opcode == OpcodeClose) {
                    SendClose(connection);
                    Close(server, connection, DisconnectionReason.RemoteSocketClosed);
                    return;
                }

                if (opcode == OpcodePing) {
                    SendFrame(connection, payload, 0x8A);
                    continue;
                }

                if (opcode == OpcodeText || opcode == OpcodeBinary) {
                    JsonObject? clientRequest = ParseClientRequest(payload);
                    SendSnapshotAsync(connection, state, clientRequest);
                }
            }
        }

        private void SendSnapshotAsync(NetworkConnection connection, ShellProxyJsonWebSocketState state, JsonObject? clientRequest) {
            Task.Run(() => {
                try {
                    JsonObject payload = _host.BuildShellProxyJsonWebSocketSnapshot(state, clientRequest);
                    SendJson(connection, payload);
                } catch (Exception ex) {
                    SendJson(connection, new JsonObject {
                        ["type"] = "snapshot",
                        ["ok"] = false,
                        ["socketJackTransport"] = "websocket",
                        ["socketJackProxyRoute"] = state.RouteName,
                        ["socketJackForwardedPath"] = state.ForwardedPath,
                        ["statusCode"] = 500,
                        ["error"] = ex.Message,
                        ["socketJackSentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
                    });
                }
            });
        }

        private static JsonObject? ParseClientRequest(byte[] payload) {
            if (payload == null || payload.Length == 0)
                return null;
            try {
                string text = Encoding.UTF8.GetString(payload);
                return JsonNode.Parse(text) as JsonObject ?? new JsonObject { ["message"] = text };
            } catch {
                return null;
            }
        }

        private static bool TryParseRequestTarget(string requestHeader, out string path, out string queryString) {
            path = "";
            queryString = "";
            string firstLine = requestHeader.Split(new[] { "\r\n", "\n" }, StringSplitOptions.None).FirstOrDefault() ?? "";
            string[] parts = firstLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length < 2)
                return false;
            string target = parts[1].Trim();
            if (Uri.TryCreate(target, UriKind.Absolute, out Uri? absolute)) {
                path = absolute.AbsolutePath;
                queryString = absolute.Query.TrimStart('?');
                return !string.IsNullOrWhiteSpace(path);
            }

            int queryIndex = target.IndexOf('?');
            path = queryIndex >= 0 ? target.Substring(0, queryIndex) : target;
            queryString = queryIndex >= 0 ? target.Substring(queryIndex + 1) : "";
            return !string.IsNullOrWhiteSpace(path);
        }

        private static bool IsShellProxyJsonWebSocketPath(string forwardedPath) {
            return forwardedPath.Equals("/api/health", StringComparison.OrdinalIgnoreCase) ||
                   forwardedPath.Equals("/health", StringComparison.OrdinalIgnoreCase) ||
                   forwardedPath.Equals("/api/master-list/ping", StringComparison.OrdinalIgnoreCase) ||
                   forwardedPath.Equals("/api/server-hardware", StringComparison.OrdinalIgnoreCase);
        }

        private static int FindHeaderEnd(List<byte> buffer) {
            for (int i = 0; i <= buffer.Count - 4; i++) {
                if (buffer[i] == '\r' && buffer[i + 1] == '\n' && buffer[i + 2] == '\r' && buffer[i + 3] == '\n')
                    return i + 4;
            }
            return -1;
        }

        private static string HeaderValue(string request, string name) {
            foreach (string line in request.Split(new[] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)) {
                int colon = line.IndexOf(':');
                if (colon > 0 && line.Substring(0, colon).Trim().Equals(name, StringComparison.OrdinalIgnoreCase))
                    return line.Substring(colon + 1).Trim();
            }
            return "";
        }

        private static void SendHttpError(NetworkConnection connection, int statusCode, string reason, string body) {
            byte[] bodyBytes = Encoding.UTF8.GetBytes(body ?? "");
            string header = "HTTP/1.1 " + statusCode.ToString(CultureInfo.InvariantCulture) + " " + reason + "\r\n" +
                            "Content-Type: text/plain; charset=utf-8\r\n" +
                            "Content-Length: " + bodyBytes.Length.ToString(CultureInfo.InvariantCulture) + "\r\n" +
                            "Connection: close\r\n" +
                            "Cache-Control: no-store\r\n\r\n";
            WriteRaw(connection, Encoding.UTF8.GetBytes(header));
            if (bodyBytes.Length > 0)
                WriteRaw(connection, bodyBytes);
        }

        private static void SendJson(NetworkConnection connection, JsonObject payload) {
            SendFrame(connection, Encoding.UTF8.GetBytes(payload.ToJsonString()), 0x81);
        }

        private static void SendClose(NetworkConnection connection) {
            SendFrame(connection, Array.Empty<byte>(), 0x88);
        }

        private static void SendFrame(NetworkConnection connection, byte[] payload, byte opcode) {
            byte[] frame = BuildWebSocketFrame(payload ?? Array.Empty<byte>(), opcode);
            WriteRaw(connection, frame);
        }

        private static byte[] BuildWebSocketFrame(byte[] payload, byte opcode) {
            if (payload.Length <= 125) {
                byte[] frame = new byte[2 + payload.Length];
                frame[0] = opcode;
                frame[1] = (byte)payload.Length;
                Buffer.BlockCopy(payload, 0, frame, 2, payload.Length);
                return frame;
            }
            if (payload.Length <= 65535) {
                byte[] frame = new byte[4 + payload.Length];
                frame[0] = opcode;
                frame[1] = 126;
                frame[2] = (byte)((payload.Length >> 8) & 0xFF);
                frame[3] = (byte)(payload.Length & 0xFF);
                Buffer.BlockCopy(payload, 0, frame, 4, payload.Length);
                return frame;
            }
            byte[] longFrame = new byte[10 + payload.Length];
            longFrame[0] = opcode;
            longFrame[1] = 127;
            ulong length = (ulong)payload.Length;
            for (int i = 0; i < 8; i++)
                longFrame[2 + i] = (byte)((length >> (56 - i * 8)) & 0xFF);
            Buffer.BlockCopy(payload, 0, longFrame, 10, payload.Length);
            return longFrame;
        }

        private static void WriteRaw(NetworkConnection connection, byte[] data) {
            try {
                Stream? stream = connection.Stream;
                if (stream == null || data == null || data.Length == 0)
                    return;
                lock (connection) {
                    stream.Write(data, 0, data.Length);
                    stream.Flush();
                }
            } catch {
            }
        }

        private static void Close(MutableTcpServer server, NetworkConnection connection, DisconnectionReason reason) {
            try {
                connection.Close(server, reason);
            } catch {
            }
        }
    }

    private static bool IsShellProxyStreamingRequest(HttpRequest request, string forwardedPath) {
        if (forwardedPath.Equals("/api/chat-stream", StringComparison.OrdinalIgnoreCase))
            return true;
        if (request.Headers.TryGetValue("Accept", out string? accept) &&
            accept.IndexOf("text/event-stream", StringComparison.OrdinalIgnoreCase) >= 0)
            return true;
        return false;
    }

    private static bool IsShellProxyStreamingResponse(string contentType, string forwardedPath) {
        return IsShellProxyStreamingPath(forwardedPath) ||
               (!string.IsNullOrWhiteSpace(contentType) &&
                (contentType.IndexOf("text/event-stream", StringComparison.OrdinalIgnoreCase) >= 0 ||
                 contentType.IndexOf("application/x-ndjson", StringComparison.OrdinalIgnoreCase) >= 0 ||
                 contentType.IndexOf("application/json-seq", StringComparison.OrdinalIgnoreCase) >= 0));
    }

    private static bool IsShellProxyStreamingPath(string path) {
        string normalized = (path ?? "").Split('?')[0].TrimEnd('/');
        return normalized.Equals("/api/chat-stream", StringComparison.OrdinalIgnoreCase) ||
               normalized.Equals("/api/llm-client/chat-stream", StringComparison.OrdinalIgnoreCase) ||
               normalized.EndsWith("/api/chat-stream", StringComparison.OrdinalIgnoreCase) ||
               normalized.EndsWith("/api/llm-client/chat-stream", StringComparison.OrdinalIgnoreCase);
    }

    private static int GetShellProxyStreamingBufferSize(string contentType, string path) {
        return IsShellProxyStreamingResponse(contentType, path) ? 2048 : 16 * 1024;
    }

    private static void StreamShellProxyResponse(HttpRequest request, System.Net.Http.HttpResponseMessage upstreamResponse, string contentType, CancellationToken cancellationToken, IReadOnlyDictionary<string, string>? extraHeaders = null) {
        HttpResponse response = request.Context.Response;
        request.Context.StatusCodeNumber = (int)upstreamResponse.StatusCode;
        request.Context.ReasonPhrase = string.IsNullOrWhiteSpace(upstreamResponse.ReasonPhrase)
            ? GetReasonPhrase((int)upstreamResponse.StatusCode)
            : upstreamResponse.ReasonPhrase!;
        response.ContentType = contentType;
        response.RawResponseWritten = true;

        Stream? output = request.Context.Connection?.Stream;
        if (output == null)
            return;

        var headerBuilder = new StringBuilder();
        headerBuilder.Append(request.Version).Append(' ')
            .Append(((int)upstreamResponse.StatusCode).ToString(CultureInfo.InvariantCulture))
            .Append(' ')
            .Append(string.IsNullOrWhiteSpace(upstreamResponse.ReasonPhrase) ? GetReasonPhrase((int)upstreamResponse.StatusCode) : upstreamResponse.ReasonPhrase)
            .Append("\r\n");

        bool wroteContentType = false;
        CopyStreamingProxyHeaders(headerBuilder, upstreamResponse.Headers, ref wroteContentType);
        CopyStreamingProxyHeaders(headerBuilder, upstreamResponse.Content.Headers, ref wroteContentType);
        if (!wroteContentType)
            headerBuilder.Append("Content-Type: ").Append(string.IsNullOrWhiteSpace(contentType) ? "application/octet-stream" : contentType).Append("\r\n");
        AppendExtraHttpStreamingHeaders(headerBuilder, extraHeaders);
        headerBuilder.Append("Transfer-Encoding: chunked\r\n");
        headerBuilder.Append("Connection: close\r\n");
        headerBuilder.Append("Cache-Control: no-cache, no-store\r\n");
        headerBuilder.Append("Access-Control-Allow-Origin: *\r\n");
        headerBuilder.Append("\r\n");

        byte[] headerBytes = Encoding.UTF8.GetBytes(headerBuilder.ToString());
        output.Write(headerBytes, 0, headerBytes.Length);
        output.Flush();

        using Stream upstreamStream = upstreamResponse.Content.ReadAsStream(cancellationToken);
        byte[] buffer = new byte[GetShellProxyStreamingBufferSize(contentType, request.Path)];
        while (!cancellationToken.IsCancellationRequested) {
            int read = upstreamStream.Read(buffer, 0, buffer.Length);
            if (read <= 0)
                break;

            WriteHttpChunk(output, buffer, read);
        }

        byte[] trailer = Encoding.ASCII.GetBytes("0\r\n\r\n");
        output.Write(trailer, 0, trailer.Length);
        output.Flush();
    }

    private static void CopyStreamingProxyHeaders(StringBuilder target, System.Net.Http.Headers.HttpHeaders headers, ref bool wroteContentType) {
        foreach (KeyValuePair<string, IEnumerable<string>> header in headers) {
            if (ShouldSkipStreamingProxyHeader(header.Key))
                continue;
            if (header.Key.Equals("Content-Type", StringComparison.OrdinalIgnoreCase))
                wroteContentType = true;
            target.Append(header.Key).Append(": ").Append(string.Join(", ", header.Value)).Append("\r\n");
        }
    }

    private static void AppendExtraHttpStreamingHeaders(StringBuilder target, IReadOnlyDictionary<string, string>? headers) {
        if (headers == null)
            return;
        foreach (KeyValuePair<string, string> header in headers) {
            if (string.IsNullOrWhiteSpace(header.Key) || ShouldSkipStreamingProxyHeader(header.Key))
                continue;
            target.Append(header.Key).Append(": ").Append(header.Value ?? "").Append("\r\n");
        }
    }

    private static bool ShouldSkipStreamingProxyHeader(string name) {
        return name.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Upgrade", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Content-Encoding", StringComparison.OrdinalIgnoreCase);
    }

    private static void WriteHttpChunk(Stream output, byte[] buffer, int count) {
        byte[] size = Encoding.ASCII.GetBytes(count.ToString("X", CultureInfo.InvariantCulture) + "\r\n");
        output.Write(size, 0, size.Length);
        output.Write(buffer, 0, count);
        output.Write(new byte[] { 13, 10 }, 0, 2);
        output.Flush();
    }

    private static bool TryParseShellProxyPath(string path, out string routeName, out string forwardedPath) {
        routeName = "";
        forwardedPath = "/";
        if (string.IsNullOrWhiteSpace(path) || !path.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
            return false;

        string remainder = path.Substring("/proxy/".Length);
        if (string.IsNullOrWhiteSpace(remainder))
            return false;

        int slashIndex = remainder.IndexOf('/');
        string routeSegment = slashIndex >= 0 ? remainder.Substring(0, slashIndex) : remainder;
        routeName = Uri.UnescapeDataString(routeSegment.Replace("+", "%20"));
        forwardedPath = slashIndex >= 0 ? "/" + remainder.Substring(slashIndex + 1) : "/";
        if (string.IsNullOrWhiteSpace(forwardedPath))
            forwardedPath = "/";
        return !string.IsNullOrWhiteSpace(routeName);
    }

    private static bool TryParseAutoProxyPath(string path, out string forwardedPath) {
        forwardedPath = "/";
        if (string.IsNullOrWhiteSpace(path))
            return false;

        string trimmed = path.Trim();
        if (trimmed.Equals("/Auto", StringComparison.OrdinalIgnoreCase) ||
            trimmed.Equals("/Auto/", StringComparison.OrdinalIgnoreCase))
            return true;
        if (!trimmed.StartsWith("/Auto/", StringComparison.OrdinalIgnoreCase))
            return false;

        forwardedPath = "/" + trimmed.Substring("/Auto/".Length);
        if (string.IsNullOrWhiteSpace(forwardedPath))
            forwardedPath = "/";
        return true;
    }

    private static bool ShouldSkipProxyRequestHeader(string name) {
        return name.Equals("Host", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Upgrade", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Accept-Encoding", StringComparison.OrdinalIgnoreCase);
    }

    private static void CopyProxyHeaders(Dictionary<string, string> target, System.Net.Http.Headers.HttpHeaders headers, bool rewritten, string proxyPath) {
        foreach (KeyValuePair<string, IEnumerable<string>> header in headers) {
            if (ShouldSkipProxyResponseHeader(header.Key, rewritten))
                continue;
            string value = string.Join(", ", header.Value);
            if (header.Key.Equals("Location", StringComparison.OrdinalIgnoreCase) && value.StartsWith("/", StringComparison.Ordinal))
                value = proxyPath + value;
            target[header.Key] = value;
        }
    }

    private static bool ShouldSkipProxyResponseHeader(string name, bool rewritten) {
        return name.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
               (rewritten && name.Equals("Content-Encoding", StringComparison.OrdinalIgnoreCase));
    }

    private static bool IsHtmlContentType(string contentType) {
        return !string.IsNullOrWhiteSpace(contentType) &&
               contentType.IndexOf("text/html", StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static bool IsShellProxyBrowserProxyPath(string forwardedPath) {
        string path = (forwardedPath ?? "").Trim();
        int queryIndex = path.IndexOf('?');
        if (queryIndex >= 0)
            path = path[..queryIndex];
        path = path.TrimEnd('/');
        return path.Equals("/api/browser-proxy", StringComparison.OrdinalIgnoreCase) ||
               path.EndsWith("/api/browser-proxy", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsMasterListPingPath(string forwardedPath) {
        return forwardedPath.Equals("/api/master-list/ping", StringComparison.OrdinalIgnoreCase) ||
               forwardedPath.Equals("/api/lmvsproxy/ping", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsShellProxyModelsApiPath(string forwardedPath) {
        return forwardedPath.Equals("/api/models", StringComparison.OrdinalIgnoreCase);
    }

    private static byte[] RewriteShellProxyModelsApiResponse(byte[] body) {
        if (body == null || body.Length == 0)
            return Array.Empty<byte>();
        string json = Encoding.UTF8.GetString(body);
        string enriched = EnrichShellProxyModelsApiJson(json);
        return Encoding.UTF8.GetBytes(enriched);
    }

    private static string EnrichShellProxyModelsApiJson(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return "{}";
        try {
            JsonNode? node = JsonNode.Parse(json);
            if (node is not JsonObject root)
                return json;

            JsonArray? models = root["models"] as JsonArray ?? root["data"] as JsonArray;
            if (models == null)
                return json;

            bool serverDynamic = JsonNodeIsTruthy(root["dynamicLoadingEnabled"], false) ||
                                 JsonNodeIsTruthy(root["serverDynamicLoadingEnabled"], false) ||
                                 JsonNodeIsTruthy(root["web_chat_model_load_api_enabled"], false);
            var available = new List<string>();
            var loaded = new List<string>();
            var enabled = new List<string>();
            var disabled = new List<string>();
            string modelBenchmarksJson = FindUsefulModelBenchmarksJson(root);
            Dictionary<string, JsonObject> benchmarksByModel = BuildBenchmarkNodeMap(modelBenchmarksJson);

            foreach (JsonNode? itemNode in models) {
                if (itemNode is not JsonObject model)
                    continue;
                string id = FirstNonEmpty(
                    JsonNodeText(model["id"]),
                    JsonNodeText(model["key"]),
                    JsonNodeText(model["name"]),
                    JsonNodeText(model["model"]),
                    JsonNodeText(model["displayName"]),
                    JsonNodeText(model["display_name"]));
                if (string.IsNullOrWhiteSpace(id))
                    continue;

                bool isLoaded = JsonNodeIsTruthy(model["isLoaded"], JsonNodeIsTruthy(model["loaded"], JsonNodeIsTruthy(model["active"], JsonNodeIsTruthy(model["ready"], false))));
                bool hasEnabledField = model.ContainsKey("enabled") || model.ContainsKey("isEnabled") || model.ContainsKey("web_chat_model_enabled");
                bool isEnabled = hasEnabledField
                    ? JsonNodeIsTruthy(model["enabled"], JsonNodeIsTruthy(model["isEnabled"], JsonNodeIsTruthy(model["web_chat_model_enabled"], false)))
                    : true;
                bool dynamicLoad = JsonNodeIsTruthy(model["dynamicLoadEnabled"], JsonNodeIsTruthy(model["web_chat_dynamic_load_enabled"], serverDynamic || isEnabled));
                bool modelDisabled = JsonNodeIsTruthy(model["disabled"], !isEnabled && !dynamicLoad && !isLoaded);
                string status = FirstNonEmpty(JsonNodeText(model["status"]),
                    isLoaded && isEnabled ? "loaded-enabled" :
                    isLoaded && dynamicLoad ? "loaded-dynamic" :
                    isLoaded ? "loaded-disabled" :
                    isEnabled ? "enabled" :
                    serverDynamic ? "dynamic-load-available" :
                    modelDisabled ? "disabled" : "available");

                model["isAvailable"] = true;
                model["isLoaded"] = isLoaded;
                model["enabled"] = isEnabled;
                model["isEnabled"] = isEnabled;
                model["disabled"] = modelDisabled;
                model["dynamicLoadEnabled"] = dynamicLoad;
                model["serverDynamicLoadingEnabled"] = serverDynamic;
                model["status"] = status;
                model["benchmarked"] = false;
                if (benchmarksByModel.TryGetValue(id.Trim(), out JsonObject benchmark))
                    ApplyBenchmarkToShellProxyModel(model, benchmark);

                AddDistinct(available, id);
                if (isLoaded)
                    AddDistinct(loaded, id);
                if (isEnabled)
                    AddDistinct(enabled, id);
                if (modelDisabled)
                    AddDistinct(disabled, id);
            }

            root["modelCount"] = available.Count;
            root["availableModelCount"] = available.Count;
            root["loadedModelCount"] = loaded.Count;
            root["enabledModelCount"] = enabled.Count;
            root["disabledModelCount"] = disabled.Count;
            root["availableModels"] = string.Join(", ", available);
            root["loadedModels"] = string.Join(", ", loaded);
            root["enabledModels"] = string.Join(", ", enabled);
            root["disabledModels"] = string.Join(", ", disabled);
            root["dynamicLoadingEnabled"] = serverDynamic || models.OfType<JsonObject>().Any(model => JsonNodeIsTruthy(model["dynamicLoadEnabled"], false));
            root["serverDynamicLoadingEnabled"] = serverDynamic;
            if (!string.IsNullOrWhiteSpace(modelBenchmarksJson)) {
                root["modelBenchmarksJson"] = modelBenchmarksJson;
                root["benchmarkedModelCount"] = CountBenchmarkItems(modelBenchmarksJson);
            } else {
                root["modelBenchmarksJson"] = "";
                root["benchmarkedModelCount"] = 0;
                root.Remove("modelBenchmarks");
                root.Remove("benchmarks");
            }
            return root.ToJsonString(MasterListJson.Options);
        } catch {
            return json;
        }
    }

    private static Dictionary<string, JsonObject> BuildBenchmarkNodeMap(string modelBenchmarksJson) {
        var benchmarks = new Dictionary<string, JsonObject>(StringComparer.OrdinalIgnoreCase);
        modelBenchmarksJson = NormalizeModelBenchmarksJsonText(modelBenchmarksJson);
        if (string.IsNullOrWhiteSpace(modelBenchmarksJson))
            return benchmarks;
        try {
            JsonNode? node = JsonNode.Parse(modelBenchmarksJson);
            if (node is not JsonArray array)
                return benchmarks;
            foreach (JsonNode? itemNode in array) {
                if (itemNode is not JsonObject item)
                    continue;
                string id = FirstNonEmpty(
                    JsonNodeText(GetJsonNodeProperty(item, "modelId")),
                    JsonNodeText(GetJsonNodeProperty(item, "ModelId")),
                    JsonNodeText(GetJsonNodeProperty(item, "id")),
                    JsonNodeText(GetJsonNodeProperty(item, "model")),
                    JsonNodeText(GetJsonNodeProperty(item, "name")));
                if (!string.IsNullOrWhiteSpace(id))
                    benchmarks[id.Trim()] = item;
            }
        } catch {
        }

        return benchmarks;
    }

    private static void ApplyBenchmarkToShellProxyModel(JsonObject model, JsonObject benchmark) {
        if (model == null || benchmark == null)
            return;

        double tokensPerSecond = JsonNodeDouble(
            GetJsonNodeProperty(benchmark, "tokensPerSecond") ?? GetJsonNodeProperty(benchmark, "TokensPerSecond"),
            0);
        double tokensPerHour = JsonNodeDouble(
            GetJsonNodeProperty(benchmark, "tokensPerHour") ?? GetJsonNodeProperty(benchmark, "TokensPerHour"),
            0);
        int outputTokens = JsonNodeInt(
            GetJsonNodeProperty(benchmark, "outputTokens") ?? GetJsonNodeProperty(benchmark, "OutputTokens"),
            0);
        double durationMs = JsonNodeDouble(
            GetJsonNodeProperty(benchmark, "durationMs") ?? GetJsonNodeProperty(benchmark, "DurationMs") ?? GetJsonNodeProperty(benchmark, "benchmarkDurationMs") ?? GetJsonNodeProperty(benchmark, "BenchmarkDurationMs"),
            0);
        int rating = JsonNodeInt(
            GetJsonNodeProperty(benchmark, "rating") ??
            GetJsonNodeProperty(benchmark, "Rating") ??
            GetJsonNodeProperty(benchmark, "benchmarkRating") ??
            GetJsonNodeProperty(benchmark, "score") ??
            GetJsonNodeProperty(benchmark, "Score"),
            0);
        if (rating <= 0 && tokensPerSecond > 0)
            rating = (int)Math.Round(Math.Max(0, Math.Min(100, (tokensPerSecond / 120d) * 100d)));

        string benchmarkedUtc = FirstNonEmpty(
            JsonNodeText(GetJsonNodeProperty(benchmark, "benchmarkedUtc")),
            JsonNodeText(GetJsonNodeProperty(benchmark, "BenchmarkedUtc")));
        string benchmarkStatus = FirstNonEmpty(
            JsonNodeText(GetJsonNodeProperty(benchmark, "status")),
            JsonNodeText(GetJsonNodeProperty(benchmark, "Status")),
            JsonNodeText(GetJsonNodeProperty(benchmark, "benchmarkStatus")));

        model["benchmarked"] = tokensPerSecond > 0 || rating > 0 || !string.IsNullOrWhiteSpace(benchmarkedUtc);
        if (tokensPerSecond > 0)
            model["tokensPerSecond"] = tokensPerSecond;
        if (tokensPerHour > 0)
            model["tokensPerHour"] = tokensPerHour;
        if (outputTokens > 0)
            model["outputTokens"] = outputTokens;
        if (durationMs > 0)
            model["benchmarkDurationMs"] = durationMs;
        if (rating > 0) {
            model["benchmarkRating"] = rating;
            model["rating"] = rating;
            model["score"] = rating;
        }
        if (!string.IsNullOrWhiteSpace(benchmarkedUtc))
            model["benchmarkedUtc"] = benchmarkedUtc;
        if (!string.IsNullOrWhiteSpace(benchmarkStatus))
            model["benchmarkStatus"] = benchmarkStatus;

        CopyBenchmarkBool(benchmark, model, "supportsImages", "SupportsImages");
        CopyBenchmarkBool(benchmark, model, "supportsTools", "SupportsTools");
        CopyBenchmarkBool(benchmark, model, "supportsImageGeneration", "SupportsImageGeneration");
        CopyBenchmarkBool(benchmark, model, "supportsAudioGeneration", "SupportsAudioGeneration");
        CopyBenchmarkBool(benchmark, model, "supportsVideoGeneration", "SupportsVideoGeneration");
    }

    private static void CopyBenchmarkBool(JsonObject benchmark, JsonObject model, string lowerName, string upperName) {
        bool value = JsonNodeIsTruthy(GetJsonNodeProperty(benchmark, lowerName) ?? GetJsonNodeProperty(benchmark, upperName), false);
        if (value)
            model[lowerName] = true;
    }

    private static JsonNode? GetJsonNodeProperty(JsonObject obj, string name) {
        return TryGetJsonNodeProperty(obj, name, out JsonNode? value) ? value : null;
    }

    private static double JsonNodeDouble(JsonNode? node, double fallback) {
        if (node is JsonValue value) {
            if (value.TryGetValue(out double number))
                return number;
            if (value.TryGetValue(out int integer))
                return integer;
            if (value.TryGetValue(out long longValue))
                return longValue;
            if (value.TryGetValue(out string? text) && double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed))
                return parsed;
        }

        return fallback;
    }

    private static int JsonNodeInt(JsonNode? node, int fallback) {
        if (node is JsonValue value) {
            if (value.TryGetValue(out int integer))
                return integer;
            if (value.TryGetValue(out long longValue))
                return longValue > int.MaxValue ? int.MaxValue : longValue < int.MinValue ? int.MinValue : (int)longValue;
            if (value.TryGetValue(out double number))
                return (int)Math.Round(number);
            if (value.TryGetValue(out string? text) && int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed))
                return parsed;
        }

        return fallback;
    }

    private static string JsonNodeText(JsonNode? node) {
        return node == null ? "" : node.ToString();
    }

    private static void AddDistinct(List<string> values, string value) {
        if (values == null || string.IsNullOrWhiteSpace(value))
            return;
        if (!values.Any(existing => string.Equals(existing, value, StringComparison.OrdinalIgnoreCase)))
            values.Add(value.Trim());
    }

    private static byte[] RewriteShellProxyHtml(byte[] body, string proxyPath) {
        if (body == null || body.Length == 0)
            return Array.Empty<byte>();

        string html = Encoding.UTF8.GetString(body);
        html = Regex.Replace(html, "(\\b(?:href|src|action)\\s*=\\s*[\"'])/(?!/)", match => match.Groups[1].Value + proxyPath + "/", RegexOptions.IgnoreCase);
        html = Regex.Replace(html, "(\\b(?:fetch|open)\\s*\\(\\s*[\"'])/(?!/)", match => match.Groups[1].Value + proxyPath + "/", RegexOptions.IgnoreCase);
        html = Regex.Replace(html, "(url\\(\\s*[\"']?)/(?!/)", match => match.Groups[1].Value + proxyPath + "/", RegexOptions.IgnoreCase);

        string baseHref = proxyPath.TrimEnd('/') + "/";
        int headIndex = html.IndexOf("<head", StringComparison.OrdinalIgnoreCase);
        if (headIndex >= 0 && html.IndexOf("<base", StringComparison.OrdinalIgnoreCase) < 0) {
            int headClose = html.IndexOf('>', headIndex);
            if (headClose >= 0)
                html = html.Insert(headClose + 1, "<base href=\"" + baseHref + "\">");
        }

        return Encoding.UTF8.GetBytes(html);
    }

    private static void SetShellProxyWaitingResponse(HttpRequest request, MasterShellRelay relay, string message) {
        if (!IsShellProxyBrowserNavigation(request)) {
            SetShellProxyError(request, 503, "Service Unavailable", message);
            return;
        }

        request.Context.StatusCodeNumber = 503;
        request.Context.ReasonPhrase = "Service Unavailable";
        request.Context.Response.ContentType = "text/html; charset=utf-8";
        request.Context.Response.Headers["Cache-Control"] = "no-store, no-cache, must-revalidate";
        request.Context.Response.Headers["Pragma"] = "no-cache";
        request.Context.Response.Headers["Retry-After"] = "4";
        request.Context.Response.Body = request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase)
            ? ""
            : BuildShellProxyWaitingHtml(relay, message);
        AddCors(request);
    }

    private static CancellationTokenSource? CreateShellProxyTimeout(CancellationToken cancellationToken, bool streamingRequest) {
        if (streamingRequest)
            return null;

        CancellationTokenSource timeoutCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
        timeoutCts.CancelAfter(TimeSpan.FromSeconds(65));
        return timeoutCts;
    }

    private static bool IsShellProxyBrowserNavigation(HttpRequest request) {
        if (request == null)
            return false;
        if (!request.Method.Equals("GET", StringComparison.OrdinalIgnoreCase) &&
            !request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase))
            return false;
        if (request.Headers.TryGetValue("Sec-Fetch-Dest", out string? dest) &&
            dest.Equals("document", StringComparison.OrdinalIgnoreCase))
            return true;
        if (request.Headers.TryGetValue("Accept", out string? accept) &&
            accept.IndexOf("text/html", StringComparison.OrdinalIgnoreCase) >= 0)
            return true;
        return false;
    }

    private static string BuildShellProxyWaitingHtml(MasterShellRelay relay, string message) {
        string title = WebUtility.HtmlEncode(string.IsNullOrWhiteSpace(relay?.Name) ? "SocketJack Proxy" : relay.Name);
        string route = WebUtility.HtmlEncode(string.IsNullOrWhiteSpace(relay?.ProxyPath) ? "/proxy" : relay.ProxyPath);
        string probePathJson = JsonSerializer.Serialize((string.IsNullOrWhiteSpace(relay?.ProxyPath) ? "/proxy" : relay.ProxyPath).TrimEnd('/') + "/api/master-list/ping");
        string encodedMessage = WebUtility.HtmlEncode(message ?? "Waiting for proxy.");
        return """
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Waiting for SocketJack proxy</title>
<style>
:root{color-scheme:dark;--ease:cubic-bezier(.785,.135,.15,.86);--surface:cubic-bezier(.22,1,.36,1)}
*{box-sizing:border-box}
