body{--a:#40c9a2;--b:#7dd3fc;--c:#facc15;--glow-a:rgba(64,201,162,.34);--glow-b:rgba(125,211,252,.18);--wash-a:rgba(64,201,162,.24);--wash-b:rgba(125,211,252,.20);--text:#e5edf7;display:grid;place-items:center;padding:7vmin;background:radial-gradient(circle at 50% 50%,var(--wash-a),transparent 20vmin),radial-gradient(circle at 50% 50%,var(--wash-b),transparent 34vmin),linear-gradient(135deg,#020203,#07090c 45%,#111318);color:var(--text);font-family:"Segoe UI","Cascadia Code",sans-serif;transition:background 900ms var(--surface),color 900ms var(--surface),filter 900ms var(--surface)}
body.not-responding{--a:#fb7185;--b:#ef4444;--c:#f97316;--glow-a:rgba(251,113,133,.46);--glow-b:rgba(239,68,68,.24);--wash-a:rgba(127,29,29,.48);--wash-b:rgba(248,113,113,.18);filter:saturate(1.08)}
body.connected{--a:#40c9a2;--b:#7dd3fc;--c:#facc15;--glow-a:rgba(64,201,162,.44);--glow-b:rgba(125,211,252,.28);--wash-a:rgba(64,201,162,.30);--wash-b:rgba(125,211,252,.24)}
.loader{display:grid;justify-items:center;gap:clamp(14px,2.2vmin,24px);width:min(72vw,520px);padding:clamp(18px,3vmin,32px);filter:drop-shadow(0 0 28px var(--glow-a)) drop-shadow(0 0 72px var(--glow-b));transition:filter 900ms var(--surface)}
.throbber{position:relative;width:clamp(150px,33vmin,380px);height:clamp(150px,33vmin,380px)}
.throbber:before,.throbber:after{content:"";position:absolute;border-radius:999px;pointer-events:none}
.throbber:before{inset:12%;background:radial-gradient(circle,color-mix(in srgb,var(--b) 34%,transparent),color-mix(in srgb,var(--a) 14%,transparent) 42%,transparent 68%);filter:blur(12px);animation:glow 2100ms ease-in-out infinite;transition:background 900ms var(--surface)}
.throbber:after{inset:28%;border:1px solid rgba(255,255,255,.14);box-shadow:0 0 34px var(--glow-a),inset 0 0 30px var(--glow-b);transition:box-shadow 900ms var(--surface)}
.throbber span{position:absolute;inset:0;border-radius:999px;border:clamp(3px,.52vmin,6px) solid color-mix(in srgb,var(--b) 22%,transparent);border-top-color:var(--a);border-right-color:color-mix(in srgb,var(--b) 70%,transparent);box-shadow:0 0 26px var(--glow-a);animation:spin 1150ms var(--ease) infinite;transition:border-color 900ms var(--surface),box-shadow 900ms var(--surface)}
.throbber span:nth-child(2){inset:15%;border-top-color:rgba(244,114,182,.82);animation-duration:1450ms;animation-direction:reverse}
.throbber span:nth-child(3){inset:32%;border-top-color:rgba(250,204,21,.86);animation-duration:950ms}
.progress{position:relative;width:min(100%,420px);height:8px;overflow:hidden;border-radius:999px;background:rgba(148,163,184,.16);box-shadow:inset 0 0 0 1px rgba(255,255,255,.10),0 0 22px var(--glow-b);transition:box-shadow 900ms var(--surface)}
.fill{position:absolute;inset:0 auto 0 0;width:4%;border-radius:inherit;background:linear-gradient(90deg,var(--a),var(--b) 58%,var(--c));box-shadow:0 0 20px var(--glow-a),0 0 34px var(--glow-b);transition:width 520ms var(--surface),background 900ms var(--surface),box-shadow 900ms var(--surface)}
.fill:after{content:"";position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(255,255,255,.54),transparent);animation:sheen 1400ms ease-in-out infinite}
.text{color:rgba(255,255,255,.86);font:800 .74rem "Cascadia Code",monospace;letter-spacing:0;text-align:center;transition:color 900ms var(--surface)}
.meta{max-width:min(620px,86vw);color:rgba(226,232,240,.62);font:.72rem/1.45 "Cascadia Code",monospace;text-align:center;overflow-wrap:anywhere}
.actions{display:flex;flex-wrap:wrap;gap:10px;justify-content:center}.actions a,.actions button{min-height:34px;border:1px solid rgba(125,211,252,.28);border-radius:8px;background:rgba(15,23,42,.62);color:#e5edf7;padding:7px 11px;font:800 .72rem "Cascadia Code",monospace;text-decoration:none;cursor:pointer}.actions button{border-color:rgba(64,201,162,.38);background:linear-gradient(135deg,rgba(64,201,162,.22),rgba(125,211,252,.12))}
@keyframes spin{to{transform:rotate(360deg)}}@keyframes glow{0%,100%{opacity:.62;transform:scale(.94)}50%{opacity:1;transform:scale(1.08)}}@keyframes sheen{0%{transform:translateX(-100%)}100%{transform:translateX(100%)}}
@media (prefers-reduced-motion:reduce){.throbber:before,.throbber span,.fill:after{animation:none}}
</style>
</head>
<body>
<main class="loader" aria-live="polite">
<div class="throbber" aria-hidden="true"><span></span><span></span><span></span></div>
<div class="progress" role="progressbar" aria-valuemin="0" aria-valuemax="100" aria-valuenow="4"><div class="fill"></div></div>
<div class="text">Server not responding 4%</div>
<div class="meta"><strong>__TITLE__</strong><br>__MESSAGE__<br>__ROUTE__</div>
<div class="actions"><button type="button" id="retryNow">Retry</button><a href="/MasterList">MasterList</a></div>
</main>
<script>
const key='socketjack.shellProxy.waitStart:'+location.pathname;
const probePath=__PROBE_PATH_JSON__;
const now=Date.now();
let start=Number(sessionStorage.getItem(key)||0);
if(!start||now-start>10*60*1000){start=now;sessionStorage.setItem(key,String(start))}
const fill=document.querySelector('.fill'),bar=document.querySelector('.progress'),text=document.querySelector('.text');
let connected=false;
requestAnimationFrame(()=>document.body.classList.add('not-responding'));
function percent(){const elapsed=(Date.now()-start)/1000;return Math.min(96,Math.round(4+elapsed*1.55))}
function render(){const p=connected?100:percent();fill.style.width=p+'%';bar.setAttribute('aria-valuenow',String(p));text.textContent=(connected?'Server responding ':'Server not responding ')+p+'%'}
function markConnected(){if(connected)return;connected=true;document.body.classList.remove('not-responding');document.body.classList.add('connected');sessionStorage.removeItem(key);render();setTimeout(()=>location.reload(),780)}
async function probe(){if(connected)return;try{const r=await fetch(probePath,{cache:'no-store',credentials:'include',headers:{Accept:'application/json'},redirect:'manual'});const body=await r.text().catch(()=>'');if(r.ok&&/pong/i.test(body))markConnected()}catch{}}
document.getElementById('retryNow').addEventListener('click',probe);
render();setInterval(render,620);setInterval(probe,1300);setTimeout(probe,550);
</script>
</body>
</html>
"""
            .Replace("__TITLE__", title)
            .Replace("__MESSAGE__", encodedMessage)
            .Replace("__ROUTE__", route)
            .Replace("__PROBE_PATH_JSON__", probePathJson);
    }

    private static void SetShellProxyError(HttpRequest request, int statusCode, string reasonPhrase, string message) {
        request.Context.StatusCodeNumber = statusCode;
        request.Context.ReasonPhrase = reasonPhrase;
        request.Context.Response.ContentType = "application/json";
        request.Context.Response.Body = JsonSerializer.Serialize(new {
            ok = false,
            error = message
        });
        AddCors(request);
    }

    private static string GetReasonPhrase(int statusCode) {
        return statusCode switch {
            200 => "OK",
            201 => "Created",
            202 => "Accepted",
            204 => "No Content",
            301 => "Moved Permanently",
            302 => "Found",
            304 => "Not Modified",
            400 => "Bad Request",
            401 => "Unauthorized",
            403 => "Forbidden",
            404 => "Not Found",
            500 => "Internal Server Error",
            502 => "Bad Gateway",
            503 => "Service Unavailable",
            504 => "Gateway Timeout",
            _ => "OK"
        };
    }

    private static string NormalizeIdentifierText(string value, string fallback) {
        value = (value ?? "").Trim();
        var builder = new StringBuilder(value.Length);
        foreach (char c in value) {
            if (char.IsLetterOrDigit(c) || c == '-' || c == '_' || c == '.')
                builder.Append(char.ToLowerInvariant(c));
            else if (builder.Length == 0 || builder[^1] != '-')
                builder.Append('-');
        }

        string result = builder.ToString().Trim('-');
        return string.IsNullOrWhiteSpace(result) ? fallback : result;
    }

    private static string MakeHashId(string prefix, string value, int byteCount) {
        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes((value ?? "").Trim().ToLowerInvariant()));
        int count = Math.Clamp(byteCount, 1, hash.Length);
        return prefix + Convert.ToHexString(hash, 0, count).ToLowerInvariant();
    }

    private void StartEnabledShellRelays() {
        lock (_sync) {
            foreach (MasterShellRelay relay in _shellRelays.Values.ToList()) {
                if (relay.Enabled)
                    StartShellRelayLocked(relay.Id);
            }
        }
    }

    private void StopAllShellRelays() {
        lock (_sync) {
            foreach (string id in _shellRelayServers.Keys.ToList())
                StopShellRelayLocked(id);
        }
    }

    private void StartShellRelayLocked(string id) {
        if (!_shellRelays.TryGetValue(id, out MasterShellRelay? relay))
            return;
        if (_shellRelayServers.ContainsKey(id))
            return;

        ReverseTcpRelayServer server = new(relay.Id, relay.Name, relay.PublicPort, relay.AgentPort);
        server.Enabled = relay.Enabled;
        server.Log += ShellRelayServer_Log;
        try {
            server.Start();
            _shellRelayServers[id] = server;
            relay.Status = "Listening";
            relay.LastUpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            AppendShellRelayLogLocked(relay, "Relay listening on public " + relay.PublicPort.ToString(CultureInfo.InvariantCulture) + " and agent " + relay.AgentPort.ToString(CultureInfo.InvariantCulture) + ".");
        } catch (Exception ex) {
            server.Log -= ShellRelayServer_Log;
            server.Dispose();
            relay.Status = "Start failed: " + ex.Message;
            AppendShellRelayLogLocked(relay, relay.Status);
        }
    }

    private void StopShellRelayLocked(string id) {
        if (_shellRelayServers.TryGetValue(id, out ReverseTcpRelayServer? server)) {
            server.Log -= ShellRelayServer_Log;
            server.Dispose();
            _shellRelayServers.Remove(id);
        }

        if (_shellRelays.TryGetValue(id, out MasterShellRelay? relay)) {
            relay.Status = relay.Enabled ? "Stopped" : "Disabled";
            relay.ActiveSessions = 0;
            relay.WaitingAgents = 0;
            relay.WaitingPublicClients = 0;
            relay.LastUpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            AppendShellRelayLogLocked(relay, "Relay stopped.");
        }
    }

    private MasterShellRelay UpdateShellRelayRuntime(MasterShellRelay relay) {
        relay.SupportsWebSocketTunnel = true;
        relay.TransportMode = NormalizeShellProxyTransportMode(relay.TransportMode);
        relay.WebSocketTunnelUrl = BuildShellProxyTunnelEndpoint(relay.Id);
        relay.WebSocketTunnelCount = _shellProxyWebSocketTunnels.GetConnectedCount(relay.Id);
        relay.WebSocketTunnelConnected = relay.WebSocketTunnelCount > 0;
        string lastTunnelSeen = _shellProxyWebSocketTunnels.GetLastSeenUtc(relay.Id);
        if (!string.IsNullOrWhiteSpace(lastTunnelSeen))
            relay.LastTunnelSeenUtc = lastTunnelSeen;
        if (_shellRelayServers.TryGetValue(relay.Id, out ReverseTcpRelayServer? server)) {
            server.PruneDisconnectedClients();
            relay.IsRunning = server.IsRunning;
            relay.ActiveSessions = server.ActiveSessions;
            relay.WaitingAgents = server.WaitingAgents;
            relay.WaitingPublicClients = server.WaitingPublicClients;
            relay.Status = server.IsRunning ? "Listening" : relay.Status;
            if (server.IsRunning && (server.WaitingAgents > 0 || server.ActiveSessions > 0))
                relay.LastAgentSeenUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        } else {
            relay.IsRunning = false;
            relay.ActiveSessions = 0;
            relay.WaitingAgents = 0;
            relay.WaitingPublicClients = 0;
            if (!relay.Enabled)
                relay.Status = "Disabled";
        }

        return relay;
    }

    private void ShellRelayServer_Log(object? sender, ReverseTcpRelayLogEventArgs e) {
        bool serverChanged = false;
        lock (_sync) {
            if (_shellRelays.TryGetValue(e.InstanceId, out MasterShellRelay? relay)) {
                UpdateShellRelayRuntime(relay);
                AppendShellRelayLogLocked(relay, e.TimestampUtc.ToLocalTime().ToString("HH:mm:ss", CultureInfo.CurrentCulture) + " " + e.Message);
                serverChanged = UpdateShellRelayPublishedServerHealthLocked(relay, e.TimestampUtc);
                if (serverChanged)
                    _dataServer.Save();
            }
        }

        NotifyShellRelaysChanged(affectsServerList: false);
        if (serverChanged)
            NotifyServersChanged();
    }

    private static void AppendShellRelayLogLocked(MasterShellRelay relay, string message) {
        relay.DebugLines.Add(DateTime.Now.ToString("HH:mm:ss", CultureInfo.CurrentCulture) + " " + message);
        while (relay.DebugLines.Count > 300)
            relay.DebugLines.RemoveAt(0);
    }

    private void AppendShellRelayRuntimeLog(string relayId, string message) {
        lock (_sync) {
            if (_shellRelays.TryGetValue(relayId ?? "", out MasterShellRelay? relay)) {
                AppendShellRelayLogLocked(relay, message);
                relay.LastUpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            }
        }
        NotifyShellRelaysChanged(affectsServerList: false);
    }

    private static string NormalizePublicHost(string value) {
        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            return uri.Host;
        return RegisteredServer.NormalizeExternalHost(value);
    }

    private static void MapMetadataImageRoute(MutableTcpServer server) {
        MapFaviconAsset(server, "/favicon.ico", FaviconFileName);
        MapFaviconAsset(server, "/Images/favicon.ico", FaviconFileName);
        MapMetadataImageAsset(server, LegacyMetadataImageRoute, WorkstationMetadataImageFileName);
        MapMetadataImageAsset(server, WorkstationMetadataImageRoute, WorkstationMetadataImageFileName);
        MapMetadataImageAsset(server, MasterListMetadataImageRoute, WorkstationMetadataImageFileName);
        MapMetadataImageAsset(server, AutoMetadataImageRoute, AutoMetadataImageFileName);
        MapMetadataImageAsset(server, SiteIconCandidateRoute, SiteIconCandidateFileName);
        MapMetadataImageAsset(server, JackLlmWorkstationMetadataCandidateRoute, JackLlmWorkstationMetadataCandidateFileName);
        MapMetadataImageAsset(server, SocketJackLandingMetadataCandidateRoute, SocketJackLandingMetadataCandidateFileName);
        MapMetadataImageAsset(server, VisualStudioExtensionScreenshotRoute, VisualStudioExtensionScreenshotFileName);
        MapMetadataImageAsset(server, WorkstationMainApplicationScreenshotRoute, WorkstationMainApplicationScreenshotFileName);
