    private static void MapMetadataImageAsset(MutableTcpServer server, string route, string fileName) {
        server.Map("GET", route, (connection, request, cancellationToken) => BuildMetadataImageResponse(request, fileName));
        server.Map("HEAD", route, (connection, request, cancellationToken) => BuildMetadataImageResponse(request, fileName));
    }

    private static void MapFaviconAsset(MutableTcpServer server, string route, string fileName) {
        server.Map("GET", route, (connection, request, cancellationToken) => BuildStaticImageResponse(request, fileName, "image/x-icon"));
        server.Map("HEAD", route, (connection, request, cancellationToken) => BuildStaticImageResponse(request, fileName, "image/x-icon"));
    }

    private static object BuildStaticImageResponse(HttpRequest request, string fileName, string contentType) {
        byte[] bytes = MetadataImageBytes
            .GetOrAdd(fileName, name => new Lazy<byte[]>(() => LoadMetadataImageBytes(name)))
            .Value;
        if (bytes == null || bytes.Length == 0)
            return Text(request, "Image asset not found.", "text/plain; charset=utf-8", 404, "Not Found");

        request.Context.Response.Headers["Cache-Control"] = "public, max-age=86400";
        AddCors(request);
        return new FileResponse(
            string.Equals(request.Method, "HEAD", StringComparison.OrdinalIgnoreCase) ? Array.Empty<byte>() : bytes,
            contentType,
            fileName);
    }

    private static object BuildMetadataImageResponse(HttpRequest request, string fileName) {
        byte[] bytes = MetadataImageBytes
            .GetOrAdd(fileName, name => new Lazy<byte[]>(() => LoadMetadataImageBytes(name)))
            .Value;
        if (bytes == null || bytes.Length == 0)
            return Text(request, "Metadata image not found.", "text/plain; charset=utf-8", 404, "Not Found");

        request.Context.Response.Headers["Cache-Control"] = "public, max-age=86400";
        AddCors(request);
        return new FileResponse(
            string.Equals(request.Method, "HEAD", StringComparison.OrdinalIgnoreCase) ? Array.Empty<byte>() : bytes,
            "image/png",
            fileName);
    }

    private void MapRoutes() {
        MapJackLLMUpdateRoutes(_server);
        MapDownloadRoutes(_server);
        MapMetadataImageRoute(_server);
        MapAutoRoutes(_server, includePage: true);
        MapAgentBuilderRoutes(_server);

        _server.Map("GET", "/", (connection, request, cancellationToken) => {
            return Json(request, new {
                service = "SocketJack-MagicMasterList API",
                websiteUrl = _options.WebsitePublicUrl,
                publicUrl = _options.PublicUrl,
                endpoints = new[] {
                    "/healthz",
                    "/api/lmvsproxy/servers",
                    "/api/jackllm/servers",
                    "/api/lmvsproxy/server-location",
                    "/api/jackllm/server-location",
                    "/api/lmvsproxy/pricing",
                    "/api/jackllm/update",
                    "/update",
                    "/update/meta",
                    "/LlmRuntime",
                    "/MasterList",
                    "/Download",
                    "/UPDATE",
                    "/JackLLM/Update",
                    "/api/shell/proxies",
                    "/api/socketjack/video/presentation",
                    "/api/web-auth/session",
                    "/api/socketjack/oauth/session",
                    "/api/socketjack/oauth/introspect",
                    "/sql"
                }
            });
        });

        _server.Map("GET", "/api", (connection, request, cancellationToken) => {
            MasterListResponse snapshot = BuildResponse();
            return Json(request, new {
                service = "SocketJack-MagicMasterList",
                server = "SocketJack server",
                database = _options.DatabaseName,
                table = _options.TableName,
                publicUrl = snapshot.PublicUrl,
                updatedUtc = snapshot.UpdatedUtc,
                count = snapshot.Count,
                endpoints = new[] {
                    "/healthz",
                    "/api/lmvsproxy/servers",
                    "/api/jackllm/servers",
                    "/api/lmvsproxy/server-location",
                    "/api/jackllm/server-location",
                    "/api/lmvsproxy/pricing",
                    "/api/jackllm/update",
                    "/update",
                    "/update/meta",
                    "/LlmRuntime",
                    "/MasterList",
                    "/Download",
                    "/UPDATE",
                    "/JackLLM/Update",
                    "/api/shell/proxies",
                    "/api/socketjack/video/presentation",
                    "/api/web-auth/session",
                    "/api/socketjack/oauth/session",
                    "/api/socketjack/oauth/introspect",
                    "/sql"
                }
            });
        });

        _server.Map("GET", "/healthz", (connection, request, cancellationToken) => {
            return Json(request, new {
                status = _server.IsListening ? "ok" : "stopped",
                service = "SocketJack-MagicMasterList",
                server = "SocketJack server",
                publicUrl = _options.PublicUrl,
                database = _options.DatabaseName,
                count = Count(),
                checkedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });
        });

        _server.Map("GET", "/api/lmvsproxy/servers", (connection, request, cancellationToken) => {
            return Json(request, BuildResponse(request));
        });

        _server.Map("GET", "/api/jackllm/servers", (connection, request, cancellationToken) => {
            return Json(request, BuildResponse(request));
        });

        _server.Map("GET", "/api/socketjack/servers", (connection, request, cancellationToken) => {
            return Json(request, BuildResponse(request));
        });

        _server.Map("GET", "/api/socketjack-com/servers", (connection, request, cancellationToken) => {
            return Json(request, BuildResponse(request));
        });

        _server.Map("GET", "/api/socketjack/ai-servers", (connection, request, cancellationToken) => {
            return Json(request, BuildResponse(request));
        });

        MapServerLocationRoutes(_server);
        MapServerBackgroundRoutes(_server);

        _server.Map("GET", "/api/lmvsproxy/pricing", (connection, request, cancellationToken) => {
            return Json(request, BuildPricingResponse(request));
        });

        _server.Map("GET", "/api/socketjack/pricing", (connection, request, cancellationToken) => {
            return Json(request, BuildPricingResponse(request));
        });

        _server.Map("GET", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => HandleAutoPublishPreference(request, false));
        _server.Map("POST", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => HandleAutoPublishPreference(request, true));
        _server.Map("OPTIONS", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => NoContent(request));

        MapRuntimeReportRoutes(_server);
        MapSocketJackAdminApiRoutes(_server);
        MapIssueRoutes(_server, includePage: false);
        MapVideoPresentationRoutes(_server);

        _server.Map("GET", "/api/shell/instances", (connection, request, cancellationToken) => {
            return Json(request, new {
                masterHost = NormalizePublicHost(_options.PublicUrl),
                count = GetShellRelays().Count,
                instances = GetShellRelays()
            });
        });

        _server.Map("GET", "/api/shell/proxies", (connection, request, cancellationToken) => {
            return Json(request, new {
                masterHost = NormalizePublicHost(_options.PublicUrl),
                count = GetShellRelays().Count,
                proxies = GetShellRelays(),
                instances = GetShellRelays()
            });
        });

        _server.Map("POST", "/api/shell/instances", (connection, request, cancellationToken) => {
            try {
                if (string.IsNullOrWhiteSpace(request.Body))
                    return Json(request, new { error = "Request body is required." }, 400, "Bad Request");

                using JsonDocument document = JsonDocument.Parse(request.Body);
                MasterShellRelay relay = MasterShellRelay.FromJson(document.RootElement);
                MasterShellRelay saved = UpsertShellRelay(relay);
                return Json(request, new { instance = saved, instances = GetShellRelays() });
            } catch (JsonException ex) {
                return Json(request, new { error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
            } catch (InvalidOperationException ex) {
                return Json(request, new { error = "Shell relay rejected.", detail = ex.Message }, 400, "Bad Request");
            } catch (Exception ex) {
                return Json(request, new { error = "Shell relay update failed.", detail = ex.Message }, 500, "Internal Server Error");
            }
        });

        _server.Map("POST", "/api/shell/proxies", (connection, request, cancellationToken) => HandleShellProxyRequest(connection, request));

        _server.Map("POST", "/api/lmvsproxy/servers", (connection, request, cancellationToken) => {
            try {
                if (string.IsNullOrWhiteSpace(request.Body))
                    return Json(request, new { error = "Request body is required." }, 400, "Bad Request");

                using JsonDocument document = JsonDocument.Parse(request.Body);
                string remoteIp = connection?.EndPoint?.Address?.ToString() ?? "";
                RegisteredServer registered = Register(document.RootElement, remoteIp, request);
                MasterListResponse response = BuildResponse();
                return Json(request, new {
                    registered,
                    response.UpdatedUtc,
                    response.PublicUrl,
                    response.Count,
                    response.Servers
                });
            } catch (JsonException ex) {
                return Json(request, new { error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
            } catch (InvalidOperationException ex) {
                return Json(request, new { error = "Registration rejected.", detail = ex.Message }, 400, "Bad Request");
            } catch (Exception ex) {
                return Json(request, new { error = "Registration failed.", detail = ex.Message }, 500, "Internal Server Error");
            }
        });

        _server.Map("OPTIONS", "/api/lmvsproxy/servers", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/jackllm/servers", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/socketjack/servers", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/socketjack-com/servers", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/socketjack/ai-servers", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/lmvsproxy/pricing", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/socketjack/pricing", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/shell/instances", (connection, request, cancellationToken) => NoContent(request));
        _server.Map("OPTIONS", "/api/shell/proxies", (connection, request, cancellationToken) => NoContent(request));

        _server.Map("DELETE", "/api/lmvsproxy/servers/*", (connection, request, cancellationToken) => {
            string id = request.PathVariables.Count > 0 ? request.PathVariables[0] : "";
            if (string.IsNullOrWhiteSpace(id)) {
                request.QueryParameters.TryGetValue("id", out string? queryId);
                id = queryId ?? "";
            }
            if (string.IsNullOrWhiteSpace(id))
                return Json(request, new { error = "Server id is required." }, 400, "Bad Request");

            string remoteIp = connection?.EndPoint?.Address?.ToString() ?? "";
            return Remove(id, request, remoteIp, out string error)
                ? NoContent(request)
                : Json(request, new { error = error }, error.IndexOf("owner", StringComparison.OrdinalIgnoreCase) >= 0 ? 403 : 404, error.IndexOf("owner", StringComparison.OrdinalIgnoreCase) >= 0 ? "Forbidden" : "Not Found");
        });

        MapAuthRoutes(_server);
    }

    private void MapWebsiteRoutes(MutableTcpServer websiteServer) {
        MapDownloadRoutes(websiteServer);
        MapMetadataImageRoute(websiteServer);
        MapSecureAuthorityRoutes(websiteServer);
        MapAutoRoutes(websiteServer, includePage: true);
        MapDocumentationRoutes(websiteServer);
        MapIssueRoutes(websiteServer, includePage: true);
        MapAgentBuilderRoutes(websiteServer);

        websiteServer.Map("GET", "/", (connection, request, cancellationToken) => {
            if (IsWebsiteRootSignedIn(connection, request))
                return Redirect(request, "/MasterList");
            return Html(request, SocketJackLandingHtml.Value);
        });

        foreach (string landingPath in new[] { "/LlmRuntime", "/LlmRuntime/", "/llmruntime", "/llmruntime/" }) {
            websiteServer.Map("GET", landingPath, (connection, request, cancellationToken) => {
                return Html(request, SocketJackLandingHtml.Value);
            });
        }

        foreach (string masterPath in new[] { "/MasterList", "/MasterList/", "/master-list", "/master-list/" }) {
            websiteServer.Map("GET", masterPath, (connection, request, cancellationToken) => {
                return MasterListHtml(request, _masterListHtml.Value);
            });
        }

        foreach (string loginPath in new[] { "/Login", "/Login/", "/login", "/login/" }) {
            websiteServer.Map("GET", loginPath, (connection, request, cancellationToken) => {
                return MasterListHtml(request, _masterListHtml.Value);
            });
        }

        foreach (string adminPath in new[] { "/Admin", "/Admin/", "/admin", "/admin/" }) {
            websiteServer.Map("GET", adminPath, (connection, request, cancellationToken) => {
                return Html(request, BuildAdminHtml());
            });
        }

        websiteServer.Map("GET", "/healthz", (connection, request, cancellationToken) => {
            return Json(request, new {
                status = websiteServer.IsListening ? "ok" : "stopped",
                service = "SocketJack-MagicMasterList Website",
                websiteUrl = _options.WebsitePublicUrl,
                apiUrl = _options.PublicUrl,
                checkedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });
        });

        MapWebsitePublicApiRoutes(websiteServer);
        MapAuthRoutes(websiteServer);
    }

    private void MapDocumentationRoutes(MutableTcpServer server) {
        foreach (string path in new[] {
            "/Documentation", "/Documentation/", "/documentation", "/documentation/",
            "/Doc", "/Doc/", "/doc", "/doc/",
            "/Docs", "/Docs/", "/docs", "/docs/",
            "/ReadMe", "/ReadMe/", "/readme", "/readme/",
            "/Info", "/Info/", "/info", "/info/",
            "/Help", "/Help/", "/help", "/help/"
        }) {
            server.Map("GET", path, (connection, request, cancellationToken) => Html(request, BuildDocumentationHtml()));
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }

        foreach (string path in new[] {
            "/Documentation/*", "/documentation/*",
            "/Doc/*", "/doc/*",
            "/Docs/*", "/docs/*",
            "/ReadMe/*", "/readme/*",
            "/Info/*", "/info/*",
            "/Help/*", "/help/*"
        }) {
            server.Map("GET", path, (connection, request, cancellationToken) => Html(request, BuildDocumentationHtml()));
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }
    }

    private static string BuildDocumentationHtml() {
        string html = global::SocketJack.HtmlPageResources.GetHtml("Documentation.html");
        return string.IsNullOrWhiteSpace(html)
            ? "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"utf-8\"><title>SocketJack Documentation</title></head><body><h1>SocketJack Documentation</h1><p>Documentation is unavailable in this build.</p></body></html>"
            : html;
    }

