    private object HandleAutoSessionsRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        string search = FirstNonEmpty(GetQuery(request, "search"), GetQuery(request, "q")).Trim();
        bool includeArchived = ParseBool(FirstNonEmpty(GetQuery(request, "archived"), GetQuery(request, "includeArchived")), false);
        List<AutoSessionRecord> sessions = ListAutoSessionsForViewer(account, clientIp, includeArchived, search);
        return Json(request, new {
            ok = true,
            authenticated = account != null,
            username = account?.UserName ?? "",
            clientIp,
            count = sessions.Count,
            sessions,
            groups = BuildAutoSessionGroups(sessions, Array.Empty<JsonObject>()),
            suggestions = BuildAutoSessionSuggestions(sessions)
        });
    }

    internal MasterListLivePayload GetCachedMasterListLivePayload() {
        for (int attempt = 0; attempt < 3; attempt++) {
            long version = ServerListVersion;
            lock (_masterListLiveSnapshotLock) {
                if (_cachedMasterListLivePayload != null && _cachedMasterListLivePayload.Version == version)
                    return _cachedMasterListLivePayload;
            }

            MasterListLivePayload payload = BuildMasterListLivePayload(version);
            if (ServerListVersion != version)
                continue;

            lock (_masterListLiveSnapshotLock) {
                if (_cachedMasterListLivePayload == null || _cachedMasterListLivePayload.Version != version)
                    _cachedMasterListLivePayload = payload;
                return _cachedMasterListLivePayload;
            }
        }

        long latestVersion = ServerListVersion;
        MasterListLivePayload latestPayload = BuildMasterListLivePayload(latestVersion);
        lock (_masterListLiveSnapshotLock) {
            _cachedMasterListLivePayload = latestPayload;
            return _cachedMasterListLivePayload;
        }
    }

    private MasterListLivePayload BuildMasterListLivePayload(long version) {
        MasterListResponse response = BuildResponse();
        JsonObject output = CreateMasterListLiveSnapshot(response, "", version);
        string json = output.ToJsonString(MasterListJson.Options);
        byte[] bytes = Encoding.UTF8.GetBytes(json);
        string signature = Convert.ToBase64String(SHA256.HashData(bytes));
        return new MasterListLivePayload(version, signature, bytes);
    }

    private JsonObject BuildLiveWebSocketSnapshot(NetworkConnection connection, IReadOnlyDictionary<string, string> headers, string page, string queryString, JsonObject? clientRequest) {
        page = (page ?? "").Trim().ToLowerInvariant();
        if (page.Equals("masterlist", StringComparison.Ordinal))
            return BuildMasterListLiveSnapshot(clientRequest);
        return BuildAutoLiveSnapshot(connection, headers, queryString, clientRequest);
    }

    private JsonObject BuildMasterListLiveSnapshot(JsonObject? clientRequest) {
        MasterListResponse response = BuildResponse();
        string requestId = JsonText(clientRequest, "id", JsonText(clientRequest, "requestId", ""));
        return CreateMasterListLiveSnapshot(response, requestId, ServerListVersion);
    }

    private JsonObject CreateMasterListLiveSnapshot(MasterListResponse response, string requestId, long version) {
        var output = new JsonObject {
            ["ok"] = true,
            ["type"] = "snapshot",
            ["topic"] = "servers",
            ["page"] = "masterlist",
            ["version"] = version,
            ["updatedUtc"] = response.UpdatedUtc,
            ["count"] = response.Count,
            ["publicUrl"] = response.PublicUrl,
            ["servers"] = JsonSerializer.SerializeToNode(response.Servers, MasterListJson.Options)
        };
        if (!string.IsNullOrWhiteSpace(requestId))
            output["requestId"] = requestId;
        output["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        return output;
    }

    private JsonObject BuildAutoLiveSnapshot(NetworkConnection connection, IReadOnlyDictionary<string, string> headers, string queryString, JsonObject? clientRequest) {
        AccountRecord? account = AuthenticateWebSocketHeaders(headers, clientRequest, out _);
        string clientIp = ExtractClientIp(connection, headers);
        MergeAutoSessionsForAccount(account, clientIp);

        Dictionary<string, string> query = ParseWebSocketQueryString(queryString);
        string search = FirstNonEmpty(
            JsonText(clientRequest, "search", ""),
            QueryValue(query, "search"),
            QueryValue(query, "q")).Trim();
        bool includeArchived = ParseBool(FirstNonEmpty(
            JsonText(clientRequest, "includeArchived", ""),
            JsonText(clientRequest, "archived", ""),
            QueryValue(query, "includeArchived"),
            QueryValue(query, "archived")), false);
        bool includeServerSessions = ParseBool(FirstNonEmpty(
            JsonText(clientRequest, "includeServerSessions", ""),
            QueryValue(query, "includeServerSessions")), true);

        List<AutoSessionRecord> sessions = ListAutoSessionsForViewer(account, clientIp, includeArchived, search);
        List<JsonObject> serverOnlySessions = includeServerSessions && account != null
            ? DiscoverServerOnlyAutoSessions(sessions, search, query, clientRequest)
            : new List<JsonObject>();
        MasterListResponse serverResponse = BuildResponse();

        string requestId = JsonText(clientRequest, "id", JsonText(clientRequest, "requestId", ""));
        var output = new JsonObject {
            ["ok"] = true,
            ["type"] = "snapshot",
            ["topic"] = "auto-sessions",
            ["page"] = "auto",
            ["authenticated"] = account != null,
            ["username"] = account?.UserName ?? "",
            ["clientIp"] = clientIp,
            ["count"] = sessions.Count,
            ["serverOnlyCount"] = serverOnlySessions.Count,
            ["sessions"] = JsonSerializer.SerializeToNode(sessions, MasterListJson.Options),
            ["serverOnlySessions"] = new JsonArray(serverOnlySessions.Select(item => item.DeepClone()).ToArray()),
            ["groups"] = BuildAutoSessionGroups(sessions, serverOnlySessions),
            ["suggestions"] = JsonSerializer.SerializeToNode(BuildAutoSessionSuggestions(sessions), MasterListJson.Options),
            ["modelCache"] = JsonSerializer.SerializeToNode(new {
                version = ServerListVersion,
                updatedUtc = serverResponse.UpdatedUtc,
                servers = serverResponse.Servers
            }, MasterListJson.Options),
            ["usage"] = account == null
                ? JsonSerializer.SerializeToNode(BuildAnonymousUsage(), MasterListJson.Options)
                : JsonSerializer.SerializeToNode(BuildUsage(account), MasterListJson.Options),
            ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
        };
        if (!string.IsNullOrWhiteSpace(requestId))
            output["requestId"] = requestId;
        return output;
    }

    private JsonObject HandleAutoLiveSessionImport(NetworkConnection connection, IReadOnlyDictionary<string, string> headers, JsonObject? clientRequest) {
        string requestId = JsonText(clientRequest, "id", JsonText(clientRequest, "requestId", ""));
        AccountRecord? account = AuthenticateWebSocketHeaders(headers, clientRequest, out string authError);
        if (account == null) {
            return new JsonObject {
                ["ok"] = false,
                ["type"] = "error",
                ["topic"] = "auto-sessions",
                ["requestId"] = requestId,
                ["statusCode"] = 401,
                ["error"] = string.IsNullOrWhiteSpace(authError) ? "SocketJack login required." : authError
            };
        }

        JsonObject? source = clientRequest?["session"] as JsonObject;
        if (source == null) {
            return new JsonObject {
                ["ok"] = false,
                ["type"] = "error",
                ["topic"] = "auto-sessions",
                ["requestId"] = requestId,
                ["statusCode"] = 400,
                ["error"] = "Session import payload is required."
            };
        }

        try {
            using JsonDocument document = JsonDocument.Parse(source.ToJsonString(MasterListJson.Options));
            AutoSessionRecord session = AutoSessionFromJson(document.RootElement);
            string requestedId = FirstNonEmpty(JsonText(clientRequest, "newSessionId", ""), JsonText(clientRequest, "autoSessionId", ""));
            if (!string.IsNullOrWhiteSpace(requestedId))
                session.Id = requestedId;
            if (string.IsNullOrWhiteSpace(session.Id) || session.Id.StartsWith("server_", StringComparison.OrdinalIgnoreCase))
                session.Id = "auto_" + Guid.NewGuid().ToString("N");
            if (string.IsNullOrWhiteSpace(session.Title))
                session.Title = FirstNonEmpty(JsonText(source, "title", ""), "Imported server session");
            if (string.IsNullOrWhiteSpace(session.PreviewText))
                session.PreviewText = "Imported from " + FirstNonEmpty(session.ServerTitle, session.ServerId, "LLM server") + ".";
            if (session.MessageCount <= 0)
                session.MessageCount = 1;

            string clientIp = ExtractClientIp(connection, headers);
            MergeAutoSessionsForAccount(account, clientIp);
            AutoSessionRecord saved = SaveAutoSessionForViewer(session, account, clientIp);
            return new JsonObject {
                ["ok"] = true,
                ["type"] = "session-imported",
                ["topic"] = "auto-sessions",
                ["requestId"] = requestId,
                ["authenticated"] = true,
                ["username"] = account.UserName,
                ["session"] = JsonSerializer.SerializeToNode(saved, MasterListJson.Options),
                ["sentUtc"] = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        } catch (Exception ex) {
            return new JsonObject {
                ["ok"] = false,
                ["type"] = "error",
                ["topic"] = "auto-sessions",
                ["requestId"] = requestId,
                ["statusCode"] = 400,
                ["error"] = ex.Message
            };
        }
    }

    private JsonArray BuildAutoSessionGroups(List<AutoSessionRecord> sessions, IReadOnlyList<JsonObject> serverOnlySessions) {
        var groups = new Dictionary<string, JsonObject>(StringComparer.OrdinalIgnoreCase);

        JsonObject GetGroup(string serverId, string serverTitle) {
            serverId = FirstNonEmpty(serverId, "unknown").Trim();
            serverTitle = FirstNonEmpty(serverTitle, serverId, "Unknown server").Trim();
            string key = serverId.ToLowerInvariant();
            if (!groups.TryGetValue(key, out JsonObject? group)) {
                group = new JsonObject {
                    ["serverId"] = serverId,
                    ["serverTitle"] = serverTitle,
                    ["count"] = 0,
                    ["masterCount"] = 0,
                    ["serverOnlyCount"] = 0,
                    ["sessions"] = new JsonArray()
                };
                groups[key] = group;
            }
            return group;
        }

        foreach (AutoSessionRecord session in sessions ?? new List<AutoSessionRecord>()) {
            JsonObject group = GetGroup(session.ServerId, session.ServerTitle);
            JsonArray items = group["sessions"] as JsonArray ?? new JsonArray();
            JsonObject sessionJson = JsonSerializer.SerializeToNode(session, MasterListJson.Options) as JsonObject ?? new JsonObject();
            sessionJson["source"] = "master";
            items.Add(sessionJson);
            group["sessions"] = items;
            group["count"] = (int?)group["count"] + 1 ?? 1;
            group["masterCount"] = (int?)group["masterCount"] + 1 ?? 1;
        }

        foreach (JsonObject serverSession in serverOnlySessions ?? Array.Empty<JsonObject>()) {
            string serverId = JsonText(serverSession, "serverId", "unknown");
            string serverTitle = JsonText(serverSession, "serverTitle", serverId);
            JsonObject group = GetGroup(serverId, serverTitle);
            JsonArray items = group["sessions"] as JsonArray ?? new JsonArray();
            JsonObject clone = serverSession.DeepClone() as JsonObject ?? new JsonObject();
            clone["source"] = "server";
            items.Add(clone);
            group["sessions"] = items;
            group["count"] = (int?)group["count"] + 1 ?? 1;
            group["serverOnlyCount"] = (int?)group["serverOnlyCount"] + 1 ?? 1;
        }

        var array = new JsonArray();
        foreach (JsonObject group in groups.Values
            .OrderByDescending(group => (int?)group["count"] ?? 0)
            .ThenBy(group => JsonText(group, "serverTitle", ""), StringComparer.OrdinalIgnoreCase)) {
            array.Add(group);
        }
        return array;
    }

    private List<JsonObject> DiscoverServerOnlyAutoSessions(List<AutoSessionRecord> masterSessions, string search, IReadOnlyDictionary<string, string> query, JsonObject? clientRequest) {
        var results = new List<JsonObject>();
        string selectedServer = FirstNonEmpty(
            JsonText(clientRequest, "serverId", ""),
            JsonText(clientRequest, "server", ""),
            JsonText(clientRequest, "server_id", ""),
            QueryValue(query, "serverId"),
            QueryValue(query, "server"),
            QueryValue(query, "server_id")).Trim();

        HashSet<string> masterSessionIds = new((masterSessions ?? new List<AutoSessionRecord>())
            .Select(session => session.Id)
            .Where(id => !string.IsNullOrWhiteSpace(id)), StringComparer.OrdinalIgnoreCase);

        List<MasterShellRelay> relays;
        DateTimeOffset now = DateTimeOffset.UtcNow;
        lock (_sync) {
            relays = _shellRelays.Values
                .Where(relay => relay.Enabled && relay.IsRunning)
                .Where(relay => string.IsNullOrWhiteSpace(selectedServer) ||
                    string.Equals(relay.ServerId, selectedServer, StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(relay.RouteName, selectedServer, StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(relay.Id, selectedServer, StringComparison.OrdinalIgnoreCase))
                .Select(relay => relay.Clone())
                .ToList();
        }

        foreach (MasterShellRelay relay in relays
            .Where(relay => _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id) || ShouldAttemptShellProxyForward(relay, now))
            .Take(string.IsNullOrWhiteSpace(selectedServer) ? 4 : 1)) {
            try {
                ShellProxyJsonFetchResult fetch = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)
                    ? _shellProxyWebSocketTunnels.FetchJson(relay, "/api/chat-sessions", "", CancellationToken.None)
                    : FetchShellProxyJsonForWebSocket(relay, "/api/chat-sessions", "", CancellationToken.None);
                if (fetch.StatusCode < 200 || fetch.StatusCode >= 300 || string.IsNullOrWhiteSpace(fetch.Body))
                    continue;

                JsonObject data = ParseShellProxyJsonObject(fetch.Body);
                if (!(data["sessions"] is JsonArray sessions))
                    continue;

                RegisteredServer? server = FindRegisteredServerForShellRelay(relay);
                string serverTitle = FirstNonEmpty(server?.Title ?? "", server?.DisplayName ?? "", relay.Name, relay.ServerId, relay.RouteName);
                foreach (JsonNode? item in sessions.Take(60)) {
                    if (item is not JsonObject session)
                        continue;
                    string chatId = FirstNonEmpty(JsonText(session, "id", ""), JsonText(session, "sessionId", ""));
                    if (string.IsNullOrWhiteSpace(chatId) || masterSessionIds.Contains(chatId))
                        continue;

                    string title = FirstNonEmpty(JsonText(session, "title", ""), "Server chat session");
                    string model = JsonText(session, "model", "");
                    string preview = FirstNonEmpty(JsonText(session, "previewText", ""), model);
                    if (!AutoServerSessionMatchesSearch(title, preview, model, serverTitle, search))
                        continue;

                    results.Add(new JsonObject {
                        ["id"] = "server_" + SanitizeAutoSessionId(relay.Id + "_" + chatId),
                        ["serverSessionId"] = chatId,
                        ["source"] = "server",
                        ["title"] = title,
                        ["createdUtc"] = JsonText(session, "createdUtc", ""),
                        ["updatedUtc"] = JsonText(session, "updatedUtc", ""),
                        ["lastMode"] = "tools",
                        ["originMode"] = "hybrid",
                        ["billingTier"] = "Free",
                        ["tokenCost"] = 0,
                        ["serverId"] = FirstNonEmpty(relay.ServerId, relay.Id, relay.RouteName),
                        ["serverTitle"] = serverTitle,
                        ["serverHardwareSummary"] = server?.AvailableResources ?? "",
                        ["serverContinueUrl"] = BuildShellProxyEndpoint(relay.RouteName),
                        ["modelUsed"] = model,
                        ["messageCount"] = ParseInt(JsonText(session, "messageCount", "0"), 0, 0, int.MaxValue),
                        ["messageLength"] = 0,
                        ["previewText"] = FirstNonEmpty(preview, "Stored on " + serverTitle + ". Click to import this server session into /Auto."),
                        ["relayId"] = relay.Id,
                        ["routeName"] = relay.RouteName,
                        ["muted"] = true
                    });
                }
            } catch {
            }
        }

        return results
            .GroupBy(item => JsonText(item, "serverSessionId", JsonText(item, "id", "")), StringComparer.OrdinalIgnoreCase)
            .Select(group => group.First())
            .OrderByDescending(item => JsonText(item, "updatedUtc", ""))
            .Take(120)
            .ToList();
    }

    private static bool AutoServerSessionMatchesSearch(string title, string preview, string model, string serverTitle, string search) {
        if (string.IsNullOrWhiteSpace(search))
            return true;
        string haystack = string.Join("\n", title, preview, model, serverTitle);
        try {
            return new Regex(search, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant, TimeSpan.FromMilliseconds(100)).IsMatch(haystack);
        } catch {
            return haystack.Contains(search, StringComparison.OrdinalIgnoreCase);
        }
    }

    private object HandleAutoSessionSaveRequest(NetworkConnection connection, HttpRequest request) {
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Session body is required." }, 400, "Bad Request");

        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            AutoSessionRecord session = AutoSessionFromJson(document.RootElement);
            AutoSessionRecord saved = SaveAutoSessionForViewer(session, account, clientIp);
            return Json(request, new { ok = true, session = saved });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid session JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (InvalidOperationException ex) {
            return Json(request, new { ok = false, error = ex.Message }, 403, "Forbidden");
        }
    }

    private object HandleAutoSessionActionRequest(NetworkConnection connection, HttpRequest request) {
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Session action body is required." }, 400, "Bad Request");

        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            string id = FirstNonEmpty(GetJsonString(root, "id"), GetJsonString(root, "sessionId"));
            string action = FirstNonEmpty(GetJsonString(root, "action"), "rename").Trim().ToLowerInvariant();
            string title = GetJsonString(root, "title");
            AutoSessionRecord? session = ApplyAutoSessionAction(id, action, title, account, clientIp);
            return Json(request, new { ok = true, action, session });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid session action JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (InvalidOperationException ex) {
            return Json(request, new { ok = false, error = ex.Message }, 400, "Bad Request");
        }
    }

    private object HandleAutoSessionFilesRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return AutoSessionFileLoginRequired(request, authError);

        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        string sessionId = SanitizeAutoSessionId(FirstNonEmpty(GetQuery(request, "sessionId"), GetQuery(request, "autoSession"), GetQuery(request, "id")));
        if (string.IsNullOrWhiteSpace(sessionId))
            return Json(request, new { ok = false, error = "Session id is required." }, 400, "Bad Request");
        if (!AutoSessionFilesVisibleToViewer(sessionId, account, clientIp))
            return Json(request, new { ok = false, error = "Auto session files are not available to this viewer." }, 403, "Forbidden");

        object[] files = ListAutoSessionFileEntries(request, sessionId);
        return Json(request, new {
            ok = true,
            authenticated = true,
            username = account.UserName,
            sessionId,
            count = files.Length,
            files
        });
    }

    private object HandleAutoSessionFileUploadRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return AutoSessionFileLoginRequired(request, authError);
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "File upload body is required." }, 400, "Bad Request");

        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            string sessionId = SanitizeAutoSessionId(FirstNonEmpty(GetJsonString(root, "sessionId"), GetJsonString(root, "autoSession"), GetQuery(request, "sessionId")));
            if (string.IsNullOrWhiteSpace(sessionId))
                return Json(request, new { ok = false, error = "Session id is required." }, 400, "Bad Request");
            if (!AutoSessionFilesVisibleToViewer(sessionId, account, clientIp))
                return Json(request, new { ok = false, error = "Auto session files are not available to this viewer." }, 403, "Forbidden");

            string mediaType = FirstNonEmpty(GetJsonString(root, "mimeType"), GetJsonString(root, "mediaType"), "application/octet-stream");
            string base64 = FirstNonEmpty(GetJsonString(root, "base64"), GetJsonString(root, "contentBase64"));
            string dataUrl = FirstNonEmpty(GetJsonString(root, "dataUrl"), GetJsonString(root, "contentDataUrl"));
            if (!string.IsNullOrWhiteSpace(dataUrl) &&
                !TryExtractDataUrlPayload(dataUrl, out base64, out mediaType, out string dataUrlError))
                return Json(request, new { ok = false, error = dataUrlError }, 400, "Bad Request");
            if (string.IsNullOrWhiteSpace(base64))
                return Json(request, new { ok = false, error = "A dataUrl or base64 file payload is required." }, 400, "Bad Request");

            byte[] bytes;
            try {
                bytes = Convert.FromBase64String(base64.Trim());
            } catch (FormatException ex) {
                return Json(request, new { ok = false, error = "File content is not valid base64.", detail = ex.Message }, 400, "Bad Request");
            }
            if (bytes.Length == 0)
                return Json(request, new { ok = false, error = "Uploaded file is empty." }, 400, "Bad Request");
            if (bytes.Length > 52_428_800)
                return Json(request, new { ok = false, error = "Uploaded file is too large for Auto session storage. Limit: 50 MB." }, 413, "Payload Too Large");

            string fileName = SanitizeAutoSessionRelativeFilePath(
                FirstNonEmpty(GetJsonString(root, "fileName"), GetJsonString(root, "filename"), GetJsonString(root, "name"), "upload"),
                mediaType,
                FirstNonEmpty(GetJsonString(root, "folder"), GetJsonString(root, "directory"), GetJsonString(root, "subdirectory")));
            string directory = AutoSessionFilesDirectory(sessionId);
            Directory.CreateDirectory(directory);
            string requestedPath = Path.Combine(directory, fileName.Replace('/', Path.DirectorySeparatorChar));
            if (!TryResolveAutoSessionFilePath(directory, requestedPath, out string resolvedRequestedPath))
                return Json(request, new { ok = false, error = "File path is outside the Auto session storage directory." }, 400, "Bad Request");
            string targetDirectory = Path.GetDirectoryName(resolvedRequestedPath) ?? directory;
            Directory.CreateDirectory(targetDirectory);
            string path = BuildUniqueAutoSessionFilePath(targetDirectory, Path.GetFileName(resolvedRequestedPath));
            File.WriteAllBytes(path, bytes);

            FileInfo file = new(path);
            return Json(request, new {
                ok = true,
                authenticated = true,
                username = account.UserName,
                sessionId,
                file = BuildAutoSessionFileEntry(request, sessionId, directory, file)
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid file upload JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "File upload failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private object HandleAutoSessionFilesRestoreRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return AutoSessionFileLoginRequired(request, authError);
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Session file restore body is required." }, 400, "Bad Request");

        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            string sessionId = SanitizeAutoSessionId(FirstNonEmpty(GetJsonString(root, "sessionId"), GetJsonString(root, "autoSession"), GetQuery(request, "sessionId")));
            if (string.IsNullOrWhiteSpace(sessionId))
                return Json(request, new { ok = false, error = "Session id is required." }, 400, "Bad Request");
            if (!AutoSessionFilesVisibleToViewer(sessionId, account, clientIp))
                return Json(request, new { ok = false, error = "Auto session files are not available to this viewer." }, 403, "Forbidden");

            JsonElement filesElement = default;
            bool hasFiles = root.ValueKind == JsonValueKind.Object && (
                root.TryGetProperty("files", out filesElement) ||
                root.TryGetProperty("snapshot", out filesElement) ||
                root.TryGetProperty("items", out filesElement));
            if (!hasFiles || filesElement.ValueKind != JsonValueKind.Array)
                return Json(request, new { ok = false, error = "Restore files must be an array." }, 400, "Bad Request");

            string directory = AutoSessionFilesDirectory(sessionId);
            Directory.CreateDirectory(directory);
            string directoryFull = Path.GetFullPath(directory);
            var restoreNames = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var restorePayloads = new List<(string Name, string MediaType, byte[] Bytes, DateTimeOffset? LastWriteUtc)>();
            long totalBytes = 0;

            foreach (JsonElement item in filesElement.EnumerateArray()) {
                if (item.ValueKind != JsonValueKind.Object)
                    continue;
                string mediaType = FirstNonEmpty(GetJsonString(item, "mimeType"), GetJsonString(item, "mediaType"), "application/octet-stream");
                string name = SanitizeAutoSessionRelativeFilePath(
                    FirstNonEmpty(GetJsonString(item, "name"), GetJsonString(item, "fileName"), GetJsonString(item, "filename"), GetJsonString(item, "path")),
                    mediaType,
                    FirstNonEmpty(GetJsonString(item, "folder"), GetJsonString(item, "directory"), GetJsonString(item, "subdirectory")));
                if (string.IsNullOrWhiteSpace(name) || restoreNames.Contains(name))
                    continue;
                string base64 = FirstNonEmpty(GetJsonString(item, "base64"), GetJsonString(item, "contentBase64"));
                string dataUrl = FirstNonEmpty(GetJsonString(item, "dataUrl"), GetJsonString(item, "contentDataUrl"));
                if (!string.IsNullOrWhiteSpace(dataUrl) &&
                    !TryExtractDataUrlPayload(dataUrl, out base64, out mediaType, out string dataUrlError))
                    return Json(request, new { ok = false, error = dataUrlError }, 400, "Bad Request");
                if (string.IsNullOrWhiteSpace(base64))
                    return Json(request, new { ok = false, error = "Restore file payload is missing base64 data.", name }, 400, "Bad Request");

                byte[] bytes;
                try {
                    bytes = Convert.FromBase64String(base64.Trim());
                } catch (FormatException ex) {
                    return Json(request, new { ok = false, error = "Restore file content is not valid base64.", name, detail = ex.Message }, 400, "Bad Request");
                }
                if (bytes.Length > 52_428_800)
                    return Json(request, new { ok = false, error = "Restore file is too large. Limit: 50 MB.", name }, 413, "Payload Too Large");
                totalBytes += bytes.LongLength;
                if (totalBytes > 1_610_612_736L)
                    return Json(request, new { ok = false, error = "Restore would exceed the Auto session storage snapshot limit." }, 413, "Payload Too Large");

                DateTimeOffset? lastWriteUtc = null;
                string lastWriteText = FirstNonEmpty(GetJsonString(item, "lastWriteUtc"), GetJsonString(item, "uploadedUtc"), GetJsonString(item, "updatedUtc"));
                if (DateTimeOffset.TryParse(lastWriteText, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal | DateTimeStyles.AdjustToUniversal, out DateTimeOffset parsedLastWrite))
                    lastWriteUtc = parsedLastWrite;

                restoreNames.Add(name);
                restorePayloads.Add((name, mediaType, bytes, lastWriteUtc));
            }

            int removed = 0;
            foreach (FileInfo existing in EnumerateAutoSessionFiles(directoryFull)) {
                string existingRelativePath = AutoSessionRelativeFilePath(directoryFull, existing);
                if (restoreNames.Contains(existingRelativePath))
                    continue;
                try {
                    existing.Delete();
                    removed++;
                } catch {
                }
            }

            int restored = 0;
            foreach ((string name, string mediaType, byte[] bytes, DateTimeOffset? lastWriteUtc) in restorePayloads) {
                string path = Path.Combine(directoryFull, name.Replace('/', Path.DirectorySeparatorChar));
                if (!TryResolveAutoSessionFilePath(directoryFull, path, out string resolvedPath))
                    continue;
                Directory.CreateDirectory(Path.GetDirectoryName(resolvedPath) ?? directoryFull);
                File.WriteAllBytes(resolvedPath, bytes);
                if (lastWriteUtc.HasValue)
                    File.SetLastWriteTimeUtc(resolvedPath, lastWriteUtc.Value.UtcDateTime);
                restored++;
            }
            RemoveEmptyAutoSessionDirectories(directoryFull);

            object[] files = ListAutoSessionFileEntries(request, sessionId);
            return Json(request, new {
                ok = true,
                authenticated = true,
                username = account.UserName,
                sessionId,
                restored,
                removed,
                count = files.Length,
                files
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid session file restore JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Session file restore failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private object HandleAutoSessionFileDownloadRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return AutoSessionFileLoginRequired(request, authError);

        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        string sessionId = SanitizeAutoSessionId(FirstNonEmpty(GetQuery(request, "sessionId"), GetQuery(request, "autoSession"), GetQuery(request, "id")));
        string fileName = SanitizeAutoSessionRelativeFilePath(FirstNonEmpty(GetQuery(request, "name"), GetQuery(request, "fileName"), GetQuery(request, "file")), "");
        if (string.IsNullOrWhiteSpace(sessionId) || string.IsNullOrWhiteSpace(fileName))
            return Json(request, new { ok = false, error = "Session id and file name are required." }, 400, "Bad Request");
        if (!AutoSessionFilesVisibleToViewer(sessionId, account, clientIp))
            return Json(request, new { ok = false, error = "Auto session files are not available to this viewer." }, 403, "Forbidden");

        string directory = AutoSessionFilesDirectory(sessionId);
        string filePath = Path.Combine(directory, fileName.Replace('/', Path.DirectorySeparatorChar));
        if (!TryResolveAutoSessionFilePath(directory, filePath, out string resolvedPath) || !File.Exists(resolvedPath))
            return Json(request, new { ok = false, error = "Auto session file was not found." }, 404, "Not Found");

        AddCors(request);
        string contentType = AutoSessionMimeType(Path.GetExtension(resolvedPath));
        string disposition = ParseBool(FirstNonEmpty(GetQuery(request, "download")), false) ? "attachment" : "inline";
        request.Context.Response.Headers["Cache-Control"] = "private, no-store";
        request.Context.Response.Headers["Content-Disposition"] = disposition + "; filename=\"" + Path.GetFileName(resolvedPath).Replace("\"", "", StringComparison.Ordinal) + "\"";
        FileResponse response = FileResponse.FromFile(resolvedPath);
        response.ContentType = contentType;
        return response;
    }

    private object HandleAutoSessionFileDeleteRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return AutoSessionFileLoginRequired(request, authError);

        string bodySessionId = "";
        string bodyFileName = "";
        if (!string.IsNullOrWhiteSpace(request.Body)) {
            try {
                using JsonDocument document = JsonDocument.Parse(request.Body);
                JsonElement root = document.RootElement;
                bodySessionId = FirstNonEmpty(GetJsonString(root, "sessionId"), GetJsonString(root, "autoSession"), GetJsonString(root, "id"));
                bodyFileName = FirstNonEmpty(GetJsonString(root, "name"), GetJsonString(root, "fileName"), GetJsonString(root, "filename"), GetJsonString(root, "file"));
            } catch (JsonException ex) {
                return Json(request, new { ok = false, error = "Invalid file delete JSON.", detail = ex.Message }, 400, "Bad Request");
            }
        }

        string clientIp = ExtractClientIp(connection, request);
        MergeAutoSessionsForAccount(account, clientIp);
        string sessionId = SanitizeAutoSessionId(FirstNonEmpty(GetQuery(request, "sessionId"), GetQuery(request, "autoSession"), GetQuery(request, "id"), bodySessionId));
        string fileName = SanitizeAutoSessionRelativeFilePath(FirstNonEmpty(GetQuery(request, "name"), GetQuery(request, "fileName"), GetQuery(request, "file"), bodyFileName), "");
        if (string.IsNullOrWhiteSpace(sessionId) || string.IsNullOrWhiteSpace(fileName))
            return Json(request, new { ok = false, error = "Session id and file name are required." }, 400, "Bad Request");
        if (!AutoSessionFilesVisibleToViewer(sessionId, account, clientIp))
            return Json(request, new { ok = false, error = "Auto session files are not available to this viewer." }, 403, "Forbidden");

        string directory = AutoSessionFilesDirectory(sessionId);
        string filePath = Path.Combine(directory, fileName.Replace('/', Path.DirectorySeparatorChar));
        if (!TryResolveAutoSessionFilePath(directory, filePath, out string resolvedPath) || !File.Exists(resolvedPath))
            return Json(request, new { ok = false, error = "Auto session file was not found." }, 404, "Not Found");

        try {
            File.Delete(resolvedPath);
            RemoveEmptyAutoSessionDirectories(directory);
            return Json(request, new {
                ok = true,
                authenticated = true,
                username = account.UserName,
                sessionId,
                name = fileName,
                removed = true
            });
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Auto session file could not be removed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private object AutoSessionFileLoginRequired(HttpRequest request, string authError) {
        string returnUrl = (request.Path ?? "/Auto") + (string.IsNullOrWhiteSpace(request.QueryString) ? "" : "?" + request.QueryString);
        return Json(request, new {
            ok = false,
            code = "auto_file_login_required",
            error = string.IsNullOrWhiteSpace(authError) || authError.Contains("expired", StringComparison.OrdinalIgnoreCase)
                ? "SocketJack.com login is required to upload or view Auto session files."
                : authError,
            loginUrl = BuildSocketJackLoginPath(returnUrl),
            authenticated = false,
            username = ""
        }, 401, "Unauthorized");
    }

    private object HandleIssueSessionsRequest(NetworkConnection connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        string search = FirstNonEmpty(GetQuery(request, "search"), GetQuery(request, "q")).Trim();
        bool includeArchived = ParseBool(FirstNonEmpty(GetQuery(request, "archived"), GetQuery(request, "includeArchived")), false);
        List<SocketJackIssueSession> sessions = ListIssueSessionsForViewer(account, clientIp, includeArchived, search);
