            ok = true,
            authenticated = account != null,
            username = account?.UserName ?? "",
            clientIp,
            documentationUrl = BuildAbsoluteWebsiteUrl("/Documentation"),
            issuePrompt = BuildIssueAssistantPrompt(),
            count = sessions.Count,
            sessions
        });
    }

    private object HandleIssueSessionSaveRequest(NetworkConnection connection, HttpRequest request) {
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Issue session body is required." }, 400, "Bad Request");

        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            SocketJackIssueSession session = IssueSessionFromJson(document.RootElement);
            SocketJackIssueSession saved = SaveIssueSessionForViewer(session, account, clientIp);
            return Json(request, new { ok = true, session = saved });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid issue session JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (InvalidOperationException ex) {
            return Json(request, new { ok = false, error = ex.Message }, 400, "Bad Request");
        }
    }

    private object HandleIssueReportRequest(NetworkConnection connection, HttpRequest request) {
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Issue report body is required." }, 400, "Bad Request");

        AccountRecord? account = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            SocketJackIssueReport report = IssueReportFromJson(document.RootElement);
            report.OwnerUserName = FirstNonEmpty(account?.UserName, ExtractRememberedUserName(request));
            report.ClientIp = clientIp;
            report.UserAgent = GetHeaderValue(request, "User-Agent");
            SaveIssueReport(report);
            AppendMasterLog(
                "info",
                "issue-report",
                "Issue report received: " + report.Title,
                "screenshots=" + report.ScreenshotCount.ToString(CultureInfo.InvariantCulture) + "; lines=" + report.ErrorLineCount.ToString(CultureInfo.InvariantCulture),
                report.OwnerUserName,
                clientIp,
                request.Path ?? "");
            return Json(request, new { ok = true, reportId = report.Id, savedUtc = report.CreatedUtc });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid issue report JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (InvalidOperationException ex) {
            int status = ex.Message.Contains("10,000", StringComparison.OrdinalIgnoreCase) || ex.Message.Contains("screenshot", StringComparison.OrdinalIgnoreCase) ? 413 : 400;
            return Json(request, new { ok = false, error = ex.Message }, status, status == 413 ? "Payload Too Large" : "Bad Request");
        } catch (Exception ex) {
            AppendMasterLog("error", "issue-report", "Issue report failed.", ex.Message, "", clientIp, request.Path ?? "");
            return Json(request, new { ok = false, error = "Issue report failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleSocketJackAdminIssues(NetworkConnection connection, HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (!IsJackAdministrator(admin))
            return Json(request, new { ok = false, error = "JACK administrator login required." }, 403, "Forbidden");

        int take = ClampAdminTake(GetQueryValue(request, "take"), 200);
        return Json(request, new {
            ok = true,
            username = admin?.UserName ?? "",
            jackOnly = true,
            count = CountIssueReports(),
            issues = ListIssueReports(take)
        });
    }

    private List<SocketJackIssueSession> ListIssueSessionsForViewer(AccountRecord? account, string clientIp, bool includeArchived, string search) {
        lock (_sync) {
            return _issueSessionsTable.Rows
                .Select(IssueSessionFromRow)
                .Where(session => !session.Deleted)
                .Where(session => includeArchived || !session.Archived)
                .Where(session => IssueSessionVisibleToViewer(session, account, clientIp))
                .Where(session => IssueSessionMatchesSearch(session, search))
                .OrderByDescending(session => session.UpdatedUtc, StringComparer.Ordinal)
                .Take(250)
                .ToList();
        }
    }

    private SocketJackIssueSession SaveIssueSessionForViewer(SocketJackIssueSession session, AccountRecord? account, string clientIp) {
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        if (string.IsNullOrWhiteSpace(session.Id))
            session.Id = "issue_session_" + Guid.NewGuid().ToString("N");
        session.Id = SanitizeIssueId(session.Id, "issue_session");
        if (string.IsNullOrWhiteSpace(session.CreatedUtc))
            session.CreatedUtc = now;
        session.UpdatedUtc = now;
        session.OwnerUserName = account?.UserName ?? "";
        session.ClientIp = clientIp ?? "";
        NormalizeIssueSession(session);

        lock (_sync) {
            int existingIndex = FindIssueSessionRowIndexLocked(session.Id);
            if (existingIndex >= 0) {
                SocketJackIssueSession existing = IssueSessionFromRow(_issueSessionsTable.Rows[existingIndex]);
                if (!IssueSessionVisibleToViewer(existing, account, clientIp ?? ""))
                    throw new InvalidOperationException("Issue session is not available to this viewer.");
                session.CreatedUtc = FirstNonEmpty(existing.CreatedUtc, session.CreatedUtc);
                session.Archived = session.Archived || existing.Archived;
                session.Deleted = session.Deleted || existing.Deleted;
                _issueSessionsTable.Rows[existingIndex] = IssueSessionToRow(session);
            } else {
                _issueSessionsTable.Rows.Add(IssueSessionToRow(session));
            }
            TrimTableRows(_issueSessionsTable, 2000);
            _dataServer.Save();
        }

        return session;
    }

    private void SaveIssueReport(SocketJackIssueReport report) {
        NormalizeIssueReport(report);
        lock (_sync) {
            _issueReportsTable.Rows.Add(IssueReportToRow(report));
            TrimTableRows(_issueReportsTable, 2000);
            _dataServer.Save();
        }
    }

    private int CountIssueReports() {
        lock (_sync)
            return _issueReportsTable.Rows.Count;
    }

    private List<SocketJackIssueReport> ListIssueReports(int take) {
        lock (_sync) {
            return _issueReportsTable.Rows
                .Select(IssueReportFromRow)
                .OrderByDescending(report => report.CreatedUtc, StringComparer.Ordinal)
                .Take(Math.Max(1, take))
                .ToList();
        }
    }

    private int FindIssueSessionRowIndexLocked(string id) {
        for (int i = 0; i < _issueSessionsTable.Rows.Count; i++) {
            SocketJackIssueSession session = IssueSessionFromRow(_issueSessionsTable.Rows[i]);
            if (string.Equals(session.Id, id, StringComparison.OrdinalIgnoreCase))
                return i;
        }
        return -1;
    }

    private static SocketJackIssueSession IssueSessionFromJson(JsonElement root) {
        string messagesJson = GetJsonString(root, "messagesJson");
        if (string.IsNullOrWhiteSpace(messagesJson) && root.ValueKind == JsonValueKind.Object && root.TryGetProperty("messages", out JsonElement messages))
            messagesJson = messages.GetRawText();

        return new SocketJackIssueSession {
            Id = FirstNonEmpty(GetJsonString(root, "id"), GetJsonString(root, "sessionId")),
            Title = GetJsonString(root, "title"),
            CreatedUtc = GetJsonString(root, "createdUtc"),
            UpdatedUtc = GetJsonString(root, "updatedUtc"),
            MessageCount = Math.Max(0, (int)GetJsonLong(root, "messageCount", 0)),
            PreviewText = GetJsonString(root, "previewText"),
            MessagesJson = messagesJson,
            Archived = GetJsonBool(root, "archived", false),
            Deleted = GetJsonBool(root, "deleted", false)
        };
    }

    private SocketJackIssueSession IssueSessionFromRow(object[] row) {
        row = NormalizeRow(row, IssueSessionColumns.Length);
        return new SocketJackIssueSession {
            Id = Cell(row, 0),
            OwnerUserName = Cell(row, 1),
            ClientIp = Cell(row, 2),
            Title = Cell(row, 3),
            CreatedUtc = Cell(row, 4),
            UpdatedUtc = Cell(row, 5),
            MessageCount = Math.Max(0, (int)ParseLong(Cell(row, 6), 0)),
            PreviewText = Cell(row, 7),
            MessagesJson = Cell(row, 8),
            Archived = ParseBool(Cell(row, 9), false),
            Deleted = ParseBool(Cell(row, 10), false)
        };
    }

    private object[] IssueSessionToRow(SocketJackIssueSession session) {
        NormalizeIssueSession(session);
        return NormalizeRow(new object[] {
            session.Id,
            session.OwnerUserName,
            session.ClientIp,
            session.Title,
            session.CreatedUtc,
            session.UpdatedUtc,
            Math.Max(0, session.MessageCount).ToString(CultureInfo.InvariantCulture),
            session.PreviewText,
            session.MessagesJson,
            session.Archived ? "true" : "false",
            session.Deleted ? "true" : "false"
        }, IssueSessionColumns.Length);
    }

    private static SocketJackIssueReport IssueReportFromJson(JsonElement root) {
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        string errorText = FirstNonEmpty(GetJsonString(root, "errorText"), GetJsonString(root, "exceptionText"), GetJsonString(root, "text"));
        int lineCount = CountTextLines(errorText);
        if (lineCount > MaxIssueErrorLines)
            throw new InvalidOperationException("Issue reports allow up to 10,000 lines of exception/error text.");

        string screenshotManifestJson = BuildIssueScreenshotManifestJson(root, out int screenshotCount);
        return new SocketJackIssueReport {
            Id = FirstNonEmpty(GetJsonString(root, "id"), "issue_" + Guid.NewGuid().ToString("N")),
            CreatedUtc = FirstNonEmpty(GetJsonString(root, "createdUtc"), now),
            UpdatedUtc = FirstNonEmpty(GetJsonString(root, "updatedUtc"), now),
            Status = FirstNonEmpty(GetJsonString(root, "status"), "new"),
            Title = FirstNonEmpty(GetJsonString(root, "title"), "SocketJack issue report"),
            Context = FirstNonEmpty(GetJsonString(root, "context"), GetJsonString(root, "question"), GetJsonString(root, "description")),
            ErrorText = errorText,
            ErrorLineCount = lineCount,
            ScreenshotCount = screenshotCount,
            ScreenshotManifestJson = screenshotManifestJson,
            IssueSessionId = FirstNonEmpty(GetJsonString(root, "issueSessionId"), GetJsonString(root, "sessionId")),
            ConversationJson = ReadRawJsonProperty(root, "conversation", "messages"),
            AdminNotes = GetJsonString(root, "adminNotes")
        };
    }

    private SocketJackIssueReport IssueReportFromRow(object[] row) {
        row = NormalizeRow(row, IssueReportColumns.Length);
        return new SocketJackIssueReport {
            Id = Cell(row, 0),
            CreatedUtc = Cell(row, 1),
            UpdatedUtc = Cell(row, 2),
            Status = Cell(row, 3),
            Title = Cell(row, 4),
            Context = Cell(row, 5),
            ErrorText = Cell(row, 6),
            ErrorLineCount = Math.Max(0, (int)ParseLong(Cell(row, 7), 0)),
            ScreenshotCount = Math.Max(0, (int)ParseLong(Cell(row, 8), 0)),
            ScreenshotManifestJson = Cell(row, 9),
            IssueSessionId = Cell(row, 10),
            ConversationJson = Cell(row, 11),
            OwnerUserName = Cell(row, 12),
            ClientIp = Cell(row, 13),
            UserAgent = Cell(row, 14),
            AdminNotes = Cell(row, 15)
        };
    }

    private object[] IssueReportToRow(SocketJackIssueReport report) {
        NormalizeIssueReport(report);
        return NormalizeRow(new object[] {
            report.Id,
            report.CreatedUtc,
            report.UpdatedUtc,
            report.Status,
            report.Title,
            report.Context,
            report.ErrorText,
            Math.Max(0, report.ErrorLineCount).ToString(CultureInfo.InvariantCulture),
            Math.Max(0, report.ScreenshotCount).ToString(CultureInfo.InvariantCulture),
            report.ScreenshotManifestJson,
            report.IssueSessionId,
            report.ConversationJson,
            report.OwnerUserName,
            report.ClientIp,
            report.UserAgent,
            report.AdminNotes
        }, IssueReportColumns.Length);
    }

    private static void NormalizeIssueSession(SocketJackIssueSession session) {
        session.Id = SanitizeIssueId(session.Id, "issue_session");
        session.OwnerUserName = TruncateText(session.OwnerUserName, 80);
        session.ClientIp = TruncateText(session.ClientIp, 80);
        session.Title = TruncateText(FirstNonEmpty(session.Title, session.PreviewText, "Troubleshooting chat"), 140);
        session.PreviewText = TruncateText(session.PreviewText, 320);
        if (session.MessagesJson != null && session.MessagesJson.Length > 240_000)
            session.MessagesJson = session.MessagesJson.Substring(0, 240_000);
    }

    private static void NormalizeIssueReport(SocketJackIssueReport report) {
        report.Id = SanitizeIssueId(FirstNonEmpty(report.Id, "issue_" + Guid.NewGuid().ToString("N")), "issue");
        report.CreatedUtc = TruncateText(FirstNonEmpty(report.CreatedUtc, DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)), 64);
        report.UpdatedUtc = TruncateText(FirstNonEmpty(report.UpdatedUtc, report.CreatedUtc), 64);
        report.Status = TruncateText(FirstNonEmpty(report.Status, "new"), 40);
        report.Title = TruncateText(FirstNonEmpty(report.Title, "SocketJack issue report"), 180);
        report.Context = TruncateText(report.Context, 12000);
        report.ErrorLineCount = CountTextLines(report.ErrorText);
        if (report.ErrorLineCount > MaxIssueErrorLines)
            throw new InvalidOperationException("Issue reports allow up to 10,000 lines of exception/error text.");
        report.ErrorText ??= "";
        report.ScreenshotCount = Math.Clamp(report.ScreenshotCount, 0, MaxIssueScreenshots);
        report.ScreenshotManifestJson = string.IsNullOrWhiteSpace(report.ScreenshotManifestJson) ? "[]" : report.ScreenshotManifestJson;
        report.IssueSessionId = SanitizeIssueId(report.IssueSessionId, "issue_session");
        report.ConversationJson = TruncateText(report.ConversationJson, 240_000);
        report.OwnerUserName = TruncateText(report.OwnerUserName, 160);
        report.ClientIp = TruncateText(report.ClientIp, 120);
        report.UserAgent = TruncateText(report.UserAgent, 400);
        report.AdminNotes = TruncateText(report.AdminNotes, 12000);
    }

    private static bool IssueSessionVisibleToViewer(SocketJackIssueSession session, AccountRecord? account, string clientIp) {
        if (account != null && !string.IsNullOrWhiteSpace(session.OwnerUserName))
            return string.Equals(session.OwnerUserName, account.UserName, StringComparison.OrdinalIgnoreCase);
        return !string.IsNullOrWhiteSpace(clientIp) &&
               string.Equals(session.ClientIp, clientIp, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IssueSessionMatchesSearch(SocketJackIssueSession session, string search) {
        if (string.IsNullOrWhiteSpace(search))
            return true;
        string haystack = string.Join("\n", session.Title, session.PreviewText, session.MessagesJson);
        return haystack.Contains(search, StringComparison.OrdinalIgnoreCase);
    }

    private static string BuildIssueScreenshotManifestJson(JsonElement root, out int count) {
        count = 0;
        if (root.ValueKind != JsonValueKind.Object || !root.TryGetProperty("screenshots", out JsonElement screenshots) || screenshots.ValueKind != JsonValueKind.Array)
            return "[]";
        if (screenshots.GetArrayLength() > MaxIssueScreenshots)
            throw new InvalidOperationException("Issue reports allow up to 10 screenshots.");

        var manifest = new JsonArray();
        int index = 0;
        foreach (JsonElement item in screenshots.EnumerateArray()) {
            index++;
            string dataUrl = item.ValueKind == JsonValueKind.String
                ? item.GetString() ?? ""
                : FirstNonEmpty(GetJsonString(item, "dataUrl"), GetJsonString(item, "contentDataUrl"));
            if (string.IsNullOrWhiteSpace(dataUrl))
                continue;
            if (!TryExtractDataUrlPayload(dataUrl, out _, out string detectedMime, out string dataUrlError))
                throw new InvalidOperationException("Screenshot " + index.ToString(CultureInfo.InvariantCulture) + " is invalid: " + dataUrlError);
            string mimeType = item.ValueKind == JsonValueKind.Object
                ? FirstNonEmpty(GetJsonString(item, "mimeType"), GetJsonString(item, "mediaType"), detectedMime)
                : detectedMime;
            if (!mimeType.StartsWith("image/", StringComparison.OrdinalIgnoreCase))
                throw new InvalidOperationException("Screenshot " + index.ToString(CultureInfo.InvariantCulture) + " must be an image.");
            string fileName = item.ValueKind == JsonValueKind.Object
                ? FirstNonEmpty(GetJsonString(item, "fileName"), GetJsonString(item, "filename"), GetJsonString(item, "name"), "screenshot-" + index.ToString(CultureInfo.InvariantCulture))
                : "screenshot-" + index.ToString(CultureInfo.InvariantCulture);
            manifest.Add(new JsonObject {
                ["fileName"] = SanitizeIssueFileName(fileName, mimeType),
                ["mimeType"] = mimeType,
                ["dataUrl"] = dataUrl
            });
            count++;
        }

        return manifest.ToJsonString(MasterListJson.Options);
    }

    private static string ReadRawJsonProperty(JsonElement root, params string[] names) {
        if (root.ValueKind != JsonValueKind.Object)
            return "";
        foreach (string name in names) {
            if (root.TryGetProperty(name, out JsonElement value))
                return value.GetRawText();
        }
        return "";
    }

    private static int CountTextLines(string text) {
        if (string.IsNullOrEmpty(text))
            return 0;
        int count = 1;
        foreach (char c in text) {
            if (c == '\n')
                count++;
        }
        return count;
    }

    private static string SanitizeIssueId(string id, string prefix) {
        id = (id ?? "").Trim();
        if (string.IsNullOrWhiteSpace(id))
            return "";
        id = Regex.Replace(id, @"[^A-Za-z0-9_.:-]", "_");
        if (!id.StartsWith(prefix + "_", StringComparison.OrdinalIgnoreCase) && !id.StartsWith(prefix + "-", StringComparison.OrdinalIgnoreCase))
            id = prefix + "_" + id;
        return id.Length <= 120 ? id : id.Substring(0, 120);
    }

    private static string SanitizeIssueFileName(string value, string mediaType) {
        value = Path.GetFileName((value ?? "").Trim());
        if (string.IsNullOrWhiteSpace(value))
            value = "screenshot";
        char[] invalid = Path.GetInvalidFileNameChars();
        var builder = new StringBuilder(value.Length);
        foreach (char c in value) {
            builder.Append(invalid.Contains(c) || char.IsControl(c) ? '_' : c);
        }
        string fileName = builder.ToString().Trim('.', ' ');
        if (string.IsNullOrWhiteSpace(Path.GetExtension(fileName)))
            fileName += IssueScreenshotExtension(mediaType);
        return string.IsNullOrWhiteSpace(fileName) ? "screenshot.png" : fileName;
    }

    private static string IssueScreenshotExtension(string mediaType) {
        mediaType = (mediaType ?? "").Trim().ToLowerInvariant();
        return mediaType switch {
            "image/jpeg" or "image/jpg" => ".jpg",
            "image/gif" => ".gif",
            "image/webp" => ".webp",
            "image/bmp" => ".bmp",
            "image/svg+xml" => ".svg",
            _ => ".png"
        };
    }

    private static bool IsJackAdministrator(AccountRecord? account) {
        return account != null && IsBuiltInAdministratorUserName(account.UserName);
    }

    private static string GetHeaderValue(HttpRequest request, string name) {
        if (request.Headers != null && request.Headers.TryGetValue(name, out string? value))
            return value ?? "";
        return "";
    }

    private string BuildAbsoluteWebsiteUrl(string path) {
        string baseUrl = FirstNonEmpty(_options.WebsitePublicUrl, _options.PublicUrl, "https://socketjack.com/");
        return CombineUrl(baseUrl, (path ?? "/").TrimStart('/'));
    }

    private string BuildIssueAssistantPrompt() {
        string documentationUrl = BuildAbsoluteWebsiteUrl("/Documentation");
        return "You are the SocketJack troubleshooting assistant. Help the user by grounding your answer in the SocketJack documentation page. First use or read this full documentation link when you need product facts: " + documentationUrl + ". Prefer answers that point the user back to " + documentationUrl + " and explain the relevant docs section before suggesting fixes. If the user includes exception text or screenshots, summarize the likely cause, ask for missing version/runtime details, and avoid inventing APIs that are not documented.";
    }

    private object HandleAutoApiRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        if (request.Method.Equals("OPTIONS", StringComparison.OrdinalIgnoreCase))
            return NoContent(request);

        string mode = NormalizeAutoMode(ExtractAutoMode(request, request.Path ?? ""));
        string model = ExtractAutoModel(request);
        string requestedServerId = ExtractAutoServerId(request);
        bool strictServerRequest = ExtractAutoStrictServerEnabled(request);
        string originMode = NormalizeAutoOriginMode(ExtractAutoOriginMode(request));
        bool autoPoolEnabled = ExtractAutoPoolEnabled(request);
        double minParameterBillions = ExtractAutoMinParameterBillions(request);
        double maxParameterBillions = ExtractAutoMaxParameterBillions(request);
        ISet<string> disabledAutoModels = ExtractAutoDisabledModels(request);
        bool isStatusRequest = IsAutoApiStatusRequest(request);
        List<AutoApiParallelRequest> parallelRequests = new();
        string parallelBatchWarning = "";
        bool isParallelBatchRequest = !isStatusRequest && TryBuildAutoApiParallelRequests(request, mode, model, out parallelRequests, out parallelBatchWarning);
        bool requiresAuthenticatedUser = AutoApiRequiresAuthenticatedUser(request, mode);
        if (isParallelBatchRequest && parallelRequests.Any(item => AutoApiRequiresAuthenticatedUser(request, item.Mode)))
            requiresAuthenticatedUser = true;
        bool premiumModelsEnabled = ExtractAutoPremiumModelsEnabled(request);
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            TryAutoAuthenticateKnownIp(connection, request, out account, out _);

        if (!isStatusRequest && requiresAuthenticatedUser) {
            if (account == null) {
                string returnUrl = (request.Path ?? "/Auto") + (string.IsNullOrWhiteSpace(request.QueryString) ? "" : "?" + request.QueryString);
                return Json(request, new {
                    ok = false,
                    code = "auto_login_required",
                    error = string.IsNullOrWhiteSpace(authError) || authError.Contains("expired", StringComparison.OrdinalIgnoreCase)
                        ? "SocketJack.com login is required for Auto non-text requests."
                        : authError,
                    loginUrl = BuildSocketJackLoginPath(returnUrl),
                    authenticated = false,
                    username = "",
                    mode,
                    origin = originMode,
                    pool = autoPoolEnabled,
                    min_params_b = minParameterBillions,
                    max_params_b = maxParameterBillions,
                    disabled_models = disabledAutoModels.ToArray(),
                    model
                }, 401, "Unauthorized");
            }
        }

        if (isParallelBatchRequest) {
            return HandleAutoApiParallelBatchRequest(
                connection,
                request,
                parallelRequests,
                parallelBatchWarning,
                model,
                requestedServerId,
                originMode,
                autoPoolEnabled,
                minParameterBillions,
                maxParameterBillions,
                premiumModelsEnabled,
                strictServerRequest,
                account,
                disabledAutoModels,
                cancellationToken);
        }

        string routingModel = model;
        string effectiveRequestedServerId = requestedServerId;
        bool serverFallbackUsed = false;
        bool resolvedAutoTarget = TryResolveAutoApiTarget(routingModel, mode, effectiveRequestedServerId, originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out RegisteredServer? selectedServer, out MasterShellRelay? relay, out Uri? baseUri, out int eligibleCount, out int premiumBlockedCount, out string reason, userDisabledModels: disabledAutoModels);
        if (!resolvedAutoTarget && !strictServerRequest && !string.IsNullOrWhiteSpace(effectiveRequestedServerId)) {
            effectiveRequestedServerId = "";
            serverFallbackUsed = true;
            resolvedAutoTarget = TryResolveAutoApiTarget(routingModel, mode, effectiveRequestedServerId, originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out selectedServer, out relay, out baseUri, out eligibleCount, out premiumBlockedCount, out reason, userDisabledModels: disabledAutoModels);
        }
        if (!resolvedAutoTarget && !string.IsNullOrWhiteSpace(routingModel) && AutoModeAllowsModellessFallback(mode)) {
            routingModel = "";
            resolvedAutoTarget = TryResolveAutoApiTarget(routingModel, mode, effectiveRequestedServerId, originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out selectedServer, out relay, out baseUri, out eligibleCount, out premiumBlockedCount, out reason, userDisabledModels: disabledAutoModels);
            if (!resolvedAutoTarget && !strictServerRequest && !string.IsNullOrWhiteSpace(effectiveRequestedServerId)) {
                effectiveRequestedServerId = "";
                serverFallbackUsed = true;
                resolvedAutoTarget = TryResolveAutoApiTarget(routingModel, mode, effectiveRequestedServerId, originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out selectedServer, out relay, out baseUri, out eligibleCount, out premiumBlockedCount, out reason, userDisabledModels: disabledAutoModels);
            }
        }

        if (!resolvedAutoTarget ||
            selectedServer == null ||
            baseUri == null) {
            return Json(request, new {
                ok = false,
                error = reason,
                code = "auto_no_eligible_server",
                mode,
                origin = originMode,
                pool = autoPoolEnabled,
                min_params_b = minParameterBillions,
                max_params_b = maxParameterBillions,
                disabled_models = disabledAutoModels.ToArray(),
                model = routingModel,
                requested_model = model,
                server = effectiveRequestedServerId,
                requested_server = requestedServerId,
                strict_server = strictServerRequest,
                server_fallback = serverFallbackUsed,
                eligible_servers = eligibleCount,
                authenticated = account != null,
                username = account?.UserName ?? "",
                premium_models_enabled = premiumModelsEnabled,
                premium_blocked_servers = premiumBlockedCount,
                usage = account == null ? BuildAnonymousUsage() : BuildUsage(account)
            }, 503, "Service Unavailable");
        }

        if (isStatusRequest) {
            return Json(request, new {
                ok = true,
                mode,
                origin = originMode,
                pool = autoPoolEnabled,
                min_params_b = minParameterBillions,
                max_params_b = maxParameterBillions,
                disabled_models = disabledAutoModels.ToArray(),
                model = routingModel,
                requested_model = model,
                requested_server = requestedServerId,
                strict_server = strictServerRequest,
                server_fallback = serverFallbackUsed,
                eligible_servers = eligibleCount,
                api = "/auto/api",
                selected = BuildAutoApiServerSummary(selectedServer, relay, mode, minParameterBillions, maxParameterBillions, disabledAutoModels),
                transport = relay == null ? "direct-http" : "socketjack-master-relay",
                authenticated = account != null,
                username = account?.UserName ?? "",
                premium_models_enabled = premiumModelsEnabled,
                premium_blocked_servers = premiumBlockedCount,
                premium_available = premiumModelsEnabled && AccountHasAutoPremiumTokens(account),
                usage = account == null ? BuildAnonymousUsage() : BuildUsage(account)
            });
        }

        string forwardedPath = GetAutoApiForwardPath(request, mode);
        string query = BuildAutoApiForwardQuery(request, forwardedPath);
        string resolvedRuntimeModel = ResolveAutoApiRuntimeModel(selectedServer, mode, routingModel, minParameterBillions, maxParameterBillions, disabledAutoModels);
        bool forceInitialModel = !NormalizeAutoModelId(resolvedRuntimeModel).Equals(NormalizeAutoModelId(model), StringComparison.OrdinalIgnoreCase);
        byte[] bodyBytes = BuildAutoApiBodyBytes(request, mode, resolvedRuntimeModel, forceInitialModel);
        string attemptModel = resolvedRuntimeModel;
        int totalEligibleCount = eligibleCount;
        int retryCount = 0;
        var excludedAutoServers = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var failedAutoModels = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

        bool TrySelectAlternateModelOnCurrentTarget(RegisteredServer currentServer, MasterShellRelay? currentRelay, Uri currentBaseUri) {
            string failedModel = NormalizeAutoModelId(attemptModel);
            if (!string.IsNullOrWhiteSpace(failedModel))
                failedAutoModels.Add(failedModel);

            string alternateModel = ChooseAutoApiModelForMode(currentServer, mode, failedAutoModels, minParameterBillions, maxParameterBillions, disabledAutoModels);
            if (string.IsNullOrWhiteSpace(alternateModel))
                return false;

            selectedServer = currentServer;
            relay = currentRelay;
            baseUri = currentBaseUri;
            attemptModel = alternateModel;
            retryCount++;
            return true;
        }

        bool TrySelectNextAutoApiTarget(bool allowModelFallback) {
            ExcludeAutoServer(excludedAutoServers, selectedServer);

            if (!string.IsNullOrWhiteSpace(routingModel) &&
                TryResolveAutoApiTarget(routingModel, mode, "", originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out RegisteredServer? sameModelServer, out MasterShellRelay? sameModelRelay, out Uri? sameModelBaseUri, out int sameModelEligible, out _, out _, excludedServerIds: excludedAutoServers, userDisabledModels: disabledAutoModels) &&
                sameModelServer != null &&
                sameModelBaseUri != null) {
                selectedServer = sameModelServer;
                relay = sameModelRelay;
                baseUri = sameModelBaseUri;
                eligibleCount = Math.Max(totalEligibleCount, sameModelEligible);
                attemptModel = ResolveAutoApiRuntimeModel(sameModelServer, mode, routingModel, minParameterBillions, maxParameterBillions, disabledAutoModels);
                retryCount++;
                return true;
            }

            if (!allowModelFallback ||
                !TryResolveAutoApiTarget("", mode, "", originMode, autoPoolEnabled, minParameterBillions, maxParameterBillions, premiumModelsEnabled, account, out RegisteredServer? fallbackServer, out MasterShellRelay? fallbackRelay, out Uri? fallbackBaseUri, out int fallbackEligible, out _, out _, excludedServerIds: excludedAutoServers, userDisabledModels: disabledAutoModels) ||
                fallbackServer == null ||
                fallbackBaseUri == null)
                return false;

            selectedServer = fallbackServer;
            relay = fallbackRelay;
            baseUri = fallbackBaseUri;
            eligibleCount = Math.Max(totalEligibleCount, fallbackEligible);
            attemptModel = ChooseAutoApiModelForMode(fallbackServer, mode, minParameterBillions: minParameterBillions, maxParameterBillions: maxParameterBillions, userDisabledModels: disabledAutoModels);
            retryCount++;
            return true;
        }

        while (selectedServer != null && baseUri != null) {
            RegisteredServer currentServer = selectedServer;
            MasterShellRelay? currentRelay = relay;
            Uri currentBaseUri = baseUri;
            byte[] attemptBodyBytes = retryCount == 0
                ? bodyBytes
                : BuildAutoApiBodyBytes(request, mode, attemptModel, forceModel: true);

            try {
                if (IsShellProxyStreamingResponse("", forwardedPath)) {
                    if (currentRelay != null && _shellProxyWebSocketTunnels.HasConnectedTunnel(currentRelay.Id)) {
                        _shellProxyWebSocketTunnels.StreamRequest(
                            request,
                            currentRelay,
                            request.Method ?? "GET",
                            forwardedPath,
                            query,
                            request.Headers,
                            attemptBodyBytes,
                            BuildAutoRoutingHeaderMap(currentServer, currentRelay, eligibleCount, mode, attemptModel),
                            cancellationToken);
                    } else {
                        if (!TryBuildAutoApiTargetUri(currentBaseUri, forwardedPath, query, out Uri? streamingTargetUri, out string streamingTargetError) || streamingTargetUri == null)
                            return Json(request, new { ok = false, error = streamingTargetError, mode, origin = originMode, model = attemptModel }, 400, "Bad Request");

                        StreamAutoApiHttpResult(connection, request, streamingTargetUri, attemptBodyBytes, currentServer, currentRelay, eligibleCount, mode, attemptModel, cancellationToken);
                    }

                    return "";
                }

                AutoApiForwardResult forwardResult;
                if (currentRelay != null && _shellProxyWebSocketTunnels.HasConnectedTunnel(currentRelay.Id)) {
                    forwardResult = FetchAutoApiTunnelResult(currentRelay, request, forwardedPath, query, attemptBodyBytes, cancellationToken);
                } else {
                    if (!TryBuildAutoApiTargetUri(currentBaseUri, forwardedPath, query, out Uri? targetUri, out string targetError) || targetUri == null)
                        return Json(request, new { ok = false, error = targetError, mode, origin = originMode, model = attemptModel }, 400, "Bad Request");

                    forwardResult = FetchAutoApiHttpResult(connection, request, targetUri, attemptBodyBytes, currentServer, mode, cancellationToken, attemptModel);
                }

                if (IsAutoApiRetryableModelLoadFailure(forwardResult, attemptModel)) {
                    FlagAutoModelForBenchmark(currentServer, attemptModel, mode, DecodeAutoApiResponseText(forwardResult.BodyBytes), account?.UserName ?? "");
                    if (TrySelectAlternateModelOnCurrentTarget(currentServer, currentRelay, currentBaseUri) ||
                        TrySelectNextAutoApiTarget(allowModelFallback: true))
                        continue;
                }

                if (TryGetAutoApiModelFailureRequiringBenchmark(forwardResult, attemptModel, mode, out string failureReason) ||
                    AutoApiMediaResponseMissingArtifact(forwardResult, mode, out failureReason)) {
                    FlagAutoModelForBenchmark(currentServer, attemptModel, mode, failureReason, account?.UserName ?? "");
                    if (TrySelectAlternateModelOnCurrentTarget(currentServer, currentRelay, currentBaseUri) ||
                        TrySelectNextAutoApiTarget(allowModelFallback: true))
                        continue;
                }

                return WriteAutoApiForwardResult(request, forwardResult, currentServer, currentRelay, eligibleCount, mode, retryCount, attemptModel);
            } catch (TaskCanceledException ex) {
                if (TrySelectNextAutoApiTarget(allowModelFallback: false))
                    continue;
                return Json(request, new {
                    ok = false,
                    error = currentRelay != null ? "Auto API tunnel request timed out." : "Auto API request timed out.",
                    detail = ex.Message,
                    mode,
                    origin = originMode,
                    model = attemptModel,
                    selected = BuildAutoApiServerSummary(currentServer, currentRelay, mode, minParameterBillions, maxParameterBillions, disabledAutoModels)
                }, 504, "Gateway Timeout");
            } catch (Exception ex) when (ex is HttpRequestException || ex is IOException || ex is InvalidOperationException || ex is TimeoutException) {
                if (TrySelectNextAutoApiTarget(allowModelFallback: false))
                    continue;
                return Json(request, new {
                    ok = false,
                    error = currentRelay != null ? "Auto API tunnel failed." : "Auto API target failed.",
                    detail = ex.Message,
                    mode,
                    origin = originMode,
                    model = attemptModel,
                    selected = BuildAutoApiServerSummary(currentServer, currentRelay, mode, minParameterBillions, maxParameterBillions, disabledAutoModels)
                }, 502, "Bad Gateway");
            }
        }

        return Json(request, new { ok = false, error = "No retryable Auto API target remained available.", mode, origin = originMode, model = attemptModel }, 503, "Service Unavailable");
    }

    private object HandleAutoApiParallelBatchRequest(
        NetworkConnection connection,
        HttpRequest request,
        IReadOnlyList<AutoApiParallelRequest> parallelRequests,
        string warning,
        string fallbackModel,
        string requestedServerId,
        string originMode,
        bool autoPoolEnabled,
        double minParameterBillions,
        double maxParameterBillions,
        bool premiumModelsEnabled,
        bool strictServerRequest,
        AccountRecord? account,
        ISet<string> disabledAutoModels,
        CancellationToken cancellationToken) {
        AutoApiParallelRequest[] requests = (parallelRequests ?? Array.Empty<AutoApiParallelRequest>())
            .Where(item => item != null && !string.IsNullOrWhiteSpace(item.Prompt))
            .Take(12)
            .ToArray();
        if (requests.Length <= 1)
            return Json(request, new { ok = false, error = "Auto parallel batches require at least two prompts.", code = "auto_parallel_batch_too_small" }, 400, "Bad Request");

        int maxConcurrency = AutoApiParallelBatchConcurrency(requests);
        using var throttle = new SemaphoreSlim(maxConcurrency, maxConcurrency);
        var tasks = requests
            .Select(item => Task.Run(() => {
                throttle.Wait(cancellationToken);
                try {
                    return ExecuteAutoApiParallelRequest(
                        connection,
                        request,
                        item,
                        fallbackModel,
                        requestedServerId,
                        originMode,
                        autoPoolEnabled,
                        minParameterBillions,
                        maxParameterBillions,
                        premiumModelsEnabled,
                        strictServerRequest,
                        account,
                        disabledAutoModels,
                        cancellationToken);
                } catch (Exception ex) when (ex is not OperationCanceledException) {
                    return BuildAutoApiParallelUnhandledError(item, fallbackModel, ex);
                } finally {
                    throttle.Release();
                }
            }, cancellationToken))
            .ToArray();

        AutoApiParallelResult[] results;
        try {
            results = Task.WhenAll(tasks).GetAwaiter().GetResult()
                .OrderBy(result => result.Index)
                .ToArray();
        } catch (OperationCanceledException) {
            return Json(request, new { ok = false, error = "Auto parallel batch was cancelled.", code = "auto_parallel_cancelled" }, 499, "Client Closed Request");
        }

        bool ok = results.Length > 0 && results.All(result => result.Ok);
        int status = ok ? 200 : results.Any(result => result.Status == 401) ? 401 : results.Any(result => result.Status == 503) ? 503 : 207;
        string reason = status == 200 ? "OK" : status == 207 ? "Multi-Status" : GetReasonPhrase(status);
        return Json(request, new {
            ok,
            parallel = true,
            batch = true,
            code = ok ? "auto_parallel_completed" : "auto_parallel_partial",
            warning,
            count = requests.Length,
            completed = results.Count(result => result.Ok),
            failed = results.Count(result => !result.Ok),
            concurrency = maxConcurrency,
            same_session = true,
            gpu_hint = "Independent prompts are forwarded concurrently; LlmRuntime selects the least busy loaded GPU/model instance on the workstation.",
            origin = originMode,
            pool = autoPoolEnabled,
            requested_model = fallbackModel,
            authenticated = account != null,
            username = account?.UserName ?? "",
            premium_models_enabled = premiumModelsEnabled,
            usage = account == null ? BuildAnonymousUsage() : BuildUsage(account),
            results
        }, status, reason);
    }

    private static int AutoApiParallelBatchConcurrency(IReadOnlyList<AutoApiParallelRequest> requests) {
        int count = Math.Max(1, requests?.Count ?? 1);
        bool mediaBatch = (requests ?? Array.Empty<AutoApiParallelRequest>())
            .Any(item => {
                string mode = NormalizeAutoMode(item?.Mode ?? "");
                return mode.Equals("image", StringComparison.OrdinalIgnoreCase) ||
                       mode.Equals("video", StringComparison.OrdinalIgnoreCase) ||
                       mode.Equals("audio", StringComparison.OrdinalIgnoreCase);
            });
        return mediaBatch ? Math.Min(2, count) : count;
    }

    private static void AddAutoApiFailedModel(ISet<string> failedModels, string model) {
        if (failedModels == null || string.IsNullOrWhiteSpace(model))
            return;

        string raw = NormalizeAutoModelId(model);
        if (!string.IsNullOrWhiteSpace(raw))
            failedModels.Add(raw);

        string clean = NormalizeAutoModelId(CleanAutoModelDisplayName(model));
        if (!string.IsNullOrWhiteSpace(clean))
            failedModels.Add(clean);
    }

    private static bool AutoApiModelWasFailed(ISet<string> failedModels, string model) {
        if (failedModels == null || string.IsNullOrWhiteSpace(model))
            return false;

        string raw = NormalizeAutoModelId(model);
        string clean = NormalizeAutoModelId(CleanAutoModelDisplayName(model));
        return (!string.IsNullOrWhiteSpace(raw) && failedModels.Contains(raw)) ||
               (!string.IsNullOrWhiteSpace(clean) && failedModels.Contains(clean));
    }

    private AutoApiParallelResult ExecuteAutoApiParallelRequest(
        NetworkConnection connection,
        HttpRequest request,
        AutoApiParallelRequest item,
        string fallbackModel,
        string requestedServerId,
        string originMode,
        bool autoPoolEnabled,
        double minParameterBillions,
        double maxParameterBillions,
        bool premiumModelsEnabled,
        bool strictServerRequest,
        AccountRecord? account,
        ISet<string> disabledAutoModels,
        CancellationToken cancellationToken) {
        string mode = NormalizeAutoMode(item.Mode);
        string routingModel = FirstNonEmpty(item.Model, fallbackModel);
        string effectiveRequestedServerId = requestedServerId;
        var excludedServers = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var failedModels = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        int attempts = 0;
        int eligibleCount = 0;
        int premiumBlockedCount = 0;
        string lastReason = "";

        while (attempts < 4 && !cancellationToken.IsCancellationRequested) {
            attempts++;
            string effectiveRoutingModel = routingModel;
            if (AutoModeAllowsModellessFallback(mode) && AutoApiModelWasFailed(failedModels, effectiveRoutingModel))
                effectiveRoutingModel = "";
            if (!TryResolveAutoApiTarget(
                    effectiveRoutingModel,
                    mode,
                    effectiveRequestedServerId,
                    originMode,
                    autoPoolEnabled,
                    minParameterBillions,
                    maxParameterBillions,
                    premiumModelsEnabled,
                    account,
                    out RegisteredServer? selectedServer,
                    out MasterShellRelay? relay,
                    out Uri? baseUri,
                    out eligibleCount,
                    out premiumBlockedCount,
                    out string reason,
                    excludedServerIds: excludedServers,
                    userDisabledModels: disabledAutoModels) ||
                selectedServer == null ||
                baseUri == null) {
                if (!strictServerRequest && !string.IsNullOrWhiteSpace(effectiveRequestedServerId)) {
                    effectiveRequestedServerId = "";
                    continue;
                }

                if (!string.IsNullOrWhiteSpace(routingModel) && AutoModeAllowsModellessFallback(mode)) {
                    routingModel = "";
                    continue;
                }

                lastReason = reason;
                break;
            }

            string resolvedModel = ResolveAutoApiRuntimeModel(selectedServer, mode, effectiveRoutingModel, minParameterBillions, maxParameterBillions, disabledAutoModels);
            if (string.IsNullOrWhiteSpace(resolvedModel))
                resolvedModel = ChooseAutoApiModelForMode(selectedServer, mode, failedModels, minParameterBillions, maxParameterBillions, disabledAutoModels);
            bool forceModel = !string.IsNullOrWhiteSpace(resolvedModel) &&
                              !NormalizeAutoModelId(resolvedModel).Equals(NormalizeAutoModelId(item.Model), StringComparison.OrdinalIgnoreCase);

            JsonObject childBody = CloneAutoApiJsonObject(item.Body);
            childBody["auto_parallel_attempt"] = attempts;
            AddAutoApiBodyDefaults(childBody, mode, resolvedModel, forceModel);
            byte[] bodyBytes = Encoding.UTF8.GetBytes(childBody.ToJsonString(MasterListJson.Options));
            string forwardedPath = GetAutoApiForwardPath(request, mode);
            string query = BuildAutoApiForwardQuery(request, forwardedPath);

            try {
                AutoApiForwardResult forwardResult;
                if (relay != null && _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)) {
                    forwardResult = FetchAutoApiTunnelResult(relay, request, forwardedPath, query, bodyBytes, cancellationToken);
                } else {
                    if (!TryBuildAutoApiTargetUri(baseUri, forwardedPath, query, out Uri? targetUri, out string targetError) || targetUri == null)
                        return BuildAutoApiParallelError(item, mode, resolvedModel, 400, targetError, selectedServer, relay, eligibleCount, minParameterBillions, maxParameterBillions, disabledAutoModels);

                    forwardResult = FetchAutoApiHttpResult(connection, request, targetUri, bodyBytes, selectedServer, mode, cancellationToken, resolvedModel);
                }

                string failureReason = "";
                bool retryableModelFailure = IsAutoApiRetryableModelLoadFailure(forwardResult, resolvedModel);
                bool benchmarkModelFailure =
                    TryGetAutoApiModelFailureRequiringBenchmark(forwardResult, resolvedModel, mode, out failureReason) ||
                    AutoApiMediaResponseMissingArtifact(forwardResult, mode, out failureReason);
                if ((retryableModelFailure || benchmarkModelFailure) && attempts < 4) {
                    string failure = string.IsNullOrWhiteSpace(failureReason) ? DecodeAutoApiResponseText(forwardResult.BodyBytes) : failureReason;
                    AddAutoApiFailedModel(failedModels, resolvedModel);
                    if (AutoModeAllowsModellessFallback(mode) && AutoApiModelWasFailed(failedModels, routingModel))
                        routingModel = "";
                    FlagAutoModelForBenchmark(selectedServer, resolvedModel, mode, failure, account?.UserName ?? "");
                    continue;
                }

                Dictionary<string, string> headers = new(forwardResult.Headers, StringComparer.OrdinalIgnoreCase);
                foreach (KeyValuePair<string, string> header in BuildAutoRoutingHeaderMap(selectedServer, relay, eligibleCount, mode, resolvedModel))
                    headers[header.Key] = header.Value;
                return new AutoApiParallelResult {
                    Index = item.Index,
                    GpuLabel = "GPU " + (item.Index + 1).ToString(CultureInfo.InvariantCulture),
                    Ok = forwardResult.StatusCode >= 200 && forwardResult.StatusCode < 300,
                    Status = forwardResult.StatusCode,
                    Reason = FirstNonEmpty(forwardResult.ReasonPhrase, GetReasonPhrase(forwardResult.StatusCode)),
                    Mode = mode,
                    Model = resolvedModel,
                    Prompt = item.Prompt,
                    ContentType = forwardResult.ContentType,
                    Body = DecodeAutoApiResponseText(forwardResult.BodyBytes),
                    DurationMs = forwardResult.DurationMs,
                    Selected = BuildAutoApiServerSummary(selectedServer, relay, mode, minParameterBillions, maxParameterBillions, disabledAutoModels),
                    Headers = headers
                };
            } catch (Exception ex) when (ex is HttpRequestException || ex is IOException || ex is InvalidOperationException || ex is TimeoutException || ex is TaskCanceledException) {
                lastReason = relay != null ? "Auto API tunnel failed: " + ex.Message : "Auto API target failed: " + ex.Message;
                ExcludeAutoServer(excludedServers, selectedServer);
            }
        }

        return new AutoApiParallelResult {
            Index = item.Index,
            GpuLabel = "GPU " + (item.Index + 1).ToString(CultureInfo.InvariantCulture),
            Ok = false,
            Status = premiumBlockedCount > 0 ? 402 : 503,
            Reason = FirstNonEmpty(lastReason, "No healthy Auto target remained available for this parallel prompt."),
            Mode = mode,
            Model = routingModel,
            Prompt = item.Prompt,
            ContentType = "application/json",
            Body = JsonSerializer.Serialize(new {
                ok = false,
                error = FirstNonEmpty(lastReason, "No healthy Auto target remained available for this parallel prompt."),
                code = "auto_parallel_child_failed",
                mode,
                model = routingModel,
                eligible_servers = eligibleCount,
                premium_blocked_servers = premiumBlockedCount
            }, MasterListJson.Options)
        };
    }

    private AutoApiParallelResult BuildAutoApiParallelError(
        AutoApiParallelRequest item,
        string mode,
        string model,
        int status,
        string error,
        RegisteredServer? selectedServer,
        MasterShellRelay? relay,
        int eligibleCount,
        double minParameterBillions,
        double maxParameterBillions,
        ISet<string> disabledAutoModels) =>
        new() {
            Index = item.Index,
            GpuLabel = "GPU " + (item.Index + 1).ToString(CultureInfo.InvariantCulture),
            Ok = false,
            Status = status,
            Reason = FirstNonEmpty(error, GetReasonPhrase(status)),
            Mode = mode,
            Model = model,
            Prompt = item.Prompt,
            ContentType = "application/json",
            Body = JsonSerializer.Serialize(new { ok = false, error, mode, model }, MasterListJson.Options),
            Selected = selectedServer == null ? null : BuildAutoApiServerSummary(selectedServer, relay, mode, minParameterBillions, maxParameterBillions, disabledAutoModels)
        };

    private static AutoApiParallelResult BuildAutoApiParallelUnhandledError(AutoApiParallelRequest item, string fallbackModel, Exception ex) {
        string mode = NormalizeAutoMode(item?.Mode ?? "");
        string model = FirstNonEmpty(item?.Model ?? "", fallbackModel);
        string detail = ex?.Message ?? "Unexpected branch failure.";
        return new AutoApiParallelResult {
            Index = item?.Index ?? 0,
            GpuLabel = "GPU " + ((item?.Index ?? 0) + 1).ToString(CultureInfo.InvariantCulture),
            Ok = false,
            Status = 500,
            Reason = "Auto parallel branch failed: " + detail,
            Mode = mode,
            Model = model,
            Prompt = item?.Prompt ?? "",
            ContentType = "application/json",
            Body = JsonSerializer.Serialize(new {
                ok = false,
                error = "Auto parallel branch failed.",
                detail,
                code = "auto_parallel_branch_exception",
                mode,
                model
            }, MasterListJson.Options)
        };
    }

    private object HandleAutoModelsRequest(HttpRequest request, CancellationToken cancellationToken) {
        try {
            string rawMode = FirstNonEmpty(GetQuery(request, "mode"), GetQuery(request, "type"), GetQuery(request, "modality"));
            string mode = string.IsNullOrWhiteSpace(rawMode) ? "" : NormalizeAutoMode(rawMode);
            string search = FirstNonEmpty(GetQuery(request, "q"), GetQuery(request, "search")).Trim();
            int limit = ParseInt(FirstNonEmpty(GetQuery(request, "limit")), 120, 1, 500);
            HuggingFaceModelCatalog catalog = GetHuggingFaceModelCatalog(cancellationToken);
            List<HuggingFaceCachedModel> cachedModels = catalog.Models ?? new List<HuggingFaceCachedModel>();
            DateTimeOffset generatedUtc = GetHuggingFaceCatalogGeneratedUtc(catalog);
            DateTimeOffset nextUpdateUtc = generatedUtc == DateTimeOffset.MinValue
                ? DateTimeOffset.UtcNow
                : generatedUtc.Add(HuggingFaceModelCatalogMaxAge);
            IEnumerable<HuggingFaceCachedModel> query = cachedModels;
            if (!string.IsNullOrWhiteSpace(mode))
                query = query.Where(model => HuggingFaceModelMatchesMode(model, mode));
            if (!string.IsNullOrWhiteSpace(search))
                query = query.Where(model => model.ModelId.Contains(search, StringComparison.OrdinalIgnoreCase));

            var models = query
                .OrderByDescending(model => ScoreHuggingFaceModel(model, search))
                .ThenBy(model => model.ModelId, StringComparer.OrdinalIgnoreCase)
                .Take(limit)
                .Select(model => new {
                    modelId = model.ModelId,
                    modes = model.Modes,
                    url = model.Url,
                    pipelineTag = model.PipelineTag,
                    libraryName = model.LibraryName,
                    downloads = model.Downloads,
                    likes = model.Likes
                })
                .ToList();

            return Json(request, new {
                ok = true,
                source = "huggingface",
                cache = new {
                    updatedUtc = catalog.GeneratedUtc,
                    nextUpdateUtc = nextUpdateUtc == DateTimeOffset.MinValue ? "" : nextUpdateUtc.ToString("O", CultureInfo.InvariantCulture),
                    ageSeconds = generatedUtc == DateTimeOffset.MinValue ? 0 : Math.Max(0, (long)(DateTimeOffset.UtcNow - generatedUtc).TotalSeconds),
                    stale = HuggingFaceModelCatalogIsStale(catalog),
                    total = cachedModels.Count,
                    error = catalog.Error
                },
                query = new { mode, search, limit },
                models
            });
        } catch (Exception ex) {
            return Json(request, new {
                ok = false,
                error = "Hugging Face model cache is unavailable.",
                detail = ex.Message
            }, 500, "Internal Server Error");
        }
    }

    private object HandleAutoModelBenchmarkFlagRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        if (request.Method.Equals("OPTIONS", StringComparison.OrdinalIgnoreCase))
            return NoContent(request);

        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            TryAutoAuthenticateKnownIp(connection, request, out account, out _);
        if (account == null) {
            return Json(request, new {
                ok = false,
                code = "auto_flag_login_required",
                error = string.IsNullOrWhiteSpace(authError) ? "SocketJack.com login is required to disable a failed Auto model globally." : authError,
                authenticated = false
            }, 401, "Unauthorized");
        }

        string serverId = FirstNonEmpty(
            GetJsonBodyText(request, "serverId"),
            GetJsonBodyText(request, "server_id"),
            GetQuery(request, "serverId"),
            GetQuery(request, "server_id"));
        string model = FirstNonEmpty(
            GetJsonBodyText(request, "model"),
            GetJsonBodyText(request, "modelId"),
            GetJsonBodyText(request, "model_id"),
            GetQuery(request, "model"),
            GetQuery(request, "modelId"),
            GetQuery(request, "model_id"));
        string mode = NormalizeAutoMode(FirstNonEmpty(GetJsonBodyText(request, "mode"), GetQuery(request, "mode"), "text"));
        string reason = FirstNonEmpty(GetJsonBodyText(request, "reason"), GetJsonBodyText(request, "error"), GetQuery(request, "reason"), "Auto generation failed.");

        if (string.IsNullOrWhiteSpace(serverId))
            return Json(request, new { ok = false, error = "Auto server id is required before disabling a failed model." }, 400, "Bad Request");
        if (string.IsNullOrWhiteSpace(model))
            return Json(request, new { ok = false, error = "Auto model id is required before disabling it for a fresh benchmark." }, 400, "Bad Request");

        RegisteredServer? server = GetServers(refreshAvailability: false)
            .FirstOrDefault(candidate => ServerMatchesAutoRequest(candidate, serverId));
        if (server == null)
            return Json(request, new { ok = false, error = "Auto server was not found." }, 404, "Not Found");

        FlagAutoModelForBenchmark(server, model, mode, reason, account.UserName);
        return Json(request, new {
            ok = true,
            code = "auto_model_benchmark_required",
            message = "Disabled " + CleanAutoModelDisplayName(model) + " on " + AutoServerDisplayName(server) + " until fresh healthy status or a fresh benchmark is published.",
            serverId = FirstNonEmpty(server.Id, server.TitleText),
            model = CleanAutoModelDisplayName(model),
            mode,
            authenticated = true,
            username = account.UserName
        });
    }

    private object HandleAutoModeDecisionRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        string prompt = ExtractAutoDecisionPrompt(request);
        if (string.IsNullOrWhiteSpace(prompt)) {
            return Json(request, new {
                ok = false,
                error = "Prompt is required before Auto can choose a mode.",
                mode = "text",
                command = "USE TEXT"
            }, 400, "Bad Request");
        }

        string originMode = NormalizeAutoOriginMode(ExtractAutoOriginMode(request));
        string requestedServerId = ExtractAutoServerId(request);
        bool autoPoolEnabled = ExtractAutoPoolEnabled(request);
        bool premiumModelsEnabled = ExtractAutoPremiumModelsEnabled(request);
        string inferredFastMode = InferAutoModeFromPrompt(prompt);
        if (!inferredFastMode.Equals("text", StringComparison.OrdinalIgnoreCase)) {
            string fastCommand = BuildAutoModeDecisionCommand(inferredFastMode, InferAutoParallelAgentCount(prompt, inferredFastMode));
            return Json(request, new {
                ok = true,
                mode = inferredFastMode,
                command = fastCommand,
                parallelAgents = AutoModeDecisionParallelAgentCount(fastCommand),
                parallelMode = AutoModeDecisionParallelAgentMode(fastCommand),
                source = "heuristic",
                origin = originMode,
                pool = autoPoolEnabled,
                server = requestedServerId,
                authenticated = false,
                username = "",
                classifier = new {
                    server = requestedServerId,
                    model = "",
                    transport = "heuristic"
                }
            });
        }
        AccountRecord? account = AuthenticateRequest(request, out _);

        if (!TryResolveAutoModeDecisionTarget(
                requestedServerId,
                originMode,
                autoPoolEnabled,
                premiumModelsEnabled,
                account,
                out RegisteredServer? selectedServer,
                out MasterShellRelay? selectedRelay,
                out Uri? selectedBaseUri,
                out string classifierModel,
                out int eligibleCount,
                out int premiumBlockedCount,
                out string reason) ||
            selectedServer == null ||
            selectedBaseUri == null) {
            string fallbackMode = InferAutoModeFromPrompt(prompt);
            string fallbackCommand = BuildAutoModeDecisionCommand(fallbackMode, InferAutoParallelAgentCount(prompt, fallbackMode));
            return Json(request, new {
                ok = true,
                mode = fallbackMode,
                command = fallbackCommand,
                parallelAgents = AutoModeDecisionParallelAgentCount(fallbackCommand),
                parallelMode = AutoModeDecisionParallelAgentMode(fallbackCommand),
                source = "fallback",
                error = reason,
                origin = originMode,
                pool = autoPoolEnabled,
                eligible_routers = eligibleCount,
                premium_blocked_routers = premiumBlockedCount,
                server = requestedServerId,
                authenticated = account != null,
                username = account?.UserName ?? "",
                classifier = new {
                    server = "",
                    model = "",
                    transport = ""
                }
            });
        }

        byte[] bodyBytes = BuildAutoModeDecisionRequestBody(prompt, classifierModel);

        try {
            AutoApiForwardResult result;
            if (selectedRelay != null && _shellProxyWebSocketTunnels.HasConnectedTunnel(selectedRelay.Id)) {
                result = FetchAutoApiTunnelResult(selectedRelay, request, "/api/chat-stream", "", bodyBytes, cancellationToken);
            } else {
                if (!TryBuildAutoApiTargetUri(selectedBaseUri, "/api/chat-stream", "", out Uri? targetUri, out string targetError) || targetUri == null)
                    return Json(request, new { ok = false, error = targetError }, 400, "Bad Request");

                result = FetchAutoApiHttpResult(connection, request, targetUri, bodyBytes, selectedServer, "text", cancellationToken);
            }

            string raw = DecodeAutoApiResponseText(result.BodyBytes);
            string decisionText = ExtractAutoModeDecisionText(raw);
            string inferredMode = InferAutoModeFromPrompt(prompt);
            bool llmDecision = TryParseAutoModeDecision(decisionText, out string command, out string mode);
            if (!llmDecision) {
                mode = inferredMode;
                command = BuildAutoModeDecisionCommand(mode, InferAutoParallelAgentCount(prompt, mode));
            } else if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase)) {
                mode = "text";
                command = BuildAutoModeDecisionCommand(mode, InferAutoParallelAgentCount(prompt, mode));
                llmDecision = false;
            }
            int inferredAgentCount = InferAutoParallelAgentCount(prompt, mode);
            if (inferredAgentCount > 1 && AutoModeDecisionParallelAgentCount(command) <= 1)
                command = BuildAutoModeDecisionCommand(mode, inferredAgentCount);

            return Json(request, new {
                ok = true,
                mode,
                command,
                parallelAgents = AutoModeDecisionParallelAgentCount(command),
                parallelMode = AutoModeDecisionParallelAgentMode(command),
                source = llmDecision ? "llm" : "fallback",
                rawDecision = decisionText,
                origin = originMode,
                pool = autoPoolEnabled,
                eligible_routers = eligibleCount,
                premium_blocked_routers = premiumBlockedCount,
                authenticated = account != null,
                username = account?.UserName ?? "",
                classifier = new {
                    server = FirstNonEmpty(selectedServer.TitleText, selectedServer.DisplayName, selectedServer.Id),
                    serverId = selectedServer.Id,
                    model = classifierModel,
                    transport = selectedRelay == null ? "direct-http" : "socketjack-master-relay",
                    relay = selectedRelay?.RouteName ?? "",
                    statusCode = result.StatusCode,
                    durationMs = result.DurationMs
                }
            });
        } catch (Exception ex) when (ex is HttpRequestException || ex is IOException || ex is InvalidOperationException || ex is TimeoutException || ex is TaskCanceledException) {
            string fallbackMode = InferAutoModeFromPrompt(prompt);
            string fallbackCommand = BuildAutoModeDecisionCommand(fallbackMode, InferAutoParallelAgentCount(prompt, fallbackMode));
            return Json(request, new {
                ok = true,
                mode = fallbackMode,
                command = fallbackCommand,
                parallelAgents = AutoModeDecisionParallelAgentCount(fallbackCommand),
                parallelMode = AutoModeDecisionParallelAgentMode(fallbackCommand),
                source = "fallback",
                error = "Auto mode router failed: " + ex.Message,
                origin = originMode,
                pool = autoPoolEnabled,
                eligible_routers = eligibleCount,
                premium_blocked_routers = premiumBlockedCount,
                authenticated = account != null,
                username = account?.UserName ?? "",
                classifier = new {
                    server = FirstNonEmpty(selectedServer.TitleText, selectedServer.DisplayName, selectedServer.Id),
                    serverId = selectedServer.Id,
                    model = classifierModel,
                    transport = selectedRelay == null ? "direct-http" : "socketjack-master-relay",
                    relay = selectedRelay?.RouteName ?? ""
                }
            });
        }
    }

    private bool TryResolveAutoModeDecisionTarget(
        string requestedServerId,
        string originMode,
        bool poolEnabled,
        bool premiumModelsEnabled,
        AccountRecord? account,
        out RegisteredServer? selectedServer,
        out MasterShellRelay? selectedRelay,
        out Uri? selectedBaseUri,
        out string classifierModel,
        out int eligibleCount,
        out int premiumBlockedCount,
        out string reason) {
        selectedServer = null;
        selectedRelay = null;
        selectedBaseUri = null;
        classifierModel = "";
        eligibleCount = 0;
        premiumBlockedCount = 0;
        reason = "";
        bool sameOriginOnly = originMode.Equals("same-origin", StringComparison.OrdinalIgnoreCase);
        bool canUsePremium = premiumModelsEnabled && AccountHasAutoPremiumTokens(account);
        DateTimeOffset now = DateTimeOffset.UtcNow;
        var eligible = new List<(RegisteredServer Server, MasterShellRelay? Relay, Uri BaseUri, bool Direct, string Model, int ServerPreference, int ModelScore)>();

        foreach (RegisteredServer server in GetServers(refreshAvailability: true).Where(server => !server.WebsiteHidden)) {
            server.HydrateFromStoredRegistration();
            TryHydrateAutoServerModelInventory(server);
            if (!ServerIsAutoOnline(server, "text"))
                continue;
            if (!ServerMatchesAutoRequest(server, requestedServerId))
                continue;
            if (!ServerSupportsAutoMode(server, "", "text"))
                continue;
            string model = ChooseAutoModeDecisionModel(server);
            if (string.IsNullOrWhiteSpace(model))
                continue;
            if (ServerRequiresAutoPremium(server) && !canUsePremium) {
                premiumBlockedCount++;
                continue;
            }

            int serverPreference = AutoModeDecisionServerPreference(server);
            int modelScore = AutoModeDecisionModelScore(model);
            bool directAdded = false;
            if (!sameOriginOnly && TryBuildAutoDirectBaseUri(server, out Uri? directBaseUri) && directBaseUri != null) {
                eligible.Add((server, null, directBaseUri, true, model, serverPreference, modelScore));
                directAdded = true;
            }
            if (directAdded)
                continue;

            if (TryResolveAutoRouteName(server, out string routeName)) {
                MasterShellRelay? relay = ResolveShellRelayForProxy(routeName);
                if (relay == null || !relay.Enabled || !relay.IsRunning || !ShouldAttemptShellProxyForward(relay, now))
                    continue;
                eligible.Add((server, relay, new Uri("http://127.0.0.1:" + relay.PublicPort.ToString(CultureInfo.InvariantCulture) + "/"), false, model, serverPreference, modelScore));
            }
        }

        eligibleCount = eligible.Count;
        var ordered = eligible
            .OrderBy(item => item.ServerPreference)
            .ThenByDescending(item => item.ModelScore)
            .ThenBy(item => AutoResourceLoadScore(item.Server))
            .ThenByDescending(item => AutoHardwareScore(item.Server))
            .ThenByDescending(item => item.Direct)
            .ThenBy(item => AutoLatencyScore(item.Server))
            .ThenBy(item => AutoCostScore(item.Server))
            .ThenBy(item => item.Server.TitleText, StringComparer.OrdinalIgnoreCase)
            .ToList();
        long poolSequence = Interlocked.Increment(ref _autoPoolSequence);
        var selected = poolEnabled && ordered.Count > 0
            ? ordered[(int)(unchecked((ulong)poolSequence) % (ulong)Math.Min(ordered.Count, Math.Max(1, ordered.Count > 2 ? 2 : ordered.Count)))]
            : ordered.FirstOrDefault();

        if (selected.Server == null) {
            if (premiumBlockedCount > 0 && !premiumModelsEnabled)
                reason = "TitanX/Sable or another reasoning router is available only through Premium Models.";
            else if (premiumBlockedCount > 0 && account == null)
                reason = "A reasoning router is available, but SocketJack.com login with tokens is required.";
            else if (premiumBlockedCount > 0)
                reason = "A reasoning router is available, but this account has no tokens remaining.";
            else if (!string.IsNullOrWhiteSpace(requestedServerId))
                reason = "The requested Auto router is not healthy or cannot classify Auto prompts.";
            else
                reason = "No healthy benchmarked TitanX, Sable, or other text reasoning model is available for Auto mode routing.";
            return false;
        }

        selectedServer = selected.Server;
        selectedRelay = selected.Relay;
        selectedBaseUri = selected.BaseUri;
        classifierModel = selected.Model;
        return true;
    }

    private static string ExtractAutoDecisionPrompt(HttpRequest request) {
        string prompt = FirstNonEmpty(
            GetQuery(request, "originalPrompt"),
            GetQuery(request, "original_prompt"),
            GetJsonBodyText(request, "originalPrompt"),
            GetJsonBodyText(request, "original_prompt"),
            GetQuery(request, "prompt"),
            GetQuery(request, "message"),
            GetQuery(request, "q"),
            GetJsonBodyText(request, "prompt"),
            GetJsonBodyText(request, "message"),
            GetJsonBodyText(request, "q"));
        if (!string.IsNullOrWhiteSpace(prompt))
            return prompt.Trim();

        if (string.IsNullOrWhiteSpace(request?.Body))
            return "";
        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            if (document.RootElement.ValueKind != JsonValueKind.Object ||
                !document.RootElement.TryGetProperty("messages", out JsonElement messages) ||
                messages.ValueKind != JsonValueKind.Array)
                return "";

            foreach (JsonElement message in messages.EnumerateArray().Reverse()) {
                if (message.ValueKind != JsonValueKind.Object)
                    continue;
                string role = GetJsonString(message, "role");
                if (!role.Equals("user", StringComparison.OrdinalIgnoreCase))
                    continue;
                string content = GetJsonString(message, "content");
                if (!string.IsNullOrWhiteSpace(content))
                    return content.Trim();
            }
        } catch {
        }

        return "";
    }

    private static byte[] BuildAutoModeDecisionRequestBody(string prompt, string model) {
        var body = new JsonObject {
            ["temperature"] = 0,
            ["max_tokens"] = 32,
            ["sessionId"] = "auto_router_" + Guid.NewGuid().ToString("N"),
            ["messages"] = new JsonArray {
                new JsonObject {
                    ["role"] = "system",
                    ["content"] = "You are SocketJack Auto Router. Classify the user's prompt into exactly one command. Respond with only the command. Do not explain, think aloud, include reasoning, or write any other text. Allowed single-route commands: USE TEXT, USE MULTIMODAL, USE IMAGE, USE VIDEO, USE AUDIO, USE EMBEDDING. SocketJack can also run multiple independent slave agents at once and then route the results through a master answer. For true parallel generation or explicitly independent-agent work, return one Start_N command where N is 2-12: Start_N_Image_Gen for N independent JackONNX image generator slaves, Start_N_Video_Gen for video generator slaves, Start_N_Audio_Gen for audio generator slaves, or Start_N_Text for text/reasoning agents. Do not use Start_N_* merely because the final answer needs several websites, URLs, links, citations, search queries, facts, bullets, sections, or comparison rows. Route URL/link/source/citation compilation, search, documentation lookup, official homepage lookup, browser work, file, code, shell, admin, external actions, workstation model delegation, and current/latest/live lookup to USE TEXT. Use Start_N_Image_Gen when the user asks for multiple separate visual outputs, including N images, a batch, set, series, collection, pack, several/multiple options, variants, variations, versions, concepts, drafts, logos, portraits, icons, thumbnails, posters, renders, or similar visual outputs. Do not use Start_N_Image_Gen when the user asks for several subjects inside one image, collage, sprite sheet, contact sheet, grid, or single canvas. Use USE VIDEO for one video or clip. Use USE IMAGE for one image/art request. Use USE AUDIO for one speech, sound, voice, music, or audio request. Use USE MULTIMODAL for analyzing attached/linked media. Use USE EMBEDDING for vector or semantic-search tasks. Use USE TEXT for ordinary chat, writing, explanation, Q&A, current-info questions, URLs, files, and source requests."
                },
                new JsonObject {
                    ["role"] = "user",
                    ["content"] = "/no_think\nPrompt: " + (prompt ?? "").Trim() + "\nCommand:"
                }
            }
        };
        if (!string.IsNullOrWhiteSpace(model))
            body["model"] = model.Trim();
        return Encoding.UTF8.GetBytes(body.ToJsonString(MasterListJson.Options));
    }

    private string ChooseAutoModeDecisionModel(RegisteredServer server) {
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var candidates = new List<(string Model, int AvailabilityScore)>();
        void Add(string value, int availabilityScore = 0) {
            string clean = CleanAutoModelDisplayName(value);
            if (string.IsNullOrWhiteSpace(clean))
                return;
            string normalized = NormalizeAutoModelId(clean);
            if (seen.Add(normalized))
                candidates.Add((value, availabilityScore));
        }

        foreach (RegisteredServerModelInfo item in server.Models.Where(item => AutoModelIsSelectableForMode(item, "text") && !AutoModelRequiresFreshBenchmark(server, item)))
            Add(item.Id, item.Loaded ? 500 : item.Enabled ? 60 : item.RuntimeLoadEnabled || item.DynamicLoadEnabled ? 20 : 0);

        return candidates
            .OrderByDescending(candidate => candidate.AvailabilityScore + AutoModeDecisionModelScore(candidate.Model))
            .ThenBy(candidate => CleanAutoModelDisplayName(candidate.Model), StringComparer.OrdinalIgnoreCase)
            .Select(candidate => candidate.Model)
            .FirstOrDefault() ?? "";
    }

    private static int AutoModeDecisionServerPreference(RegisteredServer server) {
        string text = NormalizeAutoModelId(string.Join(" ", server.Id, server.TitleText, server.DisplayName, server.Endpoint, server.LaunchUrl));
        if (text.Contains("titanx", StringComparison.OrdinalIgnoreCase) || text.Contains("titan-x", StringComparison.OrdinalIgnoreCase) || text.Contains("titan x", StringComparison.OrdinalIgnoreCase))
            return 0;
        if (text.Contains("sable", StringComparison.OrdinalIgnoreCase))
            return 1;
        return 20;
    }

    private static int AutoModeDecisionModelScore(string model) {
        string text = NormalizeAutoModelId(CleanAutoModelDisplayName(model));
        int score = 1;
        if (text.Contains("claude", StringComparison.OrdinalIgnoreCase)) score += 90;
        if (Regex.IsMatch(text, @"(?:^|[\s._/-])2b(?:[\s._/-]|$)", RegexOptions.IgnoreCase)) score += 70;
        if (text.Contains("reason", StringComparison.OrdinalIgnoreCase)) score += 50;
        if (text.Contains("qwen", StringComparison.OrdinalIgnoreCase)) score += 35;
        if (text.Contains("opus", StringComparison.OrdinalIgnoreCase)) score += 24;
        if (text.Contains("distill", StringComparison.OrdinalIgnoreCase)) score += 18;
        if (text.Contains("tool", StringComparison.OrdinalIgnoreCase) || text.Contains("function", StringComparison.OrdinalIgnoreCase)) score += 12;
        if (text.Contains("instruct", StringComparison.OrdinalIgnoreCase) || text.Contains("chat", StringComparison.OrdinalIgnoreCase)) score += 8;
        if (Regex.IsMatch(text, @"(?:stable|diffusion|sdxl|flux|image|video|audio|speech|tts|whisper|embed|embedding)", RegexOptions.IgnoreCase)) score -= 35;
        if (Regex.IsMatch(text, @"(?:tokenizer|scheduler|vae|unet|config|pytorch|onnx|safetensors)", RegexOptions.IgnoreCase)) score -= 100;
        return score;
    }

    private static string ExtractAutoModeDecisionText(string raw) {
        if (string.IsNullOrWhiteSpace(raw))
            return "";
        try {
            using JsonDocument document = JsonDocument.Parse(raw);
            string text = ExtractAutoModeDecisionText(document.RootElement);
            if (!string.IsNullOrWhiteSpace(text))
                return text.Trim();
        } catch {
        }

        string streamedText = ExtractAutoModeDecisionTextFromStream(raw);
        if (!string.IsNullOrWhiteSpace(streamedText))
            return streamedText.Trim();

        return raw.Trim();
    }

    private static string ExtractAutoModeDecisionTextFromStream(string raw) {
        if (string.IsNullOrWhiteSpace(raw))
            return "";

        var parts = new List<string>();
        foreach (string line in raw.Split(new[] { "\r\n", "\n" }, StringSplitOptions.None)) {
            string text = line.Trim();
            if (string.IsNullOrWhiteSpace(text) ||
                text.StartsWith("event:", StringComparison.OrdinalIgnoreCase) ||
                text.StartsWith("id:", StringComparison.OrdinalIgnoreCase) ||
                text.StartsWith("retry:", StringComparison.OrdinalIgnoreCase))
                continue;

            if (text.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
                text = text.Substring(5).Trim();

            if (string.IsNullOrWhiteSpace(text) || text.Equals("[DONE]", StringComparison.OrdinalIgnoreCase))
                continue;

            try {
                using JsonDocument document = JsonDocument.Parse(text);
                string extracted = ExtractAutoModeDecisionText(document.RootElement);
                if (!string.IsNullOrWhiteSpace(extracted) && !IsAutoModeDecisionProgressText(extracted)) {
                    parts.Add(extracted);
                    continue;
                }
            } catch {
            }

            if (!IsAutoModeDecisionProgressText(text) && (
                text.Contains("START_", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("START ", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("USE ", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("GENERATE ", StringComparison.OrdinalIgnoreCase) ||
                text.Contains("CREATE EMBEDDING", StringComparison.OrdinalIgnoreCase)))
                parts.Add(text);
        }

        return string.Join(" ", parts);
    }

    private static bool IsAutoModeDecisionProgressText(string value) {
        string text = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(text))
            return true;

        return Regex.IsMatch(text, @"^(connected to auto server|waiting for|checking llmruntime model|llmruntime model .* is loaded|opening chat stream|loading llmruntime model|running prompt on llmruntime|server started|server completed|server is working|done\.?|failed)$", RegexOptions.IgnoreCase) ||
            Regex.IsMatch(text, @"\bstill connected after \d+s\b", RegexOptions.IgnoreCase);
    }

    private static string ExtractAutoModeDecisionText(JsonElement element) {
        if (element.ValueKind == JsonValueKind.Object) {
            string direct = FirstNonEmpty(
                GetJsonString(element, "content"),
                GetJsonString(element, "text"),
                GetJsonString(element, "message"),
                GetJsonString(element, "output_text"),
                GetJsonString(element, "outputText"),
                GetJsonString(element, "reasoning"));
            if (!string.IsNullOrWhiteSpace(direct))
                return direct;

            if (element.TryGetProperty("choices", out JsonElement choices) && choices.ValueKind == JsonValueKind.Array) {
                foreach (JsonElement choice in choices.EnumerateArray()) {
                    string choiceText = ExtractAutoModeDecisionText(choice);
                    if (!string.IsNullOrWhiteSpace(choiceText))
                        return choiceText;
                }
            }

            if (element.TryGetProperty("message", out JsonElement messageElement)) {
                string messageText = ExtractAutoModeDecisionText(messageElement);
                if (!string.IsNullOrWhiteSpace(messageText))
                    return messageText;
            }

            if (element.TryGetProperty("delta", out JsonElement deltaElement)) {
                string deltaText = ExtractAutoModeDecisionText(deltaElement);
                if (!string.IsNullOrWhiteSpace(deltaText))
                    return deltaText;
            }

            if (element.TryGetProperty("output", out JsonElement outputElement)) {
                string outputText = ExtractAutoModeDecisionText(outputElement);
                if (!string.IsNullOrWhiteSpace(outputText))
                    return outputText;
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            var parts = new List<string>();
            foreach (JsonElement item in element.EnumerateArray()) {
                string text = ExtractAutoModeDecisionText(item);
                if (!string.IsNullOrWhiteSpace(text))
                    parts.Add(text);
            }
            return string.Join(" ", parts);
        } else if (element.ValueKind == JsonValueKind.String) {
            return element.GetString() ?? "";
        }

        return "";
    }

    private static bool TryParseAutoModeDecision(string value, out string command, out string mode) {
        string text = Regex.Replace((value ?? "").Trim().ToUpperInvariant(), @"\s+", " ");
        command = "";
        mode = "";
        bool Has(string pattern) => Regex.IsMatch(text, pattern, RegexOptions.IgnoreCase);
        Match startMatch = Regex.Match(text, @"\bSTART[_\s-]*(\d{1,2})[_\s-]*(IMAGE[_\s-]*GEN|IMAGE|VIDEO[_\s-]*GEN|VIDEO|AUDIO[_\s-]*GEN|AUDIO|TOOLS?|AGENTS?|TEXT|REASONING)\b", RegexOptions.IgnoreCase);
        if (startMatch.Success) {
            int count = Math.Clamp(ParseInt(startMatch.Groups[1].Value, 0, 0, 12), 0, 12);
            string kind = startMatch.Groups[2].Value.Replace(" ", "_").Replace("-", "_").ToUpperInvariant();
            if (kind.StartsWith("IMAGE", StringComparison.OrdinalIgnoreCase))
                mode = "image";
            else if (kind.StartsWith("VIDEO", StringComparison.OrdinalIgnoreCase))
                mode = "video";
            else if (kind.StartsWith("AUDIO", StringComparison.OrdinalIgnoreCase))
                mode = "audio";
            else if (kind.StartsWith("TOOL", StringComparison.OrdinalIgnoreCase) || kind.StartsWith("AGENT", StringComparison.OrdinalIgnoreCase))
                mode = "text";
            else
                mode = "text";
            command = BuildAutoModeDecisionCommand(mode, count);
            return count > 1 && !string.IsNullOrWhiteSpace(mode);
        }

        if (Has(@"\bUSE VIDEO\b|\bGENERATE VIDEO\b|^VIDEO$|\b(?:generate|create|make|render|animate)\b.{0,160}\b(?:video|clip|movie|animation|mp4|webm|gif)\b|\b(?:video|clip|movie|animation)\b.{0,160}\b(?:generate|create|make|render|animate|request)\b")) {
            command = "USE VIDEO";
            mode = "video";
        } else if (Has(@"\bUSE IMAGE\b|\bGENERATE IMAGE\b|^IMAGE$|\b(?:generate|create|make|draw|render)\b.{0,160}\b(?:image|picture|photo|illustration|art|logo|poster|thumbnail|wallpaper)\b|\b(?:image|picture|photo|illustration|art|logo|poster|thumbnail|wallpaper)\b.{0,160}\b(?:generate|create|make|draw|render|request)\b")) {
            command = "USE IMAGE";
            mode = "image";
        } else if (Has(@"\bUSE AUDIO\b|\bGENERATE AUDIO\b|^AUDIO$|\b(?:generate|create|make|speak|narrate)\b.{0,160}\b(?:audio|sound|music|song|voice|speech|tts|narration)\b|\b(?:audio|sound|music|song|voice|speech|tts|narration)\b.{0,160}\b(?:generate|create|make|request)\b")) {
            command = "USE AUDIO";
            mode = "audio";
        } else if (Has(@"\bUSE TOOLS\b|^TOOLS?$|^AGENT$|\b(?:browser|website|file|folder|download|upload|code|shell|terminal|command|admin|tool|agent|open|click|run)\b|\b(?:find|compile|collect|gather|list|search|look\s*up|return|provide|compare|verify|cite|source)\b.{0,160}\b(?:urls?|links?|sources?|citations?|references?|websites?|web\s+pages?|pages?|docs?|documentation|home\s*pages?|official)\b|\b(?:official|urls?|links?|sources?|citations?|references?|websites?|web\s+pages?|pages?|docs?|documentation|home\s*pages?)\b.{0,160}\b(?:find|compile|collect|gather|list|search|look\s*up|return|provide|compare|verify|cite|source)\b|\b(?:another|other|enabled|workstation|runtime|web\s*chat)\s+models?\b|\bmodels?\b.{0,160}\b(?:consult|compare|delegate|run|ask|signal|load|enabled|workstation|runtime|web\s*chat)\b|\b(?:consult|compare|delegate|ask|signal|load|run)\b.{0,160}\b(?:another|other|enabled|workstation|runtime|web\s*chat)\s+models?\b|\b(?:ask|consult|delegate|compare\s+with|run|load)\b.{0,160}\b(?:qwen|llama|mistral|gemma|phi|deepseek|gpt[-_ ]?oss|model)\b|\b(?:current|latest|live|right now|today|recent|up[- ]?to[- ]?date)\b.{0,160}\b(?:lookup|search|fact|answer|question|president|weather|price|news)\b")) {
            command = "USE TEXT";
            mode = "text";
        } else if (Has(@"\bUSE EMBEDDINGS?\b|\bCREATE EMBEDDINGS?\b|\bGENERATE EMBEDDINGS?\b|^EMBEDDINGS?$|^VECTOR$")) {
            command = "USE EMBEDDING";
            mode = "embedding";
        } else if (Has(@"\bUSE MULTIMODAL\b|\bGENERATE MULTIMODAL\b|\bANALYZE MULTIMODAL\b|^MULTIMODAL$|^VISION$")) {
            command = "USE MULTIMODAL";
            mode = "multimodal";
        } else if (Has(@"\bUSE TEXT\b|\bGENERATE TEXT\b|\bANSWER TEXT\b|^TEXT$|^CHAT$|\b(?:ordinary|straightforward|simple|factual)\b.{0,160}\b(?:question|answer|q&a|chat|text)\b")) {
            command = "USE TEXT";
            mode = "text";
        }

        return !string.IsNullOrWhiteSpace(mode);
    }

    private static bool AutoPromptNeedsTools(string text) {
        if (string.IsNullOrWhiteSpace(text))
            return false;

        if (Regex.IsMatch(text, @"\b(browser|website|file|folder|download|upload|code|shell|terminal|command|admin|tool|agent|open|click|run)\b", RegexOptions.IgnoreCase))
            return true;

        if (Regex.IsMatch(text, @"\b(?:another|other|enabled|workstation|runtime|web\s*chat)\s+models?\b|\bmodels?\b.{0,160}\b(?:consult|compare|delegate|run|ask|signal|load|enabled|workstation|runtime|web\s*chat)\b|\b(?:consult|compare|delegate|ask|signal|load|run)\b.{0,160}\b(?:another|other|enabled|workstation|runtime|web\s*chat)\s+models?\b|\b(?:ask|consult|delegate|compare\s+with|run|load)\b.{0,160}\b(?:qwen|llama|mistral|gemma|phi|deepseek|gpt[-_ ]?oss|model)\b", RegexOptions.IgnoreCase))
            return true;

        if (Regex.IsMatch(text, @"\b(current|latest|live|right now|today|recent|up[- ]?to[- ]?date)\b.*\b(lookup|search|find|fact|answer|question|president|weather|price|news|listing|listings)\b", RegexOptions.IgnoreCase))
            return true;

        if (Regex.IsMatch(text, @"\b(find|search|look\s*up|lookup|locate|get|fetch|browse|check)\b.{0,180}\b(github|git\s*hub|repo|repository|url|link|website|site|web|internet|ebay|amazon|price|listing|listings|guide|docs|documentation|download)\b", RegexOptions.IgnoreCase))
            return true;

        if (Regex.IsMatch(text, @"\b(github|git\s*hub|repo|repository|url|link|website|site|web|internet|ebay|amazon|price|listing|listings|guide|docs|documentation|download)\b.{0,180}\b(find|search|look\s*up|lookup|locate|get|fetch|browse|check|summary|summarize)\b", RegexOptions.IgnoreCase))
            return true;

        return false;
    }

    private static string InferAutoModeFromPrompt(string prompt) {
        string text = (prompt ?? "").Trim().ToLowerInvariant();
        if (Regex.IsMatch(text, @"\b(video|clip|movie|animation|animate|mp4|webm|gif)\b", RegexOptions.IgnoreCase))
            return "video";
        if (Regex.IsMatch(text, @"\b(image|picture|photo|draw|illustration|art|logo|poster|thumbnail|wallpaper|portrait|icon|avatar|sticker|banner|cover|mockup|concept|render|design|scene|graphic|visual|asset)\b", RegexOptions.IgnoreCase))
            return "image";
        if (Regex.IsMatch(text, @"\b(audio|sound|music|song|voice|speech|tts|speak|narration)\b", RegexOptions.IgnoreCase))
            return "audio";
        if (Regex.IsMatch(text, @"\b(embed|embedding|vector|semantic search)\b", RegexOptions.IgnoreCase))
            return "embedding";
        if (AutoPromptNeedsTools(text))
            return "text";
        if (Regex.IsMatch(text, @"\b(attached|upload|image analysis|vision|multimodal|describe this|what is in)\b", RegexOptions.IgnoreCase))
            return "multimodal";
        return "text";
    }

    private static int AutoBatchCountWord(string text) {
        text = Regex.Replace((text ?? "").Trim().ToLowerInvariant(), @"\s+", " ");
        if (int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value))
            return value;
        return text switch {
            "one" => 1,
            "two" => 2,
            "three" => 3,
            "four" => 4,
            "five" => 5,
            "six" => 6,
            "seven" => 7,
            "eight" => 8,
            "nine" => 9,
            "ten" => 10,
            "eleven" => 11,
            "twelve" => 12,
            "a couple" => 2,
            "couple" => 2,
            "pair" => 2,
            "a few" => 3,
            "few" => 3,
            "several" => 4,
            "handful" => 5,
            "half a dozen" => 6,
            "half dozen" => 6,
            "dozen" => 12,
            _ => 0
        };
    }

    private static bool AutoPromptRequestsSingleMediaCanvas(string text) {
        if (string.IsNullOrWhiteSpace(text))
            return false;
        if (Regex.IsMatch(text, @"\b(?:all|everything)\s+(?:in|into|as|on)\s+(?:one|a|an|single)\b", RegexOptions.IgnoreCase))
            return true;
        if (Regex.IsMatch(text, @"\b(?:in|into|as|on|within|inside)\s+(?:one|a|an|single)\s+(?:image|picture|photo|render|illustration|poster|canvas|composition|scene|video|clip|track|audio|file)\b", RegexOptions.IgnoreCase))
            return true;
        if (Regex.IsMatch(text, @"\b(?:one|single)\s+(?:image|picture|photo|render|illustration|poster|canvas|video|clip|audio|track|file)\s+(?:with|containing|of|showing)\b", RegexOptions.IgnoreCase))
            return true;
        if (Regex.IsMatch(text, @"\b(?:collage|contact\s+sheet|sprite\s+sheet|multi[-\s]?panel|composite|grid)\b", RegexOptions.IgnoreCase) &&
            !Regex.IsMatch(text, @"\b(?:not|no|without)\s+(?:a\s+)?(?:collage|contact\s+sheet|sprite\s+sheet|multi[-\s]?panel|composite|grid)\b", RegexOptions.IgnoreCase))
            return true;
        return false;
    }

    private static int AutoMediaBatchDefaultCount(string text) {
        if (Regex.IsMatch(text, @"\bhalf\s+(?:a\s+)?dozen\b", RegexOptions.IgnoreCase))
            return 6;
        if (Regex.IsMatch(text, @"\bdozen\b", RegexOptions.IgnoreCase))
            return 12;
        if (Regex.IsMatch(text, @"\b(?:a\s+couple|couple|pair)\b", RegexOptions.IgnoreCase))
            return 2;
        if (Regex.IsMatch(text, @"\b(?:a\s+few|few)\b", RegexOptions.IgnoreCase))
            return 3;
        if (Regex.IsMatch(text, @"\bseveral\b", RegexOptions.IgnoreCase))
            return 4;
        if (Regex.IsMatch(text, @"\bhandful\b", RegexOptions.IgnoreCase))
            return 5;
        if (Regex.IsMatch(text, @"\b(?:batch|multiple|various|set|series|collection|pack|bundle|variants?|variations?|versions?|options?|concepts?|alternatives?|samples?|drafts?)\b", RegexOptions.IgnoreCase))
            return 4;
        return 0;
    }

    private static bool AutoPromptLooksMediaBatchGeneration(string text, string noun) {
        if (string.IsNullOrWhiteSpace(text) || string.IsNullOrWhiteSpace(noun))
            return false;
        bool hasBatchSignal = Regex.IsMatch(text, @"\b(?:batch|multiple|several|various|a\s+few|few|set|series|collection|pack|bundle|variants?|variations?|versions?|options?|concepts?|alternatives?|samples?|drafts?)\b", RegexOptions.IgnoreCase);
        bool hasGenerationSignal = Regex.IsMatch(text, @"\b(?:generate|create|make|draw|render|design|paint|illustrate|produce|draft|mock\s*up|mockup)\b", RegexOptions.IgnoreCase);
        bool hasMediaNoun = Regex.IsMatch(text, @"\b" + noun + @"\b", RegexOptions.IgnoreCase);
        return hasBatchSignal && hasGenerationSignal && hasMediaNoun;
    }

    private static int InferAutoParallelAgentCount(string prompt, string mode) {
        string text = (prompt ?? "").Trim();
        if (string.IsNullOrWhiteSpace(text))
            return 0;
        string normalizedMode = NormalizeAutoMode(mode);
        if (AutoPromptRequestsSingleMediaCanvas(text))
            return 0;
        string noun = normalizedMode switch {
            "image" => @"(?:images?|pictures?|photos?|renders?|illustrations?|variants?|variations?|versions?|options?|concepts?|alternatives?|samples?|drafts?|generations?|outputs?|thumbnails?|logos?|posters?|portraits?|characters?|designs?|icons?|avatars?|stickers?|banners?|covers?|mockups?|scenes?|wallpapers?|backgrounds?|graphics?|visuals?|assets?)",
            "video" => @"(?:videos?|movies?|animations?|clips?|video\s+outputs?|video\s+generations?)",
            "audio" => @"(?:audio(?:\s+clips?)?|sounds?|tracks?|audio\s+outputs?|audio\s+generations?)",
            "tools" => @"(?:agents?|workers?|tasks?|searches?|lookups?|tool\s+runs?)",
            "text" => @"(?:agents?|branches?|drafts?|answers?|approaches?|options?|analyses?)",
            _ => ""
        };
        string count = @"(?<count>\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve|a\s+couple|couple|pair|a\s+few|few|several|handful|half\s+a\s+dozen|half\s+dozen|dozen)";
        if (!string.IsNullOrWhiteSpace(noun)) {
            string modifiers = @"(?:\s+(?:different|distinct|unique|separate|individual|alternate|alternative|varied|new|quick|sample|sampled|draft|drafts?|style|styled|concept|concepts?))*";
            Match nounMatch = Regex.Match(text, @"\b" + count + modifiers + @"\s+" + noun + @"\b", RegexOptions.IgnoreCase);
            if (nounMatch.Success) {
                int value = AutoBatchCountWord(nounMatch.Groups["count"].Value);
                if (value > 1)
                    return Math.Clamp(value, 2, 12);
            }
            Match batchCountMatch = Regex.Match(text, @"\b(?:batch|set|series|collection|pack|bundle|round|run)\s+(?:of\s+)?" + count + @"\b.{0,180}\b" + noun + @"\b", RegexOptions.IgnoreCase);
            if (batchCountMatch.Success) {
                int value = AutoBatchCountWord(batchCountMatch.Groups["count"].Value);
                if (value > 1)
                    return Math.Clamp(value, 2, 12);
            }
            Match broadCountMatch = Regex.Match(text, @"\b" + count + @"\b(?=.{0,160}\b" + noun + @"\b)", RegexOptions.IgnoreCase);
            if (broadCountMatch.Success && Regex.IsMatch(text, @"\b(?:generate|create|make|draw|render|design|paint|illustrate|produce|draft|mock\s*up|mockup)\b", RegexOptions.IgnoreCase)) {
                int value = AutoBatchCountWord(broadCountMatch.Groups["count"].Value);
                if (value > 1)
                    return Math.Clamp(value, 2, 12);
            }
            if (AutoPromptLooksMediaBatchGeneration(text, noun)) {
                int value = AutoMediaBatchDefaultCount(text);
                if (value > 1)
                    return Math.Clamp(value, 2, 12);
            }
        }

        Match startMatch = Regex.Match(text, @"\bstart[_\s-]*" + count + @"[_\s-]*(?:image[_\s-]*gen|video[_\s-]*gen|audio[_\s-]*gen|tools?|agents?|text)\b", RegexOptions.IgnoreCase);
        if (startMatch.Success) {
            int value = AutoBatchCountWord(startMatch.Groups["count"].Value);
            if (value > 1)
                return Math.Clamp(value, 2, 12);
        }

        return 0;
    }

    private static string BuildAutoModeDecisionCommand(string mode, int parallelAgents = 0) {
        mode = NormalizeAutoMode(mode);
        if (parallelAgents > 1) {
            int count = Math.Clamp(parallelAgents, 2, 12);
            if (mode.Equals("video", StringComparison.OrdinalIgnoreCase)) return "Start_" + count.ToString(CultureInfo.InvariantCulture) + "_Video_Gen";
            if (mode.Equals("image", StringComparison.OrdinalIgnoreCase)) return "Start_" + count.ToString(CultureInfo.InvariantCulture) + "_Image_Gen";
            if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase)) return "Start_" + count.ToString(CultureInfo.InvariantCulture) + "_Audio_Gen";
            if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase)) return "Start_" + count.ToString(CultureInfo.InvariantCulture) + "_Tools";
            return "Start_" + count.ToString(CultureInfo.InvariantCulture) + "_Text";
        }
        if (mode.Equals("video", StringComparison.OrdinalIgnoreCase)) return "USE VIDEO";
        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase)) return "USE IMAGE";
        if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase)) return "USE AUDIO";
        if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase)) return "USE TEXT";
        if (mode.Equals("embedding", StringComparison.OrdinalIgnoreCase)) return "USE EMBEDDING";
        if (mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase)) return "USE MULTIMODAL";
        return "USE TEXT";
    }

    private static int AutoModeDecisionParallelAgentCount(string command) {
        Match match = Regex.Match(command ?? "", @"\bStart_(\d{1,2})_", RegexOptions.IgnoreCase);
        return match.Success ? Math.Clamp(ParseInt(match.Groups[1].Value, 0, 0, 12), 0, 12) : 0;
    }

    private static string AutoModeDecisionParallelAgentMode(string command) {
        string text = (command ?? "").Trim();
        if (!Regex.IsMatch(text, @"\bStart_\d{1,2}_", RegexOptions.IgnoreCase))
            return "";
        if (text.Contains("Image", StringComparison.OrdinalIgnoreCase)) return "image";
        if (text.Contains("Video", StringComparison.OrdinalIgnoreCase)) return "video";
        if (text.Contains("Audio", StringComparison.OrdinalIgnoreCase)) return "audio";
        if (text.Contains("Tools", StringComparison.OrdinalIgnoreCase)) return "tools";
        return "text";
    }

    private HuggingFaceModelCatalog GetHuggingFaceModelCatalog(CancellationToken cancellationToken) {
        HuggingFaceModelCatalog cached = _huggingFaceModelCatalog ?? LoadHuggingFaceModelCatalogFromDisk();
        if (!HuggingFaceModelCatalogIsStale(cached))
            return cached;

        bool hasWarmCache = cached.Models != null && cached.Models.Count > 0;
        bool acquired;
        if (hasWarmCache) {
            acquired = _huggingFaceModelCatalogSemaphore.Wait(0);
        } else {
            _huggingFaceModelCatalogSemaphore.Wait(cancellationToken);
            acquired = true;
        }

        if (!acquired)
            return cached;

        try {
            cached = _huggingFaceModelCatalog ?? LoadHuggingFaceModelCatalogFromDisk();
            if (!HuggingFaceModelCatalogIsStale(cached))
                return cached;

            HuggingFaceModelCatalog fresh = FetchHuggingFaceModelCatalog(cancellationToken);
            SaveHuggingFaceModelCatalog(fresh);
            _huggingFaceModelCatalog = fresh;
            return fresh;
        } catch (Exception ex) {
            cached.Error = "Refresh failed: " + ex.Message;
            _huggingFaceModelCatalog = cached;
            return cached;
        } finally {
            _huggingFaceModelCatalogSemaphore.Release();
        }
    }

    private HuggingFaceModelCatalog LoadHuggingFaceModelCatalogFromDisk() {
        if (_huggingFaceModelCatalog != null)
            return _huggingFaceModelCatalog;

        string path = GetHuggingFaceModelCatalogPath();
        try {
            if (File.Exists(path)) {
                HuggingFaceModelCatalog? catalog = JsonSerializer.Deserialize<HuggingFaceModelCatalog>(
                    File.ReadAllText(path, Encoding.UTF8),
                    MasterListJson.Options);
                if (catalog != null) {
                    catalog.Models ??= [];
                    _huggingFaceModelCatalog = catalog;
                    return catalog;
                }
            }
        } catch (Exception ex) {
            return new HuggingFaceModelCatalog {
                GeneratedUtc = "",
                Error = "Cache read failed: " + ex.Message
            };
        }

        var empty = new HuggingFaceModelCatalog();
        _huggingFaceModelCatalog = empty;
        return empty;
    }

    private HuggingFaceModelCatalog FetchHuggingFaceModelCatalog(CancellationToken cancellationToken) {
        var models = new Dictionary<string, HuggingFaceCachedModel>(StringComparer.OrdinalIgnoreCase);
        var errors = new List<string>();
        foreach (HuggingFaceCatalogQuery query in HuggingFaceCatalogQueries) {
            try {
                string url = BuildHuggingFaceCatalogUrl(query, 50);
                using var hfRequest = new HttpRequestMessage(HttpMethod.Get, url);
                hfRequest.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-MasterList/1.0");
                using HttpResponseMessage response = HuggingFaceCatalogHttpClient.Send(hfRequest, cancellationToken);
                string body = response.Content.ReadAsStringAsync(cancellationToken).GetAwaiter().GetResult();
                if (!response.IsSuccessStatusCode) {
                    errors.Add(query.Mode + ":" + query.PipelineTag + " HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture));
                    continue;
                }

                using JsonDocument document = JsonDocument.Parse(body);
                if (document.RootElement.ValueKind != JsonValueKind.Array)
                    continue;

                foreach (JsonElement item in document.RootElement.EnumerateArray()) {
                    if (GetJsonBool(item, "private", false))
                        continue;

                    string id = FirstNonEmpty(GetJsonString(item, "modelId"), GetJsonString(item, "id"));
                    if (!IsValidHuggingFaceModelId(id))
                        continue;

                    if (!models.TryGetValue(id, out HuggingFaceCachedModel? model)) {
                        model = new HuggingFaceCachedModel {
                            ModelId = id,
                            Url = "https://huggingface.co/" + id.Trim('/'),
                            PipelineTag = FirstNonEmpty(GetJsonString(item, "pipeline_tag"), query.PipelineTag),
                            LibraryName = FirstNonEmpty(GetJsonString(item, "library_name"), query.Library),
                            Downloads = GetJsonLong(item, "downloads", 0),
                            Likes = GetJsonLong(item, "likes", 0)
                        };
                        models[id] = model;
                    } else {
                        model.Downloads = Math.Max(model.Downloads, GetJsonLong(item, "downloads", 0));
                        model.Likes = Math.Max(model.Likes, GetJsonLong(item, "likes", 0));
                        model.PipelineTag = FirstNonEmpty(model.PipelineTag, GetJsonString(item, "pipeline_tag"), query.PipelineTag);
                        model.LibraryName = FirstNonEmpty(model.LibraryName, GetJsonString(item, "library_name"), query.Library);
                    }

                    if (!model.Modes.Any(mode => mode.Equals(query.Mode, StringComparison.OrdinalIgnoreCase)))
                        model.Modes.Add(query.Mode);
                }
            } catch (OperationCanceledException) {
                throw;
            } catch (Exception ex) {
                errors.Add(query.Mode + ":" + query.PipelineTag + " " + ex.Message);
            }
        }

        return new HuggingFaceModelCatalog {
            GeneratedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture),
            Error = errors.Count == 0 ? "" : string.Join("; ", errors.Take(5)),
            Models = models.Values
                .OrderByDescending(model => model.Downloads)
                .ThenBy(model => model.ModelId, StringComparer.OrdinalIgnoreCase)
                .ToList()
        };
    }

    private string GetHuggingFaceModelCatalogPath() {
        string dataPath = _options.ResolveDataFilePath();
        string directory = Path.GetDirectoryName(dataPath) ?? AppContext.BaseDirectory;
        return Path.Combine(directory, "huggingface-model-ids-cache.json");
    }

    private void SaveHuggingFaceModelCatalog(HuggingFaceModelCatalog catalog) {
        string path = GetHuggingFaceModelCatalogPath();
        string? directory = Path.GetDirectoryName(path);
        if (!string.IsNullOrWhiteSpace(directory))
            Directory.CreateDirectory(directory);
        File.WriteAllText(path, JsonSerializer.Serialize(catalog, MasterListJson.Options), Encoding.UTF8);
    }

    private static string BuildHuggingFaceCatalogUrl(HuggingFaceCatalogQuery query, int limit) {
        var parameters = new List<KeyValuePair<string, string>> {
            new("sort", "downloads"),
            new("direction", "-1"),
            new("limit", Math.Clamp(limit, 1, 50).ToString(CultureInfo.InvariantCulture))
        };
        AddHuggingFaceCatalogParameter(parameters, "pipeline_tag", query.PipelineTag);
        AddHuggingFaceCatalogParameter(parameters, "library", query.Library);
        AddHuggingFaceCatalogParameter(parameters, "search", query.Search);
        return "https://huggingface.co/api/models?" + string.Join("&", parameters.Select(pair =>
            Uri.EscapeDataString(pair.Key) + "=" + Uri.EscapeDataString(pair.Value)));
    }

    private static void AddHuggingFaceCatalogParameter(List<KeyValuePair<string, string>> parameters, string name, string value) {
        if (!string.IsNullOrWhiteSpace(value))
            parameters.Add(new KeyValuePair<string, string>(name, value.Trim()));
    }

    private static bool IsValidHuggingFaceModelId(string value) {
        if (string.IsNullOrWhiteSpace(value))
            return false;
        value = value.Trim();
        return value.Length <= 180 &&
               !value.Contains(' ') &&
               !value.Contains('\\') &&
               !value.StartsWith(".", StringComparison.Ordinal) &&
               value.Count(c => c == '/') <= 1;
    }

    private static DateTimeOffset GetHuggingFaceCatalogGeneratedUtc(HuggingFaceModelCatalog catalog) =>
        DateTimeOffset.TryParse(catalog.GeneratedUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed)
            ? parsed.ToUniversalTime()
            : DateTimeOffset.MinValue;

    private static bool HuggingFaceModelCatalogIsStale(HuggingFaceModelCatalog catalog) {
        DateTimeOffset generatedUtc = GetHuggingFaceCatalogGeneratedUtc(catalog);
        return generatedUtc == DateTimeOffset.MinValue ||
               DateTimeOffset.UtcNow - generatedUtc >= HuggingFaceModelCatalogMaxAge;
    }

    private static bool HuggingFaceModelMatchesMode(HuggingFaceCachedModel model, string mode) {
        if (string.IsNullOrWhiteSpace(mode))
            return true;
        if (model.Modes.Any(item => item.Equals(mode, StringComparison.OrdinalIgnoreCase)))
            return true;
        return mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase) &&
               model.Modes.Any(item => item.Equals("vision", StringComparison.OrdinalIgnoreCase));
    }

    private static long ScoreHuggingFaceModel(HuggingFaceCachedModel model, string search) {
        long score = Math.Max(0, model.Downloads) + Math.Max(0, model.Likes) * 2000L;
        if (!string.IsNullOrWhiteSpace(search)) {
            string id = model.ModelId ?? "";
            if (id.Equals(search, StringComparison.OrdinalIgnoreCase))
                score += 20_000_000L;
            else if (id.StartsWith(search, StringComparison.OrdinalIgnoreCase))
                score += 8_000_000L;
            else if (id.Contains("/" + search, StringComparison.OrdinalIgnoreCase))
                score += 4_000_000L;
        }

        return score;
    }

    private static int ParseInt(string text, int fallback, int min, int max) =>
        int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value)
            ? Math.Clamp(value, min, max)
            : fallback;

    private bool TryResolveAutoApiTarget(
        string model,
        string mode,
        string requestedServerId,
        string originMode,
        bool poolEnabled,
        double minParameterBillions,
        double maxParameterBillions,
        bool premiumModelsEnabled,
        AccountRecord? account,
        out RegisteredServer? selectedServer,
        out MasterShellRelay? selectedRelay,
        out Uri? selectedBaseUri,
        out int eligibleCount,
        out int premiumBlockedCount,
        out string reason,
        ISet<string>? excludedServerIds = null,
        ISet<string>? userDisabledModels = null) {
        selectedServer = null;
        selectedRelay = null;
        selectedBaseUri = null;
        eligibleCount = 0;
        premiumBlockedCount = 0;
        reason = "";
        DateTimeOffset now = DateTimeOffset.UtcNow;
        var eligible = new List<(RegisteredServer Server, MasterShellRelay? Relay, Uri BaseUri, bool Direct)>();
        bool sameOriginOnly = originMode.Equals("same-origin", StringComparison.OrdinalIgnoreCase);
        bool canUsePremium = premiumModelsEnabled && AccountHasAutoPremiumTokens(account);

        foreach (RegisteredServer server in GetServers(refreshAvailability: true).Where(server => !server.WebsiteHidden)) {
            server.HydrateFromStoredRegistration();
            TryHydrateAutoServerModelInventory(server);
            if (!ServerIsAutoOnline(server, mode))
                continue;
            if (!ServerMatchesAutoRequest(server, requestedServerId))
                continue;
            if (AutoServerIsExcluded(server, excludedServerIds))
                continue;
            if (!ServerSupportsAutoModel(server, model))
                continue;
            if (!ServerSupportsAutoMode(server, model, mode))
                continue;
            if (!ServerHasUsableAutoBenchmarkModel(server, model, mode, minParameterBillions, maxParameterBillions, userDisabledModels))
                continue;
            if (ServerRequiresAutoPremium(server) && !canUsePremium) {
                premiumBlockedCount++;
                continue;
            }

            bool directAdded = false;
            if (!sameOriginOnly && TryBuildAutoDirectBaseUri(server, out Uri? directBaseUri) && directBaseUri != null) {
                eligible.Add((server, null, directBaseUri, true));
                directAdded = true;
            }
            if (directAdded)
                continue;

            if (TryResolveAutoRouteName(server, out string routeName)) {
                MasterShellRelay? relay = ResolveShellRelayForProxy(routeName);
                if (relay == null || !relay.Enabled || !relay.IsRunning || !ShouldAttemptShellProxyForward(relay, now))
                    continue;

                eligible.Add((server, relay, new Uri("http://127.0.0.1:" + relay.PublicPort.ToString(CultureInfo.InvariantCulture) + "/"), false));
            }
        }

        eligibleCount = eligible.Count;
        var ordered = eligible
            .OrderBy(item => AutoResourceLoadScore(item.Server))
            .ThenByDescending(item => AutoHardwareScore(item.Server))
            .ThenByDescending(item => item.Direct)
            .ThenBy(item => AutoLatencyScore(item.Server))
            .ThenBy(item => AutoCostScore(item.Server))
            .ThenBy(item => item.Server.TitleText, StringComparer.OrdinalIgnoreCase)
            .ToList();
        long poolSequence = Interlocked.Increment(ref _autoPoolSequence);
        var selected = poolEnabled && ordered.Count > 0
            ? ordered[(int)(unchecked((ulong)poolSequence) % (ulong)Math.Min(ordered.Count, Math.Max(1, ordered.Count > 2 ? 2 : ordered.Count)))]
            : ordered.FirstOrDefault();

        if (selected.Server == null) {
            if (premiumBlockedCount > 0 && !premiumModelsEnabled) {
                reason = "Premium Auto servers are available for " + mode + ", but Premium Models are disabled on this page.";
            } else if (premiumBlockedCount > 0 && account == null) {
                reason = "Premium Auto servers are available for " + mode + ", but SocketJack.com login with tokens is required.";
            } else if (premiumBlockedCount > 0) {
                reason = "Premium Auto servers are available for " + mode + ", but this account has no tokens remaining.";
            } else if (!string.IsNullOrWhiteSpace(requestedServerId)) {
                reason = "The requested Auto server is not healthy or cannot serve " + mode + ".";
            } else if (sameOriginOnly) {
                reason = string.IsNullOrWhiteSpace(model)
                    ? "No same-origin SocketJack relay servers are available for " + mode + "."
                    : "No same-origin SocketJack relay servers are available for model '" + model + "' in " + mode + " mode.";
            } else {
                reason = string.IsNullOrWhiteSpace(model)
                ? "No healthy Auto servers with a compatible model are available for " + mode + "."
                : "No healthy Auto servers with model '" + model + "' are available for " + mode + ".";
            }
            return false;
        }

        selectedServer = selected.Server;
        selectedRelay = selected.Relay;
        selectedBaseUri = selected.BaseUri;
        return true;
    }

    private static bool ServerMatchesAutoRequest(RegisteredServer server, string requestedServerId) {
        if (string.IsNullOrWhiteSpace(requestedServerId))
            return true;

        string requested = NormalizeAutoModelId(requestedServerId);
        foreach (string value in new[] {
            server.Id,
            server.TitleText,
            server.DisplayName,
            server.Endpoint,
            server.LaunchUrl
        }) {
            string normalized = NormalizeAutoModelId(value);
            if (!string.IsNullOrWhiteSpace(normalized) &&
                (normalized.Equals(requested, StringComparison.OrdinalIgnoreCase) ||
                 normalized.EndsWith("/" + requested, StringComparison.OrdinalIgnoreCase)))
                return true;
        }

        if (TryResolveAutoRouteName(server, out string routeName) &&
            NormalizeAutoModelId(routeName).Equals(requested, StringComparison.OrdinalIgnoreCase))
            return true;

        return false;
    }

    private static bool AutoServerIsExcluded(RegisteredServer server, ISet<string>? excludedServerIds) {
        if (excludedServerIds == null || excludedServerIds.Count == 0)
            return false;

        foreach (string value in AutoServerIdentityAliases(server)) {
            if (excludedServerIds.Contains(NormalizeAutoModelId(value)))
                return true;
        }

        return false;
    }

    private void TryHydrateAutoServerModelInventory(RegisteredServer server) {
        if (server == null)
            return;
        if (server.ModelCount > 0 && !string.IsNullOrWhiteSpace(server.ModelCapabilitiesJson))
            return;
        if (!TryResolveAutoRouteName(server, out string routeName))
            return;

        MasterShellRelay? relay = ResolveShellRelayForProxy(routeName);
        if (relay == null || !relay.Enabled || !relay.IsRunning || !ShouldAttemptShellProxyForward(relay, DateTimeOffset.UtcNow))
            return;

        try {
            ShellProxyJsonFetchResult result = _shellProxyWebSocketTunnels.HasConnectedTunnel(relay.Id)
                ? _shellProxyWebSocketTunnels.FetchJson(relay, "/api/models", "", CancellationToken.None)
                : FetchShellProxyJsonForWebSocket(relay, "/api/models", "", CancellationToken.None);
            if (result.StatusCode < 200 || result.StatusCode >= 300 || string.IsNullOrWhiteSpace(result.Body))
                return;

            JsonObject inventory = ParseShellProxyJsonObject(EnrichShellProxyModelsApiJson(result.Body));
            string modelBenchmarksJson = FirstUsefulModelBenchmarksJson(
                FindUsefulModelBenchmarksJson(inventory),
                FetchShellProxyHardwareBenchmarkJson(relay));
            if (!string.IsNullOrWhiteSpace(modelBenchmarksJson))
                inventory["modelBenchmarksJson"] = modelBenchmarksJson;

            ModelRuntimeHealthInfo runtime = ReadModelRuntimeHealth(inventory.ToJsonString(MasterListJson.Options), server);
            bool changed = false;
            if (!string.IsNullOrWhiteSpace(runtime.AvailableModels) && string.IsNullOrWhiteSpace(server.AvailableModels)) {
                server.AvailableModels = runtime.AvailableModels;
                changed = true;
            }
            if (!string.IsNullOrWhiteSpace(runtime.ModelInventoryJson) && string.IsNullOrWhiteSpace(server.ModelCapabilitiesJson)) {
                server.ModelCapabilitiesJson = runtime.ModelInventoryJson;
                changed = true;
            }
            if (!string.IsNullOrWhiteSpace(runtime.ModelBenchmarksJson) && string.IsNullOrWhiteSpace(server.ModelBenchmarksJson)) {
                server.ModelBenchmarksJson = runtime.ModelBenchmarksJson;
                changed = true;
            }

            if (!changed || string.IsNullOrWhiteSpace(server.Id))
                return;

            lock (_sync) {
                int index = FindRowIndexLocked(server.Id);
                if (index < 0)
                    return;
                object[] row = _table.Rows[index];
                if (!string.IsNullOrWhiteSpace(runtime.AvailableModels))
                    SetCellIfChanged(row, nameof(RegisteredServer.AvailableModels), runtime.AvailableModels);
                if (!string.IsNullOrWhiteSpace(runtime.ModelInventoryJson))
                    SetCellIfChanged(row, nameof(RegisteredServer.ModelCapabilitiesJson), runtime.ModelInventoryJson);
                if (!string.IsNullOrWhiteSpace(runtime.ModelBenchmarksJson))
                    SetCellIfChanged(row, nameof(RegisteredServer.ModelBenchmarksJson), runtime.ModelBenchmarksJson);
            }
        } catch {
        }
    }

    private static IEnumerable<string> AutoServerIdentityAliases(RegisteredServer server) {
        if (server == null)
            yield break;

        foreach (string value in new[] {
            server.Id,
            server.TitleText,
            server.DisplayName,
            server.Endpoint,
            server.LaunchUrl,
            RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort)
        }) {
            if (!string.IsNullOrWhiteSpace(value))
                yield return value;
        }

        if (TryResolveAutoRouteName(server, out string routeName))
            yield return routeName;
    }

    private static void ExcludeAutoServer(ISet<string> excludedServerIds, RegisteredServer? server) {
        if (excludedServerIds == null || server == null)
            return;

        foreach (string value in AutoServerIdentityAliases(server)) {
            string normalized = NormalizeAutoModelId(value);
            if (!string.IsNullOrWhiteSpace(normalized))
                excludedServerIds.Add(normalized);
        }
    }

    private bool ServerHasUsableAutoBenchmarkModel(RegisteredServer server, string model, string mode, double minParameterBillions = 0, double maxParameterBillions = 0, ISet<string>? userDisabledModels = null) {
        if (server == null)
            return false;

        string normalizedMode = NormalizeAutoMode(mode);
        List<string> requestedAliases = AutoModelAliases(model).ToList();
        foreach (RegisteredServerModelInfo item in server.Models) {
            if (!AutoModelIsSelectableForMode(item, normalizedMode))
                continue;
            if (AutoModelIsUserDisabled(item.Id, userDisabledModels))
                continue;
            if (!AutoModelMatchesParameterLimit(item.Id, normalizedMode, minParameterBillions, maxParameterBillions))
                continue;
            if (requestedAliases.Count > 0 &&
                !AutoModelAliases(item.Id).Any(candidate => AutoModelAliasMatches(candidate, requestedAliases)))
                continue;
            if (AutoModelRequiresFreshBenchmark(server, item))
                continue;
            return true;
        }

        if (normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase) &&
            server.SupportsTools &&
            (string.IsNullOrWhiteSpace(model) || server.Models.Count == 0 && string.IsNullOrWhiteSpace(server.AvailableModels)) &&
            TryResolveAutoRouteName(server, out _))
            return true;

        return false;
    }

    private bool AutoModelRequiresFreshBenchmark(RegisteredServer server, RegisteredServerModelInfo item) {
        if (server == null || item == null || string.IsNullOrWhiteSpace(item.Id))
            return true;

        string key = AutoModelBenchmarkRequirementKey(server, item.Id);
        if (string.IsNullOrWhiteSpace(key))
            return false;

        lock (_autoModelBenchmarkRequirements) {
            if (!_autoModelBenchmarkRequirements.TryGetValue(key, out AutoModelBenchmarkRequirement? requirement))
                return false;

            if (AutoBenchmarkRequirementWasClientTextExtractionFailure(requirement)) {
                _autoModelBenchmarkRequirements.Remove(key);
                return false;
            }

            DateTimeOffset evidenceUtc = AutoModelBenchmarkEvidenceUtc(server, item);
            if (AutoBenchmarkRequirementCanRecoverWithFreshHealth(requirement) &&
                AutoModelHasFreshHealthRecoveryEvidence(server, item, requirement, evidenceUtc)) {
                _autoModelBenchmarkRequirements.Remove(key);
                return false;
            }

            if (!AutoModelHasBenchmarkNumber(item))
                return true;

            if (evidenceUtc > requirement.FlaggedUtc) {
                _autoModelBenchmarkRequirements.Remove(key);
                return false;
            }

            return true;
        }
    }

    private static bool AutoBenchmarkRequirementWasClientTextExtractionFailure(AutoModelBenchmarkRequirement requirement) {
        if (requirement == null)
            return false;
        string reason = requirement.Reason ?? "";
        return requirement.Mode.Equals("text", StringComparison.OrdinalIgnoreCase) &&
               (reason.Contains("did not receive any response text", StringComparison.OrdinalIgnoreCase) ||
                reason.Contains("completed without returning text", StringComparison.OrdinalIgnoreCase)) ||
               requirement.Mode.Equals("tools", StringComparison.OrdinalIgnoreCase) &&
               (reason.Contains("Auto tools request failed", StringComparison.OrdinalIgnoreCase) ||
                reason.Contains("download_file", StringComparison.OrdinalIgnoreCase) ||
                reason.Contains("Downloading file", StringComparison.OrdinalIgnoreCase));
    }

    private static bool AutoBenchmarkRequirementWasTransientHealthFailure(AutoModelBenchmarkRequirement requirement) {
        if (requirement == null)
            return false;

        string reason = requirement.Reason ?? "";
        if (string.IsNullOrWhiteSpace(reason))
            return false;

        return Regex.IsMatch(reason,
            @"\b(no\s+healthy|not\s+healthy|unhealthy|no\s+same[-\s]?origin|same[-\s]?origin\s+socketjack\s+relay\s+servers|auto_no_eligible_server|auto_parallel_child_failed|server\s+is\s+not\s+responding|not\s+responding\s+through\s+shell|shell\s+proxy|shell\s+route|proxy\s+route|route\s+disabled|offline|disconnected|timed?\s*out|timeout|connection\s+refused|failed\s+to\s+connect|temporarily\s+unavailable)\b",
            RegexOptions.IgnoreCase);
    }

    private static bool AutoBenchmarkRequirementCanRecoverWithFreshHealth(AutoModelBenchmarkRequirement requirement) {
        if (requirement == null)
            return false;

        if (AutoBenchmarkRequirementWasTransientHealthFailure(requirement))
            return true;

        string mode = NormalizeAutoMode(requirement.Mode);
        if (mode is not ("image" or "audio" or "video"))
            return false;

        string reason = requirement.Reason ?? "";
        return Regex.IsMatch(reason,
            @"\b(previewable\s+media|media\s+file|generated\s+media\s+completed|could\s+not\s+find\s+a\s+previewable|completed\s+without\s+returning\s+a\s+previewable)\b",
            RegexOptions.IgnoreCase);
    }

    private static bool AutoModelHasFreshHealthRecoveryEvidence(
        RegisteredServer server,
        RegisteredServerModelInfo item,
        AutoModelBenchmarkRequirement requirement,
        DateTimeOffset evidenceUtc) {
        if (server == null || item == null || requirement == null)
            return false;
        if (evidenceUtc <= requirement.FlaggedUtc)
            return false;
        if (!ServerIsAutoOnline(server, requirement.Mode))
            return false;
        return AutoModelIsSelectableForMode(item, requirement.Mode);
    }

    private void FlagAutoModelForBenchmark(RegisteredServer? server, string model, string mode, string reason, string flaggedBy = "") {
        if (server == null || string.IsNullOrWhiteSpace(model))
            return;

        string key = AutoModelBenchmarkRequirementKey(server, model);
        if (string.IsNullOrWhiteSpace(key))
            return;

        string displayModel = CleanAutoModelDisplayName(model);
        if (string.IsNullOrWhiteSpace(displayModel))
            displayModel = model.Trim();
        DateTimeOffset now = DateTimeOffset.UtcNow;
        lock (_autoModelBenchmarkRequirements) {
            _autoModelBenchmarkRequirements[key] = new AutoModelBenchmarkRequirement {
                ServerId = FirstNonEmpty(server.Id, server.TitleText),
                Model = displayModel,
                Mode = NormalizeAutoMode(mode),
                Reason = string.IsNullOrWhiteSpace(reason) ? "Auto generation failed; benchmark required before reuse." : LimitWebSocketPreview(reason, 500),
                FlaggedBy = flaggedBy,
                FlaggedUtc = now
            };
        }

        bool healthRecoveryCanReenable = AutoBenchmarkRequirementCanRecoverWithFreshHealth(new AutoModelBenchmarkRequirement {
            Reason = reason,
            Mode = NormalizeAutoMode(mode)
        });
        string recoveryText = healthRecoveryCanReenable
            ? " until it publishes fresh healthy status or a fresh benchmark."
            : " until it publishes a fresh benchmark.";

        AppendMasterLog("warn", "auto-model-benchmark-required",
            "Auto disabled model '" + displayModel + "' on " + AutoServerDisplayName(server) + recoveryText,
            reason, "", "", "/Auto");
        NotifyServersChanged();
    }

    private static string AutoModelBenchmarkRequirementKey(RegisteredServer server, string model) {
        string serverKey = FirstNonEmpty(server?.Id ?? "", server?.TitleText ?? "", server?.Endpoint ?? "", server?.LaunchUrl ?? "");
        string modelKey = NormalizeAutoModelId(model);
        return string.IsNullOrWhiteSpace(serverKey) || string.IsNullOrWhiteSpace(modelKey)
            ? ""
            : NormalizeAutoModelId(serverKey) + "|" + modelKey;
    }

    private static DateTimeOffset AutoModelBenchmarkEvidenceUtc(RegisteredServer server, RegisteredServerModelInfo item) {
        DateTimeOffset freshest = DateTimeOffset.MinValue;
        foreach (string value in new[] { item?.BenchmarkedUtc ?? "", server?.UpdatedUtc ?? "", server?.LastSeenUtc ?? "" }) {
            if (DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed)) {
                parsed = parsed.ToUniversalTime();
                if (parsed > freshest)
                    freshest = parsed;
            }
        }

        return freshest;
    }

    private bool TryBuildAutoDirectBaseUri(RegisteredServer server, out Uri? baseUri) {
        baseUri = null;
        string websiteHost = NormalizePublicHost(_options.WebsitePublicUrl);
        string apiHost = NormalizePublicHost(_options.PublicUrl);
        foreach (string value in new[] {
            server.Endpoint,
            server.LaunchUrl,
            RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort)
        }) {
            if (string.IsNullOrWhiteSpace(value))
                continue;
            if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
                continue;
            if (!uri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
                !uri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                continue;
            if (uri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
                continue;
            if (IsLoopbackHost(uri.Host))
                continue;
            if (string.Equals(uri.Host, websiteHost, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(uri.Host, apiHost, StringComparison.OrdinalIgnoreCase))
                continue;

            string text = uri.GetLeftPart(UriPartial.Authority);
            string path = uri.AbsolutePath.TrimEnd('/');
            if (!string.IsNullOrWhiteSpace(path) && path != "/")
                text += path;
            baseUri = new Uri(text.TrimEnd('/') + "/");
            return true;
        }

        return false;
    }

    private object BuildAutoApiServerSummary(RegisteredServer server, MasterShellRelay? relay, string mode = "", double minParameterBillions = 0, double maxParameterBillions = 0, ISet<string>? userDisabledModels = null) {
        return new {
            id = server.Id,
            title = FirstNonEmpty(server.TitleText, server.DisplayName, server.Id),
            owner = server.OwnerUserName,
            runtime = server.ModelRuntimeProvider,
            status = FirstNonEmpty(server.ModelRuntimeStatus, server.StatusText, server.LastStatus),
            models = BuildAutoDisplayModelList(server, mode, minParameterBillions, maxParameterBillions, userDisabledModels),
            relay = relay == null ? "" : relay.RouteName,
            continueUrl = BuildAutoServerContinueUrl(server, relay),
            hardwareSummary = BuildAutoServerHardwareSummary(server),
            premium = ServerRequiresAutoPremium(server),
            requiresPayment = server.RequiresPayment,
            estimatedPromptTokens = EstimateAutoPromptTokenCost(server, "text"),
            costFactor = server.CostFactor > 0 ? server.CostFactor : 1d,
            resourceLoadScore = AutoResourceLoadScore(server),
            hardwareScore = AutoHardwareScore(server)
        };
    }

    private static string BuildAutoServerContinueUrl(RegisteredServer server, MasterShellRelay? relay) {
        if (relay != null) {
            string proxyPath = FirstNonEmpty(
                relay.ProxyPath,
                string.IsNullOrWhiteSpace(relay.RouteName) ? "" : "/proxy/" + Uri.EscapeDataString(relay.RouteName));
            if (!string.IsNullOrWhiteSpace(proxyPath))
                return proxyPath;
        }

        return FirstNonEmpty(server.LaunchUrl, server.Endpoint, RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort));
    }

    private static string BuildAutoServerHardwareSummary(RegisteredServer server) {
        if (server == null)
            return "";

        var parts = new List<string>();
        void AddPart(string label, string value) {
            value = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(value) ||
                value.Equals("unknown", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("n/a", StringComparison.OrdinalIgnoreCase))
                return;
            parts.Add(label + ": " + value);
        }

        AddPart("GPU", FirstNonEmpty(server.GpuModel, server.GpuAvailable, server.AvailableVram));
        AddPart("VRAM", FirstNonEmpty(server.AvailableVram, server.GpuAvailable));
        AddPart("CPU", FirstNonEmpty(server.CpuModel, server.CpuAvailable));
        AddPart("RAM", FirstNonEmpty(server.AvailableRam, server.AvailableResources));
        return string.Join(" | ", parts.Take(4));
    }

    private static bool IsAutoApiStatusRequest(HttpRequest request) {
        if (!request.Method.Equals("GET", StringComparison.OrdinalIgnoreCase))
            return false;
        if (!string.IsNullOrWhiteSpace(GetQuery(request, "path")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "target")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "endpoint")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "prompt")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "message")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "q")) ||
            !string.IsNullOrWhiteSpace(GetQuery(request, "forward")))
            return false;

        string path = (request.Path ?? "").TrimEnd('/');
        return path.Equals("/auto/api", StringComparison.OrdinalIgnoreCase);
    }

    private static string GetAutoApiForwardPath(HttpRequest request, string mode) {
        string explicitPath = FirstNonEmpty(GetQuery(request, "path"), GetQuery(request, "target"), GetQuery(request, "endpoint"));
        if (!string.IsNullOrWhiteSpace(explicitPath))
            return NormalizeAutoApiForwardPath(explicitPath);

        string path = request.Path ?? "";
        foreach (string prefix in new[] { "/auto/api", "/Auto/api" }) {
            if (path.Length > prefix.Length && path.StartsWith(prefix + "/", StringComparison.OrdinalIgnoreCase))
                return NormalizeAutoApiForwardPath(path.Substring(prefix.Length));
        }

        return "/api/chat-stream";
    }

    private static string NormalizeAutoApiForwardPath(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "/api/chat-stream";
        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            value = uri.PathAndQuery;
        if (!value.StartsWith("/", StringComparison.Ordinal))
            value = "/" + value;
        return value;
    }

    private static string BuildAutoApiForwardQuery(HttpRequest request, string forwardedPath) {
        if (request.QueryParameters == null || request.QueryParameters.Count == 0)
            return "";

        bool pathQueryWasControl = AutoApiPathQueryWasControl(request, forwardedPath);
        bool mediaFileForward = IsAutoApiMediaFileForwardPath(forwardedPath);
        var pairs = new List<string>();
        foreach (KeyValuePair<string, string> item in request.QueryParameters) {
            if (IsAutoApiControlQuery(item.Key, pathQueryWasControl))
                continue;
            if (item.Value == null)
                continue;
            if (mediaFileForward && IsAutoApiMediaFilePathQuery(item.Key)) {
                pairs.Add(WebUtility.UrlEncode("path") + "=" + WebUtility.UrlEncode(item.Value));
                continue;
            }
            pairs.Add(WebUtility.UrlEncode(item.Key) + "=" + WebUtility.UrlEncode(item.Value));
        }

        return pairs.Count == 0 ? "" : string.Join("&", pairs);
    }

    private static bool IsAutoApiMediaFileForwardPath(string forwardedPath) {
        string path = NormalizeAutoApiForwardPath(forwardedPath);
        int queryIndex = path.IndexOf('?');
        if (queryIndex >= 0)
            path = path.Substring(0, queryIndex);

        return path.Equals("/api/chat-file-preview", StringComparison.OrdinalIgnoreCase) ||
               path.Equals("/api/chat-file-download", StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsAutoApiMediaFilePathQuery(string name) =>
        name.Equals("filePath", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("artifactPath", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("mediaPath", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("sessionPath", StringComparison.OrdinalIgnoreCase);

    private static bool AutoApiPathQueryWasControl(HttpRequest request, string forwardedPath) {
        string requestPath = (request.Path ?? "").TrimEnd('/');
        bool rootPath = requestPath.Equals("/auto/api", StringComparison.OrdinalIgnoreCase);
        if (!rootPath)
            return false;

        string explicitPath = FirstNonEmpty(GetQuery(request, "path"), GetQuery(request, "target"), GetQuery(request, "endpoint"));
        return !string.IsNullOrWhiteSpace(explicitPath) &&
               NormalizeAutoApiForwardPath(explicitPath).Equals(NormalizeAutoApiForwardPath(forwardedPath), StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsAutoApiControlQuery(string name, bool pathQueryWasControl) =>
        name.Equals("mode", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("type", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("modality", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("model", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("model_id", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("modelId", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("server", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("server_id", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("serverId", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("strictServer", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("strict_server", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("requireServer", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("require_server", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("lockServer", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("lock_server", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("origin", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("origin_mode", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("originMode", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("routing_strategy", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("routingStrategy", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("pool", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("pool_enabled", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("poolEnabled", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("multiGpu", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("multi_gpu", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("multiGpuPool", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("multi_gpu_pool", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parallelPool", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parallel_pool", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("maxParamsB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("paramsB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("max_parameters_b", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("maxParametersB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parameterLimitB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parameter_limit_b", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("minParamsB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("min_parameters_b", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("minParametersB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parameterMinimumB", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parameter_minimum_b", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("disabledModels", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("disabled_models", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("excludedModels", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("excluded_models", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("excludeModels", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("exclude_models", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("render_strategy", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("renderStrategy", StringComparison.OrdinalIgnoreCase) ||
        (pathQueryWasControl && name.Equals("path", StringComparison.OrdinalIgnoreCase)) ||
        (pathQueryWasControl && name.Equals("target", StringComparison.OrdinalIgnoreCase)) ||
        (pathQueryWasControl && name.Equals("endpoint", StringComparison.OrdinalIgnoreCase)) ||
        name.Equals("prompt", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("message", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("q", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("prompts", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parallelPrompts", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("parallel_prompts", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("batchPrompts", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("batch_prompts", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("requests", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("jobs", StringComparison.OrdinalIgnoreCase) ||
        name.Equals("forward", StringComparison.OrdinalIgnoreCase);

    private static bool TryBuildAutoApiTargetUri(Uri baseUri, string forwardedPath, string query, out Uri? targetUri, out string error) {
        targetUri = null;
        error = "";
        forwardedPath = NormalizeAutoApiForwardPath(forwardedPath);
        string path = forwardedPath;
        string embeddedQuery = "";
        int queryIndex = path.IndexOf('?');
        if (queryIndex >= 0) {
            embeddedQuery = path.Substring(queryIndex + 1);
            path = path.Substring(0, queryIndex);
        }

        string combinedQuery = string.Join("&", new[] { embeddedQuery, query }.Where(item => !string.IsNullOrWhiteSpace(item)));
        string relative = path.TrimStart('/');
        if (!string.IsNullOrWhiteSpace(combinedQuery))
            relative += "?" + combinedQuery;

        targetUri = new Uri(baseUri, relative);
        return true;
    }

    private static byte[] BuildAutoApiBodyBytes(HttpRequest request, string mode, string model, bool forceModel = false) {
        string body = request.Body ?? "";
        string prompt = FirstNonEmpty(GetQuery(request, "prompt"), GetQuery(request, "message"), GetQuery(request, "q"));
        if (string.IsNullOrWhiteSpace(body) && !string.IsNullOrWhiteSpace(prompt)) {
            var generated = new JsonObject {
                ["message"] = prompt,
                ["prompt"] = prompt,
                ["sessionId"] = "auto_" + Guid.NewGuid().ToString("N"),
                ["messages"] = new JsonArray(new JsonObject {
                    ["role"] = "user",
                    ["content"] = prompt
                })
            };
            AddAutoApiBodyDefaults(generated, mode, model, forceModel);
            return Encoding.UTF8.GetBytes(generated.ToJsonString(MasterListJson.Options));
        }

        if (string.IsNullOrWhiteSpace(body))
            return Array.Empty<byte>();

        try {
            JsonNode? node = JsonNode.Parse(body);
            if (node is JsonObject obj) {
                AddAutoApiBodyDefaults(obj, mode, model, forceModel);
                return Encoding.UTF8.GetBytes(obj.ToJsonString(MasterListJson.Options));
            }
        } catch {
        }

        return request.BodyBytes != null && request.BodyBytes.Length > 0
            ? request.BodyBytes
            : Encoding.UTF8.GetBytes(body);
    }

    private static bool TryBuildAutoApiParallelRequests(HttpRequest request, string defaultMode, string defaultModel, out List<AutoApiParallelRequest> requests, out string error) {
        requests = new List<AutoApiParallelRequest>();
        error = "";
        if (request == null || string.IsNullOrWhiteSpace(request.Body))
            return false;

        try {
            JsonNode? node = JsonNode.Parse(request.Body);
            if (node is not JsonObject root)
                return false;

            JsonArray? rawItems = FindAutoApiParallelArray(root);
            if (rawItems == null || rawItems.Count <= 1)
                return false;

            string parentSessionId = FirstNonEmpty(JsonNodeText(root["sessionId"]), JsonNodeText(root["autoSession"]), JsonNodeText(root["auto_session"]));
            string parentStreamId = FirstNonEmpty(JsonNodeText(root["streamId"]), JsonNodeText(root["stream_id"]));
            int maxItems = Math.Min(rawItems.Count, 12);
            for (int i = 0; i < maxItems; i++) {
                JsonNode? rawItem = rawItems[i];
                string prompt = "";
                string mode = defaultMode;
                string model = defaultModel;
                JsonObject? itemObject = rawItem as JsonObject;
                if (itemObject != null) {
                    prompt = FirstNonEmpty(
                        JsonNodeText(itemObject["prompt"]),
                        JsonNodeText(itemObject["message"]),
                        JsonNodeText(itemObject["q"]),
                        JsonNodeText(itemObject["content"]),
                        JsonNodeText(itemObject["text"]));
                    mode = NormalizeAutoMode(FirstNonEmpty(JsonNodeText(itemObject["mode"]), JsonNodeText(itemObject["type"]), JsonNodeText(itemObject["modality"]), defaultMode));
                    model = FirstNonEmpty(JsonNodeText(itemObject["model"]), JsonNodeText(itemObject["model_id"]), JsonNodeText(itemObject["modelId"]), defaultModel);
                } else {
                    prompt = JsonNodeText(rawItem);
                }

                prompt = (prompt ?? "").Trim();
                if (string.IsNullOrWhiteSpace(prompt))
                    continue;

                JsonObject child = CloneAutoApiJsonObject(root);
                RemoveAutoApiParallelBodyFields(child);
                if (itemObject != null)
                    ApplyAutoApiParallelItemOverrides(child, itemObject);

                child["prompt"] = prompt;
                child["message"] = prompt;
                child["q"] = prompt;
                child["mode"] = NormalizeAutoMode(mode);
                if (!string.IsNullOrWhiteSpace(model))
                    child["model"] = model;
                if (!string.IsNullOrWhiteSpace(parentSessionId))
                    child["sessionId"] = parentSessionId;
                if (!string.IsNullOrWhiteSpace(parentStreamId))
                    child["streamId"] = parentStreamId + "_p" + (i + 1).ToString(CultureInfo.InvariantCulture);
                RewriteAutoApiParallelMessages(child, prompt);
                child["auto_parallel"] = true;
                child["auto_parallel_index"] = i;
                child["auto_parallel_count"] = maxItems;

                requests.Add(new AutoApiParallelRequest {
                    Index = i,
                    Prompt = prompt,
                    Mode = NormalizeAutoMode(mode),
                    Model = model,
                    Body = child
                });
            }

            if (requests.Count <= 1) {
                requests.Clear();
                return false;
            }

            if (rawItems.Count > maxItems)
                error = "Auto parallel batches are limited to " + maxItems.ToString(CultureInfo.InvariantCulture) + " prompts per request.";
            return true;
        } catch (JsonException) {
            return false;
        }
    }

    private static JsonArray? FindAutoApiParallelArray(JsonObject root) {
        foreach (string name in new[] { "prompts", "parallelPrompts", "parallel_prompts", "batchPrompts", "batch_prompts", "requests", "jobs" }) {
            if (root.TryGetPropertyValue(name, out JsonNode? node) && node is JsonArray array)
                return array;
        }

        return null;
    }

    private static JsonObject CloneAutoApiJsonObject(JsonObject source) {
        try {
            return JsonNode.Parse(source.ToJsonString(MasterListJson.Options)) as JsonObject ?? new JsonObject();
        } catch {
            return new JsonObject();
        }
    }

    private static void RemoveAutoApiParallelBodyFields(JsonObject obj) {
        foreach (string name in new[] { "prompts", "parallelPrompts", "parallel_prompts", "batchPrompts", "batch_prompts", "requests", "jobs", "auto_parallel", "auto_parallel_index", "auto_parallel_count" })
            obj.Remove(name);
    }

    private static void ApplyAutoApiParallelItemOverrides(JsonObject target, JsonObject item) {
        foreach (KeyValuePair<string, JsonNode?> property in item) {
            if (property.Value == null)
                continue;
            if (property.Key.Equals("content", StringComparison.OrdinalIgnoreCase) ||
                property.Key.Equals("text", StringComparison.OrdinalIgnoreCase))
                continue;
            target[property.Key] = JsonNode.Parse(property.Value.ToJsonString(MasterListJson.Options));
        }
    }

    private static void RewriteAutoApiParallelMessages(JsonObject obj, string prompt) {
        if (obj["messages"] is not JsonArray messages) {
            obj["messages"] = new JsonArray(new JsonObject {
                ["role"] = "user",
                ["content"] = prompt
            });
            return;
        }

        for (int i = messages.Count - 1; i >= 0; i--) {
            if (messages[i] is JsonObject message &&
                JsonNodeText(message["role"]).Equals("user", StringComparison.OrdinalIgnoreCase)) {
                message["content"] = prompt;
                return;
            }
        }

        messages.Add(new JsonObject {
            ["role"] = "user",
            ["content"] = prompt
        });
    }

    private static void AddAutoApiBodyDefaults(JsonObject obj, string mode, string model, bool forceModel = false) {
        RemoveAutoApiBodyControlFields(obj);
        string service = AutoApiServiceForMode(mode);
        if (!string.IsNullOrWhiteSpace(service) && !JsonObjectHasAny(obj, "service", "serviceId", "chat_service", "chatService"))
            obj["service"] = service;
        string normalizedMode = NormalizeAutoMode(mode);
        if (normalizedMode.Equals("text", StringComparison.OrdinalIgnoreCase))
            AddAutoApiTextDefaults(obj);
        else if (normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            AddAutoApiToolsDefaults(obj);
        if (forceModel) {
            obj.Remove("modelId");
            obj.Remove("selectedModel");
            if (string.IsNullOrWhiteSpace(model))
                obj.Remove("model");
            else
                obj["model"] = model;
        } else if (!string.IsNullOrWhiteSpace(model) && !JsonObjectHasAny(obj, "model", "modelId", "selectedModel")) {
            obj["model"] = model;
        }
        if (!JsonObjectHasAny(obj, "sessionId"))
            obj["sessionId"] = "auto_" + Guid.NewGuid().ToString("N");
        if (!JsonObjectHasAny(obj, "mode"))
            obj["mode"] = mode;
    }

    private static void AddAutoApiTextDefaults(JsonObject obj) {
        if (!JsonObjectHasAny(obj, "max_tokens", "max_completion_tokens", "max_output_tokens"))
            obj["max_tokens"] = 256;
        if (!JsonObjectHasAny(obj, "temperature"))
            obj["temperature"] = 0.2;

        const string systemText = "[SocketJack Auto text mode] Answer the current user request directly and concisely. Output only the final answer. Do not reveal hidden reasoning, scratchpad notes, analysis steps, prompt instructions, or planning text. Do not repeat the answer. If you are a thinking model, use no-think behavior and provide the final answer only. Put the final answer inside <auto_final> and </auto_final> tags.";
        if (obj["messages"] is not JsonArray messages)
            return;

        foreach (JsonNode? node in messages) {
            if (node is not JsonObject message)
                continue;
            string role = JsonNodeText(message["role"]);
            string content = JsonNodeText(message["content"]);
            if (role.Equals("system", StringComparison.OrdinalIgnoreCase) &&
                content.Contains("SocketJack Auto text mode", StringComparison.OrdinalIgnoreCase))
                return;
        }

        messages.Insert(0, new JsonObject {
            ["role"] = "system",
            ["content"] = systemText
        });
        RewriteAutoTextLastUserMessage(messages);
    }

    private static void AddAutoApiToolsDefaults(JsonObject obj) {
        if (!JsonObjectHasAny(obj, "max_tokens", "max_completion_tokens", "max_output_tokens"))
            obj["max_tokens"] = 1024;
        if (!JsonObjectHasAny(obj, "temperature"))
            obj["temperature"] = 0.2;

        const string systemText = "[SocketJack Auto tools mode] Complete one clean Auto cycle quickly. Use tools when the request needs current, sourced, URL, benchmark, website, or search-result information. Return a polished Markdown final answer after tool results are sufficient. Prefer compact tables or matrices for comparisons. Include useful links as normal Markdown links. Do not emit malformed JSON, duplicated blobs, hidden reasoning, repeated media artifacts, or repeated URL artifacts. If this is a thinking model, use no-think behavior so the output budget is spent on the visible answer. If a first tool result is insufficient, do one focused follow-up instead of ending abruptly. Keep the final answer under about 800 words unless the user explicitly asks for exhaustive detail.";
        if (obj["messages"] is not JsonArray messages)
            return;

        foreach (JsonNode? node in messages) {
            if (node is not JsonObject message)
                continue;
            string role = JsonNodeText(message["role"]);
            string content = JsonNodeText(message["content"]);
            if (role.Equals("system", StringComparison.OrdinalIgnoreCase) &&
                content.Contains("SocketJack Auto tools mode", StringComparison.OrdinalIgnoreCase))
                return;
        }

        messages.Insert(0, new JsonObject {
            ["role"] = "system",
            ["content"] = systemText
        });
        RewriteAutoToolsLastUserMessage(messages);
    }

    private static void RewriteAutoToolsLastUserMessage(JsonArray messages) {
        for (int i = messages.Count - 1; i >= 0; i--) {
            if (messages[i] is not JsonObject message)
                continue;
            string role = JsonNodeText(message["role"]);
            if (!role.Equals("user", StringComparison.OrdinalIgnoreCase))
                continue;
            string content = JsonNodeText(message["content"]).Trim();
            if (string.IsNullOrWhiteSpace(content) ||
                content.Contains("[SocketJack Auto tools request]", StringComparison.OrdinalIgnoreCase))
                return;
            message["content"] = "[SocketJack Auto tools request]\n/no_think\nComplete this as a single clean tools cycle. Search or use tools when current/source/URL/benchmark/site information is needed, then finish with a concise Markdown answer. Use a compact grid/matrix for comparisons when useful. Do not show hidden reasoning or malformed JSON.\n\nUser request:\n" + content;
            return;
        }
    }

    private static void RewriteAutoTextLastUserMessage(JsonArray messages) {
        for (int i = messages.Count - 1; i >= 0; i--) {
            if (messages[i] is not JsonObject message)
                continue;
            string role = JsonNodeText(message["role"]);
            if (!role.Equals("user", StringComparison.OrdinalIgnoreCase))
                continue;
            string content = JsonNodeText(message["content"]).Trim();
            if (string.IsNullOrWhiteSpace(content) ||
                content.Contains("[SocketJack Auto text request]", StringComparison.OrdinalIgnoreCase))
                return;
            message["content"] = "[SocketJack Auto text request]\n/no_think\nRespond with the final answer only. Be concise. Do not show reasoning, analysis, prompt instructions, or repeated text. Put only the final answer inside <auto_final> and </auto_final> tags.\n\nUser request:\n" + content;
            return;
        }
    }

    private static void RemoveAutoApiBodyControlFields(JsonObject obj) {
        foreach (string name in new[] { "server", "serverId", "server_id", "selectedServer", "selectedServerId", "strictServer", "strict_server", "requireServer", "require_server", "lockServer", "lock_server", "origin", "originMode", "origin_mode", "pool", "poolEnabled", "pool_enabled", "multiGpu", "multi_gpu", "multiGpuPool", "multi_gpu_pool", "parallelPool", "parallel_pool", "minParamsB", "min_parameters_b", "minParametersB", "parameterMinimumB", "parameter_minimum_b", "maxParamsB", "paramsB", "max_parameters_b", "maxParametersB", "parameterLimitB", "parameter_limit_b", "disabledModels", "disabled_models", "excludedModels", "excluded_models", "excludeModels", "exclude_models", "premiumModels", "premium_models", "prompts", "parallelPrompts", "parallel_prompts", "batchPrompts", "batch_prompts", "requests", "jobs" })
            obj.Remove(name);
    }

    private static bool JsonObjectHasAny(JsonObject obj, params string[] names) =>
        names.Any(name => obj.ContainsKey(name));

    private static string AutoApiServiceForMode(string mode) {
        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase))
            return "image_generation";
        if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            return "audio_generation";
        if (mode.Equals("video", StringComparison.OrdinalIgnoreCase))
            return "video_generation";
        if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            return "agent";
        return "";
    }

    private static bool AutoModeAllowsModellessFallback(string mode) =>
        mode.Equals("image", StringComparison.OrdinalIgnoreCase) ||
        mode.Equals("audio", StringComparison.OrdinalIgnoreCase) ||
        mode.Equals("video", StringComparison.OrdinalIgnoreCase);

    private string ResolveAutoApiRuntimeModel(RegisteredServer server, string mode, string requestedModel, double minParameterBillions = 0, double maxParameterBillions = 0, ISet<string>? userDisabledModels = null) {
        if (server == null)
            return "";
        if (string.IsNullOrWhiteSpace(requestedModel))
            return ChooseAutoApiModelForMode(server, mode, minParameterBillions: minParameterBillions, maxParameterBillions: maxParameterBillions, userDisabledModels: userDisabledModels);

        List<string> requestedAliases = AutoModelAliases(requestedModel).ToList();
        foreach (RegisteredServerModelInfo item in server.Models.Where(item => AutoModelIsSelectableForMode(item, mode))) {
            if (AutoModelRequiresFreshBenchmark(server, item))
                continue;
            if (AutoModelIsUserDisabled(item.Id, userDisabledModels))
                continue;
            if (!AutoModelMatchesParameterLimit(item.Id, mode, minParameterBillions, maxParameterBillions))
                continue;
            if (AutoModelAliases(item.Id).Any(candidate => AutoModelAliasMatches(candidate, requestedAliases)))
                return item.Id;
        }

        return "";
    }

    private string ChooseAutoApiModelForMode(RegisteredServer server, string mode, ISet<string>? excludedModels = null, double minParameterBillions = 0, double maxParameterBillions = 0, ISet<string>? userDisabledModels = null) {
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        var candidates = new List<(string Raw, string Display, int Score)>();
        void Add(string value, int score) {
            string clean = CleanAutoModelDisplayName(value);
            if (string.IsNullOrWhiteSpace(clean))
                return;
            if (AutoModelIsUserDisabled(value, userDisabledModels) || AutoModelIsUserDisabled(clean, userDisabledModels))
                return;
            if (!AutoModelMatchesParameterLimit(value, mode, minParameterBillions, maxParameterBillions) && !AutoModelMatchesParameterLimit(clean, mode, minParameterBillions, maxParameterBillions))
                return;
            string normalized = NormalizeAutoModelId(clean);
            if (excludedModels != null && excludedModels.Contains(normalized))
                return;
            string rawNormalized = NormalizeAutoModelId(value);
            if (excludedModels != null && excludedModels.Contains(rawNormalized))
                return;
            if (seen.Add(normalized))
                candidates.Add((value, clean, score));
        }

        IEnumerable<RegisteredServerModelInfo> orderedModels = server.Models;
        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase))
            orderedModels = server.Models.OrderByDescending(item => item.SupportsImageGeneration);
        else if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            orderedModels = server.Models.OrderByDescending(item => item.SupportsAudioGeneration);
        else if (mode.Equals("video", StringComparison.OrdinalIgnoreCase))
            orderedModels = server.Models.OrderByDescending(item => item.SupportsVideoGeneration);
        else if (mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase))
            orderedModels = server.Models.OrderByDescending(item => item.SupportsVision);
        else if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase))
            orderedModels = server.Models.OrderByDescending(item => item.SupportsTools);

        foreach (RegisteredServerModelInfo item in orderedModels.Where(item => AutoModelIsSelectableForMode(item, mode) && !AutoModelRequiresFreshBenchmark(server, item)))
            Add(item.Id, AutoModelModeScore(item, mode));

        return candidates
            .OrderByDescending(candidate => candidate.Score)
            .ThenBy(candidate => candidate.Display, StringComparer.OrdinalIgnoreCase)
            .Select(candidate => candidate.Raw)
            .FirstOrDefault() ?? "";
    }

    private static int AutoModelModeScore(RegisteredServerModelInfo item, string mode) {
        int score = AutoModelModeScore(item?.Id ?? "", mode);
        if (item == null)
            return score;

        if (item.Loaded) score += 20;
        if (item.Enabled) score += 8;
        if (item.RuntimeLoadEnabled || item.DynamicLoadEnabled) score += 3;

        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase)) {
            score += item.SupportsImageGeneration ? 100 : 0;
            score -= item.SupportsVideoGeneration || item.SupportsAudioGeneration ? 60 : 0;
        } else if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase)) {
            score += item.SupportsAudioGeneration ? 100 : 0;
            score -= item.SupportsImageGeneration || item.SupportsVideoGeneration ? 60 : 0;
        } else if (mode.Equals("video", StringComparison.OrdinalIgnoreCase)) {
            score += item.SupportsVideoGeneration ? 100 : 0;
            score -= item.SupportsImageGeneration || item.SupportsAudioGeneration ? 60 : 0;
        } else if (mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase)) {
            score += item.SupportsVision ? 100 : 0;
            score += item.SupportsTools ? 20 : 0;
            score -= item.SupportsImageGeneration || item.SupportsAudioGeneration || item.SupportsVideoGeneration ? 30 : 0;
        } else if (mode.Equals("tools", StringComparison.OrdinalIgnoreCase)) {
            score += item.SupportsTools ? 120 : 0;
            score += item.SupportsVision ? 20 : 0;
            score -= item.SupportsImageGeneration || item.SupportsAudioGeneration || item.SupportsVideoGeneration ? 40 : 0;
        } else if (mode.Equals("embedding", StringComparison.OrdinalIgnoreCase)) {
            score += AutoModelLooksEmbedding(item.Id) ? 100 : 0;
        } else {
            score += item.SupportsTools ? 80 : 0;
            score += item.SupportsVision ? 45 : 0;
            score += AutoTextParameterScore(item.Id);
            score -= item.SupportsImageGeneration || item.SupportsAudioGeneration || item.SupportsVideoGeneration ? 90 : 0;
        }

        return score;
    }

    private static int AutoModelModeScore(string model, string mode) {
        string text = (model ?? "").ToLowerInvariant();
        int score = 1;
        if (mode.Equals("image", StringComparison.OrdinalIgnoreCase))
            score += Regex.IsMatch(text, @"stable|diffusion|sdxl|flux|image|vision") ? 10 : 0;
        else if (mode.Equals("video", StringComparison.OrdinalIgnoreCase))
            score += Regex.IsMatch(text, @"video|svd|animated|motion|wan2|ltx|hunyuan") ? 10 : 0;
        else if (mode.Equals("audio", StringComparison.OrdinalIgnoreCase))
            score += Regex.IsMatch(text, @"audio|speech|tts|whisper|music|voice") ? 10 : 0;
        else if (mode.Equals("embedding", StringComparison.OrdinalIgnoreCase))
            score += Regex.IsMatch(text, @"embed|embedding|vector") ? 10 : 0;
        else if (mode.Equals("multimodal", StringComparison.OrdinalIgnoreCase))
            score += Regex.IsMatch(text, @"vision|vl|omni|multi") ? 10 : 0;
        else
            score += Regex.IsMatch(text, @"qwen|llama|mistral|gemma|phi|claude|opus|instruct|chat|llm|gguf|unsloth|gpt") ? 12 : 0;

        if (!mode.Equals("image", StringComparison.OrdinalIgnoreCase) &&
            !mode.Equals("audio", StringComparison.OrdinalIgnoreCase) &&
            !mode.Equals("video", StringComparison.OrdinalIgnoreCase) &&
            AutoModelLooksGenerationOnly(text))
            score -= 40;
        if (Regex.IsMatch(text, @"auth|complete[-_ ]?model|tokenizer|scheduler|config"))
            score -= 50;
        return score;
    }

    private static int AutoTextParameterScore(string model) {
        string text = model ?? "";
        if (!TryExtractAutoModelParameterBillions(text, out double billions))
            return 0;
        return Math.Clamp((int)Math.Round(billions * 12d), 0, 80);
    }

    private static bool AutoParameterFilterApplies(string mode) {
        string normalizedMode = NormalizeAutoMode(mode);
        return normalizedMode.Equals("text", StringComparison.OrdinalIgnoreCase) ||
               normalizedMode.Equals("tools", StringComparison.OrdinalIgnoreCase) ||
               normalizedMode.Equals("multimodal", StringComparison.OrdinalIgnoreCase) ||
               normalizedMode.Equals("embedding", StringComparison.OrdinalIgnoreCase);
    }

    private static bool AutoModelMatchesParameterLimit(string model, string mode, double minParameterBillions, double maxParameterBillions) {
        minParameterBillions = Math.Clamp(minParameterBillions, 0d, 1000d);
        maxParameterBillions = Math.Clamp(maxParameterBillions, 0d, 1000d);
        if (maxParameterBillions > 0 && minParameterBillions > maxParameterBillions)
            (minParameterBillions, maxParameterBillions) = (maxParameterBillions, minParameterBillions);
        if ((minParameterBillions <= 0 && maxParameterBillions <= 0) || !AutoParameterFilterApplies(mode))
            return true;
        return TryExtractAutoModelParameterBillions(model, out double billions) &&
               (minParameterBillions <= 0 || billions + 0.0001d >= minParameterBillions) &&
               (maxParameterBillions <= 0 || billions <= maxParameterBillions + 0.0001d);
    }

    private static bool AutoModelIsUserDisabled(string model, ISet<string>? userDisabledModels) {
        if (userDisabledModels == null || userDisabledModels.Count == 0 || string.IsNullOrWhiteSpace(model))
            return false;
        foreach (string alias in AutoModelAliases(model)) {
            string normalized = NormalizeAutoModelId(alias);
            if (!string.IsNullOrWhiteSpace(normalized) && userDisabledModels.Contains(normalized))
                return true;
        }
        return false;
    }

    private static bool TryExtractAutoModelParameterBillions(string model, out double billions) {
        billions = 0;
        string text = model ?? "";
        foreach (Match match in Regex.Matches(text, @"(^|[^a-z0-9])(\d+(?:\.\d+)?)\s*([bt])(?=$|[^a-z0-9])", RegexOptions.IgnoreCase)) {
            if (!double.TryParse(match.Groups[2].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out double value))
                continue;
            string unit = match.Groups[3].Value.ToLowerInvariant();
            if (unit.Equals("t", StringComparison.Ordinal))
                value *= 1000d;
            billions = Math.Max(billions, value);
        }
        return billions > 0;
    }

    private object ForwardAutoApiTunnelRequest(
        HttpRequest request,
        MasterShellRelay relay,
        string forwardedPath,
        string query,
        byte[] bodyBytes,
        RegisteredServer selectedServer,
        int eligibleCount,
        string mode,
        string model,
        CancellationToken cancellationToken) {
        AutoApiForwardResult result = FetchAutoApiTunnelResult(relay, request, forwardedPath, query, bodyBytes, cancellationToken);
        return WriteAutoApiForwardResult(request, result, selectedServer, relay, eligibleCount, mode, 0);
    }

    private AutoApiForwardResult FetchAutoApiTunnelResult(
        MasterShellRelay relay,
        HttpRequest request,
        string forwardedPath,
        string query,
        byte[] bodyBytes,
        CancellationToken cancellationToken) {
        ShellProxyFetchResult result = _shellProxyWebSocketTunnels.FetchRequest(
            relay,
            request.Method ?? "GET",
            forwardedPath,
            query,
            request.Headers,
            bodyBytes,
            cancellationToken);

        string contentType = string.IsNullOrWhiteSpace(result.ContentType) ? "application/octet-stream" : result.ContentType;
        return new AutoApiForwardResult(result.StatusCode, FirstNonEmpty(result.ReasonPhrase, GetReasonPhrase(result.StatusCode)), contentType, result.BodyBytes, result.Headers, true, result.DurationMs);
    }

    private object ForwardAutoApiRequest(
        NetworkConnection connection,
        HttpRequest request,
        Uri targetUri,
        string forwardedPath,
        byte[] bodyBytes,
        RegisteredServer selectedServer,
        int eligibleCount,
        string mode,
        CancellationToken cancellationToken) {
        AutoApiForwardResult result = FetchAutoApiHttpResult(connection, request, targetUri, bodyBytes, selectedServer, mode, cancellationToken);
        return WriteAutoApiForwardResult(request, result, selectedServer, null, eligibleCount, mode, 0);
    }

    private AutoApiForwardResult FetchAutoApiHttpResult(
        NetworkConnection connection,
        HttpRequest request,
        Uri targetUri,
        byte[] bodyBytes,
        RegisteredServer selectedServer,
        string mode,
        CancellationToken cancellationToken,
        string model = "") {
        HttpContext context = request.Context ?? throw new InvalidOperationException("HTTP context is required.");
        using var upstream = new HttpRequestMessage(new HttpMethod(request.Method), targetUri);
        if (bodyBytes.Length > 0 || RequestMethodAllowsBody(request.Method)) {
            upstream.Content = new ByteArrayContent(bodyBytes);
            string contentType = "application/json";
            if (request.Headers != null &&
                request.Headers.TryGetValue("Content-Type", out string? requestContentType) &&
                !string.IsNullOrWhiteSpace(requestContentType))
                contentType = requestContentType;
            upstream.Content.Headers.TryAddWithoutValidation("Content-Type", contentType);
        }

        if (request.Headers != null) {
            foreach (KeyValuePair<string, string> header in request.Headers) {
                if (ShouldSkipAutoApiRequestHeader(header.Key))
                    continue;
                if (!upstream.Headers.TryAddWithoutValidation(header.Key, header.Value) && upstream.Content != null)
                    upstream.Content.Headers.TryAddWithoutValidation(header.Key, header.Value);
            }
        }

        string originalHost = request.Headers != null && request.Headers.TryGetValue("Host", out string? hostHeader)
            ? hostHeader
            : request.Host;
        if (!string.IsNullOrWhiteSpace(originalHost))
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-Host", SanitizeForwardedHeaderValue(originalHost));
        upstream.Headers.TryAddWithoutValidation("X-Forwarded-Proto", context.Connection?.Parent?.Options?.UseSsl == true ? "https" : "http");
        upstream.Headers.TryAddWithoutValidation("X-Forwarded-Prefix", "/auto/api");
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto", "true");
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Mode", mode);
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Server", FirstNonEmpty(selectedServer.Id, selectedServer.TitleText));
        if (!string.IsNullOrWhiteSpace(model))
            upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Model", CleanAutoModelDisplayName(model));
        try {
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-For", connection?.EndPoint?.Address?.ToString() ?? "");
        } catch {
        }

        using CancellationTokenSource? timeoutCts = CreateShellProxyTimeout(cancellationToken, false);
        CancellationToken effectiveCancellation = timeoutCts?.Token ?? cancellationToken;
        Stopwatch stopwatch = Stopwatch.StartNew();
        using HttpResponseMessage response = ShellProxyHttpClient.Send(upstream, HttpCompletionOption.ResponseContentRead, effectiveCancellation);
        byte[] responseBytes = response.Content!.ReadAsByteArrayAsync(effectiveCancellation).GetAwaiter().GetResult();
        stopwatch.Stop();
        string contentTypeOut = response.Content.Headers.ContentType?.ToString() ?? "application/octet-stream";

        var headers = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        CopyAutoApiResponseHeaders(headers, response.Headers);
        CopyAutoApiResponseHeaders(headers, response.Content!.Headers);
        string reason = string.IsNullOrWhiteSpace(response.ReasonPhrase)
            ? GetReasonPhrase((int)response.StatusCode)
            : response.ReasonPhrase!;
        return new AutoApiForwardResult((int)response.StatusCode, reason, contentTypeOut, responseBytes, headers, false, ClampLatencyMilliseconds(stopwatch.Elapsed));
    }

    private void StreamAutoApiHttpResult(
        NetworkConnection connection,
        HttpRequest request,
        Uri targetUri,
        byte[] bodyBytes,
        RegisteredServer selectedServer,
        MasterShellRelay? relay,
        int eligibleCount,
        string mode,
        string model,
        CancellationToken cancellationToken) {
        HttpContext context = request.Context ?? throw new InvalidOperationException("HTTP context is required.");
        using var upstream = new HttpRequestMessage(new HttpMethod(request.Method), targetUri);
        if (bodyBytes.Length > 0 || RequestMethodAllowsBody(request.Method)) {
            upstream.Content = new ByteArrayContent(bodyBytes);
            string contentType = "application/json";
            if (request.Headers != null &&
                request.Headers.TryGetValue("Content-Type", out string? requestContentType) &&
                !string.IsNullOrWhiteSpace(requestContentType))
                contentType = requestContentType;
            upstream.Content.Headers.TryAddWithoutValidation("Content-Type", contentType);
        }

        if (request.Headers != null) {
            foreach (KeyValuePair<string, string> header in request.Headers) {
                if (ShouldSkipAutoApiRequestHeader(header.Key))
                    continue;
                if (!upstream.Headers.TryAddWithoutValidation(header.Key, header.Value) && upstream.Content != null)
                    upstream.Content.Headers.TryAddWithoutValidation(header.Key, header.Value);
            }
        }

        string originalHost = request.Headers != null && request.Headers.TryGetValue("Host", out string? hostHeader)
            ? hostHeader
            : request.Host;
        if (!string.IsNullOrWhiteSpace(originalHost))
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-Host", SanitizeForwardedHeaderValue(originalHost));
        upstream.Headers.TryAddWithoutValidation("X-Forwarded-Proto", context.Connection?.Parent?.Options?.UseSsl == true ? "https" : "http");
        upstream.Headers.TryAddWithoutValidation("X-Forwarded-Prefix", "/auto/api");
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto", "true");
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Mode", mode);
        upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Server", FirstNonEmpty(selectedServer.Id, selectedServer.TitleText));
        if (!string.IsNullOrWhiteSpace(model))
            upstream.Headers.TryAddWithoutValidation("X-SocketJack-Auto-Model", CleanAutoModelDisplayName(model));
        try {
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-For", connection?.EndPoint?.Address?.ToString() ?? "");
        } catch {
        }

        using HttpResponseMessage response = ShellProxyHttpClient.Send(upstream, HttpCompletionOption.ResponseHeadersRead, cancellationToken);
        string contentTypeOut = response.Content.Headers.ContentType?.ToString() ?? "application/octet-stream";
        StreamShellProxyResponse(request, response, contentTypeOut, cancellationToken, BuildAutoRoutingHeaderMap(selectedServer, relay, eligibleCount, mode, model));
    }

    private object WriteAutoApiForwardResult(
        HttpRequest request,
        AutoApiForwardResult result,
        RegisteredServer selectedServer,
        MasterShellRelay? relay,
        int eligibleCount,
        string mode,
        int retryCount,
        string model = "") {
        HttpContext context = request.Context ?? throw new InvalidOperationException("HTTP context is required.");
        context.StatusCodeNumber = result.StatusCode;
        context.ReasonPhrase = FirstNonEmpty(result.ReasonPhrase, GetReasonPhrase(result.StatusCode));
        context.Response.ContentType = string.IsNullOrWhiteSpace(result.ContentType) ? "application/octet-stream" : result.ContentType;
        CopyAutoApiTunnelHeaders(context.Response.Headers, result.Headers);
        context.Response.Headers["X-SocketJack-Auto-Transport"] = result.FromTunnel ? "socketjack-master-tunnel" : "direct-http";
        if (result.DurationMs > 0)
            context.Response.Headers["X-SocketJack-Auto-Duration-Ms"] = result.DurationMs.ToString(CultureInfo.InvariantCulture);
        if (retryCount > 0)
            context.Response.Headers["X-SocketJack-Auto-Retry-Count"] = retryCount.ToString(CultureInfo.InvariantCulture);
        AddAutoRoutingHeaders(request, selectedServer, eligibleCount, mode, model, relay);
        AddCors(request);
        return new FileResponse(
            request.Method.Equals("HEAD", StringComparison.OrdinalIgnoreCase) ? Array.Empty<byte>() : result.BodyBytes,
            context.Response.ContentType);
    }

    private static bool IsAutoApiRetryableModelLoadFailure(AutoApiForwardResult result, string model) {
        string body = DecodeAutoApiResponseText(result.BodyBytes);
        if (string.IsNullOrWhiteSpace(body))
            return false;

        bool modelMentioned = string.IsNullOrWhiteSpace(model) || body.Contains(model, StringComparison.OrdinalIgnoreCase);
        bool loadFailure =
            body.Contains("model_load_error", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("\"code\":\"load_failed\"", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Model not found", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("LlmRuntime could not load", StringComparison.OrdinalIgnoreCase);
        return modelMentioned && loadFailure;
    }

    private static bool TryGetAutoApiModelFailureRequiringBenchmark(AutoApiForwardResult result, string model, string mode, out string reason) {
        reason = "";
        string body = DecodeAutoApiResponseText(result.BodyBytes);
        if (string.IsNullOrWhiteSpace(body))
            return false;

        string displayModel = CleanAutoModelDisplayName(model);
        bool modelMentioned = string.IsNullOrWhiteSpace(model) ||
            body.Contains(model, StringComparison.OrdinalIgnoreCase) ||
            (!string.IsNullOrWhiteSpace(displayModel) && body.Contains(displayModel, StringComparison.OrdinalIgnoreCase));
        string normalizedMode = NormalizeAutoMode(mode);
        bool mediaMode = normalizedMode.Equals("image", StringComparison.OrdinalIgnoreCase) ||
            normalizedMode.Equals("audio", StringComparison.OrdinalIgnoreCase) ||
            normalizedMode.Equals("video", StringComparison.OrdinalIgnoreCase);
        bool runtimeFailure =
            body.Contains("model_load_error", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("\"code\":\"load_failed\"", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("load_failed", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Model not found", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("LlmRuntime could not load", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("generation failed for model", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Image Generation did not complete", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Video Generation did not complete", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Audio Generation did not complete", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("No compatible Python image generation runtime completed", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Diffusers/Torch pipeline is unavailable", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Could not prepare image generation runtime", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("No module named", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("Failed to import", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("exited with code", StringComparison.OrdinalIgnoreCase);
        bool failedMediaResponse = mediaMode && (
            body.Contains("\"success\":false", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("\"status\":\"failed\"", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("failed", StringComparison.OrdinalIgnoreCase) && body.Contains("traceback", StringComparison.OrdinalIgnoreCase));

        if (!modelMentioned || (!runtimeFailure && !failedMediaResponse))
            return false;

        reason = LimitWebSocketPreview(body, 900);
        return true;
    }

    private static bool AutoApiMediaResponseMissingArtifact(AutoApiForwardResult result, string mode, out string reason) {
        reason = "";
        string normalizedMode = NormalizeAutoMode(mode);
        bool mediaMode = normalizedMode.Equals("image", StringComparison.OrdinalIgnoreCase) ||
            normalizedMode.Equals("audio", StringComparison.OrdinalIgnoreCase) ||
            normalizedMode.Equals("video", StringComparison.OrdinalIgnoreCase);
        if (!mediaMode || result.StatusCode < 200 || result.StatusCode >= 300)
            return false;

        string body = DecodeAutoApiResponseText(result.BodyBytes);
        if (string.IsNullOrWhiteSpace(body))
            return false;
        if (AutoApiResponseContainsPreviewableMedia(body, normalizedMode))
            return false;

        bool lookedComplete =
            body.Contains("completed", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("\"ok\":true", StringComparison.OrdinalIgnoreCase) ||
            body.Contains("\"success\":true", StringComparison.OrdinalIgnoreCase);
        if (!lookedComplete)
            return false;

        reason = NormalizeAutoMode(normalizedMode) + " generation completed without returning a previewable media artifact.";
        return true;
    }

    private static bool AutoApiResponseContainsPreviewableMedia(string body, string mode) {
        if (string.IsNullOrWhiteSpace(body))
            return false;

        string mediaPrefix = NormalizeAutoMode(mode) switch {
            "audio" => "audio/",
            "video" => "video/",
            _ => "image/"
        };
        if (body.Contains(mediaPrefix, StringComparison.OrdinalIgnoreCase) ||
            Regex.IsMatch(body, @"GeneratedMedia[\\/][^""'\r\n<>]*?\.(?:png|jpe?g|webp|gif|bmp|svg|mp4|webm|mov|m4v|mp3|wav|ogg|flac|m4a)", RegexOptions.IgnoreCase))
            return true;

        return Regex.IsMatch(body, @"\.(?:png|jpe?g|webp|gif|bmp|mp4|webm|mov|m4v|mp3|wav|ogg|flac|m4a)(?:[""'\s,}\]]|$)", RegexOptions.IgnoreCase);
    }

    private static string DecodeAutoApiResponseText(byte[] bytes) {
        if (bytes == null || bytes.Length == 0)
            return "";
        try {
            int length = Math.Min(bytes.Length, 32_000);
            return Encoding.UTF8.GetString(bytes, 0, length);
        } catch {
            return "";
        }
    }

    private static bool ShouldSkipAutoApiRequestHeader(string headerName) =>
        ShouldSkipSecureAuthorityProxyHeader(headerName) ||
        headerName.Equals("Accept-Encoding", StringComparison.OrdinalIgnoreCase);

    private static void CopyAutoApiResponseHeaders(Dictionary<string, string> target, System.Net.Http.Headers.HttpHeaders headers) {
        foreach (KeyValuePair<string, IEnumerable<string>> header in headers) {
            if (ShouldSkipSecureAuthorityProxyResponseHeader(header.Key))
                continue;
            target[header.Key] = string.Join(", ", header.Value);
        }
    }

    private static void CopyAutoApiTunnelHeaders(Dictionary<string, string> target, Dictionary<string, string> headers) {
        foreach (KeyValuePair<string, string> header in headers) {
            if (ShouldSkipSecureAuthorityProxyResponseHeader(header.Key))
                continue;
            target[header.Key] = header.Value;
        }
    }

    private static string BuildAutoHtml() {
        return """
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
