<style>
:root{color-scheme:dark;--bg:#070a12;--panel:#0d1522;--panel2:#111d2d;--line:rgba(155,176,211,.24);--text:#f4f8ff;--muted:#9fb0c8;--accent:#2ee6aa;--blue:#60c9ff;--rose:#fb7185;--amber:#fbbf24}*{box-sizing:border-box}[hidden]{display:none!important}html,body{height:100%;margin:0;overflow:hidden}body{background:radial-gradient(circle at 14% 12%,rgba(46,230,170,.16),transparent 26rem),radial-gradient(circle at 86% 8%,rgba(96,201,255,.15),transparent 28rem),linear-gradient(180deg,#070a12 0%,#0b1320 55%,#070a12 100%);color:var(--text);font:15px/1.5 "Segoe UI",system-ui,sans-serif}.app{height:100%;min-height:0;display:grid;grid-template-rows:auto minmax(0,1fr);gap:12px;width:min(1180px,calc(100% - 22px));margin:0 auto;padding:16px 0}.top{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:14px;align-items:center;border:1px solid var(--line);border-radius:8px;background:rgba(9,17,30,.78);box-shadow:0 24px 80px rgba(0,0,0,.28),inset 0 1px 0 rgba(255,255,255,.07);backdrop-filter:blur(22px);padding:12px 14px}.brand h1{font-size:1.08rem;margin:0}.brand .sub{color:var(--muted);font-size:.8rem}.server-capsule{display:grid;gap:4px;text-align:right}.server-label{color:var(--muted);font:800 .62rem "Cascadia Code",monospace;text-transform:uppercase}.server-name{max-width:360px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;border:1px solid rgba(46,230,170,.34);border-radius:8px;padding:7px 10px;background:rgba(11,28,35,.72);font:800 .76rem "Cascadia Code",monospace}.continue-server{justify-self:end;display:inline-flex;align-items:center;gap:6px;max-width:360px;min-height:30px;border:1px solid rgba(96,201,255,.30);border-radius:8px;padding:6px 10px;background:rgba(4,10,20,.64);color:#e5f6ff;text-decoration:none;font:900 .68rem "Cascadia Code",monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.continue-server:hover,.continue-server:focus-visible{border-color:rgba(46,230,170,.58);background:linear-gradient(135deg,rgba(46,230,170,.20),rgba(96,201,255,.12));outline:none}.chat-shell{min-height:0;display:grid;grid-template-rows:auto minmax(0,1fr) auto;border:1px solid var(--line);border-radius:8px;overflow:hidden;background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(10,18,31,.64));box-shadow:0 28px 90px rgba(0,0,0,.30),inset 0 1px 0 rgba(255,255,255,.08)}.chat-head{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:12px;align-items:center;padding:12px;border-bottom:1px solid rgba(155,176,211,.18);background:rgba(10,18,31,.70)}.switchbar{display:grid;gap:8px}.mode-toggle,.origin-toggle{display:flex;flex-wrap:wrap;gap:6px}.mode-toggle button,.origin-toggle button{min-height:34px;border:1px solid rgba(155,176,211,.22);border-radius:8px;background:rgba(4,10,20,.64);color:#dbeafe;padding:6px 10px;font:800 .72rem "Cascadia Code",monospace;cursor:pointer}.mode-toggle button.active,.origin-toggle button.active{border-color:rgba(46,230,170,.58);background:linear-gradient(135deg,rgba(46,230,170,.24),rgba(96,201,255,.13));color:#f1fff9}.origin-toggle button{min-height:30px;font-size:.66rem}.chat-actions{display:flex;gap:8px;align-items:center}.pill{display:inline-flex;align-items:center;gap:6px;min-height:30px;border:1px solid rgba(155,176,211,.22);border-radius:8px;padding:5px 9px;background:rgba(4,10,20,.62);color:#dbeafe;font:800 .68rem "Cascadia Code",monospace}.pill.good{border-color:rgba(46,230,170,.4);color:#c8ffe8}.pill.warn{border-color:rgba(251,191,36,.38);color:#fde68a}.pill.auth-link{text-decoration:none;cursor:pointer}.button{border:1px solid rgba(96,201,255,.28);border-radius:8px;background:rgba(4,10,20,.64);color:#e5f6ff;text-decoration:none;padding:7px 10px;font:800 .72rem "Cascadia Code",monospace}.messages{min-height:0;overflow:auto;padding:18px;display:grid;gap:14px;align-content:start}.bubble{max-width:min(860px,92%);display:grid;gap:8px}.bubble.user{justify-self:end}.bubble.assistant{justify-self:start}.bubble-card{border:1px solid rgba(155,176,211,.18);border-radius:8px;padding:12px 13px;background:rgba(5,12,22,.72);box-shadow:inset 0 1px 0 rgba(255,255,255,.06)}.bubble.user .bubble-card{border-color:rgba(96,201,255,.28);background:linear-gradient(135deg,rgba(96,201,255,.18),rgba(11,24,40,.72))}.bubble.assistant .bubble-card{border-color:rgba(46,230,170,.24);background:linear-gradient(135deg,rgba(46,230,170,.11),rgba(11,24,40,.72))}.bubble-role{color:var(--muted);font:900 .62rem "Cascadia Code",monospace;text-transform:uppercase}.bubble-text{white-space:pre-wrap;overflow-wrap:anywhere}.bubble-progress{color:#b7c7db;font:.78rem "Cascadia Code",monospace}.composer{display:grid;grid-template-columns:minmax(180px,280px) minmax(0,1fr) auto;gap:10px;padding:12px;border-top:1px solid rgba(155,176,211,.18);background:rgba(10,18,31,.74)}input,textarea{width:100%;border:1px solid rgba(226,244,255,.16);border-radius:8px;background:rgba(3,9,18,.78);color:var(--text);padding:10px;outline:none;font:inherit}input:focus,textarea:focus{border-color:rgba(46,230,170,.52);box-shadow:0 0 0 3px rgba(46,230,170,.12)}textarea{height:48px;max-height:160px;resize:vertical}.send{min-width:104px;border:1px solid rgba(46,230,170,.40);border-radius:8px;background:linear-gradient(135deg,rgba(46,230,170,.26),rgba(96,201,255,.14));color:#effffb;font:900 .8rem "Cascadia Code",monospace;cursor:pointer}.send:disabled{opacity:.58;cursor:wait}.media-grid{display:grid;gap:10px}.media-card{overflow:hidden;border:1px solid rgba(155,176,211,.20);border-radius:8px;background:rgba(2,8,16,.74)}.media-card img,.media-card video{display:block;width:100%;max-height:72vh;object-fit:contain;background:#020816}.media-card audio{display:block;width:100%;padding:12px}.media-caption{display:flex;justify-content:space-between;gap:8px;align-items:center;padding:8px 10px;color:var(--muted);font:.72rem "Cascadia Code",monospace}.media-caption a{color:#bdf7ff}.error{color:#fecaca}.login-note{display:grid;gap:8px}.login-note a{width:max-content}.model-combo{position:relative;min-width:0}.model-suggestions{position:absolute;left:0;right:0;bottom:calc(100% + 8px);z-index:8;max-height:min(340px,46vh);overflow:auto;border:1px solid rgba(96,201,255,.30);border-radius:8px;background:rgba(3,9,18,.96);box-shadow:0 22px 70px rgba(0,0,0,.38),inset 0 1px 0 rgba(255,255,255,.08);padding:6px}.model-suggestion{width:100%;display:grid;grid-template-columns:minmax(0,1fr) auto;gap:8px;align-items:center;border:0;border-radius:7px;background:transparent;color:var(--text);padding:8px 9px;text-align:left;cursor:pointer}.model-suggestion:hover,.model-suggestion.active{background:rgba(46,230,170,.14)}.model-suggestion strong{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font:800 .76rem "Cascadia Code",monospace}.model-suggestion span{color:var(--muted);font:800 .62rem "Cascadia Code",monospace;text-transform:uppercase}@media(max-width:780px){.top,.chat-head,.composer{grid-template-columns:1fr}.server-capsule{text-align:left}.server-name,.continue-server{max-width:100%;justify-self:start}.messages{padding:12px}.bubble{max-width:100%}.model-suggestions{bottom:auto;top:calc(100% + 8px)}}
</style>
<style>
:root{--auto-star-x:0px;--auto-star-y:0px;--auto-bg-x:0px;--auto-bg-y:0px;--auto-glass-x:0px;--auto-glass-y:0px;--auto-glass-point-x:50%;--auto-glass-point-y:34%}
.messages{overflow-x:hidden}.bubble,.bubble-card{min-width:0}.bubble-card{max-width:100%;overflow:hidden}.markdown-body{white-space:normal;overflow-wrap:anywhere;line-height:1.55}.markdown-body>:first-child{margin-top:0}.markdown-body>:last-child{margin-bottom:0}.markdown-body h2,.markdown-body h3{margin:.15rem 0 .45rem;color:#f8fbff;line-height:1.2}.markdown-body h2{font-size:1.02rem}.markdown-body h3{font-size:.9rem;color:#bdf7ff}.markdown-body p{margin:.45rem 0}.markdown-body ul,.markdown-body ol{margin:.42rem 0 .42rem 1.1rem;padding:0}.markdown-body li{margin:.22rem 0}.markdown-body code:not(pre code){border:1px solid rgba(125,211,252,.18);border-radius:6px;background:rgba(2,8,16,.74);padding:.08rem .32rem;color:#d9fbff;font:800 .82em "Cascadia Code",monospace}.markdown-body a{color:#9eeeff;text-decoration:none}.markdown-body a:hover{text-decoration:underline}.markdown-body blockquote{margin:.5rem 0;padding:.35rem .7rem;border-left:3px solid rgba(46,230,170,.58);background:rgba(46,230,170,.07);color:#c8d8eb}.code-block{margin:.62rem 0;border:1px solid rgba(96,201,255,.22);border-radius:8px;background:#020816;overflow:hidden}.code-title{display:flex;justify-content:space-between;gap:10px;padding:6px 9px;border-bottom:1px solid rgba(155,176,211,.16);color:#9eeeff;background:rgba(96,201,255,.075);font:900 .62rem "Cascadia Code",monospace;text-transform:uppercase}.code-block pre{margin:0;max-width:100%;overflow:auto;padding:10px 12px;white-space:pre;tab-size:2}.code-block code{font:800 .76rem/1.5 "Cascadia Code","Consolas",monospace;color:#dbeafe}.tok-comment{color:#7a8da8;font-style:italic}.tok-string{color:#a7f3d0}.tok-keyword{color:#93c5fd}.tok-number{color:#fcd34d}.tok-type{color:#f0abfc}.tok-fn{color:#67e8f9}.tok-var{color:#f9a8d4}.tok-tag{color:#7dd3fc}.tok-attr{color:#fbbf24}.welcome-readme .bubble-card{border-color:rgba(96,201,255,.30);background:linear-gradient(135deg,rgba(46,230,170,.13),rgba(96,201,255,.08),rgba(11,24,40,.72))}.bubble-progress,.bubble-insights{max-width:100%;min-width:0;margin-top:8px;border:1px solid rgba(155,176,211,.16);border-radius:8px;background:rgba(2,8,16,.58);color:#b7c7db;font:.72rem "Cascadia Code",monospace;overflow:hidden}
.prompt-progress-track{height:2px;background:rgba(148,163,184,.16);overflow:hidden}
.prompt-progress-fill{height:100%;width:4%;background:linear-gradient(90deg,#ff3df2,#8b5cf6,#38bdf8,#2ee6aa,#facc15,#ff3df2);background-size:360% 100%;animation:autoTokenRgb 1.8s linear infinite;box-shadow:0 0 12px rgba(46,230,170,.7);transition:width .28s ease}
.bubble-progress.complete .prompt-progress-fill{width:100%!important}
.bubble-progress-row{display:grid;grid-template-columns:auto minmax(0,1fr) auto;grid-template-areas:"meter status elapsed" "toggle status .";align-items:flex-start;gap:5px 9px;min-height:42px;padding:7px 8px;cursor:pointer}
.prompt-progress-meter{grid-area:meter;display:inline-flex;align-items:center;gap:7px;min-height:20px}
.prompt-progress-spinner{width:13px;height:13px;border:2px solid rgba(125,211,252,.24);border-top-color:#2ee6aa;border-right-color:#ff3df2;border-radius:999px;animation:autoSpin .9s linear infinite;box-shadow:0 0 12px rgba(46,230,170,.34)}
.bubble-progress.complete .prompt-progress-spinner{animation:none;border-color:rgba(46,230,170,.62)}
.prompt-progress-percent{flex:0 0 auto;color:#fde68a;font:1000 .62rem "Cascadia Code",monospace}
.prompt-progress-elapsed{grid-area:elapsed;justify-self:end;min-width:4.2em;text-align:right;color:#9eeeff;font:1000 .62rem "Cascadia Code",monospace;white-space:nowrap}.prompt-progress-elapsed:empty{display:none}
.bubble-progress-toggle{grid-area:toggle;justify-self:start;width:22px;height:20px;display:grid;place-items:center;border:1px solid rgba(96,201,255,.24);border-radius:6px;background:rgba(2,8,16,.82);color:#dbeafe;font:1000 .7rem "Cascadia Code",monospace;cursor:pointer}
.bubble-progress-status,.bubble-insights-status{min-width:0;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:normal;overflow-wrap:anywhere;word-break:break-word;line-height:1.35;display:-webkit-box;-webkit-box-orient:vertical;-webkit-line-clamp:3;max-height:4.05em}
.bubble-progress-status{grid-area:status;color:#c9d8ef;font:900 .68rem "Cascadia Code",monospace}.bubble-progress.complete .bubble-progress-status{color:#baf7e6}
.bubble-insights-status{display:block;max-height:5.4em;overflow:auto;text-overflow:clip;-webkit-line-clamp:unset;scrollbar-width:thin}
.bubble-progress.expanded .bubble-progress-status,.bubble-insights.expanded .bubble-insights-status{-webkit-line-clamp:unset;max-height:none}
.bubble-progress-result{display:none;margin:0 8px 8px 39px;border:1px solid rgba(46,230,170,.18);border-radius:7px;background:rgba(46,230,170,.055);padding:7px 8px;color:#d8f3ff;line-height:1.35;overflow-wrap:anywhere}.bubble-progress.complete .bubble-progress-result:not(:empty){display:block}.prompt-progress-result-label{display:block;margin-bottom:3px;color:#9eeeff;font:1000 .56rem "Cascadia Code",monospace;text-transform:uppercase;letter-spacing:.04em}
.bubble-progress-lines,.bubble-insights-lines{display:none;margin:0;padding:8px;border-top:1px solid rgba(155,176,211,.14);max-height:180px;overflow:auto;white-space:pre-wrap;overflow-wrap:anywhere;word-break:break-word;background:rgba(2,8,16,.76)}
.bubble-progress.expanded .bubble-progress-lines{display:block}
.bubble-insights{border-color:rgba(251,191,36,.18);background:linear-gradient(135deg,rgba(251,191,36,.055),rgba(2,8,16,.68))}
.bubble-insights-row{display:flex;align-items:flex-start;gap:8px;min-height:30px;padding:6px 8px;cursor:pointer}.bubble-insights-toggle{width:22px;height:20px;display:grid;place-items:center;flex:0 0 auto;border:1px solid rgba(251,191,36,.24);border-radius:6px;background:rgba(2,8,16,.82);color:#fde68a;font:1000 .7rem "Cascadia Code",monospace;cursor:pointer}.bubble-insights.expanded .bubble-insights-lines{display:block}
.insight-stack{display:grid;gap:8px}.insight-thought{border:1px solid rgba(96,201,255,.16);border-left:3px solid rgba(96,201,255,.52);border-radius:7px;background:rgba(96,201,255,.06);padding:7px 8px;color:#ccecff}.insight-thought strong,.tool-card-label{display:block;margin-bottom:4px;color:#9eeeff;font:1000 .58rem "Cascadia Code",monospace;text-transform:uppercase;letter-spacing:.03em}.tool-call-card{display:grid;gap:7px;border:1px solid rgba(251,191,36,.22);border-radius:8px;background:linear-gradient(135deg,rgba(251,191,36,.08),rgba(5,12,22,.80));padding:8px}.tool-call-card.running{border-color:rgba(96,201,255,.34)}.tool-call-card.done{border-color:rgba(46,230,170,.30)}.tool-call-card.failed{border-color:rgba(251,113,133,.42)}.tool-call-head{display:flex;align-items:center;gap:7px;min-width:0}.tool-call-name{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#fff7d1;font-weight:1000}.tool-call-status{flex:0 0 auto;border:1px solid rgba(155,176,211,.22);border-radius:999px;padding:2px 6px;background:rgba(2,8,16,.72);color:#cbd5e1;font-size:.56rem;text-transform:uppercase}.tool-call-card.done .tool-call-status{color:#baf7e6;border-color:rgba(46,230,170,.34)}.tool-call-card.failed .tool-call-status{color:#fecaca;border-color:rgba(251,113,133,.44)}.tool-call-summary,.tool-call-result,.insight-line{color:#cbd5e1;line-height:1.42}.tool-call-thought{border-left:3px solid rgba(96,201,255,.42);padding:5px 7px;background:rgba(96,201,255,.055);color:#d8f3ff}.tool-call-fields{display:grid;gap:5px}.tool-call-field{display:grid;grid-template-columns:minmax(72px,120px) minmax(0,1fr);gap:8px;align-items:start}.tool-call-key{color:#f8d889;text-transform:uppercase;font-size:.56rem}.tool-call-value{min-width:0;overflow-wrap:anywhere;color:#f3f7ff}.tool-call-links{display:flex;flex-wrap:wrap;gap:5px}.tool-call-links a{max-width:100%;border:1px solid rgba(96,201,255,.24);border-radius:999px;padding:3px 7px;background:rgba(96,201,255,.08);color:#bdf7ff;text-decoration:none;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.tool-call-links a:hover{text-decoration:underline}.tool-call-read{border:1px solid rgba(155,176,211,.14);border-radius:7px;background:rgba(2,8,16,.54);padding:7px;color:#dbeafe;white-space:pre-wrap}.tool-call-raw{margin:0;max-height:96px;overflow:auto;border:1px solid rgba(155,176,211,.12);border-radius:7px;background:rgba(2,8,16,.64);padding:7px;color:#aab9d0;white-space:pre-wrap}.bubble-insights-lines a{color:#9eeeff;text-decoration:none}.bubble-insights-lines a:hover{text-decoration:underline}
.bubble{max-width:min(1040px,96%)}.bubble.user{max-width:min(860px,92%)}.bubble.assistant{width:min(1040px,96%)}.bubble.assistant .bubble-card{width:100%}.bubble.user.steer-prompt .bubble-card{position:relative;padding-top:34px}.steer-prompt-toolbar{position:absolute;right:10px;top:7px;z-index:2;display:flex;align-items:center;gap:6px}.steer-prompt-status{color:#94a3b8;font:1000 .58rem "Cascadia Code",monospace;text-transform:uppercase;letter-spacing:.04em}.steer-prompt-status.processing{color:#fbbf24;text-shadow:0 0 12px rgba(251,191,36,.28)}.steer-prompt-edit{min-height:22px;border:1px solid rgba(148,163,184,.30);border-radius:7px;background:rgba(2,8,16,.72);color:#dbeafe;padding:3px 7px;font:900 .58rem "Cascadia Code",monospace;cursor:pointer}.steer-prompt-edit:hover,.steer-prompt-edit:focus-visible{border-color:rgba(46,230,170,.56);color:#eafff7;outline:none}.bubble-insights-status{max-height:none!important;overflow:visible!important;scrollbar-width:auto}.bubble-insights-lines{max-height:none!important;overflow:visible!important}.tool-call-card,.tool-call-read,.tool-call-raw{max-height:none!important;overflow:visible!important}.tool-call-card{background:rgba(4,10,15,.88);border-color:rgba(96,201,255,.26)}.tool-call-head{padding-bottom:5px;border-bottom:1px solid rgba(155,176,211,.10)}.tool-call-thought{border-left-color:rgba(96,201,255,.58);background:rgba(96,201,255,.075)}.auto-link-chip,.markdown-body a,.bubble-insights-lines a,.tool-call-links a{display:inline-flex!important;align-items:center;gap:5px;max-width:100%;border:1px solid rgba(125,211,252,.28)!important;border-radius:999px!important;background:rgba(0,0,0,.50)!important;color:#bdf7ff!important;text-decoration:none!important;padding:2px 7px!important;vertical-align:baseline;box-shadow:inset 0 1px 0 rgba(255,255,255,.08)}.auto-link-chip::before,.markdown-body a::before,.bubble-insights-lines a::before,.tool-call-links a::before{content:"";width:.78em;height:.78em;flex:0 0 auto;border:1.7px solid currentColor;border-radius:50%;box-shadow:inset 0 0 0 2px rgba(0,0,0,.30)}.auto-link-chip:hover,.auto-link-chip:focus-visible,.markdown-body a:hover,.markdown-body a:focus-visible,.bubble-insights-lines a:hover,.bubble-insights-lines a:focus-visible,.tool-call-links a:hover,.tool-call-links a:focus-visible{border-color:rgba(46,230,170,.66)!important;background:rgba(0,0,0,.62)!important;outline:none}.markdown-body table{width:100%;border-collapse:collapse;margin:10px 0;display:block;overflow-x:auto}.markdown-body th,.markdown-body td{border:1px solid rgba(155,176,211,.20);padding:6px 8px;text-align:left;vertical-align:top}.markdown-body th{background:rgba(96,201,255,.10);color:#e8faff}.markdown-body hr{border:0;border-top:1px solid rgba(155,176,211,.22);margin:12px 0}@media(max-width:780px){.bubble,.bubble.assistant,.bubble.user{width:auto;max-width:100%}}
.mode-toggle,.origin-toggle{display:inline-flex;flex-wrap:wrap;gap:0;width:max-content;max-width:100%;border:1px solid rgba(155,176,211,.24);border-radius:8px;overflow:hidden;background:rgba(4,10,20,.62)}
.mode-toggle button,.origin-toggle button{border:0;border-right:1px solid rgba(155,176,211,.18);border-radius:0;background:rgba(4,10,20,.46);margin:0}
.mode-toggle button:last-child,.origin-toggle button:last-child{border-right:0}
.mode-toggle button:hover,.origin-toggle button:hover,.mode-toggle button:focus-visible,.origin-toggle button:focus-visible{background:rgba(96,201,255,.12);outline:none}
.mode-toggle button.active,.origin-toggle button.active{box-shadow:inset 0 0 0 1px rgba(46,230,170,.52);background:linear-gradient(135deg,rgba(46,230,170,.28),rgba(96,201,255,.14))}
.origin-toggle{font-size:.66rem}
.session-backdrop{position:fixed;inset:0;z-index:11;background:rgba(2,8,16,.54);backdrop-filter:blur(3px);opacity:0;transition:opacity .18s ease}
.session-drawer{position:fixed;z-index:12;inset:0 auto 0 0;width:min(420px,calc(100vw - 18px));display:grid;grid-template-rows:auto auto minmax(0,1fr);gap:10px;padding:14px;border-right:1px solid rgba(96,201,255,.30);background:linear-gradient(180deg,rgba(7,13,24,.98),rgba(9,18,30,.96));box-shadow:28px 0 90px rgba(0,0,0,.46),inset -1px 0 0 rgba(255,255,255,.06);transform:translateX(-104%);transition:transform .2s ease}
.session-drawer[aria-hidden="false"]{transform:translateX(0)}
body.sessions-open .session-backdrop{opacity:1}
.session-drawer-head{display:flex;align-items:flex-start;justify-content:space-between;gap:12px}.session-drawer-head strong{display:block;font:900 .98rem "Cascadia Code",monospace}.session-drawer-head span{display:block;color:var(--muted);font:800 .64rem "Cascadia Code",monospace}
.session-search-wrap{display:grid;gap:6px}.session-search-wrap input{font:800 .76rem "Cascadia Code",monospace}.session-list{min-height:0;overflow:auto;display:grid;align-content:start;gap:10px;padding-right:4px}
.session-card{display:grid;gap:8px;border:1px solid rgba(155,176,211,.18);border-radius:8px;background:rgba(5,12,22,.78);padding:10px;box-shadow:inset 0 1px 0 rgba(255,255,255,.06)}
.session-card.active{border-color:rgba(46,230,170,.54);background:linear-gradient(135deg,rgba(46,230,170,.14),rgba(5,12,22,.82))}
.session-title{width:100%;border:0;background:transparent;color:#f4f8ff;padding:0;text-align:left;font:900 .82rem "Cascadia Code",monospace;cursor:pointer;overflow-wrap:anywhere}.session-title:hover{text-decoration:underline}
.session-preview{color:#c7d6ea;font-size:.78rem;line-height:1.35;overflow-wrap:anywhere}.session-meta,.session-actions{display:flex;flex-wrap:wrap;gap:6px}.session-chip{border:1px solid rgba(155,176,211,.20);border-radius:999px;padding:3px 7px;background:rgba(3,9,18,.70);color:#dbeafe;font:800 .58rem "Cascadia Code",monospace}.session-chip.warn{border-color:rgba(251,191,36,.36);color:#fde68a}.session-chip.good{border-color:rgba(46,230,170,.34);color:#c8ffe8}
.session-detail{display:grid;gap:3px;color:#94a8c3;font:700 .63rem/1.35 "Cascadia Code",monospace;overflow-wrap:anywhere}.session-actions button,.session-actions a{min-height:28px;border:1px solid rgba(96,201,255,.24);border-radius:7px;background:rgba(4,10,20,.68);color:#e5f6ff;padding:5px 8px;text-decoration:none;font:900 .62rem "Cascadia Code",monospace;cursor:pointer}.session-actions button:hover,.session-actions a:hover,.session-actions button:focus-visible,.session-actions a:focus-visible{border-color:rgba(46,230,170,.52);outline:none}.session-empty{border:1px dashed rgba(155,176,211,.22);border-radius:8px;padding:16px;color:#b7c7db;background:rgba(4,10,20,.54);font:800 .72rem "Cascadia Code",monospace}
.buy-tokens{justify-self:end;display:inline-flex;align-items:center;justify-content:center;min-height:30px;border:1px solid rgba(251,191,36,.36);border-radius:8px;padding:6px 10px;background:linear-gradient(135deg,rgba(251,191,36,.20),rgba(244,114,182,.12));color:#fff7cc;text-decoration:none;font:900 .68rem "Cascadia Code",monospace;white-space:nowrap}
.token-meter{grid-column:1/-1;position:relative;display:grid;grid-template-columns:minmax(0,1fr) auto;gap:4px 12px;align-items:center;margin:2px -14px -12px;padding:0 14px 10px}
.token-meter-line{grid-column:1/-1;height:6px;border-radius:999px;overflow:hidden;background:rgba(3,9,18,.82);box-shadow:inset 0 0 0 1px rgba(255,255,255,.08),0 0 18px rgba(46,230,170,.16)}
.token-meter-fill{height:100%;width:0%;border-radius:inherit;background:linear-gradient(90deg,#ff3df2,#8b5cf6,#38bdf8,#2ee6aa,#facc15,#ff3df2);background-size:360% 100%;animation:autoTokenRgb 3.8s linear infinite;box-shadow:0 0 16px rgba(46,230,170,.8),0 0 28px rgba(96,201,255,.45)}
.token-meter-text,.token-meter-cost{color:#c9d8ef;font:900 .62rem "Cascadia Code",monospace;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.token-meter-cost{text-align:right;color:#fde68a}
.token-delta{position:absolute;right:18px;top:-7px;border:1px solid rgba(251,113,133,.44);border-radius:999px;padding:2px 7px;background:rgba(69,10,10,.88);color:#fecaca;font:1000 .68rem "Cascadia Code",monospace;opacity:0;transform:translateY(6px);transition:opacity .22s ease,transform .22s ease}.token-delta.visible{opacity:1;transform:translateY(-4px)}
.premium-switch{display:inline-flex;align-items:center;gap:7px;min-height:30px;border:1px solid rgba(251,191,36,.30);border-radius:8px;padding:5px 9px;background:rgba(4,10,20,.62);color:#fde68a;font:900 .68rem "Cascadia Code",monospace;cursor:pointer}.premium-switch input{width:14px;height:14px;accent-color:#fbbf24}
.composer-meta{grid-column:1/-1;display:flex;justify-content:space-between;gap:10px;align-items:center;color:#b7c7db;font:900 .68rem "Cascadia Code",monospace}.composer-meta .premium-note{color:#fde68a}
.model-suggestion-group{padding:7px 9px 4px;color:#7dd3fc;font:1000 .58rem "Cascadia Code",monospace;text-transform:uppercase;letter-spacing:.08em}.model-suggestion.hf,.model-suggestion.offline{color:#8a98ad;cursor:not-allowed;opacity:.72}.model-suggestion.hf strong,.model-suggestion.offline strong{color:#9aa8bb}.model-suggestion.offline:hover,.model-suggestion.offline.active{background:transparent}.model-suggestion.server strong{color:#eefdf7}.model-suggestion span{justify-self:end}
.media-card.media-status-card{display:grid;width:min(100%,560px);justify-self:start;overflow:hidden;border-color:rgba(46,230,170,.28);background:rgba(3,9,18,.78)}
.media-stage{position:relative;width:100%;min-width:0;min-height:220px;display:grid;place-items:center;overflow:hidden;background:radial-gradient(circle at 48% 38%,rgba(96,201,255,.20),transparent 17rem),radial-gradient(circle at 54% 64%,rgba(46,230,170,.14),transparent 19rem),#020816}
.media-stage::before{content:"";position:absolute;inset:18%;border-radius:28px;background:linear-gradient(135deg,rgba(46,230,170,.34),rgba(96,201,255,.18),rgba(244,114,182,.15));filter:blur(12px);opacity:.52;transform:scale(.92)}
.media-stage.loading::after,.media-stage.error::after{content:"";position:absolute;width:min(46%,360px);aspect-ratio:16/10;border-radius:44% 56% 50% 50%;background:linear-gradient(135deg,rgba(255,255,255,.34),rgba(96,201,255,.18),rgba(46,230,170,.16));filter:blur(6px);opacity:.36;animation:autoMediaPulse 3s ease-in-out infinite}
.media-stage.error::after{background:linear-gradient(135deg,rgba(251,113,133,.44),rgba(251,191,36,.22));animation:none}
.media-stage img,.media-stage video{position:relative;z-index:1;display:block;width:100%;max-width:100%;height:auto;max-height:min(72vh,640px);object-fit:contain;background:#020816}
.media-stage.multi{grid-template-columns:repeat(auto-fit,minmax(min(220px,100%),1fr));gap:8px;padding:8px;place-items:center}
.media-stage.multi img,.media-stage.multi video{border-radius:6px}
.media-stage audio{position:relative;z-index:1;width:min(100%,640px);padding:18px}
.media-status-row{display:flex;align-items:center;gap:8px;min-height:36px;border-top:1px solid rgba(155,176,211,.18);padding:7px 9px;background:rgba(4,10,20,.76);cursor:pointer}
.media-status-toggle{width:24px;height:22px;display:grid;place-items:center;flex:0 0 auto;border:1px solid rgba(96,201,255,.24);border-radius:6px;background:rgba(2,8,16,.82);color:#dbeafe;font:1000 .72rem "Cascadia Code",monospace;cursor:pointer}
.media-status-text{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#c9d8ef;font:900 .68rem "Cascadia Code",monospace}
.media-debug-lines{display:none;margin:0;padding:10px;border-top:1px solid rgba(155,176,211,.16);max-height:230px;overflow:auto;background:rgba(2,8,16,.78);color:#b7c7db;font:.72rem "Cascadia Code",monospace;white-space:pre-wrap;overflow-wrap:anywhere}
.media-card.expanded .media-debug-lines{display:block}
@keyframes autoMediaPulse{0%,100%{transform:scale(.94);opacity:.34}50%{transform:scale(1.08);opacity:.58}}
@keyframes autoTokenRgb{from{background-position:0% 50%}to{background-position:360% 50%}}
@keyframes autoSpin{to{transform:rotate(360deg)}}
#autoStarfield{position:fixed;inset:0;z-index:0;width:100%;height:100%;pointer-events:none}
.auto-bg-swirl,.auto-glass-parallax{position:fixed;inset:-10vmax;pointer-events:none}
.auto-bg-swirl{z-index:0;opacity:.24;filter:blur(24px) saturate(1.18);mix-blend-mode:screen;background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.20),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.18),transparent 28rem),radial-gradient(circle at 52% 76%,rgba(244,143,177,.14),transparent 30rem);transform:translate3d(var(--auto-bg-x),var(--auto-bg-y),0)}
.auto-bg-swirl::before,.auto-bg-swirl::after{content:"";position:absolute;inset:-10vmax;pointer-events:none;background-image:radial-gradient(circle,rgba(255,255,255,.92) 0 1px,transparent 1.6px),radial-gradient(circle,rgba(125,211,252,.82) 0 1.2px,transparent 1.9px),radial-gradient(circle,rgba(64,201,162,.68) 0 1px,transparent 1.7px);background-size:120px 120px,190px 190px,310px 310px;background-position:0 0,48px 72px,90px 34px;opacity:.44;mix-blend-mode:screen;filter:drop-shadow(0 0 5px rgba(125,211,252,.54));transform:translate3d(var(--auto-star-x),var(--auto-star-y),0)}
.auto-bg-swirl::after{background-size:80px 80px,150px 150px,260px 260px;background-position:22px 18px,110px 40px,64px 120px;opacity:.28;filter:drop-shadow(0 0 8px rgba(255,255,255,.34))}
.auto-glass-parallax{z-index:1;background:radial-gradient(circle at var(--auto-glass-point-x) var(--auto-glass-point-y),rgba(84,225,192,.12),transparent 18rem),repeating-linear-gradient(115deg,rgba(255,255,255,.020) 0 1px,transparent 1px 18px);opacity:.36;mix-blend-mode:screen;transform:translate3d(var(--auto-glass-x),var(--auto-glass-y),0)}
.top{backdrop-filter:blur(8px)}
body{background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.14),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.14),transparent 28rem),radial-gradient(circle at 50% 74%,rgba(244,143,177,.11),transparent 30rem),linear-gradient(180deg,#05070b 0%,#07101b 44%,#05070b 100%)}
body::before,body::after{content:"";position:fixed;inset:0;pointer-events:none;z-index:0}
body::before{background:linear-gradient(rgba(255,255,255,.035) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.028) 1px,transparent 1px);background-size:72px 72px;mask-image:linear-gradient(180deg,rgba(0,0,0,.9),rgba(0,0,0,.34) 54%,rgba(0,0,0,.72));transform:translate3d(calc(var(--auto-bg-x)*.34),calc(var(--auto-bg-y)*.34),0)}
body::after{z-index:1;background:repeating-linear-gradient(180deg,rgba(255,255,255,.032) 0 1px,transparent 1px 5px),linear-gradient(90deg,rgba(84,225,192,.045),transparent 26%,rgba(244,143,177,.035) 72%,rgba(255,207,107,.04));mix-blend-mode:screen;opacity:.30;transform:translate3d(calc(var(--auto-glass-x)*.38),calc(var(--auto-glass-y)*.38),0)}
.app{position:relative;z-index:2}
body.prompt-loading .auto-bg-swirl::before{animation:autoStarDrift 120s linear infinite}
body.prompt-loading .auto-bg-swirl::after{animation:autoStarDrift 90s linear infinite reverse}
body.prompt-loading .auto-glass-parallax{opacity:.46}
@keyframes autoStarDrift{from{background-position:0 0,48px 72px,90px 34px}to{background-position:1200px 620px,820px 1120px,1440px 760px}}
@media(max-width:720px),(orientation:portrait){#autoStarfield{opacity:.55}.auto-bg-swirl{filter:blur(14px) saturate(1.08);opacity:.18}.auto-glass-parallax{opacity:.24}.top{backdrop-filter:none}}
@media(prefers-reduced-motion:reduce){#autoStarfield,.auto-glass-parallax{display:none}.auto-bg-swirl{filter:blur(12px) saturate(1.02);opacity:.16}.auto-bg-swirl::before,.auto-bg-swirl::after{animation:none!important}}
.chat-shell{grid-template-rows:minmax(0,1fr) auto auto;background:linear-gradient(145deg,rgba(255,255,255,.08),rgba(9,20,34,.72))}
.chat-head{display:grid;grid-template-columns:minmax(360px,1fr) minmax(320px,.78fr);align-items:stretch;background:linear-gradient(135deg,rgba(13,28,48,.88),rgba(7,18,32,.74))}
.route-panel{display:grid;align-content:start;gap:8px;min-width:0;border:1px solid rgba(155,176,211,.16);border-radius:8px;padding:10px;background:linear-gradient(145deg,rgba(255,255,255,.055),rgba(3,9,18,.30));box-shadow:inset 0 1px 0 rgba(255,255,255,.06)}
.route-panel-actions{justify-content:end}.route-panel-title{color:#8fb5d6;font:1000 .56rem "Cascadia Code",monospace;text-transform:uppercase}
.switchbar{min-width:0}.chat-actions{display:flex;flex-wrap:wrap;justify-content:flex-end;align-content:start;gap:8px;min-width:0}
.mode-toggle,.origin-toggle{box-shadow:0 12px 34px rgba(2,8,20,.22),inset 0 1px 0 rgba(255,255,255,.08)}
.mode-toggle button,.origin-toggle button{padding-left:11px;padding-right:11px}.mode-toggle button.active,.origin-toggle button.active{background:linear-gradient(135deg,rgba(46,230,170,.36),rgba(96,201,255,.18));color:#f8fffc}
.session-artifacts{display:grid;grid-template-columns:auto minmax(0,1fr);gap:10px;align-items:center;min-height:46px;padding:8px 12px;border-top:1px solid rgba(155,176,211,.18);background:linear-gradient(90deg,rgba(7,19,32,.84),rgba(8,15,27,.78));box-shadow:inset 0 1px 0 rgba(255,255,255,.05)}
.session-artifacts[hidden]{display:none!important}.session-artifacts-label{color:#c9d8ef;font:900 .62rem "Cascadia Code",monospace;text-transform:uppercase;white-space:nowrap}.session-artifact-list{min-width:0;display:flex;gap:8px;overflow-x:auto;overscroll-behavior-x:contain;padding:2px 1px 4px;scrollbar-width:thin}
.bubble-artifacts{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px;padding-top:10px;border-top:1px solid rgba(155,176,211,.14)}
.bubble-actions{display:flex;justify-content:flex-end;gap:8px;margin-top:10px;padding-top:10px;border-top:1px solid rgba(155,176,211,.12)}.bubble-action{min-height:30px;border:1px solid rgba(96,201,255,.28);border-radius:7px;background:linear-gradient(135deg,rgba(96,201,255,.12),rgba(4,10,20,.72));color:#e5f6ff;padding:5px 10px;font:900 .62rem "Cascadia Code",monospace;cursor:pointer}.bubble-action.undo{border-color:rgba(251,191,36,.34);background:linear-gradient(135deg,rgba(251,191,36,.14),rgba(4,10,20,.78));color:#fff6cf}.bubble-action:hover,.bubble-action:focus-visible{border-color:rgba(46,230,170,.62);outline:none}.bubble-action:disabled{opacity:.56;cursor:wait}
.artifact-chip{max-width:280px;min-height:32px;display:grid;grid-template-columns:auto minmax(0,1fr);grid-template-rows:auto auto;gap:0 7px;align-items:center;border:1px solid rgba(96,201,255,.25);border-radius:8px;background:linear-gradient(135deg,rgba(96,201,255,.12),rgba(4,10,20,.72));color:#e6f8ff;text-decoration:none;padding:6px 8px;font:900 .66rem "Cascadia Code",monospace;box-shadow:inset 0 1px 0 rgba(255,255,255,.06)}
.artifact-chip:hover,.artifact-chip:focus-visible{border-color:rgba(46,230,170,.58);background:linear-gradient(135deg,rgba(46,230,170,.20),rgba(96,201,255,.14));outline:none}.artifact-chip .artifact-kind{grid-row:1/3;min-width:24px;height:24px;display:grid;place-items:center;border:1px solid rgba(46,230,170,.28);border-radius:6px;background:rgba(2,8,16,.72);color:#baf7e6;text-transform:uppercase}.artifact-chip .artifact-name{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.artifact-chip small{min-width:0;color:#91a8c5;font-size:.55rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.artifact-chip.link{border-color:rgba(251,191,36,.28);background:linear-gradient(135deg,rgba(251,191,36,.10),rgba(4,10,20,.72))}.artifact-chip.link .artifact-kind{border-color:rgba(251,191,36,.28);color:#fde68a}
#autoStarfield{opacity:1;filter:saturate(1.48)}
.auto-bg-swirl{opacity:.34;filter:blur(22px) saturate(1.54);background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.30),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.28),transparent 28rem),radial-gradient(circle at 52% 76%,rgba(244,143,177,.22),transparent 30rem)}
.auto-glass-parallax{opacity:.44;background:radial-gradient(circle at var(--auto-glass-point-x) var(--auto-glass-point-y),rgba(84,225,192,.17),transparent 18rem),repeating-linear-gradient(115deg,rgba(255,255,255,.026) 0 1px,transparent 1px 18px)}
body{background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.21),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.20),transparent 28rem),radial-gradient(circle at 50% 74%,rgba(244,143,177,.16),transparent 30rem),linear-gradient(180deg,#05070b 0%,#071323 44%,#05070b 100%)}
body::after{opacity:.42}
.top{grid-template-columns:minmax(0,1fr) auto;grid-template-areas:"brand server" "route route" "tokens tokens";align-items:start}.brand{grid-area:brand}.server-capsule{grid-area:server;justify-items:end}.server-name{display:inline-flex;align-items:center;justify-content:flex-end;gap:8px;max-width:min(470px,46vw);color:#ecfff9;text-decoration:none;cursor:pointer}.server-name[aria-disabled="true"]{cursor:default;color:#c4d2e6;border-color:rgba(155,176,211,.22);background:rgba(4,10,20,.58)}.server-name span:first-child{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.server-name .server-arrow{color:#bdf7ff;font-weight:1000}.server-name:not([aria-disabled="true"]):hover,.server-name:not([aria-disabled="true"]):focus-visible{border-color:rgba(46,230,170,.64);background:linear-gradient(135deg,rgba(46,230,170,.20),rgba(96,201,255,.12));outline:none}.auth-status{justify-self:end;color:#c8ffe8;text-decoration:none;font:900 .64rem "Cascadia Code",monospace}.auth-status.warn{color:#fde68a}.auth-status.good{color:#c8ffe8}.continue-server,.pool-status-silent{display:none!important}.top-route-row{grid-area:route;display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;align-items:end}.top-route-actions{display:flex;justify-content:flex-end;align-items:center;gap:8px;min-width:0}.masterlist-top{min-height:32px}.token-meter{grid-area:tokens;grid-column:1/-1;margin:2px -14px -12px;padding:0 14px 10px}.route-panel-actions{display:none}.premium-switch.disabled{opacity:.48;cursor:not-allowed}.premium-switch.disabled input{cursor:not-allowed}.session-edge-toggle{position:fixed;left:0;top:50%;z-index:13;width:46px;height:122px;transform:translateY(-50%);border:0;border-radius:0 18px 18px 0;background:linear-gradient(90deg,rgba(0,0,0,.94),rgba(0,0,0,.62),rgba(0,0,0,0));color:#dbeafe;font:1000 1.25rem "Cascadia Code",monospace;cursor:pointer;opacity:.86;box-shadow:18px 0 44px rgba(0,0,0,.38);transition:left .2s ease,opacity .16s ease,color .16s ease}.session-edge-toggle:hover,.session-edge-toggle:focus-visible{opacity:1;color:#bdf7ff;outline:none}body.sessions-open .session-edge-toggle{left:min(420px,calc(100vw - 18px));border-radius:18px 0 0 18px;background:linear-gradient(270deg,rgba(0,0,0,.86),rgba(0,0,0,.48),rgba(0,0,0,0));color:#9fb0c8}.composer{grid-template-columns:minmax(210px,300px) minmax(0,1fr) 116px;grid-template-areas:"meta meta meta" "model prompt send";align-items:stretch}.composer-meta{grid-area:meta;grid-column:auto}.model-combo{grid-area:model;display:grid;grid-template-rows:auto minmax(0,1fr);gap:8px;align-self:stretch}.model-origin-dock{display:grid;grid-template-columns:1fr;gap:6px;align-content:start;padding:7px 8px;border:1px solid rgba(155,176,211,.16);border-radius:8px;background:rgba(3,9,18,.48)}.model-origin-dock>span{color:#8fb5d6;font:1000 .56rem "Cascadia Code",monospace;text-transform:uppercase;white-space:nowrap}.model-origin-dock .origin-toggle{width:100%;display:flex}.model-origin-dock .origin-toggle button{flex:1;min-height:32px;padding:5px 6px;font-size:.58rem;line-height:1.1;white-space:normal}.composer textarea{grid-area:prompt;height:106px;min-height:106px;max-height:260px}.send{grid-area:send;min-height:106px;border:0;background:linear-gradient(135deg,rgba(255,255,255,.13),rgba(46,230,170,.10),rgba(96,201,255,.08));box-shadow:inset 0 1px 0 rgba(255,255,255,.20),0 14px 32px rgba(0,0,0,.20);backdrop-filter:blur(14px)}
