.model-suggestion-tools{position:sticky;top:0;z-index:3;display:flex;justify-content:flex-end;gap:6px;padding:3px 2px 7px;background:linear-gradient(180deg,rgba(3,9,18,.98),rgba(3,9,18,.82))}
.model-list-action{width:27px;height:27px;display:grid;place-items:center;border:1px solid rgba(125,211,252,.34);border-radius:50%;background:rgba(2,8,16,.38);color:#dffbff;font:1000 .8rem "Cascadia Code",monospace;text-shadow:0 0 8px rgba(56,189,248,.62);cursor:pointer;transition:transform .15s ease,box-shadow .15s ease,border-color .15s ease}
.model-list-action:hover,.model-list-action:focus-visible{outline:none;transform:translateY(-1px) scale(1.05);border-color:rgba(255,255,255,.78);animation:autoRouteButtonRgb 1.1s linear infinite;box-shadow:0 0 18px rgba(56,189,248,.36),0 0 34px rgba(168,85,247,.22)}
.model-suggestions .model-suggestion{grid-template-columns:minmax(0,1fr) auto 24px!important;position:relative;border:1px solid transparent!important;transition:transform .15s ease,border-color .15s ease,box-shadow .15s ease,opacity .15s ease}
.model-suggestions .model-suggestion.server{cursor:pointer}
.model-suggestions .model-suggestion.server:hover,.model-suggestions .model-suggestion.server:focus-visible{outline:none;transform:translateX(2px);border-color:rgba(56,189,248,.42)!important;box-shadow:0 0 18px rgba(56,189,248,.20),inset 0 0 0 1px rgba(255,255,255,.05)}
.model-suggestions .model-suggestion.disabled-model{opacity:.58;background:linear-gradient(135deg,rgba(75,85,99,.22),rgba(2,8,16,.58));text-decoration:line-through;text-decoration-thickness:1px;text-decoration-color:rgba(248,113,113,.70)}
.model-suggestions .model-suggestion.soloed{border-color:rgba(255,255,255,.66)!important;box-shadow:0 0 20px rgba(56,189,248,.28),0 0 38px rgba(236,72,153,.18)}
.model-suggestions .model-suggestion.model-pop{animation:autoModelPop .34s ease both}
.model-solo{width:18px;height:18px;display:grid;place-items:center;align-self:center;justify-self:end;border:1px solid rgba(148,163,184,.46);border-radius:50%;background:rgba(75,85,99,.54);color:#9ca3af;font-size:.54rem;line-height:1;cursor:pointer;box-shadow:inset 0 1px 0 rgba(255,255,255,.12);transition:transform .15s ease,border-color .15s ease,box-shadow .15s ease,color .15s ease}
.model-solo:hover,.model-solo:focus-visible{outline:none;transform:scale(1.12);border-color:rgba(255,255,255,.72);box-shadow:0 0 14px rgba(148,163,184,.32)}
.model-solo.active{border-color:rgba(255,255,255,.82);color:#fff;background:linear-gradient(120deg,#22c55e,#38bdf8,#8b5cf6,#ec4899,#22c55e);background-size:320% 100%;animation:autoParamValueRgb 1.5s linear infinite;box-shadow:0 0 16px rgba(56,189,248,.48),0 0 30px rgba(236,72,153,.24)}
@keyframes autoModelPop{0%{transform:scale(.985)}45%{transform:scale(1.018);box-shadow:0 0 26px rgba(56,189,248,.34),0 0 44px rgba(236,72,153,.18)}100%{transform:scale(1)}}
@keyframes autoRouteRgb{from{background-position:0% 50%}to{background-position:360% 50%}}
@keyframes autoRouteButtonRgb{0%{text-shadow:0 0 8px #38bdf8;border-color:rgba(56,189,248,.78)}33%{text-shadow:0 0 9px #a855f7;border-color:rgba(168,85,247,.78)}66%{text-shadow:0 0 9px #22c55e;border-color:rgba(34,197,94,.78)}100%{text-shadow:0 0 8px #38bdf8;border-color:rgba(56,189,248,.78)}}
@keyframes autoParamValueRgb{from{background-position:0% 50%;filter:saturate(1.15)}50%{filter:saturate(1.85)}to{background-position:340% 50%;filter:saturate(1.15)}}
.send{position:relative;isolation:isolate;overflow:hidden;color:#f8fffc!important;text-shadow:0 0 8px rgba(56,189,248,.52),0 0 18px rgba(168,85,247,.22);border:1px solid rgba(125,211,252,.28)!important;background:rgba(2,8,16,.34)!important;transition:transform .16s ease,box-shadow .16s ease,border-color .16s ease}
.send::before{content:"";position:absolute;inset:-2px;z-index:-2;background:linear-gradient(120deg,#22c55e,#38bdf8,#8b5cf6,#ec4899,#22c55e);background-size:380% 100%;opacity:.42;animation:autoSendRgb 5.8s linear infinite}
.send::after{content:"";position:absolute;inset:1px;z-index:-1;border-radius:7px;background:rgba(2,8,16,.74)}
.send:hover,.send:focus-visible{border-color:rgba(255,255,255,.68)!important;outline:none;transform:translateY(-1px);box-shadow:0 0 20px rgba(56,189,248,.28),0 0 42px rgba(139,92,246,.18),inset 0 1px 0 rgba(255,255,255,.20)}
.send:hover::before,.send:focus-visible::before{opacity:.58;animation-duration:3.6s}
body.prompt-loading .send,.send:disabled{opacity:1!important;cursor:wait;animation:autoSendFlash .62s ease-in-out infinite alternate;box-shadow:0 0 26px rgba(56,189,248,.44),0 0 52px rgba(139,92,246,.28),0 0 72px rgba(34,197,94,.16),inset 0 1px 0 rgba(255,255,255,.26)}
body.prompt-loading .send::before,.send:disabled::before{opacity:.86;animation-duration:.9s}
@keyframes autoSendRgb{from{background-position:0% 50%}to{background-position:380% 50%}}
@keyframes autoSendFlash{from{filter:saturate(1.15) brightness(1);transform:translateY(0) scale(1)}to{filter:saturate(2) brightness(1.28);transform:translateY(-1px) scale(1.012)}}
.token-actions{position:relative;isolation:isolate;display:flex;align-items:stretch;min-width:260px;border:1px solid transparent;border-radius:8px;overflow:visible;background:linear-gradient(145deg,rgba(255,249,196,.96) 0%,rgba(250,204,21,.94) 18%,rgba(180,83,9,.90) 52%,rgba(254,240,138,.94) 76%,rgba(113,63,18,.90) 100%) padding-box,linear-gradient(110deg,#ff2bd6,#38d5ff,#22c55e,#facc15,#ff2bd6) border-box;box-shadow:0 14px 38px rgba(120,73,5,.34),0 0 22px rgba(56,213,255,.22),inset 0 1px 0 rgba(255,255,255,.70),inset 0 -1px 0 rgba(92,56,4,.58)}
.server-capsule .token-actions{justify-self:end;width:min(300px,100%);margin-top:5px}
.token-actions::before{content:"";position:absolute;inset:0;z-index:0;background:linear-gradient(112deg,transparent 0 43%,rgba(255,255,255,.82) 43% 47%,rgba(255,255,255,.18) 47% 50%,transparent 50% 100%);background-size:220% 100%;animation:autoGoldShine 2.2s steps(2,end) infinite;pointer-events:none}
.token-actions::after{content:attr(data-tip);position:absolute;right:0;top:calc(100% + 8px);z-index:20;width:min(320px,76vw);padding:9px 10px;border:1px solid rgba(253,224,71,.74);border-radius:8px;background:linear-gradient(145deg,rgba(55,34,3,.98),rgba(120,73,5,.96));color:#fff7cc;font:800 .64rem/1.35 "Cascadia Code",monospace;box-shadow:0 18px 48px rgba(0,0,0,.42),inset 0 1px 0 rgba(255,255,255,.22);opacity:0;transform:translateY(-3px);pointer-events:none;transition:opacity .16s ease,transform .16s ease}
.token-actions:hover::after,.token-actions:focus-within::after{opacity:1;transform:translateY(0)}
.token-actions .buy-tokens,.token-actions .premium-switch{position:relative;z-index:1;flex:1 1 0;min-height:38px;border:0;border-radius:0;background:linear-gradient(100deg,#ff2bd6,#38d5ff,#22c55e,#facc15,#ff2bd6);background-size:280% 100%;-webkit-background-clip:text;background-clip:text;color:transparent;text-shadow:none;box-shadow:none;animation:autoParamValueRgb 2.4s linear infinite}
.token-actions .buy-tokens{display:flex;align-items:center;justify-content:center;padding:7px 10px;text-decoration:none;font:1000 .68rem "Cascadia Code",monospace}
.token-actions .premium-switch{display:flex;align-items:center;justify-content:center;gap:5px;border-left:1px solid rgba(92,56,4,.34);font-size:.62rem}
.token-actions .premium-switch input{accent-color:#7c4a03}
@keyframes autoGoldShine{0%,44%{background-position:130% 0}45%,100%{background-position:-90% 0}}
.top{position:relative;z-index:6;overflow:visible}.token-actions{z-index:30}.token-actions::after{z-index:1000!important;visibility:hidden;opacity:0;transition:opacity .05s linear,transform .05s linear,visibility 0s linear .05s}.token-actions:hover::after,.token-actions:focus-within::after{visibility:visible;opacity:1;transition-delay:0s}.chat-shell{position:relative;z-index:2}
.masterlist-slide-zone{position:fixed;left:50%;top:0;z-index:16;width:min(360px,52vw);height:58px;display:flex;justify-content:center;align-items:flex-start;transform:translateX(-50%);text-decoration:none;pointer-events:auto}
