.masterlist-slide-zone:hover .masterlist-slide-button,.masterlist-slide-zone:focus-visible .masterlist-slide-button{transform:translateY(0);opacity:1;border-color:rgba(46,230,170,.68);box-shadow:0 24px 70px rgba(0,0,0,.44),0 0 30px rgba(46,230,170,.24),inset 0 1px 0 rgba(255,255,255,.22);outline:none}
.auto-site-brand{grid-area:brand;display:inline-flex;align-items:center;gap:10px;color:#f4f8ff;text-decoration:none;font:1000 .82rem "Cascadia Code",monospace}.auto-site-brand small{display:block;margin-top:2px;color:rgba(244,248,255,.62);font-size:.62rem}.auto-site-brand-mark{width:40px;height:40px;display:grid;place-items:center;border-radius:9px;background:linear-gradient(135deg,#52e4ff,#68f5b4 43%,#ff7ab6);color:#031019;font-weight:1000;box-shadow:0 0 34px rgba(84,225,192,.34),inset 0 1px 0 rgba(255,255,255,.74)}
html:not(.auto-masterlist-frame) .top{grid-template-areas:"brand server" "route route" "tokens tokens"}
