.auth-status{position:fixed;left:14px;bottom:14px;z-index:18;min-height:34px;display:inline-grid;place-items:center;border:1px solid rgba(46,230,170,.62);border-radius:8px;padding:7px 11px;background:rgba(6,78,59,.66);color:#bfffea!important;box-shadow:0 0 24px rgba(46,230,170,.24),inset 0 1px 0 rgba(255,255,255,.18);backdrop-filter:blur(10px);opacity:.66}.auth-status:hover,.auth-status:focus-visible{opacity:1;outline:none}
.session-tab-new{min-width:38px;max-width:42px;padding:6px;font-size:.66rem;text-transform:none}.session-tab-new .session-tab-plus{width:18px;height:18px;display:inline-grid;place-items:center;border:1px solid rgba(46,230,170,.34);border-radius:50%;background:rgba(46,230,170,.13);color:#bfffea;font-size:.88rem}
