.composer-token-actions.token-actions::before{display:none!important}.composer-token-actions.token-actions::after{right:0;top:auto;bottom:calc(100% + 8px)}.composer-token-actions .buy-tokens,.composer-token-actions .premium-switch{min-height:34px;font-size:.58rem}.composer-token-actions .premium-switch{gap:4px}.composer-token-actions .premium-switch input{width:13px;height:13px}
