.auto-session-server-group{display:grid;gap:7px;border:1px solid rgba(125,211,252,.18);border-radius:8px;background:linear-gradient(145deg,rgba(2,8,16,.44),rgba(10,24,38,.26));padding:7px}.auto-session-server-summary{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:5px 8px;align-items:center;cursor:pointer;list-style:none}.auto-session-server-summary::-webkit-details-marker{display:none}.auto-session-server-name{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#e9fbff;font:1000 .72rem "Cascadia Code",monospace}.auto-session-server-count{justify-self:end;color:#9ab4cc;font:900 .54rem "Cascadia Code",monospace}.auto-session-server-search{grid-column:1/-1;min-height:28px;border:1px solid rgba(125,211,252,.18);border-radius:7px;background:rgba(3,9,18,.62);color:#e7f7ff;padding:5px 8px;font:800 .62rem "Cascadia Code",monospace}.auto-session-server-list{display:grid;gap:8px;margin-top:2px}.session-card.server-only{opacity:.72;border-color:rgba(148,163,184,.20);background:linear-gradient(145deg,rgba(75,85,99,.18),rgba(3,9,18,.52))}.session-card.server-only .session-title,.session-card.server-only .session-preview,.session-card.server-only .session-detail{color:#aeb8c6}.session-card.server-only:hover,.session-card.server-only:focus-within{opacity:.96;border-color:rgba(125,211,252,.36)}.session-chip.good{border-color:rgba(46,230,170,.28);color:#bfffea}
.session-top-row{min-width:0;display:flex;align-items:flex-start;gap:8px;padding:8px 12px;border-bottom:1px solid rgba(155,176,211,.16);background:linear-gradient(135deg,rgba(10,20,36,.72),rgba(3,9,18,.54));overflow:visible}.session-top-row .session-tabs{flex:1 1 auto;min-width:0;padding:0;border-bottom:0;background:transparent}.session-top-row .current-progress-panel,body.auto-browser-open .session-top-row .current-progress-panel{position:relative!important;top:auto!important;right:auto!important;z-index:8;flex:0 0 auto;width:min(360px,36vw);max-width:min(360px,calc(100vw - 28px));max-height:min(58vh,560px);align-self:flex-start;opacity:.86;transition:opacity .16s ease,border-color .16s ease,box-shadow .16s ease}.session-top-row .current-progress-panel:hover,.session-top-row .current-progress-panel:focus-within{opacity:1}.session-top-row .current-progress-panel.collapsed{width:auto;max-width:220px;align-self:center}.current-progress-panel.collapsed .current-progress-head{min-height:34px;border-bottom:0;padding:4px 5px 4px 9px}.current-progress-panel.collapsed .current-progress-head strong{max-width:118px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.current-progress-count{min-width:20px;height:20px;display:inline-grid;place-items:center;border:1px solid rgba(250,204,21,.48);border-radius:999px;background:rgba(250,204,21,.16);color:#fde68a;font:1000 .58rem/1 "Cascadia Code",monospace;box-shadow:0 0 16px rgba(250,204,21,.28)}.current-progress-count[hidden],.current-progress-panel:not(.collapsed) .current-progress-count{display:none!important}.current-progress-panel.collapsed.progress-pulse{animation:currentProgressGlow 1.25s ease-out both}.current-progress-panel.collapsed.progress-pulse .current-progress-head strong{color:#fff7c2}@keyframes currentProgressGlow{0%{border-color:rgba(250,204,21,.95);box-shadow:0 0 0 0 rgba(250,204,21,.58),0 0 28px rgba(250,204,21,.42),inset 0 1px 0 rgba(255,255,255,.18)}55%{border-color:rgba(46,230,170,.76);box-shadow:0 0 0