<style>
.session-top-row{position:relative;min-height:51px;overflow:visible}
.session-top-row .session-tabs{padding-right:min(380px,40vw)}
.current-progress-panel{width:min(430px,calc(100vw - 28px))}
.current-progress-list{gap:6px}
.current-progress-item{align-items:start}
.current-progress-copy{min-width:0;display:grid;gap:2px}
.current-progress-copy button,.current-progress-copy a{width:100%}
.current-progress-detail{color:#9fb0c8;font:.56rem/1.28 "Cascadia Code",monospace;white-space:normal;overflow-wrap:anywhere}
.progress-status-dot.pending{background:rgba(15,23,42,.80);border-color:rgba(148,163,184,.34)}
.progress-status-dot.pending::before{content:"";width:7px;height:7px;border-radius:999px;background:rgba(148,163,184,.62)}
.session-top-row .current-progress-panel,
body.auto-browser-open .session-top-row .current-progress-panel{
    position:absolute!important;
    top:8px!important;
    right:12px!important;
    z-index:18;
    flex:none!important;
    justify-self:auto!important;
    align-self:auto!important;
    max-height:min(62vh,600px);
    transform:none!important;
}
.session-top-row .current-progress-panel.collapsed{top:8px!important;right:12px!important}
@media(max-width:780px){
    .session-top-row{min-height:51px}
    .session-top-row .session-tabs{padding-right:0}
    .session-top-row .current-progress-panel,
    body.auto-browser-open .session-top-row .current-progress-panel{
        top:8px!important;
        right:8px!important;
        width:min(320px,calc(100vw - 24px));
    }
    .session-top-row .current-progress-panel.collapsed{width:auto;max-width:190px}
}
.session-edge-toggle,.files-edge-toggle,.auto-browser-edge-toggle{
    width:42px!important;
    height:58px!important;
    display:grid!important;
    place-items:center!important;
    padding:0!important;
    font-size:0!important;
}
.session-edge-toggle{top:50%!important;border-radius:0 14px 14px 0!important}
.files-edge-toggle{top:calc(50% - 34px)!important;border-radius:14px 0 0 14px!important}
.auto-browser-edge-toggle{top:calc(50% + 34px)!important;border-radius:14px 0 0 14px!important}
body.files-open .files-edge-toggle{top:calc(50% - 34px)!important;border-radius:0 14px 14px 0!important}
body.auto-browser-open .auto-browser-edge-toggle{top:calc(50% + 34px)!important;border-radius:0 14px 14px 0!important}
.edge-icon{position:relative;width:23px;height:23px;display:block;color:#dffbff}
.edge-icon::before,.edge-icon::after{content:"";position:absolute;box-sizing:border-box}
.edge-icon.session-icon::before{left:4px;top:3px;width:15px;height:17px;border:2px solid currentColor;border-radius:5px;box-shadow:-4px 3px 0 -1px rgba(223,251,255,.55)}
.edge-icon.session-icon::after{left:8px;top:8px;width:8px;height:2px;background:currentColor;box-shadow:0 5px 0 currentColor;border-radius:2px}
.edge-icon.files-icon::before{left:2px;top:7px;width:19px;height:13px;border:2px solid currentColor;border-radius:4px}
.edge-icon.files-icon::after{left:4px;top:4px;width:9px;height:6px;border:2px solid currentColor;border-bottom:0;border-radius:4px 4px 0 0}
.edge-icon.browser-icon::before{left:2px;top:4px;width:19px;height:16px;border:2px solid currentColor;border-radius:5px}
.edge-icon.browser-icon::after{left:6px;top:8px;width:3px;height:3px;background:currentColor;border-radius:50%;box-shadow:5px 0 0 currentColor,10px 0 0 currentColor}
.previewable-media{cursor:zoom-in}
.auto-preview-window{position:fixed;z-index:70;left:var(--auto-preview-left,calc(50vw - 330px));top:var(--auto-preview-top,72px);width:var(--auto-preview-width,min(660px,calc(100vw - 34px)));height:var(--auto-preview-height,min(620px,calc(100vh - 96px)));min-width:280px;min-height:220px;display:grid;grid-template-rows:auto minmax(0,1fr);border:1px solid rgba(125,211,252,.36);border-radius:8px;background:linear-gradient(180deg,rgba(7,13,24,.98),rgba(9,18,30,.96));box-shadow:0 26px 110px rgba(0,0,0,.58),inset 0 1px 0 rgba(255,255,255,.08);overflow:hidden}
.auto-preview-window[hidden]{display:none!important}.auto-preview-head{min-height:42px;display:grid;grid-template-columns:minmax(0,1fr) auto;gap:8px;align-items:center;padding:8px 9px;border-bottom:1px solid rgba(155,176,211,.16);background:rgba(10,18,31,.78);cursor:move;user-select:none}.auto-preview-title{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#eaffff;font:1000 .72rem "Cascadia Code",monospace}.auto-preview-actions{display:flex;gap:6px;align-items:center}.auto-preview-download,.auto-preview-close{min-height:28px;border:1px solid rgba(125,211,252,.25);border-radius:7px;background:rgba(2,8,16,.76);color:#dffbff;text-decoration:none;padding:5px 8px;font:1000 .62rem "Cascadia Code",monospace;cursor:pointer}.auto-preview-close{width:30px;padding:0}.auto-preview-body{min-height:0;display:grid;place-items:center;padding:10px;background:#020817;overflow:auto}.auto-preview-body img,.auto-preview-body video{max-width:100%;max-height:100%;object-fit:contain;border-radius:6px}.auto-preview-body audio{width:min(520px,100%)}.auto-preview-body iframe{width:100%;height:100%;border:0;background:#f8fafc;border-radius:6px}.auto-preview-message{color:#cde8ff;font:900 .72rem/1.45 "Cascadia Code",monospace;text-align:center;overflow-wrap:anywhere}.auto-preview-resize{position:absolute;right:0;bottom:0;width:18px;height:18px;cursor:nwse-resize;background:linear-gradient(135deg,transparent 0 45%,rgba(125,211,252,.35) 45% 58%,transparent 58% 64%,rgba(125,211,252,.58) 64% 76%,transparent 76%)}
body.auto-preview-dragging,body.auto-preview-resizing{user-select:none}
</style>
</head>
<body>
<script>try{if(window.self!==window.top&&/^\/MasterList\/?$/i.test(window.parent.location.pathname||''))document.documentElement.classList.add('auto-masterlist-frame')}catch{if(window.self!==window.top)document.documentElement.classList.add('auto-masterlist-frame')}</script>
<canvas id="autoStarfield" aria-hidden="true"></canvas>
<div class="auto-bg-swirl" aria-hidden="true"></div>
<div class="auto-glass-parallax" aria-hidden="true"></div>
<div class="session-backdrop" id="sessionBackdrop" hidden></div>
<aside class="session-drawer" id="sessionDrawer" aria-label="Auto sessions" aria-hidden="true">
  <div class="session-drawer-head"><div><strong>Auto sessions</strong><span id="sessionOwner">Saved by this browser</span></div><button class="button" id="sessionClose" type="button">Close</button></div>
  <div class="session-search-wrap"><input id="sessionSearch" list="sessionSearchSuggestions" placeholder="Regex search sessions" autocomplete="off" spellcheck="false"><datalist id="sessionSearchSuggestions"></datalist></div>
  <div class="session-list" id="sessionList"></div>
  <div class="drawer-resize-handle session-resize" id="sessionResize" title="Drag to resize sessions"></div>
</aside>
<button class="session-edge-toggle" id="sessionToggle" type="button" title="Open saved Auto sessions. Sessions are tied to this IP or SocketJack account, then merged into the account after login or registration." aria-label="Open Auto sessions" aria-expanded="false"><span class="edge-icon session-icon" aria-hidden="true"></span></button>
<aside class="files-drawer" id="filesDrawer" aria-label="Current Auto session files" aria-hidden="true">
  <div class="session-drawer-head"><div><strong>Session files</strong><span id="filesOwner">Uploads and generated files</span></div><button class="button" id="filesClose" type="button">Close</button></div>
  <div class="session-artifacts" id="sessionArtifacts"><div class="session-artifacts-label">Current session files</div><div class="session-artifact-list" id="sessionArtifactList" aria-label="Files for this Auto session"></div></div>
  <div class="drawer-resize-handle files-resize" id="filesResize" title="Drag to resize files"></div>
</aside>
<button class="files-edge-toggle" id="filesToggle" type="button" title="Open current Auto session files." aria-label="Open Auto session files" aria-expanded="false"><span class="edge-icon files-icon" aria-hidden="true"></span></button>
<aside class="auto-browser-panel" id="autoBrowserPanel" aria-label="Auto browser" aria-hidden="true">
  <div class="auto-browser-resize" id="autoBrowserResize" role="separator" aria-orientation="vertical" aria-label="Resize Auto browser" tabindex="0"></div>
  <div class="auto-browser-content">
    <div class="auto-browser-head">
      <button class="auto-browser-collapse" id="autoBrowserCollapse" type="button" aria-expanded="true" title="Collapse browser">&gt;</button>
      <input class="auto-browser-address" id="autoBrowserAddress" type="url" inputmode="url" autocomplete="url" spellcheck="false" placeholder="https://example.com" aria-label="Browser URL">
      <button class="auto-browser-go" id="autoBrowserGo" type="button">Go</button>
      <button class="auto-browser-external" id="autoBrowserExternal" type="button" title="Open externally">^</button>
    </div>
    <div class="auto-browser-stage">
      <iframe class="auto-browser-frame" id="autoBrowserFrame" title="Auto browser" sandbox="allow-scripts allow-forms allow-modals allow-popups allow-popups-to-escape-sandbox allow-same-origin" referrerpolicy="no-referrer-when-downgrade"></iframe>
      <div class="auto-browser-empty" id="autoBrowserEmpty">Nothing here yet</div>
    </div>
  </div>
</aside>
<button class="auto-browser-edge-toggle" id="autoBrowserToggle" type="button" title="Open Auto browser" aria-label="Open Auto browser" aria-expanded="false"><span class="edge-icon browser-icon" aria-hidden="true"></span></button>
