function progressStatusDotClass(status){status=String(status||'').toLowerCase();if(/fail|error|stop|cancel|blocked/.test(status))return'failed';if(/done|complete|success|finish|ready/.test(status))return'done';if(/pending|queued|wait|next/.test(status))return'pending';return'running'}
