function currentProgressDefaultPlan(routeMode,prompt){const route=normalizeMode(routeMode||mode),plan=[currentProgressPromptGoal(prompt,route),{id:'prepare',key:'prepare',label:currentProgressPlanLabel('prepare',route),status:'pending',detail:'Gather the visible prompt, session history, queued files, model filters, and undo snapshot.',meta:'context'},{id:'route',key:'route',label:currentProgressPlanLabel('route',route),status:'pending',detail:route==='auto'?'Ask Auto Router to infer Text, Tools, Vision, Media, Audio, Video, or Embeddings.':'User selected '+modeLabel(route)+' mode.',meta:'router'},{id:'server',key:'server',label:currentProgressPlanLabel('server',route),status:'pending',detail:'Choose an eligible server/model using origin, pool, parameter, premium, and disabled-model filters.',meta:'server'},{id:'send',key:'send',label:currentProgressPlanLabel('send',route),status:'pending',detail:'Forward the prompt through /auto/api using the selected route and session id.',meta:'proxy'},{id:'tools',key:'tools',label:currentProgressPlanLabel('tools',route),status:'pending',detail:'Show reasoning snippets, tool cards, sources, files, and streaming answer chunks as they arrive.',meta:'stream'},{id:'synthesize',key:'synthesize',label:currentProgressPlanLabel('synthesize',route),status:'pending',detail:'Check whether the gathered information satisfies the request before returning the final answer.',meta:'judge'},{id:'final',key:'final',label:currentProgressPlanLabel('final',route),status:'pending',detail:'Save outputs to the session, update transcript state, and finish the visible response.',meta:'finish'}];currentProgressExtractPromptGoals(prompt).forEach((goal,index)=>plan.splice(1+index,0,{id:'prompt-subgoal-'+index,key:'prompt-subgoal-'+index,label:goal,status:'pending',detail:'Prompt-derived objective: '+goal,meta:'goal'}));return currentProgressTrimGoals(plan)}
