function renderCurrentProgressList(container,items,kind){if(!container)return;container.textContent='';const list=(items||[]).slice(0,kind==='plan'?12:12);if(!list.length){const empty=document.createElement('div');empty.className='current-progress-item';empty.innerHTML='<span class="progress-status-dot done" aria-hidden="true"></span><span class="current-progress-copy"><span>None yet</span></span><small></small>';container.appendChild(empty);return}list.forEach((item,index)=>{const row=document.createElement('div');row.className='current-progress-item';const dot=document.createElement('span');dot.className='progress-status-dot '+progressStatusDotClass(item.status);dot.setAttribute('aria-hidden','true');const copy=document.createElement('span');copy.className='current-progress-copy';const action=document.createElement(kind==='source'?'a':'button');if(kind==='source'&&item.url){action.href=item.url;action.target='_blank';action.rel='noopener noreferrer'}else action.type='button';action.textContent=item.label||item.url||item.name||'item';action.title=item.detail||item.url||item.path||action.textContent;if(kind==='output')action.addEventListener('click',event=>{event.preventDefault();openAutoPreviewArtifact(item.entry||item)});if(kind==='source')action.addEventListener('click',event=>{if(item.url){event.preventDefault();openAutoBrowserUrl(item.url,item.label||'Source')}});copy.appendChild(action);const detail=String(item.detail||'').trim();if(detail&&detail!==action.textContent){const smallDetail=document.createElement('span');smallDetail.className='current-progress-detail';smallDetail.textContent=truncateInsightText(detail,160);copy.appendChild(smallDetail)}const meta=document.createElement('small');meta.textContent=item.meta||item.status||'';row.append(dot,copy,meta);container.appendChild(row)})}
