setPx('--auto-star-y',parallax.y*.44);
setPx('--auto-bg-x',parallax.x*.12);
setPx('--auto-bg-y',parallax.y*.10);
setPx('--auto-glass-x',parallax.x*.08);
setPx('--auto-glass-y',parallax.y*.07);
