const x=star.x+parallax.x*star.z;
const y=star.y+parallax.y*star.z;
const pulse=reduced ? .5 :(Math.sin(star.twinkle+time*.0004)+1)*.5;
const alpha=Math.max(.28,Math.min(.98,.38+pulse*.36+star.z*.36+(loading ? .08 : 0)));
const radius=star.r*star.z*(loading?1.18:1.12);
ctx.beginPath();
ctx.fillStyle=hsla(star.color,alpha,star.z*7);
ctx.arc(x,y,radius,0,Math.PI*2);
ctx.fill();
if(star.z>.90){
ctx.beginPath();
ctx.strokeStyle=hsla(star.color,.14+(loading ? .06 : 0),12);
ctx.lineWidth=.6;
ctx.moveTo(x-radius*3.2,y);
ctx.lineTo(x+radius*3.2,y);
ctx.moveTo(x,y-radius*3.2);
ctx.lineTo(x,y+radius*3.2);
ctx.stroke();
}
}
queueDraw(frameMs);
}
window.addEventListener('resize',resize,{passive:true});
window.addEventListener('pointermove',pointer,{passive:true});
resize();
queueDraw(0);
