    private void MapSecureAuthorityRoutes(MutableTcpServer websiteServer) {
        foreach (string method in new[] { "GET", "POST", "DELETE", "OPTIONS" }) {
            websiteServer.Map(method, "/SecureAuthority", (connection, request, cancellationToken) => HandleSecureAuthorityProxy(connection, request, cancellationToken));
            websiteServer.Map(method, "/SecureAuthority/", (connection, request, cancellationToken) => HandleSecureAuthorityProxy(connection, request, cancellationToken));
            websiteServer.Map(method, "/SecureAuthority/*", (connection, request, cancellationToken) => HandleSecureAuthorityProxy(connection, request, cancellationToken));
        }
    }

    private object HandleSecureAuthorityProxy(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        HttpContext context = request.Context ?? throw new InvalidOperationException("HTTP context is required.");
        if (!TryBuildSecureAuthorityTargetUri(request, out Uri? targetUri, out string error) || targetUri == null)
            return Json(request, new { ok = false, error }, 502, "Bad Gateway");

        try {
            bool isHealthRequest = IsSecureAuthorityHealthRequest(request);
            using var upstream = new HttpRequestMessage(new HttpMethod(request.Method ?? "GET"), targetUri);
            byte[] bodyBytes = request.BodyBytes ?? Array.Empty<byte>();
            if (bodyBytes.Length > 0 || RequestMethodAllowsBody(request.Method)) {
                upstream.Content = new ByteArrayContent(bodyBytes);
            }

            if (request.Headers != null) {
                foreach (KeyValuePair<string, string> header in request.Headers) {
                    if (ShouldSkipSecureAuthorityProxyHeader(header.Key))
                        continue;

                    if (upstream.Content != null && header.Key.StartsWith("Content-", StringComparison.OrdinalIgnoreCase))
                        upstream.Content.Headers.TryAddWithoutValidation(header.Key, header.Value);
                    else
                        upstream.Headers.TryAddWithoutValidation(header.Key, header.Value);
                }
            }

            string originalHost = request.Headers != null && request.Headers.TryGetValue("Host", out string? hostHeader)
                ? hostHeader
                : request.Host;
            if (!string.IsNullOrWhiteSpace(originalHost))
                upstream.Headers.TryAddWithoutValidation("X-Forwarded-Host", SanitizeForwardedHeaderValue(originalHost));
            try {
                upstream.Headers.TryAddWithoutValidation("X-Forwarded-For", connection?.EndPoint?.Address?.ToString() ?? "");
            } catch {
            }
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-Proto", context.Connection?.Parent?.Options?.UseSsl == true ? "https" : "http");
            upstream.Headers.TryAddWithoutValidation("X-Forwarded-Prefix", "/SecureAuthority");

            using HttpResponseMessage response = SecureAuthorityProxyHttpClient.Send(upstream, HttpCompletionOption.ResponseHeadersRead, cancellationToken);
            byte[] responseBytes = response.Content.ReadAsByteArrayAsync(cancellationToken).GetAwaiter().GetResult();
            context.StatusCodeNumber = (int)response.StatusCode;
            context.ReasonPhrase = response.ReasonPhrase ?? "";

            foreach (KeyValuePair<string, IEnumerable<string>> header in response.Headers) {
                if (!ShouldSkipSecureAuthorityProxyResponseHeader(header.Key))
                    context.Response.Headers[header.Key] = string.Join(", ", header.Value);
            }
            foreach (KeyValuePair<string, IEnumerable<string>> header in response.Content.Headers) {
                if (!ShouldSkipSecureAuthorityProxyResponseHeader(header.Key))
                    context.Response.Headers[header.Key] = string.Join(", ", header.Value);
            }

            context.Response.Headers["Cache-Control"] = "no-store";
            string? contentType = response.Content.Headers.ContentType?.ToString();
            if (string.IsNullOrWhiteSpace(contentType) &&
                context.Response.Headers.TryGetValue("Content-Type", out string? responseContentType))
                contentType = responseContentType;
            if (isHealthRequest) {
                if (response.IsSuccessStatusCode && responseBytes.Length > 0)
                    return Text(request, Encoding.UTF8.GetString(responseBytes), FirstNonEmpty(contentType, "text/plain; charset=utf-8"), (int)response.StatusCode, response.ReasonPhrase ?? "OK");

                return Json(request, new {
                    ok = false,
                    error = response.IsSuccessStatusCode
                        ? "SecureAuthority target returned an empty health body."
                        : "SecureAuthority target health check failed.",
                    statusCode = (int)response.StatusCode,
                    reason = response.ReasonPhrase ?? "",
                    target = targetUri.ToString()
                }, 502, "Bad Gateway");
            }

            if (response.IsSuccessStatusCode &&
                responseBytes.Length == 0 &&
                !string.Equals(request.Method, "OPTIONS", StringComparison.OrdinalIgnoreCase)) {
                return Json(request, new {
                    ok = false,
                    error = "SecureAuthority target returned an empty success response.",
                    statusCode = (int)response.StatusCode,
                    reason = response.ReasonPhrase ?? "",
                    target = targetUri.ToString()
                }, 502, "Bad Gateway");
            }

            return new FileResponse(responseBytes, string.IsNullOrWhiteSpace(contentType) ? "application/octet-stream" : contentType);
        } catch (Exception ex) when (ex is HttpRequestException || ex is IOException || ex is TaskCanceledException || ex is OperationCanceledException) {
            return Json(request, new {
                ok = false,
                error = "SecureAuthority target failed.",
                detail = ex.Message,
                target = _options.SecureAuthorityTargetUrl
            }, 502, "Bad Gateway");
        }
    }

    private bool TryBuildSecureAuthorityTargetUri(HttpRequest request, out Uri? targetUri, out string error) {
        targetUri = null;
        error = "";
        string baseUrl = FirstNonEmpty(_options.SecureAuthorityTargetUrl, "http://127.0.0.1:8500/");
        if (!Uri.TryCreate(EnsureTrailingSlash(baseUrl), UriKind.Absolute, out Uri? baseUri) ||
            (!baseUri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
             !baseUri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))) {
            error = "SecureAuthority target URL is invalid.";
            return false;
        }

        string path = request.Path ?? "";
        const string prefix = "/SecureAuthority";
        if (path.Equals(prefix, StringComparison.OrdinalIgnoreCase))
            path = "/";
        else if (path.StartsWith(prefix + "/", StringComparison.OrdinalIgnoreCase))
            path = path.Substring(prefix.Length);
        else
            path = "/";

        string relative = path.TrimStart('/');
        if (!string.IsNullOrWhiteSpace(request.QueryString))
            relative += (relative.Contains("?", StringComparison.Ordinal) ? "&" : "?") + request.QueryString;

        targetUri = new Uri(baseUri, relative);
        return true;
    }

    private static bool IsSecureAuthorityHealthRequest(HttpRequest request) {
        string path = (request.Path ?? "").TrimEnd('/');
        return path.Equals("/SecureAuthority/healthz", StringComparison.OrdinalIgnoreCase);
    }

    private static bool RequestMethodAllowsBody(string? method) {
        return string.Equals(method, "POST", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(method, "PUT", StringComparison.OrdinalIgnoreCase) ||
               string.Equals(method, "PATCH", StringComparison.OrdinalIgnoreCase);
    }

    private static bool ShouldSkipSecureAuthorityProxyHeader(string headerName) {
        if (string.IsNullOrWhiteSpace(headerName))
            return true;

        return headerName.Equals("Host", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Proxy-Connection", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Expect", StringComparison.OrdinalIgnoreCase);
    }

    private static bool ShouldSkipSecureAuthorityProxyResponseHeader(string headerName) {
        if (string.IsNullOrWhiteSpace(headerName))
            return true;

        return headerName.Equals("Connection", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Keep-Alive", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Proxy-Connection", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Transfer-Encoding", StringComparison.OrdinalIgnoreCase) ||
               headerName.Equals("Content-Length", StringComparison.OrdinalIgnoreCase);
    }

    private static string EnsureTrailingSlash(string value) {
        value = (value ?? "").Trim();
        return value.EndsWith("/", StringComparison.Ordinal) ? value : value + "/";
    }

    private static string SanitizeForwardedHeaderValue(string value) {
        return (value ?? "").Replace("\r", "", StringComparison.Ordinal).Replace("\n", "", StringComparison.Ordinal).Trim();
    }

    private void MapJackcastRoutes(MutableTcpServer jackcastServer) {
        string hostName = (_options.JackcastHostName ?? "").Trim();
        string targetUrl = (_options.JackcastTargetUrl ?? "").Trim();
        if (string.IsNullOrWhiteSpace(hostName) || string.IsNullOrWhiteSpace(targetUrl))
            return;

        jackcastServer.Map("GET", "/xdf", (connection, request, cancellationToken) => {
            return Html(request, BuildJackcastXdfHtml());
        });
        jackcastServer.Map("GET", "/XDF", (connection, request, cancellationToken) => {
            return Html(request, BuildJackcastXdfHtml());
        });

        MapDownloadRoutes(jackcastServer);
        MapJackLLMUpdateRoutes(jackcastServer);

        foreach (string proxyHost in GetJackcastProxyHostNames())
            jackcastServer.ProxyHost(proxyHost, targetUrl, preserveHostHeader: true);

        jackcastServer.Map("GET", "/healthz", (connection, request, cancellationToken) => {
            return Json(request, new {
                status = jackcastServer.IsListening ? "ok" : "stopped",
                service = "Jackcast Live Proxy",
                host = hostName,
                hosts = GetJackcastProxyHostNames().ToArray(),
                bindAddress = _options.JackcastBindAddress.ToString(),
                targetUrl,
                ssl = new {
                    enabled = _options.JackcastSslEnabled,
                    message = _jackcastSslError
                },
                checkedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            });
        });
    }

    private bool IsJackcastProxyHost(string hostName) {
        string normalized = NormalizeProxyHostName(hostName);
        if (string.IsNullOrWhiteSpace(normalized))
            return false;

        foreach (string proxyHost in GetJackcastProxyHostNames()) {
            if (string.Equals(normalized, NormalizeProxyHostName(proxyHost), StringComparison.OrdinalIgnoreCase))
                return true;
        }

        return false;
    }

    private IEnumerable<string> GetJackcastProxyHostNames() {
        var hosts = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        AddJackcastProxyHost(hosts, _options.JackcastHostName, addWwwAlias: true);

        foreach (string alias in (_options.JackcastHostAliases ?? "").Split(new[] { ',', ';' }, StringSplitOptions.RemoveEmptyEntries))
            AddJackcastProxyHost(hosts, alias, addWwwAlias: false);

        return hosts;
    }

    private static void AddJackcastProxyHost(HashSet<string> hosts, string value, bool addWwwAlias) {
        string host = NormalizeProxyHostName(value);
        if (string.IsNullOrWhiteSpace(host))
            return;

        hosts.Add(host);
        if (!addWwwAlias)
            return;

        string baseHost = host.StartsWith("www.", StringComparison.OrdinalIgnoreCase)
            ? host.Substring(4)
            : host;
        if (!string.IsNullOrWhiteSpace(baseHost)) {
            hosts.Add(baseHost);
            hosts.Add("www." + baseHost);
        }
    }

    private static string NormalizeProxyHostName(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "";

        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            value = uri.Host;
        else {
            int slash = value.IndexOf('/');
            if (slash >= 0)
                value = value.Substring(0, slash);
            int colon = value.LastIndexOf(':');
            if (colon > -1 && value.IndexOf(':') == colon)
                value = value.Substring(0, colon);
        }

        return value.Trim().Trim('.').ToLowerInvariant();
    }

