        websiteServer.Map("GET", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => HandleAutoPublishPreference(request, false));
        websiteServer.Map("POST", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => HandleAutoPublishPreference(request, true));
        websiteServer.Map("OPTIONS", "/api/lmvsproxy/auto-publish", (connection, request, cancellationToken) => NoContent(request));

        MapRuntimeReportRoutes(websiteServer);
        MapSocketJackAdminApiRoutes(websiteServer);
        MapVideoPresentationRoutes(websiteServer);

        websiteServer.Map("POST", "/api/lmvsproxy/servers", (connection, request, cancellationToken) => {
            try {
                if (string.IsNullOrWhiteSpace(request.Body))
                    return Json(request, new { error = "Request body is required." }, 400, "Bad Request");

                using JsonDocument document = JsonDocument.Parse(request.Body);
                string remoteIp = connection?.EndPoint?.Address?.ToString() ?? "";
                RegisteredServer registered = Register(document.RootElement, remoteIp, request);
                MasterListResponse response = BuildResponse();
                return Json(request, new {
                    registered,
                    response.UpdatedUtc,
                    response.PublicUrl,
                    response.Count,
                    response.Servers
                });
            } catch (JsonException ex) {
                return Json(request, new { error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
            } catch (InvalidOperationException ex) {
                return Json(request, new { error = "Registration rejected.", detail = ex.Message }, 400, "Bad Request");
            } catch (Exception ex) {
                return Json(request, new { error = "Registration failed.", detail = ex.Message }, 500, "Internal Server Error");
            }
        });

        websiteServer.Map("DELETE", "/api/lmvsproxy/servers/*", (connection, request, cancellationToken) => {
            string id = request.PathVariables.Count > 0 ? request.PathVariables[0] : "";
            if (string.IsNullOrWhiteSpace(id)) {
                request.QueryParameters.TryGetValue("id", out string? queryId);
                id = queryId ?? "";
            }
            if (string.IsNullOrWhiteSpace(id))
                return Json(request, new { error = "Server id is required." }, 400, "Bad Request");

            string remoteIp = connection?.EndPoint?.Address?.ToString() ?? "";
            return Remove(id, request, remoteIp, out string error)
                ? NoContent(request)
                : Json(request, new { error = error }, error.IndexOf("owner", StringComparison.OrdinalIgnoreCase) >= 0 ? 403 : 404, error.IndexOf("owner", StringComparison.OrdinalIgnoreCase) >= 0 ? "Forbidden" : "Not Found");
        });

        websiteServer.Map("GET", "/api/shell/instances", (connection, request, cancellationToken) => {
