            try {
                if (string.IsNullOrWhiteSpace(request.Body))
                    return Json(request, new { error = "Request body is required." }, 400, "Bad Request");

                using JsonDocument document = JsonDocument.Parse(request.Body);
                MasterShellRelay relay = MasterShellRelay.FromJson(document.RootElement);
                MasterShellRelay saved = UpsertShellRelay(relay);
                return Json(request, new { instance = saved, instances = GetShellRelays() });
            } catch (JsonException ex) {
                return Json(request, new { error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
            } catch (InvalidOperationException ex) {
                return Json(request, new { error = "Shell relay rejected.", detail = ex.Message }, 400, "Bad Request");
            } catch (Exception ex) {
                return Json(request, new { error = "Shell relay update failed.", detail = ex.Message }, 500, "Internal Server Error");
            }
        });

        websiteServer.Map("POST", "/api/shell/proxies", (connection, request, cancellationToken) => HandleShellProxyRequest(connection, request));

        websiteServer.Map("OPTIONS", "/api/lmvsproxy/servers", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/jackllm/servers", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/socketjack/servers", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/socketjack-com/servers", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/socketjack/ai-servers", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/lmvsproxy/pricing", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/socketjack/pricing", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/shell/instances", (connection, request, cancellationToken) => NoContent(request));
        websiteServer.Map("OPTIONS", "/api/shell/proxies", (connection, request, cancellationToken) => NoContent(request));
    }

    private void MapVideoPresentationRoutes(MutableTcpServer server) {
        foreach (string path in new[] { "/api/socketjack/video/presentation", "/api/socketjack/ffmpeg/video/presentation" }) {
            server.Map("POST", path, (connection, request, cancellationToken) => HandleVideoPresentationConversion(connection, request, cancellationToken));
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }
    }

    private string HandleVideoPresentationConversion(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        try {
            if (string.IsNullOrWhiteSpace(request.Body))
                return Json(request, new { ok = false, error = "Request body is required." }, 400, "Bad Request");

            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            if (!TryAuthorizeRegisteredShellVideoPresentationRequest(connection, request, root, out RegisteredServer? server, out MasterShellRelay? relay, out string authError))
                return Json(request, new { ok = false, error = authError }, 403, "Forbidden");
            RegisteredServer authorizedServer = server!;
            MasterShellRelay authorizedRelay = relay!;

            if (!TryReadVideoPresentationInput(root, out byte[] sourceBytes, out string sourceFileName, out string sourceMediaType, out string inputError))
                return Json(request, new { ok = false, error = inputError }, 400, "Bad Request");

            string ffmpegPath = ResolveVideoPresentationFfmpegPath();
            if (string.IsNullOrWhiteSpace(ffmpegPath))
                return Json(request, new { ok = false, error = "FFmpeg was not found. Set SOCKETJACK_FFMPEG, FFMPEG_PATH, or install C:\\FFMPEG\\ffmpeg.exe." }, 503, "Service Unavailable");

            VideoPresentationApiConversionResult converted = ConvertVideoForPresentation(ffmpegPath, sourceBytes, sourceFileName, cancellationToken);
            if (!converted.Ok)
                return Json(request, new { ok = false, error = converted.Error }, 500, "Internal Server Error");

            string remoteIp = ExtractClientIp(connection, request);
            AppendMasterLog(
                "info",
                "video-presentation",
                "Converted video for presentation.",
                authorizedRelay.Id,
                authorizedServer.OwnerUserName,
                remoteIp,
                request.Path);

            return Json(request, new {
                ok = true,
                serverId = authorizedServer.Id,
                relayId = authorizedRelay.Id,
                proxyPath = authorizedRelay.ProxyPath,
                sourceMediaType,
                mediaType = "video/mp4",
                encoding = "ffmpeg:h264+aac:yuv420p:faststart",
                fileName = converted.FileName,
                lengthBytes = converted.Bytes.Length,
                dataUrl = "data:video/mp4;base64," + Convert.ToBase64String(converted.Bytes)
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (OperationCanceledException) {
            return Json(request, new { ok = false, error = "Video presentation conversion was canceled." }, 499, "Client Closed Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Video presentation conversion failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleAutoVideoPresentationConversion(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        try {
            AccountRecord? account = AuthenticateRequest(request, out string authError);
            if (account == null)
                TryAutoAuthenticateKnownIp(connection, request, out account, out _);
            if (account == null) {
                return Json(request, new {
                    ok = false,
                    code = "auto_login_required",
                    error = string.IsNullOrWhiteSpace(authError) || authError.Contains("expired", StringComparison.OrdinalIgnoreCase)
                        ? "SocketJack.com login is required for Auto video presentation conversion."
                        : authError,
                    authenticated = false,
                    username = ""
                }, 401, "Unauthorized");
            }

            if (string.IsNullOrWhiteSpace(request.Body))
                return Json(request, new { ok = false, error = "Request body is required." }, 400, "Bad Request");

            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            if (!TryReadVideoPresentationInput(root, out byte[] sourceBytes, out string sourceFileName, out string sourceMediaType, out string inputError))
                return Json(request, new { ok = false, error = inputError }, 400, "Bad Request");

            string ffmpegPath = ResolveVideoPresentationFfmpegPath();
            if (string.IsNullOrWhiteSpace(ffmpegPath))
                return Json(request, new { ok = false, error = "FFmpeg was not found. Set SOCKETJACK_FFMPEG, FFMPEG_PATH, or install C:\\FFMPEG\\ffmpeg.exe." }, 503, "Service Unavailable");

            VideoPresentationApiConversionResult converted = ConvertVideoForPresentation(ffmpegPath, sourceBytes, sourceFileName, cancellationToken);
            if (!converted.Ok)
                return Json(request, new { ok = false, error = converted.Error }, 500, "Internal Server Error");

            string remoteIp = ExtractClientIp(connection, request);
            AppendMasterLog(
                "info",
                "auto-video-presentation",
                "Converted Auto video for browser presentation.",
                GetJsonString(root, "relayId"),
                account.UserName,
                remoteIp,
                request.Path);

            return Json(request, new {
                ok = true,
                authenticated = true,
                username = account.UserName,
                sourceMediaType,
                mediaType = "video/mp4",
                encoding = "ffmpeg:h264+aac:yuv420p:faststart",
                fileName = converted.FileName,
                lengthBytes = converted.Bytes.Length,
                dataUrl = "data:video/mp4;base64," + Convert.ToBase64String(converted.Bytes)
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (OperationCanceledException) {
            return Json(request, new { ok = false, error = "Auto video presentation conversion was canceled." }, 499, "Client Closed Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Auto video presentation conversion failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private bool TryAuthorizeRegisteredShellVideoPresentationRequest(
        NetworkConnection connection,
        HttpRequest request,
        JsonElement root,
        out RegisteredServer? selectedServer,
        out MasterShellRelay? selectedRelay,
        out string error) {
        selectedServer = null;
        selectedRelay = null;
        error = "";

        string relayId = FirstNonEmpty(
            GetJsonString(root, "relayId"),
            GetJsonString(root, "shellRelayId"),
            GetQueryValue(request, "relayId"),
            GetQueryValue(request, "shellRelayId"),
            GetRequestHeaderValue(request, "X-SocketJack-Shell-Relay"));
        string serverId = FirstNonEmpty(
            GetJsonString(root, "serverId"),
            GetJsonString(root, "id"),
            GetQueryValue(request, "serverId"),
            GetRequestHeaderValue(request, "X-SocketJack-Server-Id"));
        string routeName = NormalizeShellRelayRouteLookup(FirstNonEmpty(
            GetJsonString(root, "routeName"),
            GetJsonString(root, "proxyRoute"),
            GetJsonString(root, "serverName"),
            GetQueryValue(request, "routeName"),
            GetQueryValue(request, "proxyRoute"),
            GetRequestHeaderValue(request, "X-SocketJack-Shell-Route")));
        string remoteIp = ExtractClientIp(connection, request);
        AccountRecord? account = AuthenticateRequest(request, out _);
        string ownerKey = account == null ? "" : BuildOwnerKey(account.UserName);
        string ownerTokenHash = HashOwnerToken(ExtractOwnerTokenFromRequest(request));
        bool hasIdentifier = !string.IsNullOrWhiteSpace(relayId) ||
                             !string.IsNullOrWhiteSpace(serverId) ||
                             !string.IsNullOrWhiteSpace(routeName);

        lock (_sync) {
            var matches = new List<(MasterShellRelay Relay, RegisteredServer Server)>();
            foreach (MasterShellRelay relay in _shellRelays.Values) {
                if (!ShellRelayMatchesVideoPresentationRequest(relay, relayId, serverId, routeName, hasIdentifier))
                    continue;
                if (string.IsNullOrWhiteSpace(relay.ServerId))
                    continue;
                int index = FindRowIndexLocked(relay.ServerId);
                if (index < 0)
                    continue;
                RegisteredServer server = RowToServer(_table.Rows[index]);
                if (!IsServerOwnerAuthorized(server, request, remoteIp, ownerKey, ownerTokenHash))
                    continue;
                if (!relay.Enabled)
                    continue;

                matches.Add((relay.Clone(), server.Clone()));
            }

            if (matches.Count == 1) {
                selectedRelay = matches[0].Relay;
                selectedServer = matches[0].Server;
                return true;
            }

            if (matches.Count > 1) {
                error = "Multiple registered shell servers matched. Include relayId, shellRelayId, routeName, or serverId.";
                return false;
            }
        }

        error = hasIdentifier
            ? "No authorized registered shell server matched the request."
            : "A registered shell server identity is required. Include relayId, shellRelayId, routeName, or serverId.";
        return false;
    }

    private static bool ShellRelayMatchesVideoPresentationRequest(MasterShellRelay relay, string relayId, string serverId, string routeName, bool hasIdentifier) {
        if (relay == null)
            return false;
        if (!hasIdentifier)
            return true;
        if (!string.IsNullOrWhiteSpace(relayId) && string.Equals(relay.Id, relayId, StringComparison.OrdinalIgnoreCase))
            return true;
        if (!string.IsNullOrWhiteSpace(serverId) && string.Equals(relay.ServerId, serverId, StringComparison.OrdinalIgnoreCase))
            return true;
        if (!string.IsNullOrWhiteSpace(routeName) &&
            (string.Equals(NormalizeShellRelayRouteLookup(relay.RouteName), routeName, StringComparison.OrdinalIgnoreCase) ||
             string.Equals(NormalizeShellRelayRouteLookup(relay.ProxyPath), routeName, StringComparison.OrdinalIgnoreCase) ||
             string.Equals(NormalizeShellRelayRouteLookup(relay.Name), routeName, StringComparison.OrdinalIgnoreCase)))
            return true;
        return false;
    }

    private static string NormalizeShellRelayRouteLookup(string value) {
        value = (value ?? "").Trim();
        if (string.IsNullOrWhiteSpace(value))
            return "";
        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            value = uri.AbsolutePath;
        value = value.Trim().Trim('/');
        if (value.StartsWith("proxy/", StringComparison.OrdinalIgnoreCase))
            value = value.Substring("proxy/".Length);
        return Uri.UnescapeDataString(value).Trim().ToLowerInvariant();
    }

    private static bool TryReadVideoPresentationInput(JsonElement root, out byte[] bytes, out string fileName, out string mediaType, out string error) {
        bytes = Array.Empty<byte>();
        fileName = "";
        mediaType = "";
        error = "";
        string dataUrl = FirstNonEmpty(
            GetJsonString(root, "dataUrl"),
            GetJsonString(root, "videoDataUrl"),
            GetJsonString(root, "contentDataUrl"));
        string base64 = FirstNonEmpty(
            GetJsonString(root, "contentBase64"),
            GetJsonString(root, "videoBase64"),
            GetJsonString(root, "base64"));

        if (!string.IsNullOrWhiteSpace(dataUrl)) {
            if (!TryExtractDataUrlPayload(dataUrl, out base64, out mediaType, out error))
                return false;
        }

        if (string.IsNullOrWhiteSpace(base64)) {
            error = "A video dataUrl, videoDataUrl, contentBase64, videoBase64, or base64 value is required.";
            return false;
        }

        try {
            bytes = Convert.FromBase64String(base64.Trim());
        } catch (FormatException ex) {
            error = "Video content is not valid base64: " + ex.Message;
            return false;
        }

        if (bytes.Length == 0) {
            error = "Video content is empty.";
            return false;
        }
        if (bytes.Length > 134217728) {
            error = "Video content is too large to convert through the presentation API.";
            return false;
        }

        fileName = SanitizeVideoPresentationFileName(FirstNonEmpty(
            GetJsonString(root, "fileName"),
            GetJsonString(root, "filename"),
            GetJsonString(root, "name"),
            "video"));
        if (string.IsNullOrWhiteSpace(Path.GetExtension(fileName)))
            fileName += GuessVideoPresentationExtension(mediaType);
        return true;
    }

    private static bool TryExtractDataUrlPayload(string dataUrl, out string base64, out string mediaType, out string error) {
        base64 = "";
        mediaType = "";
        error = "";
        dataUrl = (dataUrl ?? "").Trim();
        if (!dataUrl.StartsWith("data:", StringComparison.OrdinalIgnoreCase)) {
            error = "dataUrl must start with data:.";
            return false;
        }
        int comma = dataUrl.IndexOf(',');
        if (comma < 0) {
            error = "dataUrl is missing its base64 payload.";
            return false;
        }
        string header = dataUrl.Substring(5, comma - 5);
        if (!header.Contains(";base64", StringComparison.OrdinalIgnoreCase)) {
            error = "dataUrl must be base64 encoded.";
            return false;
        }
        int semicolon = header.IndexOf(';');
        mediaType = semicolon > 0 ? header.Substring(0, semicolon).Trim() : header.Trim();
        base64 = dataUrl.Substring(comma + 1).Trim();
        return true;
    }

    private static string GuessVideoPresentationExtension(string mediaType) {
        mediaType = (mediaType ?? "").Trim().ToLowerInvariant();
        return mediaType switch {
            "video/webm" => ".webm",
            "video/quicktime" => ".mov",
            "video/ogg" => ".ogv",
            "image/gif" => ".gif",
            _ => ".mp4"
        };
    }

    private static string SanitizeVideoPresentationFileName(string value) {
        value = Path.GetFileName((value ?? "").Trim());
        if (string.IsNullOrWhiteSpace(value))
            value = "video";
        char[] invalid = Path.GetInvalidFileNameChars();
        var builder = new StringBuilder(value.Length);
        foreach (char c in value) {
            builder.Append(invalid.Contains(c) || char.IsControl(c) ? '_' : c);
        }
        string safe = builder.ToString().Trim().Trim('.');
        return string.IsNullOrWhiteSpace(safe) ? "video" : safe;
    }

    private static string ResolveVideoPresentationFfmpegPath() {
        foreach (string? candidate in new string?[] {
            Environment.GetEnvironmentVariable("SOCKETJACK_FFMPEG"),
            Environment.GetEnvironmentVariable("JACKONNX_FFMPEG"),
            Environment.GetEnvironmentVariable("FFMPEG_PATH"),
            Environment.GetEnvironmentVariable("FFMPEG"),
            OperatingSystem.IsWindows() ? @"C:\FFMPEG\ffmpeg.exe" : "",
            OperatingSystem.IsWindows() ? @"C:\FFMPEG\FFMPEG.exe" : "",
            "ffmpeg"
        }) {
            string value = (candidate ?? "").Trim().Trim('"');
            if (string.IsNullOrWhiteSpace(value))
                continue;
            if (Path.IsPathRooted(value) && File.Exists(value))
                return value;
            if (!Path.IsPathRooted(value)) {
                string resolved = ResolveExecutableOnPath(value);
                if (!string.IsNullOrWhiteSpace(resolved))
                    return resolved;
            }
        }

        return "";
    }

    private static string ResolveExecutableOnPath(string fileName) {
        fileName = (fileName ?? "").Trim().Trim('"');
        if (string.IsNullOrWhiteSpace(fileName))
            return "";
        string pathValue = Environment.GetEnvironmentVariable("PATH") ?? "";
        if (string.IsNullOrWhiteSpace(pathValue))
            return "";

        string[] names = Path.HasExtension(fileName) || !OperatingSystem.IsWindows()
            ? new[] { fileName }
            : new[] { fileName, fileName + ".exe" };
        foreach (string directory in pathValue.Split(Path.PathSeparator)) {
            string folder = (directory ?? "").Trim().Trim('"');
            if (string.IsNullOrWhiteSpace(folder))
                continue;
            foreach (string name in names) {
                try {
                    string candidate = Path.Combine(folder, name);
                    if (File.Exists(candidate))
                        return candidate;
                } catch {
                }
            }
        }

        return "";
    }

    private static VideoPresentationApiConversionResult ConvertVideoForPresentation(string ffmpegPath, byte[] sourceBytes, string sourceFileName, CancellationToken cancellationToken) {
        string root = Path.Combine(Path.GetTempPath(), "socketjack-video-presentation", Guid.NewGuid().ToString("N"));
        try {
            Directory.CreateDirectory(root);
            sourceFileName = SanitizeVideoPresentationFileName(sourceFileName);
            if (string.IsNullOrWhiteSpace(Path.GetExtension(sourceFileName)))
                sourceFileName += ".mp4";
            string inputPath = Path.Combine(root, sourceFileName);
            string outputName = Path.GetFileNameWithoutExtension(sourceFileName) + ".presentation.mp4";
            string outputPath = Path.Combine(root, outputName);
            File.WriteAllBytes(inputPath, sourceBytes);

            var startInfo = new ProcessStartInfo {
                FileName = ffmpegPath,
                UseShellExecute = false,
                CreateNoWindow = true,
                RedirectStandardError = true,
                RedirectStandardOutput = true
            };
            startInfo.ArgumentList.Add("-y");
            startInfo.ArgumentList.Add("-hide_banner");
            startInfo.ArgumentList.Add("-loglevel");
            startInfo.ArgumentList.Add("error");
            startInfo.ArgumentList.Add("-i");
            startInfo.ArgumentList.Add(inputPath);
            startInfo.ArgumentList.Add("-map");
            startInfo.ArgumentList.Add("0:v:0");
            startInfo.ArgumentList.Add("-map");
            startInfo.ArgumentList.Add("0:a?");
            startInfo.ArgumentList.Add("-vf");
            startInfo.ArgumentList.Add("scale=trunc(iw/2)*2:trunc(ih/2)*2");
            startInfo.ArgumentList.Add("-c:v");
            startInfo.ArgumentList.Add("libx264");
            startInfo.ArgumentList.Add("-pix_fmt");
            startInfo.ArgumentList.Add("yuv420p");
            startInfo.ArgumentList.Add("-preset");
            startInfo.ArgumentList.Add("veryfast");
            startInfo.ArgumentList.Add("-movflags");
            startInfo.ArgumentList.Add("+faststart");
            startInfo.ArgumentList.Add("-c:a");
            startInfo.ArgumentList.Add("aac");
            startInfo.ArgumentList.Add("-b:a");
            startInfo.ArgumentList.Add("128k");
            startInfo.ArgumentList.Add(outputPath);

            using Process process = new Process { StartInfo = startInfo };
            process.Start();
            Task<string> stdoutTask = process.StandardOutput.ReadToEndAsync();
            Task<string> stderrTask = process.StandardError.ReadToEndAsync();
            Stopwatch stopwatch = Stopwatch.StartNew();
            while (!process.WaitForExit(250)) {
                if (cancellationToken.IsCancellationRequested) {
                    TryKillProcess(process);
                    cancellationToken.ThrowIfCancellationRequested();
                }
                if (stopwatch.Elapsed > TimeSpan.FromMinutes(15)) {
                    TryKillProcess(process);
                    return VideoPresentationApiConversionResult.Failed("FFmpeg timed out while converting the video.");
                }
            }

            string stderr = stderrTask.GetAwaiter().GetResult();
            string stdout = stdoutTask.GetAwaiter().GetResult();
            if (process.ExitCode != 0)
                return VideoPresentationApiConversionResult.Failed(FirstNonEmpty(stderr, stdout, "FFmpeg exited with code " + process.ExitCode.ToString(CultureInfo.InvariantCulture)));
            if (!File.Exists(outputPath))
                return VideoPresentationApiConversionResult.Failed("FFmpeg did not create an output video.");

            byte[] converted = File.ReadAllBytes(outputPath);
            if (converted.Length == 0)
                return VideoPresentationApiConversionResult.Failed("FFmpeg created an empty output video.");
            if (converted.Length > 134217728)
                return VideoPresentationApiConversionResult.Failed("Converted video is too large to return inline.");

            return VideoPresentationApiConversionResult.Success(converted, outputName);
        } catch (OperationCanceledException) {
            throw;
        } catch (Exception ex) {
            return VideoPresentationApiConversionResult.Failed(ex.Message);
        } finally {
            try {
                if (Directory.Exists(root))
                    Directory.Delete(root, recursive: true);
            } catch {
            }
        }
    }

    private static void TryKillProcess(Process process) {
        try {
            if (process != null && !process.HasExited)
                process.Kill(entireProcessTree: true);
        } catch {
        }
    }

    private static string GetRequestHeaderValue(HttpRequest request, string name) {
        if (request?.Headers == null || string.IsNullOrWhiteSpace(name))
            return "";
        if (request.Headers.TryGetValue(name, out string? value))
            return value ?? "";
        foreach (KeyValuePair<string, string> header in request.Headers) {
            if (string.Equals(header.Key, name, StringComparison.OrdinalIgnoreCase))
                return header.Value ?? "";
        }
        return "";
    }

    private sealed record VideoPresentationApiConversionResult(bool Ok, string Error, byte[] Bytes, string FileName) {
        public static VideoPresentationApiConversionResult Success(byte[] bytes, string fileName) => new(true, "", bytes, fileName);
        public static VideoPresentationApiConversionResult Failed(string error) => new(false, error, Array.Empty<byte>(), "");
    }

    private void MapServerLocationRoutes(MutableTcpServer server) {
