        server.Map("GET", "/api/socketjack/server-location", (connection, request, cancellationToken) => HandleServerLocationLookup(request));
        server.Map("OPTIONS", "/api/lmvsproxy/server-location", (connection, request, cancellationToken) => NoContent(request));
        server.Map("OPTIONS", "/api/jackllm/server-location", (connection, request, cancellationToken) => NoContent(request));
