    }

    private string HandleServerLocationLookup(HttpRequest request) {
        string target = FirstNonEmpty(
            GetQueryValue(request, "target"),
            GetQueryValue(request, "host"),
            GetQueryValue(request, "ip"));
        if (string.IsNullOrWhiteSpace(target))
            return Json(request, new { error = "A target, host, or ip query value is required." }, 400, "Bad Request");

        ServerLocationLookupResult location = LookupServerLocation(target);
        return Json(request, new { ok = true, location });
    }

    private void MapServerBackgroundRoutes(MutableTcpServer server) {
        foreach (string path in new[] {
                     "/api/lmvsproxy/server-background",
                     "/api/jackllm/server-background",
                     "/api/socketjack/server-background"
                 }) {
            server.Map("POST", path, (connection, request, cancellationToken) => HandleServerBackgroundUpload(connection, request));
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }

        foreach (string path in new[] {
                     "/api/lmvsproxy/server-background/*",
                     "/api/jackllm/server-background/*",
                     "/api/socketjack/server-background/*"
                 }) {
            server.Map("GET", path, (connection, request, cancellationToken) => HandleServerBackgroundImage(request));
            server.Map("HEAD", path, (connection, request, cancellationToken) => HandleServerBackgroundImage(request));
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }
    }

    private string HandleServerBackgroundUpload(NetworkConnection? connection, HttpRequest request) {
        AccountRecord? account = AuthenticateRequest(request, out string authError);
        if (account == null)
            return Json(request, new { ok = false, error = string.IsNullOrWhiteSpace(authError) ? "SocketJack.com login is required to update a server background." : authError }, 401, "Unauthorized");
        if (string.IsNullOrWhiteSpace(request.Body))
            return Json(request, new { ok = false, error = "Background upload body is required." }, 400, "Bad Request");

        try {
            using JsonDocument document = JsonDocument.Parse(request.Body);
            JsonElement root = document.RootElement;
            string serverId = FirstNonEmpty(
                GetJsonString(root, "serverId"),
                GetJsonString(root, "server_id"),
                GetJsonString(root, "id"),
                GetQueryValue(request, "serverId"),
                GetQueryValue(request, "id"));
            if (string.IsNullOrWhiteSpace(serverId))
                return Json(request, new { ok = false, error = "Server id is required." }, 400, "Bad Request");

            string mediaType = FirstNonEmpty(GetJsonString(root, "mimeType"), GetJsonString(root, "mediaType"), "image/jpeg");
            string base64 = FirstNonEmpty(GetJsonString(root, "base64"), GetJsonString(root, "contentBase64"));
            string dataUrl = FirstNonEmpty(GetJsonString(root, "dataUrl"), GetJsonString(root, "contentDataUrl"));
            if (!string.IsNullOrWhiteSpace(dataUrl) &&
                !TryExtractDataUrlPayload(dataUrl, out base64, out mediaType, out string dataUrlError))
                return Json(request, new { ok = false, error = dataUrlError }, 400, "Bad Request");
            if (string.IsNullOrWhiteSpace(base64))
                return Json(request, new { ok = false, error = "A compressed JPG dataUrl or base64 payload is required." }, 400, "Bad Request");

            byte[] bytes;
            try {
                bytes = Convert.FromBase64String(base64.Trim());
            } catch (FormatException ex) {
                return Json(request, new { ok = false, error = "Background image is not valid base64.", detail = ex.Message }, 400, "Bad Request");
            }
            if (bytes.Length == 0)
                return Json(request, new { ok = false, error = "Background image is empty." }, 400, "Bad Request");
            if (bytes.Length > 8_388_608)
                return Json(request, new { ok = false, error = "Background image is too large after JPG compression. Limit: 8 MB." }, 413, "Payload Too Large");
            if (!LooksLikeJpeg(bytes))
                return Json(request, new { ok = false, error = "Background images must be compressed to JPG before upload." }, 400, "Bad Request");

            string remoteIp = ExtractClientIp(connection, request);
            string ownerKey = BuildOwnerKey(account.UserName);
            string ownerTokenHash = HashOwnerToken(ExtractOwnerTokenFromRequest(request));
            double offsetX = ClampBackgroundOffset(GetJsonDouble(root, "offsetX", GetJsonDouble(root, "backgroundOffsetX", 0)));
            double offsetY = ClampBackgroundOffset(GetJsonDouble(root, "offsetY", GetJsonDouble(root, "backgroundOffsetY", 0)));
            double scale = ClampBackgroundScale(GetJsonDouble(root, "scale", GetJsonDouble(root, "backgroundScale", 1)));

            RegisteredServer saved;
            lock (_sync) {
                int index = FindRowIndexLocked(serverId);
                if (index < 0)
                    return Json(request, new { ok = false, error = "Server was not found." }, 404, "Not Found");

                RegisteredServer server = RowToServer(_table.Rows[index]);
                if (!IsServerOwnerAuthorized(server, request, remoteIp, ownerKey, ownerTokenHash))
                    return Json(request, new { ok = false, error = "Only the owner of this server can update its background." }, 403, "Forbidden");

                string key = BuildServerBackgroundKey(server, bytes);
                string directory = ServerBackgroundsRootDirectory();
                Directory.CreateDirectory(directory);
                string path = Path.Combine(directory, key + ".jpg");
                if (!TryResolveServerBackgroundPath(directory, path, out string resolvedPath))
                    return Json(request, new { ok = false, error = "Background storage path was rejected." }, 400, "Bad Request");
                File.WriteAllBytes(resolvedPath, bytes);

                server.BackgroundImageKey = key;
                server.BackgroundImageUrl = BuildServerBackgroundImageUrl(server);
                server.BackgroundOffsetX = offsetX;
                server.BackgroundOffsetY = offsetY;
                server.BackgroundScale = scale;
                server.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                server.Normalize();
                _table.Rows[index] = ServerToRow(server);
                _dataServer.Save();
                saved = server.Clone();
            }

            NotifyServersChanged();
            StatusChanged?.Invoke(this, EventArgs.Empty);
            return Json(request, new {
                ok = true,
                serverId = saved.Id,
                backgroundImageUrl = BuildServerBackgroundImageUrl(saved),
                backgroundOffsetX = saved.BackgroundOffsetX,
                backgroundOffsetY = saved.BackgroundOffsetY,
                backgroundScale = saved.BackgroundScale,
                sizeBytes = bytes.Length,
                mediaType = "image/jpeg"
            });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid background upload JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Background upload failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private object HandleServerBackgroundImage(HttpRequest request) {
        string rawKey = request.PathVariables.Count > 0 ? request.PathVariables[0] : "";
        if (string.IsNullOrWhiteSpace(rawKey))
            rawKey = GetQueryValue(request, "key");
        string key = NormalizeServerBackgroundKey(Path.GetFileNameWithoutExtension(rawKey));
        if (string.IsNullOrWhiteSpace(key))
            return Text(request, "Background image key is required.", "text/plain; charset=utf-8", 400, "Bad Request");

        string directory = ServerBackgroundsRootDirectory();
        string path = Path.Combine(directory, key + ".jpg");
        if (!TryResolveServerBackgroundPath(directory, path, out string resolvedPath) || !File.Exists(resolvedPath))
            return Text(request, "Background image not found.", "text/plain; charset=utf-8", 404, "Not Found");

        request.Context.Response.Headers["Cache-Control"] = "public, max-age=86400";
        AddCors(request);
        byte[] bytes = string.Equals(request.Method, "HEAD", StringComparison.OrdinalIgnoreCase)
            ? Array.Empty<byte>()
            : File.ReadAllBytes(resolvedPath);
        return new FileResponse(bytes, "image/jpeg", key + ".jpg");
    }

    private string ServerBackgroundsRootDirectory() {
        string dataPath = _options.ResolveDataFilePath();
        string directory = Path.GetDirectoryName(dataPath) ?? AppContext.BaseDirectory;
        return Path.Combine(directory, "ServerBackgrounds");
    }

    private static bool LooksLikeJpeg(byte[] bytes) {
        return bytes.Length >= 4 &&
               bytes[0] == 0xFF &&
               bytes[1] == 0xD8 &&
               bytes[^2] == 0xFF &&
               bytes[^1] == 0xD9;
    }

    private static string BuildServerBackgroundKey(RegisteredServer server, byte[] bytes) {
        string id = NormalizeIdentifierText(FirstNonEmpty(server.Id, server.TitleText, "server"), "server");
        byte[] hash = SHA256.HashData(bytes);
        return NormalizeServerBackgroundKey(id + "-" + Convert.ToHexString(hash, 0, 8).ToLowerInvariant());
    }

    private static string NormalizeServerBackgroundKey(string value) {
        value = (value ?? "").Trim();
        if (value.EndsWith(".jpg", StringComparison.OrdinalIgnoreCase) ||
            value.EndsWith(".jpeg", StringComparison.OrdinalIgnoreCase))
            value = Path.GetFileNameWithoutExtension(value);
        value = Regex.Replace(value, @"[^A-Za-z0-9_-]", "-").Trim('-');
        return value.Length <= 96 ? value : value.Substring(0, 96).Trim('-');
    }

    private static double GetJsonDouble(JsonElement element, string name, double fallback) {
        string text = GetJsonString(element, name);
        return double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out double value) &&
               !double.IsNaN(value) &&
               !double.IsInfinity(value)
            ? value
            : fallback;
    }

    private static double ClampBackgroundOffset(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            value = 0;
        return Math.Max(-100, Math.Min(100, value));
    }

    private static double ClampBackgroundScale(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            value = 1;
        return Math.Max(1, Math.Min(4, value));
    }

    private static bool TryResolveServerBackgroundPath(string root, string candidate, out string resolvedPath) {
        resolvedPath = "";
        try {
            string rootFull = Path.GetFullPath(root);
            string candidateFull = Path.GetFullPath(candidate);
            if (!candidateFull.StartsWith(rootFull.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar) + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase) &&
                !candidateFull.Equals(rootFull, StringComparison.OrdinalIgnoreCase))
                return false;
            resolvedPath = candidateFull;
            return true;
        } catch {
            return false;
        }
    }

    private ServerLocationLookupResult LookupServerLocation(string rawTarget) {
        if (!TryNormalizeLocationTarget(rawTarget, out string cacheKey, out string lookupIp, out string normalizedHost, out bool privateAddress, out string error)) {
            return new ServerLocationLookupResult {
                Found = false,
                Input = rawTarget ?? "",
                Target = normalizedHost,
                Ip = lookupIp,
                PrivateAddress = privateAddress,
                Source = "local",
                Error = error,
                UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            };
        }

        DateTimeOffset now = DateTimeOffset.UtcNow;
        lock (_locationLookupLock) {
            if (_locationCache.TryGetValue(cacheKey, out ServerLocationLookupCacheEntry? cached) &&
                cached.ExpiresUtc > now &&
                cached.Result != null) {
                ServerLocationLookupResult cachedResult = cached.Result.Clone();
                cachedResult.Cached = true;
                return cachedResult;
            }

            TimeSpan wait = TimeSpan.FromMilliseconds(1100) - (now - _lastLocationLookupUtc);
            if (wait > TimeSpan.Zero)
                Thread.Sleep(wait);

            ServerLocationLookupResult result = QueryServerLocationApi(rawTarget, normalizedHost, lookupIp);
            _lastLocationLookupUtc = DateTimeOffset.UtcNow;
            _locationCache[cacheKey] = new ServerLocationLookupCacheEntry {
                ExpiresUtc = result.Found ? _lastLocationLookupUtc.AddHours(12) : _lastLocationLookupUtc.AddMinutes(15),
                Result = result.Clone()
            };
            return result;
        }
    }

    private ServerLocationLookupResult QueryServerLocationApi(string rawTarget, string normalizedHost, string lookupIp) {
        var result = new ServerLocationLookupResult {
            Found = false,
            Input = rawTarget ?? "",
            Target = normalizedHost,
            Ip = lookupIp,
            Source = "ipwho.is",
            UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
        };

        try {
            using var request = new HttpRequestMessage(HttpMethod.Get, "https://ipwho.is/" + Uri.EscapeDataString(lookupIp));
            request.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-MagicMasterList/1.0");
            using HttpResponseMessage response = _locationHttpClient.Send(request);
            string body = response.Content.ReadAsStringAsync().GetAwaiter().GetResult();
            if (!response.IsSuccessStatusCode || string.IsNullOrWhiteSpace(body)) {
                result.Error = "The location API did not return a usable response.";
                return result;
            }

            using JsonDocument document = JsonDocument.Parse(body);
            JsonElement root = document.RootElement;
            bool success = !root.TryGetProperty("success", out JsonElement successElement) ||
                           successElement.ValueKind == JsonValueKind.True ||
                           (successElement.ValueKind == JsonValueKind.String &&
                            string.Equals(successElement.GetString(), "true", StringComparison.OrdinalIgnoreCase));
            if (!success) {
                result.Error = RegisteredServer.FirstNonEmpty(
                    RegisteredServer.GetString(root, "message"),
                    RegisteredServer.GetString(root, "error"),
                    "The location API could not resolve this server.");
                return result;
            }

            string city = RegisteredServer.GetString(root, "city");
            string region = RegisteredServer.GetString(root, "region");
            string country = RegisteredServer.GetString(root, "country");
            string timezone = "";
            if (root.TryGetProperty("timezone", out JsonElement timezoneElement))
                timezone = timezoneElement.ValueKind == JsonValueKind.String ? timezoneElement.GetString() ?? "" : RegisteredServer.GetString(timezoneElement, "id");

            result.Found = true;
            result.Ip = RegisteredServer.FirstNonEmpty(RegisteredServer.GetString(root, "ip"), lookupIp);
            result.City = city;
            result.Region = region;
            result.Country = country;
            result.CountryCode = RegisteredServer.GetString(root, "country_code");
            result.Timezone = timezone;
            result.Label = BuildLocationLabel(city, region, country);
            if (root.TryGetProperty("connection", out JsonElement connection) && connection.ValueKind == JsonValueKind.Object)
                result.Isp = RegisteredServer.FirstNonEmpty(RegisteredServer.GetString(connection, "isp"), RegisteredServer.GetString(connection, "org"));
            if (root.TryGetProperty("latitude", out JsonElement latitude) && latitude.TryGetDouble(out double lat))
                result.Latitude = lat;
            if (root.TryGetProperty("longitude", out JsonElement longitude) && longitude.TryGetDouble(out double lon))
                result.Longitude = lon;
            return result;
        } catch (Exception ex) {
            result.Error = ex.Message;
            return result;
        }
    }

    private static string BuildLocationLabel(string city, string region, string country) {
        List<string> parts = new();
        foreach (string part in new[] { city, region, country }) {
            string clean = (part ?? "").Trim();
            if (clean.Length > 0 && !parts.Any(existing => string.Equals(existing, clean, StringComparison.OrdinalIgnoreCase)))
                parts.Add(clean);
        }
        return string.Join(", ", parts);
    }

    private static bool TryNormalizeLocationTarget(string rawTarget, out string cacheKey, out string lookupIp, out string normalizedHost, out bool privateAddress, out string error) {
        cacheKey = "";
        lookupIp = "";
        normalizedHost = ExtractLocationHost(rawTarget);
        privateAddress = false;
        error = "";

        if (string.IsNullOrWhiteSpace(normalizedHost)) {
            error = "The target does not contain a usable host.";
            return false;
        }
        if (normalizedHost.Equals("localhost", StringComparison.OrdinalIgnoreCase)) {
            privateAddress = true;
            error = "Localhost does not have a public location.";
            return false;
        }
        if (IPAddress.TryParse(normalizedHost, out IPAddress? address)) {
            lookupIp = address.ToString();
            if (IsPrivateOrReservedIpAddress(address)) {
                privateAddress = true;
                error = "Private or local addresses do not have a public location.";
                return false;
            }
            cacheKey = lookupIp;
            return true;
        }
        if (normalizedHost.Length > 253 || normalizedHost.Any(char.IsWhiteSpace)) {
            error = "The host name is not valid for location lookup.";
            return false;
        }

        try {
            IPAddress[] addresses = Dns.GetHostAddresses(normalizedHost);
            foreach (IPAddress candidate in addresses) {
                if (IsPrivateOrReservedIpAddress(candidate))
                    continue;
                lookupIp = candidate.ToString();
                cacheKey = normalizedHost.ToLowerInvariant() + "|" + lookupIp;
                return true;
            }
            privateAddress = addresses.Length > 0;
            error = privateAddress ? "The host resolves only to private or local addresses." : "The host did not resolve to an IP address.";
            return false;
        } catch (Exception ex) {
            error = "DNS resolution failed: " + ex.Message;
            return false;
        }
    }

    private static string ExtractLocationHost(string rawTarget) {
        string target = (rawTarget ?? "").Trim();
        if (string.IsNullOrWhiteSpace(target))
            return "";
        if (Uri.TryCreate(target, UriKind.Absolute, out Uri? uri) &&
            (uri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) ||
             uri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)))
            return (uri.Host ?? "").Trim().Trim('[', ']');

        int slashIndex = target.IndexOfAny(new[] { '/', '\\', '?', '#' });
        if (slashIndex >= 0)
            target = target[..slashIndex];
        int atIndex = target.LastIndexOf('@');
        if (atIndex >= 0)
            target = target[(atIndex + 1)..];
        if (target.StartsWith("[", StringComparison.Ordinal) && target.Contains(']')) {
            int end = target.IndexOf(']');
            return target.Substring(1, Math.Max(0, end - 1)).Trim();
        }
        int colonIndex = target.LastIndexOf(':');
        if (colonIndex > 0 && target.IndexOf(':') == colonIndex)
            target = target[..colonIndex];
        return target.Trim().Trim('[', ']');
    }

    private static bool IsPrivateOrReservedIpAddress(IPAddress address) {
        if (IPAddress.IsLoopback(address))
            return true;
        if (address.IsIPv4MappedToIPv6)
            address = address.MapToIPv4();
        if (address.AddressFamily == AddressFamily.InterNetwork) {
            byte[] bytes = address.GetAddressBytes();
            return bytes[0] == 0 ||
                   bytes[0] == 10 ||
                   bytes[0] == 127 ||
                   bytes[0] == 169 && bytes[1] == 254 ||
                   bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31 ||
                   bytes[0] == 192 && bytes[1] == 168 ||
                   bytes[0] == 198 && (bytes[1] == 18 || bytes[1] == 19) ||
                   bytes[0] == 100 && bytes[1] >= 64 && bytes[1] <= 127 ||
                   bytes[0] >= 224;
        }
        if (address.AddressFamily == AddressFamily.InterNetworkV6) {
            byte[] bytes = address.GetAddressBytes();
            return address.Equals(IPAddress.IPv6None) ||
                   address.Equals(IPAddress.IPv6Any) ||
                   address.IsIPv6LinkLocal ||
                   address.IsIPv6Multicast ||
                   address.IsIPv6SiteLocal ||
                   (bytes[0] & 0xfe) == 0xfc;
        }
        return true;
    }

