    private void MapJackLLMCompanionUpdateRoutes(MutableTcpServer server, string updateDirectory) {
        string companionDirectory = ResolveJackLLMCompanionUpdateDirectory(updateDirectory);
        foreach (string prefix in new[] {
            "/Update/jackllm-companion",
            "/update/jackllm-companion",
            "/Update/Companion",
            "/update/Companion"
        }) {
            string routePrefix = prefix;
            string publicBaseUrl = CombineUrl(GetJackLLMUpdatePublicBaseUrl(), routePrefix.TrimStart('/') + "/");

            server.Map("GET", routePrefix + "/meta", (connection, request, cancellationToken) => {
                request.Context.Response.Headers["Cache-Control"] = "no-store";
                return Json(request, DirectoryHashMetadata.BuildManifest(companionDirectory, publicBaseUrl));
            });
            server.Map("GET", routePrefix + "/manifest", (connection, request, cancellationToken) => {
                request.Context.Response.Headers["Cache-Control"] = "no-store";
                return Json(request, DirectoryHashMetadata.BuildManifest(companionDirectory, publicBaseUrl));
            });
            server.Map("GET", routePrefix + "/manifest.json", (connection, request, cancellationToken) => {
                request.Context.Response.Headers["Cache-Control"] = "no-store";
                return Json(request, DirectoryHashMetadata.BuildManifest(companionDirectory, publicBaseUrl));
            });
            server.Map("GET", routePrefix + "/*", (connection, request, cancellationToken) => {
                string relativePath = request.PathVariables.Count > 0 ? request.PathVariables[0] : "";
                if (TryResolveUpdatePath(companionDirectory, relativePath, out string fullPath) && File.Exists(fullPath))
                    return BuildJackLLMUpdateFileResponse(request, fullPath);
                return Text(request, "Companion update file not found.", "text/plain; charset=utf-8", 404, "Not Found");
            });

            server.Map("OPTIONS", routePrefix + "/meta", (connection, request, cancellationToken) => NoContent(request));
            server.Map("OPTIONS", routePrefix + "/manifest", (connection, request, cancellationToken) => NoContent(request));
            server.Map("OPTIONS", routePrefix + "/manifest.json", (connection, request, cancellationToken) => NoContent(request));
            server.Map("OPTIONS", routePrefix + "/*", (connection, request, cancellationToken) => NoContent(request));
        }
    }

    private static string ResolveJackLLMCompanionUpdateDirectory(string updateDirectory) {
        string companionDirectory = Path.Combine(updateDirectory, "Companion");
        if (Directory.Exists(companionDirectory))
            return companionDirectory;

        string channelDirectory = Path.Combine(updateDirectory, "jackllm-companion");
        return Directory.Exists(channelDirectory) ? channelDirectory : companionDirectory;
    }

    private string ResolveJackLLMUpdateDirectory() {
        string configured = _options.JackLLMUpdateDirectory;
        if (string.IsNullOrWhiteSpace(configured))
            configured = @"C:\JackLLM\Update";
        return Path.GetFullPath(configured);
    }

    private string BuildJackLLMUpdateDirectoryExplorer(string relativePath) {
        string root = ResolveJackLLMUpdateDirectory();
        if (!Directory.Exists(root)) {
            return BuildUpdateExplorerPage(
                "JackLLM Updates",
                "<p class=\"empty\">Update directory not found: " + HtmlEncode(root) + "</p>",
                "");
        }

        if (!TryResolveUpdatePath(root, relativePath, out string directoryPath) || !Directory.Exists(directoryPath)) {
            return BuildUpdateExplorerPage(
                "JackLLM Updates",
                "<p class=\"empty\">Folder not found.</p>",
                NormalizeUpdateRelativePath(relativePath));
        }

        string normalizedRelative = NormalizeUpdateRelativePath(Path.GetRelativePath(root, directoryPath));
        if (normalizedRelative == ".")
            normalizedRelative = "";

        var rows = new StringBuilder();
        if (!string.IsNullOrWhiteSpace(normalizedRelative)) {
            string parent = NormalizeUpdateRelativePath(Path.GetDirectoryName(normalizedRelative.Replace('/', Path.DirectorySeparatorChar)) ?? "");
            rows.Append("<tr><td><a class=\"dir\" href=\"")
                .Append(BuildUpdateExplorerHref(parent, true))
                .Append("\">[..]</a></td><td>Folder</td><td></td><td></td></tr>");
        }

        try {
            foreach (DirectoryInfo directory in new DirectoryInfo(directoryPath).EnumerateDirectories().OrderBy(item => item.Name, StringComparer.CurrentCultureIgnoreCase)) {
                string childRelative = CombineUpdateRelativePath(normalizedRelative, directory.Name);
                rows.Append("<tr><td><a class=\"dir\" href=\"")
                    .Append(BuildUpdateExplorerHref(childRelative, true))
                    .Append("\">")
                    .Append(HtmlEncode(directory.Name))
                    .Append("/</a></td><td>Folder</td><td></td><td>")
                    .Append(HtmlEncode(directory.LastWriteTime.ToString("g", CultureInfo.CurrentCulture)))
                    .Append("</td></tr>");
            }

            foreach (FileInfo file in new DirectoryInfo(directoryPath).EnumerateFiles().OrderBy(item => item.Name, StringComparer.CurrentCultureIgnoreCase)) {
                string childRelative = CombineUpdateRelativePath(normalizedRelative, file.Name);
                rows.Append("<tr><td><a href=\"")
                    .Append(BuildUpdateExplorerHref(childRelative, false))
                    .Append("\">")
                    .Append(HtmlEncode(file.Name))
                    .Append("</a></td><td>File</td><td>")
                    .Append(HtmlEncode(FormatUpdateFileSize(file.Length)))
                    .Append("</td><td>")
                    .Append(HtmlEncode(file.LastWriteTime.ToString("g", CultureInfo.CurrentCulture)))
                    .Append("</td></tr>");
            }
        } catch (Exception ex) {
            rows.Append("<tr><td colspan=\"4\" class=\"empty\">Unable to read folder: ")
                .Append(HtmlEncode(ex.Message))
                .Append("</td></tr>");
        }

        if (rows.Length == 0)
            rows.Append("<tr><td colspan=\"4\" class=\"empty\">This update folder is empty.</td></tr>");

        string body =
            "<table><thead><tr><th>Name</th><th>Type</th><th>Size</th><th>Modified</th></tr></thead><tbody>" +
            rows +
            "</tbody></table>";
        return BuildUpdateExplorerPage("JackLLM Updates", body, normalizedRelative);
    }

    private static string BuildUpdateExplorerPage(string title, string body, string relativePath) {
        string location = string.IsNullOrWhiteSpace(relativePath) ? "/update/" : "/update/" + HtmlEncode(relativePath.Trim('/')) + "/";
        string zipHref = BuildUpdateZipHref(relativePath);
        string folderName = string.IsNullOrWhiteSpace(relativePath) ? "Update" : Path.GetFileName(relativePath.TrimEnd('/'));
        string zipName = MakeUpdateZipFileName(folderName);
        return """
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>__TITLE__</title>
<style>
*{box-sizing:border-box}body{margin:0;background:#0d1117;color:#e8f0f8;font-family:"Segoe UI",system-ui,sans-serif;padding:32px}
main{max-width:1120px;margin:0 auto}.top{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;margin-bottom:22px}h1{font-size:24px;margin:0 0 6px}.path{color:#93a4b7}
table{width:100%;border-collapse:collapse;background:#121a24;border:1px solid #2b3a4d;border-radius:8px;overflow:hidden}
th,td{text-align:left;padding:10px 12px;border-bottom:1px solid #243244}th{color:#a9bed5;font-size:12px;text-transform:uppercase;letter-spacing:.04em;background:#172232}
a{color:#76d6ff;text-decoration:none}a:hover{text-decoration:underline}.dir{color:#6ff2a6}.empty{color:#ffcf8a;padding:18px}.zip{white-space:nowrap;background:#1f8a4e;color:white;border:1px solid #6ff2a6;border-radius:7px;padding:9px 13px;font-weight:700;box-shadow:0 0 18px rgba(111,242,166,.32)}.zip small{display:block;color:#d7ffe7;font-weight:500;margin-top:2px}
</style>
</head>
<body><main><div class="top"><div><h1>__TITLE__</h1><div class="path">__LOCATION__</div></div><a class="zip" href="__ZIP_HREF__">Download ZIP<small>__ZIP_NAME__</small></a></div>__BODY__</main></body>
</html>
""".Replace("__TITLE__", HtmlEncode(title))
            .Replace("__LOCATION__", location)
            .Replace("__ZIP_HREF__", zipHref)
            .Replace("__ZIP_NAME__", HtmlEncode(zipName))
            .Replace("__BODY__", body);
    }

    private FileResponse BuildJackLLMUpdateZipResponse(HttpRequest request, string relativePath) {
        string root = ResolveJackLLMUpdateDirectory();
        if (!TryResolveUpdatePath(root, relativePath, out string directoryPath) || !Directory.Exists(directoryPath)) {
            request.Context.StatusCodeNumber = 404;
            request.Context.ReasonPhrase = "Not Found";
            AddCors(request);
            request.Context.Response.ContentType = "text/plain";
            return new FileResponse(Encoding.UTF8.GetBytes("Folder not found."), "text/plain");
        }

        string folderName = string.Equals(Path.GetFullPath(directoryPath), Path.GetFullPath(root), StringComparison.OrdinalIgnoreCase)
            ? "Update"
            : new DirectoryInfo(directoryPath).Name;
        string zipFileName = MakeUpdateZipFileName(folderName);
        string tempPath = Path.Combine(Path.GetTempPath(), "JackLLMUpdate-" + Guid.NewGuid().ToString("N") + ".zip");
        try {
            ZipFile.CreateFromDirectory(directoryPath, tempPath, CompressionLevel.Fastest, includeBaseDirectory: true);
            byte[] bytes = File.ReadAllBytes(tempPath);
            AddCors(request);
            request.Context.Response.Headers["Content-Disposition"] = "attachment; filename=\"" + zipFileName.Replace("\"", "", StringComparison.Ordinal) + "\"";
            request.Context.Response.Headers["Cache-Control"] = "no-store";
            return new FileResponse(bytes, "application/zip");
        } catch (Exception ex) {
            request.Context.StatusCodeNumber = 500;
            request.Context.ReasonPhrase = "Internal Server Error";
            AddCors(request);
            request.Context.Response.ContentType = "text/plain";
            return new FileResponse(Encoding.UTF8.GetBytes("ZIP failed: " + ex.Message), "text/plain");
        } finally {
            try {
                if (File.Exists(tempPath))
                    File.Delete(tempPath);
            } catch {
            }
        }
    }

    private static FileResponse BuildJackLLMUpdateFileResponse(HttpRequest request, string filePath) {
        try {
            AddCors(request);
            request.Context.Response.Headers["Content-Disposition"] = "attachment; filename=\"" + Path.GetFileName(filePath).Replace("\"", "", StringComparison.Ordinal) + "\"";
            request.Context.Response.Headers["Cache-Control"] = "no-store";
            FileResponse response = FileResponse.FromFile(filePath);
            response.ContentType = "application/octet-stream";
            return response;
        } catch (Exception ex) {
            request.Context.StatusCodeNumber = 500;
            request.Context.ReasonPhrase = "Internal Server Error";
            AddCors(request);
            request.Context.Response.ContentType = "text/plain";
            return new FileResponse(Encoding.UTF8.GetBytes("File download failed: " + ex.Message), "text/plain");
        }
    }

    private static bool IsUpdateZipDownloadRequest(HttpRequest request) {
        return request.QueryParameters.TryGetValue("download", out string? value) &&
               value.Equals("zip", StringComparison.OrdinalIgnoreCase);
    }

    private static bool WantsJsonUpdateManifest(HttpRequest request) {
        if (request.QueryParameters.TryGetValue("manifest", out string? manifest) &&
            !manifest.Equals("false", StringComparison.OrdinalIgnoreCase) &&
            !manifest.Equals("0", StringComparison.OrdinalIgnoreCase))
            return true;

        if (request.QueryParameters.TryGetValue("format", out string? format) &&
            format.Equals("json", StringComparison.OrdinalIgnoreCase))
            return true;

        if (request.Headers.TryGetValue("Accept", out string? accept) &&
            accept.IndexOf("application/json", StringComparison.OrdinalIgnoreCase) >= 0 &&
            accept.IndexOf("text/html", StringComparison.OrdinalIgnoreCase) < 0)
            return true;

        return false;
    }

    private static bool TryResolveUpdatePath(string root, string relativePath, out string fullPath) {
        fullPath = "";
        try {
            root = Path.GetFullPath(root);
            relativePath = NormalizeUpdateRelativePath(Uri.UnescapeDataString((relativePath ?? "").Replace("+", "%20")));
            if (relativePath.Contains("../", StringComparison.Ordinal) || relativePath.Equals("..", StringComparison.Ordinal))
                return false;
            fullPath = Path.GetFullPath(Path.Combine(root, relativePath.Replace('/', Path.DirectorySeparatorChar)));
            return fullPath.Equals(root, StringComparison.OrdinalIgnoreCase) ||
                   fullPath.StartsWith(root.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar) + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase);
        } catch {
            fullPath = "";
            return false;
        }
    }

    private static string BuildUpdateExplorerHref(string relativePath, bool directory) {
        relativePath = NormalizeUpdateRelativePath(relativePath);
        if (string.IsNullOrWhiteSpace(relativePath))
            return "/update/";
        string encoded = string.Join("/", relativePath.Split('/', StringSplitOptions.RemoveEmptyEntries).Select(Uri.EscapeDataString));
        return "/update/" + encoded + (directory ? "/" : "");
    }

    private static string BuildUpdateZipHref(string relativePath) {
        string href = BuildUpdateExplorerHref(relativePath, true);
        return href + (href.Contains('?', StringComparison.Ordinal) ? "&" : "?") + "download=zip";
    }

    private static string MakeUpdateZipFileName(string folderName) {
        folderName = string.IsNullOrWhiteSpace(folderName) ? "Update" : folderName.Trim();
        foreach (char invalid in Path.GetInvalidFileNameChars())
            folderName = folderName.Replace(invalid, '_');
        folderName = folderName.Trim('.', ' ');
        if (string.IsNullOrWhiteSpace(folderName))
            folderName = "Update";
        return folderName.EndsWith(".zip", StringComparison.OrdinalIgnoreCase)
            ? Path.GetFileNameWithoutExtension(folderName) + ".ZIP"
            : folderName + ".ZIP";
    }

    private static string CombineUpdateRelativePath(string parent, string child) {
        parent = NormalizeUpdateRelativePath(parent);
        child = NormalizeUpdateRelativePath(child);
        return string.IsNullOrWhiteSpace(parent) ? child : parent.TrimEnd('/') + "/" + child.TrimStart('/');
    }

    private static string NormalizeUpdateRelativePath(string path) {
        path = (path ?? "").Replace('\\', '/').Trim('/');
        return path == "." ? "" : path;
    }

    private static string HtmlEncode(string value) {
        return WebUtility.HtmlEncode(value ?? "");
    }

    private static string FormatUpdateFileSize(long bytes) {
        if (bytes < 1024) return bytes.ToString("N0", CultureInfo.CurrentCulture) + " B";
        if (bytes < 1024 * 1024) return (bytes / 1024.0).ToString("N1", CultureInfo.CurrentCulture) + " KB";
        if (bytes < 1024 * 1024 * 1024L) return (bytes / (1024.0 * 1024)).ToString("N1", CultureInfo.CurrentCulture) + " MB";
        return (bytes / (1024.0 * 1024 * 1024)).ToString("N2", CultureInfo.CurrentCulture) + " GB";
    }

    private DirectoryHashManifest BuildJackLLMUpdateManifest() {
        string root = ResolveJackLLMUpdateDirectory();
        return DirectoryHashMetadata.BuildManifest(root, CombineUrl(GetJackLLMUpdatePublicBaseUrl(), "Update/"));
    }

    private static string CombineUrl(string baseUrl, string relativePath) {
        baseUrl = string.IsNullOrWhiteSpace(baseUrl) ? "https://socketjack.com/" : baseUrl.Trim();
        if (!baseUrl.EndsWith("/", StringComparison.Ordinal))
            baseUrl += "/";
        relativePath = (relativePath ?? "").TrimStart('/').Replace("\\", "/");
        return baseUrl + relativePath;
    }

    private string GetJackLLMUpdatePublicBaseUrl() {
        string publicUrl = FirstNonEmpty(_options.WebsitePublicUrl, "https://socketjack.com/");
        if (Uri.TryCreate(publicUrl, UriKind.Absolute, out Uri? uri) &&
            uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) &&
            uri.Host.Equals("socketjack.com", StringComparison.OrdinalIgnoreCase))
            return "https://socketjack.com/";
        return publicUrl;
    }

    private void MapAuthRoutes(MutableTcpServer server) {
        foreach (string path in new[] {
            "/api/web-auth/register",
            "/api/web-auth/registration-request",
            "/api/web-auth/login",
            "/api/web-auth/logout",
            "/api/web-auth/session",
            "/api/web-auth/tokens",
            "/api/web-auth/token-products",
            "/api/web-auth/checkout",
            "/api/web-auth/checkout/session",
            "/api/web-auth/stripe/connect/redirect",
            "/api/socketjack/auth/register",
            "/api/socketjack/auth/registration-request",
            "/api/socketjack/auth/registration-requests",
            "/api/socketjack/auth/registration-requests/decide",
            "/api/socketjack/auth/login",
            "/api/socketjack/auth/logout",
            "/api/socketjack/auth/session",
            "/api/socketjack/auth/inherit",
            "/api/web-auth/inherit",
            "/api/socketjack/token-products",
            "/api/socketjack/oauth/token",
            "/api/socketjack/oauth/session",
            "/api/socketjack/oauth/introspect",
            "/api/socketjack/oauth/charge",
            "/api/socketjack/checkout",
            "/api/socketjack/checkout/session",
            "/api/socketjack/stripe/connect/redirect",
            "/api/socketjack/stripe/webhook"
        }) {
            server.Map("OPTIONS", path, (connection, request, cancellationToken) => NoContent(request));
        }

        server.Map("POST", "/api/web-auth/register", (connection, request, cancellationToken) => HandleRegister(connection, request));
        server.Map("POST", "/api/socketjack/auth/register", (connection, request, cancellationToken) => HandleRegister(connection, request));
        server.Map("POST", "/api/web-auth/registration-request", (connection, request, cancellationToken) => HandleRegistrationRequest(connection, request));
        server.Map("POST", "/api/socketjack/auth/registration-request", (connection, request, cancellationToken) => HandleRegistrationRequest(connection, request));
        server.Map("POST", "/api/web-auth/login", (connection, request, cancellationToken) => HandleLogin(connection, request));
        server.Map("POST", "/api/socketjack/auth/login", (connection, request, cancellationToken) => HandleLogin(connection, request));
        server.Map("POST", "/api/socketjack/oauth/token", (connection, request, cancellationToken) => HandleToken(connection, request));
        server.Map("POST", "/api/web-auth/logout", (connection, request, cancellationToken) => HandleLogout(connection, request));
        server.Map("POST", "/api/socketjack/auth/logout", (connection, request, cancellationToken) => HandleLogout(connection, request));
        server.Map("GET", "/api/web-auth/session", (connection, request, cancellationToken) => HandleSession(connection, request));
        server.Map("GET", "/api/socketjack/auth/session", (connection, request, cancellationToken) => HandleSession(connection, request));
        server.Map("GET", "/api/web-auth/inherit", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("POST", "/api/web-auth/inherit", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("GET", "/api/socketjack/auth/inherit", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("POST", "/api/socketjack/auth/inherit", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("GET", "/api/socketjack/oauth/session", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("POST", "/api/socketjack/oauth/session", (connection, request, cancellationToken) => HandleInheritedOAuthSession(connection, request));
        server.Map("GET", "/api/web-auth/token-products", (connection, request, cancellationToken) => Json(request, BuildTokenProductsResponse(includeDisabled: false)));
        server.Map("GET", "/api/socketjack/token-products", (connection, request, cancellationToken) => Json(request, BuildTokenProductsResponse(includeDisabled: false)));
        server.Map("POST", "/api/web-auth/checkout", (connection, request, cancellationToken) => HandleTokenCheckout(connection, request, cancellationToken));
        server.Map("POST", "/api/socketjack/checkout", (connection, request, cancellationToken) => HandleTokenCheckout(connection, request, cancellationToken));
        server.Map("GET", "/api/web-auth/checkout/session", (connection, request, cancellationToken) => HandleTokenCheckoutSession(request, cancellationToken));
        server.Map("GET", "/api/socketjack/checkout/session", (connection, request, cancellationToken) => HandleTokenCheckoutSession(request, cancellationToken));
        server.Map("GET", "/api/web-auth/stripe/connect/redirect", (connection, request, cancellationToken) => HandleStripeConnectRedirect(request));
        server.Map("GET", "/api/socketjack/stripe/connect/redirect", (connection, request, cancellationToken) => HandleStripeConnectRedirect(request));
        server.Map("POST", "/api/socketjack/stripe/webhook", (connection, request, cancellationToken) => HandleStripeWebhook(request));
        server.Map("POST", "/api/socketjack/oauth/introspect", (connection, request, cancellationToken) => HandleIntrospect(request));
        server.Map("GET", "/api/socketjack/oauth/introspect", (connection, request, cancellationToken) => HandleIntrospect(request));
        server.Map("POST", "/api/socketjack/oauth/charge", (connection, request, cancellationToken) => HandleCharge(request));
        server.Map("POST", "/api/web-auth/tokens", (connection, request, cancellationToken) => HandleTokenLimit(request));
        server.Map("GET", "/api/socketjack/auth/registration-requests", (connection, request, cancellationToken) => HandleRegistrationRequests(request));
        server.Map("POST", "/api/socketjack/auth/registration-requests/decide", (connection, request, cancellationToken) => HandleRegistrationDecision(request));
    }

    private bool IsAuthorized(HttpRequest request) {
        if (!_options.HasAdminKey)
            return false;
        request.Headers.TryGetValue("X-LmVsProxy-Master-Key", out string? suppliedKey);
        byte[] suppliedBytes = Encoding.UTF8.GetBytes(suppliedKey ?? "");
        byte[] expectedBytes = Encoding.UTF8.GetBytes(_options.AdminKey);
        return suppliedBytes.Length == expectedBytes.Length &&
               CryptographicOperations.FixedTimeEquals(suppliedBytes, expectedBytes);
    }

    private bool IsServerOwnerAuthorized(RegisteredServer server, HttpRequest request, string remoteIp, string ownerKey, string ownerTokenHash) {
        if (server == null)
            return false;
        if (IsAuthorized(request))
            return true;
        if (!string.IsNullOrWhiteSpace(server.OwnerKey) &&
            !string.IsNullOrWhiteSpace(ownerKey) &&
            string.Equals(server.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
            return true;
        if (!string.IsNullOrWhiteSpace(server.OwnerTokenHash) &&
            !string.IsNullOrWhiteSpace(ownerTokenHash) &&
            FixedTimeEqualsText(server.OwnerTokenHash, ownerTokenHash))
            return true;
        if (string.IsNullOrWhiteSpace(server.OwnerKey) &&
            string.IsNullOrWhiteSpace(server.OwnerTokenHash) &&
            !string.IsNullOrWhiteSpace(remoteIp) &&
            string.Equals(server.RegisteredByIp, remoteIp, StringComparison.OrdinalIgnoreCase))
            return true;

        return false;
    }

    private static string ExtractOwnerTokenFromRequest(HttpRequest request) {
        if (request?.Headers != null) {
            if (request.Headers.TryGetValue("X-LmVsProxy-Server-Owner", out string? ownerToken) && !string.IsNullOrWhiteSpace(ownerToken))
                return ownerToken.Trim();
            if (request.Headers.TryGetValue("X-SocketJack-Server-Owner", out string? socketJackOwnerToken) && !string.IsNullOrWhiteSpace(socketJackOwnerToken))
                return socketJackOwnerToken.Trim();
        }

        return "";
    }

    private static string HashOwnerToken(string token) {
        token = (token ?? "").Trim();
        if (string.IsNullOrWhiteSpace(token))
            return "";

        return Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(token))).ToLowerInvariant();
    }

    private static bool FixedTimeEqualsText(string left, string right) {
        byte[] leftBytes = Encoding.UTF8.GetBytes(left ?? "");
        byte[] rightBytes = Encoding.UTF8.GetBytes(right ?? "");
        return leftBytes.Length == rightBytes.Length &&
               CryptographicOperations.FixedTimeEquals(leftBytes, rightBytes);
    }

    private string HandleRegister(NetworkConnection connection, HttpRequest request) {
        try {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            string username = FirstNonEmpty(GetJsonString(root, "username"), GetJsonString(root, "user"), GetJsonString(root, "login"));
            string password = FirstNonEmpty(GetJsonString(root, "password"), GetJsonString(root, "pass"));
            bool overwrite = GetJsonBool(root, "overwrite", false);
            bool remember = GetJsonBool(root, "remember", GetJsonBool(root, "rememberMe", false));
            bool requestedAdmin = GetJsonBool(root, "isAdministrator", GetJsonBool(root, "administrator", false));
            bool hasAdmin = HasAnyAccountAdministrator();
            AccountRecord? authenticated = TryAuthenticateAdmin(request, out _) ? AuthenticateRequest(request, out _) : null;

            if (!TryNormalizeUserName(username, out string normalizedUserName, out string userError))
                return Json(request, new { ok = false, error = userError }, 400, "Bad Request");
            if (!IsValidPassword(password, out string passwordError))
                return Json(request, new { ok = false, error = passwordError }, 400, "Bad Request");

            AccountRecord record = CreateAccount(normalizedUserName, password);
            RememberAccountIp(record, ExtractClientIp(connection, request));
            record.IsAdministrator = IsBuiltInAdministratorUserName(record.UserName) || !hasAdmin || (authenticated != null && requestedAdmin);
            bool created = SaveAccount(record, overwrite && authenticated != null);
            if (!created && !(overwrite && authenticated != null))
                return Json(request, new { ok = false, error = "A SocketJack user with that name already exists." }, 409, "Conflict");

            string token = IssueToken(record, request, remember);
            MergeAutoSessionsForAccount(record, ExtractClientIp(connection, request));
            LastStatus = "Registered account " + record.UserName;
            AppendMasterLog("info", "auth", LastStatus, "", record.UserName, ExtractClientIp(connection, request), request.Path);
            StatusChanged?.Invoke(this, EventArgs.Empty);
            return Json(request, BuildAuthPayload(record, token, authenticated: true, created: created, pending: false));
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Registration failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleRegistrationRequest(NetworkConnection connection, HttpRequest request) {
        return HandleRegister(connection, request);
    }

    private string HandleLogin(NetworkConnection connection, HttpRequest request) {
        try {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            string username = FirstNonEmpty(GetJsonString(root, "username"), GetJsonString(root, "user"), GetJsonString(root, "login"));
            string password = FirstNonEmpty(GetJsonString(root, "password"), GetJsonString(root, "pass"));
            bool remember = GetJsonBool(root, "remember", GetJsonBool(root, "rememberMe", false));

            if (!TryValidateCredentials(username, password, out AccountRecord? record, out string error) || record == null)
                return Json(request, new { ok = false, error = error }, 401, "Unauthorized");

            record.LastLoginUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            RememberAccountIp(record, ExtractClientIp(connection, request));
            record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            string token = IssueToken(record, request, remember);
            MergeAutoSessionsForAccount(record, ExtractClientIp(connection, request));
            LastStatus = "Login " + record.UserName;
            AppendMasterLog("info", "auth", LastStatus, "", record.UserName, ExtractClientIp(connection, request), request.Path);
            StatusChanged?.Invoke(this, EventArgs.Empty);
            return Json(request, BuildAuthPayload(record, token, authenticated: true, created: false, pending: false));
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Login failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleToken(NetworkConnection connection, HttpRequest request) {
        try {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            string grantType = FirstNonEmpty(GetJsonString(root, "grant_type"), GetJsonString(root, "grantType"), "password");
            if (!grantType.Equals("password", StringComparison.OrdinalIgnoreCase))
                return Json(request, new { error = "unsupported_grant_type" }, 400, "Bad Request");

            string username = FirstNonEmpty(GetJsonString(root, "username"), GetJsonString(root, "user"), GetJsonString(root, "login"));
            string password = FirstNonEmpty(GetJsonString(root, "password"), GetJsonString(root, "pass"));
            bool remember = GetJsonBool(root, "remember", GetJsonBool(root, "rememberMe", false));
            if (!TryValidateCredentials(username, password, out AccountRecord? record, out string error) || record == null)
                return Json(request, new { error = "invalid_grant", error_description = error }, 401, "Unauthorized");

            record.LastLoginUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            RememberAccountIp(record, ExtractClientIp(connection, request));
            record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            string token = IssueToken(record, request, remember);
            MergeAutoSessionsForAccount(record, ExtractClientIp(connection, request));
            return Json(request, new {
                access_token = token,
                token_type = "Bearer",
                expires_in = Math.Max(1, (int)Math.Round((remember ? WebAuthRememberTokenLifetime : WebAuthTokenLifetime).TotalSeconds)),
                username = record.UserName,
                ownerKey = BuildOwnerKey(record.UserName),
                isAdministrator = record.IsAdministrator,
                usage = BuildUsage(record)
            });
        } catch (Exception ex) {
            return Json(request, new { error = "server_error", error_description = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleLogout(NetworkConnection connection, HttpRequest request) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        string clientIp = ExtractClientIp(connection, request);
        bool authenticated = record != null;
        if (record == null) {
            string rememberedUser = ExtractRememberedUserName(request);
            record = GetAccount(rememberedUser);
            if (record == null || !AccountHasKnownIp(record, clientIp)) {
                ClearAuthCookie(request);
                return Json(request, new { ok = true, loggedOut = true });
            }
        }
        if (authenticated) {
            record.TokenHash = "";
            record.TokenExpiresUtc = "";
        }
        ForgetAccountIp(record, clientIp);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);
        ClearAuthCookie(request);
        return Json(request, new { ok = true, username = record.UserName, loggedOut = true });
    }

    private string HandleSession(NetworkConnection connection, HttpRequest request) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        string token = "";
        bool refreshedByKnownIp = false;
        if (record == null) {
            refreshedByKnownIp = TryAutoAuthenticateKnownIp(connection, request, out record, out token);
            if (record == null) {
                return Json(request, new {
                    ok = true,
                    authenticated = false,
                    isAdministrator = false,
                    canRegisterOpen = !HasAnyAccountAdministrator(),
                    usage = BuildAnonymousUsage()
                });
            }
        }

        string sessionClientIp = ExtractClientIp(connection, request);
        RememberAccountIp(record, sessionClientIp);
        MergeAutoSessionsForAccount(record, sessionClientIp);
        if (string.IsNullOrWhiteSpace(token) && ShouldRefreshAuthToken(record))
            token = IssueToken(record, request, remember: true);
        else
            UpsertAccount(record);
        return Json(request, BuildAuthPayload(record, token, authenticated: true, created: false, pending: false, refreshedByKnownIp: refreshedByKnownIp));
    }

    private string HandleInheritedOAuthSession(NetworkConnection connection, HttpRequest request) {
        HttpRequest effectiveRequest = request ?? throw new ArgumentNullException(nameof(request));
        string token = ExtractTokenFromRequest(effectiveRequest);
        AccountRecord? record = AuthenticateRequest(effectiveRequest, out string authError);
        bool refreshedByKnownIp = false;
        if (record == null) {
            refreshedByKnownIp = TryAutoAuthenticateKnownIp(connection, effectiveRequest, out record, out token);
        }

        string returnUrl = FirstNonEmpty(
            GetQueryValue(effectiveRequest, "returnUrl"),
            GetQueryValue(effectiveRequest, "return_url"),
            GetQueryValue(effectiveRequest, "next"),
            GetQueryValue(effectiveRequest, "redirect_uri"),
            effectiveRequest.Path ?? "/");
        string loginUrl = BuildSocketJackLoginPath(returnUrl);

        if (record == null) {
            return Json(effectiveRequest, new {
                ok = false,
                active = false,
                authenticated = false,
                error = string.IsNullOrWhiteSpace(authError) ? "SocketJack.com login required." : authError,
                loginUrl
            }, 401, "Unauthorized");
        }

        if (string.IsNullOrWhiteSpace(token))
            token = ExtractTokenFromRequest(effectiveRequest);
        if (string.IsNullOrWhiteSpace(token))
            token = IssueToken(record, effectiveRequest, remember: true);

        string inheritedClientIp = ExtractClientIp(connection, effectiveRequest);
        RememberAccountIp(record, inheritedClientIp);
        MergeAutoSessionsForAccount(record, inheritedClientIp);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);

        return Json(effectiveRequest, new {
            ok = true,
            active = true,
            authenticated = true,
            username = record.UserName,
            ownerKey = BuildOwnerKey(record.UserName),
            isAdministrator = record.IsAdministrator,
            tokenType = "Bearer",
            token_type = "Bearer",
            accessToken = token,
            access_token = token,
            expiresUtc = record.TokenExpiresUtc,
            expires_in = CalculateAuthExpiresIn(record.TokenExpiresUtc),
            refreshedByKnownIp,
            loginUrl,
            usage = BuildUsage(record)
        });
    }

    private string HandleAutoPublishPreference(HttpRequest request, bool update) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        if (record == null)
            return Json(request, new { ok = false, error = "Unauthorized." }, 401, "Unauthorized");

        if (update) {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            record.AutoPublish = GetJsonBool(root, "autoPublish", GetJsonBool(root, "enabled", record.AutoPublish));
            record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            UpsertAccount(record);
        }

        return Json(request, new {
            ok = true,
            username = record.UserName,
            autoPublish = record.AutoPublish,
            enabled = record.AutoPublish
        });
    }

    private string HandleTokenCheckout(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        if (record == null)
            return Json(request, new { ok = false, error = "Unauthorized." }, 401, "Unauthorized");

        try {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            string requestedProduct = FirstNonEmpty(
                GetJsonString(root, "productId"),
                GetJsonString(root, "priceId"),
                GetJsonString(root, "id"),
                GetJsonString(root, "name"));
            StripeTokenProductConfig? product = FindStripeTokenProduct(requestedProduct);
            if (product == null || !product.Enabled)
                return Json(request, new { ok = false, error = "Token product was not found." }, 404, "Not Found");

            long amountCents = ResolveStripeTokenProductUnitAmountCents(product);
            bool hasReusablePrice = !string.IsNullOrWhiteSpace(product.PriceId);
            if (!hasReusablePrice && (string.IsNullOrWhiteSpace(product.ProductId) || amountCents < 50))
                return Json(request, new { ok = false, error = "This token product needs a Stripe Price ID or an amount of at least 50 cents." }, 503, "Service Unavailable");

            string successUrl = NormalizeCheckoutReturnUrl(
                FirstNonEmpty(GetJsonString(root, "successUrl"), GetJsonString(root, "returnUrl")),
                "checkout=success");
            string cancelUrl = NormalizeCheckoutReturnUrl(
                FirstNonEmpty(GetJsonString(root, "cancelUrl"), GetJsonString(root, "returnUrl")),
                "checkout=cancel");

            var checkout = new StripeCheckoutSessionRequest {
                SuccessUrl = successUrl,
                CancelUrl = cancelUrl,
                ClientReferenceId = record.UserName,
                IdempotencyKey = FirstNonEmpty(GetJsonString(root, "idempotencyKey"), "socketjack-token-" + record.UserName + "-" + product.ProductId + "-" + Guid.NewGuid().ToString("N")),
                AllowPromotionCodes = GetJsonBool(root, "allowPromotionCodes", true)
            };
            checkout.Metadata["kind"] = "socketjack.token_purchase";
            checkout.Metadata["socketjack_username"] = record.UserName;
            checkout.Metadata["socketjack_owner_key"] = BuildOwnerKey(record.UserName);
            checkout.Metadata["socketjack_product_id"] = product.ProductId;
            checkout.Metadata["socketjack_product_name"] = product.Name;
            checkout.Metadata["socketjack_tokens"] = Math.Max(0, product.TokenAmount).ToString(CultureInfo.InvariantCulture);

            checkout.LineItems.Add(new StripeCheckoutLineItem {
                PriceId = product.PriceId,
                ProductId = product.ProductId,
                ProductName = product.Name,
                Description = product.Description,
                Currency = product.Currency,
                UnitAmount = hasReusablePrice ? null : amountCents,
                Quantity = 1
            });

            var paymentService = new StripePaymentService(StripePaymentServiceOptions.FromEnvironment());
            StripeCheckoutSessionResult result = paymentService.CreateCheckoutSessionAsync(checkout, cancellationToken).GetAwaiter().GetResult();
            return Json(request, new {
                ok = true,
                checkout = result,
                url = result.Url,
                product = BuildStripeTokenProductPayload(product)
            });
        } catch (Exception ex) {
            LastStatus = "Stripe token checkout failed: " + ex.Message;
            StatusChanged?.Invoke(this, EventArgs.Empty);
            return Json(request, new { ok = false, error = "Stripe checkout failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleTokenCheckoutSession(HttpRequest request, CancellationToken cancellationToken) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        if (record == null)
            return Json(request, new { ok = false, error = "Unauthorized." }, 401, "Unauthorized");

        string sessionId = FirstNonEmpty(GetQueryValue(request, "session_id"), GetQueryValue(request, "sessionId"), GetQueryValue(request, "id"));
        if (string.IsNullOrWhiteSpace(sessionId))
            return Json(request, new { ok = false, error = "Checkout session id is required." }, 400, "Bad Request");

        try {
            var paymentService = new StripePaymentService(StripePaymentServiceOptions.FromEnvironment());
            StripeCheckoutSessionResult session = paymentService.RetrieveCheckoutSessionAsync(sessionId, "", cancellationToken).GetAwaiter().GetResult();
            bool credited = false;
            long purchasedTokens = 0;
            long creditedTokens = 0;
            if (string.Equals(session.PaymentStatus, "paid", StringComparison.OrdinalIgnoreCase))
                credited = TryCreditStripeTokenPurchase(record.UserName, session.Id, session.Metadata, out record, out purchasedTokens, out creditedTokens);

            return Json(request, new {
                ok = true,
                checkout = session,
                credited,
                purchasedTokens,
                creditedTokens,
                usage = BuildUsage(record)
            });
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Checkout session could not be loaded.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleStripeWebhook(HttpRequest request) {
        try {
            string signature = "";
            if (request.Headers != null &&
                request.Headers.TryGetValue("Stripe-Signature", out string? signatureValue))
                signature = signatureValue ?? "";
            var paymentService = new StripePaymentService(StripePaymentServiceOptions.FromEnvironment());
            global::Stripe.Event stripeEvent = paymentService.ConstructWebhookEvent(request.Body ?? "", signature);
            bool credited = false;
            bool disabled = false;
            long purchasedTokens = 0;
            long creditedTokens = 0;
            if ((stripeEvent.Type == "checkout.session.completed" ||
                 stripeEvent.Type == "checkout.session.async_payment_succeeded") &&
                stripeEvent.Data.Object is Session session)
                credited = TryCreditStripeTokenPurchase("", session.Id ?? "", session.Metadata, out _, out purchasedTokens, out creditedTokens);
            else if (stripeEvent.Type == "checkout.session.expired" &&
                     stripeEvent.Data.Object is Session expiredSession)
                disabled = TryDisableUnpaidAccountForExpiredCheckout(expiredSession.Id ?? "", expiredSession.Metadata, out purchasedTokens);

            return Json(request, new { ok = true, received = true, credited, disabled, purchasedTokens, creditedTokens });
        } catch (Exception ex) {
            return Json(request, new { ok = false, error = "Stripe webhook failed.", detail = ex.Message }, 400, "Bad Request");
        }
    }

    private string HandleStripeConnectRedirect(HttpRequest request) {
        string returnUrl = FirstNonEmpty(
            TryDecodeStripeConnectState(GetQueryValue(request, "state")),
            GetQueryValue(request, "return_url"),
            GetQueryValue(request, "returnUrl"),
            GetQueryValue(request, "current_url"),
            GetQueryValue(request, "currentUrl"),
            _options.WebsitePublicUrl,
            "https://socketjack.com/");
        returnUrl = NormalizeStripeConnectReturnUrl(returnUrl);

        var query = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase) {
            ["stripe_connect"] = string.IsNullOrWhiteSpace(GetQueryValue(request, "error")) ? "success" : "error"
        };
        AddRedirectQueryValue(query, "code", GetQueryValue(request, "code"));
        AddRedirectQueryValue(query, "scope", GetQueryValue(request, "scope"));
        AddRedirectQueryValue(query, "error", GetQueryValue(request, "error"));
        AddRedirectQueryValue(query, "error_description", GetQueryValue(request, "error_description"));

        string redirectUrl = AppendQuery(returnUrl, query);
        request.Context.StatusCodeNumber = 302;
        request.Context.ReasonPhrase = "Found";
        AddCors(request);
        request.Context.Response.Headers["Location"] = redirectUrl;
        request.Context.Response.ContentType = "text/plain; charset=utf-8";
        return "Redirecting to " + redirectUrl;
    }

    private static string TryDecodeStripeConnectState(string state) {
        state = (state ?? "").Trim();
        if (state.Length == 0)
            return "";

        if (Uri.TryCreate(state, UriKind.Absolute, out Uri? direct) &&
            (direct.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) ||
             direct.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
            return direct.ToString();

        try {
            string padded = state.Replace('-', '+').Replace('_', '/');
            switch (padded.Length % 4) {
                case 2:
                    padded += "==";
                    break;
                case 3:
                    padded += "=";
                    break;
            }

            string decoded = Encoding.UTF8.GetString(Convert.FromBase64String(padded));
            if (Uri.TryCreate(decoded, UriKind.Absolute, out Uri? decodedUri) &&
                (decodedUri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) ||
                 decodedUri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
                return decodedUri.ToString();
        } catch {
        }

        return "";
    }

    private string NormalizeStripeConnectReturnUrl(string returnUrl) {
        returnUrl = FirstNonEmpty(returnUrl, _options.WebsitePublicUrl, "https://socketjack.com/");
        if (!Uri.TryCreate(returnUrl, UriKind.Absolute, out Uri? uri) ||
            (!uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) &&
             !uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
            return FirstNonEmpty(_options.WebsitePublicUrl, "https://socketjack.com/");
        return uri.ToString();
    }

    private static void AddRedirectQueryValue(IDictionary<string, string> query, string name, string value) {
        value = (value ?? "").Trim();
        if (value.Length > 0)
            query[name] = value;
    }

    private static string AppendQuery(string url, IDictionary<string, string> query) {
        if (query == null || query.Count == 0)
            return url;

        var builder = new StringBuilder(url ?? "");
        char separator = builder.ToString().Contains('?') ? '&' : '?';
        foreach (KeyValuePair<string, string> pair in query) {
            builder.Append(separator);
            builder.Append(Uri.EscapeDataString(pair.Key));
            builder.Append('=');
            builder.Append(Uri.EscapeDataString(pair.Value ?? ""));
            separator = '&';
        }

        return builder.ToString();
    }

    private static StripeTokenProductConfig? FindStripeTokenProduct(string requestedProduct) {
        string normalized = (requestedProduct ?? "").Trim();
        if (normalized.Length == 0)
            return null;

        return ReadStripeTokenProductsFromSettings().FirstOrDefault(product =>
            string.Equals(product.ProductId, normalized, StringComparison.OrdinalIgnoreCase) ||
            string.Equals(product.PriceId, normalized, StringComparison.OrdinalIgnoreCase) ||
            string.Equals(product.Name, normalized, StringComparison.OrdinalIgnoreCase));
    }

    private static object BuildStripeTokenProductPayload(StripeTokenProductConfig product) {
        long amountCents = ResolveStripeTokenProductUnitAmountCents(product);
        return new {
            productId = product.ProductId,
            name = product.Name,
            description = product.Description,
            tokenAmount = product.TokenAmount,
            unitAmountCents = amountCents,
            currency = string.IsNullOrWhiteSpace(product.Currency) ? "usd" : product.Currency,
            enabled = product.Enabled,
            configured = !string.IsNullOrWhiteSpace(product.PriceId) ||
                         (!string.IsNullOrWhiteSpace(product.ProductId) && amountCents >= 50),
            priceIdConfigured = !string.IsNullOrWhiteSpace(product.PriceId)
        };
    }

    private string NormalizeCheckoutReturnUrl(string value, string checkoutState) {
        string url = FirstNonEmpty(value, _options.WebsitePublicUrl, "https://socketjack.com/");
        if (!Uri.TryCreate(url, UriKind.Absolute, out Uri? uri) ||
            (!uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) &&
             !uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
            url = FirstNonEmpty(_options.WebsitePublicUrl, "https://socketjack.com/");

        string separator = url.Contains('?') ? "&" : "?";
        if (url.IndexOf("checkout=", StringComparison.OrdinalIgnoreCase) < 0)
            url += separator + checkoutState;
        if (checkoutState.EndsWith("success", StringComparison.OrdinalIgnoreCase) &&
            url.IndexOf("session_id=", StringComparison.OrdinalIgnoreCase) < 0)
            url += (url.Contains('?') ? "&" : "?") + "session_id={CHECKOUT_SESSION_ID}";
        return url;
    }

    private static string GetQueryValue(HttpRequest request, string name) {
        if (request?.QueryParameters != null &&
            request.QueryParameters.TryGetValue(name, out string? value))
            return value ?? "";
        return "";
    }

    private static int CalculateAuthExpiresIn(string expiresUtc) {
        if (!DateTimeOffset.TryParse(expiresUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset expires))
            return 0;
        return Math.Max(0, (int)Math.Round((expires.ToUniversalTime() - DateTimeOffset.UtcNow).TotalSeconds));
    }

    private bool TryCreditStripeTokenPurchase(string expectedUserName, string sessionId, IDictionary<string, string>? metadata, out AccountRecord record, out long purchasedTokens, out long creditedTokens) {
        record = null!;
        purchasedTokens = 0;
        creditedTokens = 0;
        sessionId = (sessionId ?? "").Trim();
        if (sessionId.Length == 0 || metadata == null)
            return false;

        metadata.TryGetValue("kind", out string? kind);
        if (!string.Equals(kind, "socketjack.token_purchase", StringComparison.Ordinal))
            return false;

        metadata.TryGetValue("socketjack_username", out string? metadataUserName);
        metadata.TryGetValue("socketjack_tokens", out string? tokenText);
        string username = FirstNonEmpty(expectedUserName, metadataUserName);
        long tokens = Math.Max(0, ParseLong(tokenText ?? "", 0));
        purchasedTokens = tokens;
        AccountRecord? account = GetAccount(username);
        if (account == null || tokens <= 0) {
            record = account ?? new AccountRecord { UserName = username };
            return false;
        }

        HashSet<string> credited = account.CreditedStripeSessionIds
            .Split(new[] { '|', ',', ';', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
            .Select(item => item.Trim())
            .Where(item => item.Length > 0)
            .ToHashSet(StringComparer.OrdinalIgnoreCase);
        if (credited.Contains(sessionId)) {
            record = account;
            return false;
        }

        account.TokenLimit = Math.Max(0, account.TokenLimit) + tokens;
        creditedTokens = tokens;
        credited.Add(sessionId);
        account.CreditedStripeSessionIds = string.Join("|", credited.OrderBy(item => item, StringComparer.OrdinalIgnoreCase));
        account.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(account);
        record = account;
        return true;
    }

    private bool TryDisableUnpaidAccountForExpiredCheckout(string sessionId, IDictionary<string, string>? metadata, out long requestedTokens) {
        requestedTokens = 0;
        sessionId = (sessionId ?? "").Trim();
        if (sessionId.Length == 0 || metadata == null)
            return false;

        metadata.TryGetValue("kind", out string? kind);
        if (!string.Equals(kind, "socketjack.token_purchase", StringComparison.Ordinal))
            return false;

        metadata.TryGetValue("socketjack_username", out string? username);
        metadata.TryGetValue("socketjack_tokens", out string? tokenText);
        requestedTokens = Math.Max(0, ParseLong(tokenText ?? "", 0));
        AccountRecord? account = GetAccount(username ?? "");
        if (account == null || account.IsAdministrator || HasCreditedStripePurchase(account) || !IsPastUnpaidGracePeriod(account))
            return false;

        account.Enabled = false;
        account.TokenHash = "";
        account.TokenExpiresUtc = "";
        account.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(account);
        LastStatus = "Disabled unpaid account " + account.UserName + " after expired Stripe Checkout " + sessionId + ".";
        StatusChanged?.Invoke(this, EventArgs.Empty);
        return true;
    }

    private static bool HasCreditedStripePurchase(AccountRecord account) {
        return account != null &&
               !string.IsNullOrWhiteSpace(account.CreditedStripeSessionIds);
    }

    private static bool IsPastUnpaidGracePeriod(AccountRecord account) {
        if (account == null)
            return false;
        if (!DateTimeOffset.TryParse(account.CreatedUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset created))
            return false;
        return DateTimeOffset.UtcNow - created.ToUniversalTime() >= UnpaidAccountGracePeriod;
    }

    private bool EnforceUnpaidAccountGracePeriod(AccountRecord account, out string error) {
        error = "";
        if (account == null || account.IsAdministrator || HasCreditedStripePurchase(account) || !IsPastUnpaidGracePeriod(account))
            return true;

        account.Enabled = false;
        account.TokenHash = "";
        account.TokenExpiresUtc = "";
        account.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(account);
        error = "SocketJack user is disabled because no token payment was completed within 1 day.";
        LastStatus = "Disabled unpaid account " + account.UserName + " after 1 day without token payment.";
        StatusChanged?.Invoke(this, EventArgs.Empty);
        return false;
    }

    private string HandleIntrospect(HttpRequest request) {
        string token = ExtractTokenFromRequest(request);
        string serverId = "";
        string serverName = "";
        string publicHost = "";
        if (!string.IsNullOrWhiteSpace(request.Body)) {
            using JsonDocument document = ParseBody(request);
            JsonElement root = document.RootElement;
            if (string.IsNullOrWhiteSpace(token))
                token = FirstNonEmpty(GetJsonString(root, "token"), GetJsonString(root, "access_token"));
            serverId = FirstNonEmpty(GetJsonString(root, "serverId"), GetJsonString(root, "id"));
            serverName = FirstNonEmpty(GetJsonString(root, "serverName"), GetJsonString(root, "name"), GetJsonString(root, "displayName"));
            publicHost = FirstNonEmpty(GetJsonString(root, "publicHost"), GetJsonString(root, "connectHost"), GetJsonString(root, "endpoint"));
        }

        if (!TryValidateToken(token, out AccountRecord? record, out _) || record == null)
            return Json(request, new { active = false });

        bool ownsServer = IsOwnedServerForAccount(record, serverId, serverName, publicHost);
        return Json(request, new {
            active = true,
            username = record.UserName,
            ownerKey = BuildOwnerKey(record.UserName),
            ownsServer,
            serverOwnerUserName = ownsServer ? record.UserName : "",
            token_type = "Bearer",
            exp = TryParseUnixTime(record.TokenExpiresUtc),
            expiresUtc = record.TokenExpiresUtc,
            isAdministrator = record.IsAdministrator,
            usage = BuildUsage(record)
        });
    }

    private bool IsOwnedServerForAccount(AccountRecord record, string serverId, string serverName, string publicHost) {
        if (record == null || string.IsNullOrWhiteSpace(record.UserName))
            return false;

        string ownerKey = BuildOwnerKey(record.UserName);
        string normalizedServerId = (serverId ?? "").Trim();
        string normalizedServerName = (serverName ?? "").Trim();
        string normalizedHost = NormalizePublicHost(publicHost).Trim();
        lock (_sync) {
            foreach (object[] row in _table.Rows.ToList()) {
                RegisteredServer server = RowToServer(row);
                if (!string.Equals(server.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
                    continue;

                if (!string.IsNullOrWhiteSpace(normalizedServerId) &&
                    string.Equals(server.Id, normalizedServerId, StringComparison.OrdinalIgnoreCase))
                    return true;

                if (!string.IsNullOrWhiteSpace(normalizedServerName) &&
                    (string.Equals(server.Title, normalizedServerName, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(server.DisplayName, normalizedServerName, StringComparison.OrdinalIgnoreCase)))
                    return true;

                if (!string.IsNullOrWhiteSpace(normalizedHost) &&
                    (string.Equals(NormalizePublicHost(server.ConnectHost), normalizedHost, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(NormalizePublicHost(server.Endpoint), normalizedHost, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(NormalizePublicHost(server.IpAddress), normalizedHost, StringComparison.OrdinalIgnoreCase)))
                    return true;
            }
        }

        return false;
    }

    private RegisteredServer? FindServerForTokenRequest(string serverId, string serverName, string publicHost) {
        string normalizedServerId = (serverId ?? "").Trim();
        string normalizedServerName = (serverName ?? "").Trim();
        string normalizedHost = NormalizePublicHost(publicHost).Trim();
        if (string.IsNullOrWhiteSpace(normalizedServerId) &&
            string.IsNullOrWhiteSpace(normalizedServerName) &&
            string.IsNullOrWhiteSpace(normalizedHost))
            return null;

        lock (_sync) {
            foreach (object[] row in _table.Rows.ToList()) {
                RegisteredServer server = RowToServer(row);
                if (!string.IsNullOrWhiteSpace(normalizedServerId) &&
                    string.Equals(server.Id, normalizedServerId, StringComparison.OrdinalIgnoreCase))
                    return server;

                if (!string.IsNullOrWhiteSpace(normalizedServerName) &&
                    (string.Equals(server.Title, normalizedServerName, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(server.DisplayName, normalizedServerName, StringComparison.OrdinalIgnoreCase)))
                    return server;

                if (!string.IsNullOrWhiteSpace(normalizedHost) &&
                    (string.Equals(NormalizePublicHost(server.ConnectHost), normalizedHost, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(NormalizePublicHost(server.Endpoint), normalizedHost, StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(NormalizePublicHost(server.IpAddress), normalizedHost, StringComparison.OrdinalIgnoreCase)))
                    return server;
            }
        }

        return null;
    }

    private static bool HasPaymentConfiguration(RegisteredServer? server) {
        return server != null &&
               server.RequiresPayment &&
               (!string.IsNullOrWhiteSpace(server.StripePriceId) || server.StripeUnitAmountCents > 0);
    }

    private string HandleCharge(HttpRequest request) {
        AccountRecord? record = AuthenticateRequest(request, out _);
        if (record == null)
            return Json(request, new { ok = false, error = "Unauthorized." }, 401, "Unauthorized");

        using JsonDocument document = ParseBody(request);
        JsonElement root = document.RootElement;
        long tokens = Math.Max(0, GetJsonLong(root, "tokens", GetJsonLong(root, "tokenDelta", 0)));
        if (tokens <= 0)
            return Json(request, new { ok = true, username = record.UserName, chargedTokens = 0, usage = BuildUsage(record) });

        string serverId = FirstNonEmpty(GetJsonString(root, "serverId"), GetJsonString(root, "id"));
        string serverName = FirstNonEmpty(GetJsonString(root, "serverName"), GetJsonString(root, "name"), GetJsonString(root, "displayName"));
        string publicHost = FirstNonEmpty(GetJsonString(root, "publicHost"), GetJsonString(root, "connectHost"), GetJsonString(root, "endpoint"));
        RegisteredServer? server = FindServerForTokenRequest(serverId, serverName, publicHost);
        bool tokenExempt = IsOwnedServerForAccount(record, serverId, serverName, publicHost) || (server != null && !HasPaymentConfiguration(server));
        if (tokenExempt)
            return Json(request, new { ok = true, username = record.UserName, chargedTokens = tokens, tokenExempt = true, usage = BuildUsage(record) });

        bool unlimited = record.TokenLimit <= 0;
        long remaining = unlimited ? long.MaxValue : Math.Max(0, record.TokenLimit - record.TokensUsed);
        if (!unlimited && remaining < tokens)
            return Json(request, new { ok = false, error = "Token limit exceeded.", usage = BuildUsage(record) }, 402, "Payment Required");

        record.TokensUsed = Math.Max(0, record.TokensUsed + tokens);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);
        return Json(request, new { ok = true, username = record.UserName, chargedTokens = tokens, usage = BuildUsage(record) });
    }

    private string HandleTokenLimit(HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        using JsonDocument document = ParseBody(request);
        JsonElement root = document.RootElement;
        string username = FirstNonEmpty(GetJsonString(root, "username"), GetJsonString(root, "user"), GetJsonString(root, "login"));
        string action = FirstNonEmpty(GetJsonString(root, "action"), "add").ToLowerInvariant();
        long tokens = Math.Max(0, GetJsonLong(root, "tokens", 0));
        AccountRecord? record = GetAccount(username);
        if (record == null)
            return Json(request, new { ok = false, error = "SocketJack user was not found." }, 404, "Not Found");

        if (action == "set")
            record.TokenLimit = tokens;
        else if (action == "reset")
            record.TokensUsed = 0;
        else
            record.TokenLimit = Math.Max(0, record.TokenLimit + tokens);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);
        return Json(request, new { ok = true, username = record.UserName, usage = BuildUsage(record) });
    }

    private string HandleRegistrationRequests(HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        List<AccountRegistrationRequest> requests = GetRegistrationRequests()
            .Where(item => item.Status.Equals("pending", StringComparison.OrdinalIgnoreCase))
            .OrderByDescending(item => item.RequestedUtc, StringComparer.Ordinal)
            .ToList();
        return Json(request, new { ok = true, requests });
    }

    private string HandleRegistrationDecision(HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        using JsonDocument document = ParseBody(request);
        JsonElement root = document.RootElement;
        string requestId = FirstNonEmpty(GetJsonString(root, "requestId"), GetJsonString(root, "id"));
        bool approved = GetJsonBool(root, "approved", string.Equals(GetJsonString(root, "action"), "approve", StringComparison.OrdinalIgnoreCase));
        string note = GetJsonString(root, "note");
        AccountRegistrationRequest decided = DecideRegistrationRequest(requestId, approved, admin.UserName, note);
        return Json(request, new { ok = true, request = decided });
    }

    private string HandleRuntimeReport(NetworkConnection connection, HttpRequest request) {
        if (request == null)
            throw new ArgumentNullException(nameof(request));

        try {
            if (string.IsNullOrWhiteSpace(request.Body))
                return Json(request, new { ok = false, error = "Request body is required." }, 400, "Bad Request");

            AccountRecord? authenticated = AuthenticateRequest(request, out _);
            using JsonDocument document = ParseBody(request);
            SocketJackRuntimeReport report = RuntimeReportFromJson(document.RootElement);
            report.ClientIp = ExtractClientIp(connection, request);
            report.AuthenticatedUserName = authenticated?.UserName ?? "";
            if (string.IsNullOrWhiteSpace(report.ReportedByUserName))
                report.ReportedByUserName = FirstNonEmpty(authenticated?.UserName, ExtractRememberedUserName(request));
            SaveRuntimeReport(report);
            AppendMasterLog(
                report.Severity,
                "runtime-report",
                report.PrimaryProvider + " -> " + report.FallbackProvider + ": " + report.Reason,
                report.Detail,
                FirstNonEmpty(report.AuthenticatedUserName, report.ReportedByUserName, report.OwnerUserName),
                report.ClientIp,
                request.Path ?? "");
            return Json(request, new { ok = true, reportId = report.Id, savedUtc = report.CreatedUtc });
        } catch (JsonException ex) {
            return Json(request, new { ok = false, error = "Invalid JSON.", detail = ex.Message }, 400, "Bad Request");
        } catch (Exception ex) {
            AppendMasterLog("error", "runtime-report", "Runtime report failed.", ex.Message, "", ExtractClientIp(connection, request), request.Path ?? "");
            return Json(request, new { ok = false, error = "Runtime report failed.", detail = ex.Message }, 500, "Internal Server Error");
        }
    }

    private string HandleSocketJackAdminSummary(NetworkConnection connection, HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        return Json(request, new {
            ok = true,
            username = admin.UserName,
            isAdministrator = admin.IsAdministrator,
            canViewIssues = IsJackAdministrator(admin),
            sqlAdmin = BuildSocketJackAdminSqlAdminPayload(admin),
            reportCount = CountRuntimeReports(),
            issueCount = IsJackAdministrator(admin) ? CountIssueReports() : 0,
            logCount = CountMasterLogs(),
            latestReports = ListRuntimeReports(10),
            latestIssues = IsJackAdministrator(admin) ? ListIssueReports(10).ToArray() : Array.Empty<SocketJackIssueReport>(),
            latestLogs = ListMasterLogs(25)
        });
    }

    private string HandleSocketJackAdminReports(NetworkConnection connection, HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        int take = ClampAdminTake(GetQueryValue(request, "take"), 200);
        return Json(request, new {
            ok = true,
            username = admin.UserName,
            count = CountRuntimeReports(),
            reports = ListRuntimeReports(take)
        });
    }

    private string HandleSocketJackAdminLogs(NetworkConnection connection, HttpRequest request) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        int take = Math.Min(MaxMasterLogRows, ClampAdminTake(GetQueryValue(request, "take"), MaxMasterLogRows));
        return Json(request, new {
            ok = true,
            username = admin.UserName,
            count = CountMasterLogs(),
            logs = ListMasterLogs(take)
        });
    }

    private string HandleSocketJackAdminSqlAdmin(NetworkConnection connection, HttpRequest request, bool update) {
        AccountRecord? admin = AuthenticateRequest(request, out _);
        if (admin == null || !admin.IsAdministrator)
            return Json(request, new { ok = false, error = "Administrator login required." }, 403, "Forbidden");

        if (update) {
            try {
                using JsonDocument document = ParseBody(request);
                JsonElement root = document.RootElement;
                bool enabled = ReadSqlAdminEnabledRequest(root, IsSqlAdminPanelEnabled());
                SetSqlAdminPanelEnabled(enabled);
                LastStatus = "SQL Admin panel " + (enabled ? "enabled" : "disabled") + " by " + admin.UserName;
                AppendMasterLog(
                    "info",
                    "admin",
                    LastStatus,
                    SqlAdminUrl,
                    admin.UserName,
                    ExtractClientIp(connection, request),
                    request.Path ?? "");
                StatusChanged?.Invoke(this, EventArgs.Empty);
            } catch (Exception ex) {
                return Json(request, new { ok = false, error = "SQL Admin control failed.", detail = ex.Message }, 400, "Bad Request");
            }
        }

        return Json(request, BuildSocketJackAdminSqlAdminPayload(admin));
    }

    private object BuildSocketJackAdminSqlAdminPayload(AccountRecord admin) {
        return new {
            ok = true,
            username = admin?.UserName ?? "",
            isAdministrator = admin?.IsAdministrator ?? false,
            enabled = IsSqlAdminPanelEnabled(),
            sqlAdminEnabled = IsSqlAdminPanelEnabled(),
            url = SqlAdminUrl,
            sqlAdminUrl = SqlAdminUrl,
            localSqlAdminUrl = LocalSqlAdminUrl,
            sqlLoopbackUrl = LocalSqlAdminUrl,
            database = _options.DatabaseName,
            table = _options.TableName,
            listener = GetSqlAdminPanelListenerStatus(),
            publicListener = IsPublicSqlAdminPanelListening() ? "listening" : "stopped",
            loopbackListener = IsSqlLoopbackPanelListening() ? "listening" : (_sqlLoopbackServer == null ? "disabled" : "stopped"),
            status = IsSqlAdminPanelEnabled() ? "enabled" : "disabled"
        };
    }

    private static bool ReadSqlAdminEnabledRequest(JsonElement root, bool fallback) {
        string action = FirstNonEmpty(
            GetJsonString(root, "action"),
            GetJsonString(root, "command"),
            GetJsonString(root, "mode")).Trim();
        if (action.Equals("enable", StringComparison.OrdinalIgnoreCase) ||
            action.Equals("start", StringComparison.OrdinalIgnoreCase))
            return true;
        if (action.Equals("disable", StringComparison.OrdinalIgnoreCase) ||
            action.Equals("stop", StringComparison.OrdinalIgnoreCase))
            return false;
        if (action.Equals("toggle", StringComparison.OrdinalIgnoreCase))
            return !fallback;

        return GetJsonBool(root, "sqlAdminEnabled", GetJsonBool(root, "enabled", fallback));
    }

    private static int ClampAdminTake(string value, int fallback) {
        return Math.Clamp((int)ParseLong(value, fallback), 1, 1000);
    }

    private JsonDocument ParseBody(HttpRequest request) {
        string body = request?.Body ?? "";
        return JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
    }

    private AccountRecord CreateAccount(string username, string password) {
        byte[] salt = RandomBytes(16);
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        return ApplyBuiltInAdministratorRule(new AccountRecord {
            UserName = username,
            PasswordSalt = Convert.ToBase64String(salt),
            PasswordHash = HashPassword(password, salt),
            CreatedUtc = now,
            UpdatedUtc = now,
            Enabled = true
        });
    }

    private bool SaveAccount(AccountRecord record, bool overwrite) {
        ApplyBuiltInAdministratorRule(record);
        lock (_sync) {
            for (int i = 0; i < _usersTable.Rows.Count; i++) {
                AccountRecord existing = AccountFromRow(_usersTable.Rows[i]);
                if (!string.Equals(existing.UserName, record.UserName, StringComparison.OrdinalIgnoreCase))
                    continue;
                if (!overwrite)
                    return false;
                record.CreatedUtc = string.IsNullOrWhiteSpace(existing.CreatedUtc) ? record.CreatedUtc : existing.CreatedUtc;
                _usersTable.Rows[i] = AccountToRow(record);
                _dataServer.Save();
                NotifyAutoLiveDataChanged();
                return false;
            }

            _usersTable.Rows.Add(AccountToRow(record));
            _dataServer.Save();
            NotifyAutoLiveDataChanged();
            return true;
        }
    }

    private void UpsertAccount(AccountRecord record) {
        ApplyBuiltInAdministratorRule(record);
        lock (_sync) {
            for (int i = 0; i < _usersTable.Rows.Count; i++) {
                AccountRecord existing = AccountFromRow(_usersTable.Rows[i]);
                if (!string.Equals(existing.UserName, record.UserName, StringComparison.OrdinalIgnoreCase))
                    continue;
                _usersTable.Rows[i] = AccountToRow(record);
                _dataServer.Save();
                NotifyAutoLiveDataChanged();
                return;
            }

            _usersTable.Rows.Add(AccountToRow(record));
            _dataServer.Save();
            NotifyAutoLiveDataChanged();
        }
    }

    private AccountRecord? GetAccount(string username) {
        if (!TryNormalizeUserName(username, out string normalized, out _))
            return null;
        lock (_sync) {
            foreach (object[] row in _usersTable.Rows) {
                AccountRecord record = AccountFromRow(row);
                if (string.Equals(record.UserName, normalized, StringComparison.OrdinalIgnoreCase))
                    return record;
            }
        }

        return null;
    }

    private bool HasAnyAccountAdministrator() {
        lock (_sync) {
            foreach (object[] row in _usersTable.Rows) {
                AccountRecord record = AccountFromRow(row);
                if (record.Enabled && record.IsAdministrator)
                    return true;
            }
        }

        return false;
    }

    private static bool IsBuiltInAdministratorUserName(string username) {
        return string.Equals((username ?? "").Trim(), "JACK", StringComparison.OrdinalIgnoreCase);
    }

    private static AccountRecord ApplyBuiltInAdministratorRule(AccountRecord record) {
        if (IsBuiltInAdministratorUserName(record.UserName)) {
            record.Enabled = true;
            record.IsAdministrator = true;
        }
        return record;
    }

    private bool TryValidateCredentials(string username, string password, out AccountRecord? record, out string error) {
        record = null;
        error = "Invalid username or password.";
        AccountRecord? candidate = GetAccount(username);
        if (candidate == null)
            return false;
        if (!candidate.Enabled) {
            error = "SocketJack user is disabled.";
            return false;
        }
        if (!VerifyPassword(password, candidate.PasswordSalt, candidate.PasswordHash))
            return false;
        if (!EnforceUnpaidAccountGracePeriod(candidate, out error))
            return false;
        record = candidate;
        return true;
    }

    private bool TryAutoAuthenticateKnownIp(NetworkConnection connection, HttpRequest request, out AccountRecord? record, out string token) {
        record = null;
        token = "";
        string username = ExtractRememberedUserName(request);
        string clientIp = ExtractClientIp(connection, request);
        if (string.IsNullOrWhiteSpace(username) || string.IsNullOrWhiteSpace(clientIp))
            return false;

        AccountRecord? candidate = GetAccount(username);
        if (candidate == null || !candidate.Enabled || !AccountHasKnownIp(candidate, clientIp))
            return false;
        if (!EnforceUnpaidAccountGracePeriod(candidate, out _))
            return false;

        candidate.LastLoginUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        RememberAccountIp(candidate, clientIp);
        candidate.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        token = IssueToken(candidate, request, remember: true);
        record = candidate;
        return true;
    }

    private static bool ShouldRefreshAuthToken(AccountRecord record) {
        if (record == null || string.IsNullOrWhiteSpace(record.TokenExpiresUtc))
            return true;
        if (!DateTimeOffset.TryParse(record.TokenExpiresUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset expires))
            return true;
        return expires <= DateTimeOffset.UtcNow.AddDays(7);
    }

    private string IssueToken(AccountRecord record, HttpRequest request, bool remember = false) {
        string token = Base64Url(RandomBytes(32));
        TimeSpan lifetime = remember ? WebAuthRememberTokenLifetime : WebAuthTokenLifetime;
        DateTimeOffset expires = DateTimeOffset.UtcNow.Add(lifetime);
        record.TokenHash = HashToken(token);
        record.TokenExpiresUtc = expires.ToString("O", CultureInfo.InvariantCulture);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);
        SetAuthCookie(request, token, expires);
        return token;
    }

    private AccountRecord? AuthenticateRequest(HttpRequest request, out string error) {
        string token = ExtractTokenFromRequest(request);
        if (TryValidateToken(token, out AccountRecord? record, out error))
            return record;
        return null;
    }

    private bool TryAuthenticateAdmin(HttpRequest request, out string error) {
        AccountRecord? record = AuthenticateRequest(request, out error);
        return record != null && record.IsAdministrator;
    }

    private bool TryValidateToken(string token, out AccountRecord? record, out string error) {
        record = null;
        error = "Invalid or expired auth token.";
        if (string.IsNullOrWhiteSpace(token))
            return false;
        string tokenHash = HashToken(token);
        lock (_sync) {
            for (int i = 0; i < _usersTable.Rows.Count; i++) {
                AccountRecord candidate = AccountFromRow(_usersTable.Rows[i]);
                if (!candidate.Enabled || string.IsNullOrWhiteSpace(candidate.TokenHash) || !ConstantTimeEquals(candidate.TokenHash, tokenHash))
                    continue;
                if (!DateTimeOffset.TryParse(candidate.TokenExpiresUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset expires) ||
                    expires <= DateTimeOffset.UtcNow) {
                    candidate.TokenHash = "";
                    candidate.TokenExpiresUtc = "";
                    _usersTable.Rows[i] = AccountToRow(candidate);
                    _dataServer.Save();
                    NotifyAutoLiveDataChanged();
                    error = "Auth token expired. Log in again.";
                    return false;
                }
                if (!EnforceUnpaidAccountGracePeriod(candidate, out error))
                    return false;

                record = candidate;
                return true;
            }
        }

        return false;
    }

    private string ExtractTokenFromRequest(HttpRequest? request) {
        if (request?.Headers != null && request.Headers.TryGetValue("Authorization", out string? authorization)) {
            if (!string.IsNullOrWhiteSpace(authorization) && authorization.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
                return authorization.Substring("Bearer ".Length).Trim();
        }
        if (request?.Headers != null && request.Headers.TryGetValue("X-SocketJack-Auth", out string? socketJackToken) && !string.IsNullOrWhiteSpace(socketJackToken))
            return socketJackToken.Trim();
        if (request?.Headers != null && request.Headers.TryGetValue("X-LmVsProxy-Auth", out string? lmvsToken) && !string.IsNullOrWhiteSpace(lmvsToken))
            return lmvsToken.Trim();
        return FirstNonEmpty(GetCookieValue(request, WebAuthCookieName), GetCookieValue(request, LegacyWebAuthCookieName));
    }

    private AccountRecord? AuthenticateWebSocketHeaders(IReadOnlyDictionary<string, string>? headers, JsonObject? clientRequest, out string error) {
        string token = FirstNonEmpty(
            JsonText(clientRequest, "accessToken", ""),
            JsonText(clientRequest, "access_token", ""),
            JsonText(clientRequest, "authToken", ""),
            JsonText(clientRequest, "token", ""),
            ExtractTokenFromHeaders(headers));
        if (TryValidateToken(token, out AccountRecord? record, out error))
            return record;
        return null;
    }

    private static string ExtractTokenFromHeaders(IReadOnlyDictionary<string, string>? headers) {
        if (headers != null && headers.TryGetValue("Authorization", out string? authorization)) {
            if (!string.IsNullOrWhiteSpace(authorization) && authorization.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
                return authorization.Substring("Bearer ".Length).Trim();
        }
        if (headers != null && headers.TryGetValue("X-SocketJack-Auth", out string? socketJackToken) && !string.IsNullOrWhiteSpace(socketJackToken))
            return socketJackToken.Trim();
        if (headers != null && headers.TryGetValue("X-LmVsProxy-Auth", out string? lmvsToken) && !string.IsNullOrWhiteSpace(lmvsToken))
            return lmvsToken.Trim();
        return FirstNonEmpty(GetCookieValue(headers, WebAuthCookieName), GetCookieValue(headers, LegacyWebAuthCookieName));
    }

    private string ExtractRememberedUserName(HttpRequest? request) {
        string username = "";
        if (request?.Headers != null) {
            if (request.Headers.TryGetValue("X-SocketJack-User", out string? socketJackUser))
                username = socketJackUser ?? "";
            if (string.IsNullOrWhiteSpace(username) && request.Headers.TryGetValue("X-SocketJack-Username", out string? socketJackUsername))
                username = socketJackUsername ?? "";
            if (string.IsNullOrWhiteSpace(username) && request.Headers.TryGetValue("X-LmVsProxy-User", out string? lmvsUser))
                username = lmvsUser ?? "";
        }
        if (string.IsNullOrWhiteSpace(username))
            username = GetCookieValue(request, "SocketJackLoginName");
        if (string.IsNullOrWhiteSpace(username) && request?.QueryParameters != null) {
            if (request.QueryParameters.TryGetValue("username", out string? queryUser))
                username = queryUser ?? "";
            else if (request.QueryParameters.TryGetValue("user", out string? queryUserAlias))
                username = queryUserAlias ?? "";
            else if (request.QueryParameters.TryGetValue("login", out string? queryLogin))
                username = queryLogin ?? "";
        }
        return TryNormalizeUserName(username, out string normalized, out _) ? normalized : "";
    }

    private string GetCookieValue(HttpRequest? request, string name) {
        if (request?.Headers == null || string.IsNullOrWhiteSpace(name))
            return "";
        if (!request.Headers.TryGetValue("Cookie", out string? cookieHeader) || string.IsNullOrWhiteSpace(cookieHeader))
            return "";
        foreach (string part in cookieHeader.Split(';')) {
            string trimmed = part.Trim();
            int separator = trimmed.IndexOf('=');
            if (separator <= 0)
                continue;
            string key = trimmed.Substring(0, separator).Trim();
            if (string.Equals(key, name, StringComparison.OrdinalIgnoreCase))
                return WebUtility.UrlDecode(trimmed.Substring(separator + 1).Trim());
        }

        return "";
    }

    private static string GetCookieValue(IReadOnlyDictionary<string, string>? headers, string name) {
        if (headers == null || string.IsNullOrWhiteSpace(name))
            return "";
        if (!headers.TryGetValue("Cookie", out string? cookieHeader) || string.IsNullOrWhiteSpace(cookieHeader))
            return "";
        foreach (string part in cookieHeader.Split(';')) {
            string trimmed = part.Trim();
            int separator = trimmed.IndexOf('=');
            if (separator <= 0)
                continue;
            string key = trimmed.Substring(0, separator).Trim();
            if (string.Equals(key, name, StringComparison.OrdinalIgnoreCase))
                return WebUtility.UrlDecode(trimmed.Substring(separator + 1).Trim());
        }

        return "";
    }

    private void SetAuthCookie(HttpRequest request, string token, DateTimeOffset expires) {
        Dictionary<string, string>? headers = request?.Context?.Response?.Headers;
        if (headers == null || string.IsNullOrWhiteSpace(token))
            return;
        int maxAge = Math.Max(1, (int)Math.Round((expires - DateTimeOffset.UtcNow).TotalSeconds));
        headers["Set-Cookie"] = WebAuthCookieName + "=" + WebUtility.UrlEncode(token) + "; Path=/; Max-Age=" + maxAge.ToString(CultureInfo.InvariantCulture) + "; SameSite=Lax; HttpOnly";
    }

    private void ClearAuthCookie(HttpRequest request) {
        Dictionary<string, string>? headers = request?.Context?.Response?.Headers;
        if (headers == null)
            return;
        headers["Set-Cookie"] = WebAuthCookieName + "=; Path=/; Max-Age=0; SameSite=Lax; HttpOnly";
    }

    private AccountRegistrationRequest SaveRegistrationRequest(string username, string password, string clientIp) {
        byte[] salt = RandomBytes(16);
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        var request = new AccountRegistrationRequest {
            Id = "regreq_" + Guid.NewGuid().ToString("N"),
            UserName = username,
            PasswordSalt = Convert.ToBase64String(salt),
            PasswordHash = HashPassword(password, salt),
            ClientIp = clientIp,
            Status = "pending",
            RequestedUtc = now
        };

        lock (_sync) {
            for (int i = 0; i < _registrationRequestsTable.Rows.Count; i++) {
                AccountRegistrationRequest existing = RegistrationRequestFromRow(_registrationRequestsTable.Rows[i]);
                if (!existing.Status.Equals("pending", StringComparison.OrdinalIgnoreCase) ||
                    !string.Equals(existing.UserName, username, StringComparison.OrdinalIgnoreCase))
                    continue;
                request.Id = existing.Id;
                request.Note = "Updated pending request.";
                _registrationRequestsTable.Rows[i] = RegistrationRequestToRow(request);
                _dataServer.Save();
                return request;
            }

            _registrationRequestsTable.Rows.Add(RegistrationRequestToRow(request));
            _dataServer.Save();
        }

        return request;
    }

    private List<AccountRegistrationRequest> GetRegistrationRequests() {
        lock (_sync) {
            return _registrationRequestsTable.Rows.Select(RegistrationRequestFromRow).ToList();
        }
    }

    private AccountRegistrationRequest DecideRegistrationRequest(string requestId, bool approved, string decidedBy, string note) {
        if (string.IsNullOrWhiteSpace(requestId))
            throw new InvalidOperationException("Registration request id is required.");

        lock (_sync) {
            for (int i = 0; i < _registrationRequestsTable.Rows.Count; i++) {
                AccountRegistrationRequest request = RegistrationRequestFromRow(_registrationRequestsTable.Rows[i]);
                if (!string.Equals(request.Id, requestId, StringComparison.OrdinalIgnoreCase))
                    continue;
                if (!request.Status.Equals("pending", StringComparison.OrdinalIgnoreCase))
                    throw new InvalidOperationException("Registration request has already been decided.");

                if (approved) {
                    if (GetAccount(request.UserName) != null)
                        throw new InvalidOperationException("A SocketJack user with that name already exists.");
                    string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                    var approvedAccount = ApplyBuiltInAdministratorRule(new AccountRecord {
                        UserName = request.UserName,
                        PasswordSalt = request.PasswordSalt,
                        PasswordHash = request.PasswordHash,
                        CreatedUtc = now,
                        UpdatedUtc = now,
                        Enabled = true,
                        LastClientIp = request.ClientIp
                    });
                    RememberAccountIp(approvedAccount, request.ClientIp);
                    SaveAccount(approvedAccount, overwrite: false);
                    MergeAutoSessionsForAccount(approvedAccount, request.ClientIp);
                }

                request.Status = approved ? "approved" : "denied";
                request.DecidedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
                request.DecidedBy = string.IsNullOrWhiteSpace(decidedBy) ? "admin" : decidedBy;
                request.Note = note ?? "";
                _registrationRequestsTable.Rows[i] = RegistrationRequestToRow(request);
                _dataServer.Save();
                return request;
            }
        }

        throw new InvalidOperationException("Registration request was not found.");
    }

    private object BuildAuthPayload(AccountRecord record, string token, bool authenticated, bool created, bool pending, bool refreshedByKnownIp = false) {
        return new {
            ok = true,
            authenticated,
            registered = authenticated,
            created,
            pending,
            refreshed = !string.IsNullOrWhiteSpace(token),
            refreshedByKnownIp,
            username = record.UserName,
            ownerKey = BuildOwnerKey(record.UserName),
            isAdministrator = record.IsAdministrator,
            tokenType = string.IsNullOrWhiteSpace(token) ? "" : "Bearer",
            accessToken = token,
            expiresUtc = record.TokenExpiresUtc,
            canRegisterOpen = !HasAnyAccountAdministrator(),
            usage = BuildUsage(record),
            table = _options.DatabaseName + "." + UsersTableName
        };
    }

    private static object BuildUsage(AccountRecord record) {
        long tokenLimit = Math.Max(0, record.TokenLimit);
        long tokensUsed = Math.Max(0, record.TokensUsed);
        bool unlimited = tokenLimit <= 0;
        return new {
            tokenLimit,
            tokensUsed,
            tokensRemaining = unlimited ? 0 : Math.Max(0, tokenLimit - tokensUsed),
            unlimited,
            ownerKey = BuildOwnerKey(record.UserName)
        };
    }

    private static object BuildAnonymousUsage() {
        return new { tokenLimit = 0, tokensUsed = 0, tokensRemaining = 0, unlimited = false, ownerKey = "" };
    }

    private void MergeAutoSessionsForAccount(AccountRecord? account, string clientIp) {
        if (account == null || string.IsNullOrWhiteSpace(account.UserName) || string.IsNullOrWhiteSpace(clientIp))
            return;

        bool changed = false;
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        lock (_sync) {
            for (int i = 0; i < _autoSessionsTable.Rows.Count; i++) {
                AutoSessionRecord session = AutoSessionFromRow(_autoSessionsTable.Rows[i]);
                if (session.Deleted)
                    continue;
                if (!string.IsNullOrWhiteSpace(session.OwnerUserName))
                    continue;
                if (!string.Equals(session.ClientIp, clientIp, StringComparison.OrdinalIgnoreCase))
                    continue;

                session.OwnerUserName = account.UserName;
                session.UpdatedUtc = now;
                _autoSessionsTable.Rows[i] = AutoSessionToRow(session);
                changed = true;
            }
            if (changed)
                _dataServer.Save();
        }
        if (changed)
            NotifyAutoLiveDataChanged();
    }

    private List<AutoSessionRecord> ListAutoSessionsForViewer(AccountRecord? account, string clientIp, bool includeArchived, string search) {
        Regex? regex = null;
        if (!string.IsNullOrWhiteSpace(search)) {
            try {
                regex = new Regex(search, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant, TimeSpan.FromMilliseconds(100));
            } catch {
                regex = null;
            }
        }

        lock (_sync) {
            return _autoSessionsTable.Rows
                .Select(AutoSessionFromRow)
                .Where(session => AutoSessionVisibleToViewer(session, account, clientIp))
                .Where(session => !session.Deleted)
                .Where(session => includeArchived || !session.Archived)
                .Where(session => AutoSessionMatchesSearch(session, search, regex))
                .OrderByDescending(session => session.UpdatedUtc, StringComparer.Ordinal)
                .Take(250)
                .ToList();
        }
    }

    private static bool AutoSessionVisibleToViewer(AutoSessionRecord session, AccountRecord? account, string clientIp) {
        if (session == null)
            return false;
        if (account != null && !string.IsNullOrWhiteSpace(session.OwnerUserName) &&
            string.Equals(session.OwnerUserName, account.UserName, StringComparison.OrdinalIgnoreCase))
            return true;
        return string.IsNullOrWhiteSpace(session.OwnerUserName) &&
               !string.IsNullOrWhiteSpace(clientIp) &&
               string.Equals(session.ClientIp, clientIp, StringComparison.OrdinalIgnoreCase);
    }

    private bool AutoSessionFilesVisibleToViewer(string sessionId, AccountRecord? account, string clientIp) {
        sessionId = SanitizeAutoSessionId(sessionId);
        if (string.IsNullOrWhiteSpace(sessionId) || account == null)
            return false;

        lock (_sync) {
            int index = FindAutoSessionRowIndexLocked(sessionId);
            if (index < 0)
                return true;

            AutoSessionRecord session = AutoSessionFromRow(_autoSessionsTable.Rows[index]);
            return AutoSessionVisibleToViewer(session, account, clientIp);
        }
    }

    private string AutoSessionFilesRootDirectory() {
        string dataPath = _options.ResolveDataFilePath();
        string directory = Path.GetDirectoryName(dataPath) ?? AppContext.BaseDirectory;
        return Path.Combine(directory, "AutoSessionFiles");
    }

    private string AutoSessionFilesDirectory(string sessionId) {
        sessionId = SanitizeAutoSessionId(sessionId);
        return Path.Combine(AutoSessionFilesRootDirectory(), sessionId);
    }

    private static bool TryResolveAutoSessionFilePath(string root, string candidate, out string resolvedPath) {
        resolvedPath = "";
        try {
            string rootFull = Path.GetFullPath(root);
            string candidateFull = Path.GetFullPath(candidate);
            if (!candidateFull.StartsWith(rootFull.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar) + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase) &&
                !candidateFull.Equals(rootFull, StringComparison.OrdinalIgnoreCase))
                return false;
            resolvedPath = candidateFull;
            return true;
        } catch {
            return false;
        }
    }

    private static string SanitizeAutoSessionFileName(string value, string mediaType) {
        string fileName = Path.GetFileName((value ?? "").Trim().Trim('"', '\'', '`'));
        if (string.IsNullOrWhiteSpace(fileName))
            fileName = "upload";
        fileName = Regex.Replace(fileName, @"[^A-Za-z0-9._ -]", "_").Trim();
        fileName = Regex.Replace(fileName, @"\s+", " ");
        while (fileName.Contains("..", StringComparison.Ordinal))
            fileName = fileName.Replace("..", ".", StringComparison.Ordinal);
        if (fileName.Length > 120) {
            string extension = Path.GetExtension(fileName);
            string stem = Path.GetFileNameWithoutExtension(fileName);
            int stemLength = Math.Max(1, 120 - extension.Length);
            fileName = stem.Substring(0, Math.Min(stem.Length, stemLength)) + extension;
        }
        if (string.IsNullOrWhiteSpace(Path.GetExtension(fileName)))
            fileName += AutoSessionExtensionForMime(mediaType);
        return string.IsNullOrWhiteSpace(fileName) ? "upload.bin" : fileName;
    }

    private static string SanitizeAutoSessionPathSegment(string value, string fallback) {
        string segment = (value ?? "").Trim().Trim('"', '\'', '`');
        segment = Regex.Replace(segment, @"[^A-Za-z0-9._ -]", "_").Trim();
        segment = Regex.Replace(segment, @"\s+", " ");
        while (segment.Contains("..", StringComparison.Ordinal))
            segment = segment.Replace("..", ".", StringComparison.Ordinal);
        segment = segment.Trim('.', ' ');
        if (string.IsNullOrWhiteSpace(segment))
            segment = fallback;
        if (segment.Length > 80)
            segment = segment.Substring(0, 80).Trim('.', ' ');
        return string.IsNullOrWhiteSpace(segment) ? fallback : segment;
    }

    private static string SanitizeAutoSessionRelativeFilePath(string value, string mediaType, string folder = "") {
        string normalized = (value ?? "").Trim().Trim('"', '\'', '`').Replace('\\', '/');
        string normalizedFolder = (folder ?? "").Trim().Trim('"', '\'', '`').Replace('\\', '/');
        var parts = new List<string>();

        foreach (string rawFolderPart in normalizedFolder.Split('/', StringSplitOptions.RemoveEmptyEntries)) {
            string folderPart = SanitizeAutoSessionPathSegment(rawFolderPart, "");
            if (!string.IsNullOrWhiteSpace(folderPart))
                parts.Add(folderPart);
        }

        string[] rawParts = normalized.Split('/', StringSplitOptions.RemoveEmptyEntries);
        for (int i = 0; i < Math.Max(0, rawParts.Length - 1); i++) {
            string folderPart = SanitizeAutoSessionPathSegment(rawParts[i], "");
            if (string.IsNullOrWhiteSpace(folderPart))
                continue;
            if (parts.Count == 1 && i == 0 && folderPart.Equals(parts[0], StringComparison.OrdinalIgnoreCase))
                continue;
            parts.Add(folderPart);
        }

        string filePart = rawParts.Length > 0 ? rawParts[^1] : normalized;
        parts.Add(SanitizeAutoSessionFileName(filePart, mediaType));
        return string.Join("/", parts.Where(part => !string.IsNullOrWhiteSpace(part)));
    }

    private static string BuildUniqueAutoSessionFilePath(string directory, string fileName) {
        string baseName = Path.GetFileNameWithoutExtension(fileName);
        string extension = Path.GetExtension(fileName);
        string path = Path.Combine(directory, fileName);
        for (int i = 2; File.Exists(path) && i < 10_000; i++)
            path = Path.Combine(directory, baseName + "-" + i.ToString(CultureInfo.InvariantCulture) + extension);
        return path;
    }

    private static string AutoSessionFileKind(string fileName) {
        string extension = Path.GetExtension(fileName).TrimStart('.').ToLowerInvariant();
        if (new[] { "png", "jpg", "jpeg", "gif", "webp", "bmp", "svg" }.Contains(extension))
            return "image";
        if (new[] { "mp4", "webm", "mov", "m4v", "ogv" }.Contains(extension))
            return "video";
        if (new[] { "wav", "mp3", "ogg", "flac", "m4a", "aac" }.Contains(extension))
            return "audio";
        if (new[] { "txt", "md", "json", "xml", "csv", "tsv", "log", "cs", "vb", "php", "js", "ts", "html", "css", "py", "cpp", "c", "h", "hpp", "sql", "ps1", "sh" }.Contains(extension))
            return "text";
        return extension.Length == 0 ? "file" : extension;
    }

    private static string AutoSessionExtensionForMime(string mediaType) {
        mediaType = (mediaType ?? "").Trim().ToLowerInvariant();
        return mediaType switch {
            "image/png" => ".png",
            "image/jpeg" => ".jpg",
            "image/webp" => ".webp",
            "image/gif" => ".gif",
            "image/bmp" => ".bmp",
            "image/svg+xml" => ".svg",
            "video/mp4" => ".mp4",
            "video/webm" => ".webm",
            "audio/mpeg" => ".mp3",
            "audio/wav" => ".wav",
            "text/plain" => ".txt",
            "application/json" => ".json",
            _ => ".bin"
        };
    }

    private static string AutoSessionMimeType(string extension) {
        extension = (extension ?? "").TrimStart('.').ToLowerInvariant();
        return extension switch {
            "png" => "image/png",
            "jpg" or "jpeg" => "image/jpeg",
            "webp" => "image/webp",
            "gif" => "image/gif",
            "bmp" => "image/bmp",
            "svg" => "image/svg+xml",
            "mp4" or "m4v" => "video/mp4",
            "webm" => "video/webm",
            "mov" => "video/quicktime",
            "ogv" => "video/ogg",
            "wav" => "audio/wav",
            "mp3" => "audio/mpeg",
            "ogg" => "audio/ogg",
            "flac" => "audio/flac",
            "m4a" => "audio/mp4",
            "aac" => "audio/aac",
            "txt" or "md" or "log" or "cs" or "vb" or "php" or "js" or "ts" or "html" or "css" or "py" or "cpp" or "c" or "h" or "hpp" or "sql" or "ps1" or "sh" => "text/plain; charset=utf-8",
            "json" => "application/json",
            "csv" => "text/csv; charset=utf-8",
            _ => "application/octet-stream"
        };
    }

    private static string AutoSessionRelativeFilePath(string directory, FileInfo file) {
        string path;
        try {
            path = Path.GetRelativePath(directory, file.FullName);
        } catch {
            path = file.Name;
        }
        return path.Replace(Path.DirectorySeparatorChar, '/').Replace(Path.AltDirectorySeparatorChar, '/').TrimStart('/');
    }

    private static IEnumerable<FileInfo> EnumerateAutoSessionFiles(string directory) {
        DirectoryInfo directoryInfo = new(directory);
        if (!directoryInfo.Exists)
            return Array.Empty<FileInfo>();
        try {
            return directoryInfo.EnumerateFiles("*", SearchOption.AllDirectories).ToArray();
        } catch {
            return Array.Empty<FileInfo>();
        }
    }

    private static void RemoveEmptyAutoSessionDirectories(string directory) {
        if (string.IsNullOrWhiteSpace(directory) || !Directory.Exists(directory))
            return;
        foreach (string child in Directory.EnumerateDirectories(directory, "*", SearchOption.AllDirectories).OrderByDescending(path => path.Length)) {
            try {
                if (!Directory.EnumerateFileSystemEntries(child).Any())
                    Directory.Delete(child);
            } catch {
            }
        }
    }

    private static object BuildAutoSessionFileEntry(HttpRequest request, string sessionId, string directory, FileInfo file) {
        string path = AutoSessionRelativeFilePath(directory, file);
        string name = path;
        string displayName = file.Name;
        string url = "/auto/session-file?sessionId=" + Uri.EscapeDataString(sessionId) + "&name=" + Uri.EscapeDataString(path);
        string contentType = AutoSessionMimeType(file.Extension);
        return new {
            type = "file",
            source = "auto-upload",
            sessionId,
            path,
            name,
            displayName,
            relativePath = path,
            kind = AutoSessionFileKind(name),
            mimeType = contentType,
            sizeBytes = file.Length,
            uploadedUtc = file.LastWriteTimeUtc.ToString("O", CultureInfo.InvariantCulture),
            url
        };
    }

    private object[] ListAutoSessionFileEntries(HttpRequest request, string sessionId) {
        string directory = AutoSessionFilesDirectory(sessionId);
        return EnumerateAutoSessionFiles(directory)
            .OrderByDescending(file => file.LastWriteTimeUtc)
            .Take(120)
            .Select(file => BuildAutoSessionFileEntry(request, sessionId, directory, file))
            .ToArray();
    }

    private static bool AutoSessionMatchesSearch(AutoSessionRecord session, string search, Regex? regex) {
        if (string.IsNullOrWhiteSpace(search))
            return true;
        string haystack = string.Join("\n", session.Title, session.PreviewText, session.ServerTitle, session.ServerHardwareSummary, session.ModelUsed, session.LastMode, session.BillingTier);
        if (regex != null)
            return regex.IsMatch(haystack);
        return haystack.Contains(search, StringComparison.OrdinalIgnoreCase);
    }

    private static string[] BuildAutoSessionSuggestions(List<AutoSessionRecord> sessions) {
        return sessions
            .SelectMany(session => new[] { session.Title, session.ServerTitle, session.ModelUsed, session.LastMode, session.BillingTier })
            .Select(value => (value ?? "").Trim())
            .Where(value => !string.IsNullOrWhiteSpace(value))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(value => value, StringComparer.OrdinalIgnoreCase)
            .Take(80)
            .ToArray();
    }

    private AutoSessionRecord SaveAutoSessionForViewer(AutoSessionRecord session, AccountRecord? account, string clientIp) {
        string now = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        if (string.IsNullOrWhiteSpace(session.Id))
            session.Id = "auto_" + Guid.NewGuid().ToString("N");
        session.Id = SanitizeAutoSessionId(session.Id);
        if (string.IsNullOrWhiteSpace(session.CreatedUtc))
            session.CreatedUtc = now;
        session.UpdatedUtc = now;
        session.OwnerUserName = account?.UserName ?? "";
        session.ClientIp = clientIp ?? "";
        NormalizeAutoSession(session);

        lock (_sync) {
            int existingIndex = FindAutoSessionRowIndexLocked(session.Id);
            if (existingIndex >= 0) {
                AutoSessionRecord existing = AutoSessionFromRow(_autoSessionsTable.Rows[existingIndex]);
                if (!AutoSessionVisibleToViewer(existing, account, clientIp ?? ""))
                    throw new InvalidOperationException("Auto session is not available to this viewer.");
                session.CreatedUtc = FirstNonEmpty(existing.CreatedUtc, session.CreatedUtc);
                session.Archived = session.Archived || existing.Archived;
                session.Deleted = session.Deleted || existing.Deleted;
                _autoSessionsTable.Rows[existingIndex] = AutoSessionToRow(session);
            } else {
                _autoSessionsTable.Rows.Add(AutoSessionToRow(session));
            }
            TrimAutoSessionsLocked();
            _dataServer.Save();
        }

        NotifyAutoLiveDataChanged();
        return session;
    }

    private AutoSessionRecord? ApplyAutoSessionAction(string id, string action, string title, AccountRecord? account, string clientIp) {
        id = SanitizeAutoSessionId(id);
        if (string.IsNullOrWhiteSpace(id))
            throw new InvalidOperationException("Auto session id is required.");

        lock (_sync) {
            int index = FindAutoSessionRowIndexLocked(id);
            if (index < 0)
                throw new InvalidOperationException("Auto session was not found.");
            AutoSessionRecord session = AutoSessionFromRow(_autoSessionsTable.Rows[index]);
            if (!AutoSessionVisibleToViewer(session, account, clientIp))
                throw new InvalidOperationException("Auto session is not available to this viewer.");

            if (action.Equals("delete", StringComparison.OrdinalIgnoreCase)) {
                session.Deleted = true;
            } else if (action.Equals("archive", StringComparison.OrdinalIgnoreCase)) {
                session.Archived = true;
            } else if (action.Equals("unarchive", StringComparison.OrdinalIgnoreCase)) {
                session.Archived = false;
            } else if (action.Equals("rename", StringComparison.OrdinalIgnoreCase)) {
                session.Title = LimitAutoSessionText(title, 120);
            } else {
                throw new InvalidOperationException("Unknown Auto session action.");
            }
            session.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
            NormalizeAutoSession(session);
            _autoSessionsTable.Rows[index] = AutoSessionToRow(session);
            _dataServer.Save();
            NotifyAutoLiveDataChanged();
            return session.Deleted ? null : session;
        }
    }

    private int FindAutoSessionRowIndexLocked(string id) {
        for (int i = 0; i < _autoSessionsTable.Rows.Count; i++) {
            AutoSessionRecord session = AutoSessionFromRow(_autoSessionsTable.Rows[i]);
            if (string.Equals(session.Id, id, StringComparison.OrdinalIgnoreCase))
                return i;
        }
        return -1;
    }

    private void TrimAutoSessionsLocked() {
        const int maxRows = 2000;
        while (_autoSessionsTable.Rows.Count > maxRows)
            _autoSessionsTable.Rows.RemoveAt(_autoSessionsTable.Rows.Count - 1);
    }

    private static AutoSessionRecord AutoSessionFromJson(JsonElement root) {
        string messagesJson = GetJsonString(root, "messagesJson");
        if (string.IsNullOrWhiteSpace(messagesJson) && root.ValueKind == JsonValueKind.Object && root.TryGetProperty("messages", out JsonElement messages))
            messagesJson = messages.GetRawText();

        return new AutoSessionRecord {
            Id = FirstNonEmpty(GetJsonString(root, "id"), GetJsonString(root, "sessionId")),
            Title = GetJsonString(root, "title"),
            CreatedUtc = GetJsonString(root, "createdUtc"),
            UpdatedUtc = GetJsonString(root, "updatedUtc"),
            LastMode = GetJsonString(root, "lastMode"),
            OriginMode = GetJsonString(root, "originMode"),
            BillingTier = GetJsonString(root, "billingTier"),
            TokenCost = Math.Max(0, GetJsonLong(root, "tokenCost", 0)),
            ServerId = GetJsonString(root, "serverId"),
            ServerTitle = GetJsonString(root, "serverTitle"),
            ServerHardwareSummary = GetJsonString(root, "serverHardwareSummary"),
            ServerContinueUrl = GetJsonString(root, "serverContinueUrl"),
            ModelUsed = GetJsonString(root, "modelUsed"),
            MessageLength = Math.Max(0, (int)GetJsonLong(root, "messageLength", 0)),
            MessageCount = Math.Max(0, (int)GetJsonLong(root, "messageCount", 0)),
            PreviewText = GetJsonString(root, "previewText"),
            MessagesJson = messagesJson,
            Archived = GetJsonBool(root, "archived", false),
            Deleted = GetJsonBool(root, "deleted", false)
        };
    }

    private AutoSessionRecord AutoSessionFromRow(object[] row) {
        row = NormalizeRow(row, AutoSessionColumns.Length);
        return new AutoSessionRecord {
            Id = Cell(row, 0),
            OwnerUserName = Cell(row, 1),
            ClientIp = Cell(row, 2),
            Title = Cell(row, 3),
            CreatedUtc = Cell(row, 4),
            UpdatedUtc = Cell(row, 5),
            LastMode = Cell(row, 6),
            OriginMode = Cell(row, 7),
            BillingTier = Cell(row, 8),
            TokenCost = Math.Max(0, ParseLong(Cell(row, 9), 0)),
            ServerId = Cell(row, 10),
            ServerTitle = Cell(row, 11),
            ServerHardwareSummary = Cell(row, 12),
            ServerContinueUrl = Cell(row, 13),
            ModelUsed = Cell(row, 14),
            MessageLength = Math.Max(0, (int)ParseLong(Cell(row, 15), 0)),
            MessageCount = Math.Max(0, (int)ParseLong(Cell(row, 16), 0)),
            PreviewText = Cell(row, 17),
            MessagesJson = Cell(row, 18),
            Archived = ParseBool(Cell(row, 19), false),
            Deleted = ParseBool(Cell(row, 20), false)
        };
    }

    private object[] AutoSessionToRow(AutoSessionRecord session) {
        NormalizeAutoSession(session);
        return NormalizeRow(new object[] {
            session.Id,
            session.OwnerUserName,
            session.ClientIp,
            session.Title,
            session.CreatedUtc,
            session.UpdatedUtc,
            session.LastMode,
            session.OriginMode,
            session.BillingTier,
            Math.Max(0, session.TokenCost).ToString(CultureInfo.InvariantCulture),
            session.ServerId,
            session.ServerTitle,
            session.ServerHardwareSummary,
            session.ServerContinueUrl,
            session.ModelUsed,
            Math.Max(0, session.MessageLength).ToString(CultureInfo.InvariantCulture),
            Math.Max(0, session.MessageCount).ToString(CultureInfo.InvariantCulture),
            session.PreviewText,
            session.MessagesJson,
            session.Archived ? "true" : "false",
            session.Deleted ? "true" : "false"
        }, AutoSessionColumns.Length);
    }

    private static void NormalizeAutoSession(AutoSessionRecord session) {
        session.Id = SanitizeAutoSessionId(session.Id);
        session.OwnerUserName = LimitAutoSessionText(session.OwnerUserName, 80);
        session.ClientIp = LimitAutoSessionText(session.ClientIp, 80);
        session.Title = LimitAutoSessionText(FirstNonEmpty(session.Title, session.PreviewText, "New Auto session"), 120);
        session.LastMode = NormalizeAutoMode(session.LastMode);
        session.OriginMode = NormalizeAutoOriginMode(session.OriginMode);
        session.BillingTier = LimitAutoSessionText(FirstNonEmpty(session.BillingTier, "Free"), 20);
        session.ServerId = LimitAutoSessionText(session.ServerId, 160);
        session.ServerTitle = LimitAutoSessionText(session.ServerTitle, 160);
        session.ServerHardwareSummary = LimitAutoSessionText(session.ServerHardwareSummary, 240);
        session.ServerContinueUrl = LimitAutoSessionText(AppendAutoSessionToUrl(session.ServerContinueUrl, session.Id), 600);
        session.ModelUsed = LimitAutoSessionText(CleanAutoModelDisplayName(session.ModelUsed), 220);
        session.PreviewText = LimitAutoSessionText(session.PreviewText, 240);
        if (session.MessagesJson != null && session.MessagesJson.Length > 120_000)
            session.MessagesJson = session.MessagesJson.Substring(0, 120_000);
    }

    private static string SanitizeAutoSessionId(string id) {
        id = (id ?? "").Trim();
        if (id.Length == 0)
            return "";
        id = Regex.Replace(id, @"[^A-Za-z0-9_.:-]", "_");
        return id.Length <= 96 ? id : id.Substring(0, 96);
    }

    private static string LimitAutoSessionText(string value, int max) {
        value = (value ?? "").Trim();
        if (value.Length <= max)
            return value;
        return value.Substring(0, max);
    }

    private static string AppendAutoSessionToUrl(string url, string sessionId) {
        url = (url ?? "").Trim();
        sessionId = SanitizeAutoSessionId(sessionId);
        if (string.IsNullOrWhiteSpace(url) || string.IsNullOrWhiteSpace(sessionId))
            return url;
        try {
            Uri baseUri = Uri.TryCreate(url, UriKind.Absolute, out Uri? absolute) ? absolute : new Uri(new Uri("https://socketjack.com/"), url);
            string left = url.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || url.StartsWith("https://", StringComparison.OrdinalIgnoreCase)
                ? baseUri.GetLeftPart(UriPartial.Path)
                : baseUri.AbsolutePath;
            string queryText = baseUri.Query.TrimStart('?');
            var pairs = new List<string>();
            if (!string.IsNullOrWhiteSpace(queryText)) {
                pairs.AddRange(queryText.Split('&', StringSplitOptions.RemoveEmptyEntries)
                    .Where(pair => !pair.StartsWith("sessionId=", StringComparison.OrdinalIgnoreCase) && !pair.StartsWith("autoSession=", StringComparison.OrdinalIgnoreCase)));
            }
            pairs.Add("sessionId=" + Uri.EscapeDataString(sessionId));
            pairs.Add("autoSession=" + Uri.EscapeDataString(sessionId));
            return left + "?" + string.Join("&", pairs) + baseUri.Fragment;
        } catch {
            char join = url.Contains('?') ? '&' : '?';
            return url + join + "sessionId=" + Uri.EscapeDataString(sessionId) + "&autoSession=" + Uri.EscapeDataString(sessionId);
        }
    }

    private static string BuildOwnerKey(string username) {
        return string.IsNullOrWhiteSpace(username) ? "" : "webauth:" + username.Trim().ToLowerInvariant();
    }

    private AccountRecord AccountFromRow(object[] row) {
        row = NormalizeRow(row, AccountColumns.Length);
        return ApplyBuiltInAdministratorRule(new AccountRecord {
            UserName = Cell(row, 0),
            PasswordSalt = Cell(row, 1),
            PasswordHash = Cell(row, 2),
            CreatedUtc = Cell(row, 3),
            UpdatedUtc = Cell(row, 4),
            LastLoginUtc = Cell(row, 5),
            TokenHash = Cell(row, 6),
            TokenExpiresUtc = Cell(row, 7),
            Enabled = ParseBool(Cell(row, 8), true),
            LastClientIp = Cell(row, 9),
            TokenLimit = Math.Max(0, ParseLong(Cell(row, 10), 0)),
