    public AccountRecord UpdateAccountForUi(string username, bool enabled, bool isAdministrator, bool autoPublish, long tokenLimit, bool resetTokens, long tokenDelta) {
        AccountRecord record = GetAccount(username) ?? throw new InvalidOperationException("SocketJack user was not found.");
        record.Enabled = enabled;
        record.IsAdministrator = isAdministrator;
        record.AutoPublish = autoPublish;
        record.TokenLimit = Math.Max(0, tokenLimit);
        if (resetTokens)
            record.TokensUsed = 0;
        if (tokenDelta != 0)
            record.TokenLimit = Math.Max(0, record.TokenLimit + tokenDelta);
        record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture);
        UpsertAccount(record);
        AppendMasterLog("info", "account-admin", "Updated SocketJack account " + record.UserName + ".", "tokenLimit=" + record.TokenLimit.ToString(CultureInfo.InvariantCulture));
        return record;
    }

    public List<AccountRegistrationRequest> GetRegistrationRequestsForUi(bool pendingOnly) {
        List<AccountRegistrationRequest> requests = GetRegistrationRequests();
        if (pendingOnly)
            requests = requests.Where(request => request.Status.Equals("pending", StringComparison.OrdinalIgnoreCase)).ToList();
        return requests
            .OrderByDescending(request => request.RequestedUtc, StringComparer.Ordinal)
            .ToList();
    }

    public AccountRegistrationRequest DecideRegistrationRequestForUi(string requestId, bool approved, string decidedBy, string note) {
        AccountRegistrationRequest request = DecideRegistrationRequest(requestId, approved, decidedBy, note);
        AppendMasterLog("info", "registration-admin", (approved ? "Approved " : "Denied ") + request.UserName + ".", note);
        return request;
    }

