    public List<MasterRouteStatusItem> GetRouteStatusItemsForUi() {
        bool jackcastHttpListening = _options.JackcastEnabled &&
            (_options.JackcastDedicatedListenersEnabled
                ? _jackcastServer?.IsListening == true
                : _websiteServer.IsListening);
        bool jackcastHttpsListening = _options.JackcastEnabled &&
            _options.JackcastSslEnabled &&
            (_options.JackcastDedicatedListenersEnabled
                ? _jackcastSslServer?.IsListening == true
                : _websiteSslServer?.IsListening == true);
        string jackcastHttpPort = _options.JackcastDedicatedListenersEnabled
            ? _options.JackcastBindAddress + ":" + _options.WebsitePort.ToString(CultureInfo.InvariantCulture)
            : "Host proxy on website :" + _options.WebsitePort.ToString(CultureInfo.InvariantCulture);
        string jackcastHttpsPort = _options.JackcastDedicatedListenersEnabled
            ? _options.JackcastBindAddress + ":" + _options.WebsiteSslPort.ToString(CultureInfo.InvariantCulture)
            : "SNI host proxy on website :" + _options.WebsiteSslPort.ToString(CultureInfo.InvariantCulture);
        string jackcastHttpStatus = !_options.JackcastEnabled
            ? "Disabled"
            : jackcastHttpListening
                ? (_options.JackcastDedicatedListenersEnabled ? "Listening" : "Forwarding by Host header")
                : "Stopped";
        string jackcastHttpsStatus = !_options.JackcastEnabled || !_options.JackcastSslEnabled
            ? "Disabled"
            : jackcastHttpsListening
                ? (_options.JackcastDedicatedListenersEnabled ? "Listening" : "Forwarding by SNI/Host")
                : FirstNonEmpty(_jackcastSslError, "Stopped");
        var routes = new List<MasterRouteStatusItem> {
            new("API", _server.IsListening, _options.PublicUrl, _options.Port.ToString(CultureInfo.InvariantCulture), _server.IsListening ? "Listening" : "Stopped"),
            new("Website HTTP", _websiteServer.IsListening, _options.WebsitePublicUrl, _options.WebsitePort.ToString(CultureInfo.InvariantCulture), _websiteServer.IsListening ? "Listening" : "Stopped"),
            new("Website HTTPS", _websiteSslServer?.IsListening == true, _options.WebsitePublicUrl, _options.WebsiteSslPort.ToString(CultureInfo.InvariantCulture), _websiteSslServer == null ? FirstNonEmpty(_websiteSslError, "HTTPS disabled or certificate unavailable") : (_websiteSslServer.IsListening ? "Listening" : "Stopped")),
            new("SecureAuthority", true, _options.SecureAuthorityTargetUrl, "/SecureAuthority/*", "Proxies update authority traffic to the private target"),
            new("JackCast HTTP", jackcastHttpListening, _options.JackcastTargetUrl, jackcastHttpPort, jackcastHttpStatus),
            new("JackCast HTTPS", jackcastHttpsListening, _options.JackcastTargetUrl, jackcastHttpsPort, jackcastHttpsStatus),
            new("SQL Admin", IsSqlAdminPanelEnabled(), SqlAdminUrl, _options.DatabaseName + "." + _options.TableName, GetSqlAdminPanelListenerStatus()),
            new("Update Files", Directory.Exists(ResolveJackLLMUpdateDirectory()), JackLLMUpdatePublicBaseUrl, ResolveJackLLMUpdateDirectory(), Directory.Exists(ResolveJackLLMUpdateDirectory()) ? "Directory available" : "Directory missing")
        };

        return routes;
    }

