        report.CreatedUtc = TruncateText(FirstNonEmpty(report.CreatedUtc, DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)), 64);
        report.Severity = TruncateText(FirstNonEmpty(report.Severity, "info"), 32);
        report.Category = TruncateText(FirstNonEmpty(report.Category, "runtime-report"), 96);
        report.PrimaryProvider = TruncateText(report.PrimaryProvider, 120);
        report.FallbackProvider = TruncateText(report.FallbackProvider, 120);
        report.Operation = TruncateText(report.Operation, 120);
        report.Reason = TruncateText(report.Reason, 1200);
        report.Detail = TruncateText(report.Detail, 6000);
        report.MachineName = TruncateText(report.MachineName, 160);
        report.ServerId = TruncateText(report.ServerId, 160);
        report.ServerName = TruncateText(report.ServerName, 220);
        report.OwnerUserName = TruncateText(report.OwnerUserName, 160);
        report.ReportedByUserName = TruncateText(report.ReportedByUserName, 160);
        report.PublicHost = TruncateText(report.PublicHost, 220);
        report.SelectedProvider = TruncateText(report.SelectedProvider, 80);
        report.ClientName = TruncateText(report.ClientName, 120);
        report.ClientIp = TruncateText(report.ClientIp, 120);
