    private static void TrimTableRows(Table table, int maxRows) {
        if (table == null || maxRows <= 0)
            return;
        while (table.Rows.Count > maxRows)
            table.Rows.RemoveAt(0);
    }

    private static string TruncateText(string value, int maxLength) {
        value ??= "";
        if (maxLength <= 0 || value.Length <= maxLength)
            return value;
        return value.Substring(0, Math.Max(0, maxLength - 3)) + "...";
    }

    private static object[] NormalizeRow(object[] row, int count) {
        row ??= Array.Empty<object>();
        if (row.Length < count)
            Array.Resize(ref row, count);
        for (int i = 0; i < row.Length; i++)
            row[i] ??= "";
        return row;
    }

    private static string Cell(object[] row, int index) {
        return index >= 0 && index < row.Length ? row[index]?.ToString() ?? "" : "";
    }

    private string HashPassword(string password, byte[] salt) {
        using var derive = new Rfc2898DeriveBytes(password ?? "", salt, WebAuthPasswordHashIterations, HashAlgorithmName.SHA256);
        return Convert.ToBase64String(derive.GetBytes(32));
    }

    private bool VerifyPassword(string password, string saltBase64, string expectedHash) {
        try {
            byte[] salt = Convert.FromBase64String(saltBase64 ?? "");
            return ConstantTimeEquals(HashPassword(password, salt), expectedHash);
        } catch {
            return false;
        }
    }

    private static string HashToken(string token) {
        return Convert.ToBase64String(SHA256.HashData(Encoding.UTF8.GetBytes(token ?? "")));
    }

    private static byte[] RandomBytes(int count) {
        byte[] bytes = new byte[Math.Max(1, count)];
        RandomNumberGenerator.Fill(bytes);
        return bytes;
    }

    private static string Base64Url(byte[] bytes) {
        return Convert.ToBase64String(bytes ?? Array.Empty<byte>()).TrimEnd('=').Replace('+', '-').Replace('/', '_');
    }

    private static bool ConstantTimeEquals(string leftBase64, string rightBase64) {
        if (string.IsNullOrEmpty(leftBase64) || string.IsNullOrEmpty(rightBase64))
            return false;
        byte[] left = Encoding.UTF8.GetBytes(leftBase64);
        byte[] right = Encoding.UTF8.GetBytes(rightBase64);
        return left.Length == right.Length && CryptographicOperations.FixedTimeEquals(left, right);
    }

    private static bool TryNormalizeUserName(string username, out string normalized, out string error) {
        normalized = (username ?? "").Trim();
        error = "";
        if (normalized.Length < 3 || normalized.Length > 80) {
            error = "Username must be between 3 and 80 characters.";
            return false;
        }
        foreach (char ch in normalized) {
            if (!(char.IsLetterOrDigit(ch) || ch == '_' || ch == '-' || ch == '.' || ch == '@')) {
                error = "Username can only contain letters, numbers, underscore, dash, dot, or @.";
                return false;
            }
        }
        return true;
    }

    private static bool IsValidPassword(string password, out string error) {
        error = "";
        if (string.IsNullOrEmpty(password) || password.Length < 8) {
            error = "Password must be at least 8 characters.";
            return false;
        }
        return true;
    }

    private static void RememberAccountIp(AccountRecord record, string clientIp) {
        if (record == null || string.IsNullOrWhiteSpace(clientIp))
            return;
        clientIp = clientIp.Trim();
        record.LastClientIp = clientIp;
        List<string> ips = SplitKnownClientIps(record.KnownClientIps);
        if (!ips.Any(ip => string.Equals(ip, clientIp, StringComparison.OrdinalIgnoreCase)))
            ips.Add(clientIp);
        record.KnownClientIps = string.Join(";", ips.TakeLast(20));
    }

    private static void ForgetAccountIp(AccountRecord record, string clientIp) {
        if (record == null || string.IsNullOrWhiteSpace(clientIp))
            return;
        List<string> ips = SplitKnownClientIps(record.KnownClientIps)
            .Where(ip => !string.Equals(ip, clientIp.Trim(), StringComparison.OrdinalIgnoreCase))
            .ToList();
        record.KnownClientIps = string.Join(";", ips);
        if (string.Equals(record.LastClientIp, clientIp.Trim(), StringComparison.OrdinalIgnoreCase))
            record.LastClientIp = ips.LastOrDefault() ?? "";
    }

    private static bool AccountHasKnownIp(AccountRecord record, string clientIp) {
        if (record == null || string.IsNullOrWhiteSpace(clientIp))
            return false;
        clientIp = clientIp.Trim();
        if (string.Equals(record.LastClientIp, clientIp, StringComparison.OrdinalIgnoreCase))
            return true;
        return SplitKnownClientIps(record.KnownClientIps)
            .Any(ip => string.Equals(ip, clientIp, StringComparison.OrdinalIgnoreCase));
    }

    private static List<string> SplitKnownClientIps(string value) {
        return (value ?? "")
            .Split(new[] { ';', ',', '\n', '\r', '\t', ' ' }, StringSplitOptions.RemoveEmptyEntries)
            .Select(ip => ip.Trim())
            .Where(ip => !string.IsNullOrWhiteSpace(ip))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToList();
    }

    private static string ExtractClientIp(NetworkConnection? connection, HttpRequest? request) {
        if (request?.Headers != null) {
            foreach (string headerName in new[] { "CF-Connecting-IP", "X-Real-IP", "X-Forwarded-For" }) {
                if (!request.Headers.TryGetValue(headerName, out string? headerValue) || string.IsNullOrWhiteSpace(headerValue))
                    continue;
                string candidate = headerValue.Split(',').Select(part => part.Trim()).FirstOrDefault(part => !string.IsNullOrWhiteSpace(part)) ?? "";
                if (!string.IsNullOrWhiteSpace(candidate))
                    return candidate;
            }
        }
        return ExtractClientIp(connection);
    }

    private static string ExtractClientIp(NetworkConnection? connection) {
        return connection?.EndPoint?.Address?.ToString() ?? "";
    }

    private static string ExtractClientIp(NetworkConnection? connection, IReadOnlyDictionary<string, string>? headers) {
        if (headers != null) {
            foreach (string headerName in new[] { "CF-Connecting-IP", "X-Real-IP", "X-Forwarded-For" }) {
                if (!headers.TryGetValue(headerName, out string? headerValue) || string.IsNullOrWhiteSpace(headerValue))
                    continue;
                string candidate = headerValue.Split(',').Select(part => part.Trim()).FirstOrDefault(part => !string.IsNullOrWhiteSpace(part)) ?? "";
                if (!string.IsNullOrWhiteSpace(candidate))
                    return candidate;
            }
        }
        return ExtractClientIp(connection);
    }

    private static Dictionary<string, string> ParseWebSocketQueryString(string queryString) {
        var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        if (string.IsNullOrWhiteSpace(queryString))
            return values;
        string trimmedQuery = queryString.TrimStart('?');
        foreach (string part in trimmedQuery.Split('&', StringSplitOptions.RemoveEmptyEntries)) {
            int separator = part.IndexOf('=');
            string key = separator >= 0 ? part.Substring(0, separator) : part;
            string value = separator >= 0 ? part.Substring(separator + 1) : "";
            key = WebUtility.UrlDecode(key.Replace('+', ' ')).Trim();
            if (string.IsNullOrWhiteSpace(key))
                continue;
            values[key] = WebUtility.UrlDecode(value.Replace('+', ' '));
        }
        return values;
    }

    private static string QueryValue(IReadOnlyDictionary<string, string>? query, string name) =>
        query != null && query.TryGetValue(name, out string? value)
            ? value ?? ""
            : "";

    private static void ValidatePublishableHost(RegisteredServer server, string remoteIp) {
        if (IsLocalRegistrationClient(remoteIp))
            return;

        string blocked = FirstBlockedAdvertisedHost(
            server.ConnectHost,
            server.IpAddress,
            ExtractHostFromEndpoint(server.Endpoint));
        if (!string.IsNullOrWhiteSpace(blocked))
            throw new InvalidOperationException("Refusing to publish private/local host '" + blocked + "' from non-local client " + (string.IsNullOrWhiteSpace(remoteIp) ? "unknown" : remoteIp) + ".");
    }

    private static string FirstBlockedAdvertisedHost(params string[] hosts) {
        foreach (string host in hosts) {
            string normalized = NormalizeValidationHost(host);
            if (string.IsNullOrWhiteSpace(normalized))
                continue;
            if (IsBlockedAdvertisedHost(normalized))
                return normalized;
        }

        return "";
    }

    private static bool IsBlockedAdvertisedHost(string host) {
        if (string.Equals(host, "localhost", StringComparison.OrdinalIgnoreCase))
            return true;
        if (host.StartsWith("127.", StringComparison.OrdinalIgnoreCase))
            return true;
        if (host.StartsWith("192.168.", StringComparison.OrdinalIgnoreCase))
            return true;
        return IPAddress.TryParse(host, out IPAddress? address) &&
               (IPAddress.IsLoopback(address) || IsPrivate192168(address));
    }

    private static bool IsPrivate192168(IPAddress address) {
        byte[] bytes = address.GetAddressBytes();
        return address.AddressFamily == AddressFamily.InterNetwork &&
               bytes.Length == 4 &&
               bytes[0] == 192 &&
               bytes[1] == 168;
    }

    private static bool IsLocalRegistrationClient(string remoteIp) {
        string normalized = NormalizeValidationHost(remoteIp);
        if (string.IsNullOrWhiteSpace(normalized))
            return false;
        if (string.Equals(normalized, "localhost", StringComparison.OrdinalIgnoreCase))
            return true;
        return IPAddress.TryParse(normalized, out IPAddress? address) &&
               (IPAddress.IsLoopback(address) || IsLocalMachineAddress(address));
    }

    private static bool IsLocalMachineAddress(IPAddress address) {
        address = NormalizeComparableAddress(address);
        try {
            foreach (NetworkInterface adapter in NetworkInterface.GetAllNetworkInterfaces()) {
                if (adapter.OperationalStatus != OperationalStatus.Up)
                    continue;

                foreach (UnicastIPAddressInformation unicast in adapter.GetIPProperties().UnicastAddresses) {
                    IPAddress local = NormalizeComparableAddress(unicast.Address);
                    if (local.Equals(address))
                        return true;
                }
            }
        } catch {
        }

        try {
            foreach (IPAddress local in Dns.GetHostAddresses(Dns.GetHostName())) {
                if (NormalizeComparableAddress(local).Equals(address))
                    return true;
            }
        } catch {
        }

        return false;
    }

    private static IPAddress NormalizeComparableAddress(IPAddress address) {
        if (address.IsIPv4MappedToIPv6)
            return address.MapToIPv4();
        return address;
    }

    private static string ExtractHostFromEndpoint(string endpoint) {
        if (string.IsNullOrWhiteSpace(endpoint))
            return "";
        if (Uri.TryCreate(endpoint.Trim(), UriKind.Absolute, out Uri? uri))
            return uri.Host;
        return endpoint;
    }

    private static string NormalizeValidationHost(string value) {
        value = (value ?? "").Trim();
        if (value.Length == 0)
            return "";
        if (value.StartsWith("::ffff:", StringComparison.OrdinalIgnoreCase))
            value = value.Substring(7);
        return RegisteredServer.NormalizeExternalHost(value);
    }

    private static long TryParseUnixTime(string value) {
        return DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed)
            ? parsed.ToUnixTimeSeconds()
            : 0;
    }

    private static string GetJsonString(JsonElement element, string name) {
        if (element.ValueKind != JsonValueKind.Object)
            return "";
        foreach (JsonProperty property in element.EnumerateObject()) {
            if (!string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase))
                continue;
            return RegisteredServer.JsonValueToText(property.Value);
        }
        return "";
    }

    private static long GetJsonLong(JsonElement element, string name, long fallback) {
        string text = GetJsonString(element, name);
        return long.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out long value) ? value : fallback;
    }

    private static bool GetJsonBool(JsonElement element, string name, bool fallback) {
        string text = GetJsonString(element, name);
        return bool.TryParse(text, out bool value) ? value : fallback;
    }

    private static bool ParseBool(string text, bool fallback) {
        return bool.TryParse(text, out bool value) ? value : fallback;
    }

    private static long ParseLong(string text, long fallback) {
        return long.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out long value) ? value : fallback;
    }

    private static string FirstNonEmpty(params string?[] values) {
        foreach (string? value in values) {
            if (!string.IsNullOrWhiteSpace(value))
                return value.Trim();
        }

        return "";
    }

