.diagram-node:last-child::after { display: none; }
.diagram-node strong {
    display: block;
    margin-bottom: 7px;
    color: #ffffff;
    overflow-wrap: anywhere;
}
.diagram-node span {
    color: var(--muted);
    font-size: 0.88rem;
    line-height: 1.5;
    overflow-wrap: anywhere;
}
.diagram-return {
    margin-top: 14px;
    border: 1px dashed rgba(104, 245, 180, 0.38);
    border-radius: 8px;
    padding: 11px 13px;
    color: rgba(217,255,237,0.86);
    background: rgba(104, 245, 180, 0.08);
}
.tech-grid {
    display: grid;
    grid-template-columns: repeat(4, minmax(0,1fr));
    gap: 12px;
}
.tech-card {
    min-height: 144px;
}
.tech-label {
    display: inline-flex;
    margin-bottom: 12px;
    color: #07111f;
    border-radius: 999px;
    padding: 5px 8px;
    background: linear-gradient(90deg, var(--cyan), var(--green));
    font-size: 0.72rem;
    font-weight: 1000;
}
.guide-grid {
    display: grid;
    grid-template-columns: repeat(4, minmax(0,1fr));
    gap: 12px;
}
.guide-card {
    display: grid;
    gap: 12px;
    min-height: 330px;
}
.guide-card.featured-guide {
    grid-column: span 2;
    min-height: 430px;
}
.step-number {
    width: 34px;
    height: 34px;
    display: grid;
    place-items: center;
    border-radius: 8px;
    color: #06111e;
    font-weight: 1000;
    background: linear-gradient(135deg, var(--cyan), var(--pink));
}
.shot-placeholder {
    min-height: 138px;
    display: grid;
    place-items: center;
    text-align: center;
    border: 1px dashed rgba(255,255,255,0.28);
    border-radius: 8px;
    background:
        linear-gradient(135deg, rgba(82,228,255,0.12), transparent 48%, rgba(255,122,182,0.12)),
        rgba(2, 8, 18, 0.52);
    color: rgba(247,251,255,0.62);
    font-weight: 900;
}
.shot-placeholder span {
    display: block;
    max-width: 160px;
}
.guide-shot {
    display: block;
    width: 100%;
    height: auto;
    border: 1px solid rgba(255,255,255,0.22);
    border-radius: 8px;
    background: rgba(2, 8, 18, 0.52);
    box-shadow: 0 18px 52px rgba(0,0,0,0.34);
}
.footer {
    margin-top: 38px;
    padding-top: 18px;
    border-top: 1px solid rgba(255,255,255,0.13);
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 12px;
    color: rgba(247,251,255,0.58);
    font-size: 0.86rem;
}
@media (max-width: 1000px) {
    .hero,
    .install-band,
    .extension-showcase,
    .download-session-showcase { grid-template-columns: 1fr; }
    .feature-grid,
    .tech-grid,
    .extension-flow { grid-template-columns: repeat(2, minmax(0,1fr)); }
    .diagram-flow { grid-template-columns: 1fr; }
    .diagram-node::after {
        top: auto;
        right: auto;
        left: 22px;
        bottom: 10px;
        width: 2px;
        height: 28px;
    }
    .guide-grid { grid-template-columns: repeat(2, minmax(0,1fr)); }
    .guide-card.featured-guide { grid-column: span 2; }
}
@media (max-width: 680px) {
    .page { width: min(100% - 24px, 1180px); padding-top: 12px; }
    .topbar { align-items: flex-start; flex-direction: column; }
    .nav-actions,
    .hero-actions,
    .download-options,
    .feature-grid,
    .tech-grid,
    .guide-grid { grid-template-columns: 1fr; }
    .nav-actions,
    .hero-actions { width: 100%; }
    .button { width: 100%; }
    .extension-actions { display: grid; }
    .extension-flow { grid-template-columns: 1fr; }
    .download-session-points { grid-template-columns: 1fr; }
    .guide-card.featured-guide { grid-column: span 1; }
    .preview-body { grid-template-columns: 1fr; }
    .preview-nav { min-height: 86px; }
    .workstation-preview { min-height: 360px; }
    .section-head { align-items: flex-start; flex-direction: column; }
}
</style>
</head>
<body>
<main class="page">
  <nav class="topbar" aria-label="SocketJack navigation">
    <a class="brand" href="/">
      <span class="brand-mark">SJ</span>
      <span>SocketJack<small>Jack LLM Workstation download</small></span>
    </a>
    <div class="nav-actions">
      <a class="button secondary" href="/">Master List</a>
      <a class="button" href="#Windows-Install" onclick="return startInstallDownload(event,'Windows-Install','https://SocketJack.com/JackLLM/Update/JackLLM-Setup.msi')">Windows x64 installer</a>
      <a class="button linux" href="#Linux-Install" onclick="return startInstallDownload(event,'Linux-Install','https://SocketJack.com/Update/LlmWorkstation_Linux64.deb')">Linux x64 package</a>
      <a class="button secondary" href="#visual-studio-extension">Visual Studio extension</a>
    </div>
  </nav>

  <section class="hero" aria-labelledby="download-title">
    <div>
      <div class="kicker">Local AI control room</div>
      <h1 id="download-title"><span class="aero-text">Jack LLM</span> Workstation</h1>
      <p class="lead">Install the application that turns your Windows or Linux machine into a SocketJack AI host. Jack LLM Workstation connects local models, tool permissions, project files, terminals, SQL, and remote browser sessions without hiding the work from the computer that owns it.</p>
      <div class="hero-actions">
        <a class="button" href="#Windows-Install" onclick="return startInstallDownload(event,'Windows-Install','https://SocketJack.com/JackLLM/Update/JackLLM-Setup.msi')">Download for Windows x64</a>
        <a class="button linux" href="#Linux-Install" onclick="return startInstallDownload(event,'Linux-Install','https://SocketJack.com/Update/LlmWorkstation_Linux64.deb')">Download Linux x64 .deb</a>
        <a class="button secondary" href="#visual-studio-extension">Visual Studio extension</a>
        <a class="button secondary" href="#getting-started">Getting Started</a>
      </div>
      <div class="hero-facts" aria-label="Workstation capabilities">
        <span class="pill">SocketJack.LlmRuntime AI technology</span>
        <span class="pill">SocketJack.Net networking stack</span>
        <span class="pill">Local tools and approvals</span>
        <span class="pill">Remote session steering</span>
        <span class="pill">Visual Studio Copilot VSIX</span>
      </div>
    </div>
    <aside class="workstation-preview" aria-label="Jack LLM Workstation interface preview">
      <div class="window-bar"><span>Jack LLM Workstation</span><span class="traffic"><i></i><i></i><i></i></span></div>
      <div class="preview-body">
        <div class="preview-nav" aria-hidden="true">
          <div class="preview-dot"></div>
          <div class="preview-dot"></div>
          <div class="preview-dot"></div>
          <div class="preview-dot"></div>
        </div>
        <div class="preview-stack">
          <div class="preview-main" aria-hidden="true">
            <div class="preview-row wide"></div>
            <div class="preview-row mid"></div>
            <div class="preview-row short"></div>
            <div class="preview-terminal">SocketJack.LlmRuntime: ready<br>SocketJack.Net: published<br>Tools: approval required</div>
          </div>
          <div class="preview-side" aria-hidden="true">
            <div class="metric"></div>
            <div class="metric"></div>
            <div class="metric"></div>
          </div>
        </div>
      </div>
    </aside>
  </section>

  <section id="web-session-preview" class="download-session-showcase" aria-labelledby="web-session-preview-title">
    <div class="download-session-copy">
      <div class="kicker">Main user web page</div>
      <h2 id="web-session-preview-title">SocketJack AI in the browser</h2>
      <p>This is the page users land in after choosing a SocketJack host: a live chat workspace with server routing, token status, model modes, GPU origin controls, multi-GPU pooling, tool progress, and a prompt composer in one browser surface.</p>
      <div class="download-session-points" aria-label="SocketJack AI browser features">
        <span>Users can route prompts through Auto, Tools, media, multimodal, and embedding modes without switching apps.</span>
        <span>Advanced controls expose model choice, parameter limits, hybrid origin, same-origin relay, best GPU, and multi-GPU pool routing.</span>
        <span>Tool calls, citations, progress, token cost, and stop controls stay visible while the workstation does the work.</span>
        <span>The same browser session connects back to Jack LLM Workstation hosts through SocketJack routing.</span>
      </div>
    </div>
    <figure class="download-session-frame">
      <img src="/img/socketjack-user-web-session.png" alt="SocketJack AI browser session showing a prompt, running tool output, GPU routing controls, model mode tabs, and the prompt composer">
      <figcaption>The public web page is the user-facing side of Jack LLM Workstation: simple prompt entry on top of local or rented SocketJack compute.</figcaption>
    </figure>
  </section>

  <section class="install-band" aria-labelledby="install-title">
    <div class="install-copy">
      <h2 id="install-title">Windows / Linux Setup (Executables)</h2>
    </div>
    <div class="download-options">
      <article class="download-tile">
        <h3>Windows x64</h3>
        <p>Install the Jack LLM Workstation desktop application and updater.</p>
        <a class="button" href="#Windows-Install" onclick="return startInstallDownload(event,'Windows-Install','https://SocketJack.com/JackLLM/Update/JackLLM-Setup.msi')">Download JackLLM-Setup.msi</a>
        <div id="Windows-Install" class="install-steps" tabindex="-1">
          <h4>Windows x64 install</h4>
          <ol>
            <li>Run the downloaded <strong>JackLLM-Setup.msi</strong>.</li>
            <li>Follow the installer prompts and launch Jack LLM Workstation.</li>
            <li>Sign in, review permissions, then open MasterList Auto to start.</li>
          </ol>
        </div>
      </article>
      <article class="download-tile">
        <h3>Linux x64</h3>
        <p>Download the Debian package or run the install command in a terminal.</p>
        <a class="button linux" href="#Linux-Install" onclick="return startInstallDownload(event,'Linux-Install','https://SocketJack.com/Update/LlmWorkstation_Linux64.deb')">Download LlmWorkstation_Linux64.deb</a>
        <div id="Linux-Install" class="install-steps" tabindex="-1">
          <h4>Linux x64 install</h4>
          <ol>
            <li>Download <strong>LlmWorkstation_Linux64.deb</strong> or copy the terminal command below.</li>
            <li>Run the package with apt so dependencies are installed.</li>
            <li>Launch Jack LLM Workstation, sign in, then open MasterList Auto to start.</li>
          </ol>
          <div id="linuxCommand" class="command-box">curl -L "https://SocketJack.com/Update/LlmWorkstation_Linux64.deb" -o /tmp/jackllm-workstation.deb &amp;&amp; sudo apt install -y /tmp/jackllm-workstation.deb</div>
          <button class="button secondary" type="button" onclick="copyLinuxCommand()">Copy Linux command</button>
          <p id="copyNote" class="copy-note" aria-live="polite"></p>
        </div>
      </article>
    </div>
  </section>

  <section id="visual-studio-extension" class="extension-showcase" aria-labelledby="vs-extension-title">
    <div class="extension-copy">
      <div class="kicker">Copilot server picker</div>
      <h2 id="vs-extension-title">SocketJack Visual Studio Extension</h2>
      <p>The Windows Jack LLM Workstation installer includes the SocketJack VSIX installer. Leave the Visual Studio extension option checked to install the Copilot server picker during setup, or clear it when you only want the workstation service.</p>
      <div class="installer-option" aria-label="Windows installer option">
        <span class="installer-check" aria-hidden="true">x</span>
        <span><strong>Install SocketJack Visual Studio Extension</strong><small>Optional setup checkbox for the bundled VSIX. The extension can be skipped without changing the workstation install.</small></span>
      </div>
      <p>After Visual Studio restarts, open <strong>Extensions &gt; SocketJack &gt; SocketJack Copilot Servers</strong>, select a server, choose an eligible tools-capable model, test the route, and click Configure.</p>
      <div class="extension-actions">
        <a class="button" href="#Windows-Install" onclick="return startInstallDownload(event,'Windows-Install','https://SocketJack.com/JackLLM/Update/JackLLM-Setup.msi')">Download Windows installer</a>
        <a class="button secondary" href="/Documentation">Read documentation</a>
      </div>
    </div>
    <figure class="extension-shot-frame">
      <img class="extension-shot" src="/img/socketjack-visual-studio-extension.png" alt="Visual Studio with the SocketJack Copilot Servers tool window selecting a server and model beside GitHub Copilot Chat">
      <figcaption>The extension writes the solution MCP config and Visual Studio Ollama BYOM settings, then Copilot can route model requests through the selected SocketJack server.</figcaption>
    </figure>
    <div class="extension-flow" aria-label="Visual Studio extension flow">
      <div class="extension-step"><em>1</em><strong>Choose during setup</strong><span>The Jack LLM Workstation MSI includes an optional SocketJack VSIX install checkbox.</span></div>
      <div class="extension-step"><em>2</em><strong>Open the picker</strong><span>Use Extensions &gt; SocketJack to open the Copilot Servers window inside Visual Studio.</span></div>
      <div class="extension-step"><em>3</em><strong>Select server and model</strong><span>Refresh the MasterList, pick an eligible server, then choose a loaded or loadable tools-capable model.</span></div>
      <div class="extension-step"><em>4</em><strong>Configure Copilot</strong><span>The extension updates MCP and BYOM so Visual Studio can send Copilot traffic through SocketJack.</span></div>
    </div>
  </section>

  <section aria-labelledby="features-title">
    <div class="section-head">
      <h2 id="features-title">Showcase features</h2>
      <p>A workstation is more than a chat box. It is the local control surface for models, tools, project context, permissions, server health, and browser-steered sessions.</p>
    </div>
    <div class="feature-grid">
      <article class="feature-card"><div class="feature-icon">AI</div><h3>Local AI runtime</h3><p>SocketJack.LlmRuntime coordinates local model providers, runtime health, generation requests, media tools, and model availability from the host machine.</p></article>
      <article class="feature-card"><div class="feature-icon">NET</div><h3>Secure network stack</h3><p>SocketJack.Net handles the HTTP, WebSocket, proxy, relay, and server-list plumbing that makes a private workstation reachable from SocketJack sessions.</p></article>
      <article class="feature-card"><div class="feature-icon">OK</div><h3>Explicit approvals</h3><p>File, terminal, SQL, internet, and automation capabilities stay behind workstation-side permissions so hosts expose only what they choose.</p></article>
      <article class="feature-card"><div class="feature-icon">GPU</div><h3>Host diagnostics</h3><p>Watch model status, usage, token settings, runtime reports, and workstation health before publishing the machine to the master list.</p></article>
      <article class="feature-card"><div class="feature-icon">PRJ</div><h3>Project aware sessions</h3><p>Attach project files, generated artifacts, and tool outputs to a session so useful work remains tied to the same local workspace.</p></article>
      <article class="feature-card"><div class="feature-icon">GO</div><h3>Remote steering</h3><p>Start at SocketJack.com, route prompts to your workstation, stream results back, and keep control without moving every workflow to a remote service.</p></article>
    </div>
  </section>

  <section aria-labelledby="diagram-title">
    <div class="section-head">
      <h2 id="diagram-title">Feature diagram</h2>
      <p>The application, AI technology, and networking stack each have a clear job, which makes the platform easier to explain and easier to evolve.</p>
    </div>
    <div class="diagram">
      <div class="diagram-flow" role="list" aria-label="SocketJack workstation request flow">
        <div class="diagram-node" role="listitem"><strong>SocketJack.com</strong><span>Browser session, server directory, launch route, account, and remote steering surface.</span></div>
        <div class="diagram-node" role="listitem"><strong>SocketJack.Net</strong><span>Networking stack for HTTP, WebSockets, relays, tunnels, routing, and host publication.</span></div>
        <div class="diagram-node" role="listitem"><strong>Jack LLM Workstation</strong><span>The installed desktop or Linux application that owns approvals, sessions, tools, and host state.</span></div>
        <div class="diagram-node" role="listitem"><strong>SocketJack.LlmRuntime</strong><span>AI runtime technology that talks to local providers, model catalogs, generation jobs, and diagnostics.</span></div>
        <div class="diagram-node" role="listitem"><strong>Models and tools</strong><span>LM Studio, local models, files, terminal commands, SQL, search, projects, and generated artifacts.</span></div>
      </div>
      <div class="diagram-return">Progress, tokens, logs, tool results, approvals, and artifacts stream back through SocketJack.Net to the browser session.</div>
    </div>
  </section>

  <section id="getting-started" aria-labelledby="guide-title">
    <div class="section-head">
      <h2 id="guide-title">Getting Started</h2>
      <p>Start in the main Jack LLM Workstation application, add the Visual Studio extension when you want Copilot routing, then publish or select a server from SocketJack.</p>
    </div>
    <div class="guide-grid">
      <article class="guide-card featured-guide">
        <div class="step-number">1</div>
        <img class="guide-shot" src="/img/jackllm-workstation-main-application.png" alt="Jack LLM Workstation main diagnostics application with proxy controls, runtime provider, health metrics, and service status cards">
        <h3>Open Jack LLM Workstation</h3>
        <p>The main application is the control room for proxy status, LlmRuntime, JackONNX, health metrics, service diagnostics, trust settings, models, and server management.</p>
      </article>
      <article class="guide-card featured-guide">
        <div class="step-number">2</div>
        <img class="guide-shot" src="/img/jackllm-workstation-models-tab.png" alt="Jack LLM Workstation Models tab showing running models, benchmarks, and GPU load settings">
        <h3>Tune models and GPU settings</h3>
        <p>The Models tab shows running and downloaded inventory, benchmarks, backend selection, GPU layers, placement, target GPUs, context length, batch size, KV-cache offload, fallback, and credentials for each loadable model.</p>
      </article>
      <article class="guide-card">
        <div class="step-number">3</div>
        <div class="shot-placeholder" data-image-slot="auto-select"><span>MasterList Auto server selection</span></div>
        <h3>Load up the MasterList Auto, select, and start (Recommended)</h3>
        <p>Recommended path for launching quickly with automatic server selection.</p>
      </article>
      <article class="guide-card">
        <div class="step-number">4</div>
        <div class="shot-placeholder" data-image-slot="manual-server"><span>Manual server selection</span></div>
        <h3>(Optional) Load the MasterList and manually select a server (Advanced)</h3>
        <p>Optional advanced path when you want to pick a specific server yourself.</p>
      </article>
    </div>
  </section>

  <section id="gpu-configuration" aria-labelledby="gpu-config-title">
    <div class="section-head">
      <h2 id="gpu-config-title">GPU Configuration</h2>
      <p>Jack LLM Workstation lets each model carry its own load profile, so small models can stay responsive while larger GGUF or media models get deliberate hardware placement.</p>
    </div>
    <div class="tech-grid">
      <article class="tech-card">
        <span class="tech-label">Backend</span>
        <h3>Select the compute path</h3>
        <p>Choose CUDA 12, DirectML, CPU, or backend fallback behavior per model. Use GPU Layers to control how much of a model is offloaded, including full auto offload when the backend supports it.</p>
      </article>
      <article class="tech-card">
        <span class="tech-label">Placement</span>
        <h3>Pin work to hardware</h3>
        <p>Target a specific GPU such as cuda:0, leave targets empty for automatic placement, or use hybrid and parallel modes when a model should span local devices or network nodes.</p>
      </article>
      <article class="tech-card">
        <span class="tech-label">Headroom</span>
        <h3>Protect VRAM and load</h3>
        <p>Set maximum GPU load and VRAM percentages so the workstation keeps room for the desktop, multiple running models, or rented sessions. Idle unload keeps heavyweight models from squatting on memory.</p>
      </article>
      <article class="tech-card">
        <span class="tech-label">Throughput</span>
        <h3>Shape speed versus memory</h3>
        <p>Adjust context length, eval batch, flash attention, and KV-cache offload to trade memory use for response speed, longer prompts, or steadier multi-session throughput.</p>
      </article>
    </div>
  </section>

  <footer class="footer">
    <span>SocketJack connects local AI hosts, model runtimes, secure routes, and browser sessions.</span>
    <span><a href="/">Master List</a> / <a href="https://lmstudio.ai/download" target="_blank" rel="noopener noreferrer">LM Studio</a></span>
  </footer>
</main>
<script>
function revealInstallSteps(targetId) {
    document.querySelectorAll('.install-steps').forEach(panel => panel.classList.toggle('is-open', panel.id === targetId));
    const panel = document.getElementById(targetId);
    if (!panel) return;
    if (location.hash !== '#' + targetId) {
        history.pushState(null, '', '#' + targetId);
    }
    panel.scrollIntoView({ behavior: 'smooth', block: 'center' });
    panel.focus({ preventScroll: true });
}
function triggerDownload(url) {
    const link = document.createElement('a');
    link.href = url;
    link.download = '';
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    link.remove();
}
function startInstallDownload(event, targetId, downloadUrl) {
    if (event) event.preventDefault();
    revealInstallSteps(targetId);
    window.setTimeout(() => triggerDownload(downloadUrl), 100);
    return false;
}
function copyLinuxCommand() {
    const source = document.getElementById('linuxCommand');
    const note = document.getElementById('copyNote');
    const text = source ? source.textContent.trim() : '';
    if (!text) return;
    const done = () => { if (note) note.textContent = 'Linux install command copied.'; };
    const failed = () => { if (note) note.textContent = 'Select the command and copy it from the box above.'; };
    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(done).catch(failed);
    } else {
        failed();
    }
}
window.addEventListener('DOMContentLoaded', () => {
    const hash = (location.hash || '').replace(/^#/, '');
    if (hash === 'Windows-Install' || hash === 'Linux-Install') revealInstallSteps(hash);
});
</script>
</body>
</html>
""";
    }

    private static string BuildJackcastXdfHtml() {
        return """
