.kicker{font-size:.64rem;text-transform:uppercase;color:#75aa7e;font-weight:900}.title{font-weight:900;color:#edfff0}
.panel-body{padding:12px;display:grid;gap:10px}
.status{min-height:36px;border:1px dashed rgba(57,255,20,.25);background:rgba(0,8,2,.58);padding:9px;color:#75aa7e;font-size:.75rem;line-height:1.45}
.status.good{color:#39ff14;border-color:rgba(57,255,20,.48)}.status.bad{color:#ff5f73;border-color:rgba(255,95,115,.48)}
.file-lines{display:grid;gap:6px;color:#75aa7e;font-size:.72rem;overflow:hidden}.file-lines b{color:#d8ffe0}
.filters{display:flex;flex-wrap:wrap;gap:7px;max-height:330px;overflow:auto;padding-right:4px}
.cat-btn{min-height:30px;font-size:.72rem;text-align:left;display:inline-flex;gap:7px;align-items:center}
.cat-btn.active{border-color:#39ff14;color:#001904;background:#39ff14;box-shadow:0 0 24px rgba(57,255,20,.32)}
.cat-count{opacity:.75;color:inherit}
.search-row{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:8px}
input,select{width:100%;min-height:34px;border:1px solid rgba(57,255,20,.3);background:rgba(0,6,2,.88);color:#d8ffe0;padding:7px 9px;outline:none}
input:focus,select:focus{border-color:#39ff14;box-shadow:0 0 0 2px rgba(57,255,20,.14),0 0 24px rgba(57,255,20,.16)}
.stats{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}.stat{border:1px solid rgba(57,255,20,.18);background:rgba(0,8,2,.48);padding:8px}.stat span{display:block;color:#75aa7e;font-size:.62rem}.stat b{display:block;margin-top:3px;color:#d8ffe0}
.table-wrap{overflow:auto;max-height:calc(100vh - 154px)}
table{width:100%;border-collapse:collapse;font-size:.76rem}
th,td{padding:9px 10px;border-bottom:1px solid rgba(57,255,20,.16);vertical-align:top;text-align:left}
th{position:sticky;top:0;z-index:3;background:rgba(0,16,5,.96);color:#39ff14;text-transform:uppercase;font-size:.62rem;letter-spacing:.06em}
tr:hover{background:rgba(57,255,20,.055)}
.item-name{font-weight:900;color:#edfff0}.desc{margin-top:4px;color:#75aa7e;font-size:.69rem;line-height:1.35;max-width:520px}
.tags{display:flex;flex-wrap:wrap;gap:4px}.tag{border:1px solid rgba(57,255,20,.28);background:rgba(0,12,4,.68);color:#39ff14;padding:2px 5px;border-radius:3px;font-size:.64rem}
.mono{font-family:inherit;color:#44ffe8}.value-input{min-width:90px;max-width:120px}.raw-note{color:#75aa7e;font-size:.66rem;margin-top:3px}
.empty{padding:22px;color:#75aa7e;text-align:center}
.loading{display:inline-block;width:.7em;height:1em;background:#39ff14;box-shadow:0 0 12px rgba(57,255,20,.6);animation:blink 1s steps(1,end) infinite}@keyframes blink{50%{opacity:0}}
@media(max-width:900px){.grid{grid-template-columns:1fr}.table-wrap{max-height:none}.topbar{align-items:flex-start;flex-direction:column}.top-actions{justify-content:flex-start}}
</style>
</head>
<body>
<main class="xdf-shell">
  <header class="topbar">
    <div class="brand">
      <a class="logo" href="/Account">JackCast<span>.Live</span></a>
      <div class="prompt">~/ecu/xdf $ parse --categories --matrix</div>
    </div>
    <div class="top-actions">
      <a class="button" href="/Account">cd ~/files</a>
      <button id="reloadBtn" type="button">./reload</button>
      <button id="downloadBtn" type="button" disabled>write patched bin</button>
    </div>
  </header>
  <section class="grid">
    <aside class="panel">
      <div class="panel-head"><div><div class="kicker">XDF Console</div><div class="title">Category Index</div></div></div>
      <div class="panel-body">
        <div id="status" class="status">booting parser <span class="loading"></span></div>
        <div class="file-lines">
          <div>BIN: <b id="binName">not loaded</b></div>
          <div>XDF: <b id="xdfName">not loaded</b></div>
        </div>
        <div class="search-row">
          <input id="searchInput" type="search" placeholder="grep parameters">
          <button id="clearBtn" type="button">clear</button>
        </div>
        <div class="stats">
          <div class="stat"><span>parameters</span><b id="itemCount">0</b></div>
          <div class="stat"><span>categories</span><b id="categoryCount">0</b></div>
        </div>
        <div class="filters" id="categoryFilters"></div>
      </div>
    </aside>
    <section class="panel">
      <div class="panel-head"><div><div class="kicker">Calibration</div><div class="title" id="tableTitle">Parameters</div></div><div class="prompt" id="visibleCount">0 visible</div></div>
      <div class="table-wrap">
        <table>
          <thead><tr><th>Name</th><th>Category</th><th>Address</th><th>Value</th><th>Type</th></tr></thead>
          <tbody id="rows"><tr><td colspan="5" class="empty">waiting for XDF and BIN files</td></tr></tbody>
        </table>
      </div>
    </section>
  </section>
</main>
<script src="/MatrixTheme.js"></script>
<script>
(function(){
  const params = new URLSearchParams(location.search);
  const state = { binName: params.get("f1") || "", xdfName: params.get("f2") || "", bin: null, xdfText: "", categories: [], items: [], activeCategory: "all", query: "", dirty: false };
  const els = {
    status: document.getElementById("status"),
    binName: document.getElementById("binName"),
    xdfName: document.getElementById("xdfName"),
    filters: document.getElementById("categoryFilters"),
    rows: document.getElementById("rows"),
    itemCount: document.getElementById("itemCount"),
    categoryCount: document.getElementById("categoryCount"),
    visibleCount: document.getElementById("visibleCount"),
    tableTitle: document.getElementById("tableTitle"),
    search: document.getElementById("searchInput"),
    download: document.getElementById("downloadBtn")
  };

  function setStatus(text, kind){
    els.status.className = "status" + (kind ? " " + kind : "");
    els.status.textContent = text;
  }

  function esc(value){
    return String(value == null ? "" : value).replace(/[&<>"']/g, ch => ({ "&":"&amp;", "<":"&lt;", ">":"&gt;", '"':"&quot;", "'":"&#39;" }[ch]));
  }

  function fileUrl(name){
    return "/" + String(name || "").split("/").filter(Boolean).map(encodeURIComponent).join("/");
  }

  async function fetchText(name){
    const response = await fetch(fileUrl(name), { cache: "no-store" });
    if (!response.ok) throw new Error(name + " returned HTTP " + response.status);
    return await response.text();
  }

  async function fetchBytes(name){
    const response = await fetch(fileUrl(name), { cache: "no-store" });
    if (!response.ok) throw new Error(name + " returned HTTP " + response.status);
    return new Uint8Array(await response.arrayBuffer());
  }

  function attr(el, names){
    for (const name of names) {
      if (el.hasAttribute && el.hasAttribute(name)) return el.getAttribute(name) || "";
      if (!el.attributes) continue;
      for (const a of Array.from(el.attributes)) {
        if (a.name.toLowerCase() === name.toLowerCase()) return a.value || "";
      }
    }
    return "";
  }

  function childText(el, names){
    const wanted = names.map(n => n.toLowerCase());
    for (const child of Array.from(el.children || [])) {
      if (wanted.includes(child.tagName.toLowerCase())) return (child.textContent || "").trim();
    }
    return "";
  }

  function parseIntFlex(value){
    value = String(value || "").trim();
    if (!value) return NaN;
    if (/^0x/i.test(value)) return parseInt(value.substring(2), 16);
    if (/^[0-9a-f]+h$/i.test(value)) return parseInt(value.slice(0, -1), 16);
    return parseInt(value, 10);
  }

  function categoryKey(value){
    value = String(value || "").trim();
    if (!value) return "";
    const parsed = parseIntFlex(value);
    return Number.isFinite(parsed) && !Number.isNaN(parsed) ? "n:" + parsed : "s:" + value.toLowerCase();
  }

  function categoryNameFromElement(el){
    return attr(el, ["name", "title", "label"]) || childText(el, ["title", "name", "label"]) || "";
  }

  function categoryIdFromElement(el){
    return attr(el, ["index", "id", "uniqueid", "category", "cat", "categoryid"]);
  }

  function buildCategoryMap(doc){
    const byKey = new Map();
    const names = new Map();
    const categories = [];
    function add(id, name){
      name = String(name || "").trim();
      if (!name) return;
      const keys = [categoryKey(id), categoryKey(name)].filter(Boolean);
      for (const key of keys) byKey.set(key, name);
      if (!names.has(name.toLowerCase())) {
        names.set(name.toLowerCase(), true);
        categories.push(name);
      }
    }
    Array.from(doc.getElementsByTagName("*")).forEach(el => {
      const tag = el.tagName.toLowerCase();
      if (!tag.includes("category") || tag.includes("categorymem")) return;
      const name = categoryNameFromElement(el);
      const id = categoryIdFromElement(el);
      add(id, name);
    });
    return { byKey, categories, add };
  }

  function resolveCategory(ref, map){
    ref = String(ref || "").trim();
    if (!ref) return "";
    const mapped = map.byKey.get(categoryKey(ref));
    if (mapped) return mapped;
    for (const name of map.categories) {
      if (name.toLowerCase() === ref.toLowerCase()) return name;
    }
    map.add(ref, ref);
    return ref;
  }

  function collectCategoryRefs(el){
    const refs = [];
    function push(value){
      String(value || "").split(/[|,;]/).map(v => v.trim()).filter(Boolean).forEach(v => refs.push(v));
    }
    push(attr(el, ["category", "categories", "cat", "catid", "categoryid"]));
    Array.from(el.getElementsByTagName("*")).forEach(child => {
      const tag = child.tagName.toLowerCase();
      if (tag.includes("categorymem")) {
        push(attr(child, ["category", "index", "id", "cat", "categoryid"]) || (child.textContent || "").trim());
      } else if (tag === "category" || tag.endsWith(":category")) {
        push(attr(child, ["name", "title", "index", "id", "category"]) || (child.textContent || "").trim());
      }
    });
    return refs;
  }

  function titleForItem(el){
    return attr(el, ["title", "name", "label"]) || childText(el, ["title", "name", "label"]) || attr(el, ["uniqueid", "id"]) || el.tagName;
  }

  function descriptionForItem(el){
    return childText(el, ["description", "desc", "comments", "comment"]) || attr(el, ["description", "desc"]);
  }

  function findAddress(el){
    const direct = attr(el, ["address", "offset", "mmedaddress"]);
    if (direct) return parseIntFlex(direct);
    for (const child of Array.from(el.getElementsByTagName("*"))) {
      const tag = child.tagName.toLowerCase();
      if (tag.includes("embeddeddata") || tag.includes("address")) {
        const value = attr(child, ["mmedaddress", "address", "offset"]);
        const parsed = parseIntFlex(value);
        if (Number.isFinite(parsed) && !Number.isNaN(parsed)) return parsed;
      }
    }
    return NaN;
  }

  function findBits(el){
    const direct = attr(el, ["bits", "sizebits", "mmedelementsizebits", "bitlength"]);
    if (direct) return parseIntFlex(direct);
    for (const child of Array.from(el.getElementsByTagName("*"))) {
      const value = attr(child, ["mmedelementsizebits", "bits", "sizebits", "bitlength"]);
      const parsed = parseIntFlex(value);
      if (Number.isFinite(parsed) && !Number.isNaN(parsed)) return parsed;
    }
    return 8;
  }

  function parseItems(doc, map){
    const itemTags = /^(xdfconstant|xdftable|xdfflag|xdfpatch|xdffunction|xdfaxis)$/i;
    const items = [];
    Array.from(doc.getElementsByTagName("*")).forEach((el, index) => {
      const tag = el.tagName.replace(/^.*:/, "");
      if (!itemTags.test(tag)) return;
      const refs = collectCategoryRefs(el);
      const categories = refs.map(ref => resolveCategory(ref, map)).filter(Boolean);
      const uniqueCategories = Array.from(new Set(categories.length ? categories : ["Uncategorized"]));
      if (uniqueCategories[0] === "Uncategorized") map.add("Uncategorized", "Uncategorized");
      const address = findAddress(el);
      const bits = findBits(el);
      items.push({
        index,
        kind: tag.replace(/^xdf/i, "").toUpperCase(),
        title: titleForItem(el),
        description: descriptionForItem(el),
        categories: uniqueCategories,
        address,
        bits,
        bytes: Math.max(1, Math.ceil((Number.isFinite(bits) && !Number.isNaN(bits) ? bits : 8) / 8))
      });
    });
    return items.sort((a,b) => a.title.localeCompare(b.title));
  }

  function parseXdf(text){
    const doc = new DOMParser().parseFromString(text, "application/xml");
    const error = doc.querySelector("parsererror");
    if (error) throw new Error("XDF XML parse failed: " + error.textContent.trim().slice(0, 160));
    const map = buildCategoryMap(doc);
    const items = parseItems(doc, map);
    const counts = new Map();
    items.forEach(item => item.categories.forEach(cat => counts.set(cat, (counts.get(cat) || 0) + 1)));
    const categories = map.categories
      .map(name => ({ name, count: counts.get(name) || 0 }))
      .filter(cat => cat.count > 0 || cat.name !== "Uncategorized")
      .sort((a,b) => a.name.localeCompare(b.name));
    return { categories, items };
  }

  function readRaw(item){
    if (!state.bin || !Number.isFinite(item.address) || Number.isNaN(item.address)) return "";
    if (item.address < 0 || item.address + item.bytes > state.bin.length) return "";
    let value = 0;
    for (let i = 0; i < item.bytes; i++) value += state.bin[item.address + i] * Math.pow(256, i);
    return Number.isSafeInteger(value) ? value : "";
  }

  function writeRaw(item, value){
    if (!state.bin || !Number.isFinite(item.address) || Number.isNaN(item.address)) return false;
    if (item.address < 0 || item.address + item.bytes > state.bin.length) return false;
    let next = Number(value);
    if (!Number.isFinite(next) || next < 0) return false;
    for (let i = 0; i < item.bytes; i++) state.bin[item.address + i] = Math.floor(next / Math.pow(256, i)) & 0xff;
    state.dirty = true;
    els.download.disabled = false;
    setStatus("patched bytes staged in browser memory", "good");
    return true;
  }

  function renderCategories(){
    const total = state.items.length;
    const buttons = [`<button class="cat-btn ${state.activeCategory === "all" ? "active" : ""}" data-cat="all">all <span class="cat-count">${total}</span></button>`];
    state.categories.forEach(cat => {
      const key = encodeURIComponent(cat.name);
      buttons.push(`<button class="cat-btn ${state.activeCategory === cat.name ? "active" : ""}" data-cat="${esc(key)}">${esc(cat.name)} <span class="cat-count">${cat.count}</span></button>`);
    });
    els.filters.innerHTML = buttons.join("");
    els.filters.querySelectorAll("button").forEach(btn => btn.addEventListener("click", () => {
      const raw = btn.getAttribute("data-cat") || "all";
      state.activeCategory = raw === "all" ? "all" : decodeURIComponent(raw);
      render();
    }));
  }

  function filteredItems(){
    const q = state.query.trim().toLowerCase();
    return state.items.filter(item => {
      if (state.activeCategory !== "all" && !item.categories.includes(state.activeCategory)) return false;
      if (!q) return true;
      return (item.title + " " + item.description + " " + item.kind + " " + item.categories.join(" ")).toLowerCase().includes(q);
    });
  }

  function renderRows(){
    const items = filteredItems();
    els.visibleCount.textContent = items.length + " visible";
    els.tableTitle.textContent = state.activeCategory === "all" ? "Parameters" : state.activeCategory;
    if (!items.length) {
      els.rows.innerHTML = `<tr><td colspan="5" class="empty">no parameters match this category/search</td></tr>`;
      return;
    }
    els.rows.innerHTML = items.map(item => {
      const address = Number.isFinite(item.address) && !Number.isNaN(item.address) ? "0x" + item.address.toString(16).toUpperCase() : "n/a";
      const raw = readRaw(item);
      const value = raw === "" ? `<span class="raw-note">not scalar or out of range</span>` : `<input class="value-input" data-item="${item.index}" type="number" min="0" value="${raw}"><div class="raw-note">${item.bytes} byte raw LE</div>`;
      return `<tr>
        <td><div class="item-name">${esc(item.title)}</div>${item.description ? `<div class="desc">${esc(item.description)}</div>` : ""}</td>
        <td><div class="tags">${item.categories.map(cat => `<span class="tag">${esc(cat)}</span>`).join("")}</div></td>
        <td class="mono">${esc(address)}</td>
        <td>${value}</td>
        <td>${esc(item.kind)}<div class="raw-note">${esc(item.bits)} bits</div></td>
      </tr>`;
    }).join("");
    els.rows.querySelectorAll(".value-input").forEach(input => input.addEventListener("change", () => {
      const item = state.items.find(candidate => String(candidate.index) === input.getAttribute("data-item"));
      if (item && !writeRaw(item, input.value)) setStatus("unable to patch value at selected address", "bad");
    }));
  }

  function render(){
    els.itemCount.textContent = state.items.length;
    els.categoryCount.textContent = state.categories.length;
    renderCategories();
    renderRows();
  }

  async function load(){
    els.binName.textContent = state.binName || "missing f1";
    els.xdfName.textContent = state.xdfName || "missing f2";
    els.download.disabled = true;
    state.dirty = false;
    if (!state.binName || !state.xdfName) {
      setStatus("missing query parameters: open from My Files after selecting one .bin and one .xdf", "bad");
      return;
    }
    try {
      setStatus("loading BIN and XDF files...");
      const results = await Promise.all([fetchBytes(state.binName), fetchText(state.xdfName)]);
      state.bin = results[0];
      state.xdfText = results[1];
      const parsed = parseXdf(state.xdfText);
      state.categories = parsed.categories;
      state.items = parsed.items;
      state.activeCategory = "all";
      render();
      setStatus("loaded " + state.items.length + " parameters across " + state.categories.length + " XDF categories", "good");
    } catch (error) {
      console.error(error);
      setStatus(error.message || "failed to load XDF", "bad");
      els.rows.innerHTML = `<tr><td colspan="5" class="empty">${esc(error.message || "failed to load XDF")}</td></tr>`;
    }
  }

  els.search.addEventListener("input", () => { state.query = els.search.value || ""; renderRows(); });
  document.getElementById("clearBtn").addEventListener("click", () => { els.search.value = ""; state.query = ""; renderRows(); });
  document.getElementById("reloadBtn").addEventListener("click", load);
  els.download.addEventListener("click", () => {
    if (!state.bin) return;
    const blob = new Blob([state.bin], { type: "application/octet-stream" });
    const a = document.createElement("a");
    const base = (state.binName || "patched.bin").split("/").pop() || "patched.bin";
    a.href = URL.createObjectURL(blob);
    a.download = base.replace(/\.bin$/i, "") + "-patched.bin";
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 1000);
  });

  load();
})();
</script>
</body>
</html>
""";
    }

    private static string BuildSocketJackLandingHtml() {
        using (Stream? stream = Assembly.GetExecutingAssembly().GetManifestResourceStream("SocketJack.MagicMasterList.Html.SocketJackHttpServerDefaultIndex.html")) {
            if (stream != null) {
                using var reader = new StreamReader(stream, Encoding.UTF8, true);
                return reader.ReadToEnd();
            }
        }

        foreach (string candidate in new[] {
            Path.Combine(AppContext.BaseDirectory, "html", "SocketJackHttpServerDefaultIndex.html"),
            Path.Combine(AppContext.BaseDirectory, "SocketJackHttpServerDefaultIndex.html"),
            Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "html", "SocketJackHttpServerDefaultIndex.html"),
            Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "SocketJackHttpServerDefaultIndex.html"),
            Path.Combine(Directory.GetCurrentDirectory(), "html", "SocketJackHttpServerDefaultIndex.html"),
            Path.Combine(Directory.GetCurrentDirectory(), "SocketJackHttpServerDefaultIndex.html")
        }) {
            if (File.Exists(candidate))
                return File.ReadAllText(candidate, Encoding.UTF8);
        }

        return "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"utf-8\"><title>SocketJack - JackLLM Workstation Network</title><meta name=\"description\" content=\"SocketJack connects JackLLM Workstation hosts, secure proxy routes, local model services, updates, and rentable AI compute in one public entry point.\"><meta property=\"og:title\" content=\"SocketJack - JackLLM Workstation Network\"><meta property=\"og:description\" content=\"Launch into the SocketJack network for live local AI hosts, secure routes, model services, updates, and rentable workstation compute.\"><meta property=\"og:type\" content=\"website\"><meta property=\"og:url\" content=\"https://socketjack.com/\"><meta property=\"og:image\" content=\"" + WorkstationMetadataImagePublicUrl + "\"><meta property=\"og:image:width\" content=\"1731\"><meta property=\"og:image:height\" content=\"909\"><meta property=\"og:image:alt\" content=\"SocketJack Workstation network preview image\"><meta name=\"twitter:card\" content=\"summary_large_image\"><meta name=\"twitter:title\" content=\"SocketJack - JackLLM Workstation Network\"><meta name=\"twitter:description\" content=\"Live local AI hosts, secure proxy routes, and rentable JackLLM workstation compute.\"><meta name=\"twitter:image\" content=\"" + WorkstationMetadataImagePublicUrl + "\"></head><body><h1>SocketJack</h1></body></html>";
    }

    private static byte[] LoadMetadataImageBytes(string fileName) {
        fileName = Path.GetFileName((fileName ?? "").Trim());
        if (string.IsNullOrWhiteSpace(fileName))
            return Array.Empty<byte>();

        using (Stream? stream = Assembly.GetExecutingAssembly().GetManifestResourceStream("SocketJack.MagicMasterList.Html." + fileName)) {
            if (stream != null) {
                using var memory = new MemoryStream();
                stream.CopyTo(memory);
                return memory.ToArray();
            }
        }

        foreach (string candidate in new[] {
            Path.Combine(AppContext.BaseDirectory, "html", fileName),
            Path.Combine(AppContext.BaseDirectory, fileName),
            Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "html", fileName),
            Path.Combine(Directory.GetCurrentDirectory(), "html", fileName),
            Path.Combine(Directory.GetCurrentDirectory(), fileName)
        }) {
            if (File.Exists(candidate))
                return File.ReadAllBytes(candidate);
        }

        return Array.Empty<byte>();
    }

    private string BuildIssuesHtml() {
        string html = """
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>SocketJack Troubleshooting</title>
<style>
:root{color-scheme:dark;--bg:#111111;--panel:rgba(38,38,38,.82);--panel2:rgba(22,27,34,.88);--text:#f5f7fb;--muted:#aeb8c5;--cyan:#61dafb;--green:#52e4b4;--pink:#ff7ab6;--orange:#f6a64f;--red:#ff6b79}
*{box-sizing:border-box}[hidden]{display:none!important}body{margin:0;min-height:100vh;background:linear-gradient(180deg,#151515,#0d1117);color:var(--text);font-family:"Segoe UI",Arial,sans-serif}a{color:#a7e8ff;text-decoration:none}button,input,textarea{font:inherit}button{min-height:36px;border:0;border-radius:7px;background:linear-gradient(135deg,var(--green),var(--cyan));color:#061015;font-weight:900;padding:8px 12px;cursor:pointer}button.secondary{background:rgba(255,255,255,.08);color:var(--text)}button.icon{width:36px;padding:0}input,textarea{width:100%;border:0;border-radius:7px;background:rgba(0,0,0,.32);color:var(--text);padding:10px 11px;outline:1px solid rgba(255,255,255,.12)}textarea{resize:vertical;min-height:110px}.app{min-height:100vh;display:grid;grid-template-rows:auto 1fr}.top{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 20px;background:rgba(20,20,20,.92);backdrop-filter:blur(16px)}.brand{display:flex;align-items:center;gap:11px;min-width:0}.mark{width:38px;height:38px;display:grid;place-items:center;border-radius:8px;background:linear-gradient(135deg,var(--pink),var(--cyan));color:#070707;font-weight:1000}.crumbs{font-size:.78rem;color:var(--muted)}.crumbs span{color:#eaf7ff}.actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}.layout{display:grid;grid-template-columns:280px minmax(0,1fr) 390px;gap:0;min-height:0}.side{background:rgba(19,23,29,.88);padding:16px;overflow:auto}.side h2,.report h2{font-size:.92rem;margin:0 0 10px}.session-list{display:grid;gap:8px}.session-card{display:grid;gap:5px;text-align:left;background:rgba(255,255,255,.06);color:var(--text);border-radius:7px;padding:10px}.session-card.active{background:rgba(82,228,180,.17)}.chat{min-width:0;display:grid;grid-template-rows:auto 1fr auto;background:rgba(17,17,17,.72)}.article-bar{display:flex;justify-content:space-between;gap:10px;align-items:center;padding:16px 18px;background:rgba(31,31,31,.82)}.article-bar h1{font-size:1.45rem;margin:0}.meta{color:var(--muted);font-size:.78rem}.messages{padding:18px;overflow:auto;display:grid;align-content:start;gap:14px}.msg{max-width:920px;padding:12px 14px;border-radius:8px;background:rgba(255,255,255,.06);line-height:1.5;white-space:normal}.msg.user{justify-self:end;background:rgba(97,218,251,.14)}.msg.assistant{justify-self:start;background:rgba(82,228,180,.11)}.msg.system{justify-self:center;background:rgba(246,166,79,.12);color:#ffe3b5}.msg pre{overflow:auto;background:#050708;padding:10px;border-radius:7px}.msg code{font-family:"Cascadia Code",Consolas,monospace;color:#d9fff5}.composer{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;padding:14px 18px;background:rgba(22,27,34,.9)}.composer textarea{min-height:54px;max-height:180px}.report{background:rgba(19,23,29,.9);padding:16px;overflow:auto}.field{display:grid;gap:6px;margin-bottom:12px}.field label{color:var(--muted);font-size:.75rem;text-transform:uppercase}.hint{font-size:.76rem;color:var(--muted);line-height:1.4}.counter{font-family:"Cascadia Code",Consolas,monospace;font-size:.72rem;color:#b6f7e3}.drop{display:grid;gap:8px;place-items:center;min-height:120px;background:rgba(255,255,255,.055);border-radius:8px;text-align:center;padding:12px}.thumbs{display:grid;grid-template-columns:repeat(5,1fr);gap:6px}.thumb{position:relative;aspect-ratio:1;border-radius:6px;overflow:hidden;background:#090b10}.thumb img{width:100%;height:100%;object-fit:cover}.thumb button{position:absolute;right:3px;top:3px;width:24px;min-height:24px;padding:0;background:rgba(0,0,0,.72);color:#fff}.status{min-height:20px;color:#b6f7e3;font-size:.78rem}.status.bad{color:#ffc6cc}.pill{display:inline-grid;place-items:center;min-height:25px;padding:4px 8px;border-radius:999px;background:rgba(255,255,255,.08);color:var(--muted);font-size:.74rem}.copy{float:right;margin-left:8px;min-height:26px;padding:4px 8px;background:rgba(255,255,255,.08);color:#fff}.doc-note{display:grid;gap:8px;background:rgba(246,166,79,.12);padding:12px;border-radius:8px;margin-bottom:12px;color:#ffe4bd}@media(max-width:1120px){.layout{grid-template-columns:1fr}.side,.report{max-height:none}.chat{min-height:68vh}.article-bar{align-items:flex-start;flex-direction:column}}@media(max-width:620px){.top,.actions,.composer{grid-template-columns:1fr;display:grid}.article-bar h1{font-size:1.16rem}.thumbs{grid-template-columns:repeat(3,1fr)}}
</style>
</head>
<body>
<div class="app">
  <header class="top">
    <div class="brand"><div class="mark">SJ</div><div><div class="crumbs">SocketJack ? <span>Troubleshooting</span></div><strong>Issues + Help</strong></div></div>
    <div class="actions"><a class="pill" id="docLink" href="__DOCUMENTATION_URL__">Documentation</a><a class="pill" href="/Documentation">Docs</a><a class="pill" href="/Admin">Admin</a></div>
  </header>
  <main class="layout">
    <aside class="side">
      <div class="actions" style="justify-content:space-between;margin-bottom:10px"><h2>Sessions</h2><button id="newSession" class="icon secondary" title="New chat" type="button">+</button></div>
      <input id="sessionSearch" type="search" placeholder="Search sessions">
      <div id="sessions" class="session-list" style="margin-top:10px"></div>
    </aside>
    <section class="chat">
      <div class="article-bar">
        <div><h1>Ask Jack About SocketJack</h1><div class="meta">Claude 2B+ tools route through <code>/auto/api</code> with the docs link in the system prompt.</div></div>
        <div class="actions"><button id="checkAi" class="secondary" type="button">Check AI</button><span id="aiState" class="pill">checking</span></div>
      </div>
      <div id="messages" class="messages"></div>
      <form id="chatForm" class="composer">
        <textarea id="prompt" placeholder="Ask about SocketJack setup, APIs, exceptions, or JackLLM Workstation..."></textarea>
        <button type="submit">Send ?</button>
      </form>
    </section>
    <aside class="report">
      <div class="doc-note"><strong>Use the docs first</strong><span>The assistant prompt points to <a href="__DOCUMENTATION_URL__">__DOCUMENTATION_URL__</a> so it can download/read the documentation page before answering.</span></div>
      <h2>Report An Error</h2>
      <div class="field"><label for="issueTitle">Title</label><input id="issueTitle" placeholder="Short issue title"></div>
      <div class="field"><label for="issueContext">What happened?</label><textarea id="issueContext" placeholder="What were you doing? Which page, API, or workstation screen?"></textarea></div>
      <div class="field"><label for="errorText">Exception / error text</label><textarea id="errorText" placeholder="Paste exception text, logs, stack traces, or failed request output."></textarea><div id="lineCounter" class="counter">0 / 10,000 lines</div></div>
      <div class="field"><label>Screenshots</label><div id="drop" class="drop"><input id="screenshots" type="file" accept="image/*" multiple><div class="hint">Up to 10 screenshots. Drag/drop or choose files.</div></div><div id="thumbs" class="thumbs"></div></div>
      <button id="submitIssue" type="button">Submit Issue</button>
      <div id="reportStatus" class="status"></div>
    </aside>
  </main>
</div>
<script>
const ISSUE_PROMPT=__ISSUE_PROMPT__;
const DOCUMENTATION_URL=__DOCUMENTATION_URL_JSON__;
const MAX_SHOTS=10,MAX_LINES=10000;
let sessionId=localStorage.getItem('SocketJackIssueSessionId')||('issue_session_'+crypto.randomUUID().replace(/-/g,''));
let messages=[];let screenshots=[];let sessions=[];
const $=id=>document.getElementById(id);
function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function readCookie(name){return document.cookie.split(';').map(x=>x.trim()).reduce((r,p)=>{if(r)return r;const i=p.indexOf('=');return i>0&&p.slice(0,i)===name?decodeURIComponent(p.slice(i+1)):''},'')}
function token(){return localStorage.getItem('SocketJackAccessToken')||sessionStorage.getItem('SocketJackAccessToken')||readCookie('SocketJackAuth')||''}
function authHeaders(extra){const h=Object.assign({},extra||{}),t=token(),u=readCookie('SocketJackLoginName');if(t)h.Authorization='Bearer '+t;if(u)h['X-SocketJack-User']=u;return h}
async function readJson(r){const text=await r.text();let data={};if(text.trim()){try{data=JSON.parse(text)}catch{data={detail:text}}}if(!r.ok)throw new Error(data.error||data.detail||('HTTP '+r.status));return data}
function lineCount(text){if(!text)return 0;return String(text).split(/\n/).length}
function renderMarkdown(text){text=esc(text);text=text.replace(/```([\s\S]*?)```/g,(m,code)=>'<pre><button class="copy" type="button">Copy</button><code>'+code+'</code></pre>');text=text.replace(/`([^`]+)`/g,'<code>$1</code>').replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br>');return text}
function addMessage(role,content){messages.push({role,content});renderMessages();saveSession()}
function renderMessages(){const box=$('messages');box.textContent='';if(!messages.length){const m=document.createElement('div');m.className='msg system';m.innerHTML='Ask a question or paste an error. Jack will use <a href="'+esc(DOCUMENTATION_URL)+'">SocketJack documentation</a> as its ground truth.';box.appendChild(m)}messages.forEach(x=>{const d=document.createElement('div');d.className='msg '+(x.role==='user'?'user':'assistant');d.innerHTML=renderMarkdown(x.content||'');box.appendChild(d)});box.querySelectorAll('.copy').forEach(btn=>btn.onclick=()=>navigator.clipboard.writeText(btn.nextElementSibling.textContent||''));box.scrollTop=box.scrollHeight}
function currentTitle(){return (messages.find(x=>x.role==='user')?.content||'Troubleshooting chat').slice(0,90)}
async function saveSession(){localStorage.setItem('SocketJackIssueSessionId',sessionId);try{await fetch('/api/issues/sessions',{method:'POST',credentials:'include',headers:authHeaders({'Content-Type':'application/json'}),body:JSON.stringify({id:sessionId,title:currentTitle(),messageCount:messages.length,previewText:messages[messages.length-1]?.content||'',messages})})}catch(e){console.warn('issue session save failed',e)}}
async function loadSessions(){try{const p=new URLSearchParams();const q=$('sessionSearch').value.trim();if(q)p.set('search',q);const data=await readJson(await fetch('/api/issues/sessions?'+p.toString(),{cache:'no-store',credentials:'include',headers:authHeaders()}));sessions=data.sessions||[];renderSessions()}catch(e){$('sessions').innerHTML='<div class="hint">Sessions unavailable: '+esc(e.message)+'</div>'}}
function renderSessions(){const list=$('sessions');list.textContent='';if(!sessions.length){list.innerHTML='<div class="hint">No troubleshooting sessions yet.</div>';return}sessions.forEach(s=>{const b=document.createElement('button');b.type='button';b.className='session-card'+(s.id===sessionId?' active':'');b.innerHTML='<strong>'+esc(s.title||'Troubleshooting chat')+'</strong><span class="hint">'+esc(s.previewText||'No preview')+'</span>';b.onclick=()=>{sessionId=s.id;try{messages=JSON.parse(s.messagesJson||'[]')}catch{messages=[]}renderMessages();renderSessions()};list.appendChild(b)})}
async function checkAi(){const state=$('aiState');state.textContent='checking';try{const u='/auto/api?mode=tools&origin=issues&minParamsB=2&model=claude';const data=await readJson(await fetch(u,{cache:'no-store',credentials:'include',headers:authHeaders()}));state.textContent=data.ok?'ready: '+(data.model||data.requested_model||'tools'):'unavailable'}catch(e){state.textContent='unavailable';addSystem('AI tools route is not ready: '+e.message)}}
function addSystem(text){const d=document.createElement('div');d.className='msg system';d.textContent=text;$('messages').appendChild(d)}
async function ask(e){e.preventDefault();const prompt=$('prompt').value.trim();if(!prompt)return;$('prompt').value='';addMessage('user',prompt);const assistant={role:'assistant',content:'Routing through /auto/api tools mode...'};messages.push(assistant);renderMessages();try{const body={mode:'tools',origin:'issues',minParamsB:2,model:'claude',prompt,message:prompt,sessionId,messages:[{role:'system',content:ISSUE_PROMPT}].concat(messages.filter(x=>x.role==='user'||x.role==='assistant').slice(-18))};const r=await fetch('/auto/api',{method:'POST',credentials:'include',headers:authHeaders({'Content-Type':'application/json'}),body:JSON.stringify(body)});const contentType=(r.headers.get('content-type')||'').toLowerCase();if(contentType.includes('application/json')){const data=await readJson(r);assistant.content=data.content||data.response||data.message||data.output_text||JSON.stringify(data,null,2)}else{assistant.content=await r.text()}if(!assistant.content.trim())assistant.content='The tools route returned an empty response.'}catch(err){assistant.content='AI help is unavailable right now. The page still saved this session. Details: '+(err.message||err)}renderMessages();saveSession();loadSessions()}
function updateLineCounter(){const count=lineCount($('errorText').value);$('lineCounter').textContent=count.toLocaleString()+' / 10,000 lines';$('lineCounter').style.color=count>MAX_LINES?'#ff9aa5':'#b6f7e3'}
async function filesToScreenshots(files){const next=[...screenshots];for(const file of Array.from(files||[])){if(next.length>=MAX_SHOTS)break;if(!String(file.type||'').startsWith('image/'))continue;const dataUrl=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(reader.error);reader.readAsDataURL(file)});next.push({fileName:file.name,mimeType:file.type||'image/png',dataUrl})}screenshots=next.slice(0,MAX_SHOTS);renderScreenshots()}
function renderScreenshots(){const box=$('thumbs');box.textContent='';screenshots.forEach((shot,i)=>{const d=document.createElement('div');d.className='thumb';d.innerHTML='<img alt=""><button type="button">x</button>';d.querySelector('img').src=shot.dataUrl;d.querySelector('button').onclick=()=>{screenshots.splice(i,1);renderScreenshots()};box.appendChild(d)})}
async function submitIssue(){const status=$('reportStatus');status.className='status';status.textContent='';const errorText=$('errorText').value||'';const lines=lineCount(errorText);if(lines>MAX_LINES){status.className='status bad';status.textContent='Error text is over 10,000 lines.';return}if(screenshots.length>MAX_SHOTS){status.className='status bad';status.textContent='Too many screenshots.';return}try{const payload={title:$('issueTitle').value,context:$('issueContext').value,errorText,screenshots,issueSessionId:sessionId,conversation:messages};const data=await readJson(await fetch('/api/issues/report',{method:'POST',credentials:'include',headers:authHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)}));status.textContent='Issue submitted: '+data.reportId;$('issueTitle').value='';$('issueContext').value='';$('errorText').value='';screenshots=[];renderScreenshots();updateLineCounter()}catch(e){status.className='status bad';status.textContent=e.message}}
$('chatForm').addEventListener('submit',ask);$('checkAi').addEventListener('click',checkAi);$('newSession').onclick=()=>{sessionId='issue_session_'+crypto.randomUUID().replace(/-/g,'');messages=[];localStorage.setItem('SocketJackIssueSessionId',sessionId);renderMessages();renderSessions()};$('sessionSearch').addEventListener('input',()=>setTimeout(loadSessions,120));$('errorText').addEventListener('input',updateLineCounter);$('screenshots').addEventListener('change',e=>filesToScreenshots(e.target.files));$('submitIssue').addEventListener('click',submitIssue);$('drop').addEventListener('dragover',e=>{e.preventDefault()});$('drop').addEventListener('drop',e=>{e.preventDefault();filesToScreenshots(e.dataTransfer.files)});$('docLink').href=DOCUMENTATION_URL;renderMessages();updateLineCounter();loadSessions();checkAi();
</script>
</body>
</html>
""";
        return html
            .Replace("__DOCUMENTATION_URL__", WebUtility.HtmlEncode(BuildAbsoluteWebsiteUrl("/Documentation")))
            .Replace("__DOCUMENTATION_URL_JSON__", JsonSerializer.Serialize(BuildAbsoluteWebsiteUrl("/Documentation")))
            .Replace("__ISSUE_PROMPT__", JsonSerializer.Serialize(BuildIssueAssistantPrompt()));
    }

    private string BuildAdminHtml() {
        string html = """
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>SocketJack Admin</title>
<style>
:root{color-scheme:dark;--line:#263449;--text:#e5edf7;--muted:#94a3b8;--accent:#40c9a2;--bad:#fb7185;--warn:#fbbf24}
*{box-sizing:border-box}[hidden]{display:none!important}body{margin:0;min-height:100vh;background:linear-gradient(135deg,#071018,#0f172a 58%,#05201d);color:var(--text);font-family:"Segoe UI","Cascadia Code",sans-serif}.app{padding:18px;display:grid;gap:14px}.top{display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;border:1px solid var(--line);border-radius:8px;background:rgba(17,24,39,.82);padding:14px 16px}.admin-brand{display:inline-flex;align-items:center;gap:12px;color:var(--text);text-decoration:none}.admin-brand-mark{width:40px;height:40px;display:grid;place-items:center;border-radius:9px;background:linear-gradient(135deg,#52e4ff,#68f5b4 43%,#ff7ab6);color:#031019;font-weight:1000;box-shadow:0 0 34px rgba(84,225,192,.34),inset 0 1px 0 rgba(255,255,255,.74)}.title{font-size:1.2rem;font-weight:800}.sub{color:var(--muted);font-size:.82rem;margin-top:2px}.actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}a,button{min-height:34px;border:1px solid rgba(64,201,162,.42);border-radius:7px;background:rgba(64,201,162,.16);color:#eafff8;font-weight:800;text-decoration:none;padding:7px 10px;cursor:pointer}button.secondary{border-color:rgba(125,211,252,.28);background:rgba(15,23,42,.62);color:#dbeafe}.pill{border:1px solid rgba(125,211,252,.28);border-radius:999px;padding:7px 10px;color:#dbeafe;background:rgba(15,23,42,.62);font:800 .72rem "Cascadia Code",monospace}.pill.good{border-color:rgba(64,201,162,.44);color:#baf7e6;background:rgba(20,83,45,.24)}.pill.bad{border-color:rgba(251,113,133,.44);color:#fecdd3;background:rgba(127,29,29,.22)}.admin-auth{border:1px solid var(--line);border-radius:8px;background:rgba(17,24,39,.82);padding:14px;display:grid;grid-template-columns:minmax(0,1fr) auto auto auto;gap:10px;align-items:end}.admin-auth label{display:grid;gap:5px;color:var(--muted);font-size:.72rem}.admin-auth input{min-height:34px;border:1px solid rgba(125,211,252,.26);border-radius:7px;background:rgba(2,6,23,.46);color:var(--text);padding:7px 9px}.sql-panel{border:1px solid var(--line);border-radius:8px;background:rgba(17,24,39,.82);padding:14px;display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap}.sql-panel h2{font-size:.95rem;margin:0}.sql-meta{color:var(--muted);font:.76rem "Cascadia Code",monospace;margin-top:4px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.panel{min-width:0;border:1px solid var(--line);border-radius:8px;background:rgba(17,24,39,.82);overflow:hidden}.panel h2{font-size:.95rem;margin:0;padding:12px 14px;border-bottom:1px solid var(--line)}.table-wrap{overflow:auto;max-height:calc(100vh - 250px)}table{width:100%;border-collapse:collapse;font-size:.78rem}th,td{padding:8px 10px;border-bottom:1px solid rgba(148,163,184,.14);vertical-align:top;text-align:left}th{position:sticky;top:0;background:#111827;color:#bfdbfe;z-index:1}td.detail{min-width:280px;color:var(--muted);font-family:"Cascadia Code",monospace;white-space:pre-wrap}.severity-critical,.level-error{color:var(--bad);font-weight:900}.severity-warning,.level-warning{color:var(--warn);font-weight:900}.empty,.error{padding:18px;color:var(--muted)}.error{color:#fecdd3}@media(max-width:980px){.grid{grid-template-columns:1fr}.admin-auth{grid-template-columns:1fr}.table-wrap{max-height:none}}
</style>
</head>
<body>
<div class="app">
  <div class="top">
    <a class="admin-brand" href="/Download" aria-label="SocketJack downloads"><span class="admin-brand-mark" aria-hidden="true">SJ</span><div><div class="title">SocketJack Admin</div><div class="sub">Runtime reports, JACK-only issues, service logs, and SQL Admin controls</div></div></a>
    <div class="actions"><span class="pill" id="userPill">Checking</span><button id="refreshBtn" type="button">Refresh</button><button class="secondary" id="logoutBtn" type="button" hidden>Logout</button><a href="/">Master List</a></div>
  </div>
  <form id="adminLogin" class="admin-auth" hidden>
    <label>Username<input id="loginUser" autocomplete="username" value="JACK"></label>
    <label>Password<input id="loginPass" type="password" autocomplete="current-password"></label>
    <button type="submit">Login</button>
    <div id="loginMessage" class="error"></div>
  </form>
  <section id="sqlPanel" class="sql-panel" hidden>
    <div><h2>SQL Admin Panel</h2><div class="sql-meta" id="sqlMeta">Loading</div></div>
    <div class="actions"><span class="pill" id="sqlStatus">Unknown</span><button id="enableSqlBtn" type="button">Enable</button><button class="secondary" id="disableSqlBtn" type="button">Disable</button><a id="openSqlLink" href="/sql">Open SQL</a></div>
  </section>
  <div id="adminBody" class="grid" hidden>
    <section class="panel"><h2>Runtime Reports</h2><div class="table-wrap"><table><thead><tr><th>Time</th><th>Severity</th><th>Provider</th><th>Server</th><th>Reason</th><th>Detail</th></tr></thead><tbody id="reports"></tbody></table><div id="reportEmpty" class="empty" hidden>No runtime reports yet.</div></div></section>
    <section class="panel" id="issuesPanel" hidden><h2>Troubleshooting Issues</h2><div class="table-wrap"><table><thead><tr><th>Time</th><th>Status</th><th>Reporter</th><th>Title</th><th>Error</th><th>Screens</th></tr></thead><tbody id="issues"></tbody></table><div id="issueEmpty" class="empty" hidden>No reported issues yet.</div></div></section>
    <section class="panel"><h2>SocketJack Logs</h2><div class="table-wrap"><table><thead><tr><th>Time</th><th>Level</th><th>Category</th><th>Message</th><th>User</th><th>Detail</th></tr></thead><tbody id="logs"></tbody></table><div id="logEmpty" class="empty" hidden>No log entries yet.</div></div></section>
  </div>
  <div id="error" class="error" hidden></div>
</div>
<script>
const API_BASE=__API_BASE__;
function api(path){const base=String(API_BASE||'').replace(/\/$/,'');return base?base+path:path}
function readCookie(name){return document.cookie.split(';').map(x=>x.trim()).reduce((found,part)=>{if(found)return found;const eq=part.indexOf('=');if(eq<0)return'';return part.slice(0,eq)===name?decodeURIComponent(part.slice(eq+1)):''},'')}
function writeCookie(name,value,days){document.cookie=name+'='+encodeURIComponent(value)+'; Path=/; Max-Age='+(days*86400)+'; SameSite=Lax'}
function deleteCookie(name){document.cookie=name+'=; Path=/; Max-Age=0; SameSite=Lax'}
function token(){return localStorage.getItem('SocketJackAccessToken')||sessionStorage.getItem('SocketJackAccessToken')||readCookie('SocketJackAuth')||''}
function saveToken(data){const t=data&&data.accessToken?data.accessToken:(data&&data.access_token?data.access_token:'');localStorage.removeItem('SocketJackAccessToken');sessionStorage.removeItem('SocketJackAccessToken');if(t)localStorage.setItem('SocketJackAccessToken',t);if(data&&data.username)writeCookie('SocketJackLoginName',data.username,365)}
function clearToken(){localStorage.removeItem('SocketJackAccessToken');sessionStorage.removeItem('SocketJackAccessToken')}
function headers(extra){const h=Object.assign({},extra||{});const t=token();const u=readCookie('SocketJackLoginName');if(t)h.Authorization='Bearer '+t;if(u)h['X-SocketJack-User']=u;return h}
async function json(path){const r=await fetch(api(path),{cache:'no-store',credentials:'include',headers:headers()});const text=await r.text();let data={};if(text.trim()){try{data=JSON.parse(text)}catch{data={detail:text}}}if(!r.ok)throw new Error(data.error||data.detail||('HTTP '+r.status));return data}
async function postJson(path,body){const r=await fetch(api(path),{method:'POST',credentials:'include',headers:headers({'Content-Type':'application/json'}),body:JSON.stringify(body||{})});const text=await r.text();let data={};if(text.trim()){try{data=JSON.parse(text)}catch{data={detail:text}}}if(!r.ok)throw new Error(data.error||data.detail||('HTTP '+r.status));return data}
function esc(v){return String(v||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function time(v){try{return v?new Date(v).toLocaleString():''}catch{return v||''}}
function row(html){const tr=document.createElement('tr');tr.innerHTML=html;return tr}
function renderReports(items){const body=document.getElementById('reports');body.textContent='';document.getElementById('reportEmpty').hidden=items.length>0;items.forEach(x=>body.appendChild(row('<td>'+esc(time(x.createdUtc))+'</td><td class="severity-'+esc((x.severity||'').toLowerCase())+'">'+esc(x.severity)+'</td><td>'+esc((x.primaryProvider||'')+' -> '+(x.fallbackProvider||''))+'</td><td>'+esc(x.serverName||x.serverId||x.publicHost)+'</td><td>'+esc(x.reason)+'</td><td class="detail">'+esc(x.detail)+'</td>')))}
function renderIssues(items,visible){const panel=document.getElementById('issuesPanel');panel.hidden=!visible;const body=document.getElementById('issues');body.textContent='';document.getElementById('issueEmpty').hidden=!visible||items.length>0;if(!visible)return;items.forEach(x=>{let screens=[];try{screens=JSON.parse(x.screenshotManifestJson||'[]')}catch{}const screenLinks=screens.slice(0,10).map((s,i)=>'<a href="'+esc(s.dataUrl||'#')+'" target="_blank" rel="noopener">shot '+(i+1)+'</a>').join('<br>');body.appendChild(row('<td>'+esc(time(x.createdUtc))+'</td><td>'+esc(x.status||'new')+'</td><td>'+esc(x.ownerUserName||x.clientIp||'guest')+'</td><td><strong>'+esc(x.title)+'</strong><div class="detail">'+esc(x.context)+'</div></td><td class="detail">'+esc((x.errorText||'').slice(0,4000))+'</td><td>'+esc(x.screenshotCount||0)+'<br>'+screenLinks+'</td>'))})}
function renderLogs(items){const body=document.getElementById('logs');body.textContent='';document.getElementById('logEmpty').hidden=items.length>0;items.forEach(x=>body.appendChild(row('<td>'+esc(time(x.createdUtc))+'</td><td class="level-'+esc((x.level||'').toLowerCase())+'">'+esc(x.level)+'</td><td>'+esc(x.category)+'</td><td>'+esc(x.message)+'</td><td>'+esc(x.userName)+'</td><td class="detail">'+esc(x.detail)+'</td>')))}
function setAuthed(on,user){document.getElementById('adminLogin').hidden=!!on;document.getElementById('adminBody').hidden=!on;document.getElementById('sqlPanel').hidden=!on;document.getElementById('logoutBtn').hidden=!on;const pill=document.getElementById('userPill');pill.textContent=on?(user+' | admin'):'Admin required';pill.classList.toggle('good',!!on);pill.classList.toggle('bad',!on)}
function renderSql(state){state=state||{};const enabled=!!(state.enabled||state.sqlAdminEnabled);const status=document.getElementById('sqlStatus');status.textContent=enabled?'Enabled':'Disabled';status.classList.toggle('good',enabled);status.classList.toggle('bad',!enabled);document.getElementById('sqlMeta').textContent=(state.database||'SocketJack')+' / '+(state.listener||'listener')+' / '+(state.url||state.sqlAdminUrl||'/sql');const link=document.getElementById('openSqlLink');link.href=state.url||state.sqlAdminUrl||'/sql'}
async function loadSql(){renderSql(await json('/api/socketjack/admin/sql-admin'))}
async function setSql(enabled){renderSql(await postJson('/api/socketjack/admin/sql-admin',{enabled:!!enabled,sqlAdminEnabled:!!enabled}));await load()}
async function login(e){e.preventDefault();const msg=document.getElementById('loginMessage');msg.textContent='';try{const data=await postJson('/api/web-auth/login',{username:document.getElementById('loginUser').value,password:document.getElementById('loginPass').value,remember:true});saveToken(data);document.getElementById('loginPass').value='';await load()}catch(err){msg.textContent=err.message;setAuthed(false,'')}}
async function logout(){try{await postJson('/api/web-auth/logout',{})}catch{}clearToken();deleteCookie('SocketJackLoginName');setAuthed(false,'');renderReports([]);renderIssues([],false);renderLogs([])}
async function load(){const err=document.getElementById('error');err.hidden=true;try{const summary=await json('/api/socketjack/admin');setAuthed(true,summary.username||'admin');const canIssues=!!summary.canViewIssues;renderReports(summary.latestReports||[]);renderIssues(summary.latestIssues||[],canIssues);renderLogs(summary.latestLogs||[]);renderSql(summary.sqlAdmin);const reports=await json('/api/socketjack/admin/reports?take=200');renderReports(reports.reports||[]);if(canIssues){const issues=await json('/api/socketjack/admin/issues?take=200');renderIssues(issues.issues||[],true)}const logs=await json('/api/socketjack/admin/logs?take=300');renderLogs(logs.logs||[]);await loadSql()}catch(e){err.textContent=e.message;err.hidden=false;setAuthed(false,'')}}
document.getElementById('adminLogin').addEventListener('submit',login);
document.getElementById('logoutBtn').addEventListener('click',logout);
document.getElementById('enableSqlBtn').addEventListener('click',()=>setSql(true).catch(e=>{const err=document.getElementById('error');err.textContent=e.message;err.hidden=false}));
document.getElementById('disableSqlBtn').addEventListener('click',()=>setSql(false).catch(e=>{const err=document.getElementById('error');err.textContent=e.message;err.hidden=false}));
document.getElementById('refreshBtn').addEventListener('click',load);
load();setInterval(load,15000);
</script>
</body>
</html>
""";
        return html.Replace("__API_BASE__", JsonSerializer.Serialize(GetBrowserApiBaseUrl()));
    }

