,240,.76);font-size:.82rem;line-height:1.45}.model-bench{border:1px solid rgba(148,163,184,.18);border-radius:7px;background:rgba(2,6,23,.24);overflow:hidden}.model-bench summary{cursor:pointer;display:flex;align-items:center;justify-content:space-between;padding:8px 10px;font-weight:800}.model-list{display:grid;gap:6px;padding:0 10px 10px}.model-row{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;align-items:center;border-top:1px solid rgba(148,163,184,.12);padding-top:6px}.model-name{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.rating{min-width:68px;text-align:center;border-radius:999px;padding:4px 8px;color:#051016;font:900 .72rem "Cascadia Code",monospace}.model-meta{grid-column:1/-1;color:var(--muted);font:.68rem "Cascadia Code",monospace}.facts{display:flex;flex-wrap:wrap;gap:8px}.fact{min-width:132px;max-width:340px;border:1px solid rgba(148,163,184,.18);border-radius:7px;background:rgba(2,6,23,.26);padding:8px 10px}.fact span{display:block;color:var(--muted);font:.62rem "Cascadia Code",monospace;text-transform:uppercase}.fact b{display:block;margin-top:3px;font-size:.78rem}.empty{height:100%;display:grid;place-items:center;text-align:center;color:var(--muted)}@media(max-width:860px){.workspace{grid-template-columns:1fr}.topbar{grid-template-columns:1fr}.status{justify-content:flex-start}.app{padding:12px}.server-top{grid-template-columns:1fr}.server-actions{justify-content:flex-start}.variant-select{max-width:100%}}
