border-radius:0 999px 999px 0}.benchmark-symbol.tools::after{content:"";position:absolute;left:4px;top:4px;width:3px;height:10px;border-radius:999px;background:currentColor}.model-showcase{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:8px}.model-tile{--score:.25;position:relative;overflow:hidden;min-height:78px;border:1px solid rgba(125,211,252,.24);border-radius:8px;padding:10px;background:linear-gradient(90deg,rgba(7,89,133,calc(.18 + var(--score)*.42)),rgba(14,165,233,calc(.10 + var(--score)*.28))),rgba(2,6,23,.34);box-shadow:inset 0 1px 0 rgba(255,255,255,.11)}.model-tile::before{content:"";position:absolute;inset:0;background:linear-gradient(100deg,transparent 0 30%,rgba(186,230,253,.22) 45%,transparent 62%);transform:translateX(-140%);animation:modelSweep 3.8s ease-in-out infinite}.model-tile::after{content:"";position:absolute;left:0;bottom:0;height:3px;width:calc(var(--score)*100%);background:#7dd3fc;box-shadow:0 0 18px rgba(125,211,252,.75)}.model-tile strong,.model-tile .model-badges,.model-tile .model-score{position:relative;z-index:1}.model-tile strong{display:block;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:.82rem}.model-badges{display:flex;gap:6px;flex-wrap:wrap;margin-top:9px}.model-badge{display:inline-flex;align-items:center;gap:4px;border-radius:999px;padding:3px 7px;border:1px solid rgba(255,255,255,.16);font:900 .62rem "Cascadia Code",monospace}.model-badge.visual{border-color:rgba(251,146,60,.34);background:rgba(249,115,22,.20);color:#fed7aa}.model-badge.tools{border-color:rgba(59,130,246,.36);background:rgba(37,99,235,.22);color:#bfdbfe}.model-badge.base{background:rgba(148,163,184,.16);color:#dbeafe}.model-symbol{width:7px;height:7px;border-radius:999px;background:currentColor;box-shadow:0 0 10px currentColor}.model-score{margin-top:8px;color:rgba(226,232,240,.82);font:.68rem "Cascadia Code",monospace}@keyframes modelSweep{0%{transform:translateX(-140%)}48%,100%{transform:translateX(140%)}}@media(max-width:980px){.model-showcase{grid-template-columns:1fr}}
.server{overflow:hidden;isolation:isolate;box-shadow:0 22px 70px rgba(2,6,23,.24),inset 0 1px 0 rgba(255,255,255,.08)}.server::before{content:"";position:absolute;inset:-1px;z-index:-1;background:radial-gradient(circle at 12% 0%,rgba(125,211,252,.20),transparent 26rem),radial-gradient(circle at 92% 10%,rgba(64,201,162,.12),transparent 20rem);opacity:.8}.server::after{content:"";position:absolute;inset:0;z-index:-1;background:linear-gradient(110deg,transparent 0 40%,rgba(255,255,255,.045) 48%,transparent 58%);transform:translateX(-120%);animation:cardSweep 8s ease-in-out infinite}.server:hover{box-shadow:0 26px 84px rgba(2,6,23,.34),0 0 0 1px rgba(125,211,252,.16),inset 0 1px 0 rgba(255,255,255,.10)}.server h2{font-size:1.08rem}.server-summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px}.summary-chip{position:relative;min-height:56px;border:1px solid rgba(148,163,184,.18);border-radius:8px;background:linear-gradient(135deg,rgba(255,255,255,.06),rgba(2,6,23,.22));padding:9px 10px;overflow:hidden}.summary-chip::before{content:"";position:absolute;left:0;top:0;bottom:0;width:3px;background:var(--chip,#7dd3fc);box-shadow:0 0 16px var(--chip,#7dd3fc)}.summary-chip span{display:block;color:var(--muted);font:.61rem "Cascadia Code",monospace;text-transform:uppercase}.summary-chip b{display:block;margin-top:4px;font-size:.82rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.summary-chip.good{--chip:#40c9a2}.summary-chip.warn{--chip:#fbbf24}.summary-chip.bad{--chip:#fb7185}.summary-chip.blue{--chip:#7dd3fc}.model-showcase{position:relative}.model-showcase::before{content:"Top models";position:absolute;right:2px;top:-18px;color:rgba(125,211,252,.75);font:900 .62rem "Cascadia Code",monospace;text-transform:uppercase}.model-tile{transition:transform 180ms ease,border-color 180ms ease}.model-tile:hover{transform:translateY(-2px);border-color:rgba(186,230,253,.44)}@keyframes cardSweep{0%,55%{transform:translateX(-120%)}78%,100%{transform:translateX(120%)}}@media(max-width:980px){.server-summary{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:620px){.server-summary{grid-template-columns:1fr}}
.state-pill{display:inline-flex;align-items:center;gap:6px}.location-pill{white-space:nowrap;min-width:76px;justify-content:center}.location-flag{font-size:1rem;line-height:1}.location-offset{font-size:.68rem}.offline-pill{border-color:rgba(251,113,133,.54);color:#ffe4e6;background:rgba(127,29,29,.30)}.state-icon{position:relative;display:inline-block;flex:0 0 auto;width:15px;height:10px}.state-icon::before,.state-icon::after{content:"";position:absolute;top:3px;width:5px;height:5px;border-radius:999px;background:currentColor;box-shadow:0 0 9px currentColor}.state-icon::before{left:0}.state-icon::after{right:0}.state-icon .state-line{position:absolute;left:4px;right:4px;top:5px;height:2px;border-radius:999px;background:currentColor;box-shadow:0 0 9px currentColor}.state-icon.disconnected .state-line{left:4px;right:auto;width:4px;transform:rotate(-24deg)}.state-icon.disconnected .state-break{position:absolute;right:4px;top:4px;width:4px;height:2px;border-radius:999px;background:currentColor;transform:rotate(-24deg);box-shadow:0 0 9px currentColor}.model-symbol.eye{position:relative;width:13px;height:8px;border:1.5px solid currentColor;border-radius:999px;background:transparent;box-shadow:none}.model-symbol.eye::after{content:"";position:absolute;left:50%;top:50%;width:3px;height:3px;border-radius:999px;background:currentColor;transform:translate(-50%,-50%);box-shadow:0 0 8px currentColor}.model-symbol.tools-icon{position:relative;width:13px;height:13px;border-radius:0;background:transparent;box-shadow:none;transform:rotate(-35deg)}.model-symbol.tools-icon::before{content:"";position:absolute;left:5px;top:0;width:7px;height:5px;border:1.5px solid currentColor;border-left:0;border-radius:0 999px 999px 0;background:transparent;box-shadow:0 0 8px currentColor}.model-symbol.tools-icon::after{content:"";position:absolute;left:3px;top:4px;width:3px;height:9px;border-radius:999px;background:currentColor;box-shadow:0 0 8px currentColor}.compact-line{display:flex;gap:7px;flex-