uto-fit,minmax(112px,1fr));gap:6px}.summary-chip{min-height:48px;padding:7px 9px;background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(2,6,23,.24))}.summary-chip span{font-size:.56rem}.summary-chip b{font-size:.76rem}.server-details summary{padding:7px 9px;font-size:.78rem}.facts{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:6px}.fact{min-width:0;max-width:none;padding:7px 9px}.compact-resources{font-size:.69rem}.launch,.variant-select,.pill{min-height:28px;padding:4px 9px;font-size:.68rem}@keyframes cardAuraSpin{to{transform:rotate(360deg)}}@media(max-width:620px){.server-list{grid-template-columns:1fr;padding:8px}.server{padding:10px}.compact-resources{white-space:normal}.server-actions>*{width:auto}.server-actions .launch{width:100%}}
.release-sticker{position:fixed;right:22px;top:22px;z-index:8;min-height:42px;display:inline-grid;place-items:center;border:1px solid rgba(125,211,252,.34);border-radius:8px;padding:8px 13px;background:rgba(8,16,25,.78);box-shadow:0 16px 50px rgba(2,6,23,.34),inset 0 1px 0 rgba(255,255,255,.10);backdrop-filter:blur(18px);color:#dffbff;text-decoration:none;font-weight:900}.release-sticker.download{border-color:rgba(64,201,162,.56);background:linear-gradient(135deg,rgba(64,201,162,.38),rgba(125,211,252,.16));color:#f2fffb}.landing{position:relative;z-index:2;min-height:100vh;overflow:hidden;padding:86px 24px 32px}.landing::before{content:"";position:absolute;inset:0;z-index:-2;background:linear-gradient(120deg,#061018 0%,#071a21 38%,#0c101a 100%)}.landing::after{content:"";position:absolute;inset:-20%;z-index:-1;background:repeating-linear-gradient(110deg,rgba(125,211,252,.08) 0 1px,transparent 1px 26px),linear-gradient(135deg,transparent 0 52%,rgba(64,201,162,.10) 52% 58%,transparent 58%),linear-gradient(25deg,transparent 0 60%,rgba(125,211,252,.10) 60% 66%,transparent 66%);transform:translateY(var(--parallax-y,0px));transition:transform .08s linear}.hero{min-height:calc(100vh - 118px);display:grid;grid-template-columns:minmax(0,1.05fr) minmax(320px,.95fr);gap:28px;align-items:center;max-width:1240px;margin:0 auto}.hero h1{font-size:clamp(2.6rem,5vw,5.8rem);line-height:.95;margin:0;max-width:760px}.hero-copy{color:rgba(226,232,240,.82);font-size:1.04rem;line-height:1.7;max-width:660px;margin-top:18px}.hero-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:24px}.hero-actions a,.hero-actions button,.page-link{display:inline-grid;place-items:center;min-height:42px;border:1px solid rgba(64,201,162,.38);border-radius:8px;background:linear-gradient(135deg,rgba(64,201,162,.24),rgba(125,211,252,.12));color:#eafff8;text-decoration:none;font-weight:900;padding:9px 14px}.hero-actions .secondary,.page-link.secondary{border-color:rgba(125,211,252,.26);background:rgba(15,23,42,.66)}.nav-pages{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.nav-card{min-height:184px;text-align:left;padding:18px;border:1px solid rgba(148,163,184,.20);border-radius:8px;background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(15,23,42,.54));box-shadow:0 20px 70px rgba(2,6,23,.30);backdrop-filter:blur(14px);color:var(--text);cursor:pointer}.nav-card strong{display:block;font-size:1.08rem}.nav-card span{display:block;margin-top:10px;color:rgba(226,232,240,.74);line-height:1.5}.nav-card.active{border-color:rgba(64,201,162,.56);box-shadow:0 0 0 3px rgba(64,201,162,.13),0 20px 70px rgba(2,6,23,.30)}.landing-page{max-width:1240px;margin:0 auto 34px;padding:22px;border:1px solid rgba(148,163,184,.18);border-radius:8px;background:rgba(8,16,25,.66);backdrop-filter:blur(16px);display:none}.landing-page.active{display:grid;gap:12px;animation:pageIn 420ms var(--surface) both}.landing-page h2{margin:0;font-size:1.35rem}.landing-page p{margin:0;color:rgba(226,232,240,.78);line-height:1.6}.auth-modal{position:fixed;inset:0;z-index:7;display:grid;place-items:center;padding:24px;background:rgba(2,6,23,.42);backdrop-filter:blur(12px) saturate(1.25)}.auth-modal[hidden]{display:none!important}.auth-card{width:min(440px,100%);border:1px solid rgba(224,242,254,.28);border-radius:8px;background:linear-gradient(145deg,rgba(17,24,39,.74),rgba(8,16,25,.58));box-shadow:0 30px 100px rgba(0,0,0,.45),inset 0 1px 0 rgba(255,255,255,.16);overflow:hidden;animation:modalIn 320ms var(--surface) both}.modal-close{float:right;min-height:28px;margin:10px 10px 0 0;padding:2px 9px}.workspace{grid-template-columns:minmax(0,1fr)}body:not(.authed) .app,body.master-list-auth-required:not(.authed) .landing{display:none}body.authed .landing{display:none}.panel.side{border:0;border-radius:0;background:transparent;box-shadow:none}.panel.side .panel-head{padding-top:18px}@keyframes pageIn{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}}@keyframes modalIn{from{opacity:0;transform:translateY(18px) scale(.97)}to{opacity:1;transform:none}}@media(max-width:920px){.hero{grid-template-columns:1fr}.nav-pages{grid-template-columns:1fr}.release-sticker{left:14px;right:14px;top:14px}.landing{padding-top:78px}}
.bg-swirl{inset:-24vmax;filter:blur(68px) saturate(1.38) brightness(.94);opacity:.86;background:radial-gradient(circle at calc(18% + var(--parallax-x)) calc(18% + var(--parallax-y)),rgba(232,249,255,.66),transparent 24vmax),radial-gradient(ellipse at calc(82% - var(--parallax-x)) 20%,rgba(56,189,248,.58),transparent 25vmax),radial-gradient(ellipse at 68% calc(82% - var(--parallax-y)),rgba(64,201,162,.42),transparent 30vmax),conic-gradient(from var(--glass-tilt) at 50% 52%,rgba(3,7,18,.18),rgba(14,165,233,.30),rgba(186,230,253,.25),rgba(64,201,162,.22),rgba(79,70,229,.18),rgba(3,7,18,.18));background-size:165% 165%,180% 180%,170% 170%,260% 260%;transform:translate3d(var(--bg-shift-x),var(--bg-shift-y),0) scale(1.06);animation:drift 116s ease-in-out infinite alternate}
.glass-parallax{inset:-2vmax;z-index:1;overflow:hidden;opacity:.58;background:radial-gradient(circle at var(--glass-x) var(--glass-y),rgba(240,249,255,.34),transparent 17rem),linear-gradient(var(--glass-tilt),rgba(255,255,255,.13),rgba(186,230,253,.045) 32%,rgba(255,255,255,.13) 48%,rgba(125,211,252,.055) 66%,rgba(255,255,255,.08)),repeating-linear-gradient(112deg,rgba(255,255,255,.055) 0 1px,transparent 1px 19px),repeating-linear-gradient(22deg,rgba(186,230,253,.028) 0 1px,transparent 1px 31px);mix-blend-mode:screen;backdrop-filter:blur(5px) saturate(1.18);filter:blur(1.2px) saturate(1.25);transform:translate3d(var(--glass-shift-x),var(--glass-shift-y),0)}
.glass-parallax::before,.glass-parallax::after{content:"";position:absolute;pointer-events:none;border-radius:999px;filter:blur(20px)}
.glass-parallax::before{left:calc(var(--glass-x) - 34rem);top:calc(var(--glass-y) - 9rem);width:72rem;height:18rem;background:linear-gradient(100deg,transparent,rgba(255,255,255,.24) 36%,rgba(186,230,253,.36) 50%,rgba(255,255,255,.16) 62%,transparent);opacity:.68;transform-origin:50% 50%;animation:centerBeamThrobble 42s linear infinite}
.glass-parallax::after{left:calc(var(--glass-x) - 14rem);top:calc(var(--glass-y) - 14rem);width:28rem;height:28rem;background:radial-gradient(circle,rgba(255,255,255,.22),rgba(186,230,253,.16) 36%,transparent 70%);opacity:.62;transform-origin:50% 50%;animation:centerCoreThrobble 8s var(--surface) infinite}
body.loading .bg-swirl{opacity:.98;animation:drift 46s ease-in-out infinite alternate,loadingSwirlGlow 2600ms ease-in-out infinite}
body.loading .glass-parallax{animation:loadingGlassGlow 2600ms ease-in-out infinite}
body.loading .glass-parallax::before{animation-duration:18s}
body.loading .glass-parallax::after{animation-duration:4200ms}
@keyframes centerBeamThrobble{0%{transform:translate3d(var(--beam-shift-x),var(--beam-shift-y),0) rotate(-14deg) scaleX(.96)}50%{transform:translate3d(var(--beam-shift-x),var(--beam-shift-y),0) rotate(166deg) scaleX(1.05)}100%{transform:translate3d(var(--beam-shift-x),var(--beam-shift-y),0) rotate(346deg) scaleX(.96)}}
@keyframes centerCoreThrobble{0%,100%{transform:translate3d(var(--core-shift-x),var(--core-shift-y),0) scale(.96);filter:blur(22px)}50%{transform:translate3d(var(--core-shift-x),var(--core-shift-y),0) scale(1.09);filter:blur(14px)}}
@keyframes loadingSwirlGlow{0%,100%{filter:blur(68px) saturate(1.38) brightness(.98)}50%{filter:blur(54px) saturate(1.72) brightness(1.28)}}
@keyframes loadingGlassGlow{0%,100%{opacity:.62;filter:blur(1.2px) saturate(1.25) brightness(1.04)}50%{opacity:.88;filter:blur(.7px) saturate(1.68) brightness(1.28)}}
.landing::after{background:repeating-linear-gradient(110deg,rgba(224,242,254,.095) 0 1px,transparent 1px 28px),radial-gradient(circle at var(--glass-x) var(--glass-y),rgba(125,211,252,.20),transparent 26rem),linear-gradient(135deg,transparent 0 52%,rgba(64,201,162,.12) 52% 58%,transparent 58%),linear-gradient(25deg,transparent 0 60%,rgba(125,211,252,.12) 60% 66%,transparent 66%);transform:translate3d(var(--landing-shift-x),var(--landing-shift-y),0);transition:none}
.nav-pages{align-self:stretch;display:grid;grid-template-columns:1fr;gap:0;padding:8px;border:1px solid rgba(224,242,254,.16);border-radius:8px;background:linear-gradient(145deg,rgba(224,242,254,.10),rgba(2,6,23,.22));box-shadow:inset 0 1px 0 rgba(255,255,255,.10),0 18px 60px rgba(2,6,23,.22);backdrop-filter:blur(20px) saturate(1.16)}
.nav-card{min-height:118px;border:1px solid transparent;border-radius:6px;background:transparent;box-shadow:none;backdrop-filter:none;padding:16px 15px;color:rgba(229,237,247,.88);transition:transform 180ms var(--surface),border-color 180ms var(--surface),background 180ms var(--surface),box-shadow 180ms var(--surface)}
.nav-card+.nav-card{border-top-color:rgba(148,163,184,.14)}
.nav-card:hover{transform:translateX(2px);background:rgba(125,211,252,.08);border-color:rgba(125,211,252,.20)}
.nav-card.active{border-color:rgba(248,113,113,.62);color:#fee2e2;background:linear-gradient(135deg,rgba(127,29,29,.42),rgba(248,113,113,.13));box-shadow:inset 3px 0 0 rgba(248,113,113,.95),0 10px 30px rgba(127,29,29,.20)}
.nav-card.active strong{color:#fecdd3}
.nav-card strong{font-size:1rem}.nav-card span{font-size:.86rem}
.selection-summary{display:grid;gap:9px;color:rgba(226,232,240,.82);line-height:1.6}.selection-summary h3{margin:4px 0 0;color:#f8fbff;font-size:1.02rem}.selection-summary p{margin:0}.selection-summary ul{margin:0;padding-left:1.15rem;display:grid;gap:5px}.selection-summary strong{color:#fef2f2}.selection-summary em{color:#bae6fd}.selection-summary code{border:1px solid rgba(125,211,252,.22);border-radius:5px;background:rgba(2,6,23,.42);padding:1px 5px;color:#d8f3ff}.selection-summary a{color:#7dd3fc}.summary-symbol{display:inline-grid;place-items:center;width:1.2em;color:#f87171;font-weight:900}.landing-page.active{border-color:rgba(248,113,113,.22)}
.release-sticker{transition:transform 180ms var(--surface),border-color 180ms var(--surface),background 180ms var(--surface),box-shadow 180ms var(--surface)}
.release-label{position:relative;z-index:2;display:inline-block;white-space:nowrap}
body.authed .release-sticker,.release-sticker.top-docked{position:static;height:30px;min-height:30px;align-self:center;flex:0 0 auto;margin:0;padding:4px 11px;border-radius:7px;box-shadow:inset 0 1px 0 rgba(255,255,255,.12);backdrop-filter:blur(14px);line-height:1;white-space:nowrap}
body.authed .release-sticker.download,.release-sticker.top-docked.download{position:relative;top:auto;right:auto;bottom:auto;left:auto;overflow:hidden;width:156px;max-width:156px;border-color:rgba(163,230,53,.78);background:linear-gradient(135deg,rgba(132,204,22,.98),rgba(34,197,94,.78) 52%,rgba(190,242,100,.86));box-shadow:0 0 20px rgba(132,204,22,.50),0 0 44px rgba(34,197,94,.18),inset 0 1px 0 rgba(255,255,255,.35);color:#04210c;text-shadow:0 1px 0 rgba(255,255,255,.28)}
body.authed .release-sticker.download:hover{transform:translateY(-1px);border-color:rgba(217,249,157,.92);box-shadow:0 0 34px rgba(163,230,53,.78),0 0 78px rgba(34,197,94,.36),inset 0 1px 0 rgba(255,255,255,.45)}
body.authed .release-sticker.download::before{content:"";position:absolute;inset:-80%;z-index:0;background:radial-gradient(circle at 28% 30%,rgba(255,255,255,.55),transparent 7%),radial-gradient(circle at 58% 65%,rgba(236,252,203,.42),transparent 8%),radial-gradient(circle at 78% 24%,rgba(187,247,208,.46),transparent 7%),conic-gradient(from 0deg,transparent,rgba(236,252,203,.34),transparent 36%);opacity:.78;animation:moneySplash 4.4s linear infinite}
body.authed .release-sticker.download::after{content:"";position:absolute;inset:0;z-index:1;background:linear-gradient(100deg,transparent 0 34%,rgba(255,255,255,.36) 48%,transparent 62%);transform:translateX(-130%);animation:limeSheen 2.7s ease-in-out infinite}
body.authed .release-sticker.download.scrolling .release-label{animation:releaseMarquee 2.8s linear infinite alternate}
body.authed .top-right{align-items:center;justify-content:flex-end}.status{order:0}.top-right>.release-sticker.top-docked{order:1}.top-auth{order:2;flex-wrap:nowrap}.top-auth .user-pill{order:0}.top-auth a{order:1}.top-auth button{order:2}#adminLink{position:fixed;right:18px;bottom:18px;z-index:26;min-height:38px;border-color:rgba(125,211,252,.52);background:linear-gradient(135deg,rgba(56,213,255,.24),rgba(45,244,180,.14),rgba(167,139,250,.16));box-shadow:0 0 26px rgba(56,213,255,.24),0 18px 54px rgba(0,0,0,.34),inset 0 1px 0 rgba(255,255,255,.18);backdrop-filter:blur(12px)}#adminLink[hidden]{display:none!important}
