<style>
.server.has-background{background:linear-gradient(145deg,rgba(4,8,17,.62),rgba(8,14,24,.42)),rgba(8,14,24,.50)}
.server.has-background::before{z-index:1;background:linear-gradient(135deg,rgba(4,8,17,.68),rgba(4,8,17,.28) 46%,rgba(4,8,17,.56)),radial-gradient(circle at 18% 0%,rgba(84,225,192,.22),transparent 22rem),radial-gradient(circle at 92% 12%,rgba(112,167,255,.18),transparent 20rem);opacity:1;filter:none;animation:none}
.server.has-background::after{z-index:1;opacity:.34}
.server-bg{position:absolute;inset:0;z-index:0;overflow:hidden;pointer-events:none;opacity:0;transition:opacity 180ms var(--surface)}
.server-bg img{width:100%;height:100%;object-fit:cover;transform:translate(var(--server-bg-x,0%),var(--server-bg-y,0%)) scale(var(--server-bg-scale,1));transform-origin:center;filter:saturate(1.08) contrast(1.04)}
.server.has-background .server-bg{opacity:1}
.server.has-background>:not(.server-bg){position:relative;z-index:2}
.image-icon-button{width:30px;min-width:30px;height:28px;min-height:28px;border:0;border-radius:7px;background:linear-gradient(90deg,rgba(255,0,98,.15),rgba(0,255,204,.15),rgba(93,143,255,.15));color:#fff;padding:0;display:inline-grid;place-items:center;box-shadow:none;transition:background 180ms var(--surface),color 180ms var(--surface),transform 180ms var(--surface)}
.image-icon-button:hover,.image-icon-button:focus-visible{background:linear-gradient(90deg,rgba(255,0,98,.66),rgba(0,255,204,.66),rgba(93,143,255,.66));color:#000;outline:none}
.image-upload-symbol{position:relative;width:16px;height:13px;border:2px solid currentColor;border-radius:3px;display:block}
.image-upload-symbol::before{content:"";position:absolute;right:2px;top:2px;width:3px;height:3px;border-radius:999px;background:currentColor}
.image-upload-symbol::after{content:"";position:absolute;left:2px;right:2px;bottom:2px;height:6px;background:currentColor;clip-path:polygon(0 100%,34% 42%,52% 70%,72% 22%,100% 100%)}
.background-editor{position:fixed;inset:0;z-index:40;display:grid;place-items:center;padding:18px;background:rgba(2,6,15,.72);backdrop-filter:blur(20px) saturate(1.05)}
.background-card{width:min(760px,calc(100vw - 28px));display:grid;gap:12px;border:1px solid rgba(226,244,255,.20);border-radius:8px;background:linear-gradient(145deg,rgba(255,255,255,.10),rgba(8,14,24,.74));box-shadow:0 34px 100px rgba(0,0,0,.46),inset 0 1px 0 rgba(255,255,255,.12);padding:14px}
.background-head{display:flex;align-items:center;justify-content:space-between;gap:10px;color:#e5edf7;font-weight:900}
.background-preview{position:relative;height:min(420px,54vh);min-height:240px;overflow:hidden;border:1px solid rgba(226,244,255,.18);border-radius:8px;background:rgba(2,8,14,.72);touch-action:none;cursor:grab}
.background-preview.dragging{cursor:grabbing}
.background-preview img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;transform:translate(var(--preview-bg-x,0%),var(--preview-bg-y,0%)) scale(var(--preview-bg-scale,1));transform-origin:center;user-select:none;-webkit-user-drag:none}
.background-preview::after{content:"";position:absolute;inset:0;border:1px solid rgba(255,255,255,.14);box-shadow:inset 0 0 0 999px rgba(2,8,14,.10);pointer-events:none}
.background-controls{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;align-items:center}
.background-controls label{display:grid;gap:5px;color:rgba(226,244,255,.72);font:.72rem "Cascadia Code",monospace}
.background-controls input[type=range]{padding:0;min-height:28px}
.background-actions{display:flex;gap:8px;justify-content:flex-end;flex-wrap:wrap}
