body::after{z-index:1;background:repeating-linear-gradient(180deg,rgba(255,255,255,.040) 0 1px,transparent 1px 5px),linear-gradient(90deg,rgba(84,225,192,.068),transparent 26%,rgba(244,143,177,.052) 72%,rgba(255,207,107,.058));mix-blend-mode:screen;opacity:.42}
.bg-swirl{z-index:0;opacity:.32;filter:blur(58px) saturate(1.58);mix-blend-mode:screen;background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.34),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.30),transparent 28rem),radial-gradient(circle at 50% 74%,rgba(244,143,177,.25),transparent 30rem)}
.bg-swirl::before,.bg-swirl::after{opacity:.14}
.glass-parallax{z-index:1;background:radial-gradient(circle at 50% 34%,rgba(84,225,192,.16),transparent 18rem),repeating-linear-gradient(115deg,rgba(255,255,255,.026) 0 1px,transparent 1px 18px);opacity:.42}
