.hero h1{font-weight:300;text-shadow:0 0 34px rgba(84,225,192,.18),0 14px 74px rgba(2,6,23,.72)}
.nav-pages{background:linear-gradient(135deg,rgba(8,14,24,.66),rgba(10,18,32,.48))}
.nav-card{background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(8,14,24,.34))}
.nav-card:hover{background:linear-gradient(145deg,rgba(84,225,192,.12),rgba(8,14,24,.42));border-color:rgba(84,225,192,.34)}
.nav-card.active{border-color:rgba(84,225,192,.48);background:linear-gradient(135deg,rgba(84,225,192,.22),rgba(112,167,255,.10));box-shadow:inset 0 -3px 0 rgba(84,225,192,.72),0 16px 44px rgba(84,225,192,.10)}
.landing-page{background:linear-gradient(145deg,rgba(255,255,255,.075),rgba(8,14,24,.42)),rgba(8,14,24,.52)}
.server-list{background:linear-gradient(135deg,rgba(255,255,255,.045),rgba(8,14,24,.26));border-color:rgba(255,255,255,.12)}
.server{background:linear-gradient(135deg,rgba(255,255,255,.10),rgba(84,225,192,.055) 42%,rgba(112,167,255,.060) 72%,rgba(8,14,24,.56));border-color:rgba(255,255,255,.16)}
.server:hover{border-color:rgba(84,225,192,.42);box-shadow:0 28px 90px rgba(2,8,23,.32),0 0 0 1px rgba(84,225,192,.16),inset 0 1px 0 rgba(255,255,255,.18)}
.toolbar input,.login input,.auth-card input,.variant-select{background:rgba(2,8,14,.58);border-color:rgba(255,255,255,.16)}
.pill,.cap,.latency-badge{background:rgba(8,14,24,.58);border-color:rgba(255,255,255,.16)}
body.authed{background:radial-gradient(circle at 16% 12%,rgba(84,225,192,.21),transparent 24rem),radial-gradient(circle at 86% 18%,rgba(112,167,255,.20),transparent 28rem),radial-gradient(circle at 50% 74%,rgba(244,143,177,.16),transparent 30rem),linear-gradient(180deg,#05070b 0%,#071323 44%,#05070b 100%)}
