.bg-swirl{animation:none;filter:blur(24px) saturate(1.36)!important;opacity:.28}
.bg-swirl::before,.bg-swirl::after{animation:none;filter:none;opacity:.12}
.glass-parallax{backdrop-filter:none;filter:saturate(1.16);opacity:.34}
.topbar,.panel,.server,.nav-pages,.nav-card,.landing-page,.auth-card,.cookie-consent,.server-list,.model-tile,.model-bench,.summary-chip,.fact,.server-details,.toolbar{backdrop-filter:blur(8px) saturate(1.05)}
