<body class="master-list-auth-required">
<canvas id="starfield" aria-hidden="true"></canvas>
<div class="bg-swirl"></div><div class="glass-parallax"></div>
<a class="release-sticker" id="releaseSticker" href="/Download" title="Download JackLLM Workstation."><span class="release-download" aria-hidden="true"></span><span class="release-label" id="releaseLabel">JackLLM Workstation</span></a>
<div id="postLoginLoader" class="post-login-loader" role="status" aria-live="polite" aria-label="Loading master list">
  <div class="loader-shell">
    <div class="loader-space"></div>
    <div class="loader-orbit">
      <span class="loader-poly"></span><span class="loader-poly"></span><span class="loader-poly"></span><span class="loader-poly"></span><span class="loader-poly"></span>
    </div>
    <div class="loader-orbit two"></div>
    <div class="loader-core"></div>
    <div class="loader-copy"><strong>Opening SocketJack Master</strong><span id="postLoginLoaderStatus">Loading master list</span></div>
  </div>
</div>
<section class="landing" id="landing">
  <div class="hero">
    <div>
      <h1 id="landingTitle">JackLLM Service</h1>
      <div class="hero-copy selection-summary" id="landingDescription"></div>
      <div class="hero-actions">
        <button type="button" id="openLoginBtn">Open JackLLM Service</button>
        <a class="secondary" href="https://github.com/JackOfFates/SocketJack" target="_blank" rel="noopener noreferrer">GitHub Docs</a>
      </div>
    </div>
    <div class="nav-pages">
      <button class="nav-card active" type="button" data-page="service"><strong>JackLLM Service</strong><span>Discover live local LLM hosts, compare model ratings, inspect GPU/CPU/RAM capacity, then launch through the SocketJack shell proxy so private machines can serve public sessions safely.</span></button>
      <button class="nav-card" type="button" data-page="nuget"><strong>NuGet Package</strong><span>Build your own SocketJack services: HTTP, WebSocket, FTP, SQL, reverse shell proxy, streaming dashboards, and typed .NET protocol tools all sharing one mutable server surface.</span></button>
      <button class="nav-card" type="button" data-page="github"><strong>GitHub</strong><span>Read the source, follow release history, download JackLLM builds, audit the master-list server, and extend the JackLLM web UI, WPF app, auth, payments, and relay stack.</span></button>
    </div>
  </div>
  <section class="landing-page active" data-page-panel="service">
    <h2>JackLLM Service</h2>
    <div class="selection-summary" data-summary></div>
    <div><button type="button" class="page-link" id="serviceLoginBtn">Login to JackLLM</button></div>
  </section>
  <section class="landing-page" data-page-panel="nuget">
    <h2>NuGet SocketJack</h2>
    <div class="selection-summary" data-summary></div>
    <div><a class="page-link" href="https://www.nuget.org/packages/SocketJack/" target="_blank" rel="noopener noreferrer">Open NuGet Package</a></div>
  </section>
  <section class="landing-page" data-page-panel="github">
    <h2>GitHub Documentation and Releases</h2>
    <div class="selection-summary" data-summary></div>
    <div><a class="page-link" href="https://github.com/JackOfFates/SocketJack" target="_blank" rel="noopener noreferrer">Open GitHub Repository</a></div>
  </section>
</section>
<div class="auth-modal" id="authModal" hidden>
  <div class="auth-card">
    <button class="secondary modal-close" id="closeLoginBtn" type="button">Close</button>
    <aside class="panel side" id="accountPanel">
      <div class="panel-head"><div><div class="kicker">Account</div><div class="title" id="accountTitle">Sign in</div></div></div>
      <form class="login" id="loginForm">
        <label>Username<input id="username" autocomplete="username"></label>
        <label>Password<input id="password" type="password" autocomplete="current-password"></label>
        <label class="remember-row"><input id="rememberLogin" type="checkbox" checked>Remember this browser</label>
        <div class="actions"><button type="submit">Login</button><button type="button" class="secondary" id="registerBtn">Register</button></div>
        <div class="error" id="authError"></div>
      </form>
      <div class="acct" id="accountInfo"><div>SocketJack master accounts are shared by participating JackLLM hosts.</div></div>
    </aside>
  </div>
</div>
<div class="cookie-consent" id="cookieConsent" role="dialog" aria-live="polite" aria-label="Cookie agreement" hidden>
  <div><strong>Cookie Agreement</strong><span>SocketJack uses cookies to keep this browser signed in with an auth token and to remember this agreement. Passwords are never stored in cookies.</span></div>
  <button id="acceptCookies" type="button">Agree</button>
</div>
<input id="serverBackgroundInput" type="file" accept="image/*" hidden>
<div class="background-editor" id="serverBackgroundEditor" hidden>
  <div class="background-card">
    <div class="background-head"><span id="serverBackgroundTitle">Server background</span><button class="secondary" id="serverBackgroundCancelTop" type="button">Close</button></div>
    <div class="background-preview" id="serverBackgroundPreview"><img id="serverBackgroundImage" alt=""></div>
    <div class="background-controls">
      <label>Scale<input id="serverBackgroundScale" type="range" min="1" max="4" step="0.01" value="1"></label>
      <div class="background-actions"><button class="secondary" id="serverBackgroundCancel" type="button">Cancel</button><button id="serverBackgroundOk" type="button">OK</button></div>
    </div>
  </div>
</div>
<main class="app">
  <header class="topbar">
    <a class="sj-brand" href="/Download" aria-label="SocketJack downloads">
      <span class="sj-brand-mark" aria-hidden="true">SJ</span>
      <div><h1>SocketJack Master</h1><div class="sub">Master List - LLM Model Service</div></div>
    </a>
    <div class="top-right">
      <div class="top-auth" id="topAuth" hidden><span class="pill user-pill" id="topUser"></span><a class="button secondary" id="adminLink" href="/Admin" hidden>Admin</a><button class="secondary" id="logoutBtn" type="button">Logout</button></div>
    </div>
  </header>
  <section class="workspace" id="workspace">
    <section class="panel main">
      <div class="toolbar"><div class="route-toolbar" aria-label="Routing mode"><div class="route-segment"><button type="button" id="manualRouteBtn">Server Browser</button><button type="button" class="active" id="autoRouteBtn">Auto (0 Servers)</button><button type="button" class="agent-builder-tab" id="agentBuilderRouteBtn">Agent Builder</button></div></div><input id="search" placeholder="Search title, description, IP, model, GPU, CPU, RAM, VRAM, tools, tokens, cost"><span class="pill" id="updated">Loading</span></div>
      <section class="auto-picker" id="autoPicker" aria-label="Auto model type selection">
        <iframe class="auto-page-frame" src="/Auto?embedded=masterlist" title="SocketJack Auto"></iframe>
      </section>
      <section class="agent-builder-picker" id="agentBuilderPicker" aria-label="Agent Builder" hidden>
        <iframe class="agent-builder-frame" src="/Builder" title="Agent Builder"></iframe>
      </section>
      <div class="server-list" id="servers"></div>
    </section>
  </section>
</main>
<script>
const API_BASE=__API_BASE__;
function api(path){const base=String(API_BASE||'').trim();if(!base)return path;try{const u=new URL(base,window.location.href);if(u.hostname===window.location.hostname&&(!u.port||u.port===window.location.port))return path}catch{}return base.replace(/\/+$/,'')+path}
const els={servers:document.getElementById('servers'),search:document.getElementById('search'),count:document.getElementById('countPill'),updated:document.getElementById('updated'),manualRoute:document.getElementById('manualRouteBtn'),autoRoute:document.getElementById('autoRouteBtn'),agentBuilderRoute:document.getElementById('agentBuilderRouteBtn'),autoModel:document.getElementById('autoModelSelect'),autoMode:document.getElementById('autoModeSelect'),autoEligible:document.getElementById('autoEligible'),autoPicker:document.getElementById('autoPicker'),agentBuilderPicker:document.getElementById('agentBuilderPicker'),autoTypeGrid:document.getElementById('autoTypeGrid'),workspace:document.getElementById('workspace'),accountPanel:document.getElementById('accountPanel'),topAuth:document.getElementById('topAuth'),topUser:document.getElementById('topUser'),adminLink:document.getElementById('adminLink'),form:document.getElementById('loginForm'),user:document.getElementById('username'),pass:document.getElementById('password'),remember:document.getElementById('rememberLogin'),error:document.getElementById('authError'),register:document.getElementById('registerBtn'),logout:document.getElementById('logoutBtn'),accountTitle:document.getElementById('accountTitle'),accountInfo:document.getElementById('accountInfo'),authModal:document.getElementById('authModal'),openLogin:document.getElementById('openLoginBtn'),serviceLogin:document.getElementById('serviceLoginBtn'),closeLogin:document.getElementById('closeLoginBtn'),releaseSticker:document.getElementById('releaseSticker'),releaseLabel:document.getElementById('releaseLabel'),cookieConsent:document.getElementById('cookieConsent'),acceptCookies:document.getElementById('acceptCookies'),landingTitle:document.getElementById('landingTitle'),landingDescription:document.getElementById('landingDescription'),postLoader:document.getElementById('postLoginLoader'),postLoaderStatus:document.getElementById('postLoginLoaderStatus'),backgroundInput:document.getElementById('serverBackgroundInput'),backgroundEditor:document.getElementById('serverBackgroundEditor'),backgroundTitle:document.getElementById('serverBackgroundTitle'),backgroundPreview:document.getElementById('serverBackgroundPreview'),backgroundImage:document.getElementById('serverBackgroundImage'),backgroundScale:document.getElementById('serverBackgroundScale'),backgroundOk:document.getElementById('serverBackgroundOk'),backgroundCancel:document.getElementById('serverBackgroundCancel'),backgroundCancelTop:document.getElementById('serverBackgroundCancelTop')};
const topRight=document.querySelector('.top-right'),landing=document.getElementById('landing');
const ROUTING_MODE_KEY='SocketJackMasterListRoutingMode';
const storedRoutingMode=localStorage.getItem(ROUTING_MODE_KEY);
let allServers=[],currentGroups=[],lastServerSignature='',emptyNode=null,routingMode=(storedRoutingMode==='manual'||storedRoutingMode==='agentBuilder')?storedRoutingMode:'auto';
let lastRenderedOrder='',serversLoading=false,loadServersPromise=null,masterLiveSocket=null,masterLiveReconnectTimer=0,masterLiveOpen=false;
const cards=new Map();
const runtimeHealth=new Map(),runtimeHealthChecks=new Map(),serverLocations=new Map(),serverLocationChecks=new Set();
let currentSession=null,backgroundEditorState=null;
const RUNTIME_HEALTH_RECHECK_MS=15000,RUNTIME_HEALTH_PROXY_TIMEOUT_MS=9000,RUNTIME_HEALTH_DIRECT_TIMEOUT_MS=3500,RUNTIME_HEALTH_OFFLINE_FAILURES=3,RUNTIME_HEALTH_OFFLINE_MS=30000;
const landingPages={
service:{title:'Master List - LLM Model Service',description:`**SocketJack Master** is the public directory for JackLLM hosts. It turns private LM Studio machines into launchable public endpoints by listing online status, model ratings, tool permissions, hardware capacity, token limits, payment settings, and shell-proxy routes in one place.

### How it works
- **Hosts publish capacity** from the WPF JackLLM: model names, benchmark scores, GPU/VRAM/CPU/RAM availability, storage caps, token-rate policy, tool permissions, Stripe pricing, and whether the listing is visible.
- **The master list verifies health** so users can distinguish a shell proxy route from a truly ready LM Studio backend with current online/offline state and recent status text.
- **Users sign in once** with a SocketJack account, browse hosts horizontally by capability, then launch a server through \`socketjack.com/proxy/...\` without needing the host's LAN address.
- **Shared sessions stay local to the host** while comments and public chat messages flow through the proxied JackLLM server, guarded by each session's randomized share hash.
- **Payments convert usage into tokens** so PC owners can rent local GPU, CPU, RAM, storage, and I/O capacity while users pay for model throughput instead of permanent infrastructure.

The master server is the trusted hub. The JackLLM is the host and client app. Together they turn local LM Studio hardware into a searchable, benchmarked, paid local LLM service.`},
nuget:{title:'NuGet Package',description:`**SocketJack on NuGet** is the reusable .NET networking package behind the master list, reverse shell relay, database admin surface, and JackLLM host stack.

### Build with it
- **SocketJack networking** can share HTTP, SocketJack, WebSocket, FTP, SQL admin, file APIs, shell routes, and custom protocol handlers on one service surface.
- **Typed messaging** keeps app code small while SocketJack handles framing, segmentation, serialization, routing, reverse relays, and transport details.
- **Data-backed services** support SQL admin panels, JSON database storage, browser dashboards, streaming model responses, uploads, downloads, and remote GUI control.
- **Proxy-friendly routing** helps apps run locally while still being reached through a public master relay path like \`/proxy/<server>/...\`.

Use this selection when you want the library, API surface, or package install path rather than the hosted JackLLM service directory.`},
github:{title:'GitHub',description:`**SocketJack GitHub** is the source, documentation, release history, JackLLM release channel, and audit trail for the public master-list service.

### Find the project
- **Download releases** including the WPF JackLLM build, updater manifest, and host-side tooling needed to publish your machine.
- **Read implementation docs** for SocketJack servers, reverse TCP relay, SocketJack clients, protocol handlers, SQL/FTP integrations, and examples.
- **Inspect source** for the master-list website, auth endpoints, public server registry, share-session comments, generated web UI, payment hooks, and WPF admin panels.
- **Contribute safely** by testing locally, reviewing generated HTML resources, and tracing how public shell proxy routes map back to the local JackLLM server.

This is the best selection for contributors, troubleshooting, release notes, and anyone who wants to understand or extend the platform.`}
};
const AUTO_TYPES=[
{id:'text',mode:'text',label:'Text',detail:'Chat, writing, coding, reasoning, and everyday assistants'},
{id:'multimodal',mode:'multimodal',label:'All Modes',detail:'Vision models, mixed text and image context, and omni-style inputs'},
{id:'image',mode:'image',label:'Image',detail:'Image generation, editing, concepts, and visual variations'},
{id:'video',mode:'video',label:'Video',detail:'Video generation, animation, image-to-video, and motion work'},
{id:'audio',mode:'audio',label:'Audio',detail:'Speech, music, transcription, and sound generation'},
{id:'tools',mode:'tools',label:'Tools',detail:'Tool-calling models for file, browser, shell, and agent workflows'},
{id:'embedding',mode:'embedding',label:'Embeddings',detail:'Vector, search, retrieval, and semantic matching models'}
];
function setLoadingText(el,text,loading){if(!el)return;el.classList.toggle('loading-inline',!!loading);el.textContent='';if(loading){const spinner=document.createElement('span');spinner.className='inline-throbber';spinner.setAttribute('aria-hidden','true');el.appendChild(spinner)}const label=document.createElement('span');label.textContent=text;el.appendChild(label)}
function setUpdatedStatus(text,loading){setLoadingText(els.updated,text,loading)}
function serverCountText(count){return count+' Servers'}
function escapeHtml(value){return String(value||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;')}
function inlineMarkdown(text){return escapeHtml(text).replace(/`([^`]+)`/g,'<code>$1</code>').replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>').replace(/\*([^*]+)\*/g,'<em>$1</em>').replace(/\[([^\]]+)\]\((https?:\/\/[^)\s]+)\)/g,'<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>')}
function renderMarkdown(markdown){const lines=String(markdown||'').split(/\r?\n/);let html='',inList=false;const closeList=()=>{if(inList){html+='</ul>';inList=false}};lines.forEach(line=>{const trimmed=line.trim();if(!trimmed){closeList();return}if(trimmed.startsWith('### ')){closeList();html+='<h3>'+inlineMarkdown(trimmed.slice(4))+'</h3>';return}if(/^[-*]\s+/.test(trimmed)){if(!inList){html+='<ul>';inList=true}html+='<li>'+inlineMarkdown(trimmed.replace(/^[-*]\s+/,''))+'</li>';return}closeList();html+='<p>'+inlineMarkdown(trimmed).replace(/^([\u{1F300}-\u{1FAFF}\u2600-\u27BF])\s/u,'<span class="summary-symbol">$1</span> ')+'</p>'});closeList();return html}
function selectLandingPage(page){const data=landingPages[page]||landingPages.service;document.querySelectorAll('.nav-card').forEach(x=>x.classList.toggle('active',x.dataset.page===page));document.querySelectorAll('[data-page-panel]').forEach(panel=>{const active=panel.dataset.pagePanel===page;panel.classList.toggle('active',active);const summary=panel.querySelector('[data-summary]');if(summary)summary.innerHTML=renderMarkdown((landingPages[panel.dataset.pagePanel]||landingPages.service).description)});if(els.landingTitle)els.landingTitle.textContent=data.title;if(els.landingDescription)els.landingDescription.innerHTML=renderMarkdown(data.description);document.title=data.title+' | SocketJack Master'}
function text(v){return v===undefined||v===null||v===''?'Unknown':String(v)}
function fact(label,value){const d=document.createElement('div');d.className='fact';d.innerHTML='<span></span><b></b>';d.querySelector('span').textContent=label;d.querySelector('b').textContent=text(value);return d}
function serverLocationTarget(s){return String(s.ipAddress||s.registeredByIp||s.connectHost||s.endpoint||s.launchUrl||'').trim()}
function serverLocationKey(s){const target=serverLocationTarget(s);return target?target.toLowerCase():''}
function serverLocationText(s){const key=serverLocationKey(s);const loc=key?serverLocations.get(key):null;if(!key)return'Location not advertised';if(!loc)return'Location lookup pending';if(loc.found)return loc.label||[loc.city,loc.region,loc.country].filter(Boolean).join(', ')||loc.ip||'Location found';if(loc.privateAddress)return'Local/private network';return'Location unavailable'}
function countryFlag(countryCode){countryCode=String(countryCode||'').trim().toUpperCase();if(!/^[A-Z]{2}$/.test(countryCode))return'';return String.fromCodePoint(...[...countryCode].map(ch=>127397+ch.charCodeAt(0)))}
function timezoneOffsetMinutes(timezone){timezone=String(timezone||'').trim();if(!timezone||typeof Intl==='undefined'||!Intl.DateTimeFormat)return null;try{const parts=new Intl.DateTimeFormat('en-US',{timeZone:timezone,timeZoneName:'shortOffset',hour:'2-digit'}).formatToParts(new Date());const name=(parts.find(part=>part.type==='timeZoneName')||{}).value||'';if(/^GMT$/i.test(name))return 0;const match=name.match(/^GMT([+-])(\d{1,2})(?::(\d{2}))?$/i);if(!match)return null;const minutes=(Number(match[2])||0)*60+(Number(match[3])||0);return match[1]==='-'?-minutes:minutes}catch{return null}}
function locationUtcOffsetText(loc){let minutes=timezoneOffsetMinutes(loc&&loc.timezone);if(!Number.isFinite(minutes)&&loc&&Number.isFinite(Number(loc.longitude)))minutes=Math.round(Number(loc.longitude)/15)*60;if(!Number.isFinite(minutes))return'UTC';const sign=minutes>=0?'+':'-';const absolute=Math.abs(minutes);const hours=Math.floor(absolute/60),remainder=absolute%60;return'UTC '+sign+hours+(remainder?':'+String(remainder).padStart(2,'0'):'')}
