function benchmarkSpeed(b){const tps=Number(b.tokensPerSecond||b.TokensPerSecond)||0;const tph=Number(b.tokensPerHour||b.TokensPerHour)||0;return tps>0?tps.toFixed(1)+' tok/s'+(tph>0?' | '+Math.round(tph).toLocaleString()+' tok/hr':''):'Not benchmarked'}
function firstModelValue(o,names){if(!o)return'';for(const n of names){if(o[n]!==undefined&&o[n]!==null&&String(o[n]).trim()!=='')return o[n]}const caps=o.capabilities||o.Capabilities||{};for(const n of names){if(caps[n]!==undefined&&caps[n]!==null&&String(caps[n]).trim()!=='')return caps[n]}return''}
function formatParameterCount(value){if(value===undefined||value===null||value==='')return'';if(typeof value==='string'&&/[a-z]/i.test(value))return value;const n=Number(value);if(!Number.isFinite(n)||n<=0)return String(value);if(n>=1e12)return(n/1e12).toFixed(n>=10e12?0:1)+'T params';if(n>=1e9)return(n/1e9).toFixed(n>=10e9?0:1)+'B params';if(n>=1e6)return(n/1e6).toFixed(n>=10e6?0:1)+'M params';return Math.round(n).toLocaleString()+' params'}
