function modelContextText(model){const value=firstModelValue(model,['contextLength','context_length','maxContextLength','max_context_length','n_ctx','ctx','maxTokens','max_tokens']);const n=Number(value);if(Number.isFinite(n)&&n>0)return Math.round(n).toLocaleString()+' ctx';return value?String(value)+' ctx':''}
