function splitModels(s){const names=[];String(s.availableModels||'').split(/[,;\n]+/).forEach(x=>{x=x.trim();if(x)names.push(x)});parseCapabilities(s).forEach(c=>{const n=capabilityName(c);if(n&&n!=='Unknown')names.push(n)});parseBenchmarks(s).forEach(b=>{const n=benchmarkName(b);if(n&&n!=='Unknown')names.push(n)});return [...new Map(names.map(n=>[normalizeModelId(n),n])).values()]}
