function refreshVariantSelect(card,group){const select=card.querySelector('.variant-select');const variants=group.variants||[];const selected=Math.max(0,Math.min(Number(card.dataset.variantIndex||0)||0,Math.max(0,variants.length-1)));const signature=variants.map((variant,index)=>index+':'+variantLabel(variant,index,group)).join('|');if(select.dataset.signature!==signature){select.textContent='';variants.forEach((variant,index)=>{const option=document.createElement('option');option.value=String(index);option.textContent=variantLabel(variant,index,group);select.appendChild(option)});select.dataset.signature=signature}select.value=String(selected);select.hidden=variants.length<2;select.onchange=()=>{card.dataset.variantIndex=select.value;updateCard(card,group);render(true)};return variants[selected]||variants[0]}
