function renderBenchmarks(card,s){const details=card.querySelector('.model-bench');const list=card.querySelector('.model-list');const best=card.querySelector('.best-rating');const benches=parseBenchmarks(s).sort((a,b)=>benchmarkRating(b)-benchmarkRating(a));const caps=parseCapabilities(s);const byName=modelBenchmarkMap(benches);const byCap=modelCapabilityMap(caps);const serverVsTools=hasVsTools(s);renderModelShowcase(card,s,benches,caps);list.textContent='';const models=splitModels(s).map(name=>{const key=normalizeModelId(name);return{name,bench:byName.get(key),cap:byCap.get(key)}});renderBenchmarkCategories(card,models,serverVsTools);if(!models.length){details.hidden=true;return}details.hidden=false;const bestRating=benches.length?benchmarkRating(benches[0]):0;best.textContent=benches.length?'Best '+bestRating+'/100':'Capabilities';best.style.color=benches.length?ratingColor(bestRating):'#8bdcff';models.sort((a,b)=>benchmarkRating(b.bench||{})-benchmarkRating(a.bench||{})||a.name.localeCompare(b.name)).forEach(model=>{const rating=benchmarkRating(model.bench||{});const row=document.createElement('div');row.className='model-row';row.innerHTML='<div class="model-name"></div><div class="rating"></div><div class="model-meta"></div>';row.querySelector('.model-name').textContent=model.name;const badge=row.querySelector('.rating');badge.textContent=rating>0?rating+'/100':'cap';badge.style.background=rating>0?ratingColor(rating):'#334155';const meta=[];if(capabilityHasVision(model.cap)||benchmarkHasVision(model.bench)||hasVisual(model.name))meta.push('Vision');if(serverVsTools||capabilityHasTools(model.cap)||benchmarkHasTools(model.bench)||modelNameHasTools(model.name))meta.push('VS_tools');if(capabilityHasGeneration(model.cap,'image')||benchmarkHasGeneration(model.bench,'image')||modelNameHasGeneration(model.name,'image'))meta.push('Image gen');if(capabilityHasGeneration(model.cap,'audio')||benchmarkHasGeneration(model.bench,'audio')||modelNameHasGeneration(model.name,'audio'))meta.push('Audio gen');if(capabilityHasGeneration(model.cap,'video')||benchmarkHasGeneration(model.bench,'video')||modelNameHasGeneration(model.name,'video'))meta.push('Video gen');const merged=Object.assign({},model.cap||{},model.bench||{});const modelMeta=modelMetaText(merged);if(modelMeta)meta.push(modelMeta);meta.push(benchmarkSpeed(model.bench||{}));row.querySelector('.model-meta').textContent=meta.filter(Boolean).join(' | ');list.appendChild(row)})}
function currentUserName(){return String(currentSession&&currentSession.username||'').trim().toLowerCase()}
function canEditServerBackground(s){if(!(currentSession&&currentSession.authenticated))return false;return String(s.ownerUserName||s.ownerUsername||'').trim().toLowerCase()===currentUserName()}
function clampBackgroundOffset(value){value=Number(value)||0;return Math.max(-100,Math.min(100,value))}
function clampBackgroundScale(value){value=Number(value)||1;return Math.max(1,Math.min(4,value))}
function applyServerBackground(card,s){const url=String(s.backgroundImageUrl||'').trim();const layer=card.querySelector('.server-bg');const img=layer&&layer.querySelector('img');card.classList.toggle('has-background',!!url);if(!layer||!img)return;if(url){if(img.getAttribute('src')!==url)img.src=url;layer.style.setProperty('--server-bg-x',clampBackgroundOffset(s.backgroundOffsetX)+'%');layer.style.setProperty('--server-bg-y',clampBackgroundOffset(s.backgroundOffsetY)+'%');layer.style.setProperty('--server-bg-scale',clampBackgroundScale(s.backgroundScale))}else{img.removeAttribute('src')}}
function openServerBackgroundUpload(s){if(!canEditServerBackground(s)){openLogin();return}if(!els.backgroundInput)return;els.backgroundInput.value='';els.backgroundInput.onchange=async()=>{const file=els.backgroundInput.files&&els.backgroundInput.files[0];if(!file)return;try{setUpdatedStatus('Compressing background',true);const dataUrl=await compressBackgroundToJpeg(file);openBackgroundEditor(s,dataUrl)}catch(error){setUpdatedStatus(error.message||String(error),false)}};els.backgroundInput.click()}
function loadImageElement(src){return new Promise((resolve,reject)=>{const img=new Image();img.onload=()=>resolve(img);img.onerror=()=>reject(new Error('Image could not be loaded.'));img.src=src})}
async function compressBackgroundToJpeg(file){if(!file||!/^image\//i.test(file.type||''))throw new Error('Choose an image file.');const raw=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(String(reader.result||''));reader.onerror=()=>reject(new Error('Image read failed.'));reader.readAsDataURL(file)});const img=await loadImageElement(raw);const maxSide=1920;const scale=Math.min(1,maxSide/Math.max(img.naturalWidth||img.width,img.naturalHeight||img.height));const width=Math.max(1,Math.round((img.naturalWidth||img.width)*scale));const height=Math.max(1,Math.round((img.naturalHeight||img.height)*scale));const canvas=document.createElement('canvas');canvas.width=width;canvas.height=height;const ctx=canvas.getContext('2d');ctx.fillStyle='#05070b';ctx.fillRect(0,0,width,height);ctx.drawImage(img,0,0,width,height);const dataUrl=canvas.toDataURL('image/jpeg',.82);if(dataUrl.length>11_200_000)throw new Error('Compressed JPG is still too large. Try a smaller image.');return dataUrl}
function setBackgroundPreviewVars(){if(!backgroundEditorState||!els.backgroundPreview)return;els.backgroundPreview.style.setProperty('--preview-bg-x',clampBackgroundOffset(backgroundEditorState.offsetX)+'%');els.backgroundPreview.style.setProperty('--preview-bg-y',clampBackgroundOffset(backgroundEditorState.offsetY)+'%');els.backgroundPreview.style.setProperty('--preview-bg-scale',clampBackgroundScale(backgroundEditorState.scale));if(els.backgroundScale)els.backgroundScale.value=String(clampBackgroundScale(backgroundEditorState.scale))}
function openBackgroundEditor(s,dataUrl){backgroundEditorState={server:s,dataUrl,offsetX:0,offsetY:0,scale:1,dragging:false,lastX:0,lastY:0};if(els.backgroundTitle)els.backgroundTitle.textContent='Background for '+text(serverTitle(s)||s.id);if(els.backgroundImage)els.backgroundImage.src=dataUrl;if(els.backgroundEditor)els.backgroundEditor.hidden=false;setBackgroundPreviewVars();setUpdatedStatus('Drag image, adjust scale, then OK',false)}
function closeBackgroundEditor(){backgroundEditorState=null;if(els.backgroundEditor)els.backgroundEditor.hidden=true;if(els.backgroundImage)els.backgroundImage.removeAttribute('src')}
async function saveServerBackground(){if(!backgroundEditorState)return;const state=backgroundEditorState;const s=state.server||{};try{setUpdatedStatus('Saving background',true);if(els.backgroundOk)els.backgroundOk.disabled=true;const response=await authFetch('/api/lmvsproxy/server-background',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({serverId:s.id,dataUrl:state.dataUrl,offsetX:state.offsetX,offsetY:state.offsetY,scale:state.scale})});const data=await readJson(response);if(!data.ok)throw new Error(data.error||'Background save failed.');const match=allServers.find(item=>String(item.id||'')===String(s.id||''));if(match){match.backgroundImageUrl=data.backgroundImageUrl;match.backgroundOffsetX=data.backgroundOffsetX;match.backgroundOffsetY=data.backgroundOffsetY;match.backgroundScale=data.backgroundScale}closeBackgroundEditor();syncServerCards(true);render(true);setUpdatedStatus('Background saved',false);loadServers().catch(()=>{})}catch(error){setUpdatedStatus(error.message||String(error),false)}finally{if(els.backgroundOk)els.backgroundOk.disabled=false}}
function createCard(){const card=document.createElement('article');card.className='server';card.innerHTML='<div class="server-bg" aria-hidden="true"><img alt=""></div><div class="server-top"><div><h2></h2><div class="endpoint"></div></div><div class="server-actions"><span class="pill state-pill"></span><span class="pill location-pill"></span><select class="variant-select" title="Server variation" aria-label="Server variation"></select><button class="image-icon-button background-upload" type="button" aria-label="Upload server background" title="Upload server background" hidden><span class="image-upload-symbol" aria-hidden="true"></span></button><a class="launch" target="_blank" rel="noopener noreferrer">Launch &gt;</a></div></div><div class="compact-line"></div><div class="latency-row" aria-label="Latency metrics"></div><div class="compact-resources"></div><details class="server-details"><summary class="details-title">Details</summary><div class="server-details-body"><div class="desc"></div><div class="server-summary"></div><div class="benchmark-categories" hidden></div><div class="model-showcase"></div><details class="model-bench"><summary><span>All Models</span><span class="best-rating"></span></summary><div class="model-list"></div></details><div class="facts"></div></div></details>';return card}
function updateCard(card,group){card.dataset.groupKey=group.key;const selected=refreshVariantSelect(card,group)||group.main;const key=selected._variantKey||serverKey(selected,selected._listIndex||0);const s=applyRuntimeHealth(selected,key);const online=s.isOnline!==false;let launch=s.launchUrl||s.endpoint||'';let launchText='Launch >';if(routingMode==='auto'){launch=autoLaunchUrl();launchText='Auto >'}card.classList.toggle('offline',!online);card.classList.toggle('auto-ineligible',routingMode==='auto'&&!groupAutoEligible(group));card.dataset.search=JSON.stringify(group.variants).toLowerCase();applyServerBackground(card,s);card.querySelector('h2').textContent=text(serverTitle(s)||group.hostDisplay||s.connectHost||s.ipAddress);card.querySelector('.endpoint').textContent=text(s.endpoint||s.connectHost);const state=card.querySelector('.state-pill');state.innerHTML='<span class="state-icon '+(online?'connected':'disconnected')+'"><span class="state-line"></span><span class="state-break"></span></span><span></span>';state.lastElementChild.textContent=online?'Online':'Offline';state.className='pill state-pill '+(online?'good':'offline-pill');renderLocationPill(card.querySelector('.location-pill'),s);const bgButton=card.querySelector('.background-upload');if(bgButton){bgButton.hidden=!canEditServerBackground(s);bgButton.onclick=()=>openServerBackgroundUpload(s)}card.querySelector('.desc').textContent=text(s.description||s.availableResources);const link=card.querySelector('.launch');link.href=launch||'#';link.hidden=!launch;link.textContent=launchText;renderCompact(card,s,group,online);renderLatency(card,s,online,key);renderSummary(card,s);renderBenchmarks(card,s);const facts=card.querySelector('.facts');facts.textContent='';[['Status',s.statusText||s.lastStatus],['Internet Latency',latencyNumber(s.internetLatencyMs,s.InternetLatencyMs,s.latencyMs,s.LatencyMs)?latencyNumber(s.internetLatencyMs,s.InternetLatencyMs,s.latencyMs,s.LatencyMs)+' ms':'Measuring'],['Browser Latency',latencyNumber(s.proxyLatencyMs,s.ProxyLatencyMs)?latencyNumber(s.proxyLatencyMs,s.ProxyLatencyMs)+' ms':(isProxyLaunch(s)?'Measuring':'Direct')],['Model Runtime',modelRuntimeStatusText(s)],['LlmRuntime',llmRuntimeStatusText(s)],['Owner',s.ownerUserName||s.ownerUsername],['Location',serverLocationText(s)],['Uptime',serverUptimeText(s)],['Available Models',s.availableModels],['Tools Allowed',s.toolsAllowed],['RAM',s.availableRam],['VRAM',s.availableVram||s.gpuAvailable],['GPU Model',s.gpuModel],['CPU Model',s.cpuModel],['Max Tokens',s.maxTokens?Number(s.maxTokens).toLocaleString():'Unknown'],['Cost Factor',(s.costFactor||1)+'x']].forEach(x=>facts.appendChild(fact(x[0],x[1])))}
function setCountPill(){if(serversLoading&&!allServers.length){setLoadingText(els.count,'Loading servers',true);return}const hostCount=currentGroups.length;const serverText=allServers.length+' server'+(allServers.length===1?'':'s');setLoadingText(els.count,hostCount&&hostCount!==allServers.length?serverText+' / '+hostCount+' host'+(hostCount===1?'':'s'):serverText,false)}
function groupRenderSignature(group){return JSON.stringify({key:group.key,hostDisplay:group.hostDisplay,sameName:group.sameName,variants:(group.variants||[]).map(normalizeServerSnapshot)})}
function syncServerCards(force){currentGroups=groupServers(allServers);const live=new Set();currentGroups.forEach(group=>{live.add(group.key);let card=cards.get(group.key);if(!card){card=createCard();cards.set(group.key,card);force=true}const signature=groupRenderSignature(group);if(force||card.dataset.renderSignature!==signature){updateCard(card,group);card.dataset.renderSignature=signature}});for(const [key,card] of cards){if(!live.has(key)){card.remove();cards.delete(key)}}for(const key of [...runtimeHealth.keys()]){if(!allServers.some((item,i)=>serverKey(item,i)===key))runtimeHealth.delete(key)}}
function render(force){const q=els.search.value.trim().toLowerCase();let visible=0;const order=[];setCountPill();refreshAutoControls();if(!emptyNode){emptyNode=document.createElement('div');emptyNode.className='empty';els.servers.appendChild(emptyNode)}const loadingEmpty=serversLoading&&!currentGroups.length;if(emptyNode.dataset.loading!==String(loadingEmpty)){emptyNode.dataset.loading=String(loadingEmpty);emptyNode.classList.toggle('loading',loadingEmpty);emptyNode.innerHTML=loadingEmpty?'<div><span class="inline-throbber" aria-hidden="true"></span><strong>Loading JackLLM servers</strong><br>Fetching the current master list.</div>':'<div><strong>No available JackLLM servers</strong><br>Waiting for hosts to register with the master list.</div>'}currentGroups.forEach(group=>{const card=cards.get(group.key);if(!card)return;const show=groupAutoEligible(group)&&(!q||(card.dataset.search||'').includes(q));card.hidden=!show;if(show){visible++;order.push(group.key);const variants=group.variants||[];const selected=variants[Math.max(0,Math.min(Number(card.dataset.variantIndex||0)||0,Math.max(0,variants.length-1)))]||group.main;if(visible<=24){const key=selected._variantKey||serverKey(selected,selected._listIndex||0);scheduleServerLocationLookup(selected);scheduleRuntimeHealthCheck(key,selected,card)}}});const orderSignature=q+'|'+routingMode+'|'+(els.autoModel?els.autoModel.value:'')+'|'+(els.autoMode?els.autoMode.value:'')+'|'+order.join('|');if(force||orderSignature!==lastRenderedOrder){order.forEach(key=>{const card=cards.get(key);if(card)els.servers.insertBefore(card,emptyNode)});lastRenderedOrder=orderSignature}emptyNode.hidden=visible>0;if(visible===0)els.servers.appendChild(emptyNode)}
async function readJson(r){const body=await r.text();let data={};if(body.trim()){try{data=JSON.parse(body)}catch{data={detail:body.slice(0,500)}}}if(!r.ok)throw new Error(data.error||data.detail||('HTTP '+r.status));return data}
async function loadServers(){if(loadServersPromise)return loadServersPromise;loadServersPromise=(async()=>{const firstLoad=!lastServerSignature&&!allServers.length;serversLoading=true;setUpdatedStatus('Loading servers',true);refreshAutoControls();render(false);try{const data=await readJson(await fetch(api('/api/lmvsproxy/servers'),{cache:'no-store',credentials:'include'}));const nextServers=Array.isArray(data.servers)?data.servers:[];const nextSignature=serverListSignature(nextServers);setUpdatedStatus(data.updatedUtc?new Date(data.updatedUtc).toLocaleString():'Updated',false);if(nextSignature!==lastServerSignature){allServers=nextServers;lastServerSignature=nextSignature;refreshAutoControls();syncServerCards(firstLoad);render(firstLoad)}else{refreshAutoControls();render(false)}}catch(error){setUpdatedStatus(error.message||String(error),false);throw error}finally{serversLoading=false;setCountPill();refreshAutoControls();render(false);loadServersPromise=null}})();return loadServersPromise}
function applyMasterListLivePayload(data){if(!data||!Array.isArray(data.servers))return;const firstLoad=!lastServerSignature&&!allServers.length;const nextServers=data.servers||[];const nextSignature=serverListSignature(nextServers);serversLoading=false;setUpdatedStatus(data.updatedUtc?new Date(data.updatedUtc).toLocaleString():'Live',false);if(nextSignature!==lastServerSignature){allServers=nextServers;lastServerSignature=nextSignature;refreshAutoControls();syncServerCards(firstLoad);render(firstLoad)}else{refreshAutoControls();render(false)}setCountPill()}
function masterLiveSocketUrl(path){return(location.protocol==='https:'?'wss://':'ws://')+location.host+path}
function shouldUseMasterLiveSocket(){return document.body.classList.contains('authed')&&document.visibilityState!=='hidden'}
function closeMasterListLiveSocket(){window.clearTimeout(masterLiveReconnectTimer);masterLiveOpen=false;const ws=masterLiveSocket;masterLiveSocket=null;if(ws){try{ws.close()}catch{}}}
function sendMasterLiveHello(){try{if(!shouldUseMasterLiveSocket()){closeMasterListLiveSocket();return}const ws=masterLiveSocket;if(!ws||ws.readyState!==WebSocket.OPEN)return;ws.send(JSON.stringify({type:'hello',id:'master_live_'+Date.now(),accessToken:readStoredToken()}))}catch{}}
function scheduleMasterLiveReconnect(){window.clearTimeout(masterLiveReconnectTimer);if(shouldUseMasterLiveSocket())masterLiveReconnectTimer=window.setTimeout(connectMasterListLiveSocket,2200)}
function connectMasterListLiveSocket(){if(!('WebSocket'in window)||!shouldUseMasterLiveSocket())return;if(masterLiveSocket&&(masterLiveSocket.readyState===WebSocket.OPEN||masterLiveSocket.readyState===WebSocket.CONNECTING))return;try{const ws=new WebSocket(masterLiveSocketUrl('/masterlist/ws'));masterLiveSocket=ws;ws.onopen=()=>{masterLiveOpen=true;sendMasterLiveHello()};ws.onmessage=event=>{try{const data=JSON.parse(event.data);if(data&&data.type==='snapshot'&&data.topic==='servers')applyMasterListLivePayload(data)}catch{}};ws.onclose=()=>{masterLiveOpen=false;if(masterLiveSocket===ws){masterLiveSocket=null;scheduleMasterLiveReconnect()}};ws.onerror=()=>{try{ws.close()}catch{}}}catch{scheduleMasterLiveReconnect()}}
function syncMasterListLiveSocket(){if(shouldUseMasterLiveSocket())connectMasterListLiveSocket();else closeMasterListLiveSocket()}
const loginRoute=/^\/login\/?$/i.test(window.location.pathname);
const masterListRoute=/^\/(?:MasterList|master-list)\/?$/i.test(window.location.pathname);
function openLogin(){els.authModal.hidden=false;requestAnimationFrame(()=>els.user.focus())}
function closeLogin(){if(!document.body.classList.contains('authed')&&(loginRoute||masterListRoute)){window.location.replace('/');return}els.authModal.hidden=true}
function readCookie(name){return document.cookie.split(';').map(x=>x.trim()).reduce((found,part)=>{if(found)return found;const eq=part.indexOf('=');if(eq<0)return'';return part.slice(0,eq)===name?decodeURIComponent(part.slice(eq+1)):''},'')}
function writeCookie(name,value,days){document.cookie=name+'='+encodeURIComponent(value)+'; Path=/; Max-Age='+(days*86400)+'; SameSite=Lax'}
function deleteCookie(name){document.cookie=name+'=; Path=/; Max-Age=0; SameSite=Lax'}
function safeStorageGet(name){for(const key of ['localStorage','sessionStorage']){try{const store=window[key];const value=store&&store.getItem(name);if(value)return value}catch{}}return''}
function safeStorageSet(name,value,preferLocal){const order=preferLocal?['localStorage','sessionStorage']:['sessionStorage','localStorage'];for(const key of order){try{const store=window[key];if(store){store.setItem(name,value);return true}}catch{}}return false}
function safeStorageRemove(name){for(const key of ['localStorage','sessionStorage']){try{const store=window[key];if(store)store.removeItem(name)}catch{}}}
function readStoredToken(){return safeStorageGet('SocketJackAccessToken')||readCookie('SocketJackAuth')||''}
function saveAuthToken(data,remember){const token=data&&data.accessToken?data.accessToken:'';safeStorageRemove('SocketJackAccessToken');deleteCookie('SocketJackAuth');if(!token)return;safeStorageSet('SocketJackAccessToken',token,remember);writeCookie('SocketJackAuth',token,remember?365:1)}
function clearAuthToken(){safeStorageRemove('SocketJackAccessToken');deleteCookie('SocketJackAuth')}
function authHeaders(extra){const headers=Object.assign({},extra||{});const token=readStoredToken();const remembered=readCookie('SocketJackLoginName');if(token)headers.Authorization='Bearer '+token;if(remembered)headers['X-SocketJack-User']=remembered;return headers}
async function authFetch(path,options){options=options||{};options.credentials='include';options.headers=authHeaders(options.headers);let response=await fetch(api(path),options);if((response.status===401||response.status===403)&&path!=='/api/web-auth/session'){try{await session()}catch(err){}options.headers=authHeaders(options.headers);response=await fetch(api(path),options)}return response}
function rememberRequested(){return !!(els.remember&&els.remember.checked)}
function applyRememberedUser(){const remembered=readCookie('SocketJackLoginName');if(remembered&&!els.user.value)els.user.value=remembered}
function saveRememberedUser(username){if(rememberRequested()&&username)writeCookie('SocketJackLoginName',username,365);else deleteCookie('SocketJackLoginName')}
function isAllowedLoginReturnUrl(url){const host=String(url.hostname||'').toLowerCase();if(url.protocol==='socketjack:'&&host==='visualstudio-auth')return true;if(url.protocol==='file:'&&/\/?JackLLMWebChat\.html$/i.test(url.pathname))return true;if((url.protocol==='http:'||url.protocol==='https:')&&(url.origin===window.location.origin||host==='localhost'||host==='127.0.0.1'||host==='::1'||host==='[::1]')&&/\/?JackLLMWebChat\.html$/i.test(url.pathname))return true;return url.origin===window.location.origin}
function loginReturnUrl(){const params=new URLSearchParams(window.location.search);const raw=params.get('returnUrl')||params.get('return_url')||params.get('next')||'';if(!raw)return'';try{const url=new URL(raw,window.location.origin);return isAllowedLoginReturnUrl(url)?url.href:''}catch{return''}}
function appendAuthTokenToReturnUrl(raw,token){if(!raw||!token)return raw||'';try{const url=new URL(raw,window.location.origin);url.searchParams.set('socketjack_auth',token);return url.href}catch{return raw}}
function redirectAfterAuth(data){const url=loginReturnUrl();if(!url)return false;const token=(data&&(data.accessToken||data.access_token||data.token))||readStoredToken();window.location.href=appendAuthTokenToReturnUrl(url,token);return true}
function redirectIfLoginReturnAuthed(data){return !!(data&&data.authenticated&&loginRoute&&redirectAfterAuth(data))}
function initCookieConsent(){if(!els.cookieConsent||!els.acceptCookies)return;if(readCookie('SocketJackCookieConsent')==='accepted'){els.cookieConsent.hidden=true;return}els.cookieConsent.hidden=false;els.acceptCookies.addEventListener('click',()=>{writeCookie('SocketJackCookieConsent','accepted',3650);els.cookieConsent.hidden=true})}
function dockReleaseSticker(authed){if(authed&&topRight&&els.topAuth){els.releaseSticker.classList.add('top-docked');topRight.insertBefore(els.releaseSticker,els.topAuth);return}els.releaseSticker.classList.remove('top-docked');if(landing&&landing.parentNode&&els.releaseSticker.nextSibling!==landing)landing.parentNode.insertBefore(els.releaseSticker,landing)}
function setReleaseLabel(text){(els.releaseLabel||els.releaseSticker).textContent=text}
