(function(){
const canvas=document.getElementById('starfield');
if(!canvas)return;
const ctx=canvas.getContext('2d');
if(!ctx)return;
const reduced=window.matchMedia&&window.matchMedia('(prefers-reduced-motion: reduce)').matches;
const palette=[{h:172,s:74,l:70},{h:142,s:82,l:70},{h:218,s:90,l:74},{h:258,s:92,l:78},{h:334,s:78,l:74},{h:42,s:96,l:72}];
let width=1,height=1,dpr=1,stars=[],meteors=[],nextMeteor=0,lastTime=performance.now();
const parallaxState={x:0,y:0,targetX:0,targetY:0};
function resize(){
dpr=Math.min(window.devicePixelRatio||1,1.25);
width=Math.max(1,window.innerWidth);
height=Math.max(1,window.innerHeight);
canvas.width=Math.floor(width*dpr);
canvas.height=Math.floor(height*dpr);
canvas.style.width=width+'px';
canvas.style.height=height+'px';
ctx.setTransform(dpr,0,0,dpr,0,0);
seedStars();
}
function seedStars(){
const count=Math.max(170,Math.min(520,Math.floor(width*height/4000)));
stars=Array.from({length:count},(_,index)=>({x:Math.random()*width,y:Math.random()*height,z:Math.random()*.92+.18,r:Math.random()*1.35+.22,twinkle:Math.random()*Math.PI*2,color:palette[index%palette.length],drift:Math.random()*.24+.06}));
}
function hsla(color,alpha,boost){return 'hsla('+color.h+', '+color.s+'%, '+Math.min(92,color.l+boost)+'%, '+alpha+')'}
function wrap(value,max,pad){if(value<-pad)return max+pad;if(value>max+pad)return -pad;return value}
function scheduleMeteor(now){nextMeteor=now+9000+Math.random()*14000}
function spawnMeteor(){
const color=palette[Math.floor(Math.random()*palette.length)];
const fromLeft=Math.random()>.28;
const angle=fromLeft?Math.PI*.16+Math.random()*.2:Math.PI*.84-Math.random()*.2;
const speed=760+Math.random()*440;
meteors.push({x:fromLeft?-120:width+120,y:Math.random()*height*.48+20,vx:Math.cos(angle)*speed,vy:Math.sin(angle)*speed,life:0,maxLife:1.1+Math.random()*.55,length:150+Math.random()*130,color,width:1.5+Math.random()*1.4});
}
function onPointerMove(event){
parallaxState.targetX=(.5-(width>0?event.clientX/width:.5))*74;
parallaxState.targetY=(.5-(height>0?event.clientY/height:.5))*54;
}
function drawStars(time,dt){
parallaxState.x+=(parallaxState.targetX-parallaxState.x)*.045;
parallaxState.y+=(parallaxState.targetY-parallaxState.y)*.045;
for(const star of stars){
if(!reduced){
star.x=wrap(star.x-dt*star.drift*(6+star.z*18),width,24);
star.y=wrap(star.y+dt*star.drift*(1.2+star.z*4),height,24);
star.twinkle+=dt*(1.4+star.z*1.2);
}
const x=star.x+parallaxState.x*star.z;
const y=star.y+parallaxState.y*star.z;
const pulse=reduced ? .5 : (Math.sin(star.twinkle+time*.0004)+1)*.5;
const alpha=Math.max(.28,Math.min(.98,.40+pulse*.38+star.z*.36));
const radius=star.r*star.z*1.18;
ctx.beginPath();
ctx.fillStyle=hsla(star.color,alpha,star.z*7);
ctx.arc(x,y,radius,0,Math.PI*2);
ctx.fill();
if(star.z>.86){
ctx.beginPath();
ctx.strokeStyle=hsla(star.color,.12,10);
ctx.lineWidth=.7;
ctx.moveTo(x-radius*4,y);
ctx.lineTo(x+radius*4,y);
ctx.moveTo(x,y-radius*4);
ctx.lineTo(x,y+radius*4);
ctx.stroke();
}
}
}
function drawMeteors(now,dt){
if(!reduced&&now>=nextMeteor){spawnMeteor();if(document.body.classList.contains('loading')&&Math.random()>.72)setTimeout(spawnMeteor,260+Math.random()*620);scheduleMeteor(now)}
for(let i=meteors.length-1;i>=0;i--){
const meteor=meteors[i];
meteor.life+=dt;
meteor.x+=meteor.vx*dt;
meteor.y+=meteor.vy*dt;
const progress=meteor.life/meteor.maxLife;
const alpha=Math.max(0,Math.sin(Math.min(1,progress)*Math.PI));
const angle=Math.atan2(meteor.vy,meteor.vx);
const lenX=Math.cos(angle)*meteor.length;
const lenY=Math.sin(angle)*meteor.length;
const gradient=ctx.createLinearGradient(meteor.x,meteor.y,meteor.x-lenX,meteor.y-lenY);
gradient.addColorStop(0,hsla(meteor.color,.95*alpha,18));
gradient.addColorStop(.18,hsla(meteor.color,.36*alpha,10));
gradient.addColorStop(1,hsla(meteor.color,0,0));
ctx.beginPath();
ctx.strokeStyle=gradient;
ctx.lineWidth=meteor.width;
ctx.lineCap='round';
ctx.moveTo(meteor.x,meteor.y);
ctx.lineTo(meteor.x-lenX,meteor.y-lenY);
ctx.stroke();
ctx.beginPath();
ctx.fillStyle=hsla(meteor.color,.98*alpha,20);
ctx.arc(meteor.x,meteor.y,meteor.width*1.35,0,Math.PI*2);
ctx.fill();
if(meteor.life>meteor.maxLife||meteor.x>width+260||meteor.x<-260||meteor.y>height+220)meteors.splice(i,1);
}
}
function queueDraw(delay){window.setTimeout(()=>requestAnimationFrame(draw),delay)}
function draw(time){
const loading=document.body.classList.contains('loading');
const frameMs=reduced?520:(loading?100:240);
if(document.hidden){lastTime=time;queueDraw(1200);return}
const dt=Math.min(.04,Math.max(.001,(time-lastTime)/1000));
lastTime=time;
ctx.clearRect(0,0,width,height);
const bg=ctx.createRadialGradient(width*.55+parallaxState.x,height*.28+parallaxState.y,0,width*.55,height*.34,Math.max(width,height)*.78);
bg.addColorStop(0,'rgba(84, 225, 192, 0.11)');
bg.addColorStop(.34,'rgba(112, 167, 255, 0.064)');
bg.addColorStop(.72,'rgba(244, 143, 177, 0.050)');
bg.addColorStop(1,'rgba(0, 0, 0, 0)');
ctx.fillStyle=bg;
ctx.fillRect(0,0,width,height);
drawStars(time,dt);
drawMeteors(time,dt);
queueDraw(frameMs);
}
window.addEventListener('resize',resize);
window.addEventListener('pointermove',onPointerMove,{passive:true});
resize();
scheduleMeteor(performance.now()-1400);
queueDraw(0);
}());
</script>
