    private string GetBrowserApiBaseUrl() {
        string publicUrl = FirstNonEmpty(_options.PublicUrl, _options.WebsitePublicUrl, "");
        string websiteUrl = FirstNonEmpty(_options.WebsitePublicUrl, "");
        if (Uri.TryCreate(publicUrl, UriKind.Absolute, out Uri? publicUri)) {
            if (IsLoopbackHost(publicUri.Host))
                return publicUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
            if (Uri.TryCreate(websiteUrl, UriKind.Absolute, out Uri? websiteUri) &&
                string.Equals(publicUri.Host, websiteUri.Host, StringComparison.OrdinalIgnoreCase))
                return "";
            if (publicUri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase))
                return "https://" + publicUri.Authority.TrimEnd('/');
            return publicUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
        }

        return "";
    }

    private string GetBrowserSqlAdminUrl() {
        string publicUrl = FirstNonEmpty(_options.WebsitePublicUrl, _options.PublicUrl, "https://socketjack.com/");
        if (Uri.TryCreate(publicUrl, UriKind.Absolute, out Uri? uri)) {
            string authority = uri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
            if (!IsLoopbackHost(uri.Host) && uri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase))
                authority = "https://" + uri.Authority.TrimEnd('/');
            return authority + "/sql";
        }

        return "/sql";
    }

    private string GetLocalSqlAdminUrl() {
        if (!_options.SqlLoopbackEnabled)
            return "";

        string host = FirstNonEmpty(_options.SqlLoopbackBindHost, "127.0.0.1");
        if (IPAddress.TryParse(host, out IPAddress? address) && address.AddressFamily == AddressFamily.InterNetworkV6)
            host = "[" + address + "]";

        string authority = _options.SqlLoopbackPort == 80
            ? host
            : host + ":" + _options.SqlLoopbackPort.ToString(CultureInfo.InvariantCulture);
        return "http://" + authority + "/sql";
    }

    private static bool IsLoopbackHost(string host) {
        if (string.IsNullOrWhiteSpace(host))
            return false;
        if (host.Equals("localhost", StringComparison.OrdinalIgnoreCase))
            return true;
        return IPAddress.TryParse(host, out IPAddress? address) && IPAddress.IsLoopback(address);
    }

    private static string Json(HttpRequest request, object value, int statusCode = 200, string reasonPhrase = "OK") {
        request.Context.StatusCodeNumber = statusCode;
        request.Context.ReasonPhrase = reasonPhrase;
        AddCors(request);
        request.Context.Response.ContentType = "application/json";
        return JsonSerializer.Serialize(value, MasterListJson.Options);
    }

    private static string Html(HttpRequest request, string html, int statusCode = 200, string reasonPhrase = "OK") {
        request.Context.StatusCodeNumber = statusCode;
        request.Context.ReasonPhrase = reasonPhrase;
        AddCors(request);
        request.Context.Response.ContentType = "text/html; charset=utf-8";
        return html;
    }

    private static string MasterListHtml(HttpRequest request, string html) {
        request.Context.Response.Headers["Cache-Control"] = "private, no-cache, stale-while-revalidate=86400";
        request.Context.Response.Headers["Vary"] = "Cookie, Authorization";
        return Html(request, html);
    }

    private static string Redirect(HttpRequest request, string location, int statusCode = 302, string reasonPhrase = "Found") {
        location = string.IsNullOrWhiteSpace(location) ? "/" : location.Trim();
        request.Context.StatusCodeNumber = statusCode;
        request.Context.ReasonPhrase = reasonPhrase;
        AddCors(request);
        request.Context.Response.Headers["Location"] = location;
        request.Context.Response.ContentType = "text/html; charset=utf-8";
        string encodedLocation = WebUtility.HtmlEncode(location);
        return "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"utf-8\"><title>Redirecting</title><meta http-equiv=\"refresh\" content=\"0; url=" + encodedLocation + "\"></head><body><a href=\"" + encodedLocation + "\">Continue</a></body></html>";
    }

    private static string Text(HttpRequest request, string text, string contentType = "text/plain; charset=utf-8", int statusCode = 200, string reasonPhrase = "OK") {
        request.Context.StatusCodeNumber = statusCode;
        request.Context.ReasonPhrase = reasonPhrase;
        AddCors(request);
        request.Context.Response.ContentType = contentType;
        return text;
    }

    private static string NoContent(HttpRequest request) {
        request.Context.StatusCodeNumber = 204;
        request.Context.ReasonPhrase = "No Content";
        AddCors(request);
        return "";
    }

    private static void AddCors(HttpRequest request) {
        Dictionary<string, string> headers = request.Context.Response.Headers;
        string origin = "";
        if (request.Headers != null &&
            request.Headers.TryGetValue("Origin", out string? requestOrigin))
            origin = requestOrigin ?? "";
        headers["Access-Control-Allow-Origin"] = string.IsNullOrWhiteSpace(origin) ? "*" : origin;
        headers["Access-Control-Allow-Credentials"] = "true";
        headers["Access-Control-Allow-Methods"] = "GET, POST, DELETE, OPTIONS";
        headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-LmVsProxy-Master-Key, X-LmVsProxy-Server-Owner, X-SocketJack-Server-Owner, X-SocketJack-Shell-Relay, X-SocketJack-Shell-Route, X-SocketJack-Server-Id, X-SocketJack-Auth, X-LmVsProxy-Auth, X-SocketJack-User, X-SocketJack-Username, X-LmVsProxy-User";
        headers["Vary"] = "Origin";
    }

    private Table EnsureServerTable() {
        lock (_sync) {
            Database database = _dataServer.Databases.GetOrAdd(_options.DatabaseName, name => new Database(name));
            Table table = database.Tables.GetOrAdd(_options.TableName, name => new Table(name));
            bool changed = EnsureColumns(table, ServerColumns);
            if (changed)
                _dataServer.Save();
            return table;
        }
    }

    private Table EnsureTable(string tableName, IReadOnlyList<string> columns) {
        lock (_sync) {
            Database database = _dataServer.Databases.GetOrAdd(_options.DatabaseName, name => new Database(name));
            Table table = database.Tables.GetOrAdd(tableName, name => new Table(name));
            bool changed = EnsureColumns(table, columns);
            if (changed)
                _dataServer.Save();
            return table;
        }
    }

    private static bool EnsureColumns(Table table, IReadOnlyList<string> columns) {
        bool changed = false;
        foreach (string columnName in columns) {
            bool exists = table.Columns.Any(column => string.Equals(column.Name, columnName, StringComparison.OrdinalIgnoreCase));
            if (!exists) {
                table.Columns.Add(new Column(columnName, typeof(string), -1));
                changed = true;
            }
        }

        int columnCount = table.Columns.Count;
        for (int i = 0; i < table.Rows.Count; i++) {
            object[] row = table.Rows[i];
            if (row.Length < columnCount) {
                Array.Resize(ref row, columnCount);
                table.Rows[i] = row;
                changed = true;
            }
        }

        return changed;
    }

    private bool UpdateServerAvailabilityLocked(DateTimeOffset now, bool allowLiveChecks) {
        bool changed = false;
        for (int i = 0; i < _table.Rows.Count; i++) {
            object[] row = _table.Rows[i];
            RegisteredServer server = RowToServer(row);
            if (string.IsNullOrWhiteSpace(server.Id))
                continue;

            bool hidden = server.WebsiteHidden;
            ServerHealthSnapshot health = hidden
                ? ServerHealthSnapshot.Offline("Hidden from website")
                : GetOrCheckHealth(server, now, allowLiveChecks);
            string status = hidden ? "Hidden from website" : health.StatusText;
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.LastStatus)), status, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.LastStatus), status);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.StatusText)), status, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.StatusText), status);
                changed = true;
            }

            string onlineText = (!hidden && health.IsOnline) ? "true" : "false";
            string hostText = (!hidden && health.HostResponding) ? "true" : "false";
            string lmStudioText = (!hidden && health.LmStudioConnected) ? "true" : "false";
            string modelRuntimeProvider = hidden ? server.ModelRuntimeProvider : RegisteredServer.FirstNonEmpty(health.ModelRuntimeProvider, server.ModelRuntimeProvider, "LM Studio");
            string modelRuntimeText = (!hidden && health.ModelRuntimeConnected) ? "true" : "false";
            string modelRuntimeStatus = hidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.ModelRuntimeStatus, health.ModelRuntimeConnected ? "Connected" : "Disconnected");
            string llmRuntimeText = (!hidden && health.LlmRuntimeConnected) ? "true" : "false";
            string llmRuntimeStatus = hidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.LlmRuntimeStatus, health.LlmRuntimeConnected ? "Connected" : "Not selected");
            string internetLatencyText = (!hidden && health.InternetLatencyMs > 0) ? health.InternetLatencyMs.ToString(CultureInfo.InvariantCulture) : "";
            string proxyLatencyText = (!hidden && health.ProxyLatencyMs > 0) ? health.ProxyLatencyMs.ToString(CultureInfo.InvariantCulture) : "";
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.IsOnline)), onlineText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.IsOnline), onlineText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.HostResponding)), hostText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.HostResponding), hostText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.LmStudioConnected)), lmStudioText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.LmStudioConnected), lmStudioText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.ModelRuntimeProvider)), modelRuntimeProvider, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.ModelRuntimeProvider), modelRuntimeProvider);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.ModelRuntimeConnected)), modelRuntimeText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.ModelRuntimeConnected), modelRuntimeText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.ModelRuntimeStatus)), modelRuntimeStatus, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.ModelRuntimeStatus), modelRuntimeStatus);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.LlmRuntimeConnected)), llmRuntimeText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.LlmRuntimeConnected), llmRuntimeText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.LlmRuntimeStatus)), llmRuntimeStatus, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.LlmRuntimeStatus), llmRuntimeStatus);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.InternetLatencyMs)), internetLatencyText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.InternetLatencyMs), internetLatencyText);
                changed = true;
            }
            if (!string.Equals(GetCell(row, nameof(RegisteredServer.ProxyLatencyMs)), proxyLatencyText, StringComparison.OrdinalIgnoreCase)) {
                SetCell(row, nameof(RegisteredServer.ProxyLatencyMs), proxyLatencyText);
                changed = true;
            }

            if (allowLiveChecks && !hidden && health.HostResponding) {
                string checkedUtc = health.CheckedUtc.ToString("O", CultureInfo.InvariantCulture);
                if (!string.Equals(GetCell(row, nameof(RegisteredServer.LastSeenUtc)), checkedUtc, StringComparison.OrdinalIgnoreCase)) {
                    SetCell(row, nameof(RegisteredServer.LastSeenUtc), checkedUtc);
                    changed = true;
                }
            }
        }

        return changed;
    }

    private RegisteredServer ApplyAvailability(RegisteredServer server, DateTimeOffset now, bool allowLiveChecks) {
        ServerHealthSnapshot health = server.WebsiteHidden
            ? ServerHealthSnapshot.Offline("Hidden from website")
            : GetOrCheckHealth(server, now, allowLiveChecks);
        server.HostResponding = !server.WebsiteHidden && health.HostResponding;
        server.LmStudioConnected = !server.WebsiteHidden && health.LmStudioConnected;
        server.ModelRuntimeProvider = RegisteredServer.FirstNonEmpty(health.ModelRuntimeProvider, server.ModelRuntimeProvider, "LM Studio");
        server.ModelRuntimeConnected = !server.WebsiteHidden && health.ModelRuntimeConnected;
        server.ModelRuntimeStatus = server.WebsiteHidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.ModelRuntimeStatus, server.ModelRuntimeConnected ? "Connected" : "Disconnected");
        server.LlmRuntimeConnected = !server.WebsiteHidden && health.LlmRuntimeConnected;
        server.LlmRuntimeStatus = server.WebsiteHidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.LlmRuntimeStatus, server.LlmRuntimeConnected ? "Connected" : "Not selected");
        server.InternetLatencyMs = server.WebsiteHidden ? 0 : health.InternetLatencyMs;
        server.ProxyLatencyMs = server.WebsiteHidden ? 0 : health.ProxyLatencyMs;
        server.IsOnline = !server.WebsiteHidden && health.IsOnline;
        server.StatusText = server.WebsiteHidden ? "Hidden from website" : health.StatusText;
        server.LastStatus = server.StatusText;
        if (allowLiveChecks && server.HostResponding)
            server.LastSeenUtc = health.CheckedUtc.ToString("O", CultureInfo.InvariantCulture);
        if (server.UptimeSeconds <= 0 &&
            DateTimeOffset.TryParse(server.StartedUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset started))
            server.UptimeSeconds = Math.Max(0, (long)Math.Floor((now - started.ToUniversalTime()).TotalSeconds));
        server.LaunchUrl = RegisteredServer.FirstNonEmpty(server.Endpoint, RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort));
        return server;
    }

    private ServerHealthSnapshot GetCachedHealth(object[] row, DateTimeOffset now) {
        RegisteredServer server = RowToServer(row);
        return GetOrCheckHealth(server, now, allowLiveCheck: false);
    }

    private ServerHealthSnapshot BuildStoredHealthSnapshot(RegisteredServer server, DateTimeOffset now) {
        if (server == null)
            return ServerHealthSnapshot.Offline("Host endpoint missing.");
        if (server.WebsiteHidden)
            return ServerHealthSnapshot.Offline("Hidden from website");

        bool expired = IsServerRegistrationExpired(server, now);
        bool online = !expired && server.IsOnline;
        bool hostResponding = !expired && server.HostResponding;
        string status = expired
            ? "Offline - registration expired"
            : FirstNonEmpty(server.StatusText, server.LastStatus, online ? "Online" : "Offline");

        return new ServerHealthSnapshot(online, hostResponding, !expired && server.LmStudioConnected, status, now) {
            ModelRuntimeProvider = FirstNonEmpty(server.ModelRuntimeProvider, "LM Studio"),
            ModelRuntimeConnected = !expired && server.ModelRuntimeConnected,
            ModelRuntimeStatus = expired
                ? status
                : FirstNonEmpty(server.ModelRuntimeStatus, server.ModelRuntimeConnected ? "Connected" : "Disconnected"),
            LlmRuntimeConnected = !expired && server.LlmRuntimeConnected,
            LlmRuntimeStatus = expired
                ? status
                : FirstNonEmpty(server.LlmRuntimeStatus, server.LlmRuntimeConnected ? "Connected" : "Not selected"),
            InternetLatencyMs = expired ? 0 : server.InternetLatencyMs,
            ProxyLatencyMs = expired ? 0 : server.ProxyLatencyMs
        };
    }

    private bool IsServerRegistrationExpired(RegisteredServer server, DateTimeOffset now) {
        if (server == null || string.IsNullOrWhiteSpace(server.LastSeenUtc))
            return false;
        if (!DateTimeOffset.TryParse(server.LastSeenUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset lastSeen))
            return false;
        return now.ToUniversalTime() - lastSeen.ToUniversalTime() > TimeSpan.FromMinutes(_options.RegistrationTtlMinutes);
    }

    private ServerHealthSnapshot GetOrCheckHealth(RegisteredServer server, DateTimeOffset now, bool allowLiveCheck) {
        string key = string.IsNullOrWhiteSpace(server.Id) ? RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort) : server.Id;
        if (string.IsNullOrWhiteSpace(key))
            return ServerHealthSnapshot.Offline("Host endpoint missing.");

        if (TryGetShellRelayHealth(server, now, allowLiveCheck, out ServerHealthSnapshot shellSnapshot)) {
            _healthCache[key] = shellSnapshot;
            return shellSnapshot;
        }

        if (_healthCache.TryGetValue(key, out ServerHealthSnapshot cached) && now - cached.CheckedUtc < TimeSpan.FromSeconds(20))
            return cached;

        if (!allowLiveCheck)
            return BuildStoredHealthSnapshot(server, now);

        ServerHealthSnapshot snapshot = CheckServerHealth(server, now);
        _healthCache[key] = snapshot;
        return snapshot;
    }

    private bool TryGetShellRelayHealth(RegisteredServer server, DateTimeOffset now, bool allowLiveCheck, out ServerHealthSnapshot snapshot) {
        snapshot = default;
        MasterShellRelay? relay = _shellRelays.Values.FirstOrDefault(candidate =>
            string.Equals(candidate.ServerId, server.Id, StringComparison.OrdinalIgnoreCase));
        if (relay == null && !string.IsNullOrWhiteSpace(server.Endpoint)) {
            relay = _shellRelays.Values.FirstOrDefault(candidate =>
                string.Equals(candidate.Endpoint, server.Endpoint, StringComparison.OrdinalIgnoreCase) ||
                (!string.IsNullOrWhiteSpace(candidate.ProxyPath) && server.Endpoint.Contains(candidate.ProxyPath, StringComparison.OrdinalIgnoreCase)));
        }
        if (relay == null)
            return false;

        relay = UpdateShellRelayRuntime(relay);
        bool routeListening = IsShellRelayRouteListening(relay);
        bool guiConnected = IsShellRelayAgentPresent(relay) || IsShellRelayTunnelPresent(relay) || HasRecentShellRelayAgentWithoutBacklog(relay, now);
        if (routeListening && guiConnected) {
            if (allowLiveCheck) {
                ServerHealthSnapshot checkedHealth = CheckServerHealth(server, now);
                snapshot = checkedHealth.IsOnline
                    ? checkedHealth
                    : ServerHealthSnapshot.ShellOnline("Shell proxy online - JackLLM reverse agent connected", now, checkedHealth);
            } else {
                snapshot = ServerHealthSnapshot.ShellOnline(
                    "Shell proxy online - JackLLM reverse agent connected",
                    now,
                    BuildStoredHealthSnapshot(server, now));
            }
            return true;
        }
        string reason = routeListening
            ? "Server is not responding through shell."
            : "Shell proxy offline: " + FirstNonEmpty(relay.Status, "not listening");
        snapshot = new ServerHealthSnapshot(false, false, false, reason, now);
        return true;
    }

    private bool UpdateShellRelayPublishedServerHealthLocked(MasterShellRelay relay, DateTimeOffset now) {
        if (relay == null || string.IsNullOrWhiteSpace(relay.ServerId))
            return false;

        int index = FindRowIndexLocked(relay.ServerId);
        if (index < 0)
            return false;

        object[] row = _table.Rows[index];
        RegisteredServer server = RowToServer(row);
        ServerHealthSnapshot health = server.WebsiteHidden
            ? ServerHealthSnapshot.Offline("Hidden from website")
            : BuildShellRelayHealthSnapshot(relay, server, now);
        string status = server.WebsiteHidden ? "Hidden from website" : health.StatusText;
        bool changed = false;
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.IsOnline), (!server.WebsiteHidden && health.IsOnline) ? "true" : "false");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.HostResponding), (!server.WebsiteHidden && health.HostResponding) ? "true" : "false");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.LmStudioConnected), (!server.WebsiteHidden && health.LmStudioConnected) ? "true" : "false");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeProvider), RegisteredServer.FirstNonEmpty(health.ModelRuntimeProvider, server.ModelRuntimeProvider, "LM Studio"));
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeConnected), (!server.WebsiteHidden && health.ModelRuntimeConnected) ? "true" : "false");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.ModelRuntimeStatus), server.WebsiteHidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.ModelRuntimeStatus, "Disconnected"));
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.LlmRuntimeConnected), (!server.WebsiteHidden && health.LlmRuntimeConnected) ? "true" : "false");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.LlmRuntimeStatus), server.WebsiteHidden ? "Hidden from website" : RegisteredServer.FirstNonEmpty(health.LlmRuntimeStatus, "Not selected"));
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.InternetLatencyMs), (!server.WebsiteHidden && health.InternetLatencyMs > 0) ? health.InternetLatencyMs.ToString(CultureInfo.InvariantCulture) : "");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.ProxyLatencyMs), (!server.WebsiteHidden && health.ProxyLatencyMs > 0) ? health.ProxyLatencyMs.ToString(CultureInfo.InvariantCulture) : "");
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.StatusText), status);
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.LastStatus), status);
        changed |= SetCellIfChanged(row, nameof(RegisteredServer.UpdatedUtc), now.ToString("O", CultureInfo.InvariantCulture));
        if (!server.WebsiteHidden && health.HostResponding)
            changed |= SetCellIfChanged(row, nameof(RegisteredServer.LastSeenUtc), now.ToString("O", CultureInfo.InvariantCulture));
        _healthCache[relay.ServerId] = health;
        return changed;
    }

    private static ServerHealthSnapshot BuildShellRelayHealthSnapshot(MasterShellRelay relay, RegisteredServer server, DateTimeOffset now) {
        bool routeListening = IsShellRelayRouteListening(relay);
        bool guiConnected = IsShellRelayAgentPresent(relay) || HasRecentShellRelayAgentWithoutBacklog(relay, now);
        if (routeListening && guiConnected) {
            var stored = new ServerHealthSnapshot(server.IsOnline, server.HostResponding, server.LmStudioConnected, RegisteredServer.FirstNonEmpty(server.StatusText, server.LastStatus, "Shell proxy online"), now) {
                ModelRuntimeProvider = RegisteredServer.FirstNonEmpty(server.ModelRuntimeProvider, "Shell proxy"),
                ModelRuntimeConnected = server.ModelRuntimeConnected,
                ModelRuntimeStatus = RegisteredServer.FirstNonEmpty(server.ModelRuntimeStatus, "Shell proxy online"),
                LlmRuntimeConnected = server.LlmRuntimeConnected,
                LlmRuntimeStatus = RegisteredServer.FirstNonEmpty(server.LlmRuntimeStatus, "Not selected"),
                InternetLatencyMs = server.InternetLatencyMs,
                ProxyLatencyMs = server.ProxyLatencyMs
            };
            return ServerHealthSnapshot.ShellOnline(relay.WebSocketTunnelConnected ? "Shell proxy online - JackLLM WebSocket tunnel connected" : "Shell proxy online - JackLLM reverse agent connected", now, stored);
        }
        string reason = routeListening
            ? "Server is not responding through shell."
            : "Shell proxy offline: " + FirstNonEmpty(relay.Status, "not listening");
        return new ServerHealthSnapshot(false, false, false, reason, now);
    }

    private static bool IsShellRelayRouteListening(MasterShellRelay relay) {
        return relay != null && relay.Enabled && relay.IsRunning;
    }

    private static bool IsShellRelayAgentPresent(MasterShellRelay relay) {
        return IsShellRelayRouteListening(relay) &&
               (relay.WaitingAgents > 0 || relay.ActiveSessions > 0);
    }

    private static bool IsShellRelayTunnelPresent(MasterShellRelay relay) {
        return relay != null && relay.Enabled && relay.WebSocketTunnelConnected;
    }

    private static bool HasRecentShellRelayAgent(MasterShellRelay relay, DateTimeOffset now) {
        if (!IsShellRelayRouteListening(relay))
            return false;
        string seenText = FirstNonEmpty(relay.LastAgentSeenUtc, relay.LastTunnelSeenUtc);
        if (string.IsNullOrWhiteSpace(seenText))
            return false;
        if (!DateTimeOffset.TryParse(seenText, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset lastSeen))
            return false;
        return now.ToUniversalTime() - lastSeen.ToUniversalTime() <= ShellProxyAgentPresenceGrace;
    }

    private static bool HasRecentShellRelayAgentWithoutBacklog(MasterShellRelay relay, DateTimeOffset now) {
        return relay != null &&
               relay.WaitingPublicClients <= 0 &&
               HasRecentShellRelayAgent(relay, now);
    }

    private static ServerHealthSnapshot CheckServerHealth(RegisteredServer server, DateTimeOffset now) {
        string endpoint = RegisteredServer.FirstNonEmpty(server.Endpoint, RegisteredServer.BuildEndpoint(server.ConnectHost, server.ChatPort));
        Uri? pingUri = BuildMasterListPingUri(endpoint);
        if (pingUri == null)
            return ServerHealthSnapshot.Offline("Host endpoint missing.");

        bool proxyRoute = IsProxyRouteEndpoint(endpoint);
        Stopwatch stopwatch = Stopwatch.StartNew();
        if (!TryHttpGet(pingUri, TimeSpan.FromMilliseconds(1800), true, true, out string pingError, out string pingBody)) {
            stopwatch.Stop();
            int failedLatency = ClampLatencyMilliseconds(stopwatch.Elapsed);
            int failedInternetLatency = server.InternetLatencyMs > 0 ? server.InternetLatencyMs : (proxyRoute ? 0 : failedLatency);
            return ServerHealthSnapshot.Offline("JackLLM did not pong: " + pingError) with {
                InternetLatencyMs = failedInternetLatency,
                ProxyLatencyMs = 0
            };
        }
        stopwatch.Stop();
        int latencyMs = ClampLatencyMilliseconds(stopwatch.Elapsed);
        int internetLatencyMs = server.InternetLatencyMs > 0 ? server.InternetLatencyMs : (proxyRoute ? 0 : latencyMs);

        if (!TryReadMasterListPong(pingBody))
            return ServerHealthSnapshot.Offline("JackLLM did not pong.") with {
                InternetLatencyMs = internetLatencyMs,
                ProxyLatencyMs = 0
            };

        ModelRuntimeHealthInfo runtime = ReadModelRuntimeHealth(pingBody, server);
        if (!runtime.HasValue) {
            return new ServerHealthSnapshot(true, true, server.LmStudioConnected, "Online - JackLLM pong", now) {
                ModelRuntimeProvider = RegisteredServer.FirstNonEmpty(server.ModelRuntimeProvider, "LM Studio"),
                ModelRuntimeConnected = server.ModelRuntimeConnected,
                ModelRuntimeStatus = RegisteredServer.FirstNonEmpty(server.ModelRuntimeStatus, server.ModelRuntimeConnected ? "Connected" : "Unknown"),
                LlmRuntimeConnected = server.LlmRuntimeConnected,
                LlmRuntimeStatus = RegisteredServer.FirstNonEmpty(server.LlmRuntimeStatus, server.LlmRuntimeConnected ? "Connected" : "Not selected"),
                InternetLatencyMs = internetLatencyMs,
                ProxyLatencyMs = 0
            };
        }

        if (!runtime.Connected) {
            string reason = RegisteredServer.FirstNonEmpty(runtime.Status, "Disconnected");
            return ServerHealthSnapshot.HostOnly(runtime.Provider + " " + reason.ToLowerInvariant(), now, runtime) with {
                InternetLatencyMs = internetLatencyMs,
                ProxyLatencyMs = 0
            };
        }

        return new ServerHealthSnapshot(true, true, runtime.LmStudioConnected, "Online - " + runtime.Provider + " connected", now) {
            ModelRuntimeProvider = runtime.Provider,
            ModelRuntimeConnected = true,
            ModelRuntimeStatus = runtime.Status,
            LlmRuntimeConnected = runtime.LlmRuntimeConnected,
            LlmRuntimeStatus = runtime.LlmRuntimeStatus,
            InternetLatencyMs = internetLatencyMs,
            ProxyLatencyMs = 0
        };
    }

    private static int ClampLatencyMilliseconds(TimeSpan elapsed) {
        if (elapsed <= TimeSpan.Zero)
            return 1;
        return (int)Math.Min(int.MaxValue, Math.Max(1, Math.Round(elapsed.TotalMilliseconds)));
    }

    private static bool IsProxyRouteEndpoint(string endpoint) {
        if (string.IsNullOrWhiteSpace(endpoint))
            return false;
        string value = endpoint.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = "http://" + value;
        return Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) &&
               uri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase);
    }

    private static Uri? BuildMasterListPingUri(string endpoint) {
        if (string.IsNullOrWhiteSpace(endpoint))
            return null;

        string value = endpoint.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = "http://" + value;

        if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? baseUri))
            return null;

        string baseText = baseUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
        if (baseUri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
            baseText += baseUri.AbsolutePath.TrimEnd('/');
        return Uri.TryCreate(baseText + "/api/master-list/ping", UriKind.Absolute, out Uri? pingUri)
            ? pingUri
            : null;
    }

    private static bool TryReadMasterListPong(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return false;

        try {
            using JsonDocument document = JsonDocument.Parse(json);
            JsonElement root = document.RootElement;
            if (root.ValueKind != JsonValueKind.Object)
                return false;

            if (TryReadBoolPath(root, out bool pong, "pong") && pong)
                return true;
            if (TryReadBoolPath(root, out bool lmVsProxyPong, "lmVsProxy", "pong") && lmVsProxyPong)
                return true;
            string ping = GetJsonString(root, "ping");
            string message = GetJsonString(root, "message");
            return ping.Equals("pong", StringComparison.OrdinalIgnoreCase) ||
                   message.Equals("pong", StringComparison.OrdinalIgnoreCase);
        } catch {
            return false;
        }
    }

    private static ModelRuntimeHealthInfo ReadModelRuntimeHealth(string json, RegisteredServer server) {
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            JsonElement root = document.RootElement;
            if (root.ValueKind != JsonValueKind.Object)
                return default;

            JsonElement modelRuntime = TryGetJsonObject(root, "modelRuntime", out JsonElement modelRuntimeElement)
                ? modelRuntimeElement
                : root;
            JsonElement lmStudio = TryGetJsonObject(root, "lmStudio", out JsonElement lmStudioElement)
                ? lmStudioElement
                : default;
            JsonElement llmRuntime = TryGetJsonObject(root, "llmRuntime", out JsonElement llmRuntimeElement)
                ? llmRuntimeElement
                : default;
            JsonElement modelInventory = TryGetJsonObject(root, "modelInventory", out JsonElement modelInventoryElement)
                ? modelInventoryElement
                : root;

            string provider = RegisteredServer.FirstNonEmpty(
                GetJsonString(modelRuntime, "provider"),
                GetJsonString(modelRuntime, "runtimeProvider"),
                GetJsonString(modelRuntime, "runtimeDisplayName"),
                GetJsonString(lmStudio, "runtimeProvider"),
                GetJsonString(lmStudio, "provider"),
                server?.ModelRuntimeProvider,
                "LM Studio");
            string providerKind = RegisteredServer.FirstNonEmpty(
                GetJsonString(modelRuntime, "providerKind"),
                GetJsonString(lmStudio, "providerKind"),
                InferModelRuntimeProviderKind(provider));
            bool connected = GetJsonBool(modelRuntime, "connected", GetJsonBool(modelRuntime, "runtimeConnected", server?.ModelRuntimeConnected ?? false));
            string status = RegisteredServer.FirstNonEmpty(
                GetJsonString(modelRuntime, "status"),
                connected ? "Connected" : "Disconnected");

            bool lmStudioSelected = GetJsonBool(lmStudio, "selected", providerKind.Equals("lmstudio", StringComparison.OrdinalIgnoreCase));
            bool lmStudioConnected = lmStudioSelected &&
                                     GetJsonBool(lmStudio, "selectedProviderConnected", GetJsonBool(lmStudio, "connected", connected));

            bool llmRuntimeSelected = GetJsonBool(llmRuntime, "selected", providerKind.Equals("llmruntime", StringComparison.OrdinalIgnoreCase));
            bool llmRuntimeConnected = llmRuntimeSelected &&
                                       GetJsonBool(llmRuntime, "connected", providerKind.Equals("llmruntime", StringComparison.OrdinalIgnoreCase) && connected);
            string llmRuntimeStatus = RegisteredServer.FirstNonEmpty(
                GetJsonString(llmRuntime, "status"),
                llmRuntimeSelected ? (llmRuntimeConnected ? "Connected" : "Disconnected") : "Not selected");
            string activeModel = RegisteredServer.FirstNonEmpty(
                GetJsonString(modelRuntime, "chatModel"),
                GetJsonString(llmRuntime, "chatModel"),
                GetJsonString(lmStudio, "chatModel"),
                GetJsonString(root, "chatModel"));
            string availableModels = ReadModelInventoryIds(root, modelInventory, "availableModels", _ => true);
            string loadedModels = ReadModelInventoryIds(root, modelInventory, "loadedModels", item => ReadModelInventoryBool(item, false, "isLoaded", "loaded", "active", "ready"));
            string enabledModels = ReadModelInventoryIds(root, modelInventory, "enabledModels", item => ReadModelInventoryBool(item, false, "enabled", "isEnabled", "web_chat_model_enabled"));
            string disabledModels = ReadModelInventoryIds(root, modelInventory, "disabledModels", item => ReadModelInventoryBool(item, false, "disabled") || string.Equals(GetJsonString(item, "status"), "disabled", StringComparison.OrdinalIgnoreCase));
            string modelInventoryJson = ReadModelInventoryJson(root, modelInventory);
            string modelBenchmarksJson = ReadModelBenchmarksJson(root, modelInventory);
            bool dynamicLoadingEnabled = GetJsonBool(root, "dynamicLoadingEnabled",
                GetJsonBool(root, "serverDynamicLoadingEnabled",
                    GetJsonBool(modelInventory, "dynamicLoadingEnabled",
                        GetJsonBool(modelInventory, "serverDynamicLoadingEnabled", false))));

            return new ModelRuntimeHealthInfo(
                true,
                provider,
                providerKind,
                connected,
                status,
                lmStudioConnected,
                llmRuntimeConnected,
                llmRuntimeStatus,
                activeModel,
                availableModels,
                loadedModels,
                enabledModels,
                disabledModels,
                modelInventoryJson,
                modelBenchmarksJson,
                dynamicLoadingEnabled);
        } catch {
            return default;
        }
    }

    private static string ReadModelInventoryJson(JsonElement root, JsonElement inventory) {
        if (TryGetJsonArray(inventory, "models", out JsonElement inventoryModels))
            return inventoryModels.GetRawText();
        if (TryGetJsonArray(root, "models", out JsonElement rootModels))
            return rootModels.GetRawText();
        return "";
    }

    private static string ReadModelBenchmarksJson(JsonElement root, JsonElement inventory) {
        return FirstUsefulModelBenchmarksJson(
            GetJsonString(root, "modelBenchmarksJson"),
            GetJsonString(inventory, "modelBenchmarksJson"),
            GetRawJsonProperty(root, "modelBenchmarks"),
            GetRawJsonProperty(inventory, "modelBenchmarks"),
            GetRawJsonProperty(root, "benchmarks"),
            GetRawJsonProperty(inventory, "benchmarks"));
    }

    private static string GetRawJsonProperty(JsonElement root, string name) {
        if (!TryGetJsonProperty(root, name, out JsonElement value))
            return "";
        return value.ValueKind == JsonValueKind.Null || value.ValueKind == JsonValueKind.Undefined
            ? ""
            : value.GetRawText();
    }

    private static string ReadModelInventoryIds(JsonElement root, JsonElement inventory, string summaryName, Func<JsonElement, bool> include) {
        string summary = FirstNonEmpty(GetJsonString(root, summaryName), GetJsonString(inventory, summaryName));
        if (!string.IsNullOrWhiteSpace(summary))
            return summary;

        JsonElement models;
        if (!TryGetJsonArray(inventory, "models", out models) && !TryGetJsonArray(root, "models", out models))
            return "";

        var ids = new List<string>();
        foreach (JsonElement item in models.EnumerateArray()) {
            if (item.ValueKind != JsonValueKind.Object)
                continue;
            if (include != null && !include(item))
                continue;
            string id = FirstNonEmpty(
                GetJsonString(item, "id"),
                GetJsonString(item, "key"),
                GetJsonString(item, "name"),
                GetJsonString(item, "model"),
                GetJsonString(item, "displayName"),
                GetJsonString(item, "display_name"));
            if (!string.IsNullOrWhiteSpace(id) && !ids.Any(existing => string.Equals(existing, id, StringComparison.OrdinalIgnoreCase)))
                ids.Add(id);
        }

        return string.Join(", ", ids);
    }

    private static bool ReadModelInventoryBool(JsonElement item, bool fallback, params string[] names) {
        if (item.ValueKind != JsonValueKind.Object)
            return fallback;
        foreach (string name in names ?? Array.Empty<string>()) {
            string text = GetJsonString(item, name);
            if (bool.TryParse(text, out bool value))
                return value;
        }
        return fallback;
    }

    private static bool TryGetJsonArray(JsonElement root, string name, out JsonElement value) {
        value = default;
        if (root.ValueKind != JsonValueKind.Object)
            return false;
        foreach (JsonProperty property in root.EnumerateObject()) {
            if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase) &&
                property.Value.ValueKind == JsonValueKind.Array) {
                value = property.Value;
                return true;
            }
        }
        return false;
    }

    private static bool TryGetJsonObject(JsonElement root, string name, out JsonElement value) {
        value = default;
        if (root.ValueKind != JsonValueKind.Object)
            return false;
        foreach (JsonProperty property in root.EnumerateObject()) {
            if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase) &&
                property.Value.ValueKind == JsonValueKind.Object) {
                value = property.Value;
                return true;
            }
        }

        return false;
    }

    private static string InferModelRuntimeProviderKind(string provider) {
        string normalized = (provider ?? "").Trim().ToLowerInvariant();
        if (normalized.Contains("llmruntime", StringComparison.Ordinal) ||
            normalized.Contains("llm runtime", StringComparison.Ordinal))
            return "llmruntime";
        if (normalized.Contains("lmstudio", StringComparison.Ordinal) ||
            normalized.Contains("lm studio", StringComparison.Ordinal))
            return "lmstudio";
        return string.IsNullOrWhiteSpace(normalized) ? "unknown" : "model-runtime";
    }

    private static Uri? BuildLiveServerUri(string endpoint) {
        if (string.IsNullOrWhiteSpace(endpoint))
            return null;

        string value = endpoint.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = "http://" + value;

        return Uri.TryCreate(value, UriKind.Absolute, out Uri? uri) ? uri : null;
    }

    private static Uri? BuildProfileHealthUri(string endpoint) {
        if (string.IsNullOrWhiteSpace(endpoint))
            return null;

        string value = endpoint.Trim();
        if (!value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
            !value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            value = "http://" + value;

        if (!Uri.TryCreate(value, UriKind.Absolute, out Uri? baseUri))
            return null;

        string baseText = baseUri.GetLeftPart(UriPartial.Authority).TrimEnd('/');
        if (baseUri.AbsolutePath.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
            baseText += baseUri.AbsolutePath.TrimEnd('/');
        return Uri.TryCreate(baseText + "/api/server-browser/profile", UriKind.Absolute, out Uri? profileUri)
            ? profileUri
            : null;
    }

    private static bool TryHttpGet(Uri uri, TimeSpan timeout, out string error, out string body) {
        return TryHttpGet(uri, timeout, true, true, out error, out body);
    }

    private static bool TryHttpGet(Uri uri, TimeSpan timeout, bool requireSuccessStatus, bool readBody, out string error, out string body) {
        body = "";
        try {
            using var timeoutCts = new CancellationTokenSource(timeout);
            using System.Net.Http.HttpRequestMessage request = new(System.Net.Http.HttpMethod.Get, uri);
            using System.Net.Http.HttpResponseMessage response = HealthProbeHttpClient.Send(request, System.Net.Http.HttpCompletionOption.ResponseHeadersRead, timeoutCts.Token);
            if (readBody)
                body = response.Content.ReadAsStringAsync(timeoutCts.Token).GetAwaiter().GetResult();

            bool statusResponded = (int)response.StatusCode < 500;
            if ((requireSuccessStatus && !response.IsSuccessStatusCode) || (!requireSuccessStatus && !statusResponded)) {
                error = "HTTP " + (int)response.StatusCode;
                return false;
            }

            error = "";
            return true;
        } catch (Exception ex) {
            error = TrimHealthError(ex.Message);
            return false;
        }
    }

    private static bool? TryReadLmStudioConnected(string json) {
        if (string.IsNullOrWhiteSpace(json))
            return null;

        try {
            using JsonDocument document = JsonDocument.Parse(json);
            JsonElement root = document.RootElement;
            if (TryReadBoolPath(root, out bool connected,
                    "lmStudio", "connected") ||
                TryReadBoolPath(root, out connected,
                    "lmStudio", "isConnected") ||
                TryReadBoolPath(root, out connected,
                    "health", "lmStudioConnected") ||
                TryReadBoolPath(root, out connected,
                    "profile", "lmStudioConnected") ||
                TryReadBoolPath(root, out connected,
                    "lmStudioConnected"))
                return connected;
        } catch {
        }

        return null;
    }

    private static bool TryReadBoolPath(JsonElement root, out bool value, params string[] path) {
        value = false;
        JsonElement current = root;
        foreach (string name in path) {
            if (current.ValueKind != JsonValueKind.Object || !TryGetJsonProperty(current, name, out current))
                return false;
        }

        if (current.ValueKind == JsonValueKind.True) {
            value = true;
            return true;
        }

        if (current.ValueKind == JsonValueKind.False) {
            value = false;
            return true;
        }

        if (current.ValueKind == JsonValueKind.String && bool.TryParse(current.GetString(), out bool parsed)) {
            value = parsed;
            return true;
        }

        return false;
    }

    private static bool TryGetJsonProperty(JsonElement element, string name, out JsonElement value) {
        foreach (JsonProperty property in element.EnumerateObject()) {
            if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase)) {
                value = property.Value;
                return true;
            }
        }

        value = default;
        return false;
    }

    private static bool TryTcpConnect(string host, int port, TimeSpan timeout, out string error) {
        try {
            using var client = new System.Net.Sockets.TcpClient();
            Task connectTask = client.ConnectAsync(host, port);
            if (!connectTask.Wait(timeout)) {
                error = "timeout";
                return false;
            }

            error = "";
            return client.Connected;
        } catch (Exception ex) {
            error = TrimHealthError(ex.Message);
            return false;
        }
    }

    private static string TrimHealthError(string message) {
        if (string.IsNullOrWhiteSpace(message))
            return "unreachable";
        message = message.Replace(Environment.NewLine, " ").Trim();
        return message.Length <= 80 ? message : message[..80] + "...";
    }

    private static string FirstNonEmptyForHealth(params string?[] values) {
        foreach (string? value in values) {
            if (!string.IsNullOrWhiteSpace(value))
                return value.Trim();
        }

        return "";
    }

    private int FindRowIndexLocked(string id) {
        for (int i = 0; i < _table.Rows.Count; i++) {
            if (string.Equals(GetCell(_table.Rows[i], nameof(RegisteredServer.Id)), id, StringComparison.OrdinalIgnoreCase))
                return i;
        }

        return -1;
    }

    private object[] ServerToRow(RegisteredServer server) {
        var row = new object[_table.Columns.Count];
        for (int i = 0; i < _table.Columns.Count; i++)
            row[i] = GetPropertyText(server, _table.Columns[i].Name);
        return row;
    }

    private RegisteredServer RowToServer(object[] row) {
        var server = new RegisteredServer();
        for (int i = 0; i < _table.Columns.Count && i < row.Length; i++) {
            string columnName = _table.Columns[i].Name;
            if (!ServerProperties.TryGetValue(columnName, out PropertyInfo? property))
                continue;

            string text = row[i]?.ToString() ?? "";
            SetPropertyValue(server, property, text);
        }

        server.Normalize();
        return server;
    }

    private string GetCell(object[] row, string columnName) {
        int index = -1;
        for (int i = 0; i < _table.Columns.Count; i++) {
            if (string.Equals(_table.Columns[i].Name, columnName, StringComparison.OrdinalIgnoreCase)) {
                index = i;
                break;
            }
        }

        return index >= 0 && index < row.Length ? row[index]?.ToString() ?? "" : "";
    }

    private void SetCell(object[] row, string columnName, string value) {
        for (int i = 0; i < _table.Columns.Count && i < row.Length; i++) {
            if (string.Equals(_table.Columns[i].Name, columnName, StringComparison.OrdinalIgnoreCase)) {
                row[i] = value;
                return;
            }
        }
    }

    private bool SetCellIfChanged(object[] row, string columnName, string value) {
        if (string.Equals(GetCell(row, columnName), value, StringComparison.OrdinalIgnoreCase))
            return false;

        SetCell(row, columnName, value);
        return true;
    }

    private static string GetPropertyText(RegisteredServer server, string propertyName) {
        if (!ServerProperties.TryGetValue(propertyName, out PropertyInfo? property))
            return "";
        object? value = property.GetValue(server);
        return value switch {
            null => "",
            bool boolean => boolean ? "true" : "false",
            IFormattable formattable => formattable.ToString(null, CultureInfo.InvariantCulture),
            _ => value.ToString() ?? ""
        };
    }

    private static void SetPropertyValue(RegisteredServer server, PropertyInfo property, string text) {
        Type type = Nullable.GetUnderlyingType(property.PropertyType) ?? property.PropertyType;
        object? value = text;
        if (type == typeof(int)) {
            value = int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed) ? parsed : 0;
        } else if (type == typeof(long)) {
            value = long.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out long parsed) ? parsed : 0L;
        } else if (type == typeof(double)) {
            value = double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed) ? parsed : 0d;
        } else if (type == typeof(bool)) {
            value = bool.TryParse(text, out bool parsed) && parsed;
        }

        property.SetValue(server, value);
    }

    public void Dispose() {
        if (_disposed)
            return;
        _disposed = true;
        try {
            if (_server.IsListening)
                _server.StopListening();
        } catch {
        }

        try {
            if (_websiteServer.IsListening)
                _websiteServer.StopListening();
        } catch {
        }

        try {
            if (_websiteSslServer?.IsListening == true)
                _websiteSslServer.StopListening();
        } catch {
        }

        try {
            if (_jackcastServer?.IsListening == true)
                _jackcastServer.StopListening();
        } catch {
        }

        try {
            if (_jackcastSslServer?.IsListening == true)
                _jackcastSslServer.StopListening();
        } catch {
        }

        try {
            StopAllShellRelays();
        } catch {
        }

        try {
            DisposeAgentBuilder();
        } catch {
        }

        try {
            _locationHttpClient.Dispose();
        } catch {
        }

        try {
            _dataServer.Save();
        } catch {
        }

        try {
            _initSemaphore.Dispose();
        } catch {
        }
    }
}

