internal readonly record struct ServerHealthSnapshot(bool IsOnline, bool HostResponding, bool LmStudioConnected, string StatusText, DateTimeOffset CheckedUtc) {
    public string ModelRuntimeProvider { get; init; } = "";
    public bool ModelRuntimeConnected { get; init; }
    public string ModelRuntimeStatus { get; init; } = "";
    public bool LlmRuntimeConnected { get; init; }
    public string LlmRuntimeStatus { get; init; } = "";
    public int InternetLatencyMs { get; init; }
    public int ProxyLatencyMs { get; init; }

    public static ServerHealthSnapshot Offline(string reason) {
        string text = string.IsNullOrWhiteSpace(reason) ? "Offline" : "Offline - " + reason.Trim();
        return new ServerHealthSnapshot(false, false, false, text, DateTimeOffset.UtcNow) {
            ModelRuntimeProvider = "Unknown",
            ModelRuntimeConnected = false,
            ModelRuntimeStatus = text,
            LlmRuntimeConnected = false,
            LlmRuntimeStatus = text
        };
    }

    public static ServerHealthSnapshot HostOnly(string reason, DateTimeOffset now) {
        string text = string.IsNullOrWhiteSpace(reason) ? "Online - LM Studio disconnected" : "Online - " + reason.Trim();
        return new ServerHealthSnapshot(true, true, false, text, now) {
            ModelRuntimeProvider = "LM Studio",
            ModelRuntimeConnected = false,
            ModelRuntimeStatus = text,
            LlmRuntimeConnected = false,
            LlmRuntimeStatus = "Not selected"
        };
    }

    public static ServerHealthSnapshot HostOnly(string reason, DateTimeOffset now, ModelRuntimeHealthInfo runtime) {
        string text = string.IsNullOrWhiteSpace(reason) ? "Online - model runtime disconnected" : "Online - " + reason.Trim();
        return new ServerHealthSnapshot(true, true, runtime.LmStudioConnected, text, now) {
            ModelRuntimeProvider = runtime.Provider,
            ModelRuntimeConnected = false,
            ModelRuntimeStatus = runtime.Status,
            LlmRuntimeConnected = runtime.LlmRuntimeConnected,
            LlmRuntimeStatus = runtime.LlmRuntimeStatus
        };
    }

    public static ServerHealthSnapshot ShellOnline(string reason, DateTimeOffset now, ServerHealthSnapshot fallback = default) {
        string text = string.IsNullOrWhiteSpace(reason) ? "Online - shell proxy" : reason.Trim();
        bool hasFallback = fallback.CheckedUtc != default;
        return new ServerHealthSnapshot(true, true, hasFallback && fallback.LmStudioConnected, text, now) {
            ModelRuntimeProvider = hasFallback ? RegisteredServer.FirstNonEmpty(fallback.ModelRuntimeProvider, "Shell proxy") : "Shell proxy",
            ModelRuntimeConnected = hasFallback && fallback.ModelRuntimeConnected,
            ModelRuntimeStatus = hasFallback ? RegisteredServer.FirstNonEmpty(fallback.ModelRuntimeStatus, text) : text,
            LlmRuntimeConnected = hasFallback && fallback.LlmRuntimeConnected,
            LlmRuntimeStatus = hasFallback ? RegisteredServer.FirstNonEmpty(fallback.LlmRuntimeStatus, "Not selected") : "Not selected",
            InternetLatencyMs = hasFallback ? fallback.InternetLatencyMs : 0,
            ProxyLatencyMs = hasFallback ? fallback.ProxyLatencyMs : 0
        };
    }
}

