    public bool ToolSupport => SupportsTools;
    public bool SupportsVision => HasCapabilitySignal("supportsImages", "SupportsImages", "supportsVision", "SupportsVision", "vision", "Vision", "images", "Images", "multimodal", "Multimodal", "supportsImageUpload", "SupportsImageUpload") ||
                                  TextLooksVisionCapable(AvailableModels, ModelCapabilitiesJson, ModelBenchmarksJson);
    public bool Vision => SupportsVision;
    public bool SupportsImages => SupportsVision;
    public bool SupportsImageGeneration => HasCapabilitySignal("supportsImageGeneration", "SupportsImageGeneration", "imageGeneration", "ImageGeneration", "image_generation", "Image_generation", "generatesImages", "GeneratesImages") ||
                                           TextLooksImageGenerationCapable(AvailableModels, ModelCapabilitiesJson, ModelBenchmarksJson, AvailableResources, ToolsAllowed);
    public bool ImageGeneration => SupportsImageGeneration;
    public bool SupportsAudioGeneration => HasCapabilitySignal("supportsAudioGeneration", "SupportsAudioGeneration", "audioGeneration", "AudioGeneration", "audio_generation", "Audio_generation", "generatesAudio", "GeneratesAudio") ||
                                           TextLooksAudioGenerationCapable(AvailableModels, ModelCapabilitiesJson, ModelBenchmarksJson, AvailableResources, ToolsAllowed);
    public bool AudioGeneration => SupportsAudioGeneration;
    public bool SupportsVideoGeneration => HasCapabilitySignal("supportsVideoGeneration", "SupportsVideoGeneration", "videoGeneration", "VideoGeneration", "video_generation", "Video_generation", "generatesVideo", "GeneratesVideo") ||
                                           TextLooksVideoGenerationCapable(AvailableModels, ModelCapabilitiesJson, ModelBenchmarksJson, AvailableResources, ToolsAllowed);
    public bool VideoGeneration => SupportsVideoGeneration;
    public bool SupportsMediaGeneration => SupportsImageGeneration ||
                                           SupportsAudioGeneration ||
                                           SupportsVideoGeneration ||
                                           HasCapabilitySignal("supportsMediaGeneration", "SupportsMediaGeneration", "mediaGeneration", "MediaGeneration", "media_generation", "Media_generation") ||
                                           TextLooksMediaGenerationCapable(AvailableModels, ModelCapabilitiesJson, ModelBenchmarksJson, AvailableResources, ToolsAllowed);
    public bool MediaGeneration => SupportsMediaGeneration;
    public IReadOnlyList<RegisteredServerModelInfo> Models => BuildPublicModelInventory();
