    [JsonIgnore]
    public string LastSeenText {
        get {
            if (DateTimeOffset.TryParse(LastSeenUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed))
                return "Seen " + parsed.ToLocalTime().ToString("g", CultureInfo.CurrentCulture);
            return "Seen unknown";
        }
    }

    [JsonIgnore]
    public string UptimeText {
        get {
            long seconds = UptimeSeconds;
            if (seconds <= 0 &&
                DateTimeOffset.TryParse(StartedUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset started))
                seconds = Math.Max(0, (long)Math.Floor((DateTimeOffset.UtcNow - started.ToUniversalTime()).TotalSeconds));
            if (seconds <= 0)
                return "Uptime pending";
            TimeSpan span = TimeSpan.FromSeconds(seconds);
            if (span.TotalDays >= 1)
                return ((int)span.TotalDays).ToString(CultureInfo.InvariantCulture) + "d " + span.Hours.ToString(CultureInfo.InvariantCulture) + "h";
            if (span.TotalHours >= 1)
                return ((int)span.TotalHours).ToString(CultureInfo.InvariantCulture) + "h " + span.Minutes.ToString(CultureInfo.InvariantCulture) + "m";
            if (span.TotalMinutes >= 1)
                return ((int)span.TotalMinutes).ToString(CultureInfo.InvariantCulture) + "m " + span.Seconds.ToString(CultureInfo.InvariantCulture) + "s";
            return span.Seconds.ToString(CultureInfo.InvariantCulture) + "s";
        }
    }

    [JsonIgnore]
    public DateTimeOffset LastSeenSort {
        get {
            return DateTimeOffset.TryParse(LastSeenUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed)
                ? parsed.ToUniversalTime()
                : DateTimeOffset.MinValue;
        }
    }

