    });

    public RegisteredServer Clone() {
        return (RegisteredServer)MemberwiseClone();
    }

    public void HydrateFromStoredRegistration() {
        if (string.IsNullOrWhiteSpace(ExtraJson))
            return;

        try {
            using JsonDocument document = JsonDocument.Parse(ExtraJson);
            JsonElement root = document.RootElement;
            if (root.ValueKind != JsonValueKind.Object)
                return;

            JsonElement profile = TryGetObject(root, "profile", out JsonElement profileElement) ? profileElement : root;
            JsonElement resources = TryGetObject(root, "resources", out JsonElement resourcesElement) ? resourcesElement :
                                    TryGetObject(profile, "resources", out JsonElement profileResources) ? profileResources :
                                    profile;
            JsonElement payment = TryGetObject(root, "payment", out JsonElement paymentElement) ? paymentElement :
                                  TryGetObject(profile, "payment", out JsonElement profilePayment) ? profilePayment :
                                  profile;
            JsonElement modelRuntime = TryGetObject(root, "modelRuntime", out JsonElement modelRuntimeElement) ? modelRuntimeElement :
                                       TryGetObject(profile, "modelRuntime", out JsonElement profileModelRuntime) ? profileModelRuntime :
                                       default;
            JsonElement llmRuntime = TryGetObject(root, "llmRuntime", out JsonElement llmRuntimeElement) ? llmRuntimeElement :
                                     TryGetObject(profile, "llmRuntime", out JsonElement profileLlmRuntime) ? profileLlmRuntime :
                                     default;
            JsonElement lmStudio = TryGetObject(root, "lmStudio", out JsonElement lmStudioElement) ? lmStudioElement :
                                   TryGetObject(profile, "lmStudio", out JsonElement profileLmStudio) ? profileLmStudio :
                                   default;

            AvailableModels = FirstNonEmpty(
                AvailableModels,
                GetString(root, "availableModels"),
                GetString(profile, "availableModels"),
                GetString(resources, "availableModels"),
                GetString(root, "models"),
                GetString(profile, "models"));
            ToolsAllowed = FirstNonEmpty(
                ToolsAllowed,
                GetString(root, "toolsAllowed"),
                GetString(profile, "toolsAllowed"),
                GetString(resources, "toolsAllowed"),
                GetString(root, "tools"),
                GetString(profile, "tools"));
            AvailableResources = FirstNonEmpty(
                AvailableResources,
                GetString(root, "availableResources"),
                GetString(profile, "availableResources"),
                JsonValueToText(resources));
            ModelCapabilitiesJson = FirstNonEmpty(
                ModelCapabilitiesJson,
                GetString(root, "modelCapabilitiesJson"),
                GetString(profile, "modelCapabilitiesJson"),
                GetRawJsonContainer(root, "modelCapabilities"),
                GetRawJsonContainer(profile, "modelCapabilities"),
                GetRawJsonContainer(root, "models"),
                GetRawJsonContainer(profile, "models"),
                BuildInferredModelCapabilitiesJson(AvailableModels));
            ModelBenchmarksJson = FirstNonEmpty(
                ModelBenchmarksJson,
                GetString(root, "modelBenchmarksJson"),
                GetString(profile, "modelBenchmarksJson"),
                GetRawJsonContainer(root, "modelBenchmarks"),
                GetRawJsonContainer(profile, "modelBenchmarks"));
            AvailableRam = FirstNonEmpty(AvailableRam, GetString(root, "availableRam"), GetString(profile, "availableRam"), GetString(resources, "availableRam"), GetString(root, "ramAvailable"), GetString(profile, "ramAvailable"));
            AvailableVram = FirstNonEmpty(AvailableVram, GetString(root, "availableVram"), GetString(profile, "availableVram"), GetString(resources, "availableVram"), GetString(root, "vramAvailable"), GetString(profile, "vramAvailable"));
            GpuModel = FirstNonEmpty(GpuModel, GetString(root, "gpuModel"), GetString(profile, "gpuModel"), GetString(resources, "gpuModel"), GetString(root, "gpuName"), GetString(profile, "gpuName"));
            GpuAvailable = FirstNonEmpty(GpuAvailable, GetString(root, "gpuAvailable"), GetString(profile, "gpuAvailable"), GetString(resources, "gpuAvailable"));
            CpuModel = FirstNonEmpty(CpuModel, GetString(root, "cpuModel"), GetString(profile, "cpuModel"), GetString(resources, "cpuModel"), GetString(root, "cpuName"), GetString(profile, "cpuName"));
            CpuAvailable = FirstNonEmpty(CpuAvailable, GetString(root, "cpuAvailable"), GetString(profile, "cpuAvailable"), GetString(resources, "cpuAvailable"));
            if (MaxTokens <= 0)
                MaxTokens = Math.Max(0, GetLong(root, "maxTokens", GetLong(profile, "maxTokens", GetLong(resources, "maxTokens", 0))));
            if (CostFactor <= 0)
                CostFactor = GetDouble(payment, "costFactor", GetDouble(profile, "costFactor", GetDouble(root, "costFactor", 1)));
            if (string.IsNullOrWhiteSpace(ModelRuntimeProvider))
                ModelRuntimeProvider = FirstNonEmpty(GetString(modelRuntime, "provider"), GetString(modelRuntime, "runtimeProvider"), GetString(modelRuntime, "runtimeDisplayName"), GetString(lmStudio, "provider"), "LM Studio");
            if (string.IsNullOrWhiteSpace(ModelRuntimeStatus))
                ModelRuntimeStatus = FirstNonEmpty(GetString(modelRuntime, "status"), ModelRuntimeConnected ? "Connected" : "Disconnected");
            if (string.IsNullOrWhiteSpace(LlmRuntimeStatus))
                LlmRuntimeStatus = FirstNonEmpty(GetString(llmRuntime, "status"), LlmRuntimeConnected ? "Connected" : "Not selected");

            Normalize();
        } catch {
        }
    }

    public bool MatchesSearch(string query) {
        if (string.IsNullOrWhiteSpace(query))
            return true;

        string corpus = SearchCorpus;
        foreach (string token in query.Split(new[] { ' ', '\t', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)) {
            if (!corpus.Contains(token, StringComparison.OrdinalIgnoreCase))
                return false;
        }

        return true;
    }

    public static RegisteredServer FromRegistration(JsonElement root, string remoteIp) {
        JsonElement profile = TryGetObject(root, "profile", out JsonElement profileElement) ? profileElement : root;
        JsonElement ports = TryGetObject(root, "ports", out JsonElement portsElement) ? portsElement : root;
        JsonElement resources = TryGetObject(root, "resources", out JsonElement resourcesElement) ? resourcesElement :
                                TryGetObject(profile, "resources", out JsonElement profileResources) ? profileResources :
                                profile;
        JsonElement payment = TryGetObject(root, "payment", out JsonElement paymentElement) ? paymentElement :
                              TryGetObject(profile, "payment", out JsonElement profilePayment) ? profilePayment :
                              profile;
        JsonElement lmStudio = TryGetObject(root, "lmStudio", out JsonElement lmStudioElement) ? lmStudioElement :
                               TryGetObject(profile, "lmStudio", out JsonElement profileLmStudio) ? profileLmStudio :
                               profile;
        JsonElement modelRuntime = TryGetObject(root, "modelRuntime", out JsonElement modelRuntimeElement) ? modelRuntimeElement :
                                   TryGetObject(profile, "modelRuntime", out JsonElement profileModelRuntime) ? profileModelRuntime :
                                   lmStudio;
        JsonElement llmRuntime = TryGetObject(root, "llmRuntime", out JsonElement llmRuntimeElement) ? llmRuntimeElement :
                                 TryGetObject(profile, "llmRuntime", out JsonElement profileLlmRuntime) ? profileLlmRuntime :
                                 default;

        string connectHost = FirstNonEmpty(
            GetString(root, "connectHost"),
            GetString(root, "publicHost"),
            GetString(profile, "publicHost"),
            GetString(profile, "PublicHost"),
            remoteIp);
        connectHost = NormalizeHost(connectHost);

        int chatPort = GetInt(ports, "chat", GetInt(root, "chatPort", 11436));
        string endpoint = FirstNonEmpty(
            GetString(root, "endpoint"),
            GetString(profile, "endpoint"),
            BuildEndpoint(connectHost, chatPort));

        string title = FirstNonEmpty(
            GetString(root, "title"),
            GetString(profile, "title"),
            GetString(root, "serverName"),
            GetString(root, "ServerName"),
            GetString(profile, "serverName"),
            GetString(profile, "ServerName"),
            GetString(root, "displayName"),
            GetString(root, "name"),
            connectHost,
            "JackLLM Host");

        DateTimeOffset now = DateTimeOffset.UtcNow;
        string updated = FirstNonEmpty(GetString(profile, "updatedUtc"), GetString(root, "updatedUtc"), now.ToString("O", CultureInfo.InvariantCulture));
        string reportedStatus = FirstNonEmpty(
            GetString(root, "lastStatus"),
            GetString(profile, "lastStatus"),
            GetString(root, "statusText"),
            GetString(profile, "statusText"),
            GetString(root, "status"),
            GetString(profile, "status"));
        bool reportedOnline = GetBool(root, "online", GetBool(profile, "online", !GetBool(root, "offline", GetBool(profile, "offline", false))));
        bool hostResponding = GetBool(root, "hostResponding", GetBool(profile, "hostResponding", reportedOnline));
        bool lmStudioConnected = GetBool(root, "lmStudioConnected", GetBool(profile, "lmStudioConnected", GetBool(lmStudio, "connected", reportedOnline)));
        string modelRuntimeProvider = FirstNonEmpty(
            GetString(root, "modelRuntimeProvider"),
            GetString(profile, "modelRuntimeProvider"),
            GetString(modelRuntime, "provider"),
            GetString(modelRuntime, "runtimeProvider"),
            GetString(modelRuntime, "runtimeDisplayName"),
            GetString(lmStudio, "runtimeProvider"),
            GetString(lmStudio, "provider"),
            "LM Studio");
        bool modelRuntimeConnected = GetBool(root, "modelRuntimeConnected", GetBool(profile, "modelRuntimeConnected", GetBool(modelRuntime, "connected", GetBool(modelRuntime, "runtimeConnected", lmStudioConnected))));
        string modelRuntimeStatus = FirstNonEmpty(
            GetString(root, "modelRuntimeStatus"),
            GetString(profile, "modelRuntimeStatus"),
            GetString(modelRuntime, "status"),
            modelRuntimeConnected ? "Connected" : "Disconnected");
        bool llmRuntimeConnected = GetBool(root, "llmRuntimeConnected", GetBool(profile, "llmRuntimeConnected", GetBool(llmRuntime, "connected", false)));
        string llmRuntimeStatus = FirstNonEmpty(
            GetString(root, "llmRuntimeStatus"),
            GetString(profile, "llmRuntimeStatus"),
            GetString(llmRuntime, "status"),
            llmRuntimeConnected ? "Connected" : "Not selected");
        string statusText = FirstNonEmpty(reportedStatus, reportedOnline ? "Online" : "Offline");

        var server = new RegisteredServer {
            Title = title,
            DisplayName = FirstNonEmpty(GetString(root, "displayName"), title),
            Description = FirstNonEmpty(GetString(root, "description"), GetString(profile, "description"), GetString(root, "serverDescription"), GetString(profile, "serverDescription")),
            Endpoint = endpoint,
            ConnectHost = connectHost,
            IpAddress = FirstNonEmpty(GetString(root, "ip"), GetString(root, "ipAddress"), GetString(profile, "ipAddress"), connectHost, remoteIp),
            ProxyPort = GetInt(ports, "vsProxy", GetInt(root, "proxyPort", 11434)),
            ChatPort = chatPort,
            LmStudioPort = GetInt(ports, "lmStudio", GetInt(root, "lmStudioPort", 11435)),
            FtpPort = GetInt(ports, "ftp", GetInt(root, "ftpPort", 2121)),
            AvailableModels = FirstNonEmpty(GetString(root, "availableModels"), GetString(profile, "availableModels"), GetString(resources, "availableModels"), GetString(root, "models"), GetString(profile, "models")),
            ModelCapabilitiesJson = FirstNonEmpty(GetString(root, "modelCapabilitiesJson"), GetString(profile, "modelCapabilitiesJson"), GetRawJson(root, "modelCapabilities"), GetRawJson(profile, "modelCapabilities")),
            ModelBenchmarksJson = FirstNonEmpty(GetString(root, "modelBenchmarksJson"), GetString(profile, "modelBenchmarksJson"), GetRawJson(root, "modelBenchmarks"), GetRawJson(profile, "modelBenchmarks")),
            ToolsAllowed = FirstNonEmpty(GetString(root, "toolsAllowed"), GetString(profile, "toolsAllowed"), GetString(resources, "toolsAllowed"), GetString(root, "tools"), GetString(profile, "tools")),
            AvailableRam = FirstNonEmpty(GetString(root, "availableRam"), GetString(profile, "availableRam"), GetString(resources, "availableRam"), GetString(root, "ramAvailable"), GetString(profile, "ramAvailable")),
            AvailableVram = FirstNonEmpty(GetString(root, "availableVram"), GetString(profile, "availableVram"), GetString(resources, "availableVram"), GetString(root, "vramAvailable"), GetString(profile, "vramAvailable")),
            AvailableResources = FirstNonEmpty(GetString(root, "availableResources"), GetString(profile, "availableResources"), JsonValueToText(resources)),
            StorageAvailable = FirstNonEmpty(GetString(root, "storageAvailable"), GetString(profile, "storageAvailable"), GetString(resources, "storageAvailable")),
            GpuModel = FirstNonEmpty(GetString(root, "gpuModel"), GetString(profile, "gpuModel"), GetString(resources, "gpuModel"), GetString(root, "gpuName"), GetString(profile, "gpuName")),
            GpuAvailable = FirstNonEmpty(GetString(root, "gpuAvailable"), GetString(profile, "gpuAvailable"), GetString(resources, "gpuAvailable")),
            CpuModel = FirstNonEmpty(GetString(root, "cpuModel"), GetString(profile, "cpuModel"), GetString(resources, "cpuModel"), GetString(root, "cpuName"), GetString(profile, "cpuName")),
            CpuAvailable = FirstNonEmpty(GetString(root, "cpuAvailable"), GetString(profile, "cpuAvailable"), GetString(resources, "cpuAvailable")),
            MaxTokens = Math.Max(0, GetLong(root, "maxTokens", GetLong(profile, "maxTokens", GetLong(resources, "maxTokens", 0)))),
            Cost = Math.Max(0, GetDouble(root, "cost", GetDouble(profile, "cost", 0))),
            CostFactor = GetDouble(payment, "costFactor", GetDouble(profile, "costFactor", GetDouble(root, "costFactor", 1))),
            RequiresPayment = GetBool(payment, "requiresPayment", GetBool(profile, "requiresPayment", GetBool(root, "requiresPayment", false))),
            StripePriceId = FirstNonEmpty(GetString(payment, "stripePriceId"), GetString(payment, "priceId"), GetString(profile, "stripePriceId"), GetString(root, "stripePriceId")),
            StripeAccount = FirstNonEmpty(GetString(payment, "stripeAccount"), GetString(payment, "connectedAccount"), GetString(payment, "account"), GetString(profile, "stripeAccount"), GetString(root, "stripeAccount")),
            StripeUnitAmountCents = Math.Max(0, GetLong(payment, "unitAmountCents", GetLong(payment, "stripeUnitAmountCents", GetLong(profile, "stripeUnitAmountCents", GetLong(root, "stripeUnitAmountCents", 0))))),
            StripeCurrency = FirstNonEmpty(GetString(payment, "currency"), GetString(payment, "stripeCurrency"), GetString(profile, "stripeCurrency"), GetString(root, "stripeCurrency"), "usd").ToLowerInvariant(),
            OwnerUserName = FirstNonEmpty(GetString(root, "ownerUserName"), GetString(root, "ownerUsername"), GetString(root, "serverOwnerUserName"), GetString(profile, "ownerUserName"), GetString(profile, "ownerUsername"), GetString(profile, "serverOwnerUserName")),
            RegisteredByIp = remoteIp,
            FirstSeenUtc = now.ToString("O", CultureInfo.InvariantCulture),
            LastSeenUtc = now.ToString("O", CultureInfo.InvariantCulture),
            StartedUtc = FirstNonEmpty(GetString(root, "startedUtc"), GetString(profile, "startedUtc"), GetString(root, "StartedUtc"), GetString(profile, "StartedUtc")),
            UptimeSeconds = Math.Max(0, GetLong(root, "uptimeSeconds", GetLong(profile, "uptimeSeconds", GetLong(root, "UptimeSeconds", GetLong(profile, "UptimeSeconds", 0))))),
            UpdatedUtc = updated,
            LastStatus = statusText,
            IsOnline = reportedOnline,
            HostResponding = hostResponding,
            LmStudioConnected = lmStudioConnected,
            ModelRuntimeProvider = modelRuntimeProvider,
            ModelRuntimeConnected = modelRuntimeConnected,
            ModelRuntimeStatus = modelRuntimeStatus,
            LlmRuntimeConnected = llmRuntimeConnected,
            LlmRuntimeStatus = llmRuntimeStatus,
            StatusText = statusText,
            InternetLatencyMs = Math.Max(0, GetInt(root, "internetLatencyMs", GetInt(profile, "internetLatencyMs", GetInt(root, "latencyMs", GetInt(profile, "latencyMs", 0))))),
            ProxyLatencyMs = Math.Max(0, GetInt(root, "proxyLatencyMs", GetInt(profile, "proxyLatencyMs", 0))),
            BackgroundImageKey = FirstNonEmpty(GetString(root, "backgroundImageKey"), GetString(profile, "backgroundImageKey")),
            BackgroundOffsetX = GetDouble(root, "backgroundOffsetX", GetDouble(profile, "backgroundOffsetX", 0)),
            BackgroundOffsetY = GetDouble(root, "backgroundOffsetY", GetDouble(profile, "backgroundOffsetY", 0)),
            BackgroundScale = GetDouble(root, "backgroundScale", GetDouble(profile, "backgroundScale", 1)),
            ExtraJson = root.GetRawText()
        };

        server.SearchText = BuildSearchText(root, server);
        string suppliedId = FirstNonEmpty(GetString(root, "id"), GetString(profile, "id"), GetString(root, "serverId"), GetString(profile, "serverId"));
        server.Id = string.IsNullOrWhiteSpace(suppliedId)
            ? MakeId(FirstNonEmpty(server.Endpoint, server.ConnectHost + ":" + server.ChatPort, server.Title))
            : NormalizeId(suppliedId);
        server.Normalize();
        return server;
    }

    public void Normalize() {
        Title = NormalizeText(Title);
        DisplayName = NormalizeText(DisplayName);
        Description = NormalizeText(Description);
        Endpoint = NormalizeText(Endpoint);
        ConnectHost = NormalizeHost(ConnectHost);
        IpAddress = NormalizeHost(IpAddress);
        OwnerUserName = NormalizeText(OwnerUserName);
        ModelRuntimeProvider = FirstNonEmpty(NormalizeText(ModelRuntimeProvider), "LM Studio");
        ModelRuntimeStatus = FirstNonEmpty(NormalizeText(ModelRuntimeStatus), ModelRuntimeConnected ? "Connected" : "Disconnected");
        LlmRuntimeStatus = FirstNonEmpty(NormalizeText(LlmRuntimeStatus), LlmRuntimeConnected ? "Connected" : "Not selected");
        InternetLatencyMs = Math.Max(0, InternetLatencyMs);
        ProxyLatencyMs = Math.Max(0, ProxyLatencyMs);
        if (string.IsNullOrWhiteSpace(Endpoint))
            Endpoint = BuildEndpoint(ConnectHost, ChatPort);
        if (string.IsNullOrWhiteSpace(Title))
            Title = FirstNonEmpty(DisplayName, ConnectHost, "JackLLM Host");
        if (string.IsNullOrWhiteSpace(DisplayName))
            DisplayName = Title;
        if (ProxyPort <= 0 || ProxyPort > 65535)
            ProxyPort = 11434;
        if (ChatPort <= 0 || ChatPort > 65535)
            ChatPort = 11436;
        if (LmStudioPort <= 0 || LmStudioPort > 65535)
            LmStudioPort = 11435;
        if (FtpPort <= 0 || FtpPort > 65535)
            FtpPort = 2121;
        CostFactor = ClampCostFactor(CostFactor);
        ModelCapabilitiesJson = NormalizeText(ModelCapabilitiesJson);
        ModelBenchmarksJson = NormalizeText(ModelBenchmarksJson);
        Cost = Math.Max(0, Cost);
        MaxTokens = Math.Max(0, MaxTokens);
        StartedUtc = NormalizeText(StartedUtc);
        UptimeSeconds = Math.Max(0, UptimeSeconds);
        StripeUnitAmountCents = Math.Max(0, StripeUnitAmountCents);
        StripeCurrency = string.IsNullOrWhiteSpace(StripeCurrency) ? "usd" : StripeCurrency.Trim().ToLowerInvariant();
        BackgroundImageKey = NormalizeText(BackgroundImageKey);
        BackgroundImageUrl = NormalizeText(BackgroundImageUrl);
        BackgroundOffsetX = ClampFinite(BackgroundOffsetX, -100, 100, 0);
        BackgroundOffsetY = ClampFinite(BackgroundOffsetY, -100, 100, 0);
        BackgroundScale = ClampFinite(BackgroundScale, 1, 4, 1);
        if (string.IsNullOrWhiteSpace(Id))
            Id = MakeId(FirstNonEmpty(Endpoint, ConnectHost + ":" + ChatPort, Title));
    }

    private static double ClampFinite(double value, double minimum, double maximum, double fallback) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            value = fallback;
        return Math.Max(minimum, Math.Min(maximum, value));
    }

    private bool HasCapabilitySignal(params string[] names) {
        return CapabilityJsonHasAny(ModelCapabilitiesJson, names) ||
               CapabilityJsonHasAny(ModelBenchmarksJson, names) ||
               CapabilityJsonHasAny(ExtraJson, names);
    }

    private static string GetRawJsonContainer(JsonElement element, string name) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return "";
        return value.ValueKind == JsonValueKind.Array || value.ValueKind == JsonValueKind.Object
            ? value.GetRawText()
            : "";
    }

    private static string BuildInferredModelCapabilitiesJson(string modelsText) {
        List<string> models = SplitModelHints(modelsText);
        if (models.Count == 0)
            return "";

        var array = new JsonArray();
        foreach (string model in models) {
            var item = new JsonObject {
                ["modelId"] = model,
                ["supportsImages"] = TextLooksVisionCapable(model),
                ["supportsTools"] = TextLooksToolCapable(model),
                ["supportsImageGeneration"] = TextLooksImageGenerationCapable(model),
                ["supportsAudioGeneration"] = TextLooksAudioGenerationCapable(model),
                ["supportsVideoGeneration"] = TextLooksVideoGenerationCapable(model)
            };
            array.Add(item);
        }

        return array.ToJsonString(MasterListJson.Options);
    }

    private List<RegisteredServerModelInfo> BuildPublicModelInventory() {
        var models = new Dictionary<string, RegisteredServerModelInfo>(StringComparer.OrdinalIgnoreCase);
        AddPublicModelsFromJson(ModelCapabilitiesJson, models);
        AddPublicModelsFromJson(ModelBenchmarksJson, models);
        foreach (string model in SplitModelHints(AvailableModels)) {
            RegisteredServerModelInfo item = GetOrAddPublicModel(models, model);
            item.Available = true;
            if (string.IsNullOrWhiteSpace(item.Status))
                item.Status = item.Enabled ? "enabled" : item.DynamicLoadEnabled ? "dynamic-load-available" : item.Loaded ? "loaded" : "available";
        }

        return models.Values
            .OrderByDescending(model => model.Loaded)
            .ThenByDescending(model => model.Enabled)
            .ThenBy(model => model.Id, StringComparer.OrdinalIgnoreCase)
            .ToList();
    }

    private static void AddPublicModelsFromJson(string json, IDictionary<string, RegisteredServerModelInfo> models) {
        if (string.IsNullOrWhiteSpace(json) || models == null)
            return;
        try {
            using JsonDocument document = JsonDocument.Parse(json);
            AddPublicModelsFromElement(document.RootElement, models, 0);
        } catch {
        }
    }

    private static void AddPublicModelsFromElement(JsonElement element, IDictionary<string, RegisteredServerModelInfo> models, int depth) {
        if (depth > 8 || models.Count > 500)
            return;

        if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement item in element.EnumerateArray())
                AddPublicModelsFromElement(item, models, depth + 1);
            return;
        }

        if (element.ValueKind != JsonValueKind.Object)
            return;

        string id = FirstNonEmpty(
            GetString(element, "modelId"),
            GetString(element, "ModelId"),
            GetString(element, "id"),
            GetString(element, "key"),
            GetString(element, "name"),
            GetString(element, "model"),
            GetString(element, "displayName"),
            GetString(element, "display_name"));
        if (!string.IsNullOrWhiteSpace(id)) {
            RegisteredServerModelInfo model = GetOrAddPublicModel(models, id);
            bool TryReadModelBool(bool fallback, params string[] names) {
                bool value = fallback;
                foreach (string name in names ?? Array.Empty<string>())
                    value = GetBool(element, name, value);
                if (TryGetObject(element, "capabilities", out JsonElement capabilities) ||
                    TryGetObject(element, "Capabilities", out capabilities)) {
                    foreach (string name in names ?? Array.Empty<string>())
                        value = GetBool(capabilities, name, value);
                }
                return value;
            }

            model.Available = GetBool(element, "isAvailable", true) || model.Available;
            model.Loaded = GetBool(element, "isLoaded", GetBool(element, "loaded", GetBool(element, "active", false))) || model.Loaded;
            model.Enabled = GetBool(element, "enabled", GetBool(element, "isEnabled", GetBool(element, "web_chat_model_enabled", false))) || model.Enabled;
            model.DynamicLoadEnabled = GetBool(element, "dynamicLoadEnabled", GetBool(element, "web_chat_dynamic_load_enabled", false)) || model.DynamicLoadEnabled;
            model.ServerDynamicLoadingEnabled = GetBool(element, "serverDynamicLoadingEnabled", GetBool(element, "web_chat_model_load_api_enabled", false)) || model.ServerDynamicLoadingEnabled;
            model.RuntimeLoadEnabled = GetBool(element, "runtime_load", GetBool(element, "runtimeLoad", GetBool(element, "runtimeLoadEnabled", GetBool(element, "canLoad", false)))) || model.RuntimeLoadEnabled;
            model.Disabled = GetBool(element, "disabled", false) || model.Disabled;
            model.SupportsVision = TryReadModelBool(false, "supportsVision", "supportsImages", "vision", "multimodal", "supportsImageUpload") || model.SupportsVision;
            model.SupportsTools = TryReadModelBool(false, "supportsTools", "tools", "toolUse", "toolCalling", "functionCalling") || model.SupportsTools;
            model.SupportsImageGeneration = TryReadModelBool(false, "supportsImageGeneration", "imageGeneration", "image_generation", "generatesImages") || model.SupportsImageGeneration;
            model.SupportsAudioGeneration = TryReadModelBool(false, "supportsAudioGeneration", "audioGeneration", "audio_generation", "generatesAudio") || model.SupportsAudioGeneration;
            model.SupportsVideoGeneration = TryReadModelBool(false, "supportsVideoGeneration", "videoGeneration", "video_generation", "generatesVideo") || model.SupportsVideoGeneration;
            double tokensPerSecond = Math.Max(0, GetDouble(element, "tokensPerSecond", GetDouble(element, "TokensPerSecond", 0)));
            double tokensPerHour = Math.Max(0, GetDouble(element, "tokensPerHour", GetDouble(element, "TokensPerHour", 0)));
            int outputTokens = Math.Max(0, GetInt(element, "outputTokens", GetInt(element, "OutputTokens", 0)));
            double durationMs = Math.Max(0, GetDouble(element, "benchmarkDurationMs", GetDouble(element, "durationMs", GetDouble(element, "DurationMs", 0))));
            int rating = Math.Max(0, GetInt(element, "benchmarkRating", GetInt(element, "rating", GetInt(element, "Rating", GetInt(element, "score", GetInt(element, "Score", 0))))));
            if (rating <= 0 && tokensPerSecond > 0)
                rating = (int)Math.Round(Math.Max(0, Math.Min(100, (tokensPerSecond / 120d) * 100d)));
            string benchmarkedUtc = FirstNonEmpty(GetString(element, "benchmarkedUtc"), GetString(element, "BenchmarkedUtc"), GetString(element, "updatedUtc"), GetString(element, "createdUtc"));
            string benchmarkStatus = FirstNonEmpty(GetString(element, "benchmarkStatus"), GetString(element, "status"), GetString(element, "Status"));
            model.TokensPerSecond = Math.Max(model.TokensPerSecond, tokensPerSecond);
            model.TokensPerHour = Math.Max(model.TokensPerHour, tokensPerHour);
            model.OutputTokens = Math.Max(model.OutputTokens, outputTokens);
            model.BenchmarkDurationMs = Math.Max(model.BenchmarkDurationMs, durationMs);
            model.BenchmarkRating = Math.Max(model.BenchmarkRating, rating);
            model.Benchmarked = model.Benchmarked || GetBool(element, "benchmarked", false) || tokensPerSecond > 0 || tokensPerHour > 0 || outputTokens > 0 || durationMs > 0 || rating > 0;
            model.BenchmarkedUtc = FirstNonEmpty(model.BenchmarkedUtc, benchmarkedUtc);
            model.BenchmarkStatus = FirstNonEmpty(model.BenchmarkStatus, benchmarkStatus);
            model.Status = FirstNonEmpty(GetString(element, "status"), model.Status);
            if (string.IsNullOrWhiteSpace(model.Status))
                model.Status = model.Loaded && model.Enabled ? "loaded-enabled" : model.Loaded && model.DynamicLoadEnabled ? "loaded-dynamic" : model.Loaded ? "loaded-disabled" : model.Enabled ? "enabled" : model.ServerDynamicLoadingEnabled ? "dynamic-load-available" : model.Disabled ? "disabled" : "available";
            return;
        }

        foreach (JsonProperty property in element.EnumerateObject())
            AddPublicModelsFromElement(property.Value, models, depth + 1);
    }

    private static RegisteredServerModelInfo GetOrAddPublicModel(IDictionary<string, RegisteredServerModelInfo> models, string id) {
        id = (id ?? "").Trim();
        if (!models.TryGetValue(id, out RegisteredServerModelInfo? model)) {
            model = new RegisteredServerModelInfo { Id = id, Available = true };
            models[id] = model;
        }
        return model;
    }

    private static int CountModelHints(params string[] values) {
        var models = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach (string value in values ?? Array.Empty<string>()) {
            foreach (string model in SplitModelHints(value))
                models.Add(model);
            AddModelHintsFromJson(value, models);
        }

        return models.Count;
    }

    private static List<string> SplitModelHints(string value) {
        var models = new List<string>();
        if (string.IsNullOrWhiteSpace(value))
            return models;

        foreach (string part in value.Replace("\r\n", "\n")
                     .Split(new[] { '\n', ',', ';', '\t' }, StringSplitOptions.RemoveEmptyEntries)) {
            string text = part.Trim();
            if (string.IsNullOrWhiteSpace(text))
                continue;
            if (text.Contains(':') && !text.Contains('/', StringComparison.Ordinal) && !text.Contains('\\', StringComparison.Ordinal))
                continue;
            if (text.Length > 140)
                continue;
            models.Add(text);
        }

        return models.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
    }

    private static void AddModelHintsFromJson(string json, ISet<string> models) {
        if (string.IsNullOrWhiteSpace(json) || models == null)
            return;

        try {
            using JsonDocument document = JsonDocument.Parse(json);
            AddModelHintsFromElement(document.RootElement, models, 0);
        } catch {
        }
    }

    private static void AddModelHintsFromElement(JsonElement element, ISet<string> models, int depth) {
        if (depth > 8 || models.Count > 500)
            return;

        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (IsModelNameProperty(property.Name)) {
                    string text = JsonValueToText(property.Value).Trim();
                    if (!string.IsNullOrWhiteSpace(text) && text.Length <= 180)
                        models.Add(text);
                } else if (property.Value.ValueKind == JsonValueKind.Object && LooksLikeModelContainerProperty(property.Name)) {
                    models.Add(property.Name.Trim());
                }

                AddModelHintsFromElement(property.Value, models, depth + 1);
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement item in element.EnumerateArray())
                AddModelHintsFromElement(item, models, depth + 1);
        } else if (element.ValueKind == JsonValueKind.String) {
            foreach (string model in SplitModelHints(element.GetString() ?? ""))
                models.Add(model);
        }
    }

    private static bool IsModelNameProperty(string name) {
        return name.Equals("modelId", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("model", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("id", StringComparison.OrdinalIgnoreCase) ||
               name.Equals("name", StringComparison.OrdinalIgnoreCase);
    }

    private static bool LooksLikeModelContainerProperty(string name) {
        if (string.IsNullOrWhiteSpace(name))
            return false;
        string value = name.Trim();
        string lower = value.ToLowerInvariant();
        if (lower is "data" or "models" or "modelcapabilities" or "model_capabilities" or "capabilities" or "metadata" or "features")
            return false;
        return value.Contains('/', StringComparison.Ordinal) ||
               value.Contains('\\', StringComparison.Ordinal) ||
               value.Contains('-', StringComparison.Ordinal) ||
               value.Contains('_', StringComparison.Ordinal) ||
               TextLooksVisionCapable(value) ||
               TextLooksImageGenerationCapable(value) ||
               TextLooksAudioGenerationCapable(value) ||
               TextLooksVideoGenerationCapable(value);
    }

    private static bool TextLooksToolCapable(params string[] values) {
        string text = JoinLower(values);
        if (string.IsNullOrWhiteSpace(text) || Regex.IsMatch(text, @"\b(none|unknown|n/a)\b", RegexOptions.IgnoreCase))
            return false;
        return ContainsAny(text, "vs_tools", "vs tools", "vs bridge", "filesystem", "file system", "terminal", "ftp", "web auth", "tool use", "tool_call", "tool calls", "function calling", "tools allowed");
    }

    private static bool TextLooksVisionCapable(params string[] values) {
        string text = JoinLower(values);
        return ContainsAny(text, "vision", "visual", "multimodal", "image upload", "supports images", "supportsimages", "vlm", "llava", "pixtral", "moondream", "minicpm-v", "qwen-vl", "qwen2-vl", "qwen2.5-vl", "bakllava");
    }

    private static bool TextLooksImageGenerationCapable(params string[] values) {
        string text = JoinLower(values);
        return ContainsAny(text, "image_generation", "image generation", "image-generation", "text-to-image", "text to image", "t2i", "stable-diffusion", "stable diffusion", "sdxl", "flux", "qwen-image", "imagegen", "diffusion");
    }

    private static bool TextLooksAudioGenerationCapable(params string[] values) {
        string text = JoinLower(values);
        return ContainsAny(text, "audio_generation", "audio generation", "audio-generation", "text-to-speech", "text to speech", "tts", "speech synthesis", "musicgen", "audio gen");
    }

    private static bool TextLooksVideoGenerationCapable(params string[] values) {
        string text = JoinLower(values);
        return ContainsAny(text, "video_generation", "video generation", "video-generation", "text-to-video", "text to video", "image-to-video", "image to video", "t2v", "i2v", "v2v", "wan2", "wan-", "hunyuanvideo", "ltx-video", "ltxv", "mochi", "motifv");
    }

    private static bool TextLooksMediaGenerationCapable(params string[] values) {
        string text = JoinLower(values);
        return TextLooksGenericMediaToolCapable(text) ||
               TextLooksImageGenerationCapable(text) ||
               TextLooksAudioGenerationCapable(text) ||
               TextLooksVideoGenerationCapable(text);
    }

    private static bool TextLooksGenericMediaToolCapable(params string[] values) {
        string text = JoinLower(values);
        return ContainsAny(text, "jackonnx media", "llmruntime media", "media tools", "media generation", "media-generation", "media_generator", "media generator", "complete models generator");
    }

    private static string JoinLower(params string[] values) {
        return string.Join(" ", (values ?? Array.Empty<string>()).Where(value => !string.IsNullOrWhiteSpace(value))).ToLowerInvariant();
    }

    private static bool ContainsAny(string text, params string[] needles) {
        if (string.IsNullOrWhiteSpace(text) || needles == null)
            return false;
        foreach (string needle in needles) {
            if (!string.IsNullOrWhiteSpace(needle) && text.Contains(needle, StringComparison.OrdinalIgnoreCase))
                return true;
        }

        return false;
    }

    private static bool CapabilityJsonHasAny(string json, params string[] names) {
        if (string.IsNullOrWhiteSpace(json) || names == null || names.Length == 0)
            return false;

        try {
            using JsonDocument document = JsonDocument.Parse(json);
            return JsonElementHasTruthyProperty(document.RootElement, new HashSet<string>(names, StringComparer.OrdinalIgnoreCase));
        } catch {
            return false;
        }
    }

    private static bool JsonElementHasTruthyProperty(JsonElement element, ISet<string> names) {
        if (names == null || names.Count == 0)
            return false;

        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (names.Contains(property.Name) && JsonElementIsTruthy(property.Value))
                    return true;
                if (JsonElementHasTruthyProperty(property.Value, names))
                    return true;
            }
        } else if (element.ValueKind == JsonValueKind.Array) {
            foreach (JsonElement item in element.EnumerateArray()) {
                if (JsonElementHasTruthyProperty(item, names))
                    return true;
            }
        }

        return false;
    }

    private static bool JsonElementIsTruthy(JsonElement element) {
        return element.ValueKind switch {
            JsonValueKind.True => true,
            JsonValueKind.Number => element.TryGetDouble(out double number) && number > 0,
            JsonValueKind.String => !string.IsNullOrWhiteSpace(element.GetString()) &&
                                    !element.GetString()!.Equals("false", StringComparison.OrdinalIgnoreCase) &&
                                    !element.GetString()!.Equals("0", StringComparison.OrdinalIgnoreCase) &&
                                    !element.GetString()!.Equals("no", StringComparison.OrdinalIgnoreCase) &&
                                    !element.GetString()!.Equals("none", StringComparison.OrdinalIgnoreCase),
            _ => false
        };
    }

    public static string JsonValueToText(JsonElement value) {
        return value.ValueKind switch {
            JsonValueKind.String => value.GetString() ?? "",
            JsonValueKind.Number => value.ToString(),
            JsonValueKind.True => "true",
            JsonValueKind.False => "false",
            JsonValueKind.Array => string.Join(", ", value.EnumerateArray()
                .Select(JsonValueToText)
                .Where(text => !string.IsNullOrWhiteSpace(text))),
            JsonValueKind.Object => string.Join(", ", value.EnumerateObject()
                .Select(property => property.Name + ": " + JsonValueToText(property.Value))
                .Where(text => !string.IsNullOrWhiteSpace(text) && !text.EndsWith(": ", StringComparison.Ordinal))),
            _ => ""
        };
    }

    private static string BuildSearchText(JsonElement root, RegisteredServer server) {
        var builder = new StringBuilder();
        builder.Append(server.SearchCorpus);
        builder.Append(' ');
        AppendSearchableJson(root, builder, 0);
        return builder.ToString();
    }

    private static void AppendSearchableJson(JsonElement element, StringBuilder builder, int depth) {
        if (depth > 8 || builder.Length > 24000)
            return;

        switch (element.ValueKind) {
            case JsonValueKind.Object:
                foreach (JsonProperty property in element.EnumerateObject()) {
                    builder.Append(' ');
                    builder.Append(property.Name);
                    AppendSearchableJson(property.Value, builder, depth + 1);
                }
                break;
            case JsonValueKind.Array:
                foreach (JsonElement item in element.EnumerateArray())
                    AppendSearchableJson(item, builder, depth + 1);
                break;
            case JsonValueKind.String:
            case JsonValueKind.Number:
            case JsonValueKind.True:
            case JsonValueKind.False:
                builder.Append(' ');
                builder.Append(JsonValueToText(element));
                break;
        }
    }

    private static bool TryGetObject(JsonElement element, string name, out JsonElement value) {
        if (TryGetProperty(element, name, out value) && value.ValueKind == JsonValueKind.Object)
            return true;
        value = default;
        return false;
    }

    private static bool TryGetProperty(JsonElement element, string name, out JsonElement value) {
        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase)) {
                    value = property.Value;
                    return true;
                }
            }
        }

        value = default;
        return false;
    }

    public static string GetString(JsonElement element, string name, string fallback = "") {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        string text = JsonValueToText(value);
        return string.IsNullOrWhiteSpace(text) ? fallback : text;
    }

    private static string GetRawJson(JsonElement element, string name) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return "";
        return value.ValueKind == JsonValueKind.Null || value.ValueKind == JsonValueKind.Undefined
            ? ""
            : value.GetRawText();
    }

    private static int GetInt(JsonElement element, string name, int fallback) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out int result))
            return result;
        return int.TryParse(JsonValueToText(value), NumberStyles.Integer, CultureInfo.InvariantCulture, out result) ? result : fallback;
    }

    private static long GetLong(JsonElement element, string name, long fallback) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt64(out long result))
            return result;
        return long.TryParse(JsonValueToText(value), NumberStyles.Integer, CultureInfo.InvariantCulture, out result) ? result : fallback;
    }

    private static double GetDouble(JsonElement element, string name, double fallback) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out double result))
            return result;
        return double.TryParse(JsonValueToText(value), NumberStyles.Float, CultureInfo.InvariantCulture, out result) ? result : fallback;
    }

    public static bool GetBool(JsonElement element, string name, bool fallback) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.True || value.ValueKind == JsonValueKind.False)
            return value.GetBoolean();
        return bool.TryParse(JsonValueToText(value), out bool result) ? result : fallback;
    }

    private static double ClampCostFactor(double value) {
        if (double.IsNaN(value) || double.IsInfinity(value))
            return 1;
        return Math.Max(1, Math.Min(5, value));
    }

    private static string MakeId(string key) {
        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes((key ?? "").Trim().ToLowerInvariant()));
        return Convert.ToHexString(hash, 0, 8).ToLowerInvariant();
    }

    private static string NormalizeId(string value) {
        value = NormalizeText(value);
        return value.Length > 128 ? MakeId(value) : value;
    }

    public static string BuildEndpoint(string host, int port) {
        host = NormalizeHost(host);
        if (string.IsNullOrWhiteSpace(host))
            return "";
        return "http://" + host + ":" + port.ToString(CultureInfo.InvariantCulture);
    }

    private static string NormalizeHost(string value) {
        value = NormalizeText(value);
        if (Uri.TryCreate(value, UriKind.Absolute, out Uri? uri))
            return uri.Host;
        int schemeIndex = value.IndexOf("://", StringComparison.Ordinal);
        if (schemeIndex >= 0)
            value = value.Substring(schemeIndex + 3);
        int slashIndex = value.IndexOf('/');
        if (slashIndex >= 0)
            value = value.Substring(0, slashIndex);
        int colonIndex = value.LastIndexOf(':');
        if (colonIndex > 0 && value.IndexOf(':') == colonIndex)
            value = value.Substring(0, colonIndex);
        return value.Trim('[', ']');
    }

    public static string NormalizeExternalHost(string value) {
        return NormalizeHost(value);
    }

    private static string NormalizeText(string value) {
        return (value ?? "").Trim();
    }

    public static string FirstNonEmpty(params string?[] values) {
        foreach (string? value in values) {
            if (!string.IsNullOrWhiteSpace(value))
                return value.Trim();
        }

        return "";
    }
}

internal sealed class MasterShellRelay {
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
    public string RouteName { get; set; } = "";
    public string ProxyPath { get; set; } = "";
    public int PublicPort { get; set; }
    public int AgentPort { get; set; }
    public string TargetHost { get; set; } = "127.0.0.1";
    public int TargetPort { get; set; }
    public bool Enabled { get; set; }
    public bool IsRunning { get; set; }
    public int ActiveSessions { get; set; }
    public int WaitingAgents { get; set; }
    public int WaitingPublicClients { get; set; }
    public string TransportMode { get; set; } = "websocketPreferred";
    public bool SupportsWebSocketTunnel { get; set; } = true;
    public string WebSocketTunnelUrl { get; set; } = "";
    public bool WebSocketTunnelConnected { get; set; }
    public int WebSocketTunnelCount { get; set; }
    public string LastTunnelSeenUtc { get; set; } = "";
    public bool FallbackTcpEnabled { get; set; } = true;
    public string Status { get; set; } = "Disabled";
    public string ServerId { get; set; } = "";
    public string Endpoint { get; set; } = "";
    [JsonIgnore]
    public string OwnerKey { get; set; } = "";
    [JsonIgnore]
    public string OwnerTokenHash { get; set; } = "";
    public string CreatedUtc { get; set; } = "";
    public string LastUpdatedUtc { get; set; } = "";
    public string LastAgentSeenUtc { get; set; } = "";
    public List<string> DebugLines { get; set; } = new();

    [JsonIgnore]
    public string TitleText => string.IsNullOrWhiteSpace(Name) ? Id : Name;

    [JsonIgnore]
    public string DetailText => "SocketJack web public " + PublicPort.ToString(CultureInfo.InvariantCulture) +
                                " / reverse JackLLM agent " + AgentPort.ToString(CultureInfo.InvariantCulture) +
                                " -> JackLLM API " + TargetHost + ":" + TargetPort.ToString(CultureInfo.InvariantCulture) +
                                (string.IsNullOrWhiteSpace(ProxyPath) ? "" : " | " + ProxyPath);

    [JsonIgnore]
    public string RuntimeText => Status + " | agents " + WaitingAgents.ToString(CultureInfo.InvariantCulture) +
                                 " | ws " + (WebSocketTunnelConnected ? WebSocketTunnelCount.ToString(CultureInfo.InvariantCulture) : "0") +
                                 " | waiting clients " + WaitingPublicClients.ToString(CultureInfo.InvariantCulture) +
                                 " | sessions " + ActiveSessions.ToString(CultureInfo.InvariantCulture);

    [JsonIgnore]
    public string DebugText => DebugLines == null || DebugLines.Count == 0
        ? "No debug data for this shell instance yet."
        : string.Join(Environment.NewLine, DebugLines);

    public void Normalize() {
        Id = NormalizeText(Id);
        Name = NormalizeText(Name);
        RouteName = NormalizeRouteName(RouteName);
        ProxyPath = NormalizeText(ProxyPath);
        Endpoint = NormalizeText(Endpoint);
        ServerId = NormalizeText(ServerId);
        OwnerKey = NormalizeText(OwnerKey);
        OwnerTokenHash = NormalizeText(OwnerTokenHash);
        TargetHost = string.IsNullOrWhiteSpace(TargetHost) ? "127.0.0.1" : TargetHost.Trim();
        if (string.IsNullOrWhiteSpace(Id))
            Id = MakeId(Name + ":" + PublicPort.ToString(CultureInfo.InvariantCulture) + ":" + AgentPort.ToString(CultureInfo.InvariantCulture));
        if (string.IsNullOrWhiteSpace(Name))
            Name = "Shell Relay " + PublicPort.ToString(CultureInfo.InvariantCulture);
        if (string.IsNullOrWhiteSpace(RouteName))
            RouteName = NormalizeRouteName(Name);
        if (string.IsNullOrWhiteSpace(ProxyPath))
            ProxyPath = "/proxy/" + Uri.EscapeDataString(RouteName);
        TransportMode = NormalizeTransportMode(TransportMode);
        SupportsWebSocketTunnel = true;
        PublicPort = Math.Clamp(PublicPort, 1, 65535);
        AgentPort = Math.Clamp(AgentPort, 1, 65535);
        TargetPort = Math.Clamp(TargetPort <= 0 ? PublicPort : TargetPort, 1, 65535);
        CreatedUtc = string.IsNullOrWhiteSpace(CreatedUtc)
            ? DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            : CreatedUtc;
        LastUpdatedUtc = string.IsNullOrWhiteSpace(LastUpdatedUtc)
            ? DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture)
            : LastUpdatedUtc;
        DebugLines ??= new List<string>();
    }

    public MasterShellRelay Clone() {
        return new MasterShellRelay {
            Id = Id,
            Name = Name,
            RouteName = RouteName,
            ProxyPath = ProxyPath,
            PublicPort = PublicPort,
            AgentPort = AgentPort,
            TargetHost = TargetHost,
            TargetPort = TargetPort,
            Enabled = Enabled,
            IsRunning = IsRunning,
            ActiveSessions = ActiveSessions,
            WaitingAgents = WaitingAgents,
            WaitingPublicClients = WaitingPublicClients,
            TransportMode = TransportMode,
            SupportsWebSocketTunnel = SupportsWebSocketTunnel,
            WebSocketTunnelUrl = WebSocketTunnelUrl,
            WebSocketTunnelConnected = WebSocketTunnelConnected,
            WebSocketTunnelCount = WebSocketTunnelCount,
            LastTunnelSeenUtc = LastTunnelSeenUtc,
            FallbackTcpEnabled = FallbackTcpEnabled,
            Status = Status,
            ServerId = ServerId,
            Endpoint = Endpoint,
            OwnerKey = OwnerKey,
            OwnerTokenHash = OwnerTokenHash,
            CreatedUtc = CreatedUtc,
            LastUpdatedUtc = LastUpdatedUtc,
            LastAgentSeenUtc = LastAgentSeenUtc,
            DebugLines = DebugLines == null ? new List<string>() : DebugLines.ToList()
        };
    }

    public static MasterShellRelay FromJson(JsonElement element) {
        var relay = new MasterShellRelay {
            Id = GetString(element, "id"),
            Name = GetString(element, "name"),
            RouteName = GetString(element, "routeName"),
            ProxyPath = GetString(element, "proxyPath"),
            PublicPort = GetInt(element, "publicPort", 0),
            AgentPort = GetInt(element, "agentPort", 0),
            TargetHost = RegisteredServer.FirstNonEmpty(GetString(element, "targetHost"), "127.0.0.1"),
            TargetPort = GetInt(element, "targetPort", 0),
            Enabled = GetBool(element, "enabled", false),
            ServerId = GetString(element, "serverId"),
            Endpoint = GetString(element, "endpoint"),
            LastAgentSeenUtc = GetString(element, "lastAgentSeenUtc"),
            TransportMode = NormalizeTransportMode(GetString(element, "transportMode")),
            SupportsWebSocketTunnel = GetBool(element, "supportsWebSocketTunnel", true),
            WebSocketTunnelUrl = GetString(element, "webSocketTunnelUrl"),
            WebSocketTunnelConnected = GetBool(element, "webSocketTunnelConnected", false),
            WebSocketTunnelCount = GetInt(element, "webSocketTunnelCount", 0),
            LastTunnelSeenUtc = GetString(element, "lastTunnelSeenUtc"),
            FallbackTcpEnabled = GetBool(element, "fallbackTcpEnabled", true)
        };
        relay.Normalize();
        return relay;
    }

    private static string NormalizeTransportMode(string value) {
        value = (value ?? "").Trim();
        if (value.Equals("tcp", StringComparison.OrdinalIgnoreCase) ||
            value.Equals("reverseTcp", StringComparison.OrdinalIgnoreCase))
            return "tcp";
        return "websocketPreferred";
    }

    private static string GetString(JsonElement element, string name) {
        return RegisteredServer.GetString(element, name);
    }

    private static int GetInt(JsonElement element, string name, int fallback) {
        if (!TryGetProperty(element, name, out JsonElement value))
            return fallback;
        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out int result))
            return result;
        return int.TryParse(RegisteredServer.JsonValueToText(value), NumberStyles.Integer, CultureInfo.InvariantCulture, out result) ? result : fallback;
    }

    private static bool GetBool(JsonElement element, string name, bool fallback) {
        return RegisteredServer.GetBool(element, name, fallback);
    }

    private static bool TryGetProperty(JsonElement element, string name, out JsonElement value) {
        if (element.ValueKind == JsonValueKind.Object) {
            foreach (JsonProperty property in element.EnumerateObject()) {
                if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase)) {
                    value = property.Value;
                    return true;
                }
            }
        }

        value = default;
        return false;
    }

    private static string MakeId(string value) {
        byte[] hash = SHA256.HashData(Encoding.UTF8.GetBytes((value ?? "").Trim().ToLowerInvariant()));
        return "shell-" + Convert.ToHexString(hash, 0, 6).ToLowerInvariant();
    }

    private static string NormalizeText(string value) {
        return (value ?? "").Trim();
    }

    private static string NormalizeRouteName(string value) {
        value = NormalizeText(value);
        if (string.IsNullOrWhiteSpace(value))
            return "";

        var builder = new StringBuilder(value.Length);
        bool lastWasSpace = false;
        foreach (char c in value) {
            if (char.IsLetterOrDigit(c) || c == '-' || c == '_' || c == '.') {
                builder.Append(c);
                lastWasSpace = false;
            } else if (char.IsWhiteSpace(c)) {
                if (!lastWasSpace && builder.Length > 0)
                    builder.Append(' ');
                lastWasSpace = true;
            }
        }

        return builder.ToString().Trim();
    }
}

internal static class MasterListJson {
    public static readonly JsonSerializerOptions Options = new() {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        WriteIndented = true
    };
}

